def _resolve_explicit_existing_directory(raw_path: Path, *, label: str) -> Path:
    """Return one caller-supplied directory without following symlink authority."""

    raw = Path(os.path.abspath(Path(raw_path).expanduser()))
    cursor = Path(raw.anchor)
    for part in raw.parts[1:]:
        cursor /= part
        if cursor.is_symlink():
            raise ValueError(f"{label} path contains a symlink: {raw}")
    try:
        resolved = raw.resolve(strict=True)
    except OSError as exc:
        raise ValueError(f"{label} path does not exist: {raw}") from exc
    if not resolved.is_dir():
        raise ValueError(f"{label} path is not a directory: {raw}")
    return resolved


def _load_policyengine_runtime_for_rulespec_roots(
    raw_runtime_root: object,
    policy_repo_roots: Sequence[Path],
) -> PolicyEngineRuntime:
    """Admit one explicit runtime for the exact active RuleSpec roots."""

    if not isinstance(raw_runtime_root, Path):
        raise PolicyEngineRuntimeError(
            "PolicyEngine oracle requires --policyengine-runtime-root with an "
            "explicit absolute checkout path"
        )
    roots = tuple(Path(root) for root in policy_repo_roots)
    if not roots:
        raise PolicyEngineRuntimeError(
            "PolicyEngine oracle requires at least one active RuleSpec root"
        )
    runtime = PolicyEngineRuntime.for_rulespec_root(
        raw_runtime_root,
        policy_repo_root=roots[0],
    )
    for root in roots[1:]:
        runtime.assert_matches_rulespec_root(root)
    runtime.assert_unchanged()
    return runtime


def _resolve_canonical_rulespec_checkout(
    raw_path: Path,
    *,
    label: str = "RuleSpec checkout",
) -> Path:
    """Resolve one explicitly authorized canonical country checkout."""

    checkout = _resolve_explicit_existing_directory(raw_path, label=label)
    if not is_composition_policy_repo_root(checkout):
        raise ValueError(
            f"{label} must be the exact canonical rulespec-<country> checkout; "
            f"got {checkout}"
        )
    return checkout


def _resolve_explicit_policy_repo_for_corpus_source(
    corpus_citation_path: str,
    authorized_root: Path,
) -> Path:
    """Route a corpus source only inside one explicit RuleSpec checkout root."""

    root = _resolve_explicit_existing_directory(
        authorized_root,
        label="RuleSpec checkout",
    )
    jurisdiction = corpus_citation_path.strip().split("/", 1)[0] or "us"
    expected_checkout_name = monorepo_checkout_name(jurisdiction)
    if root.name != expected_checkout_name:
        raise ValueError(
            f"Explicit RuleSpec checkout for {jurisdiction!r} must be the canonical "
            f"country checkout named {expected_checkout_name!r}; got {root.name!r}"
        )
    content_root = root / jurisdiction
    if content_root.is_dir():
        return _resolve_explicit_existing_directory(
            content_root,
            label=f"RuleSpec {jurisdiction} content root",
        )
    raise ValueError(
        f"Explicit RuleSpec checkout {root} does not contain the canonical "
        f"{jurisdiction!r} content root"
    )


def _canonical_validation_checkout_root(rulespec_file: Path) -> Path:
    """Require one canonical primary RuleSpec module and return its checkout."""
    content_root = find_policy_repo_root(rulespec_file)
    if content_root is None:
        raise ValueError(
            f"RuleSpec module is not inside a canonical country checkout: {rulespec_file}"
        )
    resolved_file = rulespec_file.resolve()
    try:
        relative = resolved_file.relative_to(content_root.resolve())
    except ValueError as exc:
        raise ValueError(
            f"RuleSpec module is not inside its canonical jurisdiction root: {rulespec_file}"
        ) from exc
    if (
        resolved_file.suffix != RULESPEC_FILE_SUFFIX
        or resolved_file.name.endswith(RULESPEC_TEST_FILE_SUFFIX)
        or len(relative.parts) < 2
        or relative.parts[0] not in RULESPEC_ATOMIC_MODULE_ROOTS
    ):
        raise ValueError(
            "RuleSpec module must be a primary .yaml file under exactly one of "
            f"{sorted(RULESPEC_ATOMIC_MODULE_ROOTS)} inside "
            "rulespec-<country>/<jurisdiction>: "
            f"{rulespec_file}"
        )
    if content_root.name not in jurisdiction_subdir_names(
        content_root.parent,
        allow_composition_specs=True,
    ):
        raise ValueError(
            "validation requires the country-monorepo layout "
            f"(<rulespec-country>/<jurisdiction>/...): {rulespec_file}"
        )
    return content_root.parent


def _resolve_validation_repo_roots(
    rulespec_file: Path,
    axiom_rules_path: Path,
) -> tuple[Path, Path]:
    """Resolve validation against one exact content root and engine checkout."""
    checkout_root = _canonical_validation_checkout_root(rulespec_file)
    policy_repo_root = find_policy_repo_root(rulespec_file)
    if policy_repo_root is None or policy_repo_root.parent != checkout_root:
        raise ValueError(
            f"RuleSpec module is not inside a canonical country checkout: {rulespec_file}"
        )
    engine_root = _resolve_explicit_existing_directory(
        axiom_rules_path,
        label="Axiom rules engine",
    )
    return policy_repo_root, engine_root


def _reviewer_score_map(scores) -> dict[str, float | None]:
    """Normalize reviewer scores from flat attrs or ReviewResults.reviews."""
    reviewer_names = [
        "rulespec_reviewer",
        "formula_reviewer",
        "parameter_reviewer",
        "integration_reviewer",
    ]
    values = {name: getattr(scores, name, None) for name in reviewer_names}

    for review in getattr(scores, "reviews", []) or []:
        name = getattr(review, "reviewer", "")
        if name not in values:
            continue
        checked = getattr(review, "items_checked", 0) or 0
        passed = getattr(review, "items_passed", 0) or 0
        if checked > 0:
            values[name] = round(passed / checked * 10, 1)
        else:
            values[name] = 10.0 if getattr(review, "passed", False) else 0.0

    return values


def _add_gpt_backend_argument(parser: argparse.ArgumentParser) -> None:
    """Add a GPT backend override for local-vs-API runner selection."""
    parser.add_argument(
        "--gpt-backend",
        choices=["codex", "openai"],
        default=None,
        help=(
            "Override GPT runner backend for evals. "
            "Use 'codex' locally to route gpt-* runners through Codex CLI/ChatGPT, "
            "or 'openai' to force API-backed Responses runs. "
            "Defaults to 'codex' locally, or the AXIOM_ENCODE_GPT_BACKEND env var when set."
        ),
    )


def _positive_int(value: str) -> int:
    """Parse one strictly positive CLI integer."""
    try:
        parsed = int(value)
    except ValueError as exc:
        raise argparse.ArgumentTypeError(
            f"expected a positive integer, got {value!r}"
        ) from exc
    if parsed < 1:
        raise argparse.ArgumentTypeError(f"expected a positive integer, got {value!r}")
    return parsed


