def cmd_validate(args):
    """Validate one or more RuleSpec YAML files in a single process."""
    missing = [file for file in args.files if not file.exists()]
    if missing:
        for file in missing:
            print(f"File not found: {file}")
        sys.exit(1)
    if args.oracle not in {None, "policyengine"}:
        raise ValueError(f"Unsupported validate oracle '{args.oracle}'")

    enable_oracles = args.oracle == "policyengine"
    oracle_validators = ("policyengine",) if enable_oracles else None

    # Pipelines are reused across files sharing repo roots so per-process
    # setup (registry load, repo resolution) is paid once, not per file.
    pipelines: dict[tuple[Path, Path], ValidatorPipeline] = {}
    policyengine_runtimes: dict[tuple[Path, Path], PolicyEngineRuntime | None] = {}
    json_outputs = []
    failed_files = []
    for index, file in enumerate(args.files):
        rulespec_file = file.resolve()
        roots = _resolve_validation_repo_roots(
            rulespec_file,
            args.axiom_rules_path,
        )
        pipeline = pipelines.get(roots)
        if pipeline is None:
            policy_repo_root, axiom_rules_path = roots
            corpus_release = load_rulespec_local_corpus_release(
                policy_repo_root,
                args.corpus_path,
            )
            policyengine_runtime = (
                _load_policyengine_runtime_for_rulespec_roots(
                    getattr(args, "policyengine_runtime_root", None),
                    (policy_repo_root,),
                )
                if enable_oracles
                else None
            )
            pipeline = ValidatorPipeline(
                policy_repo_path=policy_repo_root,
                axiom_rules_path=axiom_rules_path,
                enable_oracles=enable_oracles,
                oracle_validators=oracle_validators,
                policyengine_runtime=policyengine_runtime,
                local_corpus_release=corpus_release,
                rulespec_dependency_roots=_rulespec_dependency_roots_from_args(args),
            )
            pipelines[roots] = pipeline
            policyengine_runtimes[roots] = policyengine_runtime
        if not args.json and index:
            print()
        all_passed, output = _validate_one(
            args,
            pipeline,
            rulespec_file,
            policyengine_runtime=policyengine_runtimes[roots],
        )
        if output is not None:
            json_outputs.append(output)
        if not all_passed:
            failed_files.append(file)

    if args.json:
        if len(args.files) == 1:
            print(json.dumps(json_outputs[0], indent=2))
        else:
            print(json.dumps(json_outputs, indent=2))
    elif failed_files and len(args.files) > 1:
        print(f"\n{len(failed_files)} of {len(args.files)} file(s) failed:")
        for file in failed_files:
            print(f"  - {file}")

    sys.exit(1 if failed_files else 0)


def _validate_one(
    args,
    pipeline,
    rulespec_file,
    *,
    policyengine_runtime: PolicyEngineRuntime | None,
):
    """Validate a single file; return (all_passed, JSON payload or None)."""
    result = pipeline.validate(rulespec_file, skip_reviewers=args.skip_reviewers)
    scores = result.to_review_results()
    review_scores = (
        {
            "rulespec_reviewer": None,
            "formula_reviewer": None,
            "parameter_reviewer": None,
            "integration_reviewer": None,
        }
        if args.skip_reviewers
        else _reviewer_score_map(scores)
    )

    errors = []
    for name, vr in result.results.items():
        if vr.error:
            errors.append(f"{name}: {vr.error}")
    oracle_issues = None
    if args.oracle:
        oracle_issues = {}
        for name, vr in result.results.items():
            issues = getattr(vr, "issues", None)
            if name == "policyengine" and isinstance(issues, list):
                if issues:
                    oracle_issues[name] = issues
        if not oracle_issues:
            oracle_issues = None
    oracle_coverage = None
    if args.oracle:
        oracle_coverage = {}
        for name, vr in result.results.items():
            coverage = getattr(vr, "details", {}).get("coverage")
            if name == "policyengine" and isinstance(coverage, dict):
                oracle_coverage[name] = coverage
        if not oracle_coverage:
            oracle_coverage = None

    # Check oracle results against minimum match rate
    oracle_passed = True
    if args.oracle:
        min_match = args.min_match
        pe_result = result.results.get("policyengine")
        if pe_result and pe_result.score is not None and pe_result.score < min_match:
            oracle_passed = False
            errors.append(
                f"PolicyEngine: {pe_result.score:.1%} < {min_match:.0%} required"
            )
        if getattr(args, "require_oracle_classification", False) is True:
            if not oracle_coverage:
                oracle_passed = False
                errors.append(
                    "Oracle classification required but no oracle coverage was reported"
                )
            else:
                for name, coverage in oracle_coverage.items():
                    unmapped = int(coverage.get("unmapped", 0) or 0)
                    if unmapped:
                        oracle_passed = False
                        errors.append(
                            f"{name}: {unmapped} unclassified oracle output(s)"
                        )

    # Overall pass requires regular checks AND oracle checks (if enabled)
    all_passed = result.all_passed and oracle_passed
    oracle_runtime = None
    if args.oracle:
        if policyengine_runtime is None:
            raise PolicyEngineRuntimeError(
                "PolicyEngine validation output requires one admitted runtime identity"
            )
        oracle_runtime = {
            "policyengine": {
                "identity": policyengine_runtime.canonical_identity(),
                "identity_sha256": policyengine_runtime.identity_sha256,
            }
        }

    if args.json:
        return all_passed, {
            "file": str(rulespec_file),
            "ci_pass": result.ci_pass,
            "scores": {
                "rulespec_reviewer": review_scores["rulespec_reviewer"],
                "formula_reviewer": review_scores["formula_reviewer"],
                "parameter_reviewer": review_scores["parameter_reviewer"],
                "integration_reviewer": review_scores["integration_reviewer"],
            },
            "oracle_scores": {
                "policyengine": scores.policyengine_match,
            }
            if args.oracle
            else None,
            "oracle_passed": oracle_passed if args.oracle else None,
            "oracle_issues": oracle_issues,
            "oracle_coverage": oracle_coverage,
            "oracle_runtime": oracle_runtime,
            "all_passed": all_passed,
            "errors": errors,
            "duration_ms": result.total_duration_ms,
        }
    else:
        print(f"File: {rulespec_file}")
        print(f"CI: {'✓' if result.ci_pass else '✗'}")
        if not args.skip_reviewers:
            print(
                "Scores: "
                f"RuleSpec {review_scores['rulespec_reviewer']}/10 | "
                f"Formula {review_scores['formula_reviewer']}/10 | "
                f"Param {review_scores['parameter_reviewer']}/10 | "
                f"Integration {review_scores['integration_reviewer']}/10"
            )
        if args.oracle:
            runtime_provenance = oracle_runtime["policyengine"]
            print(
                "PolicyEngine runtime identity: "
                + json.dumps(
                    runtime_provenance["identity"],
                    sort_keys=True,
                    separators=(",", ":"),
                )
            )
            print(
                "PolicyEngine runtime identity SHA-256: "
                f"{runtime_provenance['identity_sha256']}"
            )
            pe_score = scores.policyengine_match
            min_match = args.min_match
            if pe_score is not None:
                status = "✓" if pe_score >= min_match else "✗"
                print(f"PolicyEngine: {status} {pe_score:.1%} (min: {min_match:.0%})")
            if oracle_coverage:
                for name, coverage in oracle_coverage.items():
                    print(
                        f"{name} coverage: comparable={coverage.get('comparable', 0)} "
                        f"passed={coverage.get('passed', 0)} "
                        f"failed={coverage.get('failed', 0)} "
                        f"unmapped={coverage.get('unmapped', 0)} "
                        f"unsupported={coverage.get('unsupported', 0)}"
                    )
        print(f"Result: {'✓ PASSED' if all_passed else '✗ FAILED'}")
        if errors:
            for err in errors:
                print(f"  - {err}")
        if oracle_issues:
            for name, issues in oracle_issues.items():
                for issue in issues[:10]:
                    print(f"  - {name}: {issue}")
                if len(issues) > 10:
                    print(f"  - {name}: ... {len(issues) - 10} more oracle issue(s)")

    return all_passed, None


def _validation_waiver_module_path(
    module: Path,
    *,
    root: Path,
) -> tuple[Path, str]:
    """Resolve one module using the canonical waiver-schema path contract."""
    return _validation_waivers.resolve_validation_waiver_module(
        root,
        Path(module).as_posix(),
    )


def _validation_waiver_companion_path(module: Path) -> Path:
    """Return the canonical adjacent companion path for a RuleSpec module."""
    return module.with_name(f"{module.stem}.test.yaml")


def _validation_waiver_validate_outcome(result) -> dict[str, Any]:
    """Extract only deterministic, complete failed-validator details."""
    validators: dict[str, dict[str, Any]] = {}
    for name, validation in sorted(result.results.items()):
        if bool(validation.passed):
            continue
        validators[str(name)] = {
            "passed": False,
            "issues": [str(issue) for issue in (validation.issues or [])],
            "error": str(validation.error) if validation.error is not None else None,
        }
    passed = bool(result.all_passed)
    if (passed and validators) or (not passed and not validators):
        raise RuntimeError(
            "ValidatorPipeline returned an inconsistent aggregate validation result"
        )
    return {"passed": passed, "validators": validators}


def _validation_waiver_companion_outcome(
    module: Path,
    *,
    root: Path,
    policy_repo_path: Path,
    binary: Path,
    axiom_rules_path: Path,
    env: dict[str, str],
    rulespec_roots: Sequence[Path],
    tmp_path: Path,
    compiled_cache: dict[Path, tuple[Path, dict]],
) -> dict[str, Any]:
    """Execute an adjacent companion independently, including parse failures."""
    companion = _validation_waiver_companion_path(module)
    relative = companion.relative_to(root).as_posix()
    if companion.is_symlink():
        raise ValueError(f"RuleSpec companion must not be a symlink: {relative}")
    if not companion.exists():
        return {
            "present": False,
            "path": relative,
            "passed": True,
            "cases": 0,
            "failures": [],
        }
    if not companion.is_file():
        raise ValueError(f"RuleSpec companion is not a file: {relative}")

    try:
        result = _execute_rulespec_test_file(
            companion,
            binary=binary,
            axiom_rules_path=axiom_rules_path,
            env=env,
            rulespec_roots=rulespec_roots,
            tmp_path=tmp_path,
            compiled_cache=compiled_cache,
            policy_repo_path=policy_repo_path,
        )
    except (ValueError, yaml.YAMLError) as error:
        result = {
            "cases": 0,
            "compiled": 0,
            "failures": [
                {
                    "file": relative,
                    "case": None,
                    "message": f"{type(error).__name__}: {error}",
                }
            ],
        }
    failures = [
        {
            "file": str(failure.get("file") or relative),
            "case": (str(failure["case"]) if failure.get("case") is not None else None),
            "message": str(failure.get("message") or "companion test failed"),
        }
        for failure in result.get("failures", [])
    ]
    return {
        "present": True,
        "path": relative,
        "passed": not failures,
        "cases": int(result.get("cases", 0) or 0),
        "failures": failures,
    }


def _validation_waiver_path_replacements(
    *,
    root: Path,
    axiom_rules_paths: list[Path],
    binaries: list[Path],
    tmp_path: Path,
    rulespec_roots: Sequence[Path],
    pipelines: list[ValidatorPipeline],
) -> dict[str, str]:
    """Return runtime-specific path prefixes that must not enter a fingerprint."""
    replacements: dict[str, str] = {}

    def add_path(path: str | Path, replacement: str, *, override: bool = False) -> None:
        raw = str(path)
        resolved = str(Path(path).resolve())
        for value in (raw, resolved):
            if override:
                replacements[value] = replacement
            else:
                replacements.setdefault(value, replacement)

    add_path(Path.home(), "<home>")
    add_path(tempfile.gettempdir(), "<system-tmp>")
    for rulespec_root in rulespec_roots:
        add_path(rulespec_root, "<rulespec-root>")
    corpus_paths = {
        str(pipeline.local_corpus_release.root)
        for pipeline in pipelines
        if pipeline.local_corpus_release is not None
    }
    for corpus_path in sorted(path for path in corpus_paths if path):
        add_path(corpus_path, "<corpus>", override=True)
    add_path(Path(__file__).resolve().parents[2], "<encoder>", override=True)
    add_path(root, "<repo>", override=True)
    for axiom_rules_path in axiom_rules_paths:
        add_path(axiom_rules_path, "<engine>", override=True)
    for binary in binaries:
        add_path(binary, "<engine-binary>", override=True)
    add_path(tmp_path, "<tmp>", override=True)
    return dict(sorted(replacements.items(), key=lambda item: (-len(item[0]), item[0])))


def _fingerprint_validation_waiver_modules(
    modules: list[Path],
    *,
    root: Path,
    corpus_path: Path,
    axiom_rules_path: Path,
    rulespec_dependency_roots: Sequence[Path] = (),
) -> list[dict[str, Any]]:
    """Execute validation and companions against one canonical checkout root."""
    root = Path(root).resolve()
    if not root.is_dir():
        raise ValueError(f"RuleSpec repository root does not exist: {root}")

    resolved_modules: dict[str, tuple[Path, Path]] = {}
    for module in modules:
        resolved, relative = _validation_waiver_module_path(module, root=root)
        canonical_root = _canonical_validation_checkout_root(resolved).resolve()
        if canonical_root != root:
            raise ValueError(
                f"waiver root must be the canonical country checkout: {canonical_root}"
            )
        content_root = find_policy_repo_root(resolved)
        if content_root is None or content_root.parent.resolve() != root:
            raise ValueError(
                f"waiver module is not inside one canonical jurisdiction root: {resolved}"
            )
        resolved_modules[relative] = (resolved, content_root)

    engine_root = _resolve_explicit_existing_directory(
        axiom_rules_path,
        label="Axiom rules engine",
    )
    corpus_release = load_rulespec_local_corpus_release(root, corpus_path)
    pipelines = {
        content_root: ValidatorPipeline(
            policy_repo_path=content_root,
            axiom_rules_path=engine_root,
            enable_oracles=False,
            local_corpus_release=corpus_release,
            rulespec_dependency_roots=rulespec_dependency_roots,
        )
        for content_root in sorted(
            {content_root for _module, content_root in resolved_modules.values()}
        )
    }
    if not pipelines:
        return []
    binary = next(iter(pipelines.values()))._axiom_rules_binary()
    engine_envs = {
        content_root: pipeline._rulespec_engine_env()
        for content_root, pipeline in pipelines.items()
    }
    compile_roots = {
        content_root: pipeline._rulespec_compile_roots()
        for content_root, pipeline in pipelines.items()
    }

    fingerprints: list[dict[str, Any]] = []
    with tempfile.TemporaryDirectory() as tmpdir:
        tmp_path = Path(tmpdir)
        compiled_cache: dict[Path, tuple[Path, dict]] = {}
        replacements = _validation_waiver_path_replacements(
            root=root,
            axiom_rules_paths=[engine_root],
            binaries=[binary],
            tmp_path=tmp_path,
            rulespec_roots=tuple(
                dict.fromkeys(
                    root for roots in compile_roots.values() for root in roots
                )
            ),
            pipelines=list(pipelines.values()),
        )
        for relative, (module, content_root) in sorted(resolved_modules.items()):
            pipeline = pipelines[content_root]
            env = engine_envs[content_root]
            rulespec_roots = compile_roots[content_root]
            pipeline_result = pipeline.validate(module, skip_reviewers=True)
            validate_outcome = _validation_waiver_validate_outcome(pipeline_result)
            companion_outcome = _validation_waiver_companion_outcome(
                module,
                root=root,
                policy_repo_path=content_root,
                binary=binary,
                axiom_rules_path=engine_root,
                env=env,
                rulespec_roots=rulespec_roots,
                tmp_path=tmp_path,
                compiled_cache=compiled_cache,
            )
            canonical_bytes = _validation_waivers.canonicalize_outcome(
                validate_outcome,
                companion_outcome,
                replacements=replacements,
            )
            digest = _validation_waivers.fingerprint_outcome(
                validate_outcome,
                companion_outcome,
                replacements=replacements,
            )
            fingerprints.append(
                {
                    "path": relative,
                    "passed": bool(validate_outcome["passed"])
                    and bool(companion_outcome["passed"]),
                    "fingerprint": digest,
                    "outcome": json.loads(canonical_bytes.decode("utf-8")),
                }
            )
    return fingerprints


def _validation_waiver_repo_relative_path(raw: str, *, label: str) -> str:
    """Validate and normalize an opinionated POSIX repository-relative path."""
    value = str(raw)
    if not value:
        raise ValueError(f"{label} must not be empty")
    if _validation_waivers._contains_control_or_format(value):
        raise ValueError(
            f"{label} must not contain control characters or Unicode format "
            f"characters: {raw!r}"
        )
    if value != value.strip():
        raise ValueError(f"{label} must not contain surrounding whitespace: {raw!r}")
    if "\\" in value:
        raise ValueError(f"{label} must use POSIX separators: {raw}")
    if value.startswith("/") or value.endswith("/"):
        raise ValueError(f"{label} must be a canonical repository-relative path: {raw}")
    parts = value.split("/")
    if any(part in {"", ".", ".."} for part in parts):
        raise ValueError(f"{label} must be a canonical repository-relative path: {raw}")
    return "/".join(parts)


def _validation_waiver_changed_paths(path: Path) -> set[str]:
    """Read the strict one-repository-relative-path-per-line transition input."""
    path = Path(path)
    if path.is_symlink() or not path.is_file():
        raise ValueError(f"changed-paths input must be a regular file: {path}")
    changed: set[str] = set()
    for line_number, raw in enumerate(path.read_text().split("\n"), 1):
        if raw == "":
            continue
        changed.add(
            _validation_waiver_repo_relative_path(
                raw,
                label=f"changed path line {line_number}",
            )
        )
    return changed


def _emit_validation_waiver_error(args, error: Exception | str) -> None:
    message = str(error)
    if getattr(args, "json", False):
        print(json.dumps({"success": False, "errors": [message]}, indent=2))
    else:
        print(f"validation-waivers: {message}", file=sys.stderr)


def _cmd_validation_waivers_fingerprint(args) -> int:
    root = Path(args.root).resolve()
    results = _fingerprint_validation_waiver_modules(
        list(args.modules),
        root=root,
        corpus_path=args.corpus_path,
        axiom_rules_path=args.axiom_rules_path,
        rulespec_dependency_roots=_rulespec_dependency_roots_from_args(args),
    )
    if args.json:
        print(
            json.dumps(
                {
                    "success": True,
                    "root": str(root),
                    "modules": results,
                },
                indent=2,
            )
        )
    else:
        for result in results:
            state = "passes" if result["passed"] else "fails"
            print(f"{result['path']}: {result['fingerprint']} ({state})")
    return 0


def _cmd_validation_waivers_active_paths(args) -> int:
    root = Path(args.root).resolve()
    waiver_file = root / _validation_waivers.DEFAULT_WAIVER_PATH
    waivers = _validation_waivers.load_validation_waivers(
        waiver_file,
        repo_root=root,
    )
    paths = sorted(waivers.active_paths)
    if args.json:
        print(json.dumps(paths, indent=2))
    else:
        for path in paths:
            print(path)
    return 0


def _cmd_validation_waivers_audit(args) -> int:
    root = Path(args.root).resolve()
    if not root.is_dir():
        raise ValueError(f"RuleSpec repository root does not exist: {root}")
    waiver_path = _validation_waivers.DEFAULT_WAIVER_PATH
    waiver_file = root / waiver_path

    protected_base_path = getattr(args, "protected_base", None)
    changed_paths_file = getattr(args, "changed_paths", None)
    if protected_base_path is None or changed_paths_file is None:
        raise ValueError("--protected-base and --changed-paths are required")

    head = _validation_waivers.load_validation_waivers(
        waiver_file,
        repo_root=root,
    )
    base = _validation_waivers.load_validation_waivers(
        Path(protected_base_path),
        repo_root=root,
        allow_expired=True,
        require_paths=False,
    )
    changed_paths = _validation_waiver_changed_paths(Path(changed_paths_file))
    transition_issues = _validation_waivers.protected_base_transition_issues(
        base,
        head,
        changed_paths=changed_paths,
        waiver_path=waiver_path,
    )

    if transition_issues:
        report = {
            "success": False,
            "root": str(root),
            "waivers": waiver_path,
            "checked": 0,
            "results": [],
            "errors": list(transition_issues),
        }
        _print_validation_waiver_audit_report(report, as_json=args.json)
        return 1

    active_paths = set(head.active_paths)
    pending_only_paths = set(head.pending_paths) - active_paths
    removed_active_paths = set(base.active_paths) - active_paths
    classified: dict[str, str] = {path: "active" for path in active_paths}
    classified.update({path: "pending" for path in pending_only_paths})
    for path in removed_active_paths:
        classified.setdefault(path, "removed")
    classified = dict(sorted(classified.items()))

    deleted_removed: set[str] = set()
    missing_required: set[str] = set()
    executable_paths: list[Path] = []
    for path, kind in classified.items():
        module = root / path
        if module.is_file():
            executable_paths.append(Path(path))
        elif kind == "removed" and not module.exists() and not module.is_symlink():
            deleted_removed.add(path)
        else:
            missing_required.add(path)

    executed = (
        _fingerprint_validation_waiver_modules(
            executable_paths,
            root=root,
            corpus_path=args.corpus_path,
            axiom_rules_path=args.axiom_rules_path,
            rulespec_dependency_roots=_rulespec_dependency_roots_from_args(args),
        )
        if executable_paths
        else []
    )
    executed_by_path = {result["path"]: result for result in executed}
    results: list[dict[str, Any]] = []
    errors: list[str] = []

    for path, kind in classified.items():
        if path in deleted_removed:
            results.append(
                {
                    "path": path,
                    "kind": kind,
                    "success": True,
                    "module_deleted": True,
                }
            )
            continue
        if path in missing_required:
            message = f"{path}: declared {kind} waiver module does not exist"
            errors.append(message)
            results.append(
                {
                    "path": path,
                    "kind": kind,
                    "success": False,
                    "error": message,
                }
            )
            continue

        actual = executed_by_path[path]
        result_record = {
            "path": path,
            "kind": kind,
            "passed": actual["passed"],
            "fingerprint": actual["fingerprint"],
            "outcome": actual["outcome"],
        }
        error: str | None = None
        if kind == "active":
            expected = head.entries[path].active.fingerprint
            result_record["expected_fingerprint"] = expected
            if actual["passed"]:
                error = f"{path}: active validation waiver is stale; module now passes"
            elif actual["fingerprint"] != expected:
                error = (
                    f"{path}: validation failure fingerprint drifted; expected "
                    f"{expected}, got {actual['fingerprint']}"
                )
        elif kind == "pending" and not actual["passed"]:
            error = f"{path}: pending waiver requires the current module to pass"
        elif kind == "removed" and not actual["passed"]:
            error = f"{path}: removed active waiver still has a failing module"
        result_record["success"] = error is None
        if error is not None:
            result_record["error"] = error
            errors.append(error)
        results.append(result_record)

    report = {
        "success": not errors,
        "root": str(root),
        "waivers": waiver_path,
        "checked": len(results),
        "results": results,
        "errors": errors,
    }
    _print_validation_waiver_audit_report(report, as_json=args.json)
    return 0 if report["success"] else 1


def _print_validation_waiver_audit_report(
    report: dict[str, Any],
    *,
    as_json: bool,
) -> None:
    if as_json:
        print(json.dumps(report, indent=2))
        return
    if report["success"]:
        print(f"Validation waiver audit passed ({report['checked']} path(s) checked)")
        return
    print(
        f"Validation waiver audit failed ({len(report['errors'])} error(s))",
        file=sys.stderr,
    )
    for error in report["errors"]:
        print(f"- {error}", file=sys.stderr)


def cmd_validation_waivers(args) -> None:
    """Dispatch strict validation waiver maintenance and audit commands."""
    try:
        command = args.validation_waivers_command
        if command == "fingerprint":
            exit_code = _cmd_validation_waivers_fingerprint(args)
        elif command == "audit":
            exit_code = _cmd_validation_waivers_audit(args)
        elif command == "active-paths":
            exit_code = _cmd_validation_waivers_active_paths(args)
        else:
            raise ValueError(f"unknown validation-waivers command: {command}")
    except Exception as error:
        _emit_validation_waiver_error(args, error)
        exit_code = 2
    sys.exit(exit_code)


def _money_atom_display_path(file: Path) -> str:
    """Return the canonical checkout-relative path for a RuleSpec module."""
    resolved = file.resolve()
    checkout_root = _canonical_validation_checkout_root(resolved).resolve()
    return resolved.relative_to(checkout_root).as_posix()


def cmd_proof_validate(args):
    """Validate explicit RuleSpec proof trees for one or more files."""
    missing = [file for file in args.files if not file.exists()]
    if missing:
        for file in missing:
            print(f"File not found: {file}")
        sys.exit(1)

    rulespec_files = [file.resolve() for file in args.files]
    for rulespec_file in rulespec_files:
        _canonical_validation_checkout_root(rulespec_file)

    money_atom_files = [
        (
            _money_atom_display_path(rulespec_file),
            rulespec_file.read_text(encoding="utf-8"),
        )
        for rulespec_file in rulespec_files
    ]
    for display_path, content in money_atom_files:
        try:
            payload = yaml.safe_load(content)
        except (yaml.YAMLError, ValueError):
            continue
        identity_issues = find_noncanonical_corpus_citation_path_issues(payload)
        if identity_issues:
            raise ValueError(f"{display_path}: {identity_issues[0]}")

    if getattr(args, "emit_ratchet", False):
        sys.stdout.write(emit_money_atom_ratchet(money_atom_files))
        sys.exit(0)

    money_atoms_only = getattr(args, "money_atoms_only", False)
    require_money_atoms = (
        getattr(args, "require_money_atoms", False) or money_atoms_only
    )
    money_run = None
    if require_money_atoms:
        ratchet = MoneyAtomRatchet.empty()
        ratchet_file = getattr(args, "ratchet_file", None)
        if ratchet_file is not None:
            if not ratchet_file.exists():
                print(f"Ratchet file not found: {ratchet_file}")
                sys.exit(1)
            try:
                ratchet = load_money_atom_ratchet(
                    ratchet_file.read_text(encoding="utf-8")
                )
            except ValueError as exc:
                print(f"Ratchet file invalid: {exc}")
                sys.exit(1)
        money_run = evaluate_money_atoms(money_atom_files, ratchet)

    if money_atoms_only:
        _emit_money_atoms_only(money_run, args.json)
        sys.exit(1 if not money_run.passed else 0)

    corpus_path = Path(args.corpus_path).expanduser()
    releases: dict[Path, LocalCorpusRelease] = {}
    source_text_cache: dict[tuple[str, str], str | None] = {}
    source_error_cache: dict[tuple[str, str], str] = {}

    json_outputs = []
    failed_files = []
    for index, rulespec_file in enumerate(rulespec_files):
        content = money_atom_files[index][1]
        rulespec_root = _canonical_validation_checkout_root(rulespec_file).resolve()
        corpus_release = releases.get(rulespec_root)
        if corpus_release is None:
            corpus_release = load_rulespec_local_corpus_release(
                rulespec_root,
                corpus_path,
            )
            releases[rulespec_root] = corpus_release
        with _authoritative_corpus_scope(corpus_release):
            proof_paths = proof_source_citation_paths(content)
            for citation_path in proof_paths:
                cache_key = (corpus_release.content_sha256, citation_path)
                if cache_key in source_text_cache:
                    continue
                try:
                    source_text_cache[cache_key] = resolve_local_corpus_source(
                        citation_path,
                        corpus_release,
                    ).body
                except CorpusResolutionError as exc:
                    source_text_cache[cache_key] = None
                    source_error_cache[cache_key] = (
                        "Proof corpus resolution failed for "
                        f"`{citation_path}`: {type(exc).__name__}: {exc}"
                    )
            source_texts = {
                citation_path: source_text_cache[
                    (corpus_release.content_sha256, citation_path)
                ]
                for citation_path in proof_paths
            }
            result = validate_rulespec_proofs(
                content,
                source_texts=source_texts,
            )
            resolution_issues = [
                source_error_cache[(corpus_release.content_sha256, citation_path)]
                for citation_path in proof_paths
                if (corpus_release.content_sha256, citation_path) in source_error_cache
            ]
        if resolution_issues:
            result = ProofValidationResult(
                passed=False,
                issues=[*result.issues, *resolution_issues],
                atoms_checked=result.atoms_checked,
                proof_required=result.proof_required,
            )
        if not result.passed:
            failed_files.append(rulespec_file)

        if args.json:
            entry = {
                "file": str(rulespec_file),
                "passed": result.passed,
                "proof_required": result.proof_required,
                "atoms_checked": result.atoms_checked,
                "issues": result.issues,
            }
            if money_run is not None:
                file_result = money_run.files[index]
                entry["money_atoms"] = {
                    "obligations": file_result.obligation_count,
                    "missing": file_result.missing_count,
                    "missing_atoms": [
                        {
                            "rule": obligation.rule_name,
                            "path": obligation.path,
                            "kind": obligation.kind,
                            "reason": obligation.reason,
                        }
                        for obligation in file_result.report.missing
                    ],
                }
            json_outputs.append(entry)
        else:
            if index:
                print()
            print(f"File: {rulespec_file}")
            print(f"Proofs required: {'yes' if result.proof_required else 'no'}")
            print(f"Atoms checked: {result.atoms_checked}")
            print(f"Result: {'✓ PASSED' if result.passed else '✗ FAILED'}")
            for issue in result.issues:
                print(f"  - {issue}")
            if money_run is not None:
                file_result = money_run.files[index]
                print(
                    f"Money atoms: {file_result.missing_count} missing of "
                    f"{file_result.obligation_count} monetary obligation(s)"
                )
                for obligation in file_result.report.missing:
                    print(
                        f"  - missing money proof atom: rule "
                        f"`{obligation.rule_name}` needs a proof atom at "
                        f"`{obligation.path}` ({obligation.reason})."
                    )

    if args.json:
        if len(args.files) == 1:
            print(json.dumps(json_outputs[0], indent=2))
        else:
            print(json.dumps(json_outputs, indent=2))
    elif failed_files and len(args.files) > 1:
        print(f"\n{len(failed_files)} of {len(args.files)} file(s) failed:")
        for file in failed_files:
            print(f"  - {file}")

    money_atoms_over_budget = False
    if money_run is not None and not args.json:
        money_atoms_over_budget = _report_money_atom_verdict(money_run)
    elif money_run is not None:
        money_atoms_over_budget = not money_run.passed

    sys.exit(1 if (failed_files or money_atoms_over_budget) else 0)


def _emit_money_atoms_only(money_run, as_json: bool) -> None:
    """Report only the money-atom result (base proof validation skipped)."""
    if as_json:
        payload = {
            "money_atoms_only": True,
            "passed": money_run.passed,
            "total_obligations": money_run.total_obligations,
            "total_missing": money_run.total_missing,
            "files": [
                {
                    "file": file_result.path,
                    "obligations": file_result.obligation_count,
                    "missing": file_result.missing_count,
                    "missing_atoms": [
                        {
                            "rule": obligation.rule_name,
                            "path": obligation.path,
                            "kind": obligation.kind,
                            "reason": obligation.reason,
                        }
                        for obligation in file_result.report.missing
                    ],
                }
                for file_result in money_run.files
                if file_result.obligation_count
            ],
        }
        print(json.dumps(payload, indent=2))
        return

    for file_result in money_run.files:
        if not file_result.report.missing:
            continue
        print(f"File: {file_result.path}")
        for obligation in file_result.report.missing:
            print(
                f"  - missing money proof atom: rule "
                f"`{obligation.rule_name}` needs a proof atom at "
                f"`{obligation.path}` ({obligation.reason})."
            )
    _report_money_atom_verdict(money_run)


def _report_money_atom_verdict(money_run) -> bool:
    """Print the money-atom ratchet verdict; return True when over budget."""
    print()
    print(
        f"Money-atom summary: {money_run.total_missing} monetary value(s) "
        f"lack a proof atom citing a provision across "
        f"{money_run.total_obligations} monetary obligation(s)."
    )
    if money_run.passed:
        allowance = (
            money_run.ratchet.total_allowed
            if money_run.ratchet.total_allowed is not None
            else 0
        )
        print(f"Money-atom check: ✓ PASSED (within ratchet allowance of {allowance}).")
        return False

    print("Money-atom check: ✗ FAILED (over ratchet allowance).")
    for path, (found, allowed) in sorted(money_run.over_budget_paths.items()):
        print(f"  - {path}: {found} missing money atoms, ratchet allows {allowed}.")
    if money_run.total_over_budget is not None:
        found, allowed = money_run.total_over_budget
        print(
            f"  - repository total (untracked files): {found} missing money "
            f"atoms, ratchet total_allowed is {allowed}."
        )
    print(
        "  Fix: add `metadata.proof.atoms` citing a provision to the monetary "
        "rules above, or raise the ratchet only for a documented backlog."
    )
    return True


def cmd_test(args):
    """Execute companion tests from one exact jurisdiction content root."""
    root = _resolve_explicit_existing_directory(
        args.root,
        label="RuleSpec jurisdiction content root",
    )
    if canonical_rulespec_root_identity(root) is None:
        raise ValueError(
            "--root must be an exact RuleSpec jurisdiction content root "
            "(rulespec-<country>/<jurisdiction>): "
            f"{root}"
        )
    test_files = _discover_rulespec_test_files(args.paths, root=root)
    if not test_files:
        message = f"No RuleSpec companion tests found under {root}"
        if args.json:
            print(
                json.dumps(
                    {
                        "success": False,
                        "root": str(root),
                        "test_files": 0,
                        "cases": 0,
                        "failures": [{"file": None, "case": None, "message": message}],
                    },
                    indent=2,
                )
            )
        else:
            print(message)
        sys.exit(1)

    for test_file in test_files:
        program_file = _rulespec_program_for_test_file(test_file)
        _canonical_validation_checkout_root(program_file)
        canonical_content_root = find_policy_repo_root(program_file)
        if canonical_content_root is None:
            raise ValueError(
                f"RuleSpec module is not inside a canonical country checkout: "
                f"{program_file}"
            )
        canonical_content_root = canonical_content_root.resolve()
        if canonical_content_root != root:
            raise ValueError(
                "--root must be the exact RuleSpec jurisdiction content root: "
                f"{canonical_content_root}"
            )

    axiom_rules_path = _resolve_explicit_existing_directory(
        args.axiom_rules_path,
        label="Axiom rules engine",
    )
    pipeline = ValidatorPipeline(
        policy_repo_path=root,
        axiom_rules_path=axiom_rules_path,
        local_corpus_release=None,
        enable_oracles=False,
        rulespec_dependency_roots=_rulespec_dependency_roots_from_args(args),
    )
    binary = pipeline._axiom_rules_binary()
    rulespec_env = pipeline._rulespec_engine_env()
    rulespec_roots = pipeline._rulespec_compile_roots()

    failures: list[dict[str, str | None]] = []
    case_count = 0
    compiled_count = 0
    with tempfile.TemporaryDirectory() as tmpdir:
        tmp_path = Path(tmpdir)
        compiled_cache: dict[Path, tuple[Path, dict]] = {}
        for test_file in test_files:
            result = _execute_rulespec_test_file(
                test_file,
                binary=binary,
                axiom_rules_path=Path(axiom_rules_path),
                env=rulespec_env,
                rulespec_roots=rulespec_roots,
                tmp_path=tmp_path,
                compiled_cache=compiled_cache,
                policy_repo_path=root,
            )
            case_count += result["cases"]
            compiled_count += result["compiled"]
            failures.extend(result["failures"])

    payload = {
        "success": not failures,
        "root": str(root),
        "test_files": len(test_files),
        "cases": case_count,
        "compiled_programs": compiled_count,
        "failures": failures,
    }
    if args.json:
        print(json.dumps(payload, indent=2, default=str))
    elif failures:
        print(
            f"RuleSpec companion tests failed: "
            f"{len(failures)} failure(s) across {case_count} case(s)"
        )
        for failure in failures[:50]:
            label = failure.get("file") or "<unknown file>"
            case_name = failure.get("case") or "<unknown case>"
            print(f"- {label} :: {case_name} :: {failure.get('message')}")
        if len(failures) > 50:
            print(f"- ... {len(failures) - 50} more failure(s)")
    else:
        print(
            f"RuleSpec companion tests passed: "
            f"{len(test_files)} file(s), {case_count} case(s)"
        )
    sys.exit(0 if not failures else 1)


_RULESPEC_TEST_DISCOVERY_IGNORED_PARTS = frozenset(
    {
        ".git",
        ".mypy_cache",
        ".pytest_cache",
        ".ruff_cache",
        ".venv",
        "__pycache__",
        "_axiom",
        "axiom-rules-engine",
        "node_modules",
    }
)


def _discover_rulespec_test_files(paths: list[Path], *, root: Path) -> list[Path]:
    candidates = paths or [root]
    test_files: list[Path] = []
    for candidate in candidates:
        path = Path(candidate)
        if not path.is_absolute():
            path = (root / path).resolve()
        if path.is_dir():
            test_files.extend(
                file
                for file in path.rglob("*.test.yaml")
                if not _is_ignored_rulespec_test_discovery_path(file, root=root)
            )
        elif _is_rulespec_test_file(
            path
        ) and not _is_ignored_rulespec_test_discovery_path(path, root=root):
            test_files.append(path)
    return sorted(set(test_files))


def _is_ignored_rulespec_test_discovery_path(path: Path, *, root: Path) -> bool:
    try:
        parts = path.resolve().relative_to(root.resolve()).parts
    except ValueError:
        parts = path.parts
    return any(part in _RULESPEC_TEST_DISCOVERY_IGNORED_PARTS for part in parts)


def _is_rulespec_test_file(path: Path) -> bool:
    return path.name.endswith(RULESPEC_TEST_FILE_SUFFIX)


def _rulespec_program_for_test_file(path: Path) -> Path:
    if path.name.endswith(".test.yaml"):
        return path.with_name(path.name.removesuffix(".test.yaml") + ".yaml")
    raise ValueError(f"{path} is not a RuleSpec companion test file")


def _execute_rulespec_test_file(
    test_file: Path,
    *,
    binary: Path,
    axiom_rules_path: Path,
    env: dict[str, str],
    rulespec_roots: Sequence[Path],
    tmp_path: Path,
    compiled_cache: dict[Path, tuple[Path, dict]],
    policy_repo_path: Path | None = None,
) -> dict:
    failures: list[dict[str, str | None]] = []
    program_file = _rulespec_program_for_test_file(test_file)
    if not program_file.exists():
        return {
            "cases": 0,
            "compiled": 0,
            "failures": [
                {
                    "file": str(test_file),
                    "case": None,
                    "message": f"missing adjacent RuleSpec file {program_file}",
                }
            ],
        }

    compiled = compiled_cache.get(program_file)
    compiled_count = 0
    if compiled is None:
        if not rulespec_roots:
            raise ValueError("RuleSpec engine compilation requires an explicit root")
        compile_file = (
            _canonical_rulespec_compile_path(program_file, policy_repo_path)
            if policy_repo_path is not None
            else program_file
        )
        compiled_path = tmp_path / (_safe_artifact_stem(program_file) + ".json")
        result = run_rulespec_compile(
            binary=binary,
            program=compile_file,
            rulespec_roots=rulespec_roots,
            output=compiled_path,
            cwd=axiom_rules_path if axiom_rules_path.exists() else None,
            env=env,
        )
        if result.returncode != 0:
            return {
                "cases": 0,
                "compiled": 0,
                "failures": [
                    {
                        "file": str(test_file),
                        "case": None,
                        "message": result.stderr.strip() or result.stdout.strip(),
                    }
                ],
            }
        artifact = json.loads(compiled_path.read_text())
        compiled_cache[program_file] = (compiled_path, artifact)
        compiled = (compiled_path, artifact)
        compiled_count = 1

    compiled_path, artifact = compiled
    cases = _load_rulespec_test_cases(test_file)
    item_policy_repo_path = (
        policy_repo_path or find_policy_repo_root(program_file) or program_file.parent
    )
    parameter_by_id: dict[str, dict] = {}
    for parameter in artifact.get("program", {}).get("parameters", []):
        if not isinstance(parameter, dict) or not parameter.get("id"):
            continue
        for key in _rulespec_public_item_keys(
            parameter,
            policy_repo_path=item_policy_repo_path,
        ):
            parameter_by_id[key] = parameter
    derived_by_id: dict[str, dict] = {}
    for derived in artifact.get("program", {}).get("derived", []):
        if not isinstance(derived, dict) or not derived.get("id"):
            continue
        for key in _rulespec_public_item_keys(
            derived,
            policy_repo_path=item_policy_repo_path,
        ):
            derived_by_id[key] = derived
    derived_ids = set(derived_by_id)
    declared_relation_names = {
        str(relation.get("name"))
        for relation in artifact.get("program", {}).get("relations", [])
        if isinstance(relation, dict) and relation.get("name")
    }

    for index, case in enumerate(cases):
        case_name = str(case.get("name") or f"case_{index}")
        try:
            failures.extend(
                _execute_rulespec_test_case(
                    test_file,
                    case,
                    case_name=case_name,
                    compiled_path=compiled_path,
                    binary=binary,
                    axiom_rules_path=axiom_rules_path,
                    env=env,
                    parameter_by_id=parameter_by_id,
                    derived_ids=derived_ids,
                    derived_by_id=derived_by_id,
                    declared_relation_names=declared_relation_names,
                    policy_repo_path=item_policy_repo_path,
                )
            )
        except Exception as error:
            failures.append(
                {"file": str(test_file), "case": case_name, "message": str(error)}
            )

    return {"cases": len(cases), "compiled": compiled_count, "failures": failures}


def _load_rulespec_test_cases(path: Path) -> list[dict]:
    data = yaml.safe_load(path.read_text())
    if isinstance(data, list):
        cases = data
    elif isinstance(data, dict) and isinstance(data.get("cases"), list):
        cases = data["cases"]
    else:
        raise ValueError(f"{path} must contain a case list or a mapping with `cases`")
    invalid = [index for index, case in enumerate(cases) if not isinstance(case, dict)]
    if invalid:
        raise ValueError(f"{path} contains non-mapping test case(s): {invalid}")
    return cases


def _execute_rulespec_test_case(
    test_file: Path,
    case: dict,
    *,
    case_name: str,
    compiled_path: Path,
    binary: Path,
    axiom_rules_path: Path,
    env: dict[str, str],
    parameter_by_id: dict[str, dict],
    derived_ids: set[str],
    derived_by_id: dict[str, dict],
    declared_relation_names: set[str],
    policy_repo_path: Path,
) -> list[dict[str, str | None]]:
    failures: list[dict[str, str | None]] = []
    period = _rulespec_period_spec(case.get("period", "2026-01"))
    interval = {"start": period["start"], "end": period["end"]}
    root_entity_id = "case"
    inputs: list[dict] = []
    relations: list[dict] = []
    flat_inputs: dict[str, object] = {}

    for key, value in (case.get("input") or {}).items():
        key = str(key)
        flat_inputs[key] = value
        if isinstance(value, list) and "#relation." in key:
            relation_name = _rulespec_test_relation_request_name(
                key,
                policy_repo_path=policy_repo_path,
            )
            relation_names = [relation_name]
            if "#relation." in relation_name:
                unqualified_name = relation_name.rsplit("#relation.", 1)[1]
                if (
                    unqualified_name
                    and unqualified_name in declared_relation_names
                    and unqualified_name not in relation_names
                ):
                    relation_names.append(unqualified_name)
            for row_index, row in enumerate(value):
                related_id = f"related_{row_index}"
                # The current relation slot convention is related entity first,
                # enclosing entity second.
                for current_relation_name in relation_names:
                    relations.append(
                        {
                            "name": current_relation_name,
                            "tuple": [related_id, root_entity_id],
                            "interval": interval,
                        }
                    )
                if not isinstance(row, dict):
                    failures.append(
                        {
                            "file": str(test_file),
                            "case": case_name,
                            "message": f"relation row for {key} is not a mapping",
                        }
                    )
                    continue
                for row_key, row_value in row.items():
                    inputs.append(
                        {
                            "name": str(row_key),
                            "entity": "Entity",
                            "entity_id": related_id,
                            "interval": interval,
                            "value": _rulespec_scalar_value(row_value),
                        }
                    )
        else:
            inputs.append(
                {
                    "name": key,
                    "entity": "Entity",
                    "entity_id": root_entity_id,
                    "interval": interval,
                    "value": _rulespec_scalar_value(value),
                }
            )

    table_rows_by_entity: dict[str, list[tuple[str, dict]]] = {}
    tables = case.get("tables")
    if tables is not None:
        if not isinstance(tables, dict):
            failures.append(
                {
                    "file": str(test_file),
                    "case": case_name,
                    "message": "`tables` must be a mapping",
                }
            )
            return failures
        for table_entity, rows in tables.items():
            table_entity = str(table_entity)
            if not isinstance(rows, list):
                failures.append(
                    {
                        "file": str(test_file),
                        "case": case_name,
                        "message": f"`tables.{table_entity}` must be a list",
                    }
                )
                return failures
            resolved_rows: list[tuple[str, dict]] = []
            for row_index, row in enumerate(rows, 1):
                if not isinstance(row, dict):
                    failures.append(
                        {
                            "file": str(test_file),
                            "case": case_name,
                            "message": (
                                f"`tables.{table_entity}` row #{row_index} "
                                "must be a mapping"
                            ),
                        }
                    )
                    return failures
                row_id = _rulespec_table_row_entity_id(table_entity, row, row_index)
                resolved_rows.append((row_id, row))
                for row_key, row_value in row.items():
                    key = str(row_key)
                    flat_inputs[key] = row_value
                    inputs.append(
                        {
                            "name": key,
                            "entity": table_entity,
                            "entity_id": row_id,
                            "interval": interval,
                            "value": _rulespec_scalar_value(row_value),
                        }
                    )
            table_rows_by_entity[table_entity] = resolved_rows

    expected = case.get("output") or {}
    parameter_expected = {
        str(key): value
        for key, value in expected.items()
        if str(key) in parameter_by_id
    }
    derived_expected = {
        str(key): value
        for key, value in expected.items()
        if str(key) not in parameter_by_id
    }

    for output, expected_value in parameter_expected.items():
        try:
            actual_value = _rulespec_parameter_value(
                parameter_by_id[output], flat_inputs, period["start"]
            )
        except Exception as error:
            failures.append(
                {
                    "file": str(test_file),
                    "case": case_name,
                    "message": f"{output}: {error}",
                }
            )
            continue
        if not _rulespec_scalar_matches(actual_value, expected_value):
            failures.append(
                {
                    "file": str(test_file),
                    "case": case_name,
                    "message": (
                        f"{output}: expected {expected_value!r}, got {actual_value!r}"
                    ),
                }
            )

    unknown = [output for output in derived_expected if output not in derived_ids]
    for output in unknown:
        failures.append(
            {
                "file": str(test_file),
                "case": case_name,
                "message": f"unknown executable output {output}",
            }
        )
    derived_expected = {
        output: value
        for output, value in derived_expected.items()
        if output in derived_ids
    }
    if not derived_expected:
        return failures

    output_entities = {
        output: str(derived_by_id.get(output, {}).get("entity") or "Case")
        for output in derived_expected
    }
    list_outputs = {
        output
        for output, expected_value in derived_expected.items()
        if isinstance(expected_value, list)
    }
    query_entity = (
        output_entities[next(iter(list_outputs))]
        if list_outputs
        else output_entities[next(iter(derived_expected))]
    )
    if any(output_entities[output] != query_entity for output in list_outputs):
        failures.append(
            {
                "file": str(test_file),
                "case": case_name,
                "message": "row-ordered outputs must use one entity type",
            }
        )
        return failures
    table_rows = table_rows_by_entity.get(query_entity, [])
    query_entity_ids = [root_entity_id]
    if table_rows:
        query_entity_ids = [row_id for row_id, _row in table_rows]
        for output in list_outputs:
            expected_value = derived_expected[output]
            if len(expected_value) != len(table_rows):
                failures.append(
                    {
                        "file": str(test_file),
                        "case": case_name,
                        "message": (
                            f"{output}: expected {len(expected_value)} row "
                            f"value(s), but tables.{query_entity} has "
                            f"{len(table_rows)} row(s)"
                        ),
                    }
                )
                return failures
    elif list_outputs:
        failures.append(
            {
                "file": str(test_file),
                "case": case_name,
                "message": (
                    f"row-ordered output list requires `tables.{query_entity}` rows"
                ),
            }
        )
        return failures

    runtime_output_by_expected = {
        output: str(derived_by_id.get(output, {}).get("id") or output)
        for output in derived_expected
    }
    request = {
        "mode": "explain",
        "dataset": {"inputs": inputs, "relations": relations},
        "queries": [
            {
                "entity_id": entity_id,
                "period": period,
                "outputs": list(runtime_output_by_expected.values()),
            }
            for entity_id in query_entity_ids
        ],
    }
    result = subprocess.run(
        [str(binary), "run-compiled", "--artifact", str(compiled_path)],
        input=json.dumps(request),
        capture_output=True,
        text=True,
        timeout=60,
        cwd=str(axiom_rules_path) if axiom_rules_path.exists() else None,
        env=env,
    )
    if result.returncode != 0:
        message = result.stderr.strip() or result.stdout.strip()
        failures.append(
            {
                "file": str(test_file),
                "case": case_name,
                "message": _translate_rulespec_engine_envelope_error(message),
            }
        )
        return failures

    results = json.loads(result.stdout)["results"]
    for output, expected_value in derived_expected.items():
        if isinstance(expected_value, list):
            for row_index, row_expected_value in enumerate(expected_value):
                outputs = results[row_index]["outputs"]
                runtime_output = runtime_output_by_expected[output]
                actual = outputs.get(output) or outputs.get(runtime_output)
                if actual is None:
                    failures.append(
                        {
                            "file": str(test_file),
                            "case": case_name,
                            "message": (
                                f"missing output {output}; got {sorted(outputs)}"
                            ),
                        }
                    )
                elif not _rulespec_output_matches(actual, row_expected_value):
                    failures.append(
                        {
                            "file": str(test_file),
                            "case": case_name,
                            "message": (
                                f"{output}[{row_index}]: expected "
                                f"{row_expected_value!r}, got {actual!r}"
                            ),
                        }
                    )
            continue
        outputs = results[0]["outputs"]
        runtime_output = runtime_output_by_expected[output]
        actual = outputs.get(output) or outputs.get(runtime_output)
        if actual is None:
            failures.append(
                {
                    "file": str(test_file),
                    "case": case_name,
                    "message": f"missing output {output}; got {sorted(outputs)}",
                }
            )
        elif not _rulespec_output_matches(actual, expected_value):
            failures.append(
                {
                    "file": str(test_file),
                    "case": case_name,
                    "message": f"{output}: expected {expected_value!r}, got {actual!r}",
                }
            )
    return failures


def _rulespec_test_relation_request_name(
    key: str,
    *,
    policy_repo_path: Path,
) -> str:
    return key


def _safe_artifact_stem(path: Path) -> str:
    return re.sub(r"[^A-Za-z0-9_.-]+", "_", str(path.resolve()))


def _rulespec_table_row_entity_id(
    table_entity: str,
    row: dict,
    index: int,
) -> str:
    entity_key = f"{_snake_case(table_entity)}_id"
    for key in ("entity_id", "id", entity_key):
        if key in row:
            return str(row[key])
    return f"{_snake_case(table_entity)}-{index}"


def _snake_case(value: str) -> str:
    first = re.sub(r"(.)([A-Z][a-z]+)", r"\1_\2", value)
    second = re.sub(r"([a-z0-9])([A-Z])", r"\1_\2", first)
    return re.sub(r"[^a-zA-Z0-9]+", "_", second).strip("_").lower()


def _rulespec_period_spec(value) -> dict[str, str]:
    if isinstance(value, dict):
        start = value.get("start")
        end = value.get("end")
        period = {
            "period_kind": str(value.get("period_kind", "period")),
            "start": start.isoformat() if hasattr(start, "isoformat") else str(start),
            "end": end.isoformat() if hasattr(end, "isoformat") else str(end),
        }
        if period["period_kind"] == "custom" and value.get("name") is not None:
            period["name"] = str(value["name"])
        return _validate_rulespec_period_spec(period)
    if isinstance(value, int) or (
        isinstance(value, str) and len(value) == 4 and value.isdigit()
    ):
        year = int(value)
        return _validate_rulespec_period_spec(
            {
                "period_kind": "tax_year",
                "start": f"{year:04d}-01-01",
                "end": f"{year:04d}-12-31",
            }
        )
    if isinstance(value, str) and re.fullmatch(r"\d{4}-\d{2}", value):
        year = int(value[:4])
        month = int(value[5:])
        next_year, next_month = (year + 1, 1) if month == 12 else (year, month + 1)
        next_start = date(next_year, next_month, 1)
        end = date.fromordinal(next_start.toordinal() - 1)
        return _validate_rulespec_period_spec(
            {
                "period_kind": "month",
                "start": f"{year:04d}-{month:02d}-01",
                "end": end.isoformat(),
            }
        )
    if isinstance(value, date):
        return _validate_rulespec_period_spec(
            {
                "period_kind": "day",
                "start": value.isoformat(),
                "end": value.isoformat(),
            }
        )
    raise ValueError(f"unsupported period shorthand: {value!r}")


# Axiom rules engine `PeriodKind` variants, as exposed by serde during the
# rulespec-dk#2 fixture failure. The engine is an external checkout, not vendored here.
_RULESPEC_ENGINE_PERIOD_KINDS = (
    "month",
    "benefit_week",
    "tax_year",
    "custom",
)


def _validate_rulespec_period_spec(period: dict[str, str]) -> dict[str, str]:
    period_kind = period["period_kind"]
    if period_kind not in _RULESPEC_ENGINE_PERIOD_KINDS:
        accepted = "|".join(_RULESPEC_ENGINE_PERIOD_KINDS)
        raise ValueError(
            f"period.period_kind: {period_kind!r} is not one of {accepted}"
        )
    return period


_SERDE_ENVELOPE_SCHEMA_ERROR_SIGNATURES = (
    r"unknown variant `[^`]+`, expected [^\r\n]+",
    r"unknown field `[^`]+`, expected [^\r\n]+",
    r"missing field `[^`]+`",
    r"duplicate field `[^`]+`",
    r"invalid type: [^\r\n]+, expected [^\r\n]+",
    r"invalid value: [^\r\n]+, expected [^\r\n]+",
    r"invalid length \d+, expected [^\r\n]+",
)
_SERDE_ENVELOPE_SCHEMA_ERROR = re.compile(
    "|".join(
        f"(?:{signature})" for signature in _SERDE_ENVELOPE_SCHEMA_ERROR_SIGNATURES
    ),
    re.IGNORECASE,
)
_SERDE_JSON_COORDINATES = re.compile(r"[ \t]+at line \d+ column \d+")


def _translate_rulespec_engine_envelope_error(message: str) -> str:
    """Replace internal-JSON coordinates on recognized serde envelope errors."""
    if not _SERDE_ENVELOPE_SCHEMA_ERROR.search(message):
        return message
    cleaned = _SERDE_JSON_COORDINATES.sub("", message)
    if cleaned == message:
        return message
    return (
        f"{cleaned} (the engine envelope is generated; check the companion "
        "fixture fields)"
    )


def _rulespec_scalar_value(value) -> dict:
    if isinstance(value, bool):
        return {"kind": "bool", "value": value}
    if isinstance(value, int):
        return {"kind": "integer", "value": value}
    if isinstance(value, float):
        return {"kind": "decimal", "value": str(value)}
    if isinstance(value, date):
        return {"kind": "date", "value": value.isoformat()}
    if isinstance(value, str):
        if re.fullmatch(r"\d{4}-\d{2}-\d{2}", value):
            return {"kind": "date", "value": value}
        return {"kind": "text", "value": value}
    raise ValueError(f"unsupported scalar value: {value!r}")


def _rulespec_parameter_value(
    parameter: dict, case_inputs: dict[str, object], period_start: str
) -> dict:
    versions = sorted(
        parameter.get("versions") or [], key=lambda item: str(item["effective_from"])
    )
    chosen = None
    for version in versions:
        if str(version["effective_from"]) <= period_start:
            chosen = version
    if chosen is None:
        if not versions:
            raise KeyError("no parameter versions")
        chosen = versions[0]
    values = chosen.get("values") or {}
    key = "0"
    indexed_by = parameter.get("indexed_by")
    if indexed_by:
        raw_index = _rulespec_case_input_value(case_inputs, indexed_by)
        if raw_index is None:
            raise KeyError(f"missing parameter index input {indexed_by}")
        if isinstance(raw_index, (int, float)) and not isinstance(raw_index, bool):
            key = str(int(raw_index))
        else:
            key = str(raw_index)
    if key not in values:
        raise KeyError(f"missing parameter value key {key}")
    return values[key]


def _rulespec_case_input_value(
    case_inputs: dict[str, object], reference: str
) -> object | None:
    reference = str(reference)
    candidates = [reference]
    fragment = reference.split("#", 1)[-1]
    if not fragment.startswith("input."):
        candidates.append(f"dummy#input.{fragment}")
    for candidate in candidates:
        if candidate in case_inputs:
            return case_inputs[candidate]
    suffix = f"#input.{fragment.removeprefix('input.')}"
    matches = [value for key, value in case_inputs.items() if str(key).endswith(suffix)]
    if len(matches) == 1:
        return matches[0]
    return None


def _rulespec_scalar_matches(actual_value: dict, expected) -> bool:
    kind = actual_value.get("kind")
    value = actual_value.get("value")
    if (
        kind in {"integer", "decimal"}
        and isinstance(expected, (int, float))
        and not isinstance(expected, bool)
    ):
        return abs(Decimal(str(value)) - Decimal(str(expected))) <= Decimal("1e-18")
    if kind == "date" and isinstance(expected, date):
        return value == expected.isoformat()
    if isinstance(expected, date):
        expected = expected.isoformat()
    return value == expected


def _rulespec_output_matches(actual: dict, expected) -> bool:
    if actual.get("kind") == "judgment":
        return actual.get("outcome") == expected
    return _rulespec_scalar_matches(actual.get("value") or {}, expected)


def cmd_program_scope_sync(args):
    """Apply or check one deterministic ProgramSpec scope update."""
    if not args.add and not args.remove:
        raise SystemExit("program-scope-sync requires at least one --add or --remove")
    try:
        result = sync_program_scope(
            repo=args.repo,
            program_spec=args.program_spec,
            scope=args.scope,
            add=args.add,
            remove=args.remove,
            write=not args.check,
        )
    except (OSError, ProgramScopeError) as exc:
        raise SystemExit(f"program-scope-sync failed: {exc}") from exc
    payload = asdict(result)
    if args.json:
        print(json.dumps(payload, indent=2, sort_keys=True))
    else:
        action = (
            "would update"
            if args.check and result.changed
            else ("updated" if result.changed else "unchanged")
        )
        print(f"{action}: {result.program_spec} scope={result.scope}")
    if args.check and result.changed:
        raise SystemExit(1)


def cmd_compile(args):
    """Compile a RuleSpec YAML file with the Axiom rules engine."""
    if not args.file.exists():
        print(f"File not found: {args.file}")
        sys.exit(1)

    try:
        rulespec_file = args.file.resolve()
        policy_repo_path, axiom_rules_path = _resolve_validation_repo_roots(
            rulespec_file,
            args.axiom_rules_path,
        )
        pipeline = ValidatorPipeline(
            policy_repo_path=policy_repo_path,
            axiom_rules_path=axiom_rules_path,
            local_corpus_release=None,
            enable_oracles=False,
            rulespec_dependency_roots=_rulespec_dependency_roots_from_args(args),
        )

        with tempfile.TemporaryDirectory() as tmpdir:
            output_path = Path(tmpdir) / "compiled.json"
            result, compiled = pipeline._compile_rulespec_to_artifact(
                rulespec_file,
                output_path,
            )
            if result.returncode != 0:
                raise RuntimeError(result.stderr.strip() or result.stdout.strip())
            if compiled is None:
                raise RuntimeError("RuleSpec compile returned no artifact payload")

        program = compiled.get("program") if isinstance(compiled, dict) else {}
        if not isinstance(program, dict):
            program = {}
        rule_names = [
            item.get("name")
            for key in ("parameters", "derived", "relations")
            for item in (program.get(key) or [])
            if isinstance(item, dict) and item.get("name")
        ]

        if args.json:
            output = {
                "success": True,
                "file": str(rulespec_file),
                "axiom_rules_path": str(axiom_rules_path),
                "rules": rule_names,
                "rule_count": len(rule_names),
            }
            print(json.dumps(output, indent=2, default=str))
        else:
            print(f"Compiled: {rulespec_file}")
            print(f"Axiom rules engine: {axiom_rules_path}")
            print(f"Rules: {len(rule_names)}")
            for name in rule_names:
                print(f"  - {name}")
            print("\nResult: compiled successfully")

        sys.exit(0)

    except Exception as e:
        if args.json:
            output = {
                "success": False,
                "file": str(args.file.resolve()),
                "error": str(e),
            }
            print(json.dumps(output, indent=2))
        else:
            print(f"Compilation failed: {e}")

        sys.exit(1)


def cmd_log(args):
    """Log an encoding run."""
    db = EncodingDB(args.db)

    # Parse errors
    errors_data = json.loads(args.errors) if args.errors else []
    iteration_errors = [
        IterationError(
            error_type=e.get("type", "other"),
            message=e.get("message", ""),
            variable=e.get("variable"),
            fix_applied=e.get("fix"),
        )
        for e in errors_data
    ]

    # Build iterations (simplified: all errors in iteration 1, success in last)
    iterations = []
    for i in range(1, args.iterations + 1):
        is_last = i == args.iterations
        iterations.append(
            Iteration(
                attempt=i,
                duration_ms=args.duration // args.iterations,
                errors=iteration_errors if i == 1 else [],
                success=is_last,
            )
        )

    # Parse review results from --scores.
    review_results = None
    if args.scores:
        s = json.loads(args.scores)
        reviews = []
        for reviewer_name, key in [
            ("rulespec_reviewer", "rulespec"),
            ("formula_reviewer", "formula"),
            ("parameter_reviewer", "param"),
            ("integration_reviewer", "integration"),
        ]:
            score = float(s.get(key, 0))
            reviews.append(
                ReviewResult(
                    reviewer=reviewer_name,
                    passed=score >= 7.0,
                    items_checked=10,
                    items_passed=int(score),
                )
            )
        review_results = ReviewResults(reviews=reviews)

    # Read RuleSpec content.
    rulespec_content = ""
    if args.file.exists():
        rulespec_content = args.file.read_text()

    run = EncodingRun(
        citation=args.citation,
        file_path=str(args.file),
        review_results=review_results,
        iterations=iterations,
        total_duration_ms=args.duration,
        rulespec_content=rulespec_content,
        session_id=args.session,
    )

    db.log_run(run)

    print(f"Logged: {run.id}")
    print(f"  Citation: {args.citation}")
    print(f"  Iterations: {args.iterations}")
    print(f"  Duration: {args.duration}ms")
    if args.session:
        print(f"  Session: {args.session}")
    if review_results:
        passed = sum(1 for r in review_results.reviews if r.passed)
        total = len(review_results.reviews)
        print(f"  Reviews: {passed}/{total} passed")


def cmd_stats(args):
    """Show encoding statistics."""
    if not args.db.exists():
        print(f"Database not found: {args.db}")
        print("Run some encodings first to collect data.")
        sys.exit(1)

    db = EncodingDB(args.db)

    # Iteration stats
    iter_stats = db.get_iteration_stats()
    print("=== Iteration Statistics ===")
    print(f"Total runs: {iter_stats['total_runs']}")
    print(f"Average iterations: {iter_stats['average']:.1f}")
    print(f"First-try success rate: {iter_stats['first_try_rate']:.0f}%")
    print(f"Distribution: {iter_stats['distribution']}")
    print()

    # Error stats
    error_stats = db.get_error_stats()
    print("=== Error Statistics ===")
    print(f"Total errors: {error_stats['total_errors']}")
    if error_stats["counts"]:
        print("By type:")
        for error_type, count in sorted(
            error_stats["counts"].items(), key=lambda x: -x[1]
        ):
            pct = error_stats["percentages"][error_type]
            print(f"  {error_type}: {count} ({pct:.0f}%)")
    print()

    # Improvement suggestions
    print("=== Improvement Suggestions ===")
    if error_stats["counts"]:
        top_error = max(error_stats["counts"].items(), key=lambda x: x[1])
        print(f"Focus on: {top_error[0]} errors ({top_error[1]} occurrences)")
        if top_error[0] == "test":
            print("  → Add more RuleSpec test examples")
        elif top_error[0] == "parse":
            print("  → Clarify RuleSpec syntax")
        elif top_error[0] == "import":
            print("  → Document import patterns better")
    else:
        print("Not enough data yet. Run more encodings.")


