def _proof_atom_kind_normalization_module_paths(checkout: Path) -> list[Path]:
    """Select primary atomic modules without validating unrelated checkout YAML."""
    modules: list[Path] = []
    country = checkout.name.removeprefix("rulespec-")
    jurisdiction_pattern = re.compile(rf"{re.escape(country)}(?:-[a-z0-9]+)*")
    for child in checkout.iterdir():
        if child.is_symlink() and jurisdiction_pattern.fullmatch(child.name):
            raise ValueError(
                f"RuleSpec jurisdiction root must not be a symlink: {child}"
            )
    jurisdiction_names = jurisdiction_subdir_names(
        checkout, allow_composition_specs=True
    )
    for jurisdiction_name in sorted(jurisdiction_names):
        content_root = checkout / jurisdiction_name
        for root_name in sorted(RULESPEC_ATOMIC_MODULE_ROOTS):
            module_root = content_root / root_name
            if module_root.is_symlink():
                raise ValueError(
                    f"RuleSpec atomic module root must not be a symlink: {module_root}"
                )
            if not module_root.exists():
                continue
            if not module_root.is_dir():
                raise ValueError(
                    f"RuleSpec atomic module root must be a directory: {module_root}"
                )
            for candidate in sorted(module_root.rglob("*")):
                if candidate.is_symlink():
                    raise ValueError(
                        f"RuleSpec atomic module content must not contain symlinks: "
                        f"{candidate}"
                    )
                if (
                    candidate.is_file()
                    and candidate.suffix == RULESPEC_FILE_SUFFIX
                    and not candidate.name.endswith(RULESPEC_TEST_FILE_SUFFIX)
                ):
                    modules.append(candidate)
    return modules


def build_proof_atom_kind_normalization_report(root: Path) -> dict[str, object]:
    """Normalize repairable proof kinds across one canonical RuleSpec checkout."""
    checkout = _resolve_canonical_rulespec_checkout(Path(root))
    modules = _proof_atom_kind_normalization_module_paths(checkout)
    repairs: list[dict[str, object]] = []
    unclassified: list[dict[str, object]] = []
    errors: list[dict[str, str]] = []
    changed_files: set[str] = set()

    for rules_file in modules:
        relative_path = rules_file.relative_to(checkout).as_posix()
        result = _normalize_invalid_proof_atom_kinds_file(rules_file)
        if result.error is not None:
            errors.append({"path": relative_path, "error": result.error})
        if result.repairs:
            changed_files.add(relative_path)
        for repair in result.repairs:
            repairs.append(
                {
                    "path": relative_path,
                    "rule": repair.rule,
                    "atom_index": repair.atom_index,
                    "old_kind": repair.old_kind,
                    "new_kind": repair.new_kind,
                }
            )
        for issue in result.unclassified:
            unclassified.append(
                {
                    "path": relative_path,
                    "rule": issue.rule,
                    "atom_index": issue.atom_index,
                    "kind": "custom",
                    "reason": issue.reason,
                }
            )

    return {
        "root": str(checkout),
        "files_scanned": len(modules),
        "files_changed": len(changed_files),
        "repair_count": len(repairs),
        "unclassified_count": len(unclassified),
        "error_count": len(errors),
        "repairs": repairs,
        "unclassified": unclassified,
        "errors": errors,
    }


def cmd_normalize_proof_atom_kinds(args) -> None:
    """Rewrite only classifiable invalid proof atom kinds in existing modules."""
    try:
        report = build_proof_atom_kind_normalization_report(args.root)
    except ValueError as exc:
        print(f"Proof atom kind normalization error: {exc}", file=sys.stderr)
        raise SystemExit(1) from exc
    if args.json:
        print(json.dumps(report, indent=2, sort_keys=True))
    else:
        print("Proof atom kind normalization")
        print(f"Root: {report['root']}")
        print(
            f"Files: {report['files_scanned']} scanned; "
            f"{report['files_changed']} changed"
        )
        print(f"Repairs: {report['repair_count']}")
        for repair in report["repairs"]:
            print(
                f"  {repair['path']}: {repair['rule']}[{repair['atom_index']}]:"
                f"{repair['old_kind']}->{repair['new_kind']}"
            )
        print(f"Unclassified custom atoms: {report['unclassified_count']}")
        for issue in report["unclassified"]:
            print(
                f"  {issue['path']}: {issue['rule']}[{issue['atom_index']}]: "
                f"{issue['reason']}"
            )
        print(f"File errors: {report['error_count']}")
        for error in report["errors"]:
            print(f"  {error['path']}: {error['error']}")

    if report["unclassified_count"] or report["error_count"]:
        sys.exit(1)


def _rulespec_module_paths(checkout: Path) -> list[Path]:
    """Return only atomic modules from one explicit country checkout."""

    checkout = _resolve_canonical_rulespec_checkout(checkout)
    flat_roots = [checkout / root for root in sorted(RULESPEC_ATOMIC_MODULE_ROOTS)]
    invalid_flat_roots = [
        path for path in flat_roots if path.exists() or path.is_symlink()
    ]
    if invalid_flat_roots:
        raise ValueError(
            "RuleSpec checkout contains repository-root atomic content; atomic roots must "
            "live under rulespec-<country>/<jurisdiction>/<content-root>: "
            + ", ".join(str(path) for path in invalid_flat_roots)
        )

    country = checkout.name.removeprefix("rulespec-")
    jurisdiction_pattern = re.compile(rf"{re.escape(country)}(?:-[a-z0-9]+)*")
    modules: list[Path] = []
    for content_root in sorted(checkout.iterdir()):
        if content_root.is_symlink():
            raise ValueError(
                f"RuleSpec checkout content must not contain symlinks: {content_root}"
            )
        root_markers = [
            content_root / root_name
            for root_name in sorted(RULESPEC_FILESYSTEM_ROOTS)
            if (content_root / root_name).exists()
            or (content_root / root_name).is_symlink()
        ]
        if jurisdiction_pattern.fullmatch(content_root.name) is None:
            if root_markers:
                raise ValueError(
                    "RuleSpec content roots must be under a matching direct "
                    f"jurisdiction directory: {content_root}"
                )
            continue
        if not content_root.is_dir():
            raise ValueError(
                "RuleSpec jurisdiction roots must be regular direct directories: "
                f"{content_root}"
            )
        if canonical_rulespec_root_identity(content_root) is None:
            raise ValueError(f"Noncanonical RuleSpec jurisdiction root: {content_root}")
        for candidate in sorted(content_root.rglob("*")):
            if candidate.is_symlink():
                raise ValueError(
                    f"RuleSpec content must not contain symlinks: {candidate}"
                )
            if not candidate.is_file():
                continue
            relative = candidate.relative_to(content_root)
            yaml_like = candidate.suffix.lower() in {".yaml", ".yml"}
            if yaml_like and candidate.suffix != RULESPEC_FILE_SUFFIX:
                raise ValueError(
                    f"RuleSpec content must use the exact .yaml extension: {candidate}"
                )
            if candidate.suffix != RULESPEC_FILE_SUFFIX:
                continue
            if not relative.parts or relative.parts[0] not in RULESPEC_FILESYSTEM_ROOTS:
                raise ValueError(
                    "RuleSpec YAML must be beneath exactly one canonical filesystem "
                    f"root {sorted(RULESPEC_FILESYSTEM_ROOTS)}: {candidate}"
                )
            if relative.parts[0] not in RULESPEC_ATOMIC_MODULE_ROOTS:
                continue
            if candidate.name.endswith(RULESPEC_TEST_FILE_SUFFIX):
                continue
            modules.append(candidate)
    return modules


def _module_corpus_citations(checkout: Path):
    """Yield RuleSpec module paths and declared corpus citations."""
    for path in _rulespec_module_paths(checkout):
        try:
            payload = yaml.safe_load(path.read_text(encoding="utf-8"))
        except (OSError, UnicodeError, yaml.YAMLError) as exc:
            yield path, None, "invalid-rulespec", str(exc)
            continue
        if not isinstance(payload, dict) or payload.get("format") != "rulespec/v1":
            yield (
                path,
                None,
                "invalid-rulespec",
                "protected RuleSpec must declare format: rulespec/v1",
            )
            continue
        plural_issues = find_plural_corpus_citation_path_issues(payload)
        if plural_issues:
            yield path, None, "invalid-rulespec", "; ".join(plural_issues)
            continue
        module = payload.get("module")
        verification = (
            module.get("source_verification") if isinstance(module, dict) else None
        )
        if not isinstance(verification, dict):
            yield (
                path,
                None,
                "invalid-rulespec",
                "module.source_verification must be an object",
            )
            continue
        singular = verification.get("corpus_citation_path")
        if not isinstance(singular, str) or not singular:
            yield (
                path,
                None,
                "invalid-rulespec",
                "module.source_verification.corpus_citation_path must be one "
                "non-empty string",
            )
            continue
        try:
            canonical = require_canonical_corpus_citation_path(singular)
        except CorpusResolutionError as exc:
            yield path, None, "invalid-rulespec", str(exc)
            continue
        if canonical != singular:
            yield (
                path,
                None,
                "invalid-rulespec",
                "module.source_verification.corpus_citation_path must be "
                "byte-exact canonical identity",
            )
            continue
        yield path, singular, None, None


def _migration_failure_reason(exc: CorpusResolutionError) -> str:
    if isinstance(exc, AmbiguousCorpusSourceError):
        return "duplicated"
    if isinstance(exc, CorpusLayoutError):
        return "missing-layout"
    if isinstance(exc, InactiveCorpusSourceError):
        return "inactive-only"
    if isinstance(exc, CorpusDescendantStructureError):
        return "malformed-descendants"
    if isinstance(exc, CorpusRowStructureError):
        return exc.reason
    if isinstance(exc, CorpusSourceNotFoundError):
        return "absent"
    return "resolution-error"


def _run_migration_inventory(
    checkouts: list[Path],
    corpus_root: Path,
) -> tuple[list[dict[str, str]], dict[Path, LocalCorpusRelease]]:
    """Run one audit bound to each checkout's pinned release object."""

    corpus = Path(corpus_root).expanduser().resolve()
    failures: list[dict[str, str]] = []
    releases: dict[Path, LocalCorpusRelease] = {}
    for raw_checkout in checkouts:
        checkout = _resolve_canonical_rulespec_checkout(
            Path(raw_checkout),
            label="Migration inventory RuleSpec checkout",
        )
        if checkout in releases:
            raise ValueError(
                f"Migration inventory checkout was supplied more than once: {checkout}"
            )
        release = load_rulespec_local_corpus_release(checkout, corpus)
        releases[checkout] = release
        for module_path, citation, scan_reason, detail in _module_corpus_citations(
            checkout
        ):
            relative = module_path.relative_to(checkout).as_posix()
            if scan_reason is not None:
                continue
            assert citation is not None
            try:
                requested = require_canonical_corpus_citation_path(citation)
                if requested != citation:
                    raise CorpusResolutionError(
                        "corpus citation is not byte-exact canonical identity"
                    )
                resolved = resolve_local_corpus_source(
                    requested,
                    release,
                )
            except InvalidCorpusReleaseError:
                raise
            except CorpusResolutionError as exc:
                failures.append(
                    {
                        "checkout": str(checkout),
                        "module": relative,
                        "citation": citation,
                        "release": release.name,
                        "release_content_sha256": release.content_sha256,
                        "reason": _migration_failure_reason(exc),
                        "detail": f"{type(exc).__name__}: {exc}",
                    }
                )
                continue
            if (
                resolved.release_name != release.name
                or resolved.release_content_sha256 != release.content_sha256
            ):
                raise InvalidCorpusReleaseError(
                    f"Release object {release.name!r} changed during "
                    "migration inventory"
                )
            if resolved.citation_path != requested:
                if not resolved.slice_required:
                    raise CorpusResolutionError(
                        "Resolver returned a different corpus path without an "
                        "attested parent slice"
                    )
                failures.append(
                    {
                        "checkout": str(checkout),
                        "module": relative,
                        "citation": citation,
                        "release": release.name,
                        "release_content_sha256": release.content_sha256,
                        "reason": "parent-slice-dependency",
                        "detail": f"resolved through {resolved.citation_path}",
                    }
                )
    for checkout, release in releases.items():
        final_release = load_rulespec_local_corpus_release(checkout, corpus)
        if final_release.content_sha256 != release.content_sha256:
            raise InvalidCorpusReleaseError(
                f"Release object {release.name!r} changed during migration inventory"
            )
    return failures, releases


def migration_inventory(
    checkouts: list[Path], corpus_root: Path
) -> list[dict[str, str]]:
    """Return citations that are not exact under configured named releases."""

    report = _migration_inventory_report(checkouts, corpus_root)
    if not report["complete"]:
        reasons = report["incomplete_scan_reasons"]
        assert isinstance(reasons, list)
        raise ValueError(
            "Migration inventory scan is incomplete:\n"
            + "\n".join(f"- {reason}" for reason in reasons)
        )
    failures = report["failures"]
    assert isinstance(failures, list)
    return failures


def _migration_inventory_report(
    checkouts: list[Path], corpus_root: Path
) -> dict[str, object]:
    """Build the reproducible release-migration census and completeness metadata."""

    failures, releases = _run_migration_inventory(checkouts, corpus_root)
    resolved_checkouts = [
        _resolve_canonical_rulespec_checkout(
            Path(path),
            label="Migration inventory RuleSpec checkout",
        )
        for path in checkouts
    ]
    scanned_modules = 0
    incomplete_rulespec_count = 0
    incomplete_reasons: list[str] = []
    checkout_metadata: list[dict[str, object]] = []
    for checkout in resolved_checkouts:
        module_rows = list(_module_corpus_citations(checkout))
        checkout_module_count = len(_rulespec_module_paths(checkout))
        scanned_modules += checkout_module_count
        if checkout_module_count == 0:
            incomplete_reasons.append(
                f"{checkout}: migration inventory found zero canonical RuleSpec modules"
            )
        for path, _citation, reason, detail in module_rows:
            if reason is not None:
                incomplete_rulespec_count += 1
                incomplete_reasons.append(
                    f"{checkout}:{path.relative_to(checkout)}: {reason}: {detail or ''}"
                )
        rulespec_identity = _rulespec_root_execution_identity(checkout)
        checkout_identity = rulespec_identity["checkout_identity"]
        assert isinstance(checkout_identity, dict)
        checkout_metadata.append(
            {
                "path": str(checkout),
                "checkout_identity": checkout_identity,
                "rulespec_content_sha256": rulespec_identity["content_sha256"],
                "release": releases[checkout].name,
                "release_content_sha256": releases[checkout].content_sha256,
                "release_selector_sha256": releases[checkout].selector_sha256,
            }
        )
        if checkout_identity.get("kind") != "git":
            incomplete_reasons.append(
                f"{checkout}: migration inventory requires a git checkout identity"
            )
    return {
        "failures": failures,
        "count": len(failures),
        "resolution_finding_count": len(failures),
        "scanned_modules": scanned_modules,
        "checkouts": checkout_metadata,
        "releases": {
            str(checkout): {
                "name": release.name,
                "content_sha256": release.content_sha256,
                "selector_sha256": release.selector_sha256,
            }
            for checkout, release in sorted(
                releases.items(), key=lambda item: str(item[0])
            )
        },
        "complete": not incomplete_reasons,
        "incomplete_scan_reasons": incomplete_reasons,
        "incomplete_scan_reason_count": len(incomplete_reasons),
        "incomplete_rulespec_count": incomplete_rulespec_count,
    }


def cmd_migration_inventory(args):
    """Print release-migration failures as JSON or a compact operator table."""
    report = _migration_inventory_report(
        args.checkouts,
        args.corpus_path,
    )
    rows = report["failures"]
    failed = bool(rows) or not report["complete"]
    if args.json:
        print(json.dumps(report, indent=2, sort_keys=True))
        if failed:
            raise SystemExit(1)
        return
    if not report["complete"]:
        print("Migration inventory scan is incomplete.")
        for reason in report["incomplete_scan_reasons"]:
            print(f"- {reason}")
    if not rows and report["complete"]:
        print("No module citation failures under configured release objects.")
        return
    if rows:
        print(
            "CHECKOUT\tMODULE\tCITATION\tRELEASE\tRELEASE_CONTENT_SHA256"
            "\tREASON\tDETAIL"
        )
        for row in rows:
            print(
                "\t".join(
                    row[key]
                    for key in (
                        "checkout",
                        "module",
                        "citation",
                        "release",
                        "release_content_sha256",
                        "reason",
                        "detail",
                    )
                )
            )
        print(f"{len(rows)} module citation failure(s).")
    raise SystemExit(1)


def cmd_migration_cascade_proof_hashes(args) -> int:
    """Audit or apply proof hashes caused by an exact ancestor migration."""
    if args.apply and args.report is None:
        print("--report is required with --apply", file=sys.stderr)
        return 2
    if args.check and args.report is not None:
        print("--report is only valid with --apply", file=sys.stderr)
        return 2
    try:
        plan = build_proof_hash_cascade_plan(args.root, args.base_ref)
        if args.check:
            print(render_proof_hash_cascade_plan(plan, as_json=args.json))
            return 1 if plan.eligible else 0
        payload = apply_proof_hash_cascade(plan, args.report)
    except (OSError, ValueError, yaml.YAMLError) as exc:
        print(f"proof hash cascade failed: {exc}", file=sys.stderr)
        return 2
    if args.json:
        print(json.dumps(payload, indent=2, sort_keys=True))
    else:
        print(f"eligible_replacements={payload['eligible_replacements']}")
        print(f"ignored_mismatches={payload['ignored_mismatches']}")
        print(f"applied_files={len(payload['applied_files'])}")
        print(f"report={args.report}")
    return 0


