def _pending_sync_authorized_prefixes(
    root: Path,
) -> tuple[tuple[str, ...], tuple[str, ...]]:
    """Return new-entry and existing legacy report path prefixes."""

    nested_checkout = root / root.name
    if nested_checkout.is_dir() and not nested_checkout.is_symlink():
        content_checkout = nested_checkout
        display_prefix = f"{root.name}/"
        country = root.name.removeprefix("rulespec-")
        jurisdictions = sorted(
            child.name
            for child in content_checkout.iterdir()
            if child.is_dir()
            and not child.is_symlink()
            and re.fullmatch(rf"{re.escape(country)}(?:-[a-z0-9]+)*", child.name)
        )
    else:
        content_checkout = root
        display_prefix = ""
        country = root.name.removeprefix("rulespec-")
        jurisdictions = sorted(
            jurisdiction_subdir_names(root, allow_composition_specs=True)
        )

    prefixes = [
        f"{display_prefix}{jurisdiction}/{module_root}/"
        for jurisdiction in jurisdictions
        for module_root in sorted(RULESPEC_ATOMIC_MODULE_ROOTS)
    ]
    legacy_prefixes = [
        f"{display_prefix}{jurisdiction}/manual/" for jurisdiction in jurisdictions
    ]
    programs_dir = content_checkout / RULESPEC_COMPOSITION_SPEC_ROOT
    if programs_dir.is_dir() and not programs_dir.is_symlink():
        prefixes.extend(
            f"{display_prefix}{RULESPEC_COMPOSITION_SPEC_ROOT}/{child.name}/"
            for child in sorted(programs_dir.iterdir())
            if child.is_dir()
            and not child.is_symlink()
            and re.fullmatch(rf"{re.escape(country)}(?:-[a-z0-9]+)*", child.name)
        )
    return tuple(prefixes), tuple(legacy_prefixes)


def _resolve_composition_rulespec_checkout(raw_path: Path) -> Path:
    """Resolve an exact country checkout while admitting top-level ProgramSpecs."""

    checkout = _resolve_explicit_existing_directory(
        raw_path,
        label="RuleSpec checkout",
    )
    if not is_composition_policy_repo_root(checkout):
        raise ValueError(
            "RuleSpec checkout must be the exact canonical rulespec-<country> "
            f"checkout; got {checkout}"
        )
    return checkout


def cmd_oracle_coverage_pending(args):
    """Check or synchronize one exact checkout's declared-pending ratchet."""
    root = _resolve_composition_rulespec_checkout(args.root)
    if args.pending_command == "sync":
        report = build_policyengine_coverage_report(root)
        authorized_prefixes, existing_legacy_prefixes = (
            _pending_sync_authorized_prefixes(root)
        )
        try:
            existing_pending_ids = set(load_pending_declarations(root))
        except PendingDeclarationError as error:
            print(f"oracle-coverage-pending error: {error}", file=sys.stderr)
            sys.exit(2)

        unmapped = [
            item["legal_id"]
            for item in report.get("items") or []
            if item.get("status") == "unmapped"
            and str(item.get("legal_id") or "").partition(":")[0].split("-", 1)[0]
            == root.name.removeprefix("rulespec-")
            and (
                str(item.get("file") or "").startswith(authorized_prefixes)
                or (
                    item.get("legal_id") in existing_pending_ids
                    and str(item.get("file") or "").startswith(existing_legacy_prefixes)
                )
            )
        ]
        try:
            result = sync_repo_pending(
                repo_root=root,
                unmapped_legal_ids=unmapped,
                source=args.source,
                since=args.since or date.today().isoformat(),
                issue=args.issue,
            )
        except PendingDeclarationError as error:
            print(f"oracle-coverage-pending error: {error}", file=sys.stderr)
            sys.exit(2)
        verb = "Updated" if result["changed"] else "Unchanged"
        print(
            f"{verb} {result['path']}: {result['count']} declared "
            f"(+{len(result['added'])} added, "
            f"-{len(result['dropped'])} drained)."
        )
        sys.exit(0)

    report = build_policyengine_coverage_report(root, program=args.program)
    try:
        files = load_pending_files(root)
        apply_pending_to_report(report, _declarations_or_raise(files))
        problems = ratchet_problems(report, files)
    except PendingDeclarationError as error:
        print(f"oracle-coverage-pending error: {error}", file=sys.stderr)
        sys.exit(2)
    pending = report.get("pending") or {}
    if args.json:
        print(
            json.dumps(
                {"pending": pending, "problems": problems},
                indent=2,
                sort_keys=True,
            )
        )
        sys.exit(1 if problems else 0)
    print("PolicyEngine oracle-coverage pending ratchet")
    print(f"Root: {root}")
    print(
        f"Declared: {pending.get('declared', 0)} "
        f"applied: {len(pending.get('applied') or [])} "
        f"stale: {len(pending.get('stale') or [])}"
    )
    if problems:
        print(f"Pending ratchet failed ({len(problems)}):", file=sys.stderr)
        for problem in problems[:50]:
            print(f"- {problem}", file=sys.stderr)
        if len(problems) > 50:
            print(f"- ... {len(problems) - 50} more", file=sys.stderr)
        sys.exit(1)
    print("Pending ratchet passed.")
    sys.exit(0)


def _declarations_or_raise(files):
    from .oracles.policyengine.pending import declarations_from_files

    return declarations_from_files(files)


def cmd_classify(args):
    """Emit PolicyEngine oracle mappings for a canonical state content root."""
    from axiom_encode.oracles.policyengine.classifier import (
        classify_rulespec_repo,
        emit_us_yaml_block,
    )

    state = args.state.lower()
    if re.fullmatch(r"[a-z]{2}", state) is None:
        print(
            f"--state must be a two-letter state code: {args.state!r}", file=sys.stderr
        )
        sys.exit(1)
    repo = args.repo.resolve()
    expected_identity = f"rulespec-us/us-{state}"
    if canonical_rulespec_root_identity(repo) != expected_identity:
        print(
            "--repo must be the exact canonical state content root "
            f"{expected_identity}: {repo}",
            file=sys.stderr,
        )
        sys.exit(1)

    classifications = classify_rulespec_repo(
        repo_root=repo,
        jurisdiction=f"us-{state}",
        program=args.program,
    )
    block = emit_us_yaml_block(classifications, program=args.program)

    if args.write_us_yaml is None:
        print(block)
        sys.exit(0)

    target = args.write_us_yaml.resolve()
    if not target.is_file():
        print(f"--write-us-yaml target not found: {target}", file=sys.stderr)
        sys.exit(1)

    import re as _re

    text = target.read_text()
    # Remove existing bulk prefix entries for this state (each starts with
    # `legal_id_prefix: us-<state>:` and runs until the next list item or
    # top-level key).
    bulk_pattern = _re.compile(
        rf"^  - legal_id_prefix: us-{state}:.*?(?=^  - |^[a-z]|\Z)",
        _re.MULTILINE | _re.DOTALL,
    )
    text_without_bulk = bulk_pattern.sub("", text)
    text_without_bulk = _re.sub(r"\n{3,}", "\n\n", text_without_bulk)

    appendix = block
    if "prefixes:" in text_without_bulk:
        new_text = text_without_bulk.replace("prefixes:", appendix + "\n\nprefixes:", 1)
    else:
        new_text = text_without_bulk.rstrip() + "\n\n" + appendix + "\n"

    target.write_text(new_text)
    print(
        f"Wrote {len(classifications)} entries for us-{state} to {target} "
        f"(removed bulk legal_id_prefix entries for the same state).",
        file=sys.stderr,
    )
    sys.exit(0)


