def cmd_guard_generated(args):
    """Reject protected RuleSpec changes that lack an apply manifest."""
    repo_path = _resolve_canonical_rulespec_checkout(
        args.repo,
        label="RuleSpec checkout",
    )
    roots = tuple(sorted(RULESPEC_ATOMIC_MODULE_ROOTS))
    all_files = bool(getattr(args, "all", False))
    issues = guard_generated_change_issues(
        repo_path,
        corpus_path=Path(args.corpus_path),
        base_ref=args.base_ref,
        head_ref=args.head_ref,
        roots=roots,
        all_files=all_files,
        expected_encoder_checkout=getattr(args, "expected_encoder_checkout", None),
    )
    payload = {"repo": str(repo_path), "passed": not issues, "issues": issues}
    if args.json:
        print(json.dumps(payload, indent=2))
    elif issues:
        print("Manual RuleSpec changes are not allowed.")
        for issue in issues:
            print(f"- {issue}")
    else:
        if all_files:
            print("All RuleSpec files have encoder apply manifests.")
        else:
            print("All changed RuleSpec files have encoder apply manifests.")
    sys.exit(0 if not issues else 1)


def _manifest_census(
    repo_path: Path,
    *,
    roots: tuple[str, ...],
    expected_encoder_checkout: Path | None = None,
) -> dict[str, object]:
    """Compute model-generated and unmanifested rule-file counts.

    A file is ``encoder`` when a signature-valid manifest with a genuine
    encoder backend (codex/openai/claude) records its current sha256;
    otherwise it is ``unmanifested``. Legacy and unknown manifest backends are
    invalid under the v5 hard cut and never receive a compatibility census
    category. Companion ``.test.yaml`` files are counted alongside their main
    rule file.
    """
    repo_path = _resolve_canonical_rulespec_checkout(repo_path)
    _rulespec_module_paths(repo_path)
    protected = _all_protected_rulespec_yaml_paths(repo_path, roots=roots)
    manifest_paths = _all_applied_encoding_manifest_paths(repo_path, roots=roots)
    surviving = [path for path in manifest_paths if (repo_path / path).exists()]
    try:
        expected_encoder_identity = _read_only_guard_encoder_execution_identity(
            expected_encoder_checkout
        )
    except RuntimeError:
        if expected_encoder_checkout is not None:
            raise
        entries, coverage = {}, {}
    else:
        entries, _issues = _load_applied_encoding_manifest_entries(
            repo_path,
            surviving,
            roots=roots,
            expected_encoder_identity=expected_encoder_identity,
        )
        coverage = _manifest_coverage_by_file(
            repo_path,
            surviving,
            roots=roots,
            expected_encoder_identity=expected_encoder_identity,
        )
    encoder = unmanifested = 0
    unmanifested_paths: list[str] = []
    for path in protected:
        current = repo_path / path
        expected_hashes = entries.get(path)
        covered = bool(
            expected_hashes
            and current.exists()
            and APPLIED_ENCODING_DELETED_MARKER not in expected_hashes
            and _sha256_file(current) in expected_hashes
        )
        if covered and any(
            record["backend"] in APPLIED_ENCODING_ENCODER_BACKENDS
            for record in coverage.get(path, [])
        ):
            encoder += 1
        else:
            unmanifested += 1
            unmanifested_paths.append(path)
    total = len(protected)
    encoder_pct = round(100.0 * encoder / total, 1) if total else 0.0
    return {
        "repo": _repo_census_label(repo_path),
        "roots": list(roots),
        "total": total,
        "encoder": encoder,
        "unmanifested": unmanifested,
        "encoder_pct": encoder_pct,
        "unmanifested_paths": unmanifested_paths,
    }


def _repo_census_label(repo_path: Path) -> str:
    return canonical_rulespec_repo_name(repo_path) or repo_path.name


def _manifest_census_badge(census: dict[str, object]) -> dict[str, object]:
    """Render a Shields endpoint badge JSON for the encoder-generated share."""
    pct = census.get("encoder_pct", 0.0)
    total = census.get("total", 0)
    if not total:
        color = "lightgrey"
    elif isinstance(pct, (int, float)) and pct >= 90:
        color = "brightgreen"
    elif isinstance(pct, (int, float)) and pct >= 50:
        color = "yellow"
    else:
        color = "orange"
    return {
        "schemaVersion": 1,
        "label": "encoder-generated",
        "message": f"{pct}% ({census.get('encoder', 0)}/{total})",
        "color": color,
    }


def cmd_manifest_census(args):
    """Report model-generated / unmanifested coverage."""
    repo_path = _resolve_canonical_rulespec_checkout(
        args.repo,
        label="RuleSpec checkout",
    )
    roots = tuple(sorted(RULESPEC_ATOMIC_MODULE_ROOTS))
    census = _manifest_census(
        repo_path,
        roots=roots,
        expected_encoder_checkout=getattr(args, "expected_encoder_checkout", None),
    )
    census["captured_at"] = (
        datetime.now(timezone.utc).isoformat().replace("+00:00", "Z")
    )
    if getattr(args, "badge", False):
        output = json.dumps(_manifest_census_badge(census), indent=2) + "\n"
    elif getattr(args, "json", False):
        output = json.dumps(census, indent=2, sort_keys=True) + "\n"
    else:
        output = (
            f"{census['repo']}: {census['encoder_pct']}% encoder-generated "
            f"({census['encoder']}/{census['total']}); "
            f"unmanifested={census['unmanifested']}\n"
        )
    out_path = getattr(args, "out", None)
    if out_path is not None:
        out_path = Path(out_path)
        out_path.parent.mkdir(parents=True, exist_ok=True)
        out_path.write_text(output)
        print(f"wrote {out_path}")
    else:
        print(output, end="")


def _run_log_repo_paths(repos_arg):
    """Resolve rulespec repo checkouts to index apply-manifests from."""
    if not repos_arg:
        raise ValueError(
            "run-log-export requires at least one explicit --repos checkout"
        )
    repos = [
        _resolve_canonical_rulespec_checkout(
            Path(repo),
            label="Run-log RuleSpec checkout",
        )
        for repo in repos_arg
    ]
    if len(set(repos)) != len(repos):
        raise ValueError("run-log-export --repos contains a duplicate checkout")
    return repos


def cmd_run_log_spec(args):
    """Print the machine-readable pipeline stage DAG."""
    from .run_log import pipeline_spec_dict

    print(json.dumps(pipeline_spec_dict(), indent=2, sort_keys=True))


def cmd_run_log_export(args):
    """Backfill run-log JSONL from encodings.db + apply-manifests."""
    from .run_log_export import export_backfill

    repos = _run_log_repo_paths(getattr(args, "repos", None))
    report = export_backfill(
        Path(args.db), repos, log_dir=args.log_dir, limit=args.limit
    )
    print(json.dumps(report, indent=2, sort_keys=True))


def cmd_run_log_publish(args):
    """Fold run-log JSONL into committed dashboard artifacts."""
    from .run_log import run_log_dir
    from .run_log_export import publish

    log_dir = args.log_dir or run_log_dir(None)
    meta = publish(log_dir, Path(args.out), max_detail_runs=args.max_detail_runs)
    print(json.dumps(meta, indent=2, sort_keys=True))


def cmd_run_log_staleness(args):
    """Fail (exit 1) when the published run-log has gone stale."""
    from .run_log import run_log_dir
    from .run_log_export import check_staleness

    log_dir = args.log_dir or run_log_dir(None)
    result = check_staleness(Path(args.out), log_dir, max_lag_hours=args.max_lag_hours)
    print(json.dumps(result, indent=2, sort_keys=True))
    if not result["ok"]:
        sys.exit(1)


def _emit_run_log_events_safe(
    result,
    run_id,
    outcome,
    *,
    total_duration_ms: int | None = None,
):
    """Emit run-log events for a just-completed encode run; never fatal.

    Set ``AXIOM_ENCODE_DISABLE_RUN_LOG=1`` to opt out.
    """
    if os.environ.get("AXIOM_ENCODE_DISABLE_RUN_LOG") == "1":
        return
    try:
        from .run_log_export import emit_live_encode_events

        emit_live_encode_events(
            result,
            run_id,
            outcome or {},
            total_duration_ms=total_duration_ms,
        )
    except Exception:  # noqa: BLE001 - run-log emission must never break a run
        pass


