def _colorado_snap_repair_manifest_groups(
    repo_path: Path,
) -> list[tuple[Path, list[Path]]]:
    groups: list[tuple[Path, list[Path]]] = []
    for relative_output in COLORADO_SNAP_REPAIR_RELATIVE_OUTPUTS:
        rules_file = repo_path / relative_output
        test_file = _rulespec_test_path(rules_file)
        files = [rules_file]
        if test_file.exists():
            files.append(test_file)
        groups.append((relative_output, files))
    return groups


def _changed_manifest_group_files(
    repo_path: Path,
    manifest_groups: list[tuple[Path, list[Path]]],
) -> list[Path]:
    changed = set(_git_changed_files(repo_path, base_ref=None, head_ref="HEAD"))
    for base_ref in ("origin/main", "main"):
        try:
            changed.update(
                _git_changed_files(repo_path, base_ref=base_ref, head_ref="HEAD")
            )
            break
        except RuntimeError:
            continue
    repo_prefix = _git_worktree_prefix(repo_path)
    return _unique_paths(
        [
            path
            for _relative_output, files in manifest_groups
            for path in files
            if _manifest_group_file_changed(
                path=path,
                repo_path=repo_path,
                repo_prefix=repo_prefix,
                changed=changed,
            )
        ]
    )


def _git_worktree_prefix(repo_path: Path) -> str:
    completed = subprocess.run(
        ["git", "rev-parse", "--show-prefix"],
        cwd=repo_path,
        text=True,
        stdout=subprocess.PIPE,
        stderr=subprocess.PIPE,
        check=False,
    )
    if completed.returncode != 0:
        return ""
    return completed.stdout.strip().strip("/")


def _manifest_group_file_changed(
    *,
    path: Path,
    repo_path: Path,
    repo_prefix: str,
    changed: set[str],
) -> bool:
    relative_path = path.relative_to(repo_path).as_posix()
    if relative_path in changed:
        return True
    if repo_prefix and f"{repo_prefix}/{relative_path}" in changed:
        return True
    return False


def _verified_current_applied_manifest_payload(
    *,
    repo_path: Path,
    relative_output: Path,
    applied_files: list[Path],
    signing_broker: SigningBroker | Ed25519PublicKey | None = None,
    local_corpus_release: LocalCorpusRelease | None = None,
) -> dict[str, object] | None:
    """Return a canonical current manifest covering exactly ``applied_files``."""

    content_root = _rulespec_apply_content_root(repo_path, relative_output)
    manifest_root, manifest_relative_output = _resolve_applied_manifest_placement(
        content_root=content_root,
        relative_output=relative_output,
    )
    manifest_path = manifest_root / _applied_encoding_manifest_path(
        manifest_relative_output
    )
    if not manifest_path.exists():
        return None
    signing_broker = signing_broker or _applied_encoding_manifest_verifier()
    if not signing_broker:
        return None
    payload, _root_prefix, _manifest_sha256, issues = (
        _load_verified_applied_encoding_manifest_payload(
            manifest_root,
            manifest_path.relative_to(manifest_root).as_posix(),
            signing_broker=signing_broker,
            local_corpus_release=local_corpus_release,
        )
    )
    if issues or payload is None:
        return None
    expected_paths = {
        path.relative_to(manifest_root).as_posix() for path in applied_files
    }
    applied_entries = payload.get("applied_files")
    if not isinstance(applied_entries, list):
        return None
    actual_paths = {
        str(entry.get("path"))
        for entry in applied_entries
        if isinstance(entry, dict)
        and isinstance(entry.get("path"), str)
        and entry.get("deleted") is not True
    }
    return payload if actual_paths == expected_paths else None


def _write_arizona_snap_composition_files(
    rules_file: Path,
    test_file: Path,
) -> list[Path]:
    rules_file.parent.mkdir(parents=True, exist_ok=True)
    changed: list[Path] = []
    rules_content = _arizona_snap_composition_rulespec()
    test_content = _arizona_snap_composition_tests()
    if not rules_file.exists() or rules_file.read_text() != rules_content:
        rules_file.write_text(rules_content)
        changed.append(rules_file)
    if not test_file.exists() or test_file.read_text() != test_content:
        test_file.write_text(test_content)
        changed.append(test_file)
    return changed


