def _applied_manifest_paths_for_files(
    repo_path: Path,
    *,
    relative_files: set[str],
) -> set[str]:
    manifest_paths: set[str] = set()
    if not relative_files:
        return manifest_paths
    try:
        expected_encoder_identity = _current_guard_encoder_execution_identity()
    except RuntimeError:
        return manifest_paths
    for relative_manifest_path in _all_applied_encoding_manifest_paths(repo_path):
        payload, _root_prefix, _manifest_sha256, issues = (
            _load_verified_applied_encoding_manifest_payload(
                repo_path,
                relative_manifest_path,
                expected_encoder_identity=expected_encoder_identity,
            )
        )
        if issues or payload is None:
            continue
        applied_files = payload["applied_files"]
        assert isinstance(applied_files, list)
        if any(
            isinstance(item, dict) and item.get("path") in relative_files
            for item in applied_files
        ):
            manifest_paths.add(relative_manifest_path)
    return manifest_paths


def _prune_unused_imports(content: str) -> tuple[str, list[str]]:
    unused_imports = _unused_import_items(content)
    if not unused_imports:
        return content, []

    unused = set(unused_imports)
    repaired_lines: list[str] = []
    in_imports = False
    imports_indent = 0
    removed: list[str] = []

    for line in content.splitlines(keepends=True):
        imports_match = re.match(r"^(\s*)imports:\s*$", line)
        if imports_match:
            in_imports = True
            imports_indent = len(imports_match.group(1))
            repaired_lines.append(line)
            continue

        if in_imports:
            stripped = line.strip()
            if stripped:
                indent = len(line) - len(line.lstrip())
                item_match = re.match(r"^\s*-\s+(.+?)\s*$", line)
                if item_match and indent >= imports_indent:
                    item = _strip_yaml_scalar_quotes(item_match.group(1).strip())
                    if item in unused:
                        removed.append(item)
                        continue
                elif indent <= imports_indent:
                    in_imports = False

        repaired_lines.append(line)

    return "".join(repaired_lines), removed


def _unused_import_items(content: str) -> list[str]:
    items: list[str] = []
    for issue in find_unused_import_issues(content):
        match = re.search(r"Unused import `([^`]+)`", issue)
        if match:
            items.append(match.group(1))
    return items


def _strip_yaml_scalar_quotes(value: str) -> str:
    if len(value) >= 2 and value[0] == value[-1] and value[0] in {"'", '"'}:
        return value[1:-1]
    return value


GeneratedValidationRepairFunc = Callable[
    [argparse.Namespace],
    list[str],
]


def _generated_validation_repair_policy_repo_path(
    repo_path: Path,
    relative_output: Path,
) -> Path:
    """Require one canonical content root and content-root-relative output."""

    content_root = _resolve_explicit_existing_directory(
        repo_path,
        label="RuleSpec jurisdiction content root",
    )
    if canonical_rulespec_root_identity(content_root) is None:
        raise ValueError(
            "Generated validation repair requires an exact canonical RuleSpec "
            f"jurisdiction content root: {content_root}"
        )
    relative = Path(relative_output)
    if (
        relative.is_absolute()
        or len(relative.parts) < 2
        or any(part in {"", ".", ".."} for part in relative.parts)
        or relative.parts[0] not in RULESPEC_ATOMIC_MODULE_ROOTS
        or relative.suffix != RULESPEC_FILE_SUFFIX
        or relative.name.endswith(RULESPEC_TEST_FILE_SUFFIX)
    ):
        raise ValueError(
            "Generated validation repair output must be a content-root-relative "
            f"primary .yaml path under {sorted(RULESPEC_ATOMIC_MODULE_ROOTS)}: {relative}"
        )
    return content_root


def _try_repair_generated_upstream_placement_duplicates_for_apply(
    result,
    *,
    output_root: Path,
    policy_repo_path: Path,
) -> list[str]:
    try:
        relative_output = _relative_generated_output_path(
            result, output_root=output_root
        )
    except RuntimeError:
        return []
    rules_file = Path(str(getattr(result, "output_file", "") or ""))
    try:
        real_rules_file = Path(policy_repo_path) / relative_output
        content_repo_path = find_policy_repo_root(
            real_rules_file
        ) or _generated_validation_repair_policy_repo_path(
            Path(policy_repo_path), relative_output
        )
        content_relative_output = real_rules_file.relative_to(content_repo_path)
    except ValueError:
        content_repo_path = _generated_validation_repair_policy_repo_path(
            Path(policy_repo_path), relative_output
        )
        content_relative_output = relative_output
    return _repair_upstream_placement_duplicate_imports(
        rules_file=rules_file,
        test_file=_rulespec_test_path(rules_file),
        repo_path=content_repo_path,
        relative_output=content_relative_output,
    )


def _try_repair_generated_upstream_placement_duplicates_and_proofs_for_apply(
    result,
    *,
    output_root: Path,
    policy_repo_path: Path,
) -> list[str]:
    repaired = _try_repair_generated_upstream_placement_duplicates_for_apply(
        result,
        output_root=output_root,
        policy_repo_path=policy_repo_path,
    )
    if not repaired:
        return []
    rules_file = Path(str(getattr(result, "output_file", "") or ""))
    try:
        content = rules_file.read_text()
    except OSError:
        return repaired
    repaired_content, repaired_rules = _repair_missing_source_proof_atoms(content)
    if repaired_content != content:
        rules_file.write_text(repaired_content)
        repaired.extend(f"proof:{name}" for name in repaired_rules)
    return repaired


_CHILD_FRAGMENT_REENCODING_ISSUE_PATTERN = re.compile(
    r"Child fragment re-encoded: .*? uses child-local input\(s\) "
    r"(?P<inputs>.+?) also used by `(?P<child_path>[^`]+)` without importing "
    r"a terminal child output\. Import and compose the child (?P<child_hint>.+?) "
    r"instead of copying the child formula or factual inputs"
)


def _try_repair_generated_child_fragment_reencoding_for_apply(
    result,
    *,
    output_root: Path,
    policy_repo_path: Path,
    issues: list[str],
) -> list[str]:
    parsed_issues = [
        parsed
        for issue in issues
        if (parsed := _parse_child_fragment_reencoding_issue(str(issue))) is not None
    ]
    if not parsed_issues:
        return []
    try:
        relative_output = _relative_generated_output_path(
            result, output_root=output_root
        )
    except RuntimeError:
        return []

    rules_file = Path(str(getattr(result, "output_file", "") or ""))
    return _repair_child_fragment_reencoding_aliases(
        rules_file=rules_file,
        policy_repo_path=policy_repo_path,
        relative_output=relative_output,
        parsed_issues=parsed_issues,
    )


def _parse_child_fragment_reencoding_issue(
    issue: str,
) -> tuple[tuple[str, ...], str] | None:
    match = _CHILD_FRAGMENT_REENCODING_ISSUE_PATTERN.search(issue)
    if match is None:
        return None
    shared_inputs = tuple(re.findall(r"`([^`]+)`", match.group("inputs")))
    child_refs = tuple(
        _normalize_rulespec_child_hint_ref(ref)
        for ref in re.findall(r"`([^`]+)`", match.group("child_hint"))
        if "#" in ref
    )
    if not shared_inputs or len(child_refs) != 1:
        return None
    return shared_inputs, child_refs[0]


def _normalize_rulespec_child_hint_ref(ref: str) -> str:
    normalized = ref.strip().strip("'\"")
    match = re.match(
        r"^(?P<prefix>[a-z]{2}(?:-[a-z0-9_]+)*):(?P=prefix)/(?P<rest>.+)$",
        normalized,
    )
    if match is not None:
        return f"{match.group('prefix')}:{match.group('rest')}"
    return normalized


def _repair_child_fragment_reencoding_aliases(
    *,
    rules_file: Path,
    policy_repo_path: Path,
    relative_output: Path,
    parsed_issues: list[tuple[tuple[str, ...], str]],
) -> list[str]:
    """Rewrite parent aliases that copy child-local symbols to terminal imports."""
    if not rules_file.exists():
        return []
    try:
        payload = yaml.safe_load(rules_file.read_text()) or {}
    except (OSError, ValueError, yaml.YAMLError):
        return []
    if not isinstance(payload, dict):
        return []
    rules = payload.get("rules")
    if not isinstance(rules, list):
        return []

    imports = payload.get("imports")
    if imports is None:
        imports = []
        payload["imports"] = imports
    if not isinstance(imports, list):
        return []

    repaired: list[str] = []
    for shared_inputs, child_ref in parsed_issues:
        child_name = child_ref.rsplit("#", 1)[1].strip()
        if not re.fullmatch(r"[A-Za-z_][A-Za-z0-9_]*", child_name):
            continue

        shared = set(shared_inputs)
        pending_repaired: list[str] = []
        for rule in rules:
            if not isinstance(rule, dict):
                continue
            rule_name = str(rule.get("name") or "")
            if not rule_name:
                continue
            rewrote = _rewrite_exact_rule_formula_and_proof_alias(
                rule,
                aliases=shared,
                child_ref=child_ref,
                child_name=child_name,
                replacement=child_name,
            )
            if not rewrote:
                continue
            pending_repaired.append(f"{rule_name}->{child_name}")
        if not pending_repaired:
            continue
        if child_ref not in imports:
            imports.append(child_ref)
            repaired.append(f"import:{child_ref}")
        repaired.extend(pending_repaired)

    if not repaired:
        return []

    content = yaml.safe_dump(payload, sort_keys=False, allow_unicode=False)
    content, removed_imports = _prune_unused_imports(content)
    for removed in removed_imports:
        repaired.append(f"remove_unused_import:{removed}")
    target_base = _relative_output_to_anchor(
        relative_output,
        policy_repo_path=policy_repo_path,
    )
    content, hash_repairs = _repair_proof_import_hashes(
        content,
        target_base=target_base,
        rules_file=rules_file,
        repo_path=policy_repo_path,
    )
    for index in range(hash_repairs):
        repaired.append(f"hash[{index}]")
    rules_file.write_text(content)
    return repaired


def _rewrite_exact_rule_formula_alias(
    rule: dict[str, object],
    *,
    aliases: set[str],
    replacement: str,
) -> bool:
    versions = rule.get("versions")
    if not isinstance(versions, list):
        return False
    changed = False
    for version in versions:
        if not isinstance(version, dict):
            continue
        formula = version.get("formula")
        if not isinstance(formula, str):
            continue
        if formula.strip() not in aliases:
            continue
        version["formula"] = replacement
        changed = True
    return changed


def _rewrite_exact_rule_formula_and_proof_alias(
    rule: dict[str, object],
    *,
    aliases: set[str],
    child_ref: str,
    child_name: str,
    replacement: str,
) -> bool:
    """Rewrite a generated direct alias only when its proof can be rewired."""
    versions = rule.get("versions")
    if not isinstance(versions, list):
        return False
    alias_versions: list[dict[str, object]] = []
    for version in versions:
        if not isinstance(version, dict):
            continue
        formula = version.get("formula")
        if not isinstance(formula, str):
            continue
        if formula.strip() in aliases:
            alias_versions.append(version)
    if not alias_versions:
        return False
    if not _rewrite_rule_proof_import_alias(
        rule,
        aliases=aliases,
        child_ref=child_ref,
        child_name=child_name,
    ):
        return False
    for version in alias_versions:
        version["formula"] = replacement
    return True


def _rewrite_rule_proof_import_alias(
    rule: dict[str, object],
    *,
    aliases: set[str],
    child_ref: str,
    child_name: str,
) -> bool:
    metadata = rule.get("metadata")
    proof = (
        metadata.get("proof")
        if isinstance(metadata, dict) and isinstance(metadata.get("proof"), dict)
        else rule.get("proof")
    )
    if not isinstance(proof, dict):
        return False
    atoms = proof.get("atoms")
    if not isinstance(atoms, list):
        return False
    changed = False
    for atom in atoms:
        if not isinstance(atom, dict):
            continue
        imported = atom.get("import")
        if not isinstance(imported, dict):
            continue
        output = str(imported.get("output") or "").strip()
        target = str(imported.get("target") or "").strip()
        target_name = target.rsplit("#", 1)[1] if "#" in target else ""
        if output not in aliases and target_name not in aliases:
            continue
        imported["target"] = child_ref
        imported["output"] = child_name
        imported["hash"] = "sha256:local"
        changed = True
    return changed


