        rf"(?m)^(?P<indent>\s*){re.escape(COLORADO_TAX_SUBSECTION_2_LOCAL_TEST_INPUT)}:\s*(?P<value>[^\n]+)$",
        _colorado_tax_subsection_2_input_replacement,
