def _section_7703_replacement_test_input_block(match: re.Match[str]) -> str:
    indent = match.group("indent")
    not_married_value = match.group("value").strip().lower()
    married = not_married_value not in {"true", "yes", "holds", "1"}
    married_value = "true" if married else "false"
    return (
        f"{indent}us:statutes/26/7703#input.spouse_dies_during_taxable_year: false\n"
        f"{indent}us:statutes/26/7703#input.taxpayer_married_at_time_of_spouse_death: false\n"
        f"{indent}us:statutes/26/7703#input.taxpayer_married_at_close_of_taxable_year: {married_value}\n"
        f"{indent}us:statutes/26/7703#input.legally_separated_under_decree_of_divorce_or_separate_maintenance: false\n"
        f"{indent}us:statutes/26/7703#input.taxpayer_files_separate_return: false\n"
        f"{indent}us:statutes/26/7703#input.taxpayer_maintains_household_as_home: false\n"
        f"{indent}us:statutes/26/7703#input.taxpayer_household_cost_fraction_furnished: 0\n"
        f"{indent}us:statutes/26/7703#input.spouse_not_member_of_household_final_month_count: 0\n"
        f"{indent}us:statutes/26/7703#relation.living_apart_child_of_tax_unit: []\n"
    )


def _replace_6012_section_6013_placeholder_test_inputs(content: str) -> str:
    question_key_pattern = re.compile(
        rf"(?m)^(?P<indent>\s*)\?\s+{re.escape(_SECTION_6012_6013_PLACEHOLDER_INPUT)}\n"
        rf"(?P=indent):\s*(?P<value>[^\n]+)\n"
    )
    content = question_key_pattern.sub(
        _section_6013_replacement_test_input_block,
        content,
    )
    scalar_key_pattern = re.compile(
        rf"(?m)^(?P<indent>\s*){re.escape(_SECTION_6012_6013_PLACEHOLDER_INPUT)}:\s*"
        rf"(?P<value>[^\n]+)\n"
    )
    return scalar_key_pattern.sub(_section_6013_replacement_test_input_block, content)


def _section_6013_replacement_test_input_block(match: re.Match[str]) -> str:
    indent = match.group("indent")
    joint_return_value = (
        "true" if _test_input_value_truthy(match.group("value")) else "false"
    )
    return (
        f"{indent}us:statutes/26/6013/a#input.spouses_have_different_taxable_years: false\n"
        f"{indent}us:statutes/26/6013/a#input.taxable_years_begin_on_same_day: false\n"
        f"{indent}us:statutes/26/6013/a#input.taxable_years_end_on_different_days_because_of_death_of_either_or_both_spouses: false\n"
        f"{indent}us:statutes/26/6013/a#input.surviving_spouse_remarries_before_close_of_surviving_spouse_taxable_year: false\n"
        f"{indent}us:statutes/26/443/a/1#input.taxpayer_changes_annual_accounting_period: false\n"
        f"{indent}us:statutes/26/443/a/1#input.secretary_approves_change_of_annual_accounting_period: false\n"
        f"{indent}us:statutes/26/6013/a#input.death_of_one_spouse_or_both_spouses: false\n"
        f"{indent}us:statutes/26/6013/a#input.joint_return_with_respect_to_decedent_made_by_executor_or_administrator: false\n"
        f"{indent}us:statutes/26/6013/a#input.death_of_one_spouse: false\n"
        f"{indent}us:statutes/26/6013/a#input.joint_return_with_respect_to_both_survivor_and_decedent_made_by_surviving_spouse: false\n"
        f"{indent}us:statutes/26/6013/a#input.no_return_for_taxable_year_made_by_decedent: false\n"
        f"{indent}us:statutes/26/6013/a#input.no_executor_or_administrator_has_been_appointed: false\n"
        f"{indent}us:statutes/26/6013/a#input.no_executor_or_administrator_appointed_before_last_day_prescribed_for_filing_surviving_spouse_return: false\n"
        f"{indent}us:statutes/26/6013/a#input.taxpayers_are_husband_and_wife: {joint_return_value}\n"
        f"{indent}us:statutes/26/6013/a#input.single_return_jointly_of_income_taxes_under_subtitle_a_is_made: {joint_return_value}\n"
        f"{indent}us:statutes/26/6013/a#input.either_spouse_is_nonresident_alien_at_any_time_during_taxable_year: false\n"
    )


def _refresh_proof_import_hashes_for_targets(
    rules_file: Path, repo_path: Path
) -> list[Path]:
    content = rules_file.read_text()
    repaired, repair_count = _repair_proof_import_hashes(
        content,
        target_base=(
            f"{_repo_jurisdiction_prefix(repo_path)}:"
            f"{_relative_rulespec_import_target(rules_file.relative_to(repo_path))}"
        ),
        rules_file=rules_file,
        repo_path=repo_path,
    )
    if repair_count == 0:
        return []
    rules_file.write_text(repaired)
    return [rules_file]


def _replace_test_input_ref(content: str, *, old_ref: str, new_ref: str) -> str:
    question_key_pattern = re.compile(
        rf"(?m)^(?P<indent>\s*)\?\s+{re.escape(old_ref)}\n"
        rf"(?P=indent):\s*(?P<value>[^\n]+)\n"
    )
    content = question_key_pattern.sub(
        lambda match: (
            f"{match.group('indent')}? {new_ref}\n"
            f"{match.group('indent')}: {match.group('value').strip()}\n"
        ),
        content,
    )
    scalar_key_pattern = re.compile(
        rf"(?m)^(?P<indent>\s*){re.escape(old_ref)}:\s*(?P<value>[^\n]+)\n"
    )
    return scalar_key_pattern.sub(
        lambda match: (
            f"{match.group('indent')}{new_ref}: {match.group('value').strip()}\n"
        ),
        content,
    )


def _remove_test_input_ref(content: str, *, input_ref: str) -> str:
    question_key_pattern = re.compile(
        rf"(?m)^\s*\?\s+{re.escape(input_ref)}\n\s*:\s*[^\n]+\n"
    )
    content = question_key_pattern.sub("", content)
    scalar_key_pattern = re.compile(rf"(?m)^\s*{re.escape(input_ref)}:\s*[^\n]+\n")
    return scalar_key_pattern.sub("", content)


def _path_differs_from_original(path: Path, original: str | None) -> bool:
    if original is None:
        return path.exists()
    if not path.exists():
        return True
    return path.read_text() != original


def _unique_paths(paths: list[Path]) -> list[Path]:
    unique: list[Path] = []
    seen: set[Path] = set()
    for path in paths:
        resolved = path.resolve()
        if resolved in seen:
            continue
        seen.add(resolved)
        unique.append(path)
    return unique


def _restore_original_files(originals: dict[Path, str | None]) -> None:
    for path, content in originals.items():
        if content is None:
            with contextlib.suppress(FileNotFoundError):
                path.unlink()
        else:
            path.parent.mkdir(parents=True, exist_ok=True)
            path.write_text(content)


def _repair_tax_filing_status_branches(content: str) -> tuple[str, list[str]]:
    if (
        "surviving spouse" not in content.lower()
        and "qualifying widow" not in content.lower()
        and "any other case" not in content.lower()
    ):
        return content, []

    repaired: list[str] = []
    repaired_rules: list[str] = []
    fallback_mode = (
        "surviving_joint"
        if (
            "surviving spouse" in content.lower()
            or "qualifying widow" in content.lower()
        )
        else None
    )
    fallback_needs_other_case = "any other case" in content.lower()
    repair_modes = _tax_filing_status_branch_repair_modes(content)
    content, summary_repairs = _repair_tax_filing_status_branch_summary(
        content,
        has_joint_only_other_case=any(
            mode == "joint_only_other" for mode in repair_modes.values()
        ),
    )
    current_rule_name: str | None = None
    index = 0
    lines = content.splitlines(keepends=True)

    while index < len(lines):
        line = lines[index]
        stripped = line.strip()
        if stripped.startswith("- name: "):
            current_rule_name = stripped.removeprefix("- name: ").strip()
        if stripped == "match filing_status:":
            match_block = [line]
            index += 1
            while index < len(lines):
                block_line = lines[index]
                block_stripped = block_line.strip()
                if block_stripped and "=>" not in block_stripped:
                    break
                match_block.append(block_line)
                index += 1
            repaired_block, block_repairs = _repair_tax_filing_status_match_block(
                match_block,
                repair_mode=repair_modes.get(current_rule_name or "") or fallback_mode,
                needs_other_case=repair_modes.get(current_rule_name or "")
                == "joint_only_other"
                or fallback_needs_other_case,
            )
            repaired.extend(repaired_block)
            repaired_rules.extend(
                f"{current_rule_name or '<unknown>'}:{repair}"
                for repair in block_repairs
            )
            continue

        repaired.append(line)
        index += 1

    return "".join(repaired), [*summary_repairs, *repaired_rules]


def _repair_tax_filing_status_branch_summary(
    content: str, *, has_joint_only_other_case: bool
) -> tuple[str, list[str]]:
    if not has_joint_only_other_case:
        return content, []

    summary_end_candidates = [
        position
        for position in (
            content.find("\n  source_verification:"),
            content.find("\nrules:"),
        )
        if position != -1
    ]
    if not summary_end_candidates:
        return content, []

    summary_end = min(summary_end_candidates)
    summary = content[:summary_end]
    rest = content[summary_end:]
    repaired = summary
    repairs: list[str] = []

    enum_repaired = _FILING_STATUS_SUMMARY_JOINT_SURVIVING_PATTERN.sub(
        _repair_tax_filing_status_branch_summary_enum_match,
        repaired,
    )
    if enum_repaired != repaired:
        repaired = enum_repaired
        repairs.append("summary:surviving_spouse_to_other_case")

    phrase_repaired = _replace_tax_filing_status_summary_phrase(
        repaired,
        "joint / surviving spouse",
        "joint return",
    )
    phrase_repaired = _replace_tax_filing_status_summary_phrase(
        phrase_repaired,
        "joint or surviving spouse",
        "joint return",
    )
    for old, new in [
        (
            "$250,000 for a joint return or surviving\n"
            "    spouse, one-half of that amount for a married individual filing\n"
            "    separately, and $200,000 in any other case.",
            "$250,000 for a joint return, one-half of that amount for a married\n"
            "    individual filing separately, and $200,000 in any other case.",
        ),
        (
            "$250,000 for a joint return or surviving\n    spouse, ",
            "$250,000 for a joint return, ",
        ),
        (
            "$250,000 for a joint return or surviving spouse, ",
            "$250,000 for a joint return, ",
        ),
        (
            "$250,000 for a joint return or surviving spouse",
            "$250,000 for a joint return",
        ),
    ]:
        phrase_repaired = phrase_repaired.replace(old, new)
    if phrase_repaired != repaired:
        repaired = phrase_repaired
        repairs.append("summary:surviving_spouse_to_other_case")

    if repaired == summary:
        return content, []
    return repaired + rest, list(dict.fromkeys(repairs))


_FILING_STATUS_SUMMARY_JOINT_SURVIVING_PATTERN = re.compile(
    r"(?m)^(?P<indent>[ \t]*)1\s*=\s*joint\s*/\s*surviving spouse"
    r"(?P<newline>\r?\n)(?P=indent)2\s*=\s*married filing separately"
    r"(?P<line2_tail>[^\r\n]*)"
    r"(?:(?P=newline)(?P=indent)3\s*=\s*head of household"
    r"(?P<line3_tail>[^\r\n]*))?"
)
_FILING_STATUS_SUMMARY_ENUM_LINE_PATTERN = re.compile(r"^[ \t]*\d+\s*=")


def _repair_tax_filing_status_branch_summary_enum_match(
    match: re.Match[str],
) -> str:
    indent = match.group("indent")
    newline = match.group("newline")
    lines = [
        f"{indent}1 = joint",
        f"{indent}2 = married filing separately{match.group('line2_tail') or ''}",
    ]
    line3_tail = match.group("line3_tail")
    if line3_tail is not None:
        lines.append(f"{indent}3 = head of household{line3_tail}")
    lines.append(f"{indent}4 = surviving spouse / qualifying widow(er)")
    return newline.join(lines)


def _replace_tax_filing_status_summary_phrase(text: str, old: str, new: str) -> str:
    lines: list[str] = []
    for line in text.splitlines(keepends=True):
        if _FILING_STATUS_SUMMARY_ENUM_LINE_PATTERN.match(line):
            lines.append(line)
            continue
        lines.append(line.replace(old, new))
    return "".join(lines)


def _tax_filing_status_branch_repair_modes(content: str) -> dict[str, str]:
    try:
        payload = yaml.safe_load(content)
    except (yaml.YAMLError, ValueError):
        return {}
    if not isinstance(payload, dict) or payload.get("format") != "rulespec/v1":
        return {}

    module_source_text = (
        _extract_source_verification_text(content)
        or extract_embedded_source_text(content)
        or content
    )
    modes: dict[str, str] = {}
    for name, kind, formula, source, rule in _rulespec_rule_formula_rule_records(
        payload
    ):
        if kind != "derived" or "filing_status" not in formula:
            continue
        source_context = _filing_status_rule_source_context(
            content=content,
            module_source_text=module_source_text,
            rule=rule,
            source=source,
        )
        if _US_TAX_JOINT_SURVIVING_SPOUSE_GROUP_TEXT_PATTERN.search(source_context):
            modes[name] = "surviving_joint"
        elif _US_TAX_JOINT_ONLY_ANY_OTHER_CASE_TEXT_PATTERN.search(source_context):
            modes[name] = "joint_only_other"
    return modes


_TEST_OUTPUT_MISMATCH_PATTERN = re.compile(
    r"Test case `(?P<case>[^`]+)` output `(?P<output>[^`]+)` "
    r"expected [^,]+, got "
    r"(?:(?P<kind>integer|decimal|float|number|boolean|string|bool|text) )?"
    r"(?P<actual>.+?)\.$"
)


def _repair_tax_filing_status_branch_test_output_mismatches(
    test_content: str,
    issues: list[str],
) -> tuple[str, list[str]]:
    try:
        payload = yaml.safe_load(test_content)
    except (yaml.YAMLError, ValueError):
        return test_content, []
    if not isinstance(payload, list):
        return test_content, []

    repairs: list[str] = []
    cases_by_name = {
        str(case.get("name") or ""): case for case in payload if isinstance(case, dict)
    }
    for issue in issues:
        match = _TEST_OUTPUT_MISMATCH_PATTERN.search(issue)
        if match is None:
            continue
        case_name = match.group("case")
        output_name = match.group("output")
        case = cases_by_name.get(case_name)
        if not isinstance(case, dict) or not _test_case_has_filing_status(case, 4):
            continue
        outputs = case.get("output")
        if not isinstance(outputs, dict) or output_name not in outputs:
            continue
        actual_value = _parse_validator_actual_output_value(
            match.group("actual"),
            kind=match.group("kind"),
        )
        if outputs[output_name] == actual_value:
            continue
        outputs[output_name] = actual_value
        repairs.append(f"test:{case_name}:{output_name}")

    if not repairs:
        return test_content, []
    return yaml.safe_dump(payload, sort_keys=False), repairs


def _rename_tax_filing_status_branch_test_cases(
    test_content: str,
) -> tuple[str, list[str]]:
    try:
        payload = yaml.safe_load(test_content)
    except (yaml.YAMLError, ValueError):
        return test_content, []
    if not isinstance(payload, list):
        return test_content, []

    repairs: list[str] = []
    for case in payload:
        if not isinstance(case, dict) or not _test_case_has_filing_status(case, 4):
            continue
        case_name = str(case.get("name") or "")
        if (
            "surviving_spouse" not in case_name and "qualifying_widow" not in case_name
        ) or "joint_threshold" not in case_name:
            continue
        new_case_name = case_name.replace(
            "uses_joint_threshold",
            "uses_other_threshold",
        ).replace("joint_threshold", "other_threshold")
        if new_case_name == case_name:
            continue
        case["name"] = new_case_name
        repairs.append(f"test:{case_name}->{new_case_name}")

    if not repairs:
        return test_content, []
    return yaml.safe_dump(payload, sort_keys=False), repairs


def _test_case_has_filing_status(case: dict[str, Any], value: int) -> bool:
    inputs = case.get("input")
    if not isinstance(inputs, dict):
        return False
    for key, input_value in inputs.items():
        if not isinstance(key, str) or not key.endswith("#input.filing_status"):
            continue
        if str(input_value).strip() == str(value):
            return True
    return False


def _parse_validator_actual_output_value(
    raw_value: str, *, kind: str | None = None
) -> Any:
    value_text = raw_value.strip()
    normalized_kind = (kind or "").lower()
    if normalized_kind in {"string", "text"}:
        return value_text
    with contextlib.suppress(yaml.YAMLError):
        return yaml.safe_load(value_text)
    return value_text


def _repair_tax_filing_status_match_block(
    block: list[str],
    *,
    repair_mode: str | None,
    needs_other_case: bool,
) -> tuple[list[str], list[str]]:
    arms: dict[int, tuple[str, str]] = {}
    for line in block:
        arm_match = re.match(r"(\s*)(\d+)\s*=>\s*(.+)$", line.rstrip("\n"))
        if arm_match is None:
            continue
        indent, code, expression = arm_match.groups()
        arms[int(code)] = (indent, expression)

    other_case_expression = None
    if 0 in arms:
        other_case_expression = arms[0][1]
    elif 3 in arms:
        other_case_expression = arms[3][1]

    should_add_surviving_spouse = (
        repair_mode == "surviving_joint" and 1 in arms and 4 not in arms
    )
    should_add_surviving_spouse_to_other = (
        repair_mode == "joint_only_other"
        and 1 in arms
        and 4 not in arms
        and other_case_expression is not None
    )
    should_route_surviving_spouse_to_other = (
        repair_mode == "joint_only_other"
        and 1 in arms
        and 4 in arms
        and other_case_expression is not None
        and arms[4][1].strip() == arms[1][1].strip()
    )
    should_add_other_case = needs_other_case and 0 in arms and 3 not in arms

    repaired: list[str] = []
    repairs: list[str] = []
    for line in block:
        arm_match = re.match(r"(\s*)(\d+)\s*=>\s*(.+)$", line.rstrip("\n"))
        if arm_match is not None:
            indent, code, expression = arm_match.groups()
            if code == "4" and should_route_surviving_spouse_to_other:
                repaired.append(f"{indent}4 => {other_case_expression}\n")
                repairs.append("surviving_spouse_to_other_case")
                continue

        repaired.append(line)
        if arm_match is None:
            continue
        indent, code, expression = arm_match.groups()
        if code == "1" and should_add_surviving_spouse:
            repaired.append(f"{indent}4 => {expression}\n")
            repairs.append("surviving_spouse")
        if code == "1" and should_add_surviving_spouse_to_other:
            repaired.append(f"{indent}4 => {other_case_expression}\n")
            repairs.append("surviving_spouse_to_other_case")
        if code == "0" and should_add_other_case:
            repaired.append(f"{indent}3 => {expression}\n")
            repairs.append("other_case")

    return repaired, repairs


def _ensure_import_proof_atoms_for_formula_symbol(
    content: str,
    *,
    symbol: str,
    target: str,
    output: str,
    source_hash: str,
) -> str:
    repaired = content
    for rule_name in _rules_with_formula_symbol(repaired, symbol):
        repaired = _ensure_rule_import_proof_atom(
            repaired,
            rule_name=rule_name,
            target=target,
            output=output,
            source_hash=source_hash,
        )
    return repaired


def _rules_with_formula_symbol(content: str, symbol: str) -> list[str]:
    rule_names: list[str] = []
    token = re.compile(rf"\b{re.escape(symbol)}\b")
    for match in re.finditer(
        r"(?m)^  - name: (?P<name>[A-Za-z_][A-Za-z0-9_]*)\n", content
    ):
        rule_start = match.start()
        next_rule = content.find("\n  - name: ", rule_start + 1)
        if next_rule == -1:
            next_rule = len(content)
        rule_block = content[rule_start:next_rule]
        if "formula:" in rule_block and token.search(rule_block):
            rule_names.append(match.group("name"))
    return rule_names


def _remove_rulespec_rule_by_name(content: str, rule_name: str) -> tuple[str, bool]:
    rule_start = content.find(f"  - name: {rule_name}\n")
    if rule_start == -1:
        return content, False
    next_rule = content.find("\n  - name: ", rule_start + 1)
    if next_rule == -1:
        next_rule = len(content)
    return content[:rule_start] + content[next_rule:], True


def _replace_formula_identifier(content: str, *, old: str, new: str) -> str:
    """Replace an identifier only inside RuleSpec formula values."""
    token = re.compile(rf"\b{re.escape(old)}\b")
    lines = content.splitlines(keepends=True)
    repaired: list[str] = []
    in_formula_block = False
    formula_indent = 0

    for line in lines:
        indent = len(line) - len(line.lstrip(" "))
        stripped = line.strip()
        if in_formula_block and stripped and indent <= formula_indent:
            in_formula_block = False

        if in_formula_block:
            repaired.append(token.sub(new, line))
            continue

        match = re.match(r"^(?P<prefix>\s*formula:\s*)(?P<body>.*)$", line)
        if match is None:
            repaired.append(line)
            continue

        body = match.group("body")
        line_ending = ""
        if line.endswith("\r\n"):
            line_ending = "\r\n"
        elif line.endswith("\n"):
            line_ending = "\n"
        if body.lstrip().startswith("|"):
            in_formula_block = True
            formula_indent = indent
            repaired.append(line)
            continue

        repaired.append(f"{match.group('prefix')}{token.sub(new, body)}{line_ending}")

    return "".join(repaired)


def _repair_missing_source_proof_atoms(content: str) -> tuple[str, list[str]]:
    try:
        payload = yaml.safe_load(content)
    except (yaml.YAMLError, ValueError):
        return content, []
    if not isinstance(payload, dict) or payload.get("format") != "rulespec/v1":
        return content, []

    module = payload.get("module")
    source_path = _rulespec_module_source_path(payload)
    if source_path is None:
        return content, []

    rules = payload.get("rules")
    if not isinstance(rules, list):
        return content, []

    repairs_by_rule: dict[str, dict[str, str]] = {}
    for index, rule in enumerate(rules):
        if not isinstance(rule, dict):
            continue
        if not _parsed_rule_requires_generated_source_proof(rule):
            continue
        rule_name = str(rule.get("name") or f"rules[{index}]").strip()
        if not rule_name:
            continue
        repairs_by_rule[rule_name] = {
            "kind": _generated_proof_atom_kind(rule),
            "corpus_citation_path": source_path,
            "span": _generated_proof_atom_span(rule),
        }

    if not repairs_by_rule:
        return content, []

    lines = content.splitlines(keepends=True)
    lines = _ensure_module_proof_validation_required(lines, module)
    repaired_lines, repaired_rules = _insert_missing_source_proof_atoms(
        lines, repairs_by_rule
    )
    if set(repaired_rules) != set(repairs_by_rule):
        structured_content, structured_rules = (
            _insert_missing_source_proof_atoms_structured(payload, repairs_by_rule)
        )
        if structured_rules:
            return structured_content, structured_rules
    return "".join(repaired_lines), repaired_rules


def _only_pending_nonnegative_amount_reduction_issues(issues: list[str]) -> bool:
    return bool(issues) and all(
        "Nonnegative amount reduction missing floor:" in issue
        or "Nonnegative amount income base missing floor:" in issue
        or "Nonnegative taxable income missing floor:" in issue
        for issue in issues
    )


def _rulespec_module_source_path(payload: dict[str, object]) -> str | None:
    """Return the module's one declared corpus source, if present."""

    module = payload.get("module")
    source_verification: object = None
    if isinstance(module, dict):
        source_verification = module.get("source_verification")
    if not isinstance(source_verification, dict):
        return None

    path = str(source_verification.get("corpus_citation_path") or "").strip()
    return path or None


def _parsed_rule_requires_generated_source_proof(rule: dict[str, object]) -> bool:
    kind = str(rule.get("kind") or "").strip()
    if kind not in {"parameter", "derived", "derived_relation"}:
        return False
    versions = rule.get("versions")
    if not isinstance(versions, list) or not versions:
        return False
    first_version = versions[0]
    if not isinstance(first_version, dict) or "formula" not in first_version:
        return False
    metadata = rule.get("metadata")
    if not isinstance(metadata, dict):
        return True
    proof = metadata.get("proof")
    if not isinstance(proof, dict):
        return True
    atoms = proof.get("atoms")
    return not isinstance(atoms, list) or not atoms


def _generated_proof_atom_kind(rule: dict[str, object]) -> str:
    if str(rule.get("kind") or "").strip() == "parameter":
        return "parameter"
    return "formula"


def _generated_proof_atom_span(rule: dict[str, object]) -> str:
    source = rule.get("source")
    if isinstance(source, str):
        return source.strip()
    if isinstance(source, dict):
        for key in ("span", "ref", "citation"):
            value = str(source.get(key) or "").strip()
            if value:
                return value
    return ""


def _ensure_module_proof_validation_required(
    lines: list[str],
    module: object,
) -> list[str]:
    if isinstance(module, dict):
        proof_validation = module.get("proof_validation")
        if (
            isinstance(proof_validation, dict)
            and proof_validation.get("required") is True
        ):
            return lines

    repaired: list[str] = []
    inserted = False
    for line in lines:
        repaired.append(line)
        if not inserted and line == "module:\n":
            repaired.append("  proof_validation:\n")
            repaired.append("    required: true\n")
            inserted = True
    return repaired


def _insert_missing_source_proof_atoms(
    lines: list[str],
    repairs_by_rule: dict[str, dict[str, str]],
) -> tuple[list[str], list[str]]:
    rule_starts = [
        index for index, line in enumerate(lines) if re.match(r"^  - name:\s*", line)
    ]
    if not rule_starts:
        return lines, []

    output = lines[:]
    offset = 0
    repaired_rules: list[str] = []
    for rule_start, next_rule_start in zip(
        rule_starts,
        rule_starts[1:] + [len(lines)],
        strict=False,
    ):
        adjusted_start = rule_start + offset
        adjusted_end = next_rule_start + offset
        name_match = re.match(r"^  - name:\s*(.+?)\s*$", output[adjusted_start])
        if name_match is None:
            continue
        rule_name = name_match.group(1).strip()
        repair = repairs_by_rule.get(rule_name)
        if repair is None:
            continue

        block = output[adjusted_start:adjusted_end]
        insertion_index, inserted_lines = _source_proof_insertion(
            block,
            proof_kind=repair["kind"],
            corpus_citation_path=repair["corpus_citation_path"],
            span=repair["span"],
        )
        absolute_insertion_index = adjusted_start + insertion_index
        output[absolute_insertion_index:absolute_insertion_index] = inserted_lines
        offset += len(inserted_lines)
        repaired_rules.append(rule_name)

    return output, repaired_rules


def _insert_missing_source_proof_atoms_structured(
    payload: dict[str, object],
    repairs_by_rule: dict[str, dict[str, str]],
) -> tuple[str, list[str]]:
    module = payload.get("module")
    if not isinstance(module, dict):
        module = {}
        payload["module"] = module
    proof_validation = module.get("proof_validation")
    if not isinstance(proof_validation, dict):
        module["proof_validation"] = {"required": True}
    else:
        proof_validation["required"] = True

    rules = payload.get("rules")
    if not isinstance(rules, list):
        return yaml.safe_dump(payload, sort_keys=False, allow_unicode=False), []

    repaired_rules: list[str] = []
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        rule_name = str(rule.get("name") or "").strip()
        repair = repairs_by_rule.get(rule_name)
        if repair is None:
            continue
        metadata = rule.get("metadata")
        if not isinstance(metadata, dict):
            metadata = {}
            rule["metadata"] = metadata
        proof = metadata.get("proof")
        if not isinstance(proof, dict):
            proof = {}
            metadata["proof"] = proof
        atoms = proof.get("atoms")
        if isinstance(atoms, list) and atoms:
            continue
        source: dict[str, str] = {
            "corpus_citation_path": repair["corpus_citation_path"],
        }
        if repair["span"]:
            source["span"] = repair["span"]
        proof["atoms"] = [
            {
                "path": "versions[0].formula",
                "kind": repair["kind"],
                "source": source,
            }
        ]
        repaired_rules.append(rule_name)

    return (
        yaml.safe_dump(payload, sort_keys=False, allow_unicode=False),
        repaired_rules,
    )


def _source_proof_insertion(
    rule_block: list[str],
    *,
    proof_kind: str,
    corpus_citation_path: str,
    span: str,
) -> tuple[int, list[str]]:
    metadata_index = next(
        (
            index
            for index, line in enumerate(rule_block)
            if re.match(r"^    metadata:\s*$", line)
        ),
        None,
    )
    proof_lines = _generated_source_proof_atom_lines(
        proof_kind=proof_kind,
        corpus_citation_path=corpus_citation_path,
        span=span,
        include_metadata=metadata_index is None,
    )
    if metadata_index is not None:
        return metadata_index + 1, proof_lines

    versions_index = next(
        (
            index
            for index, line in enumerate(rule_block)
            if re.match(r"^    versions:\s*$", line)
        ),
        len(rule_block),
    )
    return versions_index, proof_lines


def _generated_source_proof_atom_lines(
    *,
    proof_kind: str,
    corpus_citation_path: str,
    span: str,
    include_metadata: bool,
) -> list[str]:
    lines: list[str] = []
    if include_metadata:
        lines.append("    metadata:\n")
    lines.extend(
        [
            "      proof:\n",
            "        atoms:\n",
            "          - path: versions[0].formula\n",
            f"            kind: {proof_kind}\n",
            "            source:\n",
            f"              corpus_citation_path: {corpus_citation_path}\n",
        ]
    )
    if span:
        lines.append(f"              span: {_quote_yaml_single_line(span)}\n")
    return lines


def _quote_yaml_single_line(value: str) -> str:
    return "'" + value.replace("'", "''") + "'"


def _repair_proof_import_hashes(
    content: str,
    *,
    target_base: str,
    rules_file: Path,
    repo_path: Path,
) -> tuple[str, int]:
    lines = content.splitlines(keepends=True)
    repaired_lines: list[str] = []
    pending_expected_hash: str | None = None
    repair_count = 0
    for line in lines:
        stripped = line.strip()
        if stripped.startswith("target: "):
            target = stripped.removeprefix("target: ").strip().strip("'\"")
            pending_expected_hash = _expected_proof_import_hash(
                target,
                target_base=target_base,
                rules_file=rules_file,
                repo_path=repo_path,
            )
        elif pending_expected_hash is not None and stripped.startswith("hash: "):
            expected_line = f"hash: {pending_expected_hash}"
            if stripped != expected_line:
                newline = "\n" if line.endswith("\n") else ""
                prefix = line[: len(line) - len(line.lstrip())]
                line = f"{prefix}{expected_line}{newline}"
                repair_count += 1
            pending_expected_hash = None
        repaired_lines.append(line)
    return "".join(repaired_lines), repair_count


def _expected_proof_import_hash(
    target: str,
    *,
    target_base: str,
    rules_file: Path,
    repo_path: Path,
) -> str | None:
    if target.startswith(f"{target_base}#"):
        return "sha256:local"

    normalized = target.strip().strip("'\"")
    target_ref = _parse_rulespec_target(normalized)
    if target_ref is None:
        return None
    if target_ref.prefix != _repo_jurisdiction_prefix(repo_path):
        return None

    target_file = _resolve_rulespec_target_file(target_ref, repo_path)
    if target_file is None or not target_file.exists():
        return None
    if target_file.resolve() == rules_file.resolve():
        return "sha256:local"
    return f"sha256:{hashlib.sha256(target_file.read_bytes()).hexdigest()}"


class _OracleParameterTestSpec(NamedTuple):
    rule_name: str
    selector_input_ref: str | None
    selector_value: object | None
    expected_value: object
    expected_period: str | dict[str, str] | None


def _append_oracle_parameter_tests_if_missing(
    *,
    rules_file: Path,
    test_file: Path,
    target_base: str,
) -> list[str]:
    rules_content = rules_file.read_text()
    payload = yaml.safe_load(rules_content) or {}
    rules = payload.get("rules") if isinstance(payload, dict) else None
    if not isinstance(rules, list):
        return []

    factual_inputs = _local_factual_input_names_from_rules_content(rules_content)
    input_defaults = {
        f"{target_base}#input.{input_name}": _default_generated_test_input_value(
            input_name,
            rules_payload=payload,
            prefer_positive_counts=True,
        )
        for input_name in sorted(factual_inputs)
    }
    existing_outputs = _rulespec_test_output_keys(test_file)
    registry = load_policyengine_registry()
    appended_cases: list[dict] = []
    repaired: list[str] = []
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        if str(rule.get("kind") or "").strip() != "parameter":
            continue
        rule_name = str(rule.get("name") or "").strip()
        if not rule_name:
            continue
        legal_id = f"{target_base}#{rule_name}"
        if legal_id in existing_outputs:
            continue
        mapping = registry.mapping_for_legal_id(legal_id, country="us")
        if mapping is None or mapping.mapping_type != "parameter_value":
            continue

        index_name = _single_parameter_index_name(rule)
        sample = _latest_scalar_parameter_value(rule, indexed=index_name is not None)
        if sample is None:
            continue
        key, value, effective_from = sample
        case_name_parts = ["oracle_parameter", _safe_test_name(rule_name)]
        if index_name is not None:
            case_name_parts.append(_safe_test_name(str(key)))
        inputs = dict(input_defaults)
        if index_name:
            inputs[f"{target_base}#input.{index_name}"] = key
        appended_cases.append(
            {
                "name": "_".join(case_name_parts),
                "period": _oracle_parameter_test_period(
                    effective_from,
                    parameter_period=getattr(mapping, "period", None),
                ),
                "input": inputs,
                "output": {legal_id: value},
            }
        )
        repaired.append(rule_name)

    if not appended_cases:
        return []

    existing_content = test_file.read_text() if test_file.exists() else ""
    if (yaml.safe_load(existing_content) if existing_content.strip() else None) == []:
        existing_content = ""
    test_file.parent.mkdir(parents=True, exist_ok=True)
    rendered = yaml.safe_dump(appended_cases, sort_keys=False)
    separator = "" if not existing_content or existing_content.endswith("\n") else "\n"
    test_file.write_text(f"{existing_content}{separator}{rendered}")
    return repaired


def _refresh_existing_oracle_parameter_test_inputs(
    *,
    rules_file: Path,
    test_file: Path,
    target_base: str,
) -> list[str]:
    if not test_file.exists():
        return []

    rules_content = rules_file.read_text()
    payload = yaml.safe_load(rules_content) or {}
    rules = payload.get("rules") if isinstance(payload, dict) else None
    if not isinstance(rules, list):
        return []

    factual_inputs = _local_factual_input_names_from_rules_content(rules_content)
    input_defaults = {
        f"{target_base}#input.{input_name}": _default_generated_test_input_value(
            input_name,
            rules_payload=payload,
            prefer_positive_counts=True,
        )
        for input_name in sorted(factual_inputs)
    }
    registry = load_policyengine_registry()
    mapped_parameter_outputs: dict[str, _OracleParameterTestSpec] = {}
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        if str(rule.get("kind") or "").strip() != "parameter":
            continue
        rule_name = str(rule.get("name") or "").strip()
        if not rule_name:
            continue
        legal_id = f"{target_base}#{rule_name}"
        mapping = registry.mapping_for_legal_id(legal_id, country="us")
        if mapping is None or mapping.mapping_type != "parameter_value":
            continue
        index_name = _single_parameter_index_name(rule)
        sample = _latest_scalar_parameter_value(rule, indexed=index_name is not None)
        if sample is None:
            continue
        key, value, effective_from = sample
        expected_period = _oracle_parameter_test_period(
            effective_from,
            parameter_period=getattr(mapping, "period", None),
        )
        mapped_parameter_outputs[legal_id] = _OracleParameterTestSpec(
            rule_name=rule_name,
            selector_input_ref=f"{target_base}#input.{index_name}"
            if index_name
            else None,
            selector_value=key,
            expected_value=value,
            expected_period=expected_period,
        )
    if not mapped_parameter_outputs:
        return []

    try:
        test_payload = yaml.safe_load(test_file.read_text()) or []
    except yaml.YAMLError:
        return []
    if isinstance(test_payload, list):
        test_cases = test_payload
    elif isinstance(test_payload, dict) and isinstance(test_payload.get("cases"), list):
        test_cases = test_payload["cases"]
    else:
        return []

    refreshed: list[str] = []
    for case in test_cases:
        if not isinstance(case, dict):
            continue
        case_name = str(case.get("name") or "")
        if not case_name.startswith("oracle_parameter_"):
            continue
        outputs = case.get("output")
        if not isinstance(outputs, dict):
            continue
        matching_output_specs = [
            (str(output_ref), mapped_parameter_outputs[str(output_ref)])
            for output_ref in outputs
            if str(output_ref) in mapped_parameter_outputs
        ]
        if not matching_output_specs:
            continue
        matching_outputs = [spec.rule_name for _, spec in matching_output_specs]
        selector_input_refs = {
            spec.selector_input_ref
            for _, spec in matching_output_specs
            if spec.selector_input_ref
        }
        expected_periods = [
            spec.expected_period
            for _, spec in matching_output_specs
            if spec.expected_period is not None
        ]
        inputs = case.get("input")
        if not isinstance(inputs, dict):
            inputs = {}
            case["input"] = inputs
        changed = False
        if expected_periods:
            expected_period = expected_periods[0]
            if case.get("period") != expected_period:
                case["period"] = expected_period
                changed = True
        for output_ref, spec in matching_output_specs:
            existing_value = outputs.get(output_ref)
            if (
                output_ref not in outputs
                or existing_value != spec.expected_value
                or type(existing_value) is not type(spec.expected_value)
            ):
                outputs[output_ref] = spec.expected_value
                changed = True
            if spec.selector_input_ref is None:
                continue
            existing_selector_value = inputs.get(spec.selector_input_ref)
            if (
                spec.selector_input_ref not in inputs
                or existing_selector_value != spec.selector_value
                or type(existing_selector_value) is not type(spec.selector_value)
            ):
                inputs[spec.selector_input_ref] = spec.selector_value
                changed = True
        for input_ref, default_value in input_defaults.items():
            if input_ref in selector_input_refs:
                continue
            existing_value = inputs.get(input_ref)
            if (
                input_ref not in inputs
                or existing_value != default_value
                or type(existing_value) is not type(default_value)
            ):
                inputs[input_ref] = default_value
                changed = True
        if changed:
            refreshed.extend(matching_outputs)

    if not refreshed:
        return []

    test_file.write_text(
        yaml.safe_dump(test_payload, sort_keys=False, allow_unicode=False)
    )
    return refreshed


def _mapped_oracle_parameter_test_outputs(
    *,
    rules_file: Path,
    test_file: Path,
    target_base: str,
) -> list[str]:
    payload = yaml.safe_load(rules_file.read_text()) or {}
    rules = payload.get("rules") if isinstance(payload, dict) else None
    if not isinstance(rules, list):
        return []

    existing_outputs = _rulespec_test_output_keys(test_file)
    registry = load_policyengine_registry()
    covered: list[str] = []
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        if str(rule.get("kind") or "").strip() != "parameter":
            continue
        rule_name = str(rule.get("name") or "").strip()
        if not rule_name:
            continue
        legal_id = f"{target_base}#{rule_name}"
        if legal_id not in existing_outputs:
            continue
        mapping = registry.mapping_for_legal_id(legal_id, country="us")
        if mapping is None or mapping.mapping_type != "parameter_value":
            continue
        covered.append(rule_name)
    return covered


def _rulespec_test_output_keys(test_file: Path) -> set[str]:
    if not test_file.exists():
        return set()
    try:
        cases = _load_rulespec_test_cases(test_file)
    except (OSError, ValueError, yaml.YAMLError):
        return set()
    outputs: set[str] = set()
    for case in cases:
        output = case.get("output")
        if not isinstance(output, dict):
            continue
        outputs.update(str(key) for key in output)
    return outputs


def _single_parameter_index_name(rule: dict) -> str | None:
    indexed_by = rule.get("indexed_by")
    if isinstance(indexed_by, str) and indexed_by.strip():
        return indexed_by.strip()
    if (
        isinstance(indexed_by, list)
        and len(indexed_by) == 1
        and isinstance(indexed_by[0], str)
        and indexed_by[0].strip()
    ):
        return indexed_by[0].strip()
    return None


def _latest_scalar_parameter_value(
    rule: dict, *, indexed: bool
) -> tuple[object | None, object, str | None] | None:
    versions = rule.get("versions")
    if not isinstance(versions, list):
        return None
    latest: tuple[date, int, object | None, object, str | None] | None = None
    for index, version in enumerate(versions):
        if not isinstance(version, dict):
            continue
        effective_from = version.get("effective_from")
        effective_from_text = (
            str(effective_from).strip() if effective_from is not None else None
        )
        try:
            effective_sort_date = (
                date.fromisoformat(effective_from_text)
                if effective_from_text
                else date.min
            )
        except ValueError:
            effective_sort_date = date.min
        if indexed:
            values = version.get("values")
            if not isinstance(values, dict):
                continue
            for key, value in values.items():
                if isinstance(value, (str, int, float, bool)) or value is None:
                    candidate = (
                        effective_sort_date,
                        index,
                        key,
                        value,
                        effective_from_text,
                    )
                    if latest is None or candidate[:2] > latest[:2]:
                        latest = candidate
                    break
        else:
            value = _scalar_formula_value(version.get("formula"))
            if value is not None:
                candidate = (
                    effective_sort_date,
                    index,
                    None,
                    value,
                    effective_from_text,
                )
                if latest is None or candidate[:2] > latest[:2]:
                    latest = candidate
    if latest is None:
        return None
    _, _, key, value, effective_from_text = latest
    return key, value, effective_from_text


def _oracle_parameter_test_period(
    effective_from: str | None,
    *,
    parameter_period: str | None = None,
) -> str | dict[str, str]:
    """Return a one-year period that is valid for a generated parameter test."""
    default = {
        "period_kind": "tax_year",
        "start": "2026-01-01",
        "end": "2026-12-31",
    }
    if not effective_from:
        return default
    try:
        start = date.fromisoformat(effective_from)
    except ValueError:
        return default
    if start.year < 1900:
        return default
    if str(parameter_period or "").strip().lower() == "month":
        if start.day != 1:
            year = start.year + (1 if start.month == 12 else 0)
            month = 1 if start.month == 12 else start.month + 1
            return f"{year:04d}-{month:02d}"
        return f"{start.year:04d}-{start.month:02d}"
    if start.month == 1 and start.day == 1:
        return {
            "period_kind": "tax_year",
            "start": f"{start.year:04d}-01-01",
            "end": f"{start.year:04d}-12-31",
        }
    try:
        next_start = start.replace(year=start.year + 1)
    except ValueError:
        next_start = start.replace(year=start.year + 1, day=28)
    return {
        "period_kind": "custom",
        "name": "policy_year",
        "start": start.isoformat(),
        "end": date.fromordinal(next_start.toordinal() - 1).isoformat(),
    }


def _scalar_formula_value(formula: object) -> int | float | str | bool | None:
    if isinstance(formula, (int, float, bool)):
        return formula
    if not isinstance(formula, str):
        return None
    stripped = formula.strip()
    if not re.fullmatch(r"-?\d+(?:\.\d+)?", stripped):
        fraction_match = re.fullmatch(r"\(?\s*(-?\d+)\s*/\s*(-?\d+)\s*\)?", stripped)
        if not fraction_match:
            return None
        numerator = int(fraction_match.group(1))
        denominator = int(fraction_match.group(2))
        if denominator == 0:
            return None
        if not _fraction_has_terminating_decimal(denominator):
            with localcontext() as context:
                context.prec = 28
                return format(Decimal(numerator) / Decimal(denominator), "f")
        return numerator / denominator
    parsed = yaml.safe_load(stripped)
    return parsed if isinstance(parsed, (int, float)) else None


def _fraction_has_terminating_decimal(denominator: int) -> bool:
    remaining = abs(denominator)
    for prime in (2, 5):
        while remaining and remaining % prime == 0:
            remaining //= prime
    return remaining == 1


def _rulespec_companion_test_failures(
    test_file: Path,
    *,
    root: Path,
    axiom_rules_path: Path,
) -> list[dict[str, str | None]]:
    pipeline = ValidatorPipeline(
        policy_repo_path=root,
        axiom_rules_path=axiom_rules_path,
        local_corpus_release=None,
        enable_oracles=False,
    )
    binary = pipeline._axiom_rules_binary()
    rulespec_env = pipeline._rulespec_engine_env()
    rulespec_roots = pipeline._rulespec_compile_roots()
    with tempfile.TemporaryDirectory() as tmpdir:
        result = _execute_rulespec_test_file(
            test_file,
            binary=binary,
            axiom_rules_path=Path(axiom_rules_path),
            env=rulespec_env,
            rulespec_roots=rulespec_roots,
            tmp_path=Path(tmpdir),
            compiled_cache={},
            policy_repo_path=root,
        )
    return list(result["failures"])


def _safe_test_name(value: str) -> str:
    safe = re.sub(r"[^a-zA-Z0-9]+", "_", value.strip()).strip("_").lower()
    return safe or "value"


def _only_pending_zero_branch_coverage_issues(issues: list[str]) -> bool:
    return bool(issues) and all(
        "Zero branch test coverage missing: " in issue for issue in issues
    )


def _zero_branch_coverage_issues_for_files(
    *, rules_file: Path, test_file: Path
) -> list[str]:
    """Compute zero-branch issues directly, even when earlier validators mask them."""
    if not rules_file.exists() or not test_file.exists():
        return []
    try:
        test_cases = yaml.safe_load(test_file.read_text()) or []
    except (OSError, ValueError, yaml.YAMLError):
        return []
    try:
        content = rules_file.read_text()
    except OSError:
        return []
    return find_zero_branch_test_coverage_issues(content, test_cases)


def _only_pending_exception_test_coverage_issues(issues: list[str]) -> bool:
    return bool(issues) and all(
        "Exception test coverage missing: " in issue for issue in issues
    )


def _append_exception_positive_companion_tests_if_missing(
    *,
    test_file: Path,
    repo_path: Path,
    relative_output: Path,
    issues: list[str],
) -> list[str]:
    """Clone generated exception tests into missing paired companions."""
    if not issues or not test_file.exists():
        return []
    repair_specs = _exception_test_repair_specs_from_issues(issues)
    if not repair_specs:
        return []

    try:
        test_payload = yaml.safe_load(test_file.read_text()) or []
    except (OSError, ValueError, yaml.YAMLError):
        return []
    if not isinstance(test_payload, list):
        return []

    target_base = _rulespec_anchor_base_for_output(repo_path, relative_output)
    repaired: list[str] = []
    existing_case_names = {
        str(test_case.get("name") or "").strip()
        for test_case in test_payload
        if isinstance(test_case, dict)
    }
    for rule_name, exception_input in repair_specs:
        if not _has_exception_positive_companion_case(
            test_payload,
            rule_name=rule_name,
            exception_input=exception_input,
        ):
            case_name = _unique_generated_test_name(
                f"auto_positive_{_safe_test_name(rule_name)}_"
                f"{_safe_test_name(exception_input)}",
                existing_case_names,
            )
            companion = _build_exception_positive_companion_case(
                test_payload,
                target_base=target_base,
                case_name=case_name,
                rule_name=rule_name,
                exception_input=exception_input,
            )
            if companion is not None:
                test_payload.append(companion)
                existing_case_names.add(case_name)
                repaired.append(case_name)
        if not _has_exception_negative_companion_case(
            test_payload,
            rule_name=rule_name,
            exception_input=exception_input,
        ):
            case_name = _unique_generated_test_name(
                f"auto_negative_{_safe_test_name(rule_name)}_"
                f"{_safe_test_name(exception_input)}",
                existing_case_names,
            )
            companion = _build_exception_negative_companion_case(
                test_payload,
                target_base=target_base,
                case_name=case_name,
                rule_name=rule_name,
                exception_input=exception_input,
            )
            if companion is not None:
                test_payload.append(companion)
                existing_case_names.add(case_name)
                repaired.append(case_name)

    if not repaired:
        return []
    test_file.write_text(
        yaml.safe_dump(test_payload, sort_keys=False, allow_unicode=False)
    )
    return repaired


def _exception_test_repair_specs_from_issues(
    issues: list[str],
) -> list[tuple[str, str]]:
    specs: list[tuple[str, str]] = []
    seen: set[tuple[str, str]] = set()
    for issue in issues:
        match = re.search(
            r"Exception test coverage missing:\s*`(?P<rule>[^`]+)`\s+"
            r"negates\s+`(?P<input>[^`]+)`",
            str(issue),
        )
        if not match:
            continue
        spec = (match["rule"].strip(), match["input"].strip())
        if not all(spec) or spec in seen:
            continue
        seen.add(spec)
        specs.append(spec)
    return specs


def _build_exception_positive_companion_case(
    test_payload: list[object],
    *,
    target_base: str,
    case_name: str,
    rule_name: str,
    exception_input: str,
) -> dict[str, object] | None:
    for test_case in test_payload:
        if not isinstance(test_case, dict):
            continue
        inputs = test_case.get("input")
        outputs = test_case.get("output")
        if not isinstance(inputs, dict) or not isinstance(outputs, dict):
            continue
        if not _case_sets_exception_input(
            inputs, exception_input=exception_input, value=True
        ):
            continue
        if not _case_asserts_rule_value(
            outputs, rule_name=rule_name, normalized_value="not_holds"
        ):
            continue
        companion = copy.deepcopy(test_case)
        companion["name"] = case_name
        companion_inputs = companion.get("input")
        companion_outputs = companion.get("output")
        if not isinstance(companion_inputs, dict) or not isinstance(
            companion_outputs, dict
        ):
            return None
        _set_exception_input_value(
            companion_inputs,
            target_base=target_base,
            exception_input=exception_input,
            value=False,
        )
        _set_rule_output_value(
            companion_outputs,
            target_base=target_base,
            rule_name=rule_name,
            value="holds",
        )
        return companion
    return None


def _build_exception_negative_companion_case(
    test_payload: list[object],
    *,
    target_base: str,
    case_name: str,
    rule_name: str,
    exception_input: str,
) -> dict[str, object] | None:
    for test_case in test_payload:
        if not isinstance(test_case, dict):
            continue
        inputs = test_case.get("input")
        outputs = test_case.get("output")
        if not isinstance(inputs, dict) or not isinstance(outputs, dict):
            continue
        if not _case_sets_exception_input(
            inputs, exception_input=exception_input, value=False
        ):
            continue
        if not _case_asserts_rule_value(
            outputs, rule_name=rule_name, normalized_value="holds"
        ):
            continue
        companion = copy.deepcopy(test_case)
        companion["name"] = case_name
        companion_inputs = companion.get("input")
        companion_outputs = companion.get("output")
        if not isinstance(companion_inputs, dict) or not isinstance(
            companion_outputs, dict
        ):
            return None
        _set_exception_input_value(
            companion_inputs,
            target_base=target_base,
            exception_input=exception_input,
            value=True,
        )
        _set_rule_output_value(
            companion_outputs,
            target_base=target_base,
            rule_name=rule_name,
            value="not_holds",
        )
        return companion
    return None


def _has_exception_positive_companion_case(
    test_payload: list[object],
    *,
    rule_name: str,
    exception_input: str,
) -> bool:
    negative_signatures: set[tuple[tuple[str, str], ...]] = set()
    positive_signatures: set[tuple[tuple[str, str], ...]] = set()
    for test_case in test_payload:
        if not isinstance(test_case, dict):
            continue
        inputs = test_case.get("input")
        outputs = test_case.get("output")
        if not isinstance(inputs, dict) or not isinstance(outputs, dict):
            continue
        sets_exception_false = _case_sets_exception_input(
            inputs, exception_input=exception_input, value=False
        )
        sets_exception_true = _case_sets_exception_input(
            inputs, exception_input=exception_input, value=True
        )
        if sets_exception_false and _case_asserts_rule_value(
            outputs, rule_name=rule_name, normalized_value="holds"
        ):
            positive_signatures.add(
                _case_input_signature_without_exception(
                    inputs,
                    exception_input=exception_input,
                )
            )
        if sets_exception_true and _case_asserts_rule_value(
            outputs, rule_name=rule_name, normalized_value="not_holds"
        ):
            negative_signatures.add(
                _case_input_signature_without_exception(
                    inputs,
                    exception_input=exception_input,
                )
            )
    return bool(negative_signatures.intersection(positive_signatures))


def _has_exception_negative_companion_case(
    test_payload: list[object],
    *,
    rule_name: str,
    exception_input: str,
) -> bool:
    positive_signatures: set[tuple[tuple[str, str], ...]] = set()
    negative_signatures: set[tuple[tuple[str, str], ...]] = set()
    for test_case in test_payload:
        if not isinstance(test_case, dict):
            continue
        inputs = test_case.get("input")
        outputs = test_case.get("output")
        if not isinstance(inputs, dict) or not isinstance(outputs, dict):
            continue
        sets_exception_true = _case_sets_exception_input(
            inputs, exception_input=exception_input, value=True
        )
        sets_exception_false = _case_sets_exception_input(
            inputs, exception_input=exception_input, value=False
        )
        if sets_exception_true and _case_asserts_rule_value(
            outputs, rule_name=rule_name, normalized_value="not_holds"
        ):
            negative_signatures.add(
                _case_input_signature_without_exception(
                    inputs,
                    exception_input=exception_input,
                )
            )
        if sets_exception_false and _case_asserts_rule_value(
            outputs, rule_name=rule_name, normalized_value="holds"
        ):
            positive_signatures.add(
                _case_input_signature_without_exception(
                    inputs,
                    exception_input=exception_input,
                )
            )
    return bool(positive_signatures.intersection(negative_signatures))


def _case_input_signature_without_exception(
    inputs: dict[object, object],
    *,
    exception_input: str,
) -> tuple[tuple[str, str], ...]:
    exception_fragment = f"input.{exception_input}"
    signature: dict[str, str] = {}
    for key, value in inputs.items():
        fragment = _rulespec_test_key_fragment(key)
        if fragment == exception_fragment:
            continue
        signature[fragment] = _normalized_test_value_for_signature(value)
    return tuple(sorted(signature.items()))


def _normalized_test_value_for_signature(value: object) -> str:
    if isinstance(value, dict | list | tuple):
        return yaml.safe_dump(
            value,
            sort_keys=True,
            allow_unicode=False,
        ).strip()
    return _normalized_generated_test_scalar(value)


def _case_sets_exception_input(
    inputs: dict[object, object],
    *,
    exception_input: str,
    value: bool,
) -> bool:
    expected_fragment = f"input.{exception_input}"
    return any(
        _rulespec_test_key_fragment(key) == expected_fragment
        and _is_boolean_test_value(raw_value, value)
        for key, raw_value in inputs.items()
    )


def _case_asserts_rule_value(
    outputs: dict[object, object],
    *,
    rule_name: str,
    normalized_value: str,
) -> bool:
    return any(
        _rulespec_test_key_fragment(key) == rule_name
        and _normalized_generated_test_scalar(raw_value) == normalized_value
        for key, raw_value in outputs.items()
    )


def _set_exception_input_value(
    inputs: dict[object, object],
    *,
    target_base: str,
    exception_input: str,
    value: bool,
) -> None:
    expected_fragment = f"input.{exception_input}"
    for key in list(inputs):
        if _rulespec_test_key_fragment(key) == expected_fragment:
            inputs[key] = value
            return
    inputs[f"{target_base}#{expected_fragment}"] = value


def _set_rule_output_value(
    outputs: dict[object, object],
    *,
    target_base: str,
    rule_name: str,
    value: str,
) -> None:
    for key in list(outputs):
        if _rulespec_test_key_fragment(key) == rule_name:
            outputs[key] = value
            return
    outputs[f"{target_base}#{rule_name}"] = value


def _rulespec_test_key_fragment(key: object) -> str:
    raw = str(key)
    return raw.split("#", 1)[1] if "#" in raw else raw


def _is_boolean_test_value(value: object, expected: bool) -> bool:
    if isinstance(value, bool):
        return value is expected
    normalized = _normalized_generated_test_scalar(value)
    return normalized == ("true" if expected else "false")


def _normalized_generated_test_scalar(value: object) -> str:
    return str(value).strip().lower().replace("-", "_")


def _append_generated_zero_branch_tests_if_missing(
    *,
    rules_file: Path,
    test_file: Path,
    repo_path: Path,
    relative_output: Path,
    issues: list[str] | None = None,
    valid_output_names: set[str] | None = None,
) -> list[str]:
    return _append_generic_zero_branch_tests_if_missing(
        rules_file=rules_file,
        test_file=test_file,
        repo_path=repo_path,
        relative_output=relative_output,
        issues=issues or [],
        valid_output_names=valid_output_names,
    )


def _compiled_rulespec_test_output_names(
    pipeline: Any,
    rules_file: Path,
    *,
    relative_output: Path,
) -> set[str] | None:
    """Return local output names accepted by compact tests for a compiled module."""
    compile_fn = getattr(pipeline, "_compile_rulespec_to_artifact", None)
    maps_fn = getattr(pipeline, "_rulespec_program_maps", None)
    policy_repo_path = getattr(pipeline, "policy_repo_path", None)
    if not callable(compile_fn) or not callable(maps_fn) or policy_repo_path is None:
        return None

    try:
        with tempfile.TemporaryDirectory() as tmpdir:
            output_path = Path(tmpdir) / "compiled.json"
            result, payload = compile_fn(rules_file, output_path)
    except Exception:
        return None
    if getattr(result, "returncode", 1) != 0 or not isinstance(payload, dict):
        return None

    derived_by_key, parameter_by_key = maps_fn(payload)
    target_base = _rulespec_anchor_base_for_output(
        Path(policy_repo_path),
        relative_output,
    )
    output_names: set[str] = set()
    for key in {*derived_by_key, *parameter_by_key}:
        key_text = str(key).strip()
        if not key_text:
            continue
        if key_text.startswith(f"{target_base}#"):
            output_names.add(key_text.split("#", 1)[1])
            continue
        if "#" in key_text:
            output_names.add(key_text.split("#", 1)[1])
            continue
        output_names.add(key_text)
    return output_names


def _append_generic_zero_branch_tests_if_missing(
    *,
    rules_file: Path,
    test_file: Path,
    repo_path: Path,
    relative_output: Path,
    issues: list[str],
    valid_output_names: set[str] | None = None,
) -> list[str]:
    """Append deterministic zero-output tests named by validator issues."""
    if not issues or not test_file.exists() or not rules_file.exists():
        return []
    output_names = _zero_branch_output_names_from_issues(issues)
    if not output_names:
        return []

    try:
        rules_content = rules_file.read_text()
        rules_payload = yaml.safe_load(rules_content) or {}
        test_payload = yaml.safe_load(test_file.read_text()) or []
    except (OSError, ValueError, yaml.YAMLError):
        return []
    if not isinstance(rules_payload, dict) or not isinstance(test_payload, list):
        return []

    rules = rules_payload.get("rules")
    if not isinstance(rules, list):
        return []
    rule_names = {
        str(rule.get("name") or "").strip()
        for rule in rules
        if isinstance(rule, dict)
        and str(rule.get("kind") or "").strip().lower() in {"derived", "parameter"}
        and str(rule.get("name") or "").strip()
    }
    target_base = _rulespec_anchor_base_for_output(repo_path, relative_output)
    factual_inputs = _local_factual_input_names_from_rules_content(rules_content)
    input_defaults = {
        f"{target_base}#input.{input_name}": _default_generated_test_input_value(
            input_name,
            rules_payload=rules_payload,
        )
        for input_name in sorted(factual_inputs)
    }

    repaired: list[str] = []
    existing_case_names = {
        str(test_case.get("name") or "").strip()
        for test_case in test_payload
        if isinstance(test_case, dict)
    }
    for output_name in output_names:
        if output_name not in rule_names:
            continue
        if valid_output_names is not None and output_name not in valid_output_names:
            continue
        target = f"{target_base}#{output_name}"
        if _has_zero_output_test(test_payload, target):
            continue
        case_name = f"auto_zero_{_safe_test_name(output_name)}"
        if case_name in existing_case_names:
            continue
        case_inputs = dict(input_defaults)
        case_inputs.update(
            _zero_branch_numeric_upper_bound_input_overrides(
                output_name=output_name,
                rules_payload=rules_payload,
                factual_inputs=factual_inputs,
                target_base=target_base,
            )
        )
        test_payload.append(
            {
                "name": case_name,
                "period": {
                    "period_kind": "tax_year",
                    "start": "2026-01-01",
                    "end": "2026-12-31",
                },
                "input": case_inputs,
                "output": {target: 0},
            }
        )
        existing_case_names.add(case_name)
        repaired.append(case_name)

    if not repaired:
        return []
    test_file.write_text(
        yaml.safe_dump(test_payload, sort_keys=False, allow_unicode=False)
    )
    return repaired


def _zero_branch_numeric_upper_bound_input_overrides(
    *,
    output_name: str,
    rules_payload: dict[str, object],
    factual_inputs: set[str],
    target_base: str,
) -> dict[str, int | float]:
    formulas = _reachable_local_formulas_for_rule(
        output_name=output_name,
        rules_payload=rules_payload,
    )
    if not formulas:
        return {}
    scalar_values = _local_scalar_formula_values_by_name(rules_payload)
    overrides: dict[str, int | float] = {}
    target_formula = _local_formula_for_rule(
        output_name=output_name,
        rules_payload=rules_payload,
    )
    for input_name in sorted(factual_inputs):
        sentinel_selector_value = _numeric_sentinel_selector_zero_input_override(
            input_name=input_name,
            target_formula=target_formula,
            rules_payload=rules_payload,
            scalar_values=scalar_values,
        )
        if sentinel_selector_value is not None:
            overrides[f"{target_base}#input.{input_name}"] = sentinel_selector_value
            continue
        zero_branch_thresholds = _numeric_upper_bounds_returning_zero_for_input(
            input_name,
            formulas=[target_formula] if target_formula else [],
            scalar_values=scalar_values,
        )
        if zero_branch_thresholds:
            threshold, inclusive = zero_branch_thresholds[0]
            overrides[f"{target_base}#input.{input_name}"] = _within_upper_bound_value(
                threshold, inclusive=inclusive
            )
            continue
        thresholds = _numeric_upper_bounds_for_input(
            input_name,
            formulas=formulas,
            scalar_values=scalar_values,
        )
        if not thresholds:
            continue
        threshold = max(thresholds)
        overrides[f"{target_base}#input.{input_name}"] = _above_upper_bound_value(
            threshold
        )
    return overrides


def _numeric_sentinel_selector_zero_input_override(
    *,
    input_name: str,
    target_formula: str | None,
    rules_payload: dict[str, object],
    scalar_values: dict[str, float],
) -> int | float | None:
    if not target_formula:
        return None
    for selector_name in _sentinel_selector_zero_rule_names(target_formula):
        selector_formula = _local_formula_for_rule(
            output_name=selector_name,
            rules_payload=rules_payload,
        )
        if not selector_formula:
            continue
        if not re.search(rf"\b{re.escape(input_name)}\b", selector_formula):
            continue
        if not _formula_can_return_numeric_sentinel(selector_formula, sentinel=-1):
            continue
        lower_edges = _numeric_lower_edge_values_for_input(
            input_name,
            formulas=[selector_formula],
            scalar_values=scalar_values,
        )
        if not lower_edges:
            continue
        return _below_lower_edge_value(min(lower_edges))
    return None


def _sentinel_selector_zero_rule_names(formula: str) -> list[str]:
    pattern = re.compile(
        r"\b(?P<selector>[A-Za-z_][A-Za-z0-9_]*)\s*==\s*-1\s*:\s*0(?:\.0+)?\b"
    )
    names: list[str] = []
    for match in pattern.finditer(formula):
        selector = match["selector"]
        if selector not in names:
            names.append(selector)
    return names


def _formula_can_return_numeric_sentinel(formula: str, *, sentinel: int) -> bool:
    sentinel_text = re.escape(str(sentinel))
    return bool(re.search(rf"(?:^|[:\s]){sentinel_text}(?:\.0+)?\b", formula))


def _numeric_lower_edge_values_for_input(
    input_name: str,
    *,
    formulas: list[str],
    scalar_values: dict[str, float],
) -> list[float]:
    rhs_pattern = r"(?P<rhs>-?\d+(?:\.\d+)?|[A-Za-z_][A-Za-z0-9_]*)"
    left_pattern = re.compile(
        rf"\b{re.escape(input_name)}\b\s*(?P<op>==|>=|>)\s*{rhs_pattern}"
    )
    right_pattern = re.compile(
        rf"(?P<rhs>-?\d+(?:\.\d+)?|[A-Za-z_][A-Za-z0-9_]*)"
        rf"\s*(?P<op>==|<=|<)\s*\b{re.escape(input_name)}\b"
    )
    thresholds: list[float] = []
    for formula in formulas:
        for pattern in (left_pattern, right_pattern):
            for match in pattern.finditer(formula):
                value = _numeric_formula_rhs_value(match["rhs"], scalar_values)
                if value is not None:
                    thresholds.append(value)
    return thresholds


def _below_lower_edge_value(threshold: float) -> int | float:
    if threshold.is_integer():
        return int(threshold) - 1
    return threshold - max(1.0, abs(threshold) * 0.01)


def _local_formula_for_rule(
    *,
    output_name: str,
    rules_payload: dict[str, object],
) -> str | None:
    rules = rules_payload.get("rules")
    if not isinstance(rules, list):
        return None
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        if str(rule.get("name") or "").strip() != output_name:
            continue
        formula = _first_rule_formula(rule)
        return formula or None
    return None


def _reachable_local_formulas_for_rule(
    *,
    output_name: str,
    rules_payload: dict[str, object],
) -> list[str]:
    rules = rules_payload.get("rules")
    if not isinstance(rules, list):
        return []
    rules_by_name = {
        str(rule.get("name") or "").strip(): rule
        for rule in rules
        if isinstance(rule, dict) and str(rule.get("name") or "").strip()
    }
    formulas: list[str] = []
    seen: set[str] = set()

    def visit(name: str) -> None:
        if name in seen:
            return
        seen.add(name)
        rule = rules_by_name.get(name)
        if not isinstance(rule, dict):
            return
        formula = _first_rule_formula(rule)
        if not formula:
            return
        formulas.append(formula)
        for identifier in sorted(_formula_identifiers(formula)):
            if identifier in rules_by_name:
                visit(identifier)

    visit(output_name)
    return formulas


def _local_scalar_formula_values_by_name(
    rules_payload: dict[str, object],
) -> dict[str, float]:
    rules = rules_payload.get("rules")
    if not isinstance(rules, list):
        return {}
    values: dict[str, float] = {}
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        name = str(rule.get("name") or "").strip()
        if not name:
            continue
        formula = _first_rule_formula(rule).strip()
        if not re.fullmatch(r"-?\d+(?:\.\d+)?", formula):
            continue
        with contextlib.suppress(ValueError):
            values[name] = float(formula)
    return values


def _numeric_upper_bounds_for_input(
    input_name: str,
    *,
    formulas: list[str],
    scalar_values: dict[str, float],
) -> list[float]:
    rhs_pattern = r"(?P<rhs>-?\d+(?:\.\d+)?|[A-Za-z_][A-Za-z0-9_]*)"
    pattern = re.compile(rf"\b{re.escape(input_name)}\b\s*<=?\s*{rhs_pattern}")
    thresholds: list[float] = []
    for formula in formulas:
        for match in pattern.finditer(formula):
            value = _numeric_formula_rhs_value(match["rhs"], scalar_values)
            if value is not None:
                thresholds.append(value)
    return thresholds


def _numeric_upper_bounds_returning_zero_for_input(
    input_name: str,
    *,
    formulas: list[str],
    scalar_values: dict[str, float],
) -> list[tuple[float, bool]]:
    rhs_pattern = r"(?P<rhs>-?\d+(?:\.\d+)?|[A-Za-z_][A-Za-z0-9_]*)"
    pattern = re.compile(
        rf"\b{re.escape(input_name)}\b\s*(?P<op><=|<)\s*{rhs_pattern}\s*:"
        r"\s*0(?:\.0+)?\b"
    )
    thresholds: list[tuple[float, bool]] = []
    for formula in formulas:
        for match in pattern.finditer(formula):
            value = _numeric_formula_rhs_value(match["rhs"], scalar_values)
            if value is not None:
                thresholds.append((value, match["op"] == "<="))
    return thresholds


def _numeric_formula_rhs_value(
    rhs: str,
    scalar_values: dict[str, float],
) -> float | None:
    if re.fullmatch(r"-?\d+(?:\.\d+)?", rhs):
        with contextlib.suppress(ValueError):
            return float(rhs)
    return scalar_values.get(rhs)


def _within_upper_bound_value(
    threshold: float,
    *,
    inclusive: bool,
) -> int | float:
    if inclusive:
        return int(threshold) if threshold.is_integer() else threshold
    if threshold.is_integer():
        return int(threshold) - 1
    return threshold - max(0.01, abs(threshold) * 0.01)


def _above_upper_bound_value(threshold: float) -> int | float:
    if threshold.is_integer():
        return int(threshold) + 1
    return threshold + max(1.0, abs(threshold) * 0.01)


def _append_generated_derived_output_tests_if_missing(
    *,
    rules_file: Path,
    test_file: Path,
    repo_path: Path,
    relative_output: Path,
    issues: list[str],
) -> list[str]:
    """Append deterministic companion cases for local derived outputs."""
    if not issues or not test_file.exists() or not rules_file.exists():
        return []
    output_targets = _missing_derived_output_targets_from_issues(issues)
    if not output_targets:
        return []

    try:
        rules_content = rules_file.read_text()
        rules_payload = yaml.safe_load(rules_content) or {}
        test_payload = yaml.safe_load(test_file.read_text()) or []
    except (OSError, ValueError, yaml.YAMLError):
        return []
    if not isinstance(rules_payload, dict) or not isinstance(test_payload, list):
        return []

    rules = rules_payload.get("rules")
    if not isinstance(rules, list):
        return []

    target_base = (
        f"{_repo_jurisdiction_prefix(repo_path)}:"
        f"{_relative_rulespec_import_target(relative_output)}"
    )
    derived_rules_by_target = {
        f"{target_base}#{rule_name}": rule
        for rule in rules
        if isinstance(rule, dict)
        and str(rule.get("kind") or "").strip().lower() == "derived"
        and (rule_name := str(rule.get("name") or "").strip())
    }
    existing_outputs = _rulespec_test_output_keys(test_file)
    factual_inputs = _local_factual_input_names_from_rules_content(rules_content)
    input_defaults = {
        f"{target_base}#input.{input_name}": _default_generated_test_input_value(
            input_name,
            rules_payload=rules_payload,
            prefer_positive_counts=True,
        )
        for input_name in sorted(factual_inputs)
    }

    repaired: list[str] = []
    existing_case_names = {
        str(test_case.get("name") or "").strip()
        for test_case in test_payload
        if isinstance(test_case, dict)
    }
    for target in output_targets:
        if target in existing_outputs:
            continue
        rule = derived_rules_by_target.get(target)
        if rule is None:
            continue
        output_name = target.rsplit("#", 1)[-1]
        case_name = f"auto_output_{_safe_test_name(output_name)}"
        if case_name in existing_case_names:
            continue
        test_payload.append(
            {
                "name": case_name,
                "period": {
                    "period_kind": "tax_year",
                    "start": "2026-01-01",
                    "end": "2026-12-31",
                },
                "input": dict(input_defaults),
                "output": {
                    target: _default_generated_test_output_value(
                        rule,
                        rules_payload=rules_payload,
                    ),
                },
            }
        )
        existing_case_names.add(case_name)
        repaired.append(case_name)

    if not repaired:
        return []
    test_file.write_text(
        yaml.safe_dump(test_payload, sort_keys=False, allow_unicode=False)
    )
    return repaired


def _append_generated_judgment_positive_tests_if_missing(
    *,
    rules_file: Path | None = None,
    test_file: Path,
    repo_path: Path,
    axiom_rules_path: Path,
    relative_output: Path,
    issues: list[str],
    test_failure_checker=None,
) -> list[str]:
    """Clone existing scenarios into positive Judgment companion tests."""
    if not issues or not test_file.exists():
        return []
    output_targets = _judgment_positive_output_targets_from_issues(issues)
    if not output_targets:
        return []

    rules_payload: dict[str, object] | None = None
    try:
        test_payload = yaml.safe_load(test_file.read_text()) or []
        if rules_file is not None and rules_file.exists():
            loaded_rules = yaml.safe_load(rules_file.read_text()) or {}
            if isinstance(loaded_rules, dict):
                rules_payload = loaded_rules
    except (OSError, ValueError, yaml.YAMLError):
        return []
    if not isinstance(test_payload, list):
        return []

    target_base = _rulespec_anchor_base_for_output(repo_path, relative_output)
    existing_case_names = {
        str(test_case.get("name") or "").strip()
        for test_case in test_payload
        if isinstance(test_case, dict)
    }
    rules_by_name = _rules_by_name_from_payload(rules_payload)
    derived_rules_by_target = {
        f"{target_base}#{rule_name}": rule
        for rule_name, rule in rules_by_name.items()
        if str(rule.get("kind") or "").strip().lower() == "derived"
        and str(rule.get("dtype") or "").strip().lower() == "judgment"
    }
    repaired: list[str] = []
    for target in output_targets:
        rule_name = target.rsplit("#", 1)[-1]
        rule = derived_rules_by_target.get(target)
        versions = rule.get("versions") if isinstance(rule, dict) else None
        if isinstance(versions, list) and _rule_versions_are_constant_false(versions):
            continue
        if _test_payload_has_rule_output_value(
            test_payload, rule_name=rule_name, normalized_value="holds"
        ):
            continue
        case_name = _unique_generated_test_name(
            f"auto_positive_{_safe_test_name(rule_name)}",
            existing_case_names,
        )
        candidate_payload: list[object] | None = None
        synthesized = _build_generated_positive_judgment_case(
            case_name=case_name,
            target=f"{target_base}#{rule_name}",
            target_base=target_base,
            rule=rule,
            rules_payload=rules_payload,
            repo_path=repo_path,
            rules_by_name=rules_by_name,
            test_payload=test_payload,
        )
        if synthesized is not None:
            trial_payload = list(test_payload)
            trial_payload.append(synthesized)
            if test_failure_checker is not None:
                test_file.write_text(
                    yaml.safe_dump(trial_payload, sort_keys=False, allow_unicode=False)
                )
                failures = test_failure_checker(
                    test_file,
                    root=repo_path,
                    axiom_rules_path=axiom_rules_path,
                )
                if not failures:
                    candidate_payload = trial_payload
            else:
                candidate_payload = trial_payload
        for test_case in test_payload:
            if candidate_payload is not None:
                break
            if not isinstance(test_case, dict):
                continue
            outputs = test_case.get("output")
            if not isinstance(outputs, dict):
                continue
            if _case_asserts_rule_value(
                outputs, rule_name=rule_name, normalized_value="not_holds"
            ):
                continue
            companion = copy.deepcopy(test_case)
            companion["name"] = case_name
            companion["output"] = {f"{target_base}#{rule_name}": "holds"}
            trial_payload = list(test_payload)
            trial_payload.append(companion)
            if test_failure_checker is not None:
                test_file.write_text(
                    yaml.safe_dump(trial_payload, sort_keys=False, allow_unicode=False)
                )
                failures = test_failure_checker(
                    test_file,
                    root=repo_path,
                    axiom_rules_path=axiom_rules_path,
                )
                if failures:
                    continue
            candidate_payload = trial_payload
            break

        if candidate_payload is None:
            test_file.write_text(
                yaml.safe_dump(test_payload, sort_keys=False, allow_unicode=False)
            )
            continue
        test_payload = candidate_payload
        existing_case_names.add(case_name)
        repaired.append(case_name)

    if not repaired:
        return []
    test_file.write_text(
        yaml.safe_dump(test_payload, sort_keys=False, allow_unicode=False)
    )
    return repaired


def _rules_by_name_from_payload(
    rules_payload: dict[str, object] | None,
) -> dict[str, dict[str, object]]:
    if not isinstance(rules_payload, dict):
        return {}
    rules = rules_payload.get("rules")
    if not isinstance(rules, list):
        return {}
    return {
        name: rule
        for rule in rules
        if isinstance(rule, dict) and (name := str(rule.get("name") or "").strip())
    }


def _build_generated_positive_judgment_case(
    *,
    case_name: str,
    target: str,
    target_base: str,
    rule: dict[str, object] | None,
    rules_payload: dict[str, object] | None,
    repo_path: Path,
    rules_by_name: dict[str, dict[str, object]],
    test_payload: list[object],
) -> dict[str, object] | None:
    if rule is None or not isinstance(rules_payload, dict):
        return None
    formula = _first_rule_formula(rule)
    if not formula:
        return None

    imported_outputs = _imported_output_names_from_payload(rules_payload)
    assignments = _positive_judgment_formula_input_assignments(
        formula=formula,
        rules_payload=rules_payload,
        rules_by_name=rules_by_name,
        imported_outputs=imported_outputs,
    )
    imported_positive_inputs = _positive_imported_judgment_inputs_for_formula(
        formula=formula,
        rules_payload=rules_payload,
        repo_path=repo_path,
        imported_outputs=imported_outputs,
    )
    imported_inputs = _nonlocal_input_assignments_from_existing_cases(
        test_payload,
        target_base=target_base,
    )
    if not assignments and not imported_inputs and not imported_positive_inputs:
        return None

    inputs: dict[object, object] = dict(imported_inputs)
    inputs.update(imported_positive_inputs)
    for input_name, value in sorted(assignments.items()):
        inputs[f"{target_base}#input.{input_name}"] = value

    return {
        "name": case_name,
        "period": {
            "period_kind": "tax_year",
            "start": "2026-01-01",
            "end": "2026-12-31",
        },
        "input": inputs,
        "output": {target: "holds"},
    }


def _positive_imported_judgment_inputs_for_formula(
    *,
    formula: str,
    rules_payload: dict[str, object],
    repo_path: Path,
    imported_outputs: set[str],
) -> dict[object, object]:
    """Copy child companion inputs for imported Judgment operands that must hold."""
    if not imported_outputs:
        return {}
    imports = rules_payload.get("imports")
    if not isinstance(imports, list):
        return {}

    negated_group_spans = _negated_parenthesized_expression_spans(formula)
    positive_context_formula = _formula_with_spans_blank(
        formula,
        [(start, end) for start, end, _expression in negated_group_spans],
    )
    identifiers = _formula_identifiers(positive_context_formula)
    negated_identifiers = set(
        re.findall(r"\bnot\s+([A-Za-z_][A-Za-z0-9_]*)\b", positive_context_formula)
    )
    needed_imported_outputs = (identifiers - negated_identifiers) & imported_outputs
    if not needed_imported_outputs:
        return {}

    inputs: dict[object, object] = {}
    for raw_import in imports:
        if not isinstance(raw_import, str) or "#" not in raw_import:
            continue
        output_name = raw_import.rsplit("#", 1)[1].strip()
        if output_name not in needed_imported_outputs:
            continue
        resolved_import = _same_repo_import_base_and_file(
            raw_import,
            repo_path=repo_path,
        )
        if resolved_import is None:
            continue
        _canonical_base, import_file = resolved_import
        if import_file is None or not import_file.exists():
            continue
        inputs.update(
            _positive_companion_inputs_for_output(
                _rulespec_test_path(import_file),
                output_name=output_name,
            )
        )
    return inputs


def _positive_companion_inputs_for_output(
    test_file: Path,
    *,
    output_name: str,
) -> dict[object, object]:
    if not test_file.exists():
        return {}
    try:
        test_payload = yaml.safe_load(test_file.read_text()) or []
    except (OSError, ValueError, yaml.YAMLError):
        return {}
    if not isinstance(test_payload, list):
        return {}

    for test_case in test_payload:
        if not isinstance(test_case, dict):
            continue
        inputs = test_case.get("input")
        outputs = test_case.get("output")
        if not isinstance(inputs, dict) or not isinstance(outputs, dict):
            continue
        if _case_asserts_rule_value(
            outputs,
            rule_name=output_name,
            normalized_value="holds",
        ):
            return dict(inputs)
    return {}


def _positive_judgment_formula_input_assignments(
    *,
    formula: str,
    rules_payload: dict[str, object],
    rules_by_name: dict[str, dict[str, object]],
    imported_outputs: set[str],
) -> dict[str, object]:
    assignments, _protected = _positive_judgment_formula_input_assignments_for_formula(
        formula=formula,
        rules_payload=rules_payload,
        rules_by_name=rules_by_name,
        imported_outputs=imported_outputs,
        seen_rules=set(),
    )
    return assignments


_FORBIDDEN_GENERATED_JUDGMENT_INPUTS = {"filing_status", "tax_filing_status"}


def _positive_judgment_assignments_use_forbidden_inputs(
    assignments: dict[str, object],
) -> bool:
    return any(
        input_name in _FORBIDDEN_GENERATED_JUDGMENT_INPUTS for input_name in assignments
    )


def _split_top_level_boolean_disjunction(formula: str) -> list[str]:
    stripped_formula = _strip_balanced_outer_parentheses(formula.strip())
    branches: list[str] = []
    depth = 0
    quote: str | None = None
    branch_start = 0
    index = 0
    while index < len(stripped_formula):
        char = stripped_formula[index]
        if quote:
            if char == quote:
                quote = None
            index += 1
            continue
        if char in {"'", '"'}:
            quote = char
            index += 1
            continue
        if char in "([{":
            depth += 1
            index += 1
            continue
        if char in ")]}":
            if depth:
                depth -= 1
            index += 1
            continue
        if (
            depth == 0
            and stripped_formula.startswith("or", index)
            and _is_word_operator_at(stripped_formula, index, len("or"))
        ):
            branch = stripped_formula[branch_start:index].strip()
            if branch:
                branches.append(_strip_balanced_outer_parentheses(branch))
            index += len("or")
            branch_start = index
            continue
        index += 1
    final_branch = stripped_formula[branch_start:].strip()
    if final_branch:
        branches.append(_strip_balanced_outer_parentheses(final_branch))
    return [branch for branch in branches if branch]


def _is_word_operator_at(text: str, start: int, length: int) -> bool:
    before = text[start - 1] if start > 0 else " "
    after_index = start + length
    after = text[after_index] if after_index < len(text) else " "
    return not (before.isalnum() or before == "_") and not (
        after.isalnum() or after == "_"
    )


def _positive_judgment_formula_input_assignments_for_formula(
    *,
    formula: str,
    rules_payload: dict[str, object],
    rules_by_name: dict[str, dict[str, object]],
    imported_outputs: set[str],
    seen_rules: set[str],
) -> tuple[dict[str, object], set[str]]:
    disjuncts = _split_top_level_boolean_disjunction(formula)
    if len(disjuncts) > 1:
        branch_results: list[tuple[str, dict[str, object], set[str]]] = []
        for disjunct in disjuncts:
            branch_assignments, branch_protected_inputs = (
                _positive_judgment_formula_input_assignments_for_formula(
                    formula=disjunct,
                    rules_payload=rules_payload,
                    rules_by_name=rules_by_name,
                    imported_outputs=imported_outputs,
                    seen_rules=seen_rules,
                )
            )
            if branch_assignments or branch_protected_inputs:
                branch_results.append(
                    (disjunct, branch_assignments, branch_protected_inputs)
                )
        legal_branch_results = [
            result
            for result in branch_results
            if not _positive_judgment_assignments_use_forbidden_inputs(result[1])
        ]
        if legal_branch_results:
            _chosen_disjunct, branch_assignments, branch_protected_inputs = min(
                legal_branch_results,
                key=lambda result: len(result[1]),
            )
            assignments = _neutral_unassigned_formula_input_assignments(
                formula=formula,
                rules_payload=rules_payload,
                rules_by_name=rules_by_name,
                imported_outputs=imported_outputs,
                assigned_inputs=set(branch_assignments),
            )
            assignments.update(branch_assignments)
            return assignments, branch_protected_inputs

    negated_group_spans = _negated_parenthesized_expression_spans(formula)
    positive_context_formula = _formula_with_spans_blank(
        formula,
        [(start, end) for start, end, _expression in negated_group_spans],
    )
    identifiers = _formula_identifiers(positive_context_formula)
    negated_identifiers = set(
        re.findall(r"\bnot\s+([A-Za-z_][A-Za-z0-9_]*)\b", positive_context_formula)
    )
    protected_positive_inputs: set[str] = set()
    assignments: dict[str, object] = {}
    defined_symbols = set(rules_by_name) | imported_outputs

    for identifier in sorted(identifiers - negated_identifiers):
        dependency = rules_by_name.get(identifier)
        if dependency is not None:
            if _rule_is_derived_judgment(dependency) and identifier not in seen_rules:
                dependency_formula = _first_rule_formula(dependency)
                if dependency_formula:
                    (
                        dependency_assignments,
                        dependency_protected_inputs,
                    ) = _positive_judgment_formula_input_assignments_for_formula(
                        formula=dependency_formula,
                        rules_payload=rules_payload,
                        rules_by_name=rules_by_name,
                        imported_outputs=imported_outputs,
                        seen_rules=seen_rules | {identifier},
                    )
                    for input_name, value in dependency_assignments.items():
                        assignments.setdefault(input_name, value)
                    protected_positive_inputs.update(dependency_protected_inputs)
            elif dependency_formula := _first_rule_formula(dependency):
                (
                    helper_assignments,
                    helper_protected_inputs,
                ) = _positive_count_helper_input_assignments(
                    helper_name=identifier,
                    parent_formula=formula,
                    helper_formula=dependency_formula,
                    rules_payload=rules_payload,
                    rules_by_name=rules_by_name,
                    imported_outputs=imported_outputs,
                    excluded_true_inputs=negated_identifiers,
                    protected_positive_inputs=protected_positive_inputs,
                )
                for input_name, value in helper_assignments.items():
                    assignments.setdefault(input_name, value)
                protected_positive_inputs.update(helper_protected_inputs)
            continue
        if identifier in imported_outputs:
            continue
        assignments[identifier] = _positive_generated_test_input_value(
            identifier,
            rules_payload=rules_payload,
            formula=formula,
        )
        protected_positive_inputs.add(identifier)

    for identifier in sorted(negated_identifiers):
        dependency = rules_by_name.get(identifier)
        if dependency is None:
            if identifier not in imported_outputs:
                assignments[identifier] = False
            continue
        dependency_formula = _first_rule_formula(dependency)
        if not dependency_formula:
            continue
        dependency_inputs = [
            name
            for name in sorted(_formula_identifiers(dependency_formula))
            if name not in defined_symbols and name not in protected_positive_inputs
        ]
        if not dependency_inputs:
            continue
        input_name = _preferred_false_breaker_input(
            dependency_inputs,
            rules_payload=rules_payload,
        )
        assignments[input_name] = False

    for _start, _end, expression in negated_group_spans:
        assignments.update(
            _negated_expression_false_assignments(
                expression=expression,
                rules_payload=rules_payload,
                rules_by_name=rules_by_name,
                imported_outputs=imported_outputs,
                protected_positive_inputs=protected_positive_inputs,
            )
        )

    return assignments, protected_positive_inputs


def _neutral_unassigned_formula_input_assignments(
    *,
    formula: str,
    rules_payload: dict[str, object],
    rules_by_name: dict[str, dict[str, object]],
    imported_outputs: set[str],
    assigned_inputs: set[str],
) -> dict[str, object]:
    defined_symbols = set(rules_by_name) | imported_outputs
    assignments: dict[str, object] = {}
    for identifier in sorted(_formula_identifiers(formula)):
        if identifier in defined_symbols or identifier in assigned_inputs:
            continue
        assignments[identifier] = _default_generated_test_input_value(
            identifier,
            rules_payload=rules_payload,
        )
    return assignments


def _positive_count_helper_input_assignments(
    *,
    helper_name: str,
    parent_formula: str,
    helper_formula: str,
    rules_payload: dict[str, object],
    rules_by_name: dict[str, dict[str, object]],
    imported_outputs: set[str],
    excluded_true_inputs: set[str],
    protected_positive_inputs: set[str],
) -> tuple[dict[str, object], set[str]]:
    required_count = _integer_equality_count_for_helper(
        formula=parent_formula,
        helper_name=helper_name,
    )
    if required_count is None:
        return {}, set()
    helper_inputs = _boolean_sum_count_helper_inputs(
        formula=helper_formula,
        rules_payload=rules_payload,
        rules_by_name=rules_by_name,
        imported_outputs=imported_outputs,
    )
    if not helper_inputs or required_count > len(helper_inputs):
        return {}, set()

    already_selected = [
        input_name
        for input_name in helper_inputs
        if input_name in protected_positive_inputs
    ]
    if len(already_selected) > required_count:
        return {}, set()

    remaining_needed = required_count - len(already_selected)
    selectable = [
        input_name
        for input_name in helper_inputs
        if input_name not in protected_positive_inputs
        and input_name not in excluded_true_inputs
    ]
    if remaining_needed > len(selectable):
        return {}, set()

    selected = set(already_selected)
    selected.update(selectable[:remaining_needed])
    assignments: dict[str, object] = {}
    for input_name in helper_inputs:
        if input_name in protected_positive_inputs and input_name not in selected:
            return {}, set()
        assignments[input_name] = input_name in selected
    return assignments, selected


def _integer_equality_count_for_helper(*, formula: str, helper_name: str) -> int | None:
    token = re.escape(helper_name)
    patterns = (
        re.compile(rf"\b{token}\b\s*==\s*(?P<count>\d+)\b"),
        re.compile(rf"\b(?P<count>\d+)\b\s*==\s*\b{token}\b"),
    )
    for pattern in patterns:
        match = pattern.search(formula)
        if match is not None:
            return int(match["count"])
    return None


def _boolean_sum_count_helper_inputs(
    *,
    formula: str,
    rules_payload: dict[str, object],
    rules_by_name: dict[str, dict[str, object]],
    imported_outputs: set[str],
) -> list[str]:
    defined_symbols = set(rules_by_name) | imported_outputs
    inputs: list[str] = []
    seen: set[str] = set()
    pattern = re.compile(
        r"\bif\s+(?P<input>[A-Za-z_][A-Za-z0-9_]*)\s*:\s*1\s+else\s*:\s*0\b"
    )
    for match in pattern.finditer(formula):
        input_name = match["input"]
        if input_name in seen or input_name in defined_symbols:
            continue
        if _factual_input_appears_numeric(input_name, rules_payload=rules_payload):
            continue
        seen.add(input_name)
        inputs.append(input_name)
    return inputs


def _rule_is_derived_judgment(rule: dict[str, object]) -> bool:
    return (
        str(rule.get("kind") or "").strip().lower() == "derived"
        and str(rule.get("dtype") or "").strip().lower() == "judgment"
    )


def _negated_parenthesized_expression_spans(
    formula: str,
) -> list[tuple[int, int, str]]:
    spans: list[tuple[int, int, str]] = []
    for match in re.finditer(r"\bnot\s*\(", formula):
        open_paren = match.end() - 1
        depth = 0
        for index in range(open_paren, len(formula)):
            char = formula[index]
            if char == "(":
                depth += 1
            elif char == ")":
                depth -= 1
                if depth == 0:
                    spans.append(
                        (match.start(), index + 1, formula[open_paren + 1 : index])
                    )
                    break
    return spans


def _formula_with_spans_blank(formula: str, spans: list[tuple[int, int]]) -> str:
    chars = list(formula)
    for start, end in spans:
        for index in range(max(start, 0), min(end, len(chars))):
            chars[index] = " "
    return "".join(chars)


def _negated_expression_false_assignments(
    *,
    expression: str,
    rules_payload: dict[str, object],
    rules_by_name: dict[str, dict[str, object]],
    imported_outputs: set[str],
    protected_positive_inputs: set[str],
) -> dict[str, object]:
    identifiers = _formula_identifiers(expression)
    defined_symbols = set(rules_by_name) | imported_outputs
    assignments: dict[str, object] = {}

    for identifier in sorted(identifiers):
        if identifier in protected_positive_inputs or identifier in imported_outputs:
            continue
        dependency = rules_by_name.get(identifier)
        if dependency is not None:
            dependency_formula = _first_rule_formula(dependency)
            if not dependency_formula:
                continue
            for dependency_input in sorted(_formula_identifiers(dependency_formula)):
                if (
                    dependency_input in defined_symbols
                    or dependency_input in protected_positive_inputs
                    or _factual_input_appears_numeric(
                        dependency_input,
                        rules_payload=rules_payload,
                    )
                ):
                    continue
                assignments[dependency_input] = False
            continue
        if _factual_input_appears_numeric(identifier, rules_payload=rules_payload):
            continue
        assignments[identifier] = False

    if assignments:
        return assignments

    scalar_values = _local_scalar_formula_values_by_name(rules_payload)
    for identifier in sorted(identifiers):
        if identifier in defined_symbols or identifier in protected_positive_inputs:
            continue
        if not _factual_input_appears_numeric(identifier, rules_payload=rules_payload):
            continue
        value = _numeric_false_assignment_for_expression(
            input_name=identifier,
            expression=expression,
            scalar_values=scalar_values,
        )
        if value is not None:
            assignments[identifier] = value
    return assignments


def _numeric_false_assignment_for_expression(
    *,
    input_name: str,
    expression: str,
    scalar_values: dict[str, float],
) -> int | float | None:
    token = re.escape(input_name)
    value_token = r"-?\d+(?:\.\d+)?|[A-Za-z_][A-Za-z0-9_]*"
    right_pattern = re.compile(
        rf"\b{token}\b\s*(?P<op><=|>=|<|>)\s*(?P<threshold>{value_token})"
    )
    left_pattern = re.compile(
        rf"(?P<threshold>{value_token})\s*(?P<op><=|>=|<|>)\s*\b{token}\b"
    )
    for match in right_pattern.finditer(expression):
        return _comparison_false_input_value(
            operator=match["op"],
            threshold=_formula_numeric_threshold_value(
                match["threshold"], scalar_values=scalar_values
            ),
            input_on_left=True,
        )
    for match in left_pattern.finditer(expression):
        if match["threshold"] == input_name:
            continue
        return _comparison_false_input_value(
            operator=match["op"],
            threshold=_formula_numeric_threshold_value(
                match["threshold"], scalar_values=scalar_values
            ),
            input_on_left=False,
        )
    return None


def _formula_numeric_threshold_value(
    token: str, *, scalar_values: dict[str, float]
) -> float | None:
    if re.fullmatch(r"-?\d+(?:\.\d+)?", token):
        with contextlib.suppress(ValueError):
            return float(token)
    return scalar_values.get(token)


def _comparison_false_input_value(
    *, operator: str, threshold: float | None, input_on_left: bool
) -> int | float:
    high_default = 999999
    low_default = 0
    if input_on_left:
        if operator == "<":
            return _threshold_or_default(threshold, high_default)
        if operator == "<=":
            return (
                _above_upper_bound_value(threshold)
                if threshold is not None
                else high_default
            )
        if operator == ">":
            return _threshold_or_default(threshold, low_default)
        if operator == ">=":
            return (
                _below_lower_bound_value(threshold)
                if threshold is not None
                else low_default
            )
    if operator == "<":
        return _threshold_or_default(threshold, low_default)
    if operator == "<=":
        return (
            _below_lower_bound_value(threshold)
            if threshold is not None
            else low_default
        )
    if operator == ">":
        return _threshold_or_default(threshold, high_default)
    return (
        _above_upper_bound_value(threshold) if threshold is not None else high_default
    )


def _threshold_or_default(threshold: float | None, default: int) -> int | float:
    if threshold is None:
        return default
    if threshold.is_integer():
        return int(threshold)
    return threshold


def _below_lower_bound_value(threshold: float) -> int | float:
    if threshold.is_integer():
        return int(threshold) - 1
    return threshold - max(1.0, abs(threshold) * 0.01)


def _positive_generated_test_input_value(
    input_name: str,
    *,
    rules_payload: dict[str, object],
    formula: str,
) -> object:
    string_value = _string_positive_assignment_for_expression(
        input_name=input_name,
        expression=formula,
    )
    if string_value is not None:
        return string_value
    comparison_value = _numeric_positive_assignment_for_expression(
        input_name=input_name,
        expression=formula,
    )
    if comparison_value is not None:
        return comparison_value
    if not _factual_input_appears_numeric(input_name, rules_payload=rules_payload):
        return True
    return 999999


def _string_positive_assignment_for_expression(
    *,
    input_name: str,
    expression: str,
) -> str | None:
    token = re.escape(input_name)
    literal = _RULESPEC_STRING_LITERAL_RE
    right_pattern = re.compile(rf"\b{token}\b\s*==\s*(?P<literal>{literal})")
    left_pattern = re.compile(rf"(?P<literal>{literal})\s*==\s*\b{token}\b")
    for pattern in (right_pattern, left_pattern):
        match = pattern.search(expression)
        if match is None:
            continue
        return _rulespec_string_literal_value(match["literal"])
    return None


def _rulespec_string_literal_value(token: str) -> str | None:
    try:
        value = yaml.safe_load(token)
    except yaml.YAMLError:
        return None
    if isinstance(value, str):
        return value
    return None


def _numeric_positive_assignment_for_expression(
    *,
    input_name: str,
    expression: str,
) -> int | None:
    token = re.escape(input_name)
    value_token = r"-?\d+(?:\.\d+)?|[A-Za-z_][A-Za-z0-9_]*"
    right_pattern = re.compile(
        rf"\b{token}\b\s*(?P<op><=|>=|<|>)\s*(?P<threshold>{value_token})"
    )
    left_pattern = re.compile(
        rf"(?P<threshold>{value_token})\s*(?P<op><=|>=|<|>)\s*\b{token}\b"
    )
    for match in right_pattern.finditer(expression):
        return 0 if match["op"] in {"<", "<="} else 999999
    for match in left_pattern.finditer(expression):
        if match["threshold"] == input_name:
            continue
        return 999999 if match["op"] in {"<", "<="} else 0
    return None


def _preferred_false_breaker_input(
    input_names: list[str],
    *,
    rules_payload: dict[str, object],
) -> str:
    for input_name in input_names:
        if not _factual_input_appears_numeric(input_name, rules_payload=rules_payload):
            return input_name
    return input_names[0]


def _nonlocal_input_assignments_from_existing_cases(
    test_payload: list[object],
    *,
    target_base: str,
) -> dict[object, object]:
    for test_case in test_payload:
        if not isinstance(test_case, dict):
            continue
        inputs = test_case.get("input")
        if not isinstance(inputs, dict):
            continue
        nonlocal_inputs = {
            key: value
            for key, value in inputs.items()
            if "#input." in str(key)
            and not _rulespec_ref_matches_base(str(key), target_base)
        }
        if nonlocal_inputs:
            return nonlocal_inputs
    return {}


def _judgment_positive_output_targets_from_issues(issues: list[str]) -> list[str]:
    targets: list[str] = []
    seen: set[str] = set()
    for issue in issues:
        match = re.search(
            r"Judgment rule missing positive companion output coverage:"
            r"\s*`(?P<target>[^`]+)`",
            str(issue),
        )
        if not match:
            continue
        target = match["target"].strip()
        if not target or target in seen:
            continue
        seen.add(target)
        targets.append(target)
    return targets


def _test_payload_has_rule_output_value(
    test_payload: list[object],
    *,
    rule_name: str,
    normalized_value: str,
) -> bool:
    for test_case in test_payload:
        if not isinstance(test_case, dict):
            continue
        outputs = test_case.get("output")
        if not isinstance(outputs, dict):
            continue
        if _case_asserts_rule_value(
            outputs, rule_name=rule_name, normalized_value=normalized_value
        ):
            return True
    return False


def _unique_generated_test_name(base_name: str, existing_case_names: set[str]) -> str:
    if base_name not in existing_case_names:
        return base_name
    index = 2
    while f"{base_name}_{index}" in existing_case_names:
        index += 1
    return f"{base_name}_{index}"


def _missing_derived_output_targets_from_issues(issues: list[str]) -> list[str]:
    targets: list[str] = []
    seen: set[str] = set()
    for issue in issues:
        match = re.search(
            r"Derived rule missing companion output coverage:\s*`(?P<target>[^`]+)`",
            str(issue),
        )
        if not match:
            continue
        target = match["target"].strip()
        if not target or target in seen:
            continue
        seen.add(target)
        targets.append(target)
    return targets


def _default_generated_test_output_value(
    rule: dict[str, object],
    *,
    rules_payload: dict[str, object] | None = None,
) -> object:
    dtype = str(rule.get("dtype") or "").strip().lower()
    if dtype in {"integer", "int"}:
        selector_value = _default_generated_selector_output_value(
            rule,
            rules_payload=rules_payload,
        )
        if selector_value is not None:
            return selector_value
    if dtype == "judgment":
        return "not_holds"
    if dtype in {"boolean", "bool"}:
        return False
    if dtype in {"list", "array"}:
        return []
    return 0


def _default_generated_selector_output_value(
    rule: dict[str, object],
    *,
    rules_payload: dict[str, object] | None,
) -> int | None:
    selector_name = str(rule.get("name") or "").strip()
    if not selector_name or not isinstance(rules_payload, dict):
        return None
    table_keys: list[int] = []
    rules = rules_payload.get("rules")
    if not isinstance(rules, list):
        return None
    for candidate in rules:
        if not isinstance(candidate, dict):
            continue
        if str(candidate.get("kind") or "").strip().lower() != "parameter":
            continue
        if str(candidate.get("indexed_by") or "").strip() != selector_name:
            continue
        versions = candidate.get("versions")
        if not isinstance(versions, list):
            continue
        for version in versions:
            if not isinstance(version, dict):
                continue
            values = version.get("values")
            if not isinstance(values, dict):
                continue
            table_keys.extend(
                key
                for raw_key in values
                if (key := _integer_table_key(raw_key)) is not None
            )
    return min(table_keys) if table_keys else None


def _integer_table_key(raw_key: object) -> int | None:
    if isinstance(raw_key, bool):
        return None
    if isinstance(raw_key, int):
        return raw_key
    if isinstance(raw_key, str) and re.fullmatch(r"-?\d+", raw_key.strip()):
        return int(raw_key.strip())
    return None


def _remove_generated_import_output_input_placeholders(
    *,
    rules_file: Path,
    test_file: Path,
    repo_path: Path,
    relative_output: Path,
    issues: list[str],
) -> list[str]:
    if not rules_file.exists() or not test_file.exists():
        return []
    target_base = (
        f"{_repo_jurisdiction_prefix(repo_path)}:"
        f"{_relative_rulespec_import_target(relative_output)}"
    )
    imported_output_refs = _imported_output_refs_by_name(rules_file)
    if not imported_output_refs:
        return []
    invalid_refs = _invalid_input_refs_from_issues(issues)
    replacements_by_ref = {
        ref: imported_output_refs[output_name]
        for ref in invalid_refs
        if ref.startswith(f"{target_base}#input.")
        and (output_name := ref.split("#input.", 1)[1]) in imported_output_refs
    }
    removable_refs = set(replacements_by_ref)
    if not removable_refs:
        return []

    try:
        test_payload = yaml.safe_load(test_file.read_text()) or []
    except (OSError, ValueError, yaml.YAMLError):
        return []
    if not isinstance(test_payload, list):
        return []

    changed = False
    for test_case in test_payload:
        if not isinstance(test_case, dict):
            continue
        inputs = test_case.get("input")
        if _replace_import_output_placeholders_with_upstream_inputs(
            inputs,
            placeholder_refs=replacements_by_ref,
            policy_repo_path=repo_path,
        ):
            changed = True
    if not changed:
        return []
    test_file.write_text(
        yaml.safe_dump(test_payload, sort_keys=False, allow_unicode=False)
    )
    return sorted(removable_refs)


def _remove_invalid_test_input_refs(
    *,
    test_file: Path,
    issues: list[str],
) -> list[str]:
    if not test_file.exists():
        return []
    invalid_refs = {
        ref for ref in _invalid_input_refs_from_issues(issues) if "#input." in ref
    }
    if not invalid_refs:
        return []

    try:
        test_payload = yaml.safe_load(test_file.read_text()) or []
    except (OSError, ValueError, yaml.YAMLError):
        return []
    if not isinstance(test_payload, list):
        return []

    removable_refs = _expand_refs_with_matching_test_input_keys(
        test_payload,
        invalid_refs,
    )

    changed = False
    for test_case in test_payload:
        if not isinstance(test_case, dict):
            continue
        inputs = test_case.get("input")
        if _remove_mapping_keys_recursive(inputs, removable_refs):
            changed = True
    if not changed:
        return []
    test_file.write_text(
        yaml.safe_dump(test_payload, sort_keys=False, allow_unicode=False)
    )
    return sorted(removable_refs)


def _rewrite_import_output_test_input_refs(
    *,
    test_file: Path,
    repo_path: Path,
    issues: list[str],
) -> list[str]:
    """Drop the `input.` prefix when a test ref overrides an imported output.

    The encoder sometimes writes `<producer>#input.X` to override an imported
    producer's output X in a test case. The runtime rejects this because the
    producer file does not declare X as an input slot — X is its output. The
    correct shape for overriding an imported producer's output is
    `<producer>#X` (no `input.` prefix).

    This repair finds invalid `#input.X` refs that name a rule produced by
    the referenced file, rewrites the key in place, and returns a list of
    `<old> -> <new>` strings for telemetry. Runs before
    `_remove_invalid_import_output_test_input_refs` so the test case keeps
    its fidelity instead of losing the override entirely.
    """
    if not test_file.exists():
        return []
    candidate_refs = {
        ref
        for ref in _invalid_input_refs_from_issues(issues)
        if _input_ref_targets_producer_output(ref, repo_path=repo_path)
    }
    if not candidate_refs:
        return []

    try:
        test_payload = yaml.safe_load(test_file.read_text()) or []
    except (OSError, ValueError, yaml.YAMLError):
        return []
    if not isinstance(test_payload, list):
        return []

    rename_map: dict[str, str] = {
        ref: ref.replace("#input.", "#", 1) for ref in candidate_refs
    }

    changed = False
    for test_case in test_payload:
        if not isinstance(test_case, dict):
            continue
        inputs = test_case.get("input")
        if _rename_mapping_keys_recursive(inputs, rename_map):
            changed = True
    if not changed:
        return []
    test_file.write_text(
        yaml.safe_dump(test_payload, sort_keys=False, allow_unicode=False)
    )
    return sorted(f"{old} -> {new}" for old, new in rename_map.items())


def _rename_mapping_keys_recursive(value: object, rename_map: dict[str, str]) -> bool:
    """Rename keys in dict and any nested dicts/lists. Returns True if changed."""
    changed = False
    if isinstance(value, dict):
        for old_key, new_key in rename_map.items():
            if old_key in value:
                value[new_key] = value.pop(old_key)
                changed = True
        for v in value.values():
            if _rename_mapping_keys_recursive(v, rename_map):
                changed = True
    elif isinstance(value, list):
        for v in value:
            if _rename_mapping_keys_recursive(v, rename_map):
                changed = True
    return changed


def _remove_invalid_import_output_test_input_refs(
    *,
    test_file: Path,
    repo_path: Path,
    issues: list[str],
) -> list[str]:
    if not test_file.exists():
        return []
    invalid_refs = {
        ref
        for ref in _invalid_input_refs_from_issues(issues)
        if _input_ref_is_import_output_placeholder(ref, repo_path=repo_path)
    }
    if not invalid_refs:
        return []

    try:
        test_payload = yaml.safe_load(test_file.read_text()) or []
    except (OSError, ValueError, yaml.YAMLError):
        return []
    if not isinstance(test_payload, list):
        return []

    changed = False
    for test_case in test_payload:
        if not isinstance(test_case, dict):
            continue
        inputs = test_case.get("input")
        if _remove_mapping_keys_recursive(inputs, invalid_refs):
            changed = True
    if not changed:
        return []
    test_file.write_text(
        yaml.safe_dump(test_payload, sort_keys=False, allow_unicode=False)
    )
    return sorted(invalid_refs)


