def _rewrite_inline_judgment_conditional_formula(formula: str) -> str | None:
    stripped = " ".join(str(formula).strip().split())
    if not stripped:
        return None

    rewritten = _rewrite_judgment_conditional_expression(stripped)
    if rewritten == stripped:
        return None
    return rewritten


def _rewrite_judgment_conditional_expression(expression: str) -> str:
    stripped = expression.strip()
    if not stripped:
        return stripped

    if stripped.startswith("if "):
        branch_formula = _rewrite_top_level_judgment_conditional(stripped)
        if branch_formula is not None:
            return branch_formula

    comparison_formula = _rewrite_scalar_conditional_comparison_in_judgment(stripped)
    if comparison_formula != stripped:
        return _rewrite_judgment_conditional_expression(comparison_formula)

    split = _split_inline_if_expression_span(stripped)
    if split is None:
        return stripped
    start, end, condition, true_branch, false_branch = split
    true_formula = _rewrite_judgment_conditional_expression(true_branch)
    false_formula = _rewrite_judgment_conditional_expression(false_branch)
    replacement = (
        f"((({condition}) and {true_formula})\n"
        f"  or (not ({condition}) and {false_formula}))"
    )
    return f"{stripped[:start].rstrip()}{replacement}{stripped[end:].lstrip()}"


def _rewrite_scalar_conditional_comparison_in_judgment(expression: str) -> str:
    split = _split_inline_if_expression_span(expression)
    if split is None:
        return expression
    start, end, condition, true_branch, false_branch = split
    term_start, term_end = _top_level_boolean_term_span_containing(
        expression,
        start,
    )
    raw_term = expression[term_start:term_end]
    leading = len(raw_term) - len(raw_term.lstrip())
    trailing = len(raw_term) - len(raw_term.rstrip())
    trimmed_start = term_start + leading
    trimmed_end = term_end - trailing
    term = expression[trimmed_start:trimmed_end]
    if _top_level_comparison_operator(term) is None:
        return expression
    relative_start = start - trimmed_start
    relative_end = end - trimmed_start
    if relative_start < 0 or relative_end > len(term):
        return expression

    true_term = f"{term[:relative_start]}{true_branch}{term[relative_end:]}".strip()
    false_term = f"{term[:relative_start]}{false_branch}{term[relative_end:]}".strip()
    if not true_term or not false_term:
        return expression
    replacement = (
        f"((({condition}) and {true_term})\n  or (not ({condition}) and {false_term}))"
    )
    return f"{expression[:trimmed_start]}{replacement}{expression[trimmed_end:]}"


def _top_level_boolean_term_span_containing(
    text: str,
    position: int,
) -> tuple[int, int]:
    depth = 0
    quote: str | None = None
    start = 0
    end = len(text)
    index = 0
    while index < len(text):
        char = text[index]
        if quote:
            if char == quote and (index == 0 or text[index - 1] != "\\"):
                quote = None
            index += 1
            continue
        if char in {"'", '"'}:
            quote = char
            index += 1
            continue
        if char in "([{":
            depth += 1
            index += 1
            continue
        if char in ")]}":
            if depth:
                depth -= 1
            index += 1
            continue
        if depth == 0 and (
            _formula_word_at(text, index, "and") or _formula_word_at(text, index, "or")
        ):
            if index < position:
                start = index + (3 if text[index : index + 3].lower() == "and" else 2)
                index = start
                continue
            end = index
            break
        index += 1
    return start, end


def _top_level_comparison_operator(text: str) -> tuple[int, str] | None:
    depth = 0
    quote: str | None = None
    operators = ("<=", ">=", "==", "!=", "<", ">")
    index = 0
    while index < len(text):
        char = text[index]
        if quote:
            if char == quote and (index == 0 or text[index - 1] != "\\"):
                quote = None
            index += 1
            continue
        if char in {"'", '"'}:
            quote = char
            index += 1
            continue
        if char in "([{":
            depth += 1
            index += 1
            continue
        if char in ")]}":
            if depth:
                depth -= 1
            index += 1
            continue
        if depth == 0:
            for operator in operators:
                if text.startswith(operator, index):
                    return index, operator
        index += 1
    return None


def _rewrite_top_level_judgment_conditional(expression: str) -> str | None:
    branches = _inline_if_judgment_branches(expression, [])
    if not branches:
        return None
    disjuncts: list[str] = []
    for conditions, result in branches:
        cleaned_result = _rewrite_judgment_conditional_expression(result.strip())
        if not cleaned_result or cleaned_result.startswith("if "):
            return None
        terms = [*_parenthesized_condition_terms(conditions), cleaned_result]
        disjuncts.append("(" + " and ".join(terms) + ")")
    return "\n  or ".join(disjuncts)


def _inline_if_judgment_branches(
    expression: str,
    conditions: list[str],
) -> list[tuple[list[str], str]] | None:
    split = _split_inline_if_expression(expression)
    if split is None:
        return [(conditions, expression)]
    condition, true_branch, false_branch = split
    true_branches = _inline_if_judgment_branches(
        true_branch,
        [*conditions, condition],
    )
    false_branches = _inline_if_judgment_branches(
        false_branch,
        [*conditions, f"not ({condition})"],
    )
    if true_branches is None or false_branches is None:
        return None
    return [*true_branches, *false_branches]


def _split_inline_if_expression(expression: str) -> tuple[str, str, str] | None:
    text = expression.strip()
    split = _split_inline_if_expression_at(text, 0)
    if split is None or split[1] != len(text):
        return None
    _start, _end, condition, true_branch, false_branch = split
    return condition, true_branch, false_branch


def _split_inline_if_expression_span(
    expression: str,
) -> tuple[int, int, str, str, str] | None:
    index = 0
    while index < len(expression):
        if not _formula_word_at(expression, index, "if"):
            index += 1
            continue
        split = _split_inline_if_expression_at(expression, index)
        if split is not None:
            return split
        index += 1
    return None


def _split_inline_if_expression_at(
    text: str,
    start: int,
) -> tuple[int, int, str, str, str] | None:
    if not _formula_word_at(text, start, "if"):
        return None
    base_depth = _formula_bracket_depth_before(text, start)
    head_end = start + len("if")
    colon_index = _find_top_level_token(
        text,
        ":",
        start=head_end,
        base_depth=base_depth,
    )
    if colon_index is None:
        return None
    else_match = _find_inline_else_token(
        text,
        colon_index + 1,
        base_depth=base_depth,
    )
    if else_match is None:
        return None
    else_index, else_colon_index = else_match
    end = _find_inline_if_expression_end(
        text,
        else_colon_index + 1,
        base_depth=base_depth,
    )
    condition = text[head_end:colon_index].strip()
    true_branch = text[colon_index + 1 : else_index].strip()
    false_branch = text[else_colon_index + 1 : end].strip()
    if not condition or not true_branch or not false_branch:
        return None
    return start, end, condition, true_branch, false_branch


def _find_top_level_token(
    text: str,
    token: str,
    *,
    start: int = 0,
    base_depth: int = 0,
) -> int | None:
    depth = base_depth
    quote: str | None = None
    index = max(start, 0)
    while index < len(text):
        char = text[index]
        if quote:
            if char == quote:
                quote = None
            index += 1
            continue
        if char in {"'", '"'}:
            quote = char
            index += 1
            continue
        if char in "([{":
            depth += 1
            index += 1
            continue
        if char in ")]}":
            if depth:
                depth -= 1
            index += 1
            continue
        if depth == base_depth and text.startswith(token, index):
            return index
        index += 1
    return None


def _find_inline_else_token(
    text: str,
    start: int,
    *,
    base_depth: int,
) -> tuple[int, int] | None:
    depth = base_depth
    quote: str | None = None
    nested_conditionals = 0
    index = max(start, 0)
    while index < len(text):
        char = text[index]
        if quote:
            if char == quote:
                quote = None
            index += 1
            continue
        if char in {"'", '"'}:
            quote = char
            index += 1
            continue
        if char in "([{":
            depth += 1
            index += 1
            continue
        if char in ")]}":
            if depth:
                depth -= 1
            index += 1
            continue
        if depth != base_depth:
            index += 1
            continue
        if _formula_word_at(text, index, "if"):
            nested_conditionals += 1
            index += len("if")
            continue
        if _formula_word_at(text, index, "else"):
            colon_index = _find_inline_else_colon(text, index + len("else"))
            if colon_index is None:
                index += 1
                continue
            if nested_conditionals:
                nested_conditionals -= 1
                index = colon_index + 1
                continue
            return index, colon_index
        index += 1
    return None


def _find_inline_else_colon(text: str, start: int) -> int | None:
    index = start
    while index < len(text) and text[index].isspace():
        index += 1
    return index if index < len(text) and text[index] == ":" else None


def _find_inline_if_expression_end(
    text: str,
    start: int,
    *,
    base_depth: int,
) -> int:
    depth = base_depth
    quote: str | None = None
    index = max(start, 0)
    while index < len(text):
        char = text[index]
        if quote:
            if char == quote:
                quote = None
            index += 1
            continue
        if char in {"'", '"'}:
            quote = char
            index += 1
            continue
        if char in "([{":
            depth += 1
            index += 1
            continue
        if char in ")]}":
            if depth == base_depth:
                return index
            depth -= 1
            index += 1
            continue
        if char == "," and depth == base_depth:
            return index
        index += 1
    return len(text)


def _formula_bracket_depth_before(text: str, position: int) -> int:
    depth = 0
    quote: str | None = None
    for index, char in enumerate(text[: max(position, 0)]):
        if quote:
            if char == quote and (index == 0 or text[index - 1] != "\\"):
                quote = None
            continue
        if char in {"'", '"'}:
            quote = char
        elif char in "([{":
            depth += 1
        elif char in ")]}" and depth:
            depth -= 1
    return depth


def _formula_word_at(text: str, index: int, word: str) -> bool:
    end = index + len(word)
    if text[index:end].lower() != word.lower():
        return False
    before = text[index - 1] if index > 0 else ""
    after = text[end] if end < len(text) else ""
    return not (before.isalnum() or before == "_") and not (
        after.isalnum() or after == "_"
    )


def _parenthesized_condition_terms(conditions: list[str]) -> list[str]:
    terms: list[str] = []
    for condition in conditions:
        stripped = condition.strip()
        if not stripped:
            continue
        if stripped.startswith("not (") and stripped.endswith(")"):
            terms.append(stripped)
        else:
            terms.append(f"({stripped})")
    return terms


def _rewrite_judgment_numeric_comparison_formula(
    formula: str,
    *,
    names: set[str],
) -> str:
    rewritten = str(formula)
    for name in sorted(names, key=len, reverse=True):
        escaped = re.escape(name)
        name_token = rf"(?<![A-Za-z0-9_]){escaped}(?![A-Za-z0-9_])"
        zero = r"(?<![A-Za-z0-9_.])0(?:\.0+)?(?![A-Za-z0-9_.])"
        one = r"(?<![A-Za-z0-9_.])1(?:\.0+)?(?![A-Za-z0-9_.])"
        replacements = (
            (rf"{name_token}\s*==\s*{zero}", f"not {name}"),
            (rf"\b{zero}\s*==\s*{name_token}", f"not {name}"),
            (rf"{name_token}\s*!=\s*{zero}", name),
            (rf"\b{zero}\s*!=\s*{name_token}", name),
            (rf"{name_token}\s*==\s*{one}", name),
            (rf"\b{one}\s*==\s*{name_token}", name),
            (rf"{name_token}\s*!=\s*{one}", f"not {name}"),
            (rf"\b{one}\s*!=\s*{name_token}", f"not {name}"),
            (rf"{name_token}\s*==\s*false\b", f"not {name}"),
            (rf"\bfalse\s*==\s*{name_token}", f"not {name}"),
            (rf"{name_token}\s*!=\s*false\b", name),
            (rf"\bfalse\s*!=\s*{name_token}", name),
            (rf"{name_token}\s*==\s*true\b", name),
            (rf"\btrue\s*==\s*{name_token}", name),
            (rf"{name_token}\s*!=\s*true\b", f"not {name}"),
            (rf"\btrue\s*!=\s*{name_token}", f"not {name}"),
        )
        for pattern, replacement in replacements:
            rewritten = re.sub(pattern, replacement, rewritten, flags=re.IGNORECASE)
    return rewritten


def _rule_has_comparison_formula(rule: dict[str, object]) -> bool:
    versions = rule.get("versions")
    if not isinstance(versions, list):
        return False
    return any(
        isinstance(version, dict)
        and isinstance(version.get("formula"), str)
        and re.search(r"(?:<=|>=|==|!=|<|>)", version["formula"])
        for version in versions
    )


def _rule_has_top_level_comparison_formula(rule: dict[str, object]) -> bool:
    versions = rule.get("versions")
    if not isinstance(versions, list):
        return False
    return any(
        isinstance(version, dict)
        and isinstance(version.get("formula"), str)
        and _formula_has_top_level_comparison(version["formula"])
        for version in versions
    )


def _formula_has_top_level_comparison(formula: str) -> bool:
    normalized = re.sub(r"\s+", " ", str(formula).strip())
    if normalized.startswith("if ") or " else:" in normalized:
        return False
    depth = 0
    index = 0
    while index < len(normalized):
        char = normalized[index]
        if char == "(":
            depth += 1
        elif char == ")" and depth > 0:
            depth -= 1
        elif depth == 0:
            pair = normalized[index : index + 2]
            if pair in {"<=", ">=", "==", "!="}:
                return True
            if char in {"<", ">"}:
                return True
        index += 1
    return False


def _rewrite_boolean_test_values_as_judgments(
    test_file: Path,
    rule_names: set[str],
) -> None:
    if not test_file.exists():
        return
    try:
        payload = yaml.safe_load(test_file.read_text()) or []
    except (OSError, yaml.YAMLError, ValueError):
        return
    if not isinstance(payload, list):
        return

    changed = False
    for case in payload:
        if not isinstance(case, dict):
            continue
        for section_name in ("input", "output"):
            section = case.get(section_name)
            if not isinstance(section, dict):
                continue
            for key, value in list(section.items()):
                rule_name = str(key).rsplit("#", 1)[-1]
                if rule_name not in rule_names or not isinstance(value, bool):
                    continue
                section[key] = "holds" if value else "not_holds"
                changed = True

    if changed:
        test_file.write_text(
            yaml.safe_dump(payload, sort_keys=False, allow_unicode=False)
        )


def _try_repair_generated_module_layout_for_apply(
    result,
    *,
    output_root: Path,
) -> dict[str, list[str]]:
    """Promote model-emitted top-level RuleSpec members out of ``module``."""
    try:
        _relative_generated_output_path(result, output_root=output_root)
    except RuntimeError:
        return {}

    rules_file = Path(str(getattr(result, "output_file", "") or ""))
    return _promote_module_layout_members(rules_file=rules_file)


def _promote_module_layout_members(*, rules_file: Path) -> dict[str, list[str]]:
    if not rules_file.exists():
        return {}

    try:
        payload = yaml.safe_load(rules_file.read_text()) or {}
    except (OSError, yaml.YAMLError, ValueError):
        return {}
    if not isinstance(payload, dict):
        return {}

    module = payload.get("module")
    if not isinstance(module, dict):
        return {}

    promoted: dict[str, list[str]] = {}
    if "imports" in module:
        module_imports = module.pop("imports")
        if isinstance(module_imports, list):
            import_refs = [
                str(item).strip() for item in module_imports if str(item).strip()
            ]
            if import_refs:
                existing_imports = payload.get("imports")
                existing = (
                    [
                        str(item).strip()
                        for item in existing_imports
                        if str(item).strip()
                    ]
                    if isinstance(existing_imports, list)
                    else []
                )
                merged_imports = [*import_refs]
                merged_imports.extend(
                    item for item in existing if item not in merged_imports
                )
                payload["imports"] = merged_imports
                promoted["imports"] = import_refs

    if "rules" in module:
        module_rules = module.pop("rules")
        if isinstance(module_rules, list):
            rule_names = _rulespec_rule_labels(module_rules)
            if rule_names:
                existing_rules = payload.get("rules")
                if isinstance(existing_rules, list):
                    payload["rules"] = [*existing_rules, *module_rules]
                else:
                    payload["rules"] = module_rules
                promoted["rules"] = rule_names

    if not promoted:
        return {}

    reordered: dict[str, object] = {}
    inserted: set[str] = set()
    for key, value in payload.items():
        if key in {"imports", "rules"}:
            continue
        reordered[key] = value
        if key == "format":
            for promoted_key in ("imports", "rules"):
                if promoted_key in payload:
                    reordered[promoted_key] = payload[promoted_key]
                    inserted.add(promoted_key)
    for promoted_key in ("imports", "rules"):
        if promoted_key in payload and promoted_key not in inserted:
            reordered[promoted_key] = payload[promoted_key]

    rules_file.write_text(
        yaml.safe_dump(reordered, sort_keys=False, allow_unicode=False)
    )
    return promoted


def _rulespec_rule_labels(rules: list[object]) -> list[str]:
    labels: list[str] = []
    for index, rule in enumerate(rules):
        name = rule.get("name") if isinstance(rule, dict) else None
        label = str(name).strip() if isinstance(name, str) and name.strip() else ""
        labels.append(label or f"rules[{index}]")
    return labels


def _try_repair_generated_nested_test_tables_for_apply(
    result,
    *,
    output_root: Path,
) -> list[str]:
    """Hoist model-emitted ``input.tables`` companion rows before apply."""
    try:
        _relative_generated_output_path(result, output_root=output_root)
    except RuntimeError:
        return []

    rules_file = Path(str(getattr(result, "output_file", "") or ""))
    test_file = _rulespec_test_path(rules_file)
    return _hoist_nested_test_tables(test_file)


def _hoist_nested_test_tables(test_file: Path) -> list[str]:
    if not test_file.exists():
        return []

    try:
        payload = yaml.safe_load(test_file.read_text()) or []
    except (OSError, yaml.YAMLError, ValueError):
        return []

    if isinstance(payload, dict) and isinstance(payload.get("cases"), list):
        cases = payload["cases"]
    elif isinstance(payload, list):
        cases = payload
    else:
        return []

    repaired_cases: list[str] = []
    for index, test_case in enumerate(cases, start=1):
        if not isinstance(test_case, dict):
            continue
        inputs = test_case.get("input")
        if not isinstance(inputs, dict):
            continue
        nested_tables = inputs.get("tables")
        if not isinstance(nested_tables, dict):
            continue
        existing_tables = test_case.get("tables")
        if existing_tables not in (None, "") and existing_tables != {}:
            continue
        inputs.pop("tables")
        test_case["tables"] = nested_tables
        if not inputs:
            test_case["input"] = {}
        repaired_cases.append(str(test_case.get("name") or f"case {index}"))

    if not repaired_cases:
        return []

    test_file.write_text(yaml.safe_dump(payload, sort_keys=False, allow_unicode=False))
    return repaired_cases


def _try_repair_generated_table_relation_tests_for_apply(
    result,
    *,
    output_root: Path,
    issues: list[str],
) -> list[str]:
    """Split table-row relation inputs into scalar root-entity test cases."""
    if not any(
        "tables." in str(issue)
        and "#relation." in str(issue)
        and "must be scalar" in str(issue)
        for issue in issues
    ):
        return []
    try:
        _relative_generated_output_path(result, output_root=output_root)
    except RuntimeError:
        return []

    rules_file = Path(str(getattr(result, "output_file", "") or ""))
    test_file = _rulespec_test_path(rules_file)
    return _split_table_row_relation_test_cases(test_file)


_UNDECLARED_RELATION_INPUT_ISSUE_PATTERN = re.compile(
    r"relation input `(?P<reference>[^`]+#relation\.(?P<name>[A-Za-z_][A-Za-z0-9_]*))` "
    r"does not resolve to a declared relation"
)


def _try_repair_generated_missing_data_relations_for_apply(
    result,
    *,
    output_root: Path,
    issues: list[str],
) -> list[str]:
    """Declare generated local relations proven by formulas and companion tests.

    Model output can contain a valid relation aggregate such as
    `sum_where(dependent_care_recipients, ...)` and companion
    `#relation.dependent_care_recipients` rows, but omit the corresponding
    `kind: data_relation` rule. Repair only that narrow, CI-proven case.
    """
    relation_names = _undeclared_relation_names_from_issues(issues)
    if not relation_names:
        return []
    try:
        _relative_generated_output_path(result, output_root=output_root)
    except RuntimeError:
        return []

    rules_file = Path(str(getattr(result, "output_file", "") or ""))
    if not rules_file.exists():
        return []
    try:
        payload = yaml.safe_load(rules_file.read_text()) or {}
    except (OSError, ValueError, yaml.YAMLError):
        return []
    if not isinstance(payload, dict):
        return []

    rules = payload.get("rules")
    if not isinstance(rules, list):
        return []
    existing_relations = {
        str(rule.get("name") or "").strip()
        for rule in rules
        if isinstance(rule, dict)
        and str(rule.get("kind") or "").strip().lower() == "data_relation"
    }

    repaired: list[str] = []
    for relation_name in relation_names:
        if relation_name in existing_relations:
            continue
        if not _rulespec_rules_reference_relation(rules, relation_name):
            continue
        relation_rule = _build_inferred_data_relation_rule(rules, relation_name)
        if relation_rule is None:
            continue
        insert_at = _first_rule_index_referencing_relation(rules, relation_name)
        rules.insert(insert_at, relation_rule)
        existing_relations.add(relation_name)
        repaired.append(relation_name)

    if not repaired:
        return []

    test_file = _rulespec_test_path(rules_file)
    _remove_stale_relation_scalar_inputs(test_file, repaired)
    rules_file.write_text(yaml.safe_dump(payload, sort_keys=False, allow_unicode=False))
    return repaired


def _undeclared_relation_names_from_issues(issues: list[str]) -> list[str]:
    relation_names: list[str] = []
    seen: set[str] = set()
    for issue in issues:
        match = _UNDECLARED_RELATION_INPUT_ISSUE_PATTERN.search(str(issue))
        if match is None:
            continue
        name = match.group("name").strip()
        if name and name not in seen:
            seen.add(name)
            relation_names.append(name)
    return relation_names


def _rulespec_rules_reference_relation(
    rules: list[object],
    relation_name: str,
) -> bool:
    return any(
        _formula_references_relation(formula, relation_name)
        for rule in rules
        if isinstance(rule, dict)
        for formula in _rulespec_rule_formula_strings(rule)
    )


def _first_rule_index_referencing_relation(
    rules: list[object],
    relation_name: str,
) -> int:
    for index, rule in enumerate(rules):
        if not isinstance(rule, dict):
            continue
        if any(
            _formula_references_relation(formula, relation_name)
            for formula in _rulespec_rule_formula_strings(rule)
        ):
            return index
    return 0


def _build_inferred_data_relation_rule(
    rules: list[object],
    relation_name: str,
) -> dict[str, object] | None:
    by_name = {
        str(rule.get("name") or "").strip(): rule
        for rule in rules
        if isinstance(rule, dict) and str(rule.get("name") or "").strip()
    }
    related_entities: list[str] = []
    enclosing_entities: list[str] = []
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        formulas = _rulespec_rule_formula_strings(rule)
        if not any(
            _formula_references_relation(formula, relation_name) for formula in formulas
        ):
            continue
        enclosing_entity = str(rule.get("entity") or "").strip()
        if enclosing_entity:
            enclosing_entities.append(enclosing_entity)
        for formula in formulas:
            for identifier in _relation_aggregate_argument_identifiers(
                formula,
                relation_name,
            ):
                related_entity = _rulespec_rule_entity(by_name.get(identifier))
                if related_entity and related_entity != enclosing_entity:
                    related_entities.append(related_entity)

    relation: dict[str, object] = {
        "name": relation_name,
        "kind": "data_relation",
        "data_relation": {
            "predicate": relation_name,
            "arity": 2,
        },
    }
    related_entity = _first_common_value(related_entities)
    enclosing_entity = _first_common_value(enclosing_entities)
    if related_entity and enclosing_entity:
        relation["data_relation"] = {
            "predicate": relation_name,
            "arity": 2,
            "arguments": [
                {
                    "name": _singular_relation_argument_name(relation_name),
                    "entity": related_entity,
                },
                {
                    "name": _snake_case_identifier(enclosing_entity),
                    "entity": enclosing_entity,
                },
            ],
        }
    return relation


def _formula_references_relation(formula: str, relation_name: str) -> bool:
    escaped = re.escape(relation_name)
    return bool(
        re.search(
            rf"\b(?:count_where|len|sum|sum_where)\s*\(\s*{escaped}\b",
            formula,
        )
        or re.search(rf"\b{escaped}\.[A-Za-z_][A-Za-z0-9_]*\b", formula)
    )


def _relation_aggregate_argument_identifiers(
    formula: str,
    relation_name: str,
) -> list[str]:
    escaped = re.escape(relation_name)
    identifiers: list[str] = []
    for match in re.finditer(
        rf"\bsum_where\s*\(\s*{escaped}\s*,\s*"
        r"(?P<amount>[A-Za-z_][A-Za-z0-9_]*)\s*,\s*"
        r"(?P<predicate>[A-Za-z_][A-Za-z0-9_]*)\s*\)",
        formula,
    ):
        identifiers.extend([match.group("amount"), match.group("predicate")])
    for match in re.finditer(
        rf"\bcount_where\s*\(\s*{escaped}\s*,\s*"
        r"(?P<predicate>[A-Za-z_][A-Za-z0-9_]*)\s*\)",
        formula,
    ):
        identifiers.append(match.group("predicate"))
    return identifiers


def _rulespec_rule_entity(rule: object) -> str | None:
    if not isinstance(rule, dict):
        return None
    entity = str(rule.get("entity") or "").strip()
    return entity or None


def _first_common_value(values: list[str]) -> str | None:
    if not values:
        return None
    counts = Counter(values)
    return max(counts, key=lambda item: (counts[item], -values.index(item)))


def _singular_relation_argument_name(relation_name: str) -> str:
    if relation_name.endswith("_children"):
        return f"{relation_name.removesuffix('_children')}_child"
    if relation_name == "children":
        return "child"
    if relation_name.endswith("ies"):
        return f"{relation_name[:-3]}y"
    if relation_name.endswith("s") and not relation_name.endswith("ss"):
        return relation_name[:-1]
    return relation_name


def _snake_case_identifier(value: str) -> str:
    value = re.sub(r"(.)([A-Z][a-z]+)", r"\1_\2", value)
    value = re.sub(r"([a-z0-9])([A-Z])", r"\1_\2", value)
    return value.replace("-", "_").lower()


def _remove_stale_relation_scalar_inputs(
    test_file: Path,
    relation_names: list[str],
) -> list[str]:
    if not test_file.exists():
        return []
    try:
        payload = yaml.safe_load(test_file.read_text()) or []
    except (OSError, ValueError, yaml.YAMLError):
        return []
    if isinstance(payload, dict) and isinstance(payload.get("cases"), list):
        cases = payload["cases"]
    elif isinstance(payload, list):
        cases = payload
    else:
        return []

    relation_set = set(relation_names)
    removed: list[str] = []
    for index, case in enumerate(cases, start=1):
        if not isinstance(case, dict):
            continue
        inputs = case.get("input")
        if not isinstance(inputs, dict):
            continue
        case_name = str(case.get("name") or f"case {index}")
        for key in list(inputs):
            fragment = _rulespec_test_key_fragment(key)
            if not fragment.startswith("input."):
                continue
            input_name = fragment.removeprefix("input.").strip()
            if input_name not in relation_set:
                continue
            value = inputs.get(key)
            if isinstance(value, list):
                continue
            inputs.pop(key, None)
            removed.append(f"{case_name}:{input_name}")

    if not removed:
        return []
    test_file.write_text(yaml.safe_dump(payload, sort_keys=False, allow_unicode=False))
    return removed


_SCALAR_RELATION_ROW_ISSUE_PATTERN = re.compile(
    r"Test case `(?P<case>[^`]+)` input invalid: relation "
    r"`(?P<relation>[^`]+)` item #(?P<index>\d+) must be a mapping"
)

_TEST_INPUT_ASSIGNMENT_MISSING_CASE_PATTERN = re.compile(
    r"Test input assignment missing:\s*`(?P<case>[^`]+)`"
)


def _try_repair_generated_scalar_relation_rows_for_apply(
    result,
    *,
    output_root: Path,
    policy_repo_path: Path,
    issues: list[str],
) -> list[str]:
    """Replace scalar relation rows with companion-test row mappings.

    Generated tests occasionally write relation inputs as `- true` or `- 300`.
    The engine needs each relation row to be a mapping of child facts. Prefer
    exact row-shape validator issues, and fall back to missing-input-assignment
    issues only when the named generated test case still contains scalar rows.
    """
    parsed_issues = [
        parsed
        for issue in issues
        if (parsed := _parse_scalar_relation_row_issue(str(issue))) is not None
    ]
    try:
        _relative_generated_output_path(result, output_root=output_root)
    except RuntimeError:
        return []

    rules_file = Path(str(getattr(result, "output_file", "") or ""))
    test_file = _rulespec_test_path(rules_file)
    if not parsed_issues:
        parsed_issues = _scalar_relation_row_issues_from_missing_input_assignment(
            test_file,
            issues=issues,
        )
    if not parsed_issues:
        return []
    return _repair_scalar_relation_rows(
        rules_file=rules_file,
        test_file=test_file,
        policy_repo_path=policy_repo_path,
        parsed_issues=parsed_issues,
    )


_CHILD_NUMERIC_REENCODING_ISSUE_PATTERN = re.compile(
    r"Child fragment numeric output re-encoded: .*? in rule\(s\) "
    r"(?P<parents>.+?)\. Import and reference the child "
    r"(?P<child_hint>.+?) instead of copying the child value"
)


def _try_repair_generated_child_numeric_reencoding_for_apply(
    result,
    *,
    output_root: Path,
    policy_repo_path: Path,
    issues: list[str],
) -> list[str]:
    parsed_issues = [
        parsed
        for issue in issues
        if (parsed := _parse_child_numeric_reencoding_issue(str(issue))) is not None
    ]
    if not parsed_issues:
        return []
    try:
        relative_output = _relative_generated_output_path(
            result, output_root=output_root
        )
    except RuntimeError:
        return []

    rules_file = Path(str(getattr(result, "output_file", "") or ""))
    return _repair_child_numeric_reencoding_parent_aliases(
        rules_file=rules_file,
        policy_repo_path=policy_repo_path,
        relative_output=relative_output,
        parsed_issues=parsed_issues,
    )


def _parse_child_numeric_reencoding_issue(
    issue: str,
) -> tuple[tuple[str, ...], str] | None:
    match = _CHILD_NUMERIC_REENCODING_ISSUE_PATTERN.search(issue)
    if match is None:
        return None
    parent_names = tuple(re.findall(r"`([^`]+)`", match.group("parents")))
    child_refs = tuple(
        ref for ref in re.findall(r"`([^`]+)`", match.group("child_hint")) if "#" in ref
    )
    if not parent_names or len(child_refs) != 1:
        return None
    return parent_names, child_refs[0]


def _repair_child_numeric_reencoding_parent_aliases(
    *,
    rules_file: Path,
    policy_repo_path: Path,
    relative_output: Path | None = None,
    parsed_issues: list[tuple[tuple[str, ...], str]],
) -> list[str]:
    """Remove parent helpers that re-derive child-owned numeric concepts.

    This intentionally handles only a narrow generated pattern:
    a parent-local helper that copied a numeric child literal, plus optional
    `1 / helper` wrappers. Broader rewrites should stay as validation failures
    and be re-encoded.
    """
    if not rules_file.exists():
        return []
    try:
        payload = yaml.safe_load(rules_file.read_text()) or {}
    except (OSError, ValueError, yaml.YAMLError):
        return []
    if not isinstance(payload, dict):
        return []
    rules = payload.get("rules")
    if not isinstance(rules, list):
        return []

    replacements: dict[str, str] = {}
    remove_names: set[str] = set()
    for parent_names, child_ref in parsed_issues:
        if "#" not in child_ref:
            continue
        child_name = child_ref.rsplit("#", 1)[1].strip()
        if not re.fullmatch(r"[A-Za-z_][A-Za-z0-9_]*", child_name):
            continue
        for parent_name in parent_names:
            if not re.fullmatch(r"[A-Za-z_][A-Za-z0-9_]*", parent_name):
                continue
            remove_names.add(parent_name)
            replacements[parent_name] = child_name
        replacements.update(
            _child_numeric_reencoding_wrapper_replacements(
                rules,
                parent_names=set(parent_names),
                child_name=child_name,
            )
        )

    if not remove_names and not replacements:
        return []
    remove_names.update(replacements)
    removed_rules: list[str] = []
    remaining_rules: list[object] = []
    for rule in rules:
        if isinstance(rule, dict) and str(rule.get("name") or "") in remove_names:
            removed_rules.append(str(rule.get("name") or ""))
            continue
        remaining_rules.append(rule)
    if not removed_rules:
        return []
    payload["rules"] = remaining_rules

    local_ref_prefix = _rulespec_local_ref_prefix_for_generated_file(
        rules_file,
        policy_repo_path=policy_repo_path,
        relative_output=relative_output,
    )
    child_ref_by_name = {
        child_name: child_ref
        for _parent_names, child_ref in parsed_issues
        for child_name in [child_ref.rsplit("#", 1)[1].strip()]
    }
    full_ref_replacements = {
        f"{local_ref_prefix}{local_name}": child_ref_by_name[child_name]
        for local_name, child_name in replacements.items()
        if child_name in child_ref_by_name
    }
    payload = _rewrite_child_numeric_reencoding_references(
        payload,
        name_replacements=replacements,
        full_ref_replacements=full_ref_replacements,
    )
    rules_file.write_text(yaml.safe_dump(payload, sort_keys=False, allow_unicode=False))
    return removed_rules


def _child_numeric_reencoding_wrapper_replacements(
    rules: list[object],
    *,
    parent_names: set[str],
    child_name: str,
) -> dict[str, str]:
    replacements: dict[str, str] = {}
    if len(parent_names) != 1:
        return replacements
    parent_name = next(iter(parent_names))
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        name = str(rule.get("name") or "")
        if not name or name == parent_name:
            continue
        formulas = _rulespec_rule_formula_strings(rule)
        if not formulas:
            continue
        if all(
            _formula_is_one_over_identifier(formula, parent_name)
            for formula in formulas
        ):
            replacements[name] = child_name
    return replacements


def _rulespec_rule_formula_strings(rule: dict[str, object]) -> list[str]:
    versions = rule.get("versions")
    if not isinstance(versions, list):
        return []
    formulas: list[str] = []
    for version in versions:
        if not isinstance(version, dict):
            continue
        formula = version.get("formula")
        if isinstance(formula, str):
            formulas.append(formula)
    return formulas


def _formula_is_one_over_identifier(formula: str, identifier: str) -> bool:
    compact = re.sub(r"\s+", "", formula.strip())
    return compact == f"1/{identifier}"


def _rulespec_local_ref_prefix_for_generated_file(
    rules_file: Path,
    *,
    policy_repo_path: Path,
    relative_output: Path | None = None,
) -> str:
    if relative_output is not None:
        relative = relative_output
    else:
        try:
            relative = rules_file.resolve().relative_to(policy_repo_path.resolve())
        except ValueError:
            relative = rules_file
    return f"{_repo_jurisdiction_prefix(policy_repo_path)}:{relative.with_suffix('').as_posix()}#"


def _rewrite_child_numeric_reencoding_references(
    value: object,
    *,
    name_replacements: dict[str, str],
    full_ref_replacements: dict[str, str],
) -> object:
    if isinstance(value, dict):
        return {
            key: _rewrite_child_numeric_reencoding_references(
                item,
                name_replacements=name_replacements,
                full_ref_replacements=full_ref_replacements,
            )
            for key, item in value.items()
        }
    if isinstance(value, list):
        return [
            _rewrite_child_numeric_reencoding_references(
                item,
                name_replacements=name_replacements,
                full_ref_replacements=full_ref_replacements,
            )
            for item in value
        ]
    if not isinstance(value, str):
        return value
    if value in full_ref_replacements:
        return full_ref_replacements[value]
    for old_name, new_name in name_replacements.items():
        value = re.sub(
            rf"(?<![A-Za-z0-9_]){re.escape(old_name)}(?![A-Za-z0-9_])",
            new_name,
            value,
        )
    return value


def _parse_scalar_relation_row_issue(
    issue: str,
) -> tuple[str, str, int] | None:
    match = _SCALAR_RELATION_ROW_ISSUE_PATTERN.search(issue)
    if match is None:
        return None
    return (
        match.group("case"),
        match.group("relation"),
        int(match.group("index")),
    )


def _scalar_relation_row_issues_from_missing_input_assignment(
    test_file: Path,
    *,
    issues: list[str],
) -> list[tuple[str, str, int]]:
    case_names = {
        match.group("case").strip()
        for issue in issues
        if (match := _TEST_INPUT_ASSIGNMENT_MISSING_CASE_PATTERN.search(str(issue)))
    }
    if not case_names or not test_file.exists():
        return []
    try:
        payload = yaml.safe_load(test_file.read_text()) or []
    except (OSError, ValueError, yaml.YAMLError):
        return []
    if isinstance(payload, dict) and isinstance(payload.get("cases"), list):
        cases = payload["cases"]
    elif isinstance(payload, list):
        cases = payload
    else:
        return []

    parsed_issues: list[tuple[str, str, int]] = []
    for case in cases:
        if not isinstance(case, dict):
            continue
        case_name = str(case.get("name") or "").strip()
        if case_name not in case_names:
            continue
        inputs = case.get("input")
        if not isinstance(inputs, dict):
            continue
        for relation_ref, rows in inputs.items():
            relation_key = str(relation_ref)
            if "#relation." not in relation_key or not isinstance(rows, list):
                continue
            for index, row in enumerate(rows, start=1):
                if not isinstance(row, dict):
                    parsed_issues.append((case_name, relation_key, index))
    return parsed_issues


def _repair_scalar_relation_rows(
    *,
    rules_file: Path | None = None,
    test_file: Path,
    policy_repo_path: Path,
    parsed_issues: list[tuple[str, str, int]],
) -> list[str]:
    if not test_file.exists():
        return []
    try:
        payload = yaml.safe_load(test_file.read_text()) or []
    except (OSError, ValueError, yaml.YAMLError):
        return []
    if not isinstance(payload, list):
        return []

    repairs_by_case_relation: dict[tuple[str, str], set[int]] = defaultdict(set)
    for case_name, relation_ref, row_index in parsed_issues:
        repairs_by_case_relation[(case_name, relation_ref)].add(row_index)

    repaired: list[str] = []
    for case in payload:
        if not isinstance(case, dict):
            continue
        case_name = str(case.get("name") or "")
        inputs = case.get("input")
        if not isinstance(inputs, dict):
            continue
        for relation_ref, rows in list(inputs.items()):
            relation_key = str(relation_ref)
            repair_rows = repairs_by_case_relation.get((case_name, relation_key))
            if not repair_rows or not isinstance(rows, list):
                continue
            for row_index in sorted(repair_rows):
                list_index = row_index - 1
                if list_index < 0 or list_index >= len(rows):
                    continue
                scalar_value = rows[list_index]
                if isinstance(scalar_value, dict):
                    continue
                replacement = _relation_row_replacement_from_companion_tests(
                    relation_key,
                    scalar_value,
                    policy_repo_path=policy_repo_path,
                )
                if replacement is None:
                    replacement = _relation_row_replacement_from_generated_rules(
                        relation_key,
                        scalar_value,
                        rules_file=rules_file,
                    )
                if replacement is None:
                    continue
                rows[list_index] = replacement
                repaired.append(f"{case_name}:{relation_key}[{row_index}]")

    if not repaired:
        return []
    test_file.write_text(yaml.safe_dump(payload, sort_keys=False, allow_unicode=False))
    return repaired


def _repair_aca_36b_b_premium_assistance_compat(rules_file: Path) -> list[str]:
    """Normalize generated ACA 36B(b) premium-assistance shape.

    This is intentionally scoped to the 26 USC 36B(b) generated parent. It keeps
    the legal monthly cap in `premium_assistance_amount`, scopes the annual sum
    to paragraph (1), and avoids decimal noise from a literal `1 / 12` factor.
    """
    if not rules_file.exists():
        return []
    try:
        payload = yaml.safe_load(rules_file.read_text()) or {}
    except (OSError, ValueError, yaml.YAMLError):
        return []
    if not isinstance(payload, dict):
        return []
    module = payload.get("module")
    if not isinstance(module, dict):
        return []
    source_verification = module.get("source_verification")
    if not isinstance(source_verification, dict):
        return []
    if source_verification.get("corpus_citation_path") != "us/statute/26/36B":
        return []
    rules = payload.get("rules")
    if not isinstance(rules, list):
        return []
    rule_names = {
        str(rule.get("name") or "")
        for rule in rules
        if isinstance(rule, dict) and rule.get("name")
    }
    if "premium_assistance_credit_amount" not in rule_names:
        return []
    if "premium_assistance_amount" not in rule_names:
        return []

    repairs: list[str] = []
    imports = payload.get("imports")
    if isinstance(imports, list):
        filtered_imports = [
            item
            for item in imports
            if str(item).strip() != "us:statutes/26/36B/b/3/A#applicable_percentage"
        ]
        if len(filtered_imports) != len(imports):
            repairs.append("remove_applicable_percentage_import")
            if filtered_imports:
                payload["imports"] = filtered_imports
            else:
                payload.pop("imports", None)

    payload = _rewrite_aca_36b_b_compat_references(payload)
    rules = payload.get("rules")
    if not isinstance(rules, list):
        return repairs

    for rule in rules:
        if not isinstance(rule, dict):
            continue
        name = str(rule.get("name") or "")
        if name == "required_contribution_annual_to_monthly_divisor":
            if _set_first_formula(rule, "12"):
                repairs.append("monthly_divisor_formula")
        elif name == "required_monthly_contribution":
            if _set_first_formula(
                rule,
                "(household_income_for_taxable_year / required_contribution_annual_to_monthly_divisor) * applicable_percentage_for_taxable_year",
            ):
                repairs.append("required_monthly_contribution_formula")
            removed = _remove_rule_proof_import(
                rule, "us:statutes/26/36B/b/3/A#applicable_percentage"
            )
            if removed:
                repairs.append("remove_applicable_percentage_proof_import")
        elif name == "premium_assistance_credit_amount":
            if rule.get("source") != "paragraph (1)":
                rule["source"] = "paragraph (1)"
                repairs.append("annual_credit_source")

    if not repairs:
        return []
    rules_file.write_text(yaml.safe_dump(payload, sort_keys=False, allow_unicode=False))
    return repairs


def _try_repair_generated_aca_36b_b_premium_assistance_compat_for_apply(
    result,
    *,
    output_root: Path,
) -> list[str]:
    """Apply the 26 USC 36B(b) compatibility repair to generated apply output."""
    try:
        relative_output = _relative_generated_output_path(
            result, output_root=output_root
        )
    except RuntimeError:
        return []
    if relative_output != Path("statutes/26/36B/b.yaml"):
        return []
    rules_file = Path(str(getattr(result, "output_file", "") or ""))
    return _repair_aca_36b_b_premium_assistance_compat(rules_file)


def _rewrite_aca_36b_b_compat_references(value: object) -> object:
    replacements = {
        "required_contribution_monthly_fraction": (
            "required_contribution_annual_to_monthly_divisor"
        ),
        "required_monthly_contribution_amount": "required_monthly_contribution",
        "applicable_percentage *": "applicable_percentage_for_taxable_year *",
    }
    if isinstance(value, dict):
        return {
            key: _rewrite_aca_36b_b_compat_references(item)
            for key, item in value.items()
        }
    if isinstance(value, list):
        return [_rewrite_aca_36b_b_compat_references(item) for item in value]
    if not isinstance(value, str):
        return value
    for old, new in replacements.items():
        value = value.replace(old, new)
    return value


def _set_first_formula(rule: dict[str, object], formula: str) -> bool:
    versions = rule.get("versions")
    if not isinstance(versions, list):
        return False
    for version in versions:
        if not isinstance(version, dict):
            continue
        if version.get("formula") == formula:
            return False
        version["formula"] = formula
        return True
    return False


def _remove_rule_proof_import(rule: dict[str, object], target: str) -> bool:
    metadata = rule.get("metadata")
    proof = (
        metadata.get("proof")
        if isinstance(metadata, dict) and isinstance(metadata.get("proof"), dict)
        else rule.get("proof")
    )
    if not isinstance(proof, dict):
        return False
    atoms = proof.get("atoms")
    if not isinstance(atoms, list):
        return False
    filtered_atoms = []
    removed = False
    for atom in atoms:
        if isinstance(atom, dict) and isinstance(atom.get("import"), dict):
            if str(atom["import"].get("target") or "").strip() == target:
                removed = True
                continue
        filtered_atoms.append(atom)
    if removed:
        proof["atoms"] = filtered_atoms
    return removed


def _relation_row_replacement_from_companion_tests(
    relation_ref: str,
    scalar_value: object,
    *,
    policy_repo_path: Path,
) -> dict[str, object] | None:
    exemplar_rows = _relation_rows_from_companion_tests(
        relation_ref,
        policy_repo_path=policy_repo_path,
    )
    if not exemplar_rows:
        return None
    for row in exemplar_rows:
        if _relation_row_matches_scalar_value(row, scalar_value):
            return copy.deepcopy(row)
    if isinstance(scalar_value, bool):
        template = copy.deepcopy(exemplar_rows[0])
        changed = False
        for key, value in list(template.items()):
            if isinstance(value, bool):
                template[key] = scalar_value
                changed = True
        if changed:
            return template
    return None


def _relation_row_replacement_from_generated_rules(
    relation_ref: str,
    scalar_value: object,
    *,
    rules_file: Path | None,
) -> dict[str, object] | None:
    """Infer a relation row mapping when a generated formula uses one child fact.

    Companion tests are preferred because they preserve established row shape.
    New generated files can define a relation and immediately test it before any
    companion exists; in that case a scalar row like `- 30000` is unambiguous
    only when the formulas reference exactly one child fact through
    `relation_name.child_fact` or a boolean aggregate such as
    `count_where(relation_name, child_fact)`.
    """
    if rules_file is None or not rules_file.exists():
        return None
    relation_name = _relation_name_from_relation_ref(relation_ref)
    if not relation_name:
        return None
    try:
        payload = yaml.safe_load(rules_file.read_text()) or {}
    except (OSError, ValueError, yaml.YAMLError):
        return None
    child_names = _single_relation_child_fact_names(payload, relation_name)
    if len(child_names) != 1:
        return None
    relation_base = relation_ref.split("#", 1)[0].strip()
    child_ref = f"{relation_base}#input.{next(iter(child_names))}"
    return {child_ref: copy.deepcopy(scalar_value)}


def _relation_name_from_relation_ref(relation_ref: str) -> str:
    fragment = relation_ref.split("#", 1)[1] if "#" in relation_ref else relation_ref
    fragment = fragment.strip()
    if fragment.startswith("relation."):
        return fragment.removeprefix("relation.").strip()
    return ""


def _single_relation_child_fact_names(
    payload: object,
    relation_name: str,
) -> set[str]:
    if not isinstance(payload, dict) or not relation_name:
        return set()
    rules = payload.get("rules")
    if not isinstance(rules, list):
        return set()
    escaped_relation = re.escape(relation_name)
    child_pattern = re.compile(
        rf"(?<![A-Za-z0-9_]){escaped_relation}\."
        r"(?P<child>[A-Za-z_][A-Za-z0-9_]*)\b"
    )
    aggregate_pattern = re.compile(
        rf"\b(?:count_where|any_where|all_where)\(\s*{escaped_relation}\s*,\s*"
        r"(?P<child>[A-Za-z_][A-Za-z0-9_]*)\b(?!\s*\.)"
    )
    child_names: set[str] = set()
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        versions = rule.get("versions")
        if not isinstance(versions, list):
            continue
        for version in versions:
            if not isinstance(version, dict):
                continue
            formula = version.get("formula")
            if not isinstance(formula, str):
                continue
            child_names.update(
                match.group("child") for match in child_pattern.finditer(formula)
            )
            child_names.update(
                match.group("child") for match in aggregate_pattern.finditer(formula)
            )
    return child_names


def _relation_row_matches_scalar_value(
    row: dict[str, object],
    scalar_value: object,
) -> bool:
    if isinstance(scalar_value, bool):
        return any(value is scalar_value for value in row.values())
    return False


def _relation_rows_from_companion_tests(
    relation_ref: str,
    *,
    policy_repo_path: Path,
) -> list[dict[str, object]]:
    relation_test_file = _companion_test_file_for_relation_ref(
        relation_ref,
        policy_repo_path=policy_repo_path,
    )
    if relation_test_file is None or not relation_test_file.exists():
        return []
    try:
        payload = yaml.safe_load(relation_test_file.read_text()) or []
    except (OSError, ValueError, yaml.YAMLError):
        return []
    if not isinstance(payload, list):
        return []
    rows: list[dict[str, object]] = []
    for case in payload:
        if not isinstance(case, dict):
            continue
        inputs = case.get("input")
        if not isinstance(inputs, dict):
            continue
        relation_rows = inputs.get(relation_ref)
        if not isinstance(relation_rows, list):
            continue
        for row in relation_rows:
            if isinstance(row, dict):
                rows.append(copy.deepcopy(row))
    return rows


def _companion_test_file_for_relation_ref(
    relation_ref: str,
    *,
    policy_repo_path: Path,
) -> Path | None:
    relation_base = relation_ref.split("#", 1)[0].strip().strip("/")
    target_ref = _parse_rulespec_target(relation_base)
    if target_ref is None:
        return None
    target_file = _resolve_rulespec_target_file(target_ref, policy_repo_path)
    if target_file is None:
        return None
    test_file = _rulespec_test_path(target_file)
    if not test_file.exists() and not test_file.is_symlink():
        return None
    return validate_rulespec_context_file(test_file, target_file.parent)


def _split_table_row_relation_test_cases(test_file: Path) -> list[str]:
    if not test_file.exists():
        return []

    try:
        payload = yaml.safe_load(test_file.read_text()) or []
    except (OSError, yaml.YAMLError, ValueError):
        return []

    if isinstance(payload, dict) and isinstance(payload.get("cases"), list):
        cases = payload["cases"]
    elif isinstance(payload, list):
        cases = payload
    else:
        return []

    repaired_cases: list[str] = []
    updated_cases: list[object] = []
    changed = False
    for index, test_case in enumerate(cases, start=1):
        if not isinstance(test_case, dict):
            updated_cases.append(test_case)
            continue
        split_cases = _split_one_table_row_relation_test_case(test_case, index=index)
        if not split_cases:
            updated_cases.append(test_case)
            continue
        updated_cases.extend(split_cases)
        repaired_cases.append(str(test_case.get("name") or f"case {index}"))
        changed = True

    if not changed:
        return []
    if isinstance(payload, dict):
        payload["cases"] = updated_cases
    else:
        payload = updated_cases
    test_file.write_text(yaml.safe_dump(payload, sort_keys=False, allow_unicode=False))
    return repaired_cases


def _split_one_table_row_relation_test_case(
    test_case: dict,
    *,
    index: int,
) -> list[dict]:
    tables = test_case.get("tables")
    if not isinstance(tables, dict) or len(tables) != 1:
        return []
    table_entity, rows = next(iter(tables.items()))
    table_entity = str(table_entity)
    if not isinstance(rows, list) or not rows:
        return []
    if not all(isinstance(row, dict) for row in rows):
        return []
    if not any(
        any(_is_relation_input_key(row_key) for row_key in row)
        for row in rows
        if isinstance(row, dict)
    ):
        return []

    original_input = test_case.get("input") or {}
    if not isinstance(original_input, dict):
        return []
    original_output = test_case.get("output") or {}
    if not isinstance(original_output, dict):
        return []
    for expected_value in original_output.values():
        if isinstance(expected_value, list) and len(expected_value) != len(rows):
            return []

    base_name = str(test_case.get("name") or f"case {index}").strip() or f"case {index}"
    split_cases: list[dict] = []
    for row_index, row in enumerate(rows):
        case_copy = copy.deepcopy(test_case)
        case_copy.pop("tables", None)
        case_copy["name"] = f"{base_name} {table_entity} row {row_index + 1}"
        case_input = copy.deepcopy(original_input)
        case_input.update(copy.deepcopy(row))
        case_copy["input"] = case_input
        case_output: dict = {}
        for output_key, expected_value in original_output.items():
            if isinstance(expected_value, list):
                case_output[output_key] = copy.deepcopy(expected_value[row_index])
            else:
                case_output[output_key] = copy.deepcopy(expected_value)
        case_copy["output"] = case_output
        split_cases.append(case_copy)
    return split_cases


def _is_relation_input_key(key: object) -> bool:
    key_text = str(key)
    return "#relation." in key_text or ".relation." in key_text


def _try_repair_generated_proof_import_hashes_for_apply(
    result,
    *,
    output_root: Path,
    policy_repo_path: Path,
    issues: list[str],
) -> list[str]:
    """Refresh stale proof import hashes in the generated target itself."""
    if not any("Proof import hash mismatch" in str(issue) for issue in issues):
        return []
    try:
        relative_output = _relative_generated_output_path(
            result, output_root=output_root
        )
    except RuntimeError:
        return []

    rules_file = Path(str(getattr(result, "output_file", "") or ""))
    if not rules_file.exists():
        return []
    target_base = (
        f"{_repo_jurisdiction_prefix(policy_repo_path)}:"
        f"{_relative_rulespec_import_target(relative_output)}"
    )
    original = rules_file.read_text()
    repaired, repair_count = _repair_proof_import_hashes(
        original,
        target_base=target_base,
        rules_file=rules_file,
        repo_path=policy_repo_path,
    )
    if repair_count <= 0 or repaired == original:
        return []
    rules_file.write_text(repaired)
    return [f"hash[{index}]" for index in range(repair_count)]


class _ProofAtomKindRepair(NamedTuple):
    rule: str
    atom_index: int
    old_kind: str
    new_kind: str


class _UnclassifiedProofAtomKind(NamedTuple):
    rule: str
    atom_index: int
    reason: str


class _ProofAtomKindNormalizationResult(NamedTuple):
    content: str
    repairs: tuple[_ProofAtomKindRepair, ...]
    unclassified: tuple[_UnclassifiedProofAtomKind, ...]
    error: str | None


class _CustomProofAtomKindDerivation(NamedTuple):
    kind: str | None
    reason: str | None
    version_indices: tuple[int, ...]


class _ProofAtomKindCandidate(NamedTuple):
    rule: dict[str, object]
    atom: dict[str, object]
    rule_node: object
    atom_node: object
    node_path: tuple[object, ...]
    rule_name: str
    atom_index: int


_GENERATED_PROOF_RULE_KINDS = frozenset({"parameter", "derived", "derived_relation"})
_VERSION_OUTPUT_PROOF_PATH = re.compile(r"^versions\[(\d+)\]\.(?:formula|values)\b")


def _proof_atom_kind_repair_label(repair: _ProofAtomKindRepair) -> str:
    return f"{repair.rule}[{repair.atom_index}]:{repair.old_kind}->{repair.new_kind}"


def _unclassified_proof_atom_kind_label(
    issue: _UnclassifiedProofAtomKind,
) -> str:
    return f"{issue.rule}[{issue.atom_index}]:custom ({issue.reason})"


def _proof_atoms_from_rule(rule: dict[str, object]) -> object:
    metadata = rule.get("metadata")
    if isinstance(metadata, dict) and isinstance(metadata.get("proof"), dict):
        return metadata["proof"].get("atoms")
    proof = rule.get("proof")
    if isinstance(proof, dict):
        return proof.get("atoms")
    return None


def _yaml_unique_mapping_value(node: object, key: str) -> object | None:
    if not isinstance(node, MappingNode):
        return None
    matches = [
        value_node
        for key_node, value_node in node.value
        if isinstance(key_node, ScalarNode) and key_node.value == key
    ]
    if len(matches) != 1:
        return None
    return matches[0]


def _yaml_node_reference_counts(root_node: object) -> Counter[int]:
    """Count every composed-node edge so aliases can be rejected before surgery."""
    references: Counter[int] = Counter()
    expanded: set[int] = set()
    pending = [root_node]
    while pending:
        node = pending.pop()
        references[id(node)] += 1
        if id(node) in expanded:
            continue
        expanded.add(id(node))
        if isinstance(node, MappingNode):
            for key_node, value_node in node.value:
                pending.extend((key_node, value_node))
        elif isinstance(node, SequenceNode):
            pending.extend(node.value)
    return references


def _yaml_mapping_has_unique_scalar_keys(node: object) -> bool:
    if not isinstance(node, MappingNode):
        return False
    keys: list[str] = []
    for key_node, _ in node.value:
        if not isinstance(key_node, ScalarNode):
            return False
        keys.append(key_node.value)
    return len(keys) == len(set(keys))


def _yaml_node_contains_merge_key(node: object) -> bool:
    """Return whether a composed derivation node contains a YAML merge key."""
    pending = [node]
    visited: set[int] = set()
    while pending:
        current = pending.pop()
        if current is None or id(current) in visited:
            continue
        visited.add(id(current))
        if isinstance(current, MappingNode):
            for key_node, value_node in current.value:
                if isinstance(key_node, ScalarNode) and (
                    key_node.value == "<<" or key_node.tag == "tag:yaml.org,2002:merge"
                ):
                    return True
                pending.extend((key_node, value_node))
        elif isinstance(current, SequenceNode):
            pending.extend(current.value)
    return False


def _proof_atom_nodes_from_rule_node(
    rule: dict[str, object],
    rule_node: object,
) -> tuple[object, tuple[object, ...]]:
    """Follow the same metadata/top-level proof route as the parsed rule."""
    node_path: list[object] = [rule_node]
    metadata = rule.get("metadata")
    use_metadata_proof = isinstance(metadata, dict) and isinstance(
        metadata.get("proof"), dict
    )
    if use_metadata_proof:
        metadata_node = _yaml_unique_mapping_value(rule_node, "metadata")
        node_path.append(metadata_node)
        proof_node = _yaml_unique_mapping_value(metadata_node, "proof")
    else:
        proof_node = _yaml_unique_mapping_value(rule_node, "proof")
    node_path.append(proof_node)
    atoms_node = _yaml_unique_mapping_value(proof_node, "atoms")
    node_path.append(atoms_node)
    return atoms_node, tuple(node_path)


def _proof_derivation_nodes(
    rule_node: object,
    version_indices: tuple[int, ...],
) -> tuple[object, ...]:
    versions_node = _yaml_unique_mapping_value(rule_node, "versions")
    nodes: list[object] = [versions_node]
    if not isinstance(versions_node, SequenceNode):
        return tuple(nodes)
    for version_index in version_indices:
        version_node = (
            versions_node.value[version_index]
            if version_index < len(versions_node.value)
            else None
        )
        nodes.append(version_node)
    return tuple(nodes)


def _yaml_node_path_is_unambiguous(
    node_path: tuple[object, ...],
    reference_counts: Counter[int],
) -> bool:
    for node in node_path:
        if node is None or reference_counts[id(node)] != 1:
            return False
        if isinstance(node, MappingNode) and not _yaml_mapping_has_unique_scalar_keys(
            node
        ):
            return False
    return True


def _proof_version_output_kind(
    rule: dict[str, object],
    version: object,
) -> tuple[str | None, str | None]:
    if not isinstance(version, dict):
        return None, "selected version is not a mapping"

    has_formula = "formula" in version
    has_values = "values" in version
    if has_formula and has_values:
        return None, "selected version declares both formula and values"
    if has_values:
        if not isinstance(version.get("values"), dict):
            return None, "selected version values are not a mapping"
        if str(rule.get("kind") or "").strip() != "parameter":
            return None, "versioned values belong to a non-parameter rule"
        return "parameter_table", None
    if has_formula:
        if version.get("formula") is None:
            return None, "selected version formula is null"
        return _generated_proof_atom_kind(rule), None
    return None, "selected version declares neither formula nor values"


def _derived_custom_proof_atom_kind(
    rule: dict[str, object],
    atom: dict[str, object],
) -> _CustomProofAtomKindDerivation:
    rule_kind = str(rule.get("kind") or "").strip()
    if rule_kind not in _GENERATED_PROOF_RULE_KINDS:
        return _CustomProofAtomKindDerivation(
            None,
            f"unsupported rule kind {rule_kind or '<missing>'}",
            (),
        )

    versions = rule.get("versions")
    if not isinstance(versions, list) or not versions:
        return _CustomProofAtomKindDerivation(
            None, "rule has no non-empty versions list", ()
        )

    path = str(atom.get("path") or "").strip()
    if not path:
        return _CustomProofAtomKindDerivation(None, "proof atom path is missing", ())
    normalized_path = re.sub(r"\s+", "", path).rstrip(".")
    normalized_path = re.sub(r"^versions\.", "versions[0].", normalized_path)
    match = _VERSION_OUTPUT_PROOF_PATH.match(normalized_path)
    if match is not None:
        version_index = int(match.group(1))
        if version_index >= len(versions):
            return _CustomProofAtomKindDerivation(
                None,
                f"proof atom path selects missing version {version_index}",
                (),
            )
        kind, reason = _proof_version_output_kind(rule, versions[version_index])
        return _CustomProofAtomKindDerivation(kind, reason, (version_index,))

    if normalized_path != "versions":
        return _CustomProofAtomKindDerivation(
            None, "proof atom path does not identify a generated output", ()
        )

    version_kinds: list[str] = []
    for version_index, version in enumerate(versions):
        version_kind, reason = _proof_version_output_kind(rule, version)
        if version_kind is None:
            return _CustomProofAtomKindDerivation(
                None,
                f"broad versions path is not classifiable: {reason}",
                tuple(range(version_index + 1)),
            )
        version_kinds.append(version_kind)
    if len(set(version_kinds)) != 1:
        return _CustomProofAtomKindDerivation(
            None,
            "broad versions path spans mixed formula and values outputs",
            tuple(range(len(versions))),
        )
    return _CustomProofAtomKindDerivation(
        version_kinds[0], None, tuple(range(len(versions)))
    )


def _replacement_for_proof_kind_scalar(
    content: str,
    node: object,
    *,
    old_kind: str,
    new_kind: str,
) -> tuple[int, int, str] | None:
    if not isinstance(node, ScalarNode):
        return None
    if not isinstance(node.value, str) or node.value.strip() != old_kind:
        return None
    start = node.start_mark.index
    end = node.end_mark.index
    scalar = content[start:end]
    if scalar == old_kind:
        replacement = new_kind
    elif scalar == f"'{old_kind}'":
        replacement = f"'{new_kind}'"
    elif scalar == f'"{old_kind}"':
        replacement = f'"{new_kind}"'
    else:
        return None
    return start, end, replacement


def _normalize_invalid_proof_atom_kinds(
    content: str,
) -> _ProofAtomKindNormalizationResult:
    """Normalize known invalid proof kinds without rewriting unrelated YAML bytes."""
    try:
        payload = yaml.safe_load(content) or {}
        root_node = yaml.compose(content)
    except (yaml.YAMLError, ValueError) as exc:
        return _ProofAtomKindNormalizationResult(content, (), (), str(exc))
    if not isinstance(payload, dict) or not isinstance(root_node, MappingNode):
        return _ProofAtomKindNormalizationResult(content, (), (), None)

    rules = payload.get("rules")
    rules_node = _yaml_unique_mapping_value(root_node, "rules")
    if not isinstance(rules, list):
        return _ProofAtomKindNormalizationResult(content, (), (), None)
    rule_nodes = rules_node.value if isinstance(rules_node, SequenceNode) else []

    reference_counts = _yaml_node_reference_counts(root_node)
    candidates: list[_ProofAtomKindCandidate] = []
    for rule_index, rule in enumerate(rules):
        if not isinstance(rule, dict):
            continue
        rule_name = str(rule.get("name") or f"rules[{rule_index}]").strip()
        rule_name = rule_name or f"rules[{rule_index}]"
        atoms = _proof_atoms_from_rule(rule)
        if not isinstance(atoms, list):
            continue
        rule_node = rule_nodes[rule_index] if rule_index < len(rule_nodes) else None
        atoms_node, proof_node_path = _proof_atom_nodes_from_rule_node(rule, rule_node)
        atom_nodes = atoms_node.value if isinstance(atoms_node, SequenceNode) else []
        for atom_index, atom in enumerate(atoms):
            if not isinstance(atom, dict):
                continue
            kind = str(atom.get("kind") or "").strip()
            if kind not in {"custom", "rate"}:
                continue
            atom_node = atom_nodes[atom_index] if atom_index < len(atom_nodes) else None
            candidates.append(
                _ProofAtomKindCandidate(
                    rule,
                    atom,
                    rule_node,
                    atom_node,
                    (root_node, rules_node, *proof_node_path, atom_node),
                    rule_name,
                    atom_index,
                )
            )

    span_counts: Counter[tuple[int, int]] = Counter()
    for candidate in candidates:
        kind_node = _yaml_unique_mapping_value(candidate.atom_node, "kind")
        if isinstance(kind_node, ScalarNode):
            span_counts[(kind_node.start_mark.index, kind_node.end_mark.index)] += 1

    replacements: list[tuple[int, int, str]] = []
    repairs: list[_ProofAtomKindRepair] = []
    unclassified: list[_UnclassifiedProofAtomKind] = []
    for candidate in candidates:
        old_kind = str(candidate.atom.get("kind") or "").strip()
        derivation_nodes: tuple[object, ...] = ()
        if old_kind == "rate":
            new_kind, reason = "parameter", None
        else:
            derivation = _derived_custom_proof_atom_kind(candidate.rule, candidate.atom)
            new_kind, reason = derivation.kind, derivation.reason
            derivation_nodes = _proof_derivation_nodes(
                candidate.rule_node, derivation.version_indices
            )
            if any(_yaml_node_contains_merge_key(node) for node in derivation_nodes):
                new_kind = None
                reason = "YAML merge key appears on the rule/version derivation route"
        if new_kind is None:
            unclassified.append(
                _UnclassifiedProofAtomKind(
                    candidate.rule_name,
                    candidate.atom_index,
                    reason or "rule structure is not classifiable",
                )
            )
            continue

        kind_node = _yaml_unique_mapping_value(candidate.atom_node, "kind")
        if not _yaml_node_path_is_unambiguous(
            (*candidate.node_path, kind_node, *derivation_nodes), reference_counts
        ):
            if old_kind == "custom":
                unclassified.append(
                    _UnclassifiedProofAtomKind(
                        candidate.rule_name,
                        candidate.atom_index,
                        "YAML proof atom route is ambiguous or aliased",
                    )
                )
            continue
        replacement = _replacement_for_proof_kind_scalar(
            content,
            kind_node,
            old_kind=old_kind,
            new_kind=new_kind,
        )
        if replacement is None or span_counts[(replacement[0], replacement[1])] != 1:
            if old_kind == "custom":
                unclassified.append(
                    _UnclassifiedProofAtomKind(
                        candidate.rule_name,
                        candidate.atom_index,
                        "kind scalar cannot be rewritten safely",
                    )
                )
            continue
        replacements.append(replacement)
        repairs.append(
            _ProofAtomKindRepair(
                candidate.rule_name, candidate.atom_index, old_kind, new_kind
            )
        )

    normalized = content
    for start, end, replacement in sorted(replacements, reverse=True):
        normalized = normalized[:start] + replacement + normalized[end:]
    return _ProofAtomKindNormalizationResult(
        normalized,
        tuple(repairs),
        tuple(unclassified),
        None,
    )


def _normalize_invalid_proof_atom_kinds_file(
    rules_file: Path,
) -> _ProofAtomKindNormalizationResult:
    try:
        original_bytes = rules_file.read_bytes()
        original = original_bytes.decode("utf-8")
    except (OSError, UnicodeError) as exc:
        return _ProofAtomKindNormalizationResult("", (), (), str(exc))
    result = _normalize_invalid_proof_atom_kinds(original)
    if result.content != original:
        normalized_bytes = result.content.encode("utf-8")
        try:
            mode = stat.S_IMODE(rules_file.stat().st_mode)
            _atomic_replace_bytes(
                rules_file,
                normalized_bytes,
                mode=mode,
            )
        except (OSError, RuntimeError, UnicodeError) as exc:
            try:
                current_bytes = rules_file.read_bytes()
            except OSError as read_exc:
                return _ProofAtomKindNormalizationResult(
                    "",
                    (),
                    (),
                    f"{exc}; failed to verify target after write error: {read_exc}",
                )
            if current_bytes == normalized_bytes:
                return _ProofAtomKindNormalizationResult(
                    result.content,
                    result.repairs,
                    result.unclassified,
                    f"{exc} (normalized bytes were installed, but directory "
                    "durability could not be confirmed)",
                )
            if current_bytes != original_bytes:
                return _ProofAtomKindNormalizationResult(
                    "",
                    (),
                    (),
                    f"{exc}; target bytes no longer match original or normalized content",
                )
            return _ProofAtomKindNormalizationResult(original, (), (), str(exc))
    return result


def _try_repair_generated_invalid_proof_atom_kinds_for_apply(
    result,
    *,
    output_root: Path,
    issues: list[str],
) -> _ProofAtomKindNormalizationResult:
    """Normalize classifiable invalid proof kinds in generated output."""
    empty = _ProofAtomKindNormalizationResult("", (), (), None)
    if not any("Proof atom kind invalid" in str(issue) for issue in issues):
        return empty
    try:
        _relative_generated_output_path(result, output_root=output_root)
    except RuntimeError:
        return empty

    rules_file = Path(str(getattr(result, "output_file", "") or ""))
    if not rules_file.exists():
        return empty
    return _normalize_invalid_proof_atom_kinds_file(rules_file)


def _try_repair_generated_empty_deferred_source_values_for_apply(
    result,
    *,
    output_root: Path,
) -> list[str]:
    """Remove empty optional deferred-output source_values emitted by the model."""
    try:
        _relative_generated_output_path(result, output_root=output_root)
    except RuntimeError:
        return []

    rules_file = Path(str(getattr(result, "output_file", "") or ""))
    return _remove_empty_deferred_source_values(rules_file=rules_file)


def _try_repair_generated_unquoted_source_scalars_for_apply(
    result,
    *,
    output_root: Path,
) -> list[str]:
    """Quote generated source: scalars that contain YAML-significant colons."""
    try:
        _relative_generated_output_path(result, output_root=output_root)
    except RuntimeError:
        return []

    rules_file = Path(str(getattr(result, "output_file", "") or ""))
    return _quote_unquoted_source_scalars(rules_file=rules_file)


def _try_repair_generated_invalid_deferred_source_values_for_apply(
    result,
    *,
    output_root: Path,
    issues: list[str],
) -> list[str]:
    """Canonicalize or remove optional invalid source_values from deferred outputs."""
    if not any(
        (
            "module.deferred_outputs[" in str(issue)
            and (
                (
                    ".source_values entry `" in str(issue)
                    and "must be an absolute RuleSpec target" in str(issue)
                )
                or (".source_values must list absolute RuleSpec targets" in str(issue))
            )
        )
        for issue in issues
    ):
        return []
    try:
        relative_output = _relative_generated_output_path(
            result, output_root=output_root
        )
    except RuntimeError:
        return []

    rules_file = Path(str(getattr(result, "output_file", "") or ""))
    base_anchor = _relative_output_to_anchor(relative_output)
    return _canonicalize_or_remove_invalid_deferred_source_values(
        rules_file=rules_file,
        base_anchor=base_anchor,
    )


def _try_repair_generated_out_of_scope_deferred_outputs_for_apply(
    result,
    *,
    output_root: Path,
    policy_repo_path: Path,
) -> list[str]:
    """Remove deferred outputs outside the generated target file's scope."""
    try:
        relative_output = _relative_generated_output_path(
            result,
            output_root=output_root,
        )
    except RuntimeError:
        return []

    rules_file = Path(str(getattr(result, "output_file", "") or ""))
    base_anchor = _relative_output_to_anchor(
        relative_output,
        policy_repo_path=policy_repo_path,
    )
    return _remove_out_of_scope_deferred_outputs(
        rules_file=rules_file,
        base_anchor=base_anchor,
    )


def _only_pending_empty_deferred_source_values_issues(issues: list[str]) -> bool:
    return bool(issues) and all(
        "module.deferred_outputs[" in str(issue)
        and ".source_values must list absolute RuleSpec targets" in str(issue)
        for issue in issues
    )


def _remove_empty_deferred_source_values(*, rules_file: Path) -> list[str]:
    if not rules_file.exists():
        return []

    try:
        lines = rules_file.read_text().splitlines(keepends=True)
    except OSError:
        return []

    repaired: list[str] = []
    removed = 0
    for line in lines:
        if re.match(r"^\s*source_values:\s*\[\s*\]\s*(?:#.*)?$", line):
            removed += 1
            continue
        repaired.append(line)

    if removed == 0:
        return []

    rules_file.write_text("".join(repaired))
    return [f"source_values[{index}]" for index in range(removed)]


def _quote_unquoted_source_scalars(*, rules_file: Path) -> list[str]:
    if not rules_file.exists():
        return []
    try:
        original = rules_file.read_text()
    except OSError:
        return []
    try:
        yaml.safe_load(original)
        return []
    except (yaml.YAMLError, ValueError):
        pass

    repaired_lines: list[str] = []
    repaired: list[str] = []
    for line_number, raw_line in enumerate(
        original.splitlines(keepends=True),
        start=1,
    ):
        newline = "\n" if raw_line.endswith("\n") else ""
        line = raw_line[:-1] if newline else raw_line
        match = re.match(
            r"^(\s*source:\s+)([^'\"|>{\[].*:\s+.*?)(\s*)$",
            line,
        )
        if match is None:
            repaired_lines.append(raw_line)
            continue
        prefix, value, trailing = match.groups()
        quoted = value.replace("'", "''")
        repaired_lines.append(f"{prefix}'{quoted}'{trailing}{newline}")
        repaired.append(f"source:{line_number}")

    if not repaired:
        return []
    repaired_text = "".join(repaired_lines)
    try:
        yaml.safe_load(repaired_text)
    except (yaml.YAMLError, ValueError):
        return []
    rules_file.write_text(repaired_text)
    return repaired


def _canonicalize_or_remove_invalid_deferred_source_values(
    *,
    rules_file: Path,
    base_anchor: str,
) -> list[str]:
    if not rules_file.exists():
        return []
    try:
        payload = yaml.safe_load(rules_file.read_text()) or {}
    except (OSError, yaml.YAMLError, ValueError):
        return []
    if not isinstance(payload, dict):
        return []
    module = payload.get("module")
    if not isinstance(module, dict):
        return []
    deferred_outputs = module.get("deferred_outputs")
    if not isinstance(deferred_outputs, list):
        return []

    rule_names = {
        str(rule.get("name") or "").strip()
        for rule in payload.get("rules") or []
        if isinstance(rule, dict) and str(rule.get("name") or "").strip()
    }

    repaired: list[str] = []
    for index, record in enumerate(deferred_outputs):
        if not isinstance(record, dict):
            continue
        source_values = record.get("source_values")
        if source_values is None:
            continue
        if not isinstance(source_values, list) or not source_values:
            record.pop("source_values", None)
            repaired.append(f"source_values[{index}]")
            continue

        canonical_values: list[str] = []
        changed = False
        for value in source_values:
            if _looks_like_absolute_rulespec_output_target(value):
                canonical_values.append(str(value).strip())
                continue
            value_text = str(value or "").strip() if isinstance(value, str) else ""
            if re.fullmatch(r"[A-Za-z_][A-Za-z0-9_]*", value_text) and (
                value_text in rule_names
            ):
                canonical_values.append(f"{base_anchor}#{value_text}")
                changed = True
                continue
            changed = True

        if not changed:
            continue
        if canonical_values:
            record["source_values"] = list(dict.fromkeys(canonical_values))
        else:
            record.pop("source_values", None)
        repaired.append(f"source_values[{index}]")

    if not repaired:
        return []
    rules_file.write_text(yaml.safe_dump(payload, sort_keys=False, allow_unicode=False))
    return repaired


def _looks_like_absolute_rulespec_output_target(value: Any) -> bool:
    if not isinstance(value, str):
        return False
    text = str(value or "").strip()
    if ":" not in text or text.count("#") != 1:
        return False
    path, symbol = text.rsplit("#", 1)
    return bool(path.strip()) and bool(symbol.strip())


def _remove_out_of_scope_deferred_outputs(
    *,
    rules_file: Path,
    base_anchor: str,
) -> list[str]:
    if not rules_file.exists():
        return []
    try:
        payload = yaml.safe_load(rules_file.read_text()) or {}
    except (OSError, yaml.YAMLError, ValueError):
        return []
    if not isinstance(payload, dict):
        return []
    module = payload.get("module")
    if not isinstance(module, dict):
        return []
    deferred_outputs = module.get("deferred_outputs")
    if not isinstance(deferred_outputs, list):
        return []

    kept: list[Any] = []
    removed: list[str] = []
    for index, record in enumerate(deferred_outputs):
        if not isinstance(record, dict):
            kept.append(record)
            continue
        output = str(record.get("output") or "").strip()
        if not _looks_like_absolute_rulespec_output_target(output):
            kept.append(record)
            continue
        if _rulespec_target_within_anchor(output, base_anchor=base_anchor):
            kept.append(record)
            continue
        removed.append(f"deferred_outputs[{index}]")

    if not removed:
        return []
    if kept:
        module["deferred_outputs"] = kept
    else:
        module.pop("deferred_outputs", None)
    rules_file.write_text(yaml.safe_dump(payload, sort_keys=False, allow_unicode=False))
    return removed


def _rulespec_target_within_anchor(target: str, *, base_anchor: str) -> bool:
    if not _looks_like_absolute_rulespec_output_target(target):
        return False
    target_path = target.rsplit("#", 1)[0].strip()
    return target_path == base_anchor or target_path.startswith(f"{base_anchor}/")


def _try_repair_generated_deferred_output_subsection_paths_for_apply(
    result,
    *,
    output_root: Path,
    policy_repo_path: Path,
) -> list[str]:
    """Qualify parent-level deferred outputs with source subsection paths."""
    try:
        relative_output = _relative_generated_output_path(
            result,
            output_root=output_root,
        )
    except RuntimeError:
        return []

    rules_file = Path(str(getattr(result, "output_file", "") or ""))
    base_parts = relative_output.with_suffix("").parts
    if len(base_parts) != 3 or base_parts[0] != "statutes":
        return []
    return _qualify_deferred_output_subsection_paths(
        rules_file=rules_file,
        base_anchor=_relative_output_to_anchor(
            relative_output,
            policy_repo_path=policy_repo_path,
        ),
    )


def _qualify_deferred_output_subsection_paths(
    *,
    rules_file: Path,
    base_anchor: str,
) -> list[str]:
    if not rules_file.exists():
        return []
    try:
        payload = yaml.safe_load(rules_file.read_text()) or {}
    except (OSError, yaml.YAMLError, ValueError):
        return []
    if not isinstance(payload, dict):
        return []

    module = payload.get("module")
    if not isinstance(module, dict):
        return []
    deferred_outputs = module.get("deferred_outputs")
    if not isinstance(deferred_outputs, list):
        return []

    repaired: list[str] = []
    for record in deferred_outputs:
        if not isinstance(record, dict):
            continue
        output = str(record.get("output") or "").strip()
        double_hash_prefix = f"{base_anchor}#"
        if output.startswith(double_hash_prefix):
            remainder = output[len(double_hash_prefix) :]
            raw_subsection, separator, raw_symbol = remainder.partition("#")
            subsection = raw_subsection.strip().strip("()")
            symbol = raw_symbol.strip()
            if separator and re.fullmatch(r"[A-Za-z0-9]+", subsection) and symbol:
                qualified = f"{base_anchor}/{subsection}#{symbol}"
                record["output"] = qualified
                repaired.append(qualified)
                continue

        if not output.startswith(f"{base_anchor}#"):
            continue
        reason = str(record.get("reason") or "")
        match = re.search(r"\b[Ss]ubsection\s*\(([A-Za-z0-9]+)\)", reason)
        if match is None:
            match = re.search(
                r"\b(?:[0-9A-Za-z]+\s+USC\s+|section\s+)"
                r"[0-9A-Za-z.-]+\s*\(([A-Za-z0-9]+)\)",
                reason,
                flags=re.IGNORECASE,
            )
        if match is None:
            continue
        subsection = match.group(1).strip()
        symbol = output.rsplit("#", 1)[1].strip()
        if not subsection or not symbol:
            continue
        qualified = f"{base_anchor}/{subsection}#{symbol}"
        record["output"] = qualified
        repaired.append(qualified)

    if not repaired:
        return []

    rules_file.write_text(yaml.safe_dump(payload, sort_keys=False, allow_unicode=False))
    return repaired


def _try_repair_generated_missing_deferred_outputs_for_apply(
    result,
    *,
    output_root: Path,
    policy_repo_path: Path,
    issues: list[str],
) -> list[str]:
    """Add a concrete deferred output when an empty deferred module omits one."""
    if not any(
        "Source sub-paragraph coverage missing" in str(issue)
        and "module.deferred_outputs" in str(issue)
        for issue in issues
    ):
        return []
    try:
        relative_output = _relative_generated_output_path(
            result,
            output_root=output_root,
        )
    except RuntimeError:
        return []

    rules_file = Path(str(getattr(result, "output_file", "") or ""))
    if not rules_file.exists():
        return []
    try:
        payload = yaml.safe_load(rules_file.read_text()) or {}
    except (OSError, yaml.YAMLError, ValueError):
        return []
    if not isinstance(payload, dict):
        return []

    rules = payload.get("rules")
    if rules not in (None, []) and rules != []:
        return []
    module = payload.get("module")
    if not isinstance(module, dict):
        return []
    status = str(module.get("status") or "").strip().lower()
    if status not in {"deferred", "entity_not_supported"}:
        return []

    deferred_outputs = module.get("deferred_outputs")
    if deferred_outputs is None:
        deferred_outputs = []
        module["deferred_outputs"] = deferred_outputs
    if not isinstance(deferred_outputs, list):
        return []

    summary = str(module.get("summary") or "")
    symbol, label = _infer_deferred_output_symbol_from_summary(summary)
    if not symbol:
        symbol = "deferred_output"
        label = "deferred output"
    base_anchor = _relative_output_to_anchor(
        relative_output,
        policy_repo_path=policy_repo_path,
    )
    output = f"{base_anchor}#{symbol}"
    existing_outputs = {
        str(record.get("output") or "").strip()
        for record in deferred_outputs
        if isinstance(record, dict)
    }
    if output in existing_outputs:
        return []

    reason = (
        f"Generated module is marked `{status}`; the source definition for "
        f"{label} cannot be encoded as an executable RuleSpec output until the "
        "target entity or surface is supported."
    )
    deferred_outputs.append(
        {
            "output": output,
            "reason": reason,
        }
    )
    payload["rules"] = []
    rules_file.write_text(yaml.safe_dump(payload, sort_keys=False, allow_unicode=False))
    return [output]


def _try_repair_generated_mixed_missing_deferred_outputs_for_apply(
    result,
    *,
    output_root: Path,
    policy_repo_path: Path,
    issues: list[str],
) -> list[str]:
    """Add deferred outputs for unsupported source gaps in otherwise encoded modules."""
    source_gaps = [
        gap
        for issue in issues
        if "Source sub-paragraph coverage missing" in str(issue)
        and "module.deferred_outputs" in str(issue)
        for gap in [_parse_source_coverage_gap_issue(str(issue))]
        if gap is not None
    ]
    if not source_gaps:
        return []
    try:
        relative_output = _relative_generated_output_path(
            result,
            output_root=output_root,
        )
    except RuntimeError:
        return []

    rules_file = Path(str(getattr(result, "output_file", "") or ""))
    if not rules_file.exists():
        return []
    try:
        payload = yaml.safe_load(rules_file.read_text()) or {}
    except (OSError, yaml.YAMLError, ValueError):
        return []
    if not isinstance(payload, dict):
        return []

    rules = payload.get("rules")
    if not isinstance(rules, list) or not rules:
        return []
    module = payload.get("module")
    if not isinstance(module, dict):
        module = {}
        payload["module"] = module
    deferred_outputs = module.get("deferred_outputs")
    if deferred_outputs is None:
        deferred_outputs = []
        module["deferred_outputs"] = deferred_outputs
    if not isinstance(deferred_outputs, list):
        return []

    base_anchor = _relative_output_to_anchor(
        relative_output,
        policy_repo_path=policy_repo_path,
    )
    existing_outputs = {
        str(record.get("output") or "").strip()
        for record in deferred_outputs
        if isinstance(record, dict)
    }
    repaired: list[str] = []
    for citation, excerpt in source_gaps:
        output_path = _source_coverage_output_path(base_anchor, citation=citation)
        symbol = _source_coverage_deferred_symbol(excerpt, citation=citation)
        output = f"{output_path}#{symbol}"
        if output in existing_outputs:
            continue
        deferred_outputs.append(
            {
                "output": output,
                "reason": (
                    "Generated module encodes the supported rules from this "
                    "source, but this source subparagraph depends on policy "
                    "surfaces or entities that are not available in the current "
                    "RuleSpec context. It is deferred instead of being modeled "
                    "as a caller-supplied input or an unsupported local entity."
                ),
            }
        )
        existing_outputs.add(output)
        repaired.append(output)

    if not repaired:
        return []
    rules_file.write_text(yaml.safe_dump(payload, sort_keys=False, allow_unicode=False))
    return repaired


def _try_repair_generated_admin_agency_aggregate_entities_for_apply(
    result,
    *,
    output_root: Path,
    policy_repo_path: Path,
) -> list[str]:
    """Defer State-agency/FNS aggregate measures emitted on supported entities."""
    metrics = getattr(result, "metrics", None)
    issues = list(getattr(metrics, "ci_issues", []) or [])
    if not any(
        str(issue).startswith("Unsupported administrative aggregate entity:")
        for issue in issues
    ):
        return []
    try:
        relative_output = _relative_generated_output_path(
            result,
            output_root=output_root,
        )
    except RuntimeError:
        return []

    rules_file = Path(str(getattr(result, "output_file", "") or ""))
    if not rules_file.exists():
        return []
    try:
        payload = yaml.safe_load(rules_file.read_text()) or {}
    except (OSError, yaml.YAMLError, ValueError):
        return []
    if not isinstance(payload, dict):
        return []

    rules = payload.get("rules")
    if not isinstance(rules, list) or not rules:
        return []
    module = payload.get("module")
    if not isinstance(module, dict):
        module = {}
        payload["module"] = module
    module["status"] = "entity_not_supported"

    base_anchor = _relative_output_to_anchor(
        relative_output,
        policy_repo_path=policy_repo_path,
    )
    deferred_outputs = []
    seen_outputs: set[str] = set()
    for index, rule in enumerate(rules):
        if not isinstance(rule, dict):
            continue
        if not str(rule.get("entity") or "").strip():
            continue
        symbol = str(rule.get("name") or f"deferred_output_{index + 1}").strip()
        if not symbol:
            symbol = f"deferred_output_{index + 1}"
        output = f"{base_anchor}#{symbol}"
        if output in seen_outputs:
            continue
        seen_outputs.add(output)
        deferred_outputs.append(
            {
                "output": output,
                "reason": (
                    "The source defines a State agency/FNS aggregate "
                    "performance, sampling, liability, waiver, or bonus "
                    "measure, but the generated output was scoped to a "
                    "household/person/tax/payment-style entity rather than "
                    "the source-stated administrative entity."
                ),
            }
        )
    if not deferred_outputs:
        output = f"{base_anchor}#deferred_output"
        deferred_outputs.append(
            {
                "output": output,
                "reason": (
                    "The source defines a State agency/FNS administrative "
                    "aggregate measure, which cannot be encoded as an "
                    "executable RuleSpec output until that entity is supported."
                ),
            }
        )

    module["deferred_outputs"] = deferred_outputs
    payload["rules"] = []
    rules_file.write_text(yaml.safe_dump(payload, sort_keys=False, allow_unicode=False))

    test_file = _rulespec_test_path(rules_file)
    if test_file.exists():
        test_file.write_text("[]\n")

    return [str(record["output"]) for record in deferred_outputs]


def _try_repair_generated_parameter_only_companion_tests_for_apply(
    result,
    *,
    output_root: Path,
    policy_repo_path: Path,
) -> list[str]:
    """Empty generated tests that only assert local parameter constants."""
    try:
        relative_output = _relative_generated_output_path(
            result,
            output_root=output_root,
        )
    except RuntimeError:
        return []
    rules_file = Path(str(getattr(result, "output_file", "") or ""))
    test_file = _rulespec_test_path(rules_file)
    if not test_file.exists():
        return []
    parameter_names = _parameter_only_rule_names(rules_file)
    if not parameter_names:
        return []
    try:
        cases = _load_rulespec_test_cases(test_file)
    except (OSError, ValueError, yaml.YAMLError):
        return []
    if not cases:
        return []

    target_base = (
        f"{_repo_jurisdiction_prefix(policy_repo_path)}:"
        f"{_relative_rulespec_import_target(relative_output)}"
    )
    repaired_cases: list[str] = []
    for index, case in enumerate(cases, 1):
        if not isinstance(case, dict):
            return []
        outputs = case.get("output")
        if not isinstance(outputs, dict) or not outputs:
            return []
        for key in outputs:
            key_text = str(key)
            if not key_text.startswith(f"{target_base}#"):
                return []
            if _rulespec_test_key_fragment(key_text) not in parameter_names:
                return []
        repaired_cases.append(str(case.get("name") or f"case_{index}"))
    if not repaired_cases:
        return []
    test_file.write_text("[]\n")
    return repaired_cases


def _parameter_only_rule_names(rules_file: Path) -> set[str]:
    if not rules_file.exists():
        return set()
    try:
        payload = yaml.safe_load(rules_file.read_text()) or {}
    except (OSError, yaml.YAMLError, ValueError):
        return set()
    if not isinstance(payload, dict):
        return set()
    rules = payload.get("rules")
    if not isinstance(rules, list) or not rules:
        return set()
    names: set[str] = set()
    for rule in rules:
        if not isinstance(rule, dict):
            return set()
        if str(rule.get("kind") or "").strip().lower() != "parameter":
            return set()
        name = str(rule.get("name") or "").strip()
        if not name:
            return set()
        names.add(name)
    return names


def _try_repair_generated_nonoperative_source_coverage_for_apply(
    result,
    *,
    output_root: Path,
    policy_repo_path: Path,
    issues: list[str],
) -> list[str]:
    """Defer non-operative findings/intent clauses omitted from source coverage."""
    try:
        relative_output = _relative_generated_output_path(
            result,
            output_root=output_root,
        )
    except RuntimeError:
        return []

    rules_file = Path(str(getattr(result, "output_file", "") or ""))
    if not rules_file.exists():
        return []
    try:
        payload = yaml.safe_load(rules_file.read_text()) or {}
    except (OSError, yaml.YAMLError, ValueError):
        return []
    if not isinstance(payload, dict):
        return []

    module = payload.get("module")
    if not isinstance(module, dict):
        return []
    deferred_outputs = module.get("deferred_outputs")
    if deferred_outputs is None:
        deferred_outputs = []
        module["deferred_outputs"] = deferred_outputs
    if not isinstance(deferred_outputs, list):
        return []

    base_anchor = _relative_output_to_anchor(
        relative_output,
        policy_repo_path=policy_repo_path,
    )
    existing_outputs = {
        str(record.get("output") or "").strip()
        for record in deferred_outputs
        if isinstance(record, dict)
    }
    repaired: list[str] = []
    for issue in issues:
        source_gap = _parse_source_coverage_gap_issue(str(issue))
        if source_gap is None:
            continue
        citation, excerpt = source_gap
        if not _is_nonoperative_source_coverage_excerpt(excerpt):
            continue
        symbol = _nonoperative_source_coverage_symbol(excerpt)
        output_path = _source_coverage_output_path(
            base_anchor,
            citation=citation,
        )
        output = f"{output_path}#{symbol}"
        if output in existing_outputs:
            continue
        deferred_outputs.append(
            {
                "output": output,
                "reason": (
                    "Source subparagraph states legislative findings, intent, "
                    "or purpose and does not define an executable RuleSpec "
                    "calculation, eligibility condition, or parameter."
                ),
            }
        )
        existing_outputs.add(output)
        repaired.append(output)

    if not repaired:
        if not deferred_outputs:
            module.pop("deferred_outputs", None)
        return []
    rules_file.write_text(yaml.safe_dump(payload, sort_keys=False, allow_unicode=False))
    return repaired


def _parse_source_coverage_gap_issue(issue: str) -> tuple[str, str] | None:
    match = re.search(
        r"Source sub-paragraph coverage missing:\s*"
        r"(?P<citation>.+?)"
        r"(?:\s+\((?P<quote>['\"])(?P<excerpt>.*?)(?P=quote)\))?"
        r"\s+has no rule",
        issue,
    )
    if match is None:
        return None
    citation = str(match.group("citation") or "").strip()
    excerpt = str(match.group("excerpt") or "").strip()
    if not citation or not excerpt:
        return None
    return citation, excerpt


def _is_nonoperative_source_coverage_excerpt(excerpt: str) -> bool:
    normalized = " ".join(str(excerpt or "").lower().split())
    if not normalized:
        return False
    return bool(
        re.search(
            r"\b("
            r"whereas|"
            r"now,\s*therefore|"
            r"intent of (?:the )?(?:general assembly|legislature|congress)|"
            r"(?:general assembly|legislature|congress) (?:finds|declares)|"
            r"finds and declares|"
            r"purpose of (?:this|the)"
            r")\b",
            normalized,
        )
    )


def _nonoperative_source_coverage_symbol(excerpt: str) -> str:
    normalized = " ".join(str(excerpt or "").lower().split())
    if "intent" in normalized:
        return "legislative_intent"
    if "finds" in normalized or "declares" in normalized:
        return "legislative_findings"
    if "purpose" in normalized:
        return "legislative_purpose"
    return "nonoperative_source"


def _source_coverage_output_path(base_anchor: str, *, citation: str) -> str:
    segments = [
        segment.strip()
        for segment in re.findall(r"\(([A-Za-z0-9.]+)\)", str(citation or ""))
        if segment.strip()
    ]
    if not segments:
        return base_anchor
    anchor_path = base_anchor.rsplit(":", 1)[-1].strip("/")
    anchor_segments = anchor_path.split("/") if anchor_path else []
    if (
        len(anchor_segments) >= len(segments)
        and anchor_segments[-len(segments) :] == segments
    ):
        return base_anchor
    return f"{base_anchor}/{'/'.join(segments)}"


def _source_coverage_deferred_symbol(excerpt: str, *, citation: str) -> str:
    normalized = " ".join(str(excerpt or "").lower().split())
    if "basic food" in normalized:
        if "income eligible" in normalized or "income eligibility" in normalized:
            return "basic_food_income_eligible"
        if "benefit" in normalized or "allotment" in normalized:
            return "basic_food_monthly_benefit"
    if "income eligible" in normalized or "income eligibility" in normalized:
        return "income_eligible"
    if "monthly benefit" in normalized:
        return "monthly_benefit"
    symbol, _label = _infer_deferred_output_symbol_from_summary(excerpt)
    if symbol:
        return symbol
    segments = [
        segment.strip().lower()
        for segment in re.findall(r"\(([A-Za-z0-9.]+)\)", str(citation or ""))
        if segment.strip()
    ]
    if segments:
        return "deferred_" + "_".join(re.sub(r"[^a-z0-9]+", "_", s) for s in segments)
    return "deferred_output"


def _infer_deferred_output_symbol_from_summary(summary: str) -> tuple[str, str]:
    """Infer a stable deferred-output symbol from a simple definition summary."""
    normalized = " ".join(str(summary or "").strip().split())
    if not normalized:
        return "", ""
    match = re.search(r"[“\"]([^”\"]+)[”\"]\s+means\b", normalized)
    if match is None:
        match = re.search(
            r"\b(?:the\s+term\s+)?([A-Za-z][A-Za-z0-9 /,&'-]{1,80}?)\s+means\b",
            normalized,
            flags=re.IGNORECASE,
        )
    if match is None:
        return "", ""
    label = match.group(1).strip(" .,:;\"'“”")
    symbol = re.sub(r"[^0-9A-Za-z]+", "_", label.lower()).strip("_")
    if symbol and symbol[0].isdigit():
        symbol = f"deferred_{symbol}"
    return symbol, label


def _try_repair_generated_unsafe_formula_outputs_for_apply(
    result,
    *,
    output_root: Path,
    policy_repo_path: Path,
    issues: list[str],
) -> list[str]:
    """Defer generated outputs that validation proved use unsafe formulas."""
    seed_rules: set[str] = set()
    issue_reasons: dict[str, list[str]] = defaultdict(list)
    issue_source_values: dict[str, set[str]] = defaultdict(set)
    orphan_source_value_rules: set[str] = set()
    unrelated_same_section_imports: list[str] = []
    for issue in issues:
        issue_text = str(issue)
        flattened_match = _FLATTENED_THRESHOLDED_RATE_ISSUE_PATTERN.search(issue_text)
        if flattened_match:
            rule_name = flattened_match.group(1)
            seed_rules.add(rule_name)
            issue_reasons[rule_name].append("flattened_thresholded_rate")
        base_match = _CROSS_REFERENCE_BASE_MECHANICS_ISSUE_PATTERN.search(issue_text)
        if base_match:
            rule_name = base_match.group(1)
            seed_rules.add(rule_name)
            issue_reasons[rule_name].append("cross_reference_base_mechanics")
        placeholder_match = _CROSS_REFERENCE_PLACEHOLDER_ISSUE_PATTERN.search(
            issue_text
        )
        if placeholder_match:
            rule_name = placeholder_match.group(1)
            seed_rules.add(rule_name)
            issue_reasons[rule_name].append("cross_reference_placeholder")
        numeric_match = _CROSS_REFERENCE_NUMERIC_PLACEHOLDER_ISSUE_PATTERN.search(
            issue_text
        )
        if numeric_match:
            rule_name = numeric_match.group(1)
            seed_rules.add(rule_name)
            issue_reasons[rule_name].append("cross_reference_numeric_placeholder")
        generic_purpose_match = (
            _GENERIC_DEFERRED_PURPOSE_LIMITATION_ISSUE_PATTERN.search(issue_text)
        )
        if generic_purpose_match:
            rule_name = generic_purpose_match.group(1)
            seed_rules.add(rule_name)
            issue_reasons[rule_name].append("generic_deferred_purpose_limitation")
        sibling_match = _SIBLING_RULE_NAME_COLLISION_ISSUE_PATTERN.search(issue_text)
        if sibling_match:
            rule_name = sibling_match.group(1)
            seed_rules.add(rule_name)
            issue_reasons[rule_name].append("sibling_rule_name_collision")
        unused_modifier_match = _UNUSED_SOURCE_MODIFIER_ISSUE_PATTERN.search(issue_text)
        if unused_modifier_match:
            source_value_rule = unused_modifier_match.group("source_value")
            affected_rule_names = re.findall(
                r"`([^`]+)`",
                unused_modifier_match.group("affected"),
            )
            for rule_name in affected_rule_names:
                seed_rules.add(rule_name)
                issue_reasons[rule_name].append("unused_source_modifier")
                issue_source_values[rule_name].add(source_value_rule)
        no_affected_modifier_match = _NO_AFFECTED_SOURCE_MODIFIER_ISSUE_PATTERN.search(
            issue_text
        )
        if no_affected_modifier_match:
            orphan_source_value_rules.add(
                no_affected_modifier_match.group("source_value")
            )
        tax_status_component_match = _TAX_STATUS_COMPONENT_ISSUE_RE.search(issue_text)
        if tax_status_component_match:
            rule_name = tax_status_component_match.group("rule")
            seed_rules.add(rule_name)
            issue_reasons[rule_name].append("tax_status_component_placeholder")
        unrelated_same_section_match = (
            _UNRELATED_SAME_SECTION_TERM_IMPORT_ISSUE_PATTERN.search(issue_text)
        )
        if unrelated_same_section_match:
            unrelated_same_section_imports.append(
                unrelated_same_section_match.group("import")
            )

    try:
        relative_output = _relative_generated_output_path(
            result,
            output_root=output_root,
        )
    except RuntimeError:
        return []

    rules_file = Path(str(getattr(result, "output_file", "") or ""))
    if not rules_file.exists():
        return []
    try:
        payload = yaml.safe_load(rules_file.read_text()) or {}
    except (OSError, yaml.YAMLError, ValueError):
        return []
    if not isinstance(payload, dict):
        return []
    rules = payload.get("rules")
    if not isinstance(rules, list):
        return []

    rules_by_name = {
        str(rule.get("name") or ""): rule
        for rule in rules
        if isinstance(rule, dict) and str(rule.get("name") or "")
    }
    for rule_name in list(seed_rules):
        reasons = set(issue_reasons.get(rule_name, []))
        rule = rules_by_name.get(rule_name)
        if reasons != {"flattened_thresholded_rate"} or not isinstance(rule, dict):
            continue
        if _generated_rule_is_imported_judgment_composition(rule, payload=payload):
            seed_rules.discard(rule_name)
            issue_reasons.pop(rule_name, None)
    unresolved_import_symbols = _unexported_import_symbols_for_missing_inputs(
        rules_file=rules_file,
        policy_repo_path=policy_repo_path,
        issues=issues,
    )
    if unresolved_import_symbols:
        for rule_name, rule in rules_by_name.items():
            identifiers = _generated_rule_formula_identifiers(rule)
            if not identifiers.intersection(unresolved_import_symbols):
                continue
            seed_rules.add(rule_name)
            issue_reasons[rule_name].append("unresolved_import_symbol")
    for import_item in unrelated_same_section_imports:
        imported_symbols = _imported_symbols_for_unrelated_same_section_issue(
            import_item,
            rules_file=rules_file,
            policy_repo_path=policy_repo_path,
        )
        if not imported_symbols:
            continue
        for rule_name, rule in rules_by_name.items():
            if not isinstance(rule, dict):
                continue
            identifiers = _generated_rule_formula_identifiers(rule)
            if not identifiers.intersection(imported_symbols):
                continue
            seed_rules.add(rule_name)
            issue_reasons[rule_name].append("unrelated_same_section_term_import")
    if not seed_rules and not orphan_source_value_rules:
        return []

    base_anchor = _relative_output_to_anchor(
        relative_output,
        policy_repo_path=policy_repo_path,
    )
    module = payload.setdefault("module", {})
    if not isinstance(module, dict):
        return []
    deferred_outputs = module.setdefault("deferred_outputs", [])
    if not isinstance(deferred_outputs, list):
        return []
    existing_outputs = {
        str(record.get("output") or "").strip()
        for record in deferred_outputs
        if isinstance(record, dict)
    }

    if not seed_rules:
        source_value_targets = _source_value_targets_for_generated_rule_names(
            rule_names=orphan_source_value_rules,
            rules_by_name=rules_by_name,
            base_anchor=base_anchor,
        )
        repaired_deferred_outputs = _append_source_values_to_existing_deferred_outputs(
            deferred_outputs=deferred_outputs,
            source_value_targets=source_value_targets,
        )
        if not repaired_deferred_outputs:
            return []
        rules_file.write_text(
            yaml.safe_dump(payload, sort_keys=False, allow_unicode=False)
        )
        return repaired_deferred_outputs

    affected_rules = _expand_affected_generated_rule_dependencies(
        rules_by_name=rules_by_name,
        seed_rules=seed_rules,
    )
    if not affected_rules:
        return []

    deferred_targets: list[str] = []
    for rule_name in sorted(affected_rules):
        rule = rules_by_name.get(rule_name)
        if not isinstance(rule, dict):
            continue
        output = _deferred_output_target_for_generated_rule(
            rule_name=rule_name,
            rule=rule,
            base_anchor=base_anchor,
        )
        if not output:
            continue
        reasons = issue_reasons.get(rule_name) or []
        dependency_reasons = sorted(seed_rules.intersection(affected_rules))
        if not reasons and dependency_reasons:
            reason = (
                "Generated rule depends on an output that validation deferred "
                "because it flattened thresholded, capped, base-limited, or "
                "cross-referenced mechanics, or borrowed an unrelated "
                "same-named section term."
            )
        elif "cross_reference_base_mechanics" in reasons:
            reason = (
                "Generated rule computed the tax on a raw compensation, wage, "
                "remuneration, or payment base even though the source applies "
                "cited base mechanics. This output is deferred until the cited "
                "base, cap, exclusion, or excess outputs can be composed without "
                "multiplying an unadjusted base."
            )
        elif "cross_reference_numeric_placeholder" in reasons:
            reason = (
                "Generated rule kept a local numeric rate, percentage, amount, or "
                "base that the source sets by cross-reference to another legal "
                "section. This output is deferred until the cited numeric "
                "mechanics can be imported or composed without a local placeholder."
            )
        elif "cross_reference_placeholder" in reasons:
            reason = (
                "Generated rule kept a local fact for a cited legal section. This "
                "output is deferred until the cited source can be encoded or "
                "imported without a local cross-reference placeholder."
            )
        elif "generic_deferred_purpose_limitation" in reasons:
            reason = (
                "Generated rule exported a broad amount, base, inclusion, or "
                "exclusion while a source-stated purpose-specific limitation was "
                "deferred. This generic surface is deferred until the affected "
                "purpose-specific outputs can be encoded or split without "
                "applying the non-excepted rule too broadly."
            )
        elif "sibling_rule_name_collision" in reasons:
            reason = (
                "Generated rule used a local name that collides with a sibling "
                "RuleSpec export. This output is deferred until it can be "
                "encoded with a semantic branch-specific name without creating "
                "ambiguous sibling imports."
            )
        elif "unused_source_modifier" in reasons:
            reason = (
                "Generated rule ignored a source-stated substitution, "
                "modification, or limitation parameter. This output is deferred "
                "until the upstream cross-referenced mechanics can be imported "
                "or composed without stranding the modifier."
            )
        elif "tax_status_component_placeholder" in reasons:
            reason = (
                "Generated rule treated a filing-status or marital-status legal "
                "classification as a local fact. This output is deferred until "
                "the upstream status source can be encoded or imported without "
                "inventing local tax-status component inputs."
            )
        elif "unrelated_same_section_term_import" in reasons:
            reason = (
                "Generated rule imported another section's same-named term even "
                "though the current section already defines or defers that term. "
                "This output is deferred until the same-section definition can be "
                "imported or composed without borrowing the unrelated concept."
            )
        elif "unresolved_import_symbol" in reasons:
            reason = (
                "Generated rule depended on an import fragment that the referenced "
                "RuleSpec file does not export. This output is deferred until the "
                "referenced source exports the intended concept or the dependency "
                "can be corrected without inventing a local fact."
            )
        else:
            reason = (
                "Generated rule used a thresholded, capped, base-limited, or "
                "excess-amount imported rate as a flat percentage. This output "
                "is deferred until the cited mechanics can be composed without "
                "flattening the imported rate."
            )
        if output not in existing_outputs:
            deferred_record = {"output": output, "reason": reason}
            source_value_targets = _source_value_targets_for_generated_rule_names(
                rule_names=issue_source_values.get(rule_name, set()),
                rules_by_name=rules_by_name,
                base_anchor=base_anchor,
            )
            if source_value_targets:
                deferred_record["source_values"] = source_value_targets
            deferred_outputs.append(deferred_record)
            existing_outputs.add(output)
        deferred_targets.append(output)

    if orphan_source_value_rules:
        source_value_targets = _source_value_targets_for_generated_rule_names(
            rule_names=orphan_source_value_rules,
            rules_by_name=rules_by_name,
            base_anchor=base_anchor,
        )
        for output in _append_source_values_to_existing_deferred_outputs(
            deferred_outputs=deferred_outputs,
            source_value_targets=source_value_targets,
        ):
            if output not in deferred_targets:
                deferred_targets.append(output)

    if not deferred_targets:
        return []

    payload["rules"] = [
        rule
        for rule in rules
        if not (
            isinstance(rule, dict) and str(rule.get("name") or "") in affected_rules
        )
    ]
    if unresolved_import_symbols:
        _remove_imports_with_fragments(payload, unresolved_import_symbols)
    if not payload["rules"]:
        module.setdefault("status", "deferred")
    rules_file.write_text(yaml.safe_dump(payload, sort_keys=False, allow_unicode=False))

    _remove_generated_test_outputs_for_deferred_rules(
        test_file=_rulespec_test_path(rules_file),
        base_anchor=base_anchor,
        rule_names=affected_rules,
    )
    return deferred_targets


def _append_source_values_to_existing_deferred_outputs(
    *,
    deferred_outputs: list[Any],
    source_value_targets: list[str],
) -> list[str]:
    if not source_value_targets:
        return []

    repaired: list[str] = []
    for record in deferred_outputs:
        if not isinstance(record, dict):
            continue
        output = str(record.get("output") or "").strip()
        if not output:
            continue
        existing_values = record.get("source_values")
        if isinstance(existing_values, list):
            merged_values = [
                str(value).strip()
                for value in existing_values
                if str(value or "").strip()
            ]
        else:
            merged_values = []
        for target in source_value_targets:
            if target not in merged_values:
                merged_values.append(target)
        if merged_values == existing_values:
            continue
        record["source_values"] = merged_values
        repaired.append(output)
    return repaired


def _unexported_import_symbols_for_missing_inputs(
    *,
    rules_file: Path,
    policy_repo_path: Path,
    issues: list[str],
) -> set[str]:
    missing_inputs = _missing_input_names_from_issues(issues)
    if not missing_inputs or not rules_file.exists():
        return set()
    try:
        payload = yaml.safe_load(rules_file.read_text()) or {}
    except (OSError, yaml.YAMLError, ValueError):
        return set()
    if not isinstance(payload, dict):
        return set()
    imports = payload.get("imports")
    if not isinstance(imports, list):
        return set()

    unresolved: set[str] = set()
    for raw_import in imports:
        if not isinstance(raw_import, str) or "#" not in raw_import:
            continue
        fragment = raw_import.rsplit("#", 1)[1].strip()
        if fragment not in missing_inputs:
            continue
        parsed = _parse_same_repo_rulespec_import_ref(
            raw_import,
            repo_path=policy_repo_path,
        )
        if parsed is None or parsed.symbol is None:
            continue
        exported_symbols = _rulespec_exported_rule_names(parsed.path)
        exported_symbols.update(_deferred_output_names(parsed.path))
        if parsed.symbol not in exported_symbols:
            unresolved.add(parsed.symbol)
    return unresolved


def _remove_imports_with_fragments(
    payload: dict[str, object],
    fragments: set[str],
) -> None:
    imports = payload.get("imports")
    if not isinstance(imports, list):
        return
    kept_imports: list[object] = []
    for raw_import in imports:
        if (
            isinstance(raw_import, str)
            and "#" in raw_import
            and raw_import.rsplit("#", 1)[1].strip() in fragments
        ):
            continue
        kept_imports.append(raw_import)
    if kept_imports:
        payload["imports"] = kept_imports
    else:
        payload.pop("imports", None)


def _imported_symbols_for_unrelated_same_section_issue(
    import_item: str,
    *,
    rules_file: Path,
    policy_repo_path: Path,
) -> set[str]:
    if "#" in import_item:
        fragment = import_item.rsplit("#", 1)[1].strip()
        return {fragment} if fragment else set()

    import_file = _import_base_to_repo_file(
        import_item.split("#", 1)[0],
        repo_path=policy_repo_path,
    )
    if import_file is None:
        return set()
    if not import_file.exists():
        with contextlib.suppress(ValueError):
            relative_parent = rules_file.parent.resolve().relative_to(
                policy_repo_path.resolve()
            )
            import_file = policy_repo_path / relative_parent / import_file.name
    if import_file is None or not import_file.exists():
        return set()

    try:
        payload = yaml.safe_load(import_file.read_text()) or {}
    except (OSError, yaml.YAMLError, ValueError):
        return set()
    if not isinstance(payload, dict):
        return set()

    symbols = {
        str(rule.get("name") or "").strip()
        for rule in payload.get("rules", [])
        if isinstance(rule, dict) and str(rule.get("name") or "").strip()
    }
    module = payload.get("module")
    deferred_outputs = (
        module.get("deferred_outputs") if isinstance(module, dict) else None
    )
    if isinstance(deferred_outputs, list):
        for record in deferred_outputs:
            output = None
            if isinstance(record, dict):
                output = record.get("output")
            elif isinstance(record, str):
                output = record
            if not isinstance(output, str):
                continue
            fragment = output.rsplit("#", 1)[1].strip() if "#" in output else output
            if fragment:
                symbols.add(fragment)
    return symbols


def _expand_affected_generated_rule_dependencies(
    *,
    rules_by_name: dict[str, dict[str, Any]],
    seed_rules: set[str],
) -> set[str]:
    affected = {rule for rule in seed_rules if rule in rules_by_name}
    changed = True
    while changed:
        changed = False
        for rule_name, rule in rules_by_name.items():
            if rule_name in affected:
                continue
            identifiers = _generated_rule_formula_identifiers(rule)
            if identifiers.intersection(affected):
                affected.add(rule_name)
                changed = True
    return affected


def _generated_rule_formula_identifiers(rule: dict[str, Any]) -> set[str]:
    identifiers: set[str] = set()
    versions = rule.get("versions")
    if not isinstance(versions, list):
        return identifiers
    for version in versions:
        if not isinstance(version, dict):
            continue
        formula = version.get("formula")
        if isinstance(formula, str):
            identifiers.update(_formula_identifiers(formula))
    return identifiers - _RULESPEC_FORMULA_BUILTINS


def _generated_rule_is_imported_judgment_composition(
    rule: dict[str, Any],
    *,
    payload: dict[str, Any],
) -> bool:
    if str(rule.get("dtype") or "").strip().lower() != "judgment":
        return False
    imported_symbols = _rulespec_import_fragments_from_payload(payload)
    if not imported_symbols:
        return False
    versions = rule.get("versions")
    if not isinstance(versions, list):
        return False
    saw_formula = False
    for version in versions:
        if not isinstance(version, dict):
            continue
        formula = version.get("formula")
        if not isinstance(formula, str) or not formula.strip():
            continue
        saw_formula = True
        formula_without_literals = _formula_without_string_literals(formula)
        if re.search(r"[<>=*/+\-:,\[\]{}]", formula_without_literals):
            return False
        identifiers = _formula_identifiers(formula)
        if not identifiers or identifiers - imported_symbols:
            return False
    return saw_formula


def _rulespec_import_fragments_from_payload(payload: dict[str, Any]) -> set[str]:
    imports = payload.get("imports")
    if not isinstance(imports, list):
        return set()
    fragments: set[str] = set()
    for raw_import in imports:
        if not isinstance(raw_import, str) or "#" not in raw_import:
            continue
        fragment = raw_import.rsplit("#", 1)[1].strip()
        if fragment:
            fragments.add(fragment)
    return fragments


def _deferred_output_target_for_generated_rule(
    *,
    rule_name: str,
    rule: dict[str, Any],
    base_anchor: str,
) -> str:
    source = str(rule.get("source") or "")
    path_suffix = _top_level_source_suffix_from_rule_source(source)
    if path_suffix and base_anchor.endswith(path_suffix):
        path_suffix = ""
    return f"{base_anchor}{path_suffix}#{rule_name}"


def _source_value_targets_for_generated_rule_names(
    *,
    rule_names: set[str],
    rules_by_name: dict[str, dict[str, Any]],
    base_anchor: str,
) -> list[str]:
    targets: list[str] = []
    for rule_name in sorted(rule_names):
        rule = rules_by_name.get(rule_name)
        if not isinstance(rule, dict):
            continue
        target = _deferred_output_target_for_generated_rule(
            rule_name=rule_name,
            rule=rule,
            base_anchor=base_anchor,
        )
        if target and target not in targets:
            targets.append(target)
    return targets


def _top_level_source_suffix_from_rule_source(source: str) -> str:
    match = re.search(
        r"\b[0-9A-Za-z]+\s+USC\s+[0-9A-Za-z.-]+"
        r"(?P<suffix>(?:\([A-Za-z0-9]+\))+)",
        source,
    )
    if match is None:
        citation_matches = list(
            re.finditer(
                r"\b(?:[A-Za-z0-9_.:-]+/)+[A-Za-z0-9_.-]+"
                r"(?P<suffix>(?:\([A-Za-z0-9]+\))+)",
                source,
            )
        )
        match = citation_matches[-1] if citation_matches else None
    if match is None:
        return ""
    parts = re.findall(r"\(([A-Za-z0-9]+)\)", match.group("suffix"))
    if not parts:
        return ""
    return "/" + str(parts[0]).lower()


def _remove_generated_test_outputs_for_deferred_rules(
    *,
    test_file: Path,
    base_anchor: str,
    rule_names: set[str],
) -> list[str]:
    if not test_file.exists():
        return []
    try:
        test_cases = yaml.safe_load(test_file.read_text()) or []
    except (OSError, yaml.YAMLError, ValueError):
        return []
    if not isinstance(test_cases, list):
        return []

    removed_cases: list[str] = []
    repaired_cases: list[Any] = []
    changed = False
    for index, case in enumerate(test_cases):
        if not isinstance(case, dict):
            repaired_cases.append(case)
            continue
        outputs = case.get("output")
        if not isinstance(outputs, dict):
            repaired_cases.append(case)
            continue
        repaired_outputs = {
            key: value
            for key, value in outputs.items()
            if not _test_output_targets_deferred_rule(
                str(key),
                base_anchor=base_anchor,
                rule_names=rule_names,
            )
        }
        if repaired_outputs == outputs:
            repaired_cases.append(case)
            continue
        changed = True
        case_name = str(case.get("name") or f"case[{index}]")
        if repaired_outputs:
            repaired_case = dict(case)
            repaired_case["output"] = repaired_outputs
            repaired_cases.append(repaired_case)
        else:
            removed_cases.append(case_name)

    if not changed and not removed_cases:
        return []
    test_file.write_text(yaml.safe_dump(repaired_cases, sort_keys=False))
    return removed_cases


def _test_output_targets_deferred_rule(
    output_key: str,
    *,
    base_anchor: str,
    rule_names: set[str],
) -> bool:
    if "#" not in output_key:
        return False
    path, fragment = output_key.split("#", 1)
    if not path.startswith(base_anchor):
        return False
    return fragment in rule_names


def _try_repair_generated_unresolved_local_test_outputs_for_apply(
    result,
    *,
    output_root: Path,
    policy_repo_path: Path,
    issues: list[str],
) -> list[str]:
    """Remove generated test expectations for local outputs that no longer exist."""
    output_refs = _unresolved_local_test_output_refs_from_issues(issues)
    if not output_refs:
        return []
    try:
        relative_output = _relative_generated_output_path(
            result,
            output_root=output_root,
        )
    except RuntimeError:
        return []
    target_base = (
        f"{_repo_jurisdiction_prefix(policy_repo_path)}:"
        f"{_relative_rulespec_import_target(relative_output)}"
    )
    local_refs = sorted(
        ref
        for ref in output_refs
        if ref == target_base or ref.startswith(f"{target_base}#")
    )
    if not local_refs:
        return []
    test_file = _rulespec_test_path(Path(str(getattr(result, "output_file", "") or "")))
    return _remove_generated_test_output_refs(
        test_file=test_file,
        output_refs=set(local_refs),
    )


def _try_repair_generated_empty_test_outputs_for_apply(
    result,
    *,
    output_root: Path,
    issues: list[str],
) -> list[str]:
    """Remove placeholder generated test cases with empty output maps."""
    case_names = _empty_test_output_case_names_from_issues(issues)
    if not case_names:
        return []
    try:
        _relative_generated_output_path(result, output_root=output_root)
    except RuntimeError:
        return []

    test_file = _rulespec_test_path(Path(str(getattr(result, "output_file", "") or "")))
    return _remove_generated_empty_output_test_cases(
        test_file=test_file,
        case_names=case_names,
    )


def _try_repair_generated_day_period_test_shorthands_for_apply(
    result,
    *,
    output_root: Path,
    issues: list[str],
) -> list[str]:
    """Convert generated `YYYY-MM-DD` test periods to explicit day mappings."""
    case_periods = _day_period_test_cases_from_issues(issues)
    if not case_periods:
        return []
    try:
        _relative_generated_output_path(result, output_root=output_root)
    except RuntimeError:
        return []

    test_file = _rulespec_test_path(Path(str(getattr(result, "output_file", "") or "")))
    return _rewrite_generated_day_period_test_shorthands(
        test_file=test_file,
        case_periods=case_periods,
    )


def _day_period_test_cases_from_issues(issues: list[str]) -> dict[str, str]:
    case_periods: dict[str, str] = {}
    for issue in issues:
        match = _DAY_PERIOD_TEST_ISSUE_PATTERN.search(str(issue))
        if match is not None:
            case_periods[match.group("case").strip()] = match.group("period")
    return case_periods


def _rewrite_generated_day_period_test_shorthands(
    *,
    test_file: Path,
    case_periods: dict[str, str],
) -> list[str]:
    if not test_file.exists():
        return []
    try:
        test_cases = yaml.safe_load(test_file.read_text()) or []
    except (OSError, yaml.YAMLError, ValueError):
        return []
    if not isinstance(test_cases, list):
        return []

    repaired: list[str] = []
    for index, case in enumerate(test_cases):
        if not isinstance(case, dict):
            continue
        case_name = str(case.get("name") or f"case[{index}]")
        current_period = case.get("period")
        if isinstance(current_period, date):
            current_day = current_period.isoformat()
        else:
            current_day = str(current_period or "").strip()
        if _DAY_PERIOD_VALUE_PATTERN.fullmatch(current_day) is None:
            continue
        reported_day = case_periods.get(case_name)
        if reported_day is not None and current_day != reported_day:
            continue
        case["period"] = {
            "period_kind": "custom",
            "name": "day",
            "start": current_day,
            "end": current_day,
        }
        repaired.append(case_name)

    if not repaired:
        return []
    test_file.write_text(
        yaml.safe_dump(test_cases, sort_keys=False, allow_unicode=False)
    )
    return repaired


def _empty_test_output_case_names_from_issues(issues: list[str]) -> set[str]:
    names: set[str] = set()
    for issue in issues:
        match = _EMPTY_TEST_OUTPUT_ISSUE_PATTERN.search(str(issue))
        if match is not None:
            names.add(match.group("case").strip())
    return names


def _remove_generated_empty_output_test_cases(
    *,
    test_file: Path,
    case_names: set[str],
) -> list[str]:
    if not test_file.exists():
        return []
    try:
        test_cases = yaml.safe_load(test_file.read_text()) or []
    except (OSError, yaml.YAMLError, ValueError):
        return []
    if not isinstance(test_cases, list):
        return []

    removed: list[str] = []
    repaired_cases: list[Any] = []
    for index, case in enumerate(test_cases):
        if not isinstance(case, dict):
            repaired_cases.append(case)
            continue
        case_name = str(case.get("name") or f"case[{index}]")
        if case_name not in case_names:
            repaired_cases.append(case)
            continue
        outputs = case.get("output")
        if isinstance(outputs, dict) and outputs:
            repaired_cases.append(case)
            continue
        removed.append(case_name)

    if not removed:
        return []
    test_file.write_text(
        yaml.safe_dump(repaired_cases, sort_keys=False, allow_unicode=False)
    )
    return removed


def _unresolved_local_test_output_refs_from_issues(issues: list[str]) -> set[str]:
    refs: set[str] = set()
    for issue in issues:
        match = _UNRESOLVED_TEST_OUTPUT_ISSUE_PATTERN.search(str(issue))
        if match is not None:
            refs.add(match.group(1).strip())
    return refs


def _remove_generated_test_output_refs(
    *,
    test_file: Path,
    output_refs: set[str],
) -> list[str]:
    if not test_file.exists():
        return []
    try:
        test_cases = yaml.safe_load(test_file.read_text()) or []
    except (OSError, yaml.YAMLError, ValueError):
        return []
    if not isinstance(test_cases, list):
        return []

    removed: list[str] = []
    repaired_cases: list[Any] = []
    for index, case in enumerate(test_cases):
        if not isinstance(case, dict):
            repaired_cases.append(case)
            continue
        outputs = case.get("output")
        if not isinstance(outputs, dict):
            repaired_cases.append(case)
            continue
        case_name = str(case.get("name") or f"case[{index}]")
        repaired_outputs = {}
        for raw_key, value in outputs.items():
            output_ref = str(raw_key).strip().strip('"').strip("'")
            if output_ref in output_refs:
                removed.append(f"{case_name}:{output_ref}")
                continue
            repaired_outputs[raw_key] = value
        if repaired_outputs:
            repaired_case = dict(case)
            repaired_case["output"] = repaired_outputs
            repaired_cases.append(repaired_case)

    if not removed:
        return []
    test_file.write_text(
        yaml.safe_dump(repaired_cases, sort_keys=False, allow_unicode=False)
    )
    return removed


_PERSON_SCOPE_RATE_BASE_ISSUE_PATTERN = re.compile(
    r"Person-scoped rate base at unit scope: `([^`]+)`"
)
_PERSON_SCOPE_DEFINITION_ISSUE_PATTERN = re.compile(
    r"Person-scoped definition at unit scope: `([^`]+)`"
)
_SOURCE_SCOPE_PERSON_MISMATCH_ISSUE_PATTERN = re.compile(
    r"Source scope mismatch: `([^`]+)` is declared on "
    r"`(?:Household|SnapUnit|TaxUnit|Family|SPMUnit)`, but the embedded "
    r"source states an individual/person/member-scoped"
)
_SOURCE_SCOPE_UNIT_MISMATCH_PERSON_ISSUE_PATTERN = re.compile(
    r"Source scope mismatch: `([^`]+)` is declared on `Person`, but the "
    r"embedded source states (?:a `([^`]+)` unit-scoped|a household/unit-scoped) "
    r"test\."
)
_EMPLOYER_SCOPE_ISSUE_PATTERN = re.compile(
    r"Employer-scoped rule at non-employer scope: `([^`]+)`"
)
_FLATTENED_THRESHOLDED_RATE_ISSUE_PATTERN = re.compile(
    r"Flattened thresholded imported rate: `([^`]+)`"
)
_CROSS_REFERENCE_BASE_MECHANICS_ISSUE_PATTERN = re.compile(
    r"Cross-reference base mechanics omitted: `([^`]+)`"
)
_CROSS_REFERENCE_PLACEHOLDER_ISSUE_PATTERN = re.compile(
    r"(?:Encoded )?[Cc]ross-reference placeholder: `([^`]+)`"
)
_CROSS_REFERENCE_NUMERIC_PLACEHOLDER_ISSUE_PATTERN = re.compile(
    r"Cross-reference numeric placeholder: `([^`]+)`"
)
_GENERIC_DEFERRED_PURPOSE_LIMITATION_ISSUE_PATTERN = re.compile(
    r"Generic output with deferred purpose-specific limitation: `([^`]+)`"
)
_SIBLING_RULE_NAME_COLLISION_ISSUE_PATTERN = re.compile(
    r"Sibling rule name collision: rule `([^`]+)`"
)
_UNUSED_SOURCE_MODIFIER_ISSUE_PATTERN = re.compile(
    r"Source-stated modifier parameter is not used by any numeric derived output: "
    r"`(?P<source_value>[^`]+)`.+?but (?P<affected>.+?) ignores it\.",
)
_NO_AFFECTED_SOURCE_MODIFIER_ISSUE_PATTERN = re.compile(
    r"Source-stated modifier parameter has no affected numeric derived output: "
    r"`(?P<source_value>[^`]+)`"
)
_UNRELATED_SAME_SECTION_TERM_IMPORT_ISSUE_PATTERN = re.compile(
    r"Unrelated same-section term import: `(?P<import>[^`]+)` "
    r"overlaps same-section term `(?P<term>[^`]+)`"
)
_UNRESOLVED_TEST_OUTPUT_ISSUE_PATTERN = re.compile(
    r"Test case `[^`]+` output `([^`]+)` does not resolve"
)
_EMPTY_TEST_OUTPUT_ISSUE_PATTERN = re.compile(
    r"Test case `(?P<case>[^`]+)` output must be a mapping\."
)
_DAY_PERIOD_TEST_ISSUE_PATTERN = re.compile(
    r"Test case `(?P<case>[^`]+)` period invalid: unsupported period shorthand: "
    r"['\"](?P<period>\d{4}-\d{2}-\d{2})['\"]"
)
_DAY_PERIOD_VALUE_PATTERN = re.compile(r"\d{4}-\d{2}-\d{2}")
_SHARED_STATUTORY_RATE_NAME_ISSUE_PATTERN = re.compile(
    r"Shared statutory rate name [^:]+: `([^`]+)`"
)
_ANAPHORIC_SCOPE_OMISSION_ISSUE_PATTERN = re.compile(
    r"Anaphoric scope omitted: `(?P<rule>[^`]+)` uses predicate "
    r"`(?P<identifier>[^`]+)` for proof excerpt `(?P<excerpt>[^`]+)`, "
    r"but the supporting source states `(?P<scope>[^`]+)`\."
)
_INPUT_FIELD_ACCESS_PATTERN = re.compile(
    r"(?<![A-Za-z0-9_])input\.([A-Za-z_][A-Za-z0-9_]*)"
)
_RULESPEC_IDENTIFIER_PATTERN = re.compile(r"\b[A-Za-z_][A-Za-z0-9_]*\b")
_RULESPEC_STRING_LITERAL_RE = r'"(?:\\.|[^"\\])*"|\'(?:\'\'|\\.|[^\'\\])*\''
_RULESPEC_STRING_LITERAL_PATTERN = re.compile(_RULESPEC_STRING_LITERAL_RE)
_RULESPEC_FORMULA_BUILTINS = {
    "abs",
    "all",
    "and",
    "any",
    "ceil",
    "count",
    "count_where",
    "else",
    "false",
    "floor",
    "if",
    "in",
    "max",
    "min",
    "not",
    "or",
    "round",
    "sum",
    "sum_where",
    "true",
}
_UNIT_ENTITY_NAMES = {
    "benefitunit",
    "business",
    "family",
    "filingunit",
    "household",
    "spmunit",
    "taxunit",
}


def _try_repair_generated_input_field_access_for_apply(
    result,
    *,
    output_root: Path,
    issues: list[str],
) -> list[str]:
    """Rewrite generated `input.foo` formula accesses to local fact names."""
    if not any(
        "bare field access in scalar position" in str(issue) for issue in issues
    ):
        return []
    try:
        _relative_generated_output_path(result, output_root=output_root)
    except RuntimeError:
        return []

    rules_file = Path(str(getattr(result, "output_file", "") or ""))
    return _repair_input_field_accesses_in_formulas(rules_file=rules_file)


def _try_repair_generated_anaphoric_scope_for_apply(
    result,
    *,
    output_root: Path,
    issues: list[str],
) -> list[str]:
    """Rename broad generated predicates to preserve same-object scope."""
    repairs = _anaphoric_scope_repairs_from_issues(issues)
    if not repairs:
        return []
    try:
        _relative_generated_output_path(result, output_root=output_root)
    except RuntimeError:
        return []

    rules_file = Path(str(getattr(result, "output_file", "") or ""))
    test_file = _rulespec_test_path(rules_file)
    return _repair_anaphoric_scope_identifiers(
        rules_file=rules_file,
        test_file=test_file,
        repairs=repairs,
    )


def _anaphoric_scope_repairs_from_issues(
    issues: list[str],
) -> list[dict[str, str]]:
    repairs: list[dict[str, str]] = []
    seen_identifiers: set[str] = set()
    for issue in issues:
        match = _ANAPHORIC_SCOPE_OMISSION_ISSUE_PATTERN.search(str(issue))
        if match is None:
            continue
        identifier = match.group("identifier")
        if identifier in seen_identifiers:
            continue
        seen_identifiers.add(identifier)
        scope_fragment = _anaphoric_scope_identifier_fragment(match.group("scope"))
        if not scope_fragment or _identifier_contains_fragment(
            identifier,
            scope_fragment,
        ):
            continue
        repairs.append(
            {
                "rule": match.group("rule"),
                "old": identifier,
                "new": _insert_identifier_scope_fragment(identifier, scope_fragment),
                "excerpt": match.group("excerpt"),
                "scope": match.group("scope"),
            }
        )
    return repairs


def _repair_anaphoric_scope_identifiers(
    *,
    rules_file: Path,
    test_file: Path,
    repairs: list[dict[str, str]],
) -> list[str]:
    if not rules_file.exists():
        return []
    changed: list[str] = []
    for path in (rules_file, test_file):
        if not path.exists():
            continue
        try:
            content = path.read_text()
        except OSError:
            continue
        repaired_content = content
        for repair in repairs:
            repaired_content = _replace_rulespec_identifier(
                repaired_content,
                old=repair["old"],
                new=repair["new"],
            )
        if repaired_content != content:
            path.write_text(repaired_content)

    _extend_anaphoric_scope_proof_excerpts(rules_file=rules_file, repairs=repairs)
    for repair in repairs:
        if _rulespec_file_contains_identifier(rules_file, repair["new"]) or (
            test_file.exists()
            and _rulespec_file_contains_identifier(test_file, repair["new"])
        ):
            changed.append(f"{repair['old']}->{repair['new']}")
    return changed


def _anaphoric_scope_identifier_fragment(scope_phrase: str) -> str:
    fragment = re.sub(r"[^a-z0-9]+", "_", scope_phrase.lower()).strip("_")
    return re.sub(r"_+", "_", fragment)


def _identifier_contains_fragment(identifier: str, fragment: str) -> bool:
    return bool(
        re.search(
            rf"(?:^|_){re.escape(fragment)}(?:_|$)",
            identifier,
            flags=re.IGNORECASE,
        )
    )


def _insert_identifier_scope_fragment(identifier: str, fragment: str) -> str:
    for separator in ("_during_", "_after_", "_before_", "_within_"):
        if separator in identifier:
            prefix, suffix = identifier.split(separator, 1)
            return f"{prefix}_{fragment}{separator}{suffix}"
    return f"{identifier}_{fragment}"


def _replace_rulespec_identifier(content: str, *, old: str, new: str) -> str:
    return re.sub(
        rf"(?<![A-Za-z0-9_]){re.escape(old)}(?![A-Za-z0-9_])",
        new,
        content,
    )


def _rulespec_file_contains_identifier(path: Path, identifier: str) -> bool:
    with contextlib.suppress(OSError):
        return bool(
            re.search(
                rf"(?<![A-Za-z0-9_]){re.escape(identifier)}(?![A-Za-z0-9_])",
                path.read_text(),
            )
        )
    return False


class _YamlExcerptScalarSpan(NamedTuple):
    rule: str
    excerpt: str
    start: int
    end: int


def _extend_anaphoric_scope_proof_excerpts(
    *,
    rules_file: Path,
    repairs: list[dict[str, str]],
) -> None:
    try:
        content = rules_file.read_text()
        payload = yaml.safe_load(content) or {}
    except (OSError, yaml.YAMLError, ValueError):
        return
    if not isinstance(payload, dict):
        raise RuntimeError(
            "Cannot stamp source attestation: generated RuleSpec must be an object"
        )
    source_text = _extract_source_verification_text(content)
    if not source_text:
        return
    rules = payload.get("rules")
    if not isinstance(rules, list):
        return

    excerpt_spans = _yaml_excerpt_scalar_spans(content)
    if not excerpt_spans:
        return
    used_span_indexes: set[int] = set()
    replacements: list[tuple[int, int, str]] = []
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        rule_name = str(rule.get("name") or "").strip()
        metadata = rule.get("metadata")
        proof = metadata.get("proof") if isinstance(metadata, dict) else None
        atoms = proof.get("atoms") if isinstance(proof, dict) else None
        if not isinstance(atoms, list):
            continue
        for atom in atoms:
            if not isinstance(atom, dict):
                continue
            source = atom.get("source")
            if not isinstance(source, dict):
                continue
            excerpt = source.get("excerpt")
            if not isinstance(excerpt, str):
                continue
            for repair in repairs:
                if rule_name != repair["rule"] or excerpt != repair["excerpt"]:
                    continue
                if repair["scope"].lower() in excerpt.lower():
                    continue
                extended = _extend_excerpt_to_anaphoric_scope(
                    source_text=source_text,
                    excerpt=excerpt,
                    scope_phrase=repair["scope"],
                )
                if extended and extended != excerpt:
                    span_index, span = _find_yaml_excerpt_scalar_span(
                        excerpt_spans,
                        rule=rule_name,
                        excerpt=excerpt,
                        used_span_indexes=used_span_indexes,
                    )
                    if span is None:
                        continue
                    used_span_indexes.add(span_index)
                    replacements.append(
                        (
                            span.start,
                            span.end,
                            _render_yaml_excerpt_scalar_like(
                                content[span.start : span.end],
                                extended,
                            ),
                        )
                    )
    if replacements:
        repaired_content = content
        for start, end, replacement in sorted(replacements, reverse=True):
            repaired_content = (
                repaired_content[:start] + replacement + repaired_content[end:]
            )
        rules_file.write_text(repaired_content)


def _yaml_excerpt_scalar_spans(content: str) -> list[_YamlExcerptScalarSpan]:
    try:
        root = yaml.compose(content)
    except yaml.YAMLError:
        return []
    rules_node = _yaml_mapping_value(root, "rules")
    if not isinstance(rules_node, SequenceNode):
        return []

    spans: list[_YamlExcerptScalarSpan] = []
    for rule_node in rules_node.value:
        if not isinstance(rule_node, MappingNode):
            continue
        rule_name = _yaml_scalar_mapping_value(rule_node, "name")
        if not rule_name:
            continue
        metadata_node = _yaml_mapping_value(rule_node, "metadata")
        proof_node = _yaml_mapping_value(metadata_node, "proof")
        atoms_node = _yaml_mapping_value(proof_node, "atoms")
        if not isinstance(atoms_node, SequenceNode):
            continue
        for atom_node in atoms_node.value:
            source_node = _yaml_mapping_value(atom_node, "source")
            excerpt_node = _yaml_mapping_value(source_node, "excerpt")
            if not isinstance(excerpt_node, ScalarNode):
                continue
            excerpt = excerpt_node.value
            if not isinstance(excerpt, str):
                continue
            spans.append(
                _YamlExcerptScalarSpan(
                    rule=rule_name,
                    excerpt=excerpt,
                    start=excerpt_node.start_mark.index,
                    end=excerpt_node.end_mark.index,
                )
            )
    return spans


def _yaml_mapping_value(node: object, key: str) -> object | None:
    if not isinstance(node, MappingNode):
        return None
    for key_node, value_node in node.value:
        if isinstance(key_node, ScalarNode) and key_node.value == key:
            return value_node
    return None


def _yaml_scalar_mapping_value(node: object, key: str) -> str:
    value_node = _yaml_mapping_value(node, key)
    if isinstance(value_node, ScalarNode) and isinstance(value_node.value, str):
        return value_node.value
    return ""


def _find_yaml_excerpt_scalar_span(
    spans: list[_YamlExcerptScalarSpan],
    *,
    rule: str,
    excerpt: str,
    used_span_indexes: set[int],
) -> tuple[int, _YamlExcerptScalarSpan | None]:
    for index, span in enumerate(spans):
        if index in used_span_indexes:
            continue
        if span.rule == rule and span.excerpt == excerpt:
            return index, span
    return -1, None


def _render_yaml_excerpt_scalar_like(original_scalar: str, value: str) -> str:
    stripped = original_scalar.lstrip()
    if stripped.startswith('"'):
        return f'"{_yaml_double_quoted_scalar_text(value)}"'
    if stripped.startswith("'"):
        return f"'{_yaml_single_quoted_scalar_text(value)}'"
    if stripped.startswith("|") or stripped.startswith(">"):
        return _render_yaml_block_scalar_like(original_scalar, value)
    return f'"{_yaml_double_quoted_scalar_text(value)}"'


def _render_yaml_block_scalar_like(original_scalar: str, value: str) -> str:
    lines = original_scalar.splitlines(keepends=True)
    if not lines:
        return f'"{_yaml_double_quoted_scalar_text(value)}"'
    header = lines[0].rstrip("\r\n")
    indent = ""
    for line in lines[1:]:
        if line.strip():
            indent = line[: len(line) - len(line.lstrip())]
            break
    if not indent:
        indent = "  "
    rendered_lines = value.splitlines() or [""]
    rendered = header + "\n" + "\n".join(f"{indent}{line}" for line in rendered_lines)
    if original_scalar.endswith(("\n", "\r\n")):
        rendered += "\n"
    return rendered


def _yaml_double_quoted_scalar_text(value: str) -> str:
    return value.replace("\\", "\\\\").replace('"', '\\"').replace("\n", "\\n")


def _yaml_single_quoted_scalar_text(value: str) -> str:
    return value.replace("'", "''")


def _extend_excerpt_to_anaphoric_scope(
    *,
    source_text: str,
    excerpt: str,
    scope_phrase: str,
) -> str | None:
    source = re.sub(r"\s+", " ", source_text).strip()
    excerpt_text = re.sub(r"\s+", " ", excerpt).strip()
    scope_text = re.sub(r"\s+", " ", scope_phrase).strip()
    if not source or not excerpt_text or not scope_text:
        return None
    match = re.search(re.escape(excerpt_text), source, flags=re.IGNORECASE)
    if match is None:
        return None
    tail = source[match.end() : match.end() + 240]
    scope_match = re.search(re.escape(scope_text), tail, flags=re.IGNORECASE)
    if scope_match is None:
        return None
    sentence_tail = tail[: scope_match.end()]
    if _anaphoric_repair_tail_crosses_boundary(sentence_tail):
        return None
    return source[match.start() : match.end() + scope_match.end()].strip()


def _anaphoric_repair_tail_crosses_boundary(value: str) -> bool:
    boundary_indexes = [
        index for marker in (".", ";", "\n") if (index := value.find(marker)) != -1
    ]
    return bool(boundary_indexes and min(boundary_indexes) < len(value) - 1)


def _repair_input_field_accesses_in_formulas(*, rules_file: Path) -> list[str]:
    if not rules_file.exists():
        return []
    try:
        payload = yaml.safe_load(rules_file.read_text()) or {}
    except (OSError, yaml.YAMLError, ValueError):
        return []
    if not isinstance(payload, dict):
        return []
    rules = payload.get("rules")
    if not isinstance(rules, list):
        return []

    repaired: list[str] = []
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        rule_name = str(rule.get("name") or "<unknown>").strip() or "<unknown>"
        versions = rule.get("versions")
        if not isinstance(versions, list):
            continue
        for version_index, version in enumerate(versions):
            if not isinstance(version, dict):
                continue
            formula = version.get("formula")
            if not isinstance(formula, str):
                continue
            new_formula = _INPUT_FIELD_ACCESS_PATTERN.sub(r"\1", formula)
            if new_formula == formula:
                continue
            version["formula"] = new_formula
            repaired.append(f"{rule_name}:versions[{version_index}].formula")

    if not repaired:
        return []

    rules_file.write_text(yaml.safe_dump(payload, sort_keys=False, allow_unicode=False))
    return repaired


def _try_repair_generated_source_table_band_scalars_for_apply(
    result,
    *,
    output_root: Path,
    issues: list[str],
) -> list[str]:
    """Normalize generated structural table bounds and remove public scalars."""
    if not any(
        "Source table row/band scalar parameters" in str(issue) for issue in issues
    ):
        return []
    try:
        _relative_generated_output_path(result, output_root=output_root)
    except RuntimeError:
        return []

    rules_file = Path(str(getattr(result, "output_file", "") or ""))
    if not rules_file.exists():
        return []

    try:
        original_content = rules_file.read_text()
    except OSError:
        return []

    repaired_content, repaired_rules = repair_source_table_band_scalar_parameters(
        original_content
    )
    if repaired_content == original_content:
        return []

    rules_file.write_text(repaired_content)
    return repaired_rules


def _try_repair_generated_indexed_parameter_values_for_apply(
    result,
    *,
    output_root: Path,
    issues: list[str],
) -> list[str]:
    """Convert generated indexed parameter value tables into derived formulas."""
    try:
        _relative_generated_output_path(result, output_root=output_root)
    except RuntimeError:
        return []

    rules_file = Path(str(getattr(result, "output_file", "") or ""))
    test_file = _rulespec_test_path(rules_file)
    if any(
        "floating point" in str(issue) and "expected i64" in str(issue)
        for issue in issues
    ):
        repaired_float_keys = _repair_float_keyed_indexed_parameter_values(
            rules_file,
            test_file,
        )
        if repaired_float_keys:
            return repaired_float_keys

    if not any("has no formula version" in str(issue) for issue in issues):
        return []
    repaired_top_level_values = _normalize_top_level_parameter_values_to_versions(
        rules_file
    )
    if repaired_top_level_values:
        return repaired_top_level_values
    return _convert_indexed_parameter_values_to_derived_formulas(rules_file, test_file)


def _try_repair_generated_indexed_parameter_lookups_for_apply(
    result,
    *,
    output_root: Path,
    policy_repo_path: Path | None = None,
    issues: list[str],
) -> list[str]:
    """Rewrite bare generated references to indexed parameter tables."""
    try:
        _relative_generated_output_path(result, output_root=output_root)
    except RuntimeError:
        return []

    rules_file = Path(str(getattr(result, "output_file", "") or ""))
    return _repair_bare_indexed_parameter_references(
        rules_file,
        policy_repo_path=policy_repo_path,
    )


def _try_repair_generated_unreferenced_percent_label_parameters_for_apply(
    result,
    *,
    output_root: Path,
    policy_repo_path: Path | None = None,
    issues: list[str],
) -> list[str]:
    ungrounded_values = _ungrounded_numeric_values_from_issues(issues)
    if not ungrounded_values:
        return []
    try:
        relative_output = _relative_generated_output_path(
            result,
            output_root=output_root,
        )
    except RuntimeError:
        return []

    rules_file = Path(str(getattr(result, "output_file", "") or ""))
    if not rules_file.exists():
        return []
    try:
        payload = yaml.safe_load(rules_file.read_text()) or {}
    except (OSError, yaml.YAMLError, ValueError):
        return []
    if not isinstance(payload, dict):
        return []
    rules = payload.get("rules")
    if not isinstance(rules, list):
        return []

    referenced_names = _referenced_local_rule_names(rules)
    retained_rules: list[object] = []
    removed: list[str] = []
    for rule in rules:
        if not isinstance(rule, dict):
            retained_rules.append(rule)
            continue
        name = str(rule.get("name") or "").strip()
        if (
            not name
            or name in referenced_names
            or not _is_unreferenced_percent_label_parameter(
                rule,
                ungrounded_values=ungrounded_values,
            )
        ):
            retained_rules.append(rule)
            continue
        removed.append(name)

    if not removed:
        return []
    payload["rules"] = retained_rules
    rules_file.write_text(yaml.safe_dump(payload, sort_keys=False, allow_unicode=False))

    test_file = _rulespec_test_path(rules_file)
    target_anchor = _relative_output_to_anchor(
        relative_output,
        policy_repo_path=policy_repo_path,
    )
    _remove_companion_outputs_for_removed_rules(
        test_file,
        target_anchor=target_anchor,
        removed_names=set(removed),
    )
    return removed


def _ungrounded_numeric_values_from_issues(issues: list[str]) -> set[float]:
    values: set[float] = set()
    pattern = re.compile(
        r"Ungrounded generated numeric literal:\s+"
        r"(?P<raw>-?[\d,]+(?:\.\d+)?)"
        r"(?:\s+\((?P<normalized>-?[\d,]+(?:\.\d+)?)\))?"
    )
    for issue in issues:
        match = pattern.search(str(issue))
        if match is None:
            continue
        raw_value = match.group("normalized") or match.group("raw")
        with contextlib.suppress(ValueError):
            values.add(float(raw_value.replace(",", "")))
    return values


def _referenced_local_rule_names(rules: list[Any]) -> set[str]:
    referenced: set[str] = set()
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        for formula in _rulespec_rule_formula_texts_for_generated_repair(rule):
            referenced.update(_formula_identifiers(formula))
        metadata = rule.get("metadata")
        proof = metadata.get("proof") if isinstance(metadata, dict) else None
        atoms = proof.get("atoms") if isinstance(proof, dict) else None
        if not isinstance(atoms, list):
            continue
        for atom in atoms:
            if not isinstance(atom, dict):
                continue
            import_payload = atom.get("import")
            if not isinstance(import_payload, dict):
                continue
            output = str(import_payload.get("output") or "").strip()
            if output:
                referenced.add(output)
                continue
            target = str(import_payload.get("target") or "").strip()
            if "#" in target:
                referenced.add(target.rsplit("#", 1)[1].strip())
    return referenced


def _rulespec_rule_formula_texts_for_generated_repair(
    rule: dict[str, Any],
) -> list[str]:
    formulas: list[str] = []
    versions = rule.get("versions")
    if not isinstance(versions, list):
        return formulas
    for version in versions:
        if not isinstance(version, dict):
            continue
        formula = version.get("formula")
        if isinstance(formula, str) and formula.strip():
            formulas.append(formula)
    return formulas


def _is_unreferenced_percent_label_parameter(
    rule: dict[str, Any],
    *,
    ungrounded_values: set[float],
) -> bool:
    if str(rule.get("kind") or "").strip().lower() != "parameter":
        return False
    value = _single_numeric_formula_value(rule)
    if value is None or not any(
        math.isclose(value, item) for item in ungrounded_values
    ):
        return False
    if value <= 0:
        return False
    percent = value * 100
    if not math.isfinite(percent) or percent <= 0:
        return False
    source_text = _generated_rule_source_context(rule)
    if not source_text:
        return False
    percent_text = ("%f" % percent).rstrip("0").rstrip(".")
    return bool(
        re.search(
            rf"(?<![\d.]){re.escape(percent_text)}\s*(?:%(?!\w)|percent\b)",
            source_text,
            flags=re.IGNORECASE,
        )
    )


def _single_numeric_formula_value(rule: dict[str, Any]) -> float | None:
    versions = rule.get("versions")
    if not isinstance(versions, list) or len(versions) != 1:
        return None
    version = versions[0]
    if not isinstance(version, dict):
        return None
    formula = version.get("formula")
    if isinstance(formula, bool):
        return None
    if isinstance(formula, int | float):
        return float(formula)
    if isinstance(formula, str):
        normalized = formula.strip().replace(",", "")
        if re.fullmatch(r"-?\d+(?:\.\d+)?", normalized):
            return float(normalized)
    return None


def _generated_rule_source_context(rule: dict[str, Any]) -> str:
    parts: list[str] = []
    source = rule.get("source")
    if isinstance(source, str):
        parts.append(source)
    metadata = rule.get("metadata")
    proof = metadata.get("proof") if isinstance(metadata, dict) else None
    atoms = proof.get("atoms") if isinstance(proof, dict) else None
    if isinstance(atoms, list):
        for atom in atoms:
            if not isinstance(atom, dict):
                continue
            source_payload = atom.get("source")
            if not isinstance(source_payload, dict):
                continue
            excerpt = source_payload.get("excerpt")
            if isinstance(excerpt, str):
                parts.append(excerpt)
    return "\n".join(parts)


def _remove_companion_outputs_for_removed_rules(
    test_file: Path,
    *,
    target_anchor: str,
    removed_names: set[str],
) -> None:
    if not removed_names or not test_file.exists():
        return
    try:
        cases = yaml.safe_load(test_file.read_text()) or []
    except (OSError, yaml.YAMLError, ValueError):
        return
    if not isinstance(cases, list):
        return
    changed = False
    retained_cases: list[object] = []
    for case in cases:
        if not isinstance(case, dict):
            retained_cases.append(case)
            continue
        outputs = case.get("output")
        if not isinstance(outputs, dict):
            retained_cases.append(case)
            continue
        retained_outputs = {
            key: value
            for key, value in outputs.items()
            if not _test_output_targets_removed_rule(
                key,
                target_anchor=target_anchor,
                removed_names=removed_names,
            )
        }
        if len(retained_outputs) != len(outputs):
            changed = True
            if retained_outputs:
                case["output"] = retained_outputs
                retained_cases.append(case)
            continue
        retained_cases.append(case)
    if changed:
        test_file.write_text(
            yaml.safe_dump(retained_cases, sort_keys=False, allow_unicode=False)
        )


def _test_output_targets_removed_rule(
    key: object,
    *,
    target_anchor: str,
    removed_names: set[str],
) -> bool:
    key_text = str(key).strip()
    if "#" in key_text:
        base, fragment = key_text.split("#", 1)
        return base.strip() == target_anchor and fragment.strip() in removed_names
    return key_text in removed_names


def _try_repair_generated_half_unit_add_person_formulas_for_apply(
    result,
    *,
    output_root: Path,
    issues: list[str],
) -> list[str]:
    """Repair generated formulas that apply per-person add-ons per half unit."""
    if not any(
        "expected integer" in str(issue) and "got decimal" in str(issue)
        for issue in issues
    ):
        return []
    try:
        _relative_generated_output_path(result, output_root=output_root)
    except RuntimeError:
        return []

    rules_file = Path(str(getattr(result, "output_file", "") or ""))
    return _repair_half_unit_add_person_formulas(rules_file)


def _repair_half_unit_add_person_formulas(rules_file: Path) -> list[str]:
    if not rules_file.exists():
        return []
    try:
        payload = yaml.safe_load(rules_file.read_text()) or {}
    except (OSError, yaml.YAMLError, ValueError):
        return []
    if not isinstance(payload, dict):
        return []
    rules = payload.get("rules")
    if not isinstance(rules, list):
        return []

    repaired: list[str] = []
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        versions = rule.get("versions")
        if not isinstance(versions, list):
            continue
        rule_repaired = False
        for version in versions:
            if not isinstance(version, dict):
                continue
            formula = version.get("formula")
            if not isinstance(formula, str):
                continue
            updated = _repair_half_unit_add_person_formula_text(formula)
            if updated != formula:
                version["formula"] = updated
                rule_repaired = True
        if rule_repaired:
            repaired.append(str(rule.get("name") or ""))

    repaired = list(dict.fromkeys(name for name in repaired if name))
    if repaired:
        rules_file.write_text(
            yaml.safe_dump(payload, sort_keys=False, allow_unicode=False)
        )
    return repaired


def _repair_half_unit_add_person_formula_text(formula: str) -> str:
    half_unit_delta = (
        r"filing_unit_size_half_units\s*-\s*"
        r"\(\s*maximum_listed_filing_unit_half_units\s*-\s*1\s*\)"
    )
    pattern = re.compile(
        rf"\(\(\s*(?P<delta>{half_unit_delta})\s*\)\s*\*\s*"
        rf"(?P<amount>[A-Za-z_][A-Za-z0-9_]*)\s*\)"
    )

    def replace(match: re.Match[str]) -> str:
        delta = re.sub(r"\s+", " ", match.group("delta")).strip()
        amount = match.group("amount")
        return f"((({delta}) / 2) * {amount})"

    return pattern.sub(replace, formula)


def _repair_bare_indexed_parameter_references(
    rules_file: Path,
    *,
    policy_repo_path: Path | None = None,
) -> list[str]:
    if not rules_file.exists():
        return []
    try:
        payload = yaml.safe_load(rules_file.read_text()) or {}
    except (OSError, yaml.YAMLError, ValueError):
        return []
    if not isinstance(payload, dict):
        return []
    rules = payload.get("rules")
    if not isinstance(rules, list):
        return []

    indexed_parameters = _indexed_parameter_reference_selectors_from_payload(payload)
    if policy_repo_path is not None:
        indexed_parameters.update(
            _imported_indexed_parameter_reference_selectors(
                payload,
                policy_repo_path=policy_repo_path,
            )
        )
    if not indexed_parameters:
        return []

    repaired: list[str] = []
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        if str(rule.get("kind") or "").strip().lower() != "derived":
            continue
        versions = rule.get("versions")
        if not isinstance(versions, list):
            continue
        rule_name = str(rule.get("name") or "").strip()
        repaired_rule = False
        for version in versions:
            if not isinstance(version, dict):
                continue
            formula = version.get("formula")
            if not isinstance(formula, str):
                continue
            updated = formula
            for parameter_name, index_name in indexed_parameters.items():
                updated = _rewrite_bare_indexed_parameter_reference(
                    updated,
                    parameter_name=parameter_name,
                    index_name=index_name,
                )
            if updated != formula:
                version["formula"] = updated
                repaired_rule = True
        if repaired_rule:
            repaired.append(rule_name or "<unnamed>")

    if repaired:
        rules_file.write_text(yaml.safe_dump(payload, sort_keys=False))
    return repaired


def _indexed_parameter_reference_selectors_from_payload(
    payload: dict[str, object],
) -> dict[str, str]:
    rules = payload.get("rules")
    if not isinstance(rules, list):
        return {}

    indexed_parameters: dict[str, str] = {}
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        if str(rule.get("kind") or "").strip().lower() != "parameter":
            continue
        name = str(rule.get("name") or "").strip()
        index_name = _single_parameter_index_name(rule)
        if not name or not index_name:
            continue
        versions = rule.get("versions")
        if not isinstance(versions, list) or not any(
            isinstance(version, dict) and isinstance(version.get("values"), dict)
            for version in versions
        ):
            continue
        indexed_parameters[name] = index_name
    return indexed_parameters


def _imported_indexed_parameter_reference_selectors(
    payload: dict[str, object],
    *,
    policy_repo_path: Path,
) -> dict[str, str]:
    imports = payload.get("imports")
    if not isinstance(imports, list):
        return {}

    indexed_parameters: dict[str, str] = {}
    for raw_import in imports:
        if not isinstance(raw_import, str) or "#" not in raw_import:
            continue
        imported_name = raw_import.rsplit("#", 1)[1].strip()
        if not re.fullmatch(r"[A-Za-z_][A-Za-z0-9_]*", imported_name):
            continue
        resolved = _same_repo_import_base_and_file(
            raw_import,
            repo_path=policy_repo_path,
        )
        if resolved is None:
            continue
        _, import_file = resolved
        try:
            imported_payload = yaml.safe_load(import_file.read_text()) or {}
        except (OSError, yaml.YAMLError, ValueError):
            continue
        if not isinstance(imported_payload, dict):
            continue
        imported_selectors = _indexed_parameter_reference_selectors_from_payload(
            imported_payload
        )
        index_name = imported_selectors.get(imported_name)
        if index_name:
            indexed_parameters[imported_name] = index_name
    return indexed_parameters


def _rewrite_bare_indexed_parameter_reference(
    formula: str,
    *,
    parameter_name: str,
    index_name: str,
) -> str:
    pattern = re.compile(
        rf"(?<![A-Za-z0-9_#.\]])\b{re.escape(parameter_name)}\b"
        rf"(?!\s*\[)(?![A-Za-z0-9_])"
    )
    return pattern.sub(f"{parameter_name}[{index_name}]", formula)


def _normalize_top_level_parameter_values_to_versions(rules_file: Path) -> list[str]:
    if not rules_file.exists():
        return []
    try:
        payload = yaml.safe_load(rules_file.read_text()) or {}
    except (OSError, yaml.YAMLError, ValueError):
        return []
    if not isinstance(payload, dict):
        return []
    rules = payload.get("rules")
    if not isinstance(rules, list):
        return []

    repaired: list[str] = []
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        if str(rule.get("kind") or "").strip().lower() != "parameter":
            continue
        if "versions" in rule:
            continue
        values = rule.get("values")
        if not isinstance(values, dict) or not values:
            continue

        versions: list[dict[str, object]] = []
        version_kind: str | None = None
        for effective_key, value in values.items():
            effective_from = _effective_from_from_top_level_values_key(effective_key)
            if effective_from is None:
                versions = []
                break
            if isinstance(value, dict):
                if version_kind not in (None, "values"):
                    versions = []
                    break
                version_kind = "values"
                versions.append(
                    {
                        "effective_from": effective_from,
                        "values": value,
                    }
                )
                continue
            formula = _formula_text_from_top_level_parameter_value(value)
            if formula is None:
                versions = []
                break
            if version_kind not in (None, "formula"):
                versions = []
                break
            version_kind = "formula"
            versions.append(
                {
                    "effective_from": effective_from,
                    "formula": formula,
                }
            )

        if not versions or version_kind is None:
            continue
        rule.pop("values", None)
        rule["versions"] = versions
        _retarget_top_level_values_proof_atoms(
            rule,
            "versions[0].values" if version_kind == "values" else "versions[0].formula",
        )
        repaired.append(str(rule.get("name") or ""))

    if not repaired:
        return []
    rules_file.write_text(yaml.safe_dump(payload, sort_keys=False, allow_unicode=False))
    return repaired


def _effective_from_from_top_level_values_key(value: object) -> str | None:
    if isinstance(value, datetime):
        return None
    if isinstance(value, date):
        return value.isoformat()
    if isinstance(value, str) and re.fullmatch(r"\d{4}-\d{2}-\d{2}", value.strip()):
        return value.strip()
    return None


def _formula_text_from_top_level_parameter_value(value: object) -> str | None:
    if isinstance(value, bool):
        return "true" if value else "false"
    if isinstance(value, int | float):
        return str(value)
    if isinstance(value, str) and value.strip():
        return value.strip()
    return None


def _retarget_top_level_values_proof_atoms(
    rule: dict[str, object],
    target_path: str,
) -> None:
    metadata = rule.get("metadata")
    if not isinstance(metadata, dict):
        return
    proof = metadata.get("proof")
    if not isinstance(proof, dict):
        return
    atoms = proof.get("atoms")
    if not isinstance(atoms, list):
        return
    for atom in atoms:
        if not isinstance(atom, dict):
            continue
        path = atom.get("path")
        if isinstance(path, str) and (path == "values" or path.startswith("values[")):
            atom["path"] = target_path


def _convert_indexed_parameter_values_to_derived_formulas(
    rules_file: Path,
    test_file: Path | None = None,
) -> list[str]:
    if not rules_file.exists():
        return []
    try:
        payload = yaml.safe_load(rules_file.read_text()) or {}
    except (OSError, yaml.YAMLError, ValueError):
        return []
    if not isinstance(payload, dict):
        return []
    rules = payload.get("rules")
    if not isinstance(rules, list):
        return []

    rule_by_name = {
        str(rule.get("name") or ""): rule
        for rule in rules
        if isinstance(rule, dict) and rule.get("name")
    }
    repaired: list[str] = []
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        if rule.get("kind") != "parameter" or "versions" in rule:
            continue
        indexed_by = str(rule.get("indexed_by") or "").strip()
        values = rule.get("values")
        if not indexed_by or not isinstance(values, list):
            continue
        index_rule = rule_by_name.get(indexed_by)
        if not isinstance(index_rule, dict):
            continue
        entity = index_rule.get("entity")
        period = index_rule.get("period")
        if not entity or not period:
            continue
        converted = _formula_from_indexed_value_records(
            rule=rule,
            indexed_by=indexed_by,
            values=values,
        )
        if converted is None:
            continue
        effective_from, formula, selectors = converted

        rule["kind"] = "derived"
        rule["entity"] = entity
        rule["period"] = period
        rule.pop("indexed_by", None)
        rule.pop("values", None)
        rule["versions"] = [
            {
                "effective_from": effective_from,
                "formula": formula,
            }
        ]
        _retarget_formula_proof_atoms_to_first_version(rule)
        repaired.append(str(rule.get("name") or ""))
        if test_file is not None and selectors:
            _add_selector_version_test_inputs(
                test_file,
                [(str(rule.get("name") or "indexed_values_rule"), selectors)],
            )

    if not repaired:
        return []
    rules_file.write_text(yaml.safe_dump(payload, sort_keys=False, allow_unicode=False))
    return repaired


def _repair_float_keyed_indexed_parameter_values(
    rules_file: Path,
    test_file: Path | None = None,
) -> list[str]:
    """Remap decimal indexed table keys to integer band ids.

    RuleSpec indexed parameter maps are integer-keyed. LLM generations sometimes
    reuse interval lower bounds (for example 1.33, 1.50, 2.00) as lookup keys.
    Preserve the generated table shape by assigning stable integer row ids and
    rewriting the selector output/tests to use those ids.
    """
    if not rules_file.exists():
        return []
    try:
        payload = yaml.safe_load(rules_file.read_text()) or {}
    except (OSError, yaml.YAMLError, ValueError):
        return []
    if not isinstance(payload, dict):
        return []
    rules = payload.get("rules")
    if not isinstance(rules, list):
        return []

    rule_by_name = {
        str(rule.get("name") or ""): rule
        for rule in rules
        if isinstance(rule, dict) and rule.get("name")
    }
    indexed_rules_by_selector: dict[str, list[dict[str, object]]] = {}
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        if str(rule.get("kind") or "").strip().lower() != "parameter":
            continue
        indexed_by = str(rule.get("indexed_by") or "").strip()
        if not indexed_by:
            continue
        if not _rule_has_non_integer_versioned_value_key(rule):
            continue
        indexed_rules_by_selector.setdefault(indexed_by, []).append(rule)

    repaired: list[str] = []
    selector_key_maps: dict[str, dict[float, int]] = {}
    for indexed_by, parameter_rules in indexed_rules_by_selector.items():
        key_map = _integer_band_ids_for_parameter_rules(parameter_rules)
        if not key_map:
            continue
        index_rule = rule_by_name.get(indexed_by)
        table_names = [
            str(rule.get("name") or "").strip()
            for rule in parameter_rules
            if str(rule.get("name") or "").strip()
        ]
        created_selector = False
        if not isinstance(index_rule, dict):
            selector_name = _missing_float_key_selector_name(indexed_by, rule_by_name)
            index_rule = _build_float_key_selector_rule(
                selector_name=selector_name,
                source_index_name=indexed_by,
                key_map=key_map,
                parameter_rules=parameter_rules,
                rules=rules,
            )
            if index_rule is None:
                continue
            first_index = min(rules.index(rule) for rule in parameter_rules)
            rules.insert(first_index, index_rule)
            rule_by_name[selector_name] = index_rule
            target_indexed_by = selector_name
            created_selector = True
        else:
            target_indexed_by = indexed_by
        changed = False
        if index_rule.get("dtype") != "Integer":
            index_rule["dtype"] = "Integer"
            changed = True
        if not created_selector and _rewrite_selector_rule_float_returns(
            index_rule, key_map
        ):
            changed = True
        for parameter_rule in parameter_rules:
            if parameter_rule.get("indexed_by") != target_indexed_by:
                parameter_rule["indexed_by"] = target_indexed_by
                changed = True
            if _remap_versioned_values_to_integer_keys(parameter_rule, key_map):
                changed = True
                repaired.append(str(parameter_rule.get("name") or ""))
        if _rewrite_indexed_parameter_lookup_keys(
            rules,
            table_names=table_names,
            old_indexed_by=indexed_by,
            new_indexed_by=target_indexed_by,
            key_map=key_map,
        ):
            changed = True
        if changed:
            repaired.append(target_indexed_by)
            selector_key_maps[target_indexed_by] = key_map

    repaired = list(dict.fromkeys(name for name in repaired if name))
    if not repaired:
        return []
    rules_file.write_text(yaml.safe_dump(payload, sort_keys=False, allow_unicode=False))
    if test_file is not None and selector_key_maps:
        _repair_float_keyed_indexed_parameter_test_outputs(test_file, selector_key_maps)
    return repaired


def _missing_float_key_selector_name(
    indexed_by: str,
    rule_by_name: dict[str, dict[str, object]],
) -> str:
    base = f"{indexed_by}_band"
    if base not in rule_by_name:
        return base
    ordinal = 2
    while f"{base}_{ordinal}" in rule_by_name:
        ordinal += 1
    return f"{base}_{ordinal}"


def _build_float_key_selector_rule(
    *,
    selector_name: str,
    source_index_name: str,
    key_map: dict[float, int],
    parameter_rules: list[dict[str, object]],
    rules: list[object],
) -> dict[str, object] | None:
    if not key_map:
        return None
    entity, period = _infer_float_key_selector_scope(
        table_names=[
            str(rule.get("name") or "").strip()
            for rule in parameter_rules
            if str(rule.get("name") or "").strip()
        ],
        rules=rules,
    )
    if not entity or not period:
        return None
    effective_from = _earliest_parameter_effective_from(parameter_rules)
    if not effective_from:
        return None
    source = _first_rule_source(parameter_rules)
    formula = _exact_key_selector_formula(source_index_name, key_map)
    if not formula:
        return None
    selector: dict[str, object] = {
        "name": selector_name,
        "kind": "derived",
        "entity": entity,
        "dtype": "Integer",
        "period": period,
        "source": source
        or f"Generated integer row selector for {source_index_name} table labels",
        "versions": [
            {
                "effective_from": effective_from,
                "formula": formula,
            }
        ],
    }
    proof = _first_rule_table_source(parameter_rules)
    if proof is not None:
        selector["metadata"] = {
            "proof": {
                "atoms": [
                    {
                        "path": "versions[0].formula",
                        "kind": "parameter_table",
                        "source": proof,
                    }
                ]
            }
        }
    return selector


def _infer_float_key_selector_scope(
    *,
    table_names: list[str],
    rules: list[object],
) -> tuple[str | None, str | None]:
    if not table_names:
        return None, None
    lookup_patterns = [
        re.compile(rf"\b{re.escape(table_name)}\s*\[") for table_name in table_names
    ]
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        if str(rule.get("kind") or "").strip().lower() not in {
            "derived",
            "derived_relation",
        }:
            continue
        versions = rule.get("versions")
        if not isinstance(versions, list):
            continue
        formulas = [
            str(version.get("formula") or "")
            for version in versions
            if isinstance(version, dict)
        ]
        if not any(
            pattern.search(formula)
            for pattern in lookup_patterns
            for formula in formulas
        ):
            continue
        entity = str(rule.get("entity") or "").strip()
        period = str(rule.get("period") or "").strip()
        if entity and period:
            return entity, period
    return None, None


def _earliest_parameter_effective_from(
    parameter_rules: list[dict[str, object]],
) -> str | None:
    dates: list[str] = []
    for rule in parameter_rules:
        versions = rule.get("versions")
        if not isinstance(versions, list):
            continue
        for version in versions:
            if not isinstance(version, dict):
                continue
            effective_from = str(version.get("effective_from") or "").strip()
            if effective_from:
                dates.append(effective_from)
    return min(dates) if dates else None


def _first_rule_source(parameter_rules: list[dict[str, object]]) -> str | None:
    for rule in parameter_rules:
        source = rule.get("source")
        if isinstance(source, str) and source.strip():
            return source.strip()
    return None


def _first_rule_table_source(
    parameter_rules: list[dict[str, object]],
) -> dict[str, object] | None:
    for rule in parameter_rules:
        metadata = rule.get("metadata")
        if not isinstance(metadata, dict):
            continue
        proof = metadata.get("proof")
        if not isinstance(proof, dict):
            continue
        atoms = proof.get("atoms")
        if not isinstance(atoms, list):
            continue
        for atom in atoms:
            if not isinstance(atom, dict):
                continue
            source = atom.get("source")
            if isinstance(source, dict):
                return copy.deepcopy(source)
    return None


def _exact_key_selector_formula(
    source_index_name: str,
    key_map: dict[float, int],
) -> str | None:
    linear_formula = _linear_integer_band_selector_formula(source_index_name, key_map)
    if linear_formula is not None:
        return linear_formula
    branches = sorted(key_map.items(), key=lambda item: item[0], reverse=True)
    if not branches:
        return None
    formula = "-1"
    for numeric_key, band_id in branches:
        key_literal = _formula_scalar_literal(numeric_key)
        if key_literal is None:
            return None
        formula = f"if {source_index_name} == {key_literal}: {band_id} else: {formula}"
    return formula


def _linear_integer_band_selector_formula(
    source_index_name: str,
    key_map: dict[float, int],
) -> str | None:
    if len(key_map) < 2:
        return None
    try:
        ordered = sorted(
            (Decimal(str(numeric_key)), band_id)
            for numeric_key, band_id in key_map.items()
        )
    except (InvalidOperation, ValueError):
        return None
    band_ids = [band_id for _, band_id in ordered]
    if band_ids != list(range(len(band_ids))):
        return None
    steps = [
        ordered[index + 1][0] - ordered[index][0] for index in range(len(ordered) - 1)
    ]
    if not steps or any(step != steps[0] for step in steps):
        return None
    step = steps[0]
    if step <= 0:
        return None
    multiplier = Decimal(1) / step
    if multiplier != multiplier.to_integral_value():
        return None
    offset = ordered[0][0] * multiplier
    if offset != offset.to_integral_value():
        return None
    multiplier_text = str(int(multiplier))
    offset_int = int(offset)
    formula = f"floor({source_index_name} * {multiplier_text})"
    if offset_int > 0:
        formula = f"{formula} - {offset_int}"
    elif offset_int < 0:
        formula = f"{formula} + {abs(offset_int)}"
    return formula


def _rewrite_indexed_parameter_lookup_keys(
    rules: list[object],
    *,
    table_names: list[str],
    old_indexed_by: str,
    new_indexed_by: str,
    key_map: dict[float, int],
) -> bool:
    if not table_names:
        return False
    scalar_key_map = _scalar_parameter_band_key_map(rules, key_map)
    changed = False
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        versions = rule.get("versions")
        if not isinstance(versions, list):
            continue
        for version in versions:
            if not isinstance(version, dict):
                continue
            formula = version.get("formula")
            if not isinstance(formula, str):
                continue
            updated = formula
            for table_name in table_names:
                updated = _rewrite_single_indexed_parameter_lookup_key(
                    updated,
                    table_name=table_name,
                    old_indexed_by=old_indexed_by,
                    new_indexed_by=new_indexed_by,
                    key_map=key_map,
                    scalar_key_map=scalar_key_map,
                )
            if updated != formula:
                version["formula"] = updated
                changed = True
    return changed


def _scalar_parameter_band_key_map(
    rules: list[object],
    key_map: dict[float, int],
) -> dict[str, int]:
    scalar_map: dict[str, int] = {}
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        if str(rule.get("kind") or "").strip().lower() != "parameter":
            continue
        name = str(rule.get("name") or "").strip()
        versions = rule.get("versions")
        if not name or not isinstance(versions, list) or len(versions) != 1:
            continue
        version = versions[0]
        if not isinstance(version, dict):
            continue
        formula = version.get("formula")
        if not isinstance(formula, str):
            continue
        numeric = _numeric_value_from_yaml(formula)
        replacement = key_map.get(numeric) if math.isfinite(numeric) else None
        if replacement is not None:
            scalar_map[name] = replacement
    return scalar_map


def _rewrite_single_indexed_parameter_lookup_key(
    formula: str,
    *,
    table_name: str,
    old_indexed_by: str,
    new_indexed_by: str,
    key_map: dict[float, int],
    scalar_key_map: dict[str, int],
) -> str:
    pattern = re.compile(
        rf"\b{re.escape(table_name)}\s*\[\s*(?P<expr>[A-Za-z0-9_#.\-]+)\s*\]"
    )

    def replace(match: re.Match[str]) -> str:
        expr = match.group("expr")
        replacement: str | None = None
        if expr == old_indexed_by:
            replacement = new_indexed_by
        elif expr in scalar_key_map:
            replacement = str(scalar_key_map[expr])
        else:
            numeric = _numeric_value_from_yaml(expr)
            mapped = key_map.get(numeric) if math.isfinite(numeric) else None
            if mapped is not None:
                replacement = str(mapped)
        if replacement is None:
            return match.group(0)
        return f"{table_name}[{replacement}]"

    return pattern.sub(replace, formula)


def _rule_has_non_integer_versioned_value_key(rule: dict[str, object]) -> bool:
    versions = rule.get("versions")
    if not isinstance(versions, list):
        return False
    for version in versions:
        if not isinstance(version, dict):
            continue
        values = version.get("values")
        if not isinstance(values, dict):
            continue
        for key in values:
            numeric = _numeric_value_from_yaml(key)
            if math.isfinite(numeric) and (
                not numeric.is_integer() or isinstance(key, float)
            ):
                return True
    return False


def _integer_band_ids_for_parameter_rules(
    parameter_rules: list[dict[str, object]],
) -> dict[float, int]:
    numeric_keys: set[float] = set()
    requires_remap = False
    for rule in parameter_rules:
        versions = rule.get("versions")
        if not isinstance(versions, list):
            continue
        for version in versions:
            if not isinstance(version, dict):
                continue
            values = version.get("values")
            if not isinstance(values, dict):
                continue
            for raw_key in values:
                numeric = _numeric_value_from_yaml(raw_key)
                if math.isfinite(numeric):
                    numeric_keys.add(numeric)
                    if not numeric.is_integer() or isinstance(raw_key, float):
                        requires_remap = True
    if not numeric_keys or not requires_remap:
        return {}
    return {key: ordinal for ordinal, key in enumerate(sorted(numeric_keys))}


def _remap_versioned_values_to_integer_keys(
    rule: dict[str, object],
    key_map: dict[float, int],
) -> bool:
    versions = rule.get("versions")
    if not isinstance(versions, list):
        return False
    changed = False
    for version in versions:
        if not isinstance(version, dict):
            continue
        values = version.get("values")
        if not isinstance(values, dict):
            continue
        remapped: dict[object, object] = {}
        version_changed = False
        for raw_key, raw_value in values.items():
            numeric = _numeric_value_from_yaml(raw_key)
            replacement = key_map.get(numeric) if math.isfinite(numeric) else None
            if replacement is None:
                remapped[raw_key] = raw_value
                continue
            remapped[replacement] = raw_value
            if replacement != raw_key:
                version_changed = True
        if version_changed:
            version["values"] = remapped
            changed = True
    return changed


def _rewrite_selector_rule_float_returns(
    rule: dict[str, object],
    key_map: dict[float, int],
) -> bool:
    versions = rule.get("versions")
    if not isinstance(versions, list):
        return False
    changed = False
    for version in versions:
        if not isinstance(version, dict):
            continue
        formula = version.get("formula")
        if not isinstance(formula, str):
            continue
        updated = _replace_formula_return_literals_with_band_ids(formula, key_map)
        if updated != formula:
            version["formula"] = updated
            changed = True
    return changed


def _replace_formula_return_literals_with_band_ids(
    formula: str,
    key_map: dict[float, int],
) -> str:
    literal_to_band: dict[str, int] = {}
    for numeric_key, band_id in key_map.items():
        for literal in _numeric_literal_variants(numeric_key):
            literal_to_band[literal] = band_id
    if not literal_to_band:
        return formula
    literal_pattern = "|".join(
        re.escape(literal) for literal in sorted(literal_to_band, key=len, reverse=True)
    )

    def replace_inline(match: re.Match[str]) -> str:
        value = match.group("value")
        return (
            match.group("prefix") + str(literal_to_band[value]) + match.group("suffix")
        )

    formula = re.sub(
        rf"(?P<prefix>:\s*)(?P<value>{literal_pattern})(?P<suffix>\s+(?:else\b|$)|\s*$)",
        replace_inline,
        formula,
        flags=re.MULTILINE,
    )

    def replace_standalone(match: re.Match[str]) -> str:
        value = match.group("value")
        return match.group("indent") + str(literal_to_band[value]) + match.group("tail")

    return re.sub(
        rf"(?P<indent>^[ \t]+)(?P<value>{literal_pattern})(?P<tail>[ \t]*(?:#.*)?$)",
        replace_standalone,
        formula,
        flags=re.MULTILINE,
    )


def _numeric_literal_variants(value: float) -> set[str]:
    variants = {f"{value:g}", f"{value:.1f}", f"{value:.2f}"}
    if value.is_integer():
        variants.add(str(int(value)))
    return {variant for variant in variants if variant}


def _repair_float_keyed_indexed_parameter_test_outputs(
    test_file: Path,
    selector_key_maps: dict[str, dict[float, int]],
) -> bool:
    if not test_file.exists():
        return False
    try:
        cases = yaml.safe_load(test_file.read_text()) or []
    except (OSError, yaml.YAMLError, ValueError):
        return False
    if not isinstance(cases, list):
        return False
    changed = False
    for case in cases:
        if not isinstance(case, dict):
            continue
        outputs = case.get("output")
        if not isinstance(outputs, dict):
            continue
        for output_ref, output_value in list(outputs.items()):
            output_name = str(output_ref).rsplit("#", 1)[-1]
            key_map = selector_key_maps.get(output_name)
            if not key_map:
                continue
            numeric = _numeric_value_from_yaml(output_value)
            if not math.isfinite(numeric):
                continue
            replacement = key_map.get(numeric)
            if replacement is None or replacement == output_value:
                continue
            outputs[output_ref] = replacement
            changed = True
    if changed:
        test_file.write_text(yaml.safe_dump(cases, sort_keys=False))
    return changed


def _formula_from_indexed_value_records(
    *,
    rule: dict[str, object],
    indexed_by: str,
    values: list[Any],
) -> tuple[str, str, list[dict[str, str]]] | None:
    records: list[tuple[int, date, str, str]] = []
    for ordinal, record in enumerate(values, start=1):
        if not isinstance(record, dict):
            continue
        value_map = record.get("value")
        if not isinstance(value_map, dict):
            continue
        effective_from = str(record.get("effective_from") or "").strip()
        effective_date = _parse_iso_date(effective_from)
        if effective_date is None:
            return None
        record_formula = _formula_from_indexed_value_map(
            indexed_by=indexed_by,
            value_map=value_map,
        )
        if record_formula is None:
            return None
        records.append(
            (
                ordinal,
                effective_date,
                effective_from,
                record_formula,
            )
        )
    if not records:
        return None

    records.sort(key=lambda item: (item[1], item[0]))
    _first_ordinal, _first_date, first_effective_from, formula = records[0]
    selectors: list[dict[str, str]] = []
    for ordinal, _effective_date, effective_from, record_formula in records[1:]:
        predicate = _version_selector_predicate_name(rule, ordinal)
        selectors.append(
            {
                "effective_from": effective_from,
                "predicate": predicate,
                "formula": "",
            }
        )
        formula = f"if {predicate}: ({record_formula}) else: {formula}"

    return first_effective_from, formula, selectors


def _formula_from_indexed_value_map(
    *,
    indexed_by: str,
    value_map: dict[Any, Any],
) -> str | None:
    selected_mapping = value_map

    default = selected_mapping.get(0, selected_mapping.get("0", 0))
    default_literal = _formula_scalar_literal(default)
    default_numeric = _numeric_value_from_yaml(default)
    if default_literal is None or math.isnan(default_numeric):
        return None
    branches: list[tuple[float, str, str]] = []
    for raw_key, raw_value in selected_mapping.items():
        numeric_key = _numeric_value_from_yaml(raw_key)
        numeric_value = _numeric_value_from_yaml(raw_value)
        key_literal = _formula_scalar_literal(raw_key)
        value_literal = _formula_scalar_literal(raw_value)
        if (
            key_literal is None
            or value_literal is None
            or math.isnan(numeric_key)
            or math.isnan(numeric_value)
        ):
            return None
        if numeric_key == 0:
            continue
        if numeric_value == default_numeric:
            continue
        branches.append((numeric_key, key_literal, value_literal))
    if not branches:
        return default_literal

    formula = default_literal
    for _numeric_key, key_literal, value_literal in sorted(
        branches,
        key=lambda item: item[0],
    ):
        formula = f"if {indexed_by} == {key_literal}: {value_literal} else: {formula}"
    return formula


def _numeric_value_from_yaml(value: Any) -> float:
    if isinstance(value, bool):
        return 1.0 if value else 0.0
    try:
        return float(str(value).strip())
    except (TypeError, ValueError):
        return float("nan")


def _formula_scalar_literal(value: Any) -> str | None:
    if isinstance(value, bool):
        return "1" if value else "0"
    if isinstance(value, int):
        return str(value)
    if isinstance(value, float):
        if not math.isfinite(value):
            return None
        return f"{value:g}"
    text = str(value).strip()
    if re.fullmatch(r"[+-]?\d+(?:\.\d+)?", text):
        return text[1:] if text.startswith("+") else text
    return None


def _try_repair_generated_shared_statutory_rate_names_for_apply(
    result,
    *,
    output_root: Path,
    issues: list[str],
) -> list[str]:
    """Rename generated shared statutory rates away from consumer entity names."""
    target_names = _shared_statutory_rate_name_issue_names(issues)
    if not target_names:
        return []
    try:
        relative_output = _relative_generated_output_path(
            result, output_root=output_root
        )
    except RuntimeError:
        return []

    rules_file = Path(str(getattr(result, "output_file", "") or ""))
    return _repair_shared_statutory_rate_names(
        rules_file=rules_file,
        test_file=_rulespec_test_path(rules_file),
        relative_output=relative_output,
        target_names=target_names,
    )


def _shared_statutory_rate_name_issue_names(issues: list[str]) -> list[str]:
    names: list[str] = []
    for issue in issues:
        match = _SHARED_STATUTORY_RATE_NAME_ISSUE_PATTERN.search(str(issue))
        if match is not None:
            names.append(match.group(1))
    return names


def _repair_shared_statutory_rate_names(
    *,
    rules_file: Path,
    test_file: Path | None = None,
    relative_output: Path | None = None,
    target_names: list[str],
) -> list[str]:
    if not rules_file.exists():
        return []
    try:
        payload = yaml.safe_load(rules_file.read_text()) or {}
    except (OSError, yaml.YAMLError, ValueError):
        return []
    if not isinstance(payload, dict):
        return []
    rules = payload.get("rules")
    if not isinstance(rules, list):
        return []

    replacements: dict[str, str] = {}
    targets = set(target_names)
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        name = str(rule.get("name") or "").strip()
        new_name = _neutral_shared_statutory_rate_name(name, rule=rule, payload=payload)
        if name not in targets and not _is_canonicalizable_shared_rate_name(
            name,
            new_name,
            rule=rule,
            payload=payload,
        ):
            continue
        if not new_name or new_name == name or new_name in replacements:
            continue
        rule["name"] = new_name
        replacements[name] = new_name

    if not replacements:
        return []

    content = yaml.safe_dump(payload, sort_keys=False, allow_unicode=False)
    for old, new in replacements.items():
        content = _replace_formula_identifier(content, old=old, new=new)
        content = re.sub(
            rf"(?P<prefix>\bindexed_by:\s*){re.escape(old)}\b",
            rf"\g<prefix>{new}",
            content,
        )
    rules_file.write_text(content)

    if test_file is not None and test_file.exists():
        _repair_shared_statutory_rate_test_refs(
            test_file=test_file,
            relative_output=relative_output,
            replacements=replacements,
        )

    return [f"{old}->{new}" for old, new in replacements.items()]


def _is_canonicalizable_shared_rate_name(
    name: str,
    new_name: str | None,
    *,
    rule: dict[str, object],
    payload: dict[str, object],
) -> bool:
    if not new_name or new_name == name:
        return False
    dtype = str(rule.get("dtype") or "").strip().lower()
    if dtype not in {"rate", "decimal"}:
        return False
    return bool(
        _section_refs_for_rate_name(
            name,
            _shared_statutory_rate_source_text(rule=rule, payload=payload),
        )
    )


def _neutral_shared_statutory_rate_name(
    name: str,
    *,
    rule: dict[str, object],
    payload: dict[str, object],
) -> str | None:
    source_text = _shared_statutory_rate_source_text(rule=rule, payload=payload)
    section_refs = _section_refs_for_rate_name(name, source_text)
    if section_refs:
        prefix = "sections" if len(section_refs) > 1 else "section"
        return (
            "applicable_percentage_for_"
            + prefix
            + "_"
            + "_and_".join(section_refs)
            + _shared_statutory_rate_helper_suffix(name)
        )
    for suffix in (
        "_for_tax_unit",
        "_for_person",
        "_for_employer",
        "_for_household",
        "_for_family",
        "_for_business",
        "_for_corporation",
    ):
        if name.endswith(suffix):
            return name[: -len(suffix)]
    return None


def _shared_statutory_rate_helper_suffix(name: str) -> str:
    for suffix in (
        "_by_average_account_benefits_ratio_band",
        "_by_ratio_band",
        "_by_band",
    ):
        if name.endswith(suffix):
            return suffix
    return ""


def _shared_statutory_rate_source_text(
    *,
    rule: dict[str, object],
    payload: dict[str, object],
) -> str:
    parts: list[str] = []
    metadata = rule.get("metadata")
    if isinstance(metadata, dict):
        proof = metadata.get("proof")
        if isinstance(proof, dict):
            atoms = proof.get("atoms")
            if isinstance(atoms, list):
                for atom in atoms:
                    if not isinstance(atom, dict):
                        continue
                    source = atom.get("source")
                    if not isinstance(source, dict):
                        continue
                    source_text = source.get("source_text") or source.get("excerpt")
                    if isinstance(source_text, str) and source_text.strip():
                        parts.append(source_text.strip())
                    table = source.get("table")
                    if isinstance(table, dict):
                        for key in ("header", "column_key", "column"):
                            value = table.get(key)
                            if isinstance(value, str) and value.strip():
                                parts.append(value.strip())
                    corpus_span = source.get("corpus_span")
                    if isinstance(corpus_span, str) and corpus_span.strip():
                        parts.append(corpus_span.strip())
    module = payload.get("module")
    if isinstance(module, dict):
        summary = module.get("summary")
        if isinstance(summary, str) and summary.strip():
            parts.append(summary.strip())
    return "\n".join(parts)


def _section_refs_for_rate_name(name: str, source_text: str) -> list[str]:
    name_sections = set(re.findall(r"(?<!\d)\d{3,4}(?!\d)", name))
    candidates: list[list[str]] = []
    for match in re.finditer(
        r"\bsections?\s+"
        r"(?P<first>\d{3,4})\((?P<first_subsection>[A-Za-z0-9]+)\)"
        r"(?P<rest>(?:\s*(?:,|and)\s*"
        r"\d{3,4}\([A-Za-z0-9]+\))*)",
        source_text,
        flags=re.IGNORECASE,
    ):
        refs = [
            _format_section_ref(
                match.group("first"),
                match.group("first_subsection"),
            )
        ]
        rest = match.group("rest") or ""
        for section, subsection in re.findall(
            r"(\d{3,4})\(([A-Za-z0-9]+)\)",
            rest,
            flags=re.IGNORECASE,
        ):
            refs.append(_format_section_ref(section, subsection))
        candidates.append(refs)

    for refs in candidates:
        sections = {ref.split("_", 1)[0] for ref in refs}
        if sections and sections <= name_sections:
            return refs
    return []


def _format_section_ref(section: str, subsection: str) -> str:
    return f"{section}_{subsection.lower()}"


def _repair_shared_statutory_rate_test_refs(
    *,
    test_file: Path,
    relative_output: Path | None,
    replacements: dict[str, str],
) -> None:
    if not replacements:
        return
    try:
        payload = yaml.safe_load(test_file.read_text())
    except (OSError, yaml.YAMLError, ValueError):
        return
    if not isinstance(payload, list):
        return
    key_replacements = dict(replacements)
    if relative_output is not None:
        anchor = "us:" + relative_output.with_suffix("").as_posix()
        for old, new in replacements.items():
            key_replacements[f"{anchor}#{old}"] = f"{anchor}#{new}"
    if not _replace_mapping_keys_recursive(payload, key_replacements):
        return
    test_file.write_text(yaml.safe_dump(payload, sort_keys=False, allow_unicode=False))


def _try_repair_generated_employer_scope_for_apply(
    result,
    *,
    output_root: Path,
    issues: list[str],
) -> list[str]:
    """Move generated employer-imposed rules to the Employer entity."""
    target_names = _employer_scope_issue_names(issues)
    if not target_names:
        return []
    try:
        _relative_generated_output_path(result, output_root=output_root)
    except RuntimeError:
        return []

    rules_file = Path(str(getattr(result, "output_file", "") or ""))
    return _repair_employer_scoped_entities(
        rules_file=rules_file,
        target_names=target_names,
    )


def _employer_scope_issue_names(issues: list[str]) -> list[str]:
    names: list[str] = []
    for issue in issues:
        match = _EMPLOYER_SCOPE_ISSUE_PATTERN.search(str(issue))
        if match is not None:
            names.append(match.group(1))
    return names


def _repair_employer_scoped_entities(
    *,
    rules_file: Path,
    target_names: list[str],
) -> list[str]:
    if not rules_file.exists():
        return []
    try:
        payload = yaml.safe_load(rules_file.read_text()) or {}
    except (OSError, yaml.YAMLError, ValueError):
        return []
    if not isinstance(payload, dict):
        return []
    rules = payload.get("rules")
    if not isinstance(rules, list):
        return []

    by_name = {
        str(rule.get("name")).strip(): rule
        for rule in rules
        if isinstance(rule, dict)
        and isinstance(rule.get("name"), str)
        and str(rule.get("name")).strip()
    }
    repaired: list[str] = []
    for target_name in target_names:
        target_rule = by_name.get(target_name)
        if not isinstance(target_rule, dict):
            continue
        if _set_rule_entity_to_employer(target_rule):
            repaired.append(target_name)
        formula = _first_rule_formula(target_rule)
        for identifier in sorted(_formula_identifiers(formula)):
            helper = by_name.get(identifier)
            if not isinstance(helper, dict):
                continue
            if str(helper.get("dtype") or "").strip().lower() != "rate":
                continue
            if _set_rule_entity_to_employer(helper):
                repaired.append(identifier)

    if not repaired:
        return []

    rules_file.write_text(yaml.safe_dump(payload, sort_keys=False, allow_unicode=False))
    return repaired


def _set_rule_entity_to_employer(rule: dict[str, object]) -> bool:
    entity = str(rule.get("entity") or "").strip()
    if entity == "Employer":
        return False
    if entity.replace("_", "").lower() not in {*_UNIT_ENTITY_NAMES, "corporation"}:
        return False
    rule["entity"] = "Employer"
    return True


def _try_repair_generated_person_scoped_rate_base_for_apply(
    result,
    *,
    output_root: Path,
    issues: list[str],
) -> list[str]:
    """Move generated rate-base formulas back to the source-stated person scope."""
    target_names = _person_scoped_rate_base_issue_names(issues)
    if not target_names:
        return []
    try:
        _relative_generated_output_path(result, output_root=output_root)
    except RuntimeError:
        return []

    rules_file = Path(str(getattr(result, "output_file", "") or ""))
    return _repair_person_scoped_rate_base_entities(
        rules_file=rules_file,
        target_names=target_names,
    )


def _person_scoped_rate_base_issue_names(issues: list[str]) -> list[str]:
    names: list[str] = []
    for issue in issues:
        match = _PERSON_SCOPE_RATE_BASE_ISSUE_PATTERN.search(str(issue))
        if match is not None:
            names.append(match.group(1))
    return names


def _repair_person_scoped_rate_base_entities(
    *,
    rules_file: Path,
    target_names: list[str],
) -> list[str]:
    if not rules_file.exists():
        return []
    try:
        payload = yaml.safe_load(rules_file.read_text()) or {}
    except (OSError, yaml.YAMLError, ValueError):
        return []
    if not isinstance(payload, dict):
        return []
    rules = payload.get("rules")
    if not isinstance(rules, list):
        return []

    by_name = {
        str(rule.get("name")).strip(): rule
        for rule in rules
        if isinstance(rule, dict)
        and isinstance(rule.get("name"), str)
        and str(rule.get("name")).strip()
    }
    repaired: list[str] = []
    for target_name in target_names:
        target_rule = by_name.get(target_name)
        if not isinstance(target_rule, dict):
            continue
        if _set_rule_entity_to_person(target_rule):
            repaired.append(target_name)
        formula = _first_rule_formula(target_rule)
        for identifier in sorted(_formula_identifiers(formula)):
            helper = by_name.get(identifier)
            if not isinstance(helper, dict):
                continue
            if str(helper.get("dtype") or "").strip().lower() != "rate":
                continue
            if _set_rule_entity_to_person(helper):
                repaired.append(identifier)

    if not repaired:
        return []

    rules_file.write_text(yaml.safe_dump(payload, sort_keys=False, allow_unicode=False))
    return repaired


def _try_repair_generated_medicaid_magi_income_helpers_for_apply(
    result,
    *,
    output_root: Path,
    issues: list[str],
) -> list[str]:
    """Inline invalid person-scoped Medicaid MAGI household-income helpers."""
    target_names = _medicaid_magi_income_helper_issue_names(issues)
    if not target_names:
        return []
    try:
        _relative_generated_output_path(result, output_root=output_root)
    except RuntimeError:
        return []

    rules_file = Path(str(getattr(result, "output_file", "") or ""))
    test_file = _rulespec_test_path(rules_file)
    return _inline_medicaid_magi_income_helpers(
        rules_file=rules_file,
        test_file=test_file,
        target_names=target_names,
    )


def _medicaid_magi_income_helper_issue_names(issues: list[str]) -> list[str]:
    names: list[str] = []
    for issue in issues:
        match = _SOURCE_SCOPE_UNIT_MISMATCH_PERSON_ISSUE_PATTERN.search(str(issue))
        if match is not None:
            names.append(match.group(1))
    return names


def _inline_medicaid_magi_income_helpers(
    *,
    rules_file: Path,
    test_file: Path,
    target_names: list[str],
) -> list[str]:
    if not rules_file.exists():
        return []
    try:
        payload = yaml.safe_load(rules_file.read_text()) or {}
    except (OSError, yaml.YAMLError, ValueError):
        return []
    if not isinstance(payload, dict):
        return []
    if not _is_medicaid_magi_rulespec_payload(payload):
        return []
    rules = payload.get("rules")
    if not isinstance(rules, list):
        return []

    by_name = {
        str(rule.get("name")).strip(): rule
        for rule in rules
        if isinstance(rule, dict)
        and isinstance(rule.get("name"), str)
        and str(rule.get("name")).strip()
    }
    repaired: list[str] = []
    removed: set[str] = set()
    for target_name in dict.fromkeys(target_names):
        helper = by_name.get(target_name)
        if not isinstance(helper, dict):
            continue
        if not _is_medicaid_magi_income_helper_rule(helper):
            continue
        helper_formula = _medicaid_magi_single_formula(helper)
        if not helper_formula or not _formula_mentions_income(helper_formula):
            continue
        formula_references = [
            rule
            for rule in rules
            if isinstance(rule, dict)
            and rule is not helper
            and target_name in _formula_identifiers(_first_rule_formula(rule))
        ]
        if len(formula_references) != 1:
            continue
        dependents = [
            rule
            for rule in formula_references
            if _is_medicaid_magi_final_eligibility_rule(rule)
        ]
        if len(dependents) != 1:
            continue
        dependent = dependents[0]
        if _replace_formula_identifier_with_expression(
            dependent,
            identifier=target_name,
            expression=helper_formula,
        ):
            repaired.append(target_name)
            removed.add(target_name)

    if not repaired:
        return []

    payload["rules"] = [
        rule
        for rule in rules
        if not (
            isinstance(rule, dict) and str(rule.get("name") or "").strip() in removed
        )
    ]
    rules_file.write_text(yaml.safe_dump(payload, sort_keys=False, allow_unicode=False))
    _remove_test_outputs_for_rule_names(test_file, removed)
    return repaired


def _is_medicaid_magi_rulespec_payload(payload: dict[str, object]) -> bool:
    module = payload.get("module")
    if not isinstance(module, dict):
        return False
    source_verification = module.get("source_verification")
    if not isinstance(source_verification, dict):
        return False
    citation_paths = _medicaid_magi_source_verification_paths(source_verification)
    return bool(
        citation_paths
        & {
            "us/regulation/42/435/110",
            "us/regulation/42/435/116",
            "us/regulation/42/435/118",
            "us/regulation/42/435/119",
        }
    )


def _medicaid_magi_source_verification_paths(
    source_verification: dict[str, object],
) -> set[str]:
    paths: set[str] = set()
    singular = source_verification.get("corpus_citation_path")
    if isinstance(singular, str) and singular.strip():
        paths.add(singular.strip())
    return {path for path in paths if path}


def _medicaid_magi_single_formula(rule: dict[str, object]) -> str:
    versions = rule.get("versions")
    if not isinstance(versions, list):
        return ""
    formulas = [
        formula
        for version in versions
        if isinstance(version, dict)
        and isinstance((formula := version.get("formula")), str)
        and formula.strip()
    ]
    if len(formulas) != 1:
        return ""
    return formulas[0]


def _is_medicaid_magi_income_helper_rule(rule: dict[str, object]) -> bool:
    name = str(rule.get("name") or "").strip().lower()
    return (
        str(rule.get("kind") or "").strip().lower() == "derived"
        and str(rule.get("entity") or "").strip().lower() == "person"
        and str(rule.get("dtype") or "").strip().lower() == "judgment"
        and any(token in name for token in ("income", "magi", "fpl"))
    )


def _is_medicaid_magi_final_eligibility_rule(rule: dict[str, object]) -> bool:
    name = str(rule.get("name") or "").strip().lower()
    return (
        str(rule.get("kind") or "").strip().lower() == "derived"
        and str(rule.get("entity") or "").strip().lower() == "person"
        and str(rule.get("dtype") or "").strip().lower() == "judgment"
        and any(token in name for token in ("eligible", "eligibility"))
        and not any(token in name for token in ("income", "limit", "standard"))
    )


def _formula_mentions_income(formula: str) -> bool:
    return any(
        token in formula.lower() for token in ("income", "magi", "fpl", "poverty")
    )


def _replace_formula_identifier_with_expression(
    rule: dict[str, object],
    *,
    identifier: str,
    expression: str,
) -> bool:
    versions = rule.get("versions")
    if not isinstance(versions, list):
        return False
    changed = False
    replacement = f"({expression.strip()})"
    for version in versions:
        if not isinstance(version, dict):
            continue
        formula = version.get("formula")
        if not isinstance(formula, str):
            continue
        updated = _replace_rulespec_identifier(
            formula,
            old=identifier,
            new=replacement,
        )
        if updated != formula:
            version["formula"] = updated
            changed = True
    return changed


def _remove_test_outputs_for_rule_names(test_file: Path, rule_names: set[str]) -> None:
    if not rule_names or not test_file.exists():
        return
    try:
        test_cases = yaml.safe_load(test_file.read_text()) or []
    except (OSError, yaml.YAMLError, ValueError):
        return
    if not isinstance(test_cases, list):
        return

    changed = False
    repaired_cases: list[object] = []
    for case in test_cases:
        if not isinstance(case, dict):
            repaired_cases.append(case)
            continue
        outputs = case.get("output")
        if not isinstance(outputs, dict):
            repaired_cases.append(case)
            continue
        repaired_outputs = {
            key: value
            for key, value in outputs.items()
            if str(key).rsplit("#", 1)[-1] not in rule_names
        }
        if len(repaired_outputs) != len(outputs):
            changed = True
        if repaired_outputs:
            repaired_case = dict(case)
            repaired_case["output"] = repaired_outputs
            repaired_cases.append(repaired_case)

    if changed:
        test_file.write_text(
            yaml.safe_dump(repaired_cases, sort_keys=False, allow_unicode=False)
        )


def _try_repair_generated_unit_scoped_person_definition_for_apply(
    result,
    *,
    output_root: Path,
    issues: list[str],
) -> list[str]:
    """Move generated Person definitions to the source-stated unit scope."""
    target_names = _unit_scoped_person_definition_issue_names(issues)
    if not target_names:
        return []
    try:
        _relative_generated_output_path(result, output_root=output_root)
    except RuntimeError:
        return []

    rules_file = Path(str(getattr(result, "output_file", "") or ""))
    return _repair_unit_scoped_person_definition_entities(
        rules_file=rules_file,
        target_names=target_names,
        unit_entities_by_name=_unit_scoped_person_definition_issue_units(issues),
    )


def _unit_scoped_person_definition_issue_names(issues: list[str]) -> list[str]:
    names: list[str] = []
    for issue in issues:
        match = _SOURCE_SCOPE_UNIT_MISMATCH_PERSON_ISSUE_PATTERN.search(str(issue))
        if match is not None:
            names.append(match.group(1))
    return names


def _unit_scoped_person_definition_issue_units(
    issues: list[str],
) -> dict[str, str]:
    canonical = {
        "family": "Family",
        "household": "Household",
        "snapunit": "SnapUnit",
        "spmunit": "SPMUnit",
        "taxunit": "TaxUnit",
    }
    units: dict[str, str] = {}
    for issue in issues:
        match = _SOURCE_SCOPE_UNIT_MISMATCH_PERSON_ISSUE_PATTERN.search(str(issue))
        if match is None:
            continue
        unit = str(match.group(2) or "").replace("_", "").lower()
        if unit in canonical:
            units[match.group(1)] = canonical[unit]
    return units


def _repair_unit_scoped_person_definition_entities(
    *,
    rules_file: Path,
    target_names: list[str],
    unit_entities_by_name: dict[str, str] | None = None,
) -> list[str]:
    if not rules_file.exists():
        return []
    try:
        payload = yaml.safe_load(rules_file.read_text()) or {}
    except (OSError, yaml.YAMLError, ValueError):
        return []
    if not isinstance(payload, dict):
        return []
    rules = payload.get("rules")
    if not isinstance(rules, list):
        return []

    unit_entity = _dominant_unit_entity_name(rules)
    by_name = {
        str(rule.get("name")).strip(): rule
        for rule in rules
        if isinstance(rule, dict)
        and isinstance(rule.get("name"), str)
        and str(rule.get("name")).strip()
    }
    repaired: list[str] = []
    for target_name in dict.fromkeys(target_names):
        target_rule = by_name.get(target_name)
        if not isinstance(target_rule, dict):
            continue
        target_unit_entity = (unit_entities_by_name or {}).get(
            target_name
        ) or unit_entity
        if _set_rule_entity_to_unit(target_rule, unit_entity=target_unit_entity):
            repaired.append(target_name)

    if not repaired:
        return []

    rules_file.write_text(yaml.safe_dump(payload, sort_keys=False, allow_unicode=False))
    return repaired


def _dominant_unit_entity_name(rules: list[object]) -> str:
    canonical = {
        "family": "Family",
        "household": "Household",
        "snapunit": "SnapUnit",
        "spmunit": "SPMUnit",
        "taxunit": "TaxUnit",
    }
    counts: dict[str, int] = {}
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        normalized = str(rule.get("entity") or "").replace("_", "").lower()
        if normalized not in _UNIT_ENTITY_NAMES:
            continue
        counts[normalized] = counts.get(normalized, 0) + 1
    if not counts:
        return "Household"
    dominant = max(counts, key=lambda name: (counts[name], name))
    return canonical.get(dominant, "Household")


def _set_rule_entity_to_unit(
    rule: dict[str, object],
    *,
    unit_entity: str,
) -> bool:
    entity = str(rule.get("entity") or "").strip()
    if entity != "Person":
        return False
    rule["entity"] = unit_entity
    return True


