def _person_scoped_definition_issue_names(issues: list[str]) -> list[str]:
    names: list[str] = []
    for issue in issues:
        text = str(issue)
        for pattern in (
            _PERSON_SCOPE_DEFINITION_ISSUE_PATTERN,
            _SOURCE_SCOPE_PERSON_MISMATCH_ISSUE_PATTERN,
        ):
            match = pattern.search(text)
            if match is not None:
                names.append(match.group(1))
                break
    return names


def _repair_person_scoped_definition_entities(
    *,
    rules_file: Path,
    target_names: list[str],
) -> list[str]:
    if not rules_file.exists():
        return []
    try:
        payload = yaml.safe_load(rules_file.read_text()) or {}
    except (OSError, yaml.YAMLError, ValueError):
        return []
    if not isinstance(payload, dict):
        return []
    rules = payload.get("rules")
    if not isinstance(rules, list):
        return []

    by_name = {
        str(rule.get("name")).strip(): rule
        for rule in rules
        if isinstance(rule, dict)
        and isinstance(rule.get("name"), str)
        and str(rule.get("name")).strip()
    }
    reverse_dependencies: dict[str, list[str]] = {}
    for rule_name, rule in by_name.items():
        if str(rule.get("kind") or "").strip().lower() != "derived":
            continue
        for identifier in _formula_identifiers(_first_rule_formula(rule)):
            reverse_dependencies.setdefault(identifier, []).append(rule_name)

    repaired: list[str] = []
    pending = list(dict.fromkeys(target_names))
    seen: set[str] = set()
    while pending:
        target_name = pending.pop(0)
        if target_name in seen:
            continue
        seen.add(target_name)
        target_rule = by_name.get(target_name)
        if not isinstance(target_rule, dict):
            continue
        if _set_rule_entity_to_person(target_rule):
            repaired.append(target_name)
        formula = _first_rule_formula(target_rule)
        for identifier in sorted(_formula_identifiers(formula)):
            helper = by_name.get(identifier)
            if not isinstance(helper, dict):
                continue
            if str(helper.get("kind") or "").strip().lower() != "derived":
                continue
            helper_entity = str(helper.get("entity") or "").replace("_", "").lower()
            if helper_entity not in _UNIT_ENTITY_NAMES:
                continue
            pending.append(identifier)
        for dependent_name in sorted(reverse_dependencies.get(target_name, [])):
            dependent = by_name.get(dependent_name)
            if not isinstance(dependent, dict):
                continue
            dependent_entity = (
                str(dependent.get("entity") or "").replace("_", "").lower()
            )
            if dependent_entity not in _UNIT_ENTITY_NAMES:
                continue
            pending.append(dependent_name)

    if not repaired:
        return []

    rules_file.write_text(yaml.safe_dump(payload, sort_keys=False, allow_unicode=False))
    return repaired


def _set_rule_entity_to_person(rule: dict[str, object]) -> bool:
    entity = str(rule.get("entity") or "").strip()
    if entity.replace("_", "").lower() not in _UNIT_ENTITY_NAMES:
        return False
    rule["entity"] = "Person"
    return True


def _first_rule_formula(rule: dict[str, object]) -> str:
    versions = rule.get("versions")
    if not isinstance(versions, list):
        return ""
    for version in versions:
        if not isinstance(version, dict):
            continue
        formula = version.get("formula")
        if isinstance(formula, str):
            return formula
    return ""


def _formula_without_string_literals(formula: str) -> str:
    return _RULESPEC_STRING_LITERAL_PATTERN.sub(
        lambda match: " " * (match.end() - match.start()),
        formula,
    )


def _formula_identifiers(formula: str) -> set[str]:
    return (
        set(
            _RULESPEC_IDENTIFIER_PATTERN.findall(
                _formula_without_string_literals(formula)
            )
        )
        - _RULESPEC_FORMULA_BUILTINS
    )


def _try_repair_generated_nonnegative_floors_for_apply(
    result,
    *,
    output_root: Path,
    policy_repo_path: Path,
    issues: list[str],
) -> list[str]:
    """Apply deterministic nonnegative-floor repairs to the generated candidate."""
    if not _only_pending_nonnegative_amount_reduction_issues(issues):
        return []

    try:
        relative_output = _relative_generated_output_path(
            result, output_root=output_root
        )
    except RuntimeError:
        return []

    rules_file = Path(str(getattr(result, "output_file", "") or ""))
    if not rules_file.exists():
        return []

    try:
        original_content = rules_file.read_text()
    except OSError:
        return []

    repaired_content, repaired_rules = repair_nonnegative_amount_reductions(
        original_content
    )
    if repaired_content == original_content:
        return []

    rules_file.write_text(repaired_content)
    test_file = _rulespec_test_path(rules_file)
    _append_generated_zero_branch_tests_if_missing(
        rules_file=rules_file,
        test_file=test_file,
        repo_path=policy_repo_path,
        relative_output=relative_output,
    )
    return repaired_rules


