def _repair_positive_imported_judgment_composition_tests(
    *,
    rules_file: Path,
    test_file: Path,
    policy_repo_path: Path,
    relative_output: Path,
    issues: list[str],
) -> list[str]:
    if not rules_file.exists() or not test_file.exists() or not issues:
        return []

    try:
        rules_payload = yaml.safe_load(rules_file.read_text()) or {}
        test_payload = yaml.safe_load(test_file.read_text()) or []
    except (OSError, ValueError, yaml.YAMLError):
        return []
    if not isinstance(rules_payload, dict) or not isinstance(test_payload, list):
        return []

    anchor = _relative_output_to_anchor(
        relative_output, policy_repo_path=policy_repo_path
    )
    rules_by_name = _rules_by_name_from_payload(rules_payload)
    imported_refs_by_name = _imported_output_refs_by_name(rules_file)
    if not imported_refs_by_name:
        return []

    positive_mismatches: dict[str, set[str]] = defaultdict(set)
    for issue in issues:
        parsed = _parse_generated_test_output_mismatch(str(issue))
        if parsed is None:
            continue
        case_name, output_ref, actual_value = parsed
        if actual_value != "not_holds":
            continue
        if not _rulespec_ref_matches_base(output_ref, anchor):
            continue
        output_name = output_ref.rsplit("#", 1)[-1]
        rule = rules_by_name.get(output_name)
        if not isinstance(rule, dict):
            continue
        if not _generated_rule_is_imported_judgment_composition(
            rule,
            payload=rules_payload,
        ):
            continue
        positive_mismatches[case_name].add(output_ref)
    if not positive_mismatches:
        return []

    changed = False
    repairs: list[str] = []
    for test_case in test_payload:
        if not isinstance(test_case, dict):
            continue
        case_name = str(test_case.get("name") or "").strip()
        output_refs = positive_mismatches.get(case_name)
        if not output_refs:
            continue
        inputs = test_case.get("input")
        outputs = test_case.get("output")
        if not isinstance(inputs, dict) or not isinstance(outputs, dict):
            continue
        for output_ref in sorted(output_refs):
            output_key = _matching_mapping_key_by_rulespec_ref(outputs, output_ref)
            if output_key is None:
                continue
            if _normalized_generated_test_scalar(outputs[output_key]) != "holds":
                continue
            output_name = output_ref.rsplit("#", 1)[-1]
            rule = rules_by_name.get(output_name)
            if not isinstance(rule, dict):
                continue
            branch = _best_imported_judgment_branch_for_test_case(
                rule=rule,
                imported_refs_by_name=imported_refs_by_name,
                inputs=inputs,
                policy_repo_path=policy_repo_path,
            )
            if not branch:
                continue
            branch_repairs = _harmonize_imported_judgment_branch_inputs(
                inputs,
                branch=branch,
                case_name=case_name,
                policy_repo_path=policy_repo_path,
            )
            if branch_repairs is None:
                return []
            if not branch_repairs:
                continue
            repairs.extend(branch_repairs)
            changed = True

    if not changed:
        return []
    test_file.write_text(
        yaml.safe_dump(test_payload, sort_keys=False, allow_unicode=False)
    )
    return repairs


def _harmonize_imported_judgment_branch_inputs(
    inputs: dict[object, object],
    *,
    branch: tuple[str, ...],
    case_name: str,
    policy_repo_path: Path,
) -> list[str] | None:
    """Make a generated positive test satisfy an imported Judgment branch.

    Imported Judgment outputs are computed by the producer RuleSpec file. A
    generated consumer test therefore has to set the producer's factual inputs,
    not assign the imported output directly.
    """
    desired_by_fragment: dict[str, tuple[str, object]] = {}
    direct_imported_keys: list[object] = []

    for imported_ref in branch:
        direct_key = _matching_mapping_key_by_rulespec_ref(inputs, imported_ref)
        if direct_key is not None:
            if _normalized_generated_test_scalar(inputs[direct_key]) != "holds":
                return None
            direct_imported_keys.append(direct_key)

        producer_inputs = _producer_test_inputs_for_output_value(
            imported_ref,
            "holds",
            policy_repo_path=policy_repo_path,
        )
        if not producer_inputs:
            return None
        for producer_ref, producer_value in producer_inputs.items():
            producer_ref_text = str(producer_ref)
            fragment = _rulespec_test_key_fragment(producer_ref_text)
            existing = desired_by_fragment.get(fragment)
            if existing is not None and not _generated_test_values_equal(
                existing[1],
                producer_value,
            ):
                return None
            desired_by_fragment[fragment] = (
                producer_ref_text,
                copy.deepcopy(producer_value),
            )

    repairs: list[str] = []
    for direct_key in direct_imported_keys:
        if direct_key in inputs:
            del inputs[direct_key]
            repairs.append(f"test:{case_name}:remove:{direct_key}")

    for fragment, (producer_ref, desired_value) in sorted(desired_by_fragment.items()):
        matching_keys = [
            key for key in list(inputs) if _rulespec_test_key_fragment(key) == fragment
        ]
        exact_key = _matching_mapping_key_by_rulespec_ref(inputs, producer_ref)
        if exact_key is None:
            inputs[producer_ref] = copy.deepcopy(desired_value)
            repairs.append(f"test:{case_name}:{producer_ref}")
            matching_keys.append(producer_ref)
            exact_key = producer_ref
        for key in matching_keys:
            if not _generated_test_values_equal(inputs[key], desired_value):
                inputs[key] = copy.deepcopy(desired_value)
                repairs.append(f"test:{case_name}:{key}={fragment}")

    return repairs


def _best_imported_judgment_branch_for_test_case(
    *,
    rule: dict[str, object],
    imported_refs_by_name: dict[str, str],
    inputs: dict[object, object],
    policy_repo_path: Path,
) -> tuple[str, ...]:
    branches = _imported_judgment_positive_branches_for_rule(
        rule,
        imported_refs_by_name=imported_refs_by_name,
    )
    best_branch: tuple[str, ...] = ()
    best_score = 0
    for branch in branches:
        score = _imported_judgment_branch_test_score(
            branch,
            inputs=inputs,
            policy_repo_path=policy_repo_path,
        )
        if score > best_score:
            best_score = score
            best_branch = branch
    return best_branch


def _imported_judgment_positive_branches_for_rule(
    rule: dict[str, object],
    *,
    imported_refs_by_name: dict[str, str],
) -> list[tuple[str, ...]]:
    versions = rule.get("versions")
    if not isinstance(versions, list):
        return []
    imported_names = set(imported_refs_by_name)
    branches: list[tuple[str, ...]] = []
    for version in versions:
        if not isinstance(version, dict):
            continue
        formula = version.get("formula")
        if not isinstance(formula, str) or not formula.strip():
            continue
        for raw_branch in _split_top_level_boolean_operator(formula, "or"):
            branch = _strip_balanced_outer_parentheses(raw_branch)
            if re.search(r"\bnot\b", branch):
                continue
            branch_names: list[str] = []
            for raw_part in _split_top_level_boolean_operator(branch, "and"):
                part = _strip_balanced_outer_parentheses(raw_part)
                if not re.fullmatch(r"[A-Za-z_][A-Za-z0-9_]*", part):
                    branch_names = []
                    break
                if part not in imported_names:
                    branch_names = []
                    break
                branch_names.append(part)
            if not branch_names:
                continue
            branches.append(tuple(imported_refs_by_name[name] for name in branch_names))
    return branches


def _split_top_level_boolean_operator(expression: str, operator: str) -> list[str]:
    normalized_operator = operator.strip().lower()
    if normalized_operator not in {"and", "or"}:
        return [expression.strip()]
    parts: list[str] = []
    depth = 0
    start = 0
    for match in re.finditer(r"\b(?:and|or)\b|[()]", expression):
        token = match.group(0)
        if token == "(":
            depth += 1
            continue
        if token == ")":
            depth = max(0, depth - 1)
            continue
        if depth == 0 and token.lower() == normalized_operator:
            parts.append(expression[start : match.start()].strip())
            start = match.end()
    parts.append(expression[start:].strip())
    return [part for part in parts if part]


def _strip_balanced_outer_parentheses(expression: str) -> str:
    stripped = expression.strip()
    while stripped.startswith("(") and stripped.endswith(")"):
        depth = 0
        wraps = True
        for index, char in enumerate(stripped):
            if char == "(":
                depth += 1
            elif char == ")":
                depth -= 1
                if depth == 0 and index != len(stripped) - 1:
                    wraps = False
                    break
            if depth < 0:
                wraps = False
                break
        if not wraps or depth != 0:
            break
        stripped = stripped[1:-1].strip()
    return stripped


def _imported_judgment_branch_test_score(
    branch: tuple[str, ...],
    *,
    inputs: dict[object, object],
    policy_repo_path: Path,
) -> int:
    score = 0
    for imported_ref in branch:
        direct_key = _matching_mapping_key_by_rulespec_ref(inputs, imported_ref)
        if direct_key is not None:
            if _normalized_generated_test_scalar(inputs[direct_key]) != "holds":
                return -1
            score += 100
            continue
        producer_inputs = _producer_test_inputs_for_output_value(
            imported_ref,
            "holds",
            policy_repo_path=policy_repo_path,
        )
        if not producer_inputs:
            continue
        matched = 0
        for producer_ref, producer_value in producer_inputs.items():
            input_key = _matching_mapping_key_by_rulespec_ref(
                inputs,
                str(producer_ref),
            )
            if input_key is None:
                continue
            if not _generated_test_values_equal(inputs[input_key], producer_value):
                return -1
            matched += 1
        score += matched
    return score


def _repair_imported_output_test_mismatches(
    *,
    rules_file: Path | None = None,
    test_file: Path,
    policy_repo_path: Path,
    relative_output: Path,
    issues: list[str],
) -> list[str]:
    if not test_file.exists():
        return []

    try:
        test_payload = yaml.safe_load(test_file.read_text()) or []
    except (OSError, yaml.YAMLError):
        return []
    if not isinstance(test_payload, list):
        return []

    imported_composition_rules: set[str] = set()
    if rules_file is not None and rules_file.exists():
        try:
            rules_payload = yaml.safe_load(rules_file.read_text()) or {}
        except (OSError, ValueError, yaml.YAMLError):
            rules_payload = {}
        if isinstance(rules_payload, dict):
            for name, rule in _rules_by_name_from_payload(rules_payload).items():
                if _generated_rule_is_imported_judgment_composition(
                    rule,
                    payload=rules_payload,
                ):
                    imported_composition_rules.add(name)

    anchor = _relative_output_to_anchor(
        relative_output, policy_repo_path=policy_repo_path
    )
    repairs_by_case: dict[str, dict[str, object]] = {}
    for issue in issues:
        parsed = _parse_generated_test_output_mismatch(str(issue))
        if parsed is None:
            return []
        case_name, output_ref, actual_value = parsed
        if not _rulespec_ref_matches_base(output_ref, anchor):
            return []
        if re.search(r"\b(?:threshold|boundary)\b", case_name, flags=re.IGNORECASE):
            return []
        repairs_by_case.setdefault(case_name, {})[output_ref] = actual_value
    if not repairs_by_case:
        return []

    repaired_cases: list[str] = []
    for test_case in test_payload:
        if not isinstance(test_case, dict):
            continue
        case_name = str(test_case.get("name") or "").strip()
        replacements = repairs_by_case.get(case_name)
        if not replacements:
            continue
        if case_name.startswith("auto_positive_"):
            continue
        inputs = test_case.get("input")
        if not _test_case_has_imported_inputs(inputs, target_anchor=anchor):
            return []
        outputs = test_case.get("output")
        if not isinstance(outputs, dict):
            return []
        changed = False
        for output_ref, actual_value in replacements.items():
            output_key = _matching_mapping_key_by_rulespec_ref(outputs, output_ref)
            if output_key is None:
                return []
            output_name = output_ref.rsplit("#", 1)[-1]
            if (
                output_name in imported_composition_rules
                and actual_value == "not_holds"
                and _normalized_generated_test_scalar(outputs[output_key]) == "holds"
            ):
                return []
            if outputs[output_key] != actual_value:
                outputs[output_key] = actual_value
                changed = True
        if changed:
            repaired_cases.append(case_name)

    if not repaired_cases:
        return []
    test_file.write_text(
        yaml.safe_dump(test_payload, sort_keys=False, allow_unicode=False)
    )
    return repaired_cases


def _repair_auto_output_test_mismatches(
    *,
    test_file: Path,
    policy_repo_path: Path,
    relative_output: Path,
    issues: list[str],
) -> list[str]:
    if not test_file.exists():
        return []

    try:
        test_payload = yaml.safe_load(test_file.read_text()) or []
    except (OSError, yaml.YAMLError):
        return []
    if not isinstance(test_payload, list):
        return []

    anchor = _relative_output_to_anchor(
        relative_output, policy_repo_path=policy_repo_path
    )
    repairs_by_case: dict[str, dict[str, object]] = {}
    for issue in issues:
        parsed = _parse_generated_test_output_mismatch(str(issue))
        if parsed is None:
            continue
        case_name, output_ref, actual_value = parsed
        if not case_name.startswith(("auto_output_", "auto_zero_")):
            continue
        if not _rulespec_ref_matches_base(output_ref, anchor):
            continue
        repairs_by_case.setdefault(case_name, {})[output_ref] = actual_value
    if not repairs_by_case:
        return []

    repaired_cases: list[str] = []
    for test_case in test_payload:
        if not isinstance(test_case, dict):
            continue
        case_name = str(test_case.get("name") or "").strip()
        replacements = repairs_by_case.get(case_name)
        if not replacements:
            continue
        outputs = test_case.get("output")
        if not isinstance(outputs, dict):
            return []
        changed = False
        for output_ref, actual_value in replacements.items():
            output_key = _matching_mapping_key_by_rulespec_ref(outputs, output_ref)
            if output_key is None:
                return []
            if outputs[output_key] != actual_value:
                outputs[output_key] = actual_value
                changed = True
        if changed:
            repaired_cases.append(case_name)

    if not repaired_cases:
        return []
    test_file.write_text(
        yaml.safe_dump(test_payload, sort_keys=False, allow_unicode=False)
    )
    return repaired_cases


def _repair_conditional_vacuity_test_mismatches(
    *,
    rules_file: Path,
    test_file: Path,
    policy_repo_path: Path,
    relative_output: Path,
    issues: list[str],
) -> list[str]:
    if not rules_file.exists() or not test_file.exists():
        return []

    try:
        rules_payload = yaml.safe_load(rules_file.read_text()) or {}
        test_payload = yaml.safe_load(test_file.read_text()) or []
    except (OSError, yaml.YAMLError):
        return []
    if not isinstance(rules_payload, dict) or not isinstance(test_payload, list):
        return []

    anchor = _relative_output_to_anchor(
        relative_output, policy_repo_path=policy_repo_path
    )
    output_formula_guards = _rule_negated_or_guards_by_name(rules_payload)
    if not output_formula_guards:
        return []

    repairs_by_case: dict[str, dict[str, object]] = {}
    for issue in issues:
        parsed = _parse_generated_test_output_mismatch(str(issue))
        if parsed is None:
            continue
        case_name, output_ref, actual_value = parsed
        if case_name.startswith(("auto_output_", "auto_positive_")):
            continue
        if re.search(r"\b(?:threshold|boundary)\b", case_name, flags=re.IGNORECASE):
            continue
        if not _rulespec_ref_matches_base(output_ref, anchor):
            continue
        if _normalized_generated_test_scalar(actual_value) != "holds":
            continue
        rule_name = _rulespec_test_key_fragment(output_ref)
        if rule_name not in output_formula_guards:
            continue
        repairs_by_case.setdefault(case_name, {})[output_ref] = actual_value
    if not repairs_by_case:
        return []

    repaired_cases: list[str] = []
    for test_case in test_payload:
        if not isinstance(test_case, dict):
            continue
        case_name = str(test_case.get("name") or "").strip()
        replacements = repairs_by_case.get(case_name)
        if not replacements:
            continue
        inputs = test_case.get("input")
        outputs = test_case.get("output")
        if not isinstance(inputs, dict) or not isinstance(outputs, dict):
            return []

        changed = False
        for output_ref, actual_value in replacements.items():
            output_key = _matching_mapping_key_by_rulespec_ref(outputs, output_ref)
            if output_key is None:
                return []
            if _normalized_generated_test_scalar(outputs[output_key]) != "not_holds":
                continue
            rule_name = _rulespec_test_key_fragment(output_ref)
            guards = output_formula_guards.get(rule_name, set())
            if not any(
                _test_input_sets_guard_false(inputs, anchor=anchor, guard=guard)
                for guard in guards
            ):
                continue
            outputs[output_key] = actual_value
            changed = True
        if changed:
            repaired_cases.append(case_name)

    if not repaired_cases:
        return []
    test_file.write_text(
        yaml.safe_dump(test_payload, sort_keys=False, allow_unicode=False)
    )
    return repaired_cases


def _rule_negated_or_guards_by_name(
    rules_payload: dict[str, object],
) -> dict[str, set[str]]:
    rules = rules_payload.get("rules")
    if not isinstance(rules, list):
        return {}

    guards_by_rule: dict[str, set[str]] = {}
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        rule_name = str(rule.get("name") or "").strip()
        if not rule_name:
            continue
        versions = rule.get("versions")
        if not isinstance(versions, list):
            continue
        guards: set[str] = set()
        for version in versions:
            if not isinstance(version, dict):
                continue
            formula = version.get("formula")
            if isinstance(formula, str):
                guards.update(_formula_negated_or_guards(formula))
        if guards:
            guards_by_rule[rule_name] = guards
    return guards_by_rule


def _formula_negated_or_guards(formula: str) -> set[str]:
    normalized = " ".join(formula.split())
    match = re.match(
        r"^\s*(?:\(\s*)*not\s+(?P<guard>[A-Za-z_][A-Za-z0-9_]*)"
        r"\s*(?:\)\s*)*or\b",
        normalized,
    )
    if not match:
        return set()
    return {match["guard"]}


def _test_input_sets_guard_false(
    inputs: dict[object, object],
    *,
    anchor: str,
    guard: str,
) -> bool:
    target_fragment = f"input.{guard}"
    for key, value in inputs.items():
        key_text = str(key)
        if "#" in key_text and not _rulespec_ref_matches_base(key_text, anchor):
            continue
        if _rulespec_test_key_fragment(key_text) != target_fragment:
            continue
        if _is_boolean_test_value(value, False):
            return True
    return False


def _parse_generated_test_output_mismatch(
    issue: str,
) -> tuple[str, str, object] | None:
    match = re.search(
        r"Test case\s+(?:`(?P<case_quoted>[^`]+)`|(?P<case>[^\s`]+))\s+"
        r"output\s+`?(?P<output>[^\s`]+)`?\s+"
        r"expected\s+\w+\s+.+?,\s+got\s+"
        r"(?P<kind>\w+)\s+(?P<value>-?(?:\d+(?:\.\d+)?|true|false))\.?$",
        issue,
        flags=re.IGNORECASE,
    )
    if match:
        try:
            value = _rulespec_mismatch_actual_value(match["kind"], match["value"])
        except (InvalidOperation, ValueError):
            return None
        case = (match["case_quoted"] or match["case"]).strip()
        return case, match["output"].strip(), value

    judgment_match = re.search(
        r"Test case\s+(?:`(?P<case_quoted>[^`]+)`|(?P<case>[^\s`]+))\s+"
        r"output\s+`?(?P<output>[^\s`]+)`?\s+"
        r"expected\s+\w+,\s+got\s+(?P<value>holds|not_holds)\.?$",
        issue,
        flags=re.IGNORECASE,
    )
    if judgment_match:
        case = (judgment_match["case_quoted"] or judgment_match["case"]).strip()
        return (
            case,
            judgment_match["output"].strip(),
            judgment_match["value"].strip().lower(),
        )
    return None


def _rulespec_mismatch_actual_value(kind: str, raw_value: str) -> object:
    value = raw_value.strip()
    normalized_kind = kind.strip().lower()
    if normalized_kind == "integer":
        return int(value)
    if normalized_kind == "decimal":
        decimal = Decimal(value)
        return (
            int(decimal) if decimal == decimal.to_integral_value() else float(decimal)
        )
    if normalized_kind == "boolean":
        lowered = value.lower()
        if lowered in {"true", "false"}:
            return lowered == "true"
    raise ValueError(f"unsupported mismatch value: {kind} {raw_value}")


def _test_case_has_imported_inputs(inputs: object, *, target_anchor: str) -> bool:
    if not isinstance(inputs, dict):
        return False
    for key in inputs:
        key_text = str(key)
        if "#input." not in key_text:
            continue
        if not _rulespec_ref_matches_base(key_text, target_anchor):
            return True
    return False


def _parse_test_input_assignment_issue(issue: str) -> tuple[str, set[str]] | None:
    match = re.search(
        r"Test input assignment missing:\s*`(?P<case>[^`]+)`\s+"
        r"does not assign\s+(?P<inputs>.+?)\.\s+Every test",
        issue,
    )
    if not match:
        return None
    missing_inputs = {
        name.strip()
        for name in re.findall(r"#input\.([A-Za-z_][A-Za-z0-9_]*)", match["inputs"])
    }
    if not missing_inputs:
        return None
    return match["case"].strip(), missing_inputs


def _default_generated_test_input_value(
    input_name: str,
    *,
    rules_payload: dict[str, object],
    prefer_positive_counts: bool = False,
) -> bool | int | str:
    if _factual_input_appears_string_selector(input_name, rules_payload=rules_payload):
        return ""
    if _factual_input_appears_numeric(input_name, rules_payload=rules_payload):
        if prefer_positive_counts and _factual_input_name_looks_positive_count(
            input_name
        ):
            return 1
        return 0
    return False


def _factual_input_appears_string_selector(
    input_name: str, *, rules_payload: dict[str, object]
) -> bool:
    rules = rules_payload.get("rules")
    if not isinstance(rules, list):
        return False

    string_comparison = re.compile(
        rf"""
        (?:
            \b{re.escape(input_name)}\b\s*(?:==|!=)\s*(['"])[^'"]*\1
            |
            (['"])[^'"]*\2\s*(?:==|!=)\s*\b{re.escape(input_name)}\b
        )
        """,
        re.VERBOSE,
    )
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        versions = rule.get("versions")
        if not isinstance(versions, list):
            continue
        for version in versions:
            if not isinstance(version, dict):
                continue
            formula = version.get("formula")
            if isinstance(formula, str) and string_comparison.search(formula):
                return True
    return False


def _factual_input_name_looks_positive_count(input_name: str) -> bool:
    tokens = set(input_name.lower().split("_"))
    if "count" in tokens or "size" in tokens:
        return True
    positive_suffixes = (
        "_member_count",
        "_household_size",
        "_unit_size",
        "_family_size",
        "_assistance_unit_size",
    )
    return input_name.lower().endswith(positive_suffixes)


def _factual_input_appears_numeric(
    input_name: str, *, rules_payload: dict[str, object]
) -> bool:
    if input_name == "filing_status":
        return True
    if _factual_input_name_looks_boolean(input_name):
        return False

    rules = rules_payload.get("rules")
    if isinstance(rules, list):
        pattern = re.compile(rf"\b{re.escape(input_name)}\b")
        numeric_context = re.compile(
            rf"(\b{re.escape(input_name)}\b\s*(?:[+\-*/<>]=?|==|!=)"
            rf"|(?:[+\-*/]\s*)\b{re.escape(input_name)}\b)"
        )
        boolean_context = re.compile(
            rf"(\bif\s+{re.escape(input_name)}\s*:"
            rf"|\bnot\s+{re.escape(input_name)}\b"
            rf"|\b{re.escape(input_name)}\b\s+(?:and|or)\b"
            rf"|\b(?:and|or)\s+{re.escape(input_name)}\b)"
        )
        formula_hits: list[str] = []
        for rule in rules:
            if not isinstance(rule, dict):
                continue
            versions = rule.get("versions")
            if not isinstance(versions, list):
                continue
            for version in versions:
                if not isinstance(version, dict):
                    continue
                formula = version.get("formula")
                if not isinstance(formula, str) or not pattern.search(formula):
                    continue
                formula_hits.append(formula)
        if any(
            _string_positive_assignment_for_expression(
                input_name=input_name,
                expression=formula,
            )
            is not None
            for formula in formula_hits
        ):
            return False
        if any(numeric_context.search(formula) for formula in formula_hits):
            return True
        if any(boolean_context.search(formula) for formula in formula_hits):
            return False

    input_tokens = set(input_name.split("_"))
    numeric_name_fragments = (
        "amount",
        "base",
        "income",
        "wage",
        "wages",
        "remuneration",
        "salary",
        "age",
        "month",
        "months",
        "threshold",
        "rate",
        "value",
        "count",
        "cost",
        "costs",
        "need",
        "needs",
        "expense",
        "expenses",
        "deduction",
        "deductions",
        "credit",
        "credits",
        "tax",
        "gross",
        "net",
    )
    if input_tokens.intersection(numeric_name_fragments):
        return True
    return False


def _factual_input_name_looks_boolean(input_name: str) -> bool:
    normalized = input_name.lower()
    tokens = set(normalized.split("_"))
    boolean_prefixes = (
        "any_",
        "all_",
        "is_",
        "are_",
        "has_",
        "have_",
        "had_",
        "was_",
        "were_",
        "can_",
        "must_",
        "does_",
        "do_",
        "did_",
    )
    boolean_tokens = {
        prefix.strip("_")
        for prefix in boolean_prefixes
        if prefix not in {"any_", "all_"}
    }
    boolean_suffixes = (
        "_applies",
        "_applicable",
        "_eligible",
        "_ineligible",
        "_qualified",
        "_unqualified",
        "_allowable",
        "_disallowed",
        "_exempt",
        "_excluded",
        "_included",
        "_true",
        "_false",
    )
    return (
        normalized.startswith(boolean_prefixes)
        or normalized.endswith(boolean_suffixes)
        or bool(tokens.intersection(boolean_tokens))
    )


def _relative_generated_output_path(
    result,
    *,
    output_root: Path,
) -> Path:
    output_file = Path(str(getattr(result, "output_file", "") or ""))
    runner = str(getattr(result, "runner", "") or "")
    if not output_file.exists():
        raise RuntimeError(f"Generated output file not found: {output_file}")
    generated_root = Path(output_root) / runner
    try:
        relative_output = output_file.resolve().relative_to(generated_root.resolve())
    except ValueError as exc:
        raise RuntimeError(
            f"Generated output {output_file} is not under {generated_root}"
        ) from exc
    return relative_output


def _relative_output_to_anchor(
    relative_output: Path, *, policy_repo_path: Path | None = None
) -> str:
    """Convert a generated file's relative path to its RuleSpec anchor."""
    rel = relative_output.with_suffix("")
    parts = rel.parts
    jurisdiction = _relative_output_jurisdiction_prefix(relative_output)
    if jurisdiction is not None:
        return f"{parts[0]}:{Path(*parts[1:]).as_posix()}"
    repo_jurisdiction = (
        _repo_jurisdiction_prefix(policy_repo_path) if policy_repo_path else "us"
    )
    return f"{repo_jurisdiction}:{rel.as_posix()}"


def _relative_output_jurisdiction_prefix(relative_output: Path) -> str | None:
    """Return a leading jurisdiction directory from a generated output path."""
    parts = Path(relative_output).parts
    if (
        len(parts) >= 2
        and parts[1] in RULESPEC_ATOMIC_MODULE_ROOTS
        and re.fullmatch(r"[a-z]{2}(?:-[a-z0-9_]+)*", parts[0])
    ):
        return parts[0]
    return None


def _rulespec_apply_content_root(
    policy_repo_path: Path,
    relative_output: Path | None = None,
) -> Path:
    """Return the jurisdiction content root for live generated writes."""
    repo_path = Path(policy_repo_path)
    if relative_output is not None:
        output_jurisdiction = _relative_output_jurisdiction_prefix(relative_output)
        if output_jurisdiction is not None:
            content_root = jurisdiction_content_dir(repo_path, output_jurisdiction)
        else:
            content_root = jurisdiction_content_dir(
                repo_path,
                _repo_jurisdiction_prefix(repo_path),
            )
    else:
        content_root = jurisdiction_content_dir(
            repo_path,
            _repo_jurisdiction_prefix(repo_path),
        )
    if (
        not content_root.is_dir()
        or canonical_rulespec_root_identity(content_root) is None
    ):
        raise ValueError(
            "RuleSpec apply target must be an existing canonical "
            f"rulespec-<country>/<jurisdiction> content root: {content_root}"
        )
    return content_root


def _rulespec_apply_checkout_root(
    policy_repo_path: Path,
    relative_output: Path | None = None,
) -> Path:
    """Return the canonical country checkout for an apply target."""
    repo_path = Path(policy_repo_path).resolve()
    content_root = _rulespec_apply_content_root(repo_path, relative_output)
    checkout_root = content_root.parent
    if canonical_rulespec_repo_name(checkout_root) != checkout_root.name:
        raise ValueError(
            "RuleSpec apply target must belong to a canonical "
            f"rulespec-<country> checkout: {repo_path}"
        )
    return checkout_root


def _relative_to_rulespec_apply_content_root(
    path: Path,
    repo_path: Path,
    relative_output: Path | None = None,
) -> Path:
    """Return ``path`` relative to the jurisdiction content root when possible."""
    content_root = _rulespec_apply_content_root(repo_path, relative_output)
    try:
        return Path(path).relative_to(content_root)
    except ValueError:
        return Path(path).relative_to(repo_path)


def _enforce_canonical_concept_registry(
    *,
    candidate_files: list[Path],
    relative_output: Path,
    policy_repo_path: Path | None = None,
) -> list[Path]:
    """Refuse to apply a generated encoding that violates the concept registry.

    Raises RuntimeError listing every violation so the encoder caller can
    surface them. Returns repaired test files. Run before any file copy so a
    bad encode never lands in the live rules repo.
    """
    registry = load_concept_registry()
    apply_anchor = _relative_output_to_anchor(
        relative_output,
        policy_repo_path=policy_repo_path,
    )
    files = [f for f in candidate_files if f and f.exists()]
    repaired = auto_repair_test_yaml_canonical_violations(files, registry)
    if repaired:
        print(
            "  apply=auto_repaired_test_yaml_canonical_refs:"
            + ",".join(p.name for p in repaired)
        )
    violations = validate_generated_against_registry(
        files, registry, apply_anchor=apply_anchor
    )
    if not violations:
        return repaired
    lines = [str(v) for v in violations]
    raise RuntimeError(
        "Canonical concept registry violations — refusing to apply:\n  "
        + "\n  ".join(lines)
    )


def _read_corpus_citation_path_from_rulespec(path: Path) -> str | None:
    """Return the corpus_citation_path declared in a RuleSpec file, if any.

    Returns ``None`` when the file is missing, unparseable, or has no source
    verification block; callers treat that as "no claim to compare against."
    """
    if not path.exists():
        return None
    try:
        doc = yaml.safe_load(path.read_text())
    except (OSError, yaml.YAMLError):
        return None
    if not isinstance(doc, dict):
        return None
    module = doc.get("module")
    if not isinstance(module, dict):
        return None
    sv = module.get("source_verification")
    if not isinstance(sv, dict):
        return None
    single = sv.get("corpus_citation_path")
    if isinstance(single, str) and single.strip():
        return single.strip()
    return None


def _enforce_no_apply_collision(*, source_file: Path, target_file: Path) -> None:
    """Refuse to overwrite an existing RuleSpec that encodes a different corpus citation.

    Sibling encodes that resolve to the same output path are the original
    symptom that produced 342 lost CalFresh encodings in 2026-05-13. Even
    after the path-strategy and resolver-fallback fixes above, this guard is
    a deliberate backstop: if any future regression reintroduces collision,
    apply fails loudly instead of silently overwriting.

    No-ops when the target does not yet exist, when neither file declares a
    corpus_citation_path, or when both files declare the same path.
    """
    if not target_file.exists():
        return
    incoming = _read_corpus_citation_path_from_rulespec(source_file)
    existing = _read_corpus_citation_path_from_rulespec(target_file)
    if not incoming or not existing:
        return
    if incoming == existing:
        return
    raise RuntimeError(
        "Refusing to overwrite "
        f"{target_file} — existing file declares corpus citation "
        f"{existing!r}, incoming encode declares "
        f"{incoming!r}. Sibling subsections likely share an "
        "output path; check the citation-to-path strategy "
        "(see issue #71)."
    )


_SHA256_HEX_PATTERN = re.compile(r"^[0-9a-f]{64}$")


def _generated_result_source_attestation(result) -> dict[str, object] | None:
    """Return a manifest-safe copy of the resolver-owned source attestation.

    The canonical corpus-citation pipeline supplies the resolver's final body
    byte-for-byte to the model, so this digest binds the exact generation input.
    """

    attestation = getattr(result, "source_attestation", None)
    if not isinstance(attestation, dict):
        return None
    normalized = copy.deepcopy(attestation)
    manifest_file = Path(str(getattr(result, "context_manifest_file", "") or ""))
    try:
        context = json.loads(manifest_file.read_text())
        source_file = manifest_file.parent / str(context["source_text_file"])
        generation_input = source_file.read_bytes()
    except (
        OSError,
        UnicodeError,
        KeyError,
        TypeError,
        ValueError,
        json.JSONDecodeError,
    ) as exc:
        raise RuntimeError(
            "Cannot recompute generation input digest from the eval workspace"
        ) from exc
    recomputed = hashlib.sha256(generation_input).hexdigest()
    attested = normalized.get("generation_input_sha256")
    if attested != recomputed:
        raise RuntimeError(
            "Generation input digest mismatch: workspace source text does not match "
            "source_attestation.generation_input_sha256"
        )
    return normalized


def _generated_result_source_metadata(result) -> dict[str, object] | None:
    """Load source metadata only from the result's explicit context artifact."""

    manifest_file_raw = str(getattr(result, "context_manifest_file", "") or "")
    if not manifest_file_raw:
        return None
    manifest_file = Path(manifest_file_raw)
    try:
        context = json.loads(manifest_file.read_text(encoding="utf-8"))
    except (OSError, UnicodeError, json.JSONDecodeError, RecursionError) as exc:
        raise RuntimeError(
            "Cannot read explicit source metadata from the eval context manifest"
        ) from exc
    if not isinstance(context, dict):
        raise RuntimeError("Eval context manifest must be a JSON object")
    source_metadata = context.get("source_metadata")
    if source_metadata is None:
        if isinstance(getattr(result, "source_attestation", None), dict):
            raise RuntimeError(
                "Eval context manifest is missing resolver-owned source_metadata"
            )
        return None
    if not isinstance(source_metadata, dict):
        raise RuntimeError("Eval context manifest source_metadata must be an object")
    normalized = copy.deepcopy(source_metadata)
    result_attestation = getattr(result, "source_attestation", None)
    if (
        isinstance(result_attestation, dict)
        and normalized.get("source_attestation") != result_attestation
    ):
        raise RuntimeError(
            "Eval context source_metadata does not match the result source_attestation"
        )
    return normalized


def _source_attestation_structure_issues(
    attestation: object,
) -> list[str]:
    """Validate the provenance fields required to bind an applied RuleSpec."""

    if not isinstance(attestation, dict):
        return ["source_attestation must be an object"]

    issues: list[str] = []
    allowed_fields = {
        "requested_corpus_citation_path",
        "resolved_corpus_citation_path",
        "corpus_source",
        "corpus_release",
        "corpus_release_content_sha256",
        "corpus_release_selector_sha256",
        "provision_file",
        "provision_file_sha256",
        "row",
        "component_rows",
        "source_sha256",
        "resolved_text_sha256",
        "generation_input_sha256",
        "source_as_of",
        "expression_date",
        "rulespec_root",
    }
    unexpected_fields = sorted(set(attestation) - allowed_fields)
    if unexpected_fields:
        issues.append(
            "source_attestation has noncanonical fields: "
            + ", ".join(unexpected_fields)
        )

    def require_string(field: str) -> str:
        value = attestation.get(field)
        if not isinstance(value, str) or not value.strip():
            issues.append(f"source_attestation.{field} must be a non-empty string")
            return ""
        return value.strip()

    def require_sha256(field: str) -> str:
        value = require_string(field)
        if value and _SHA256_HEX_PATTERN.fullmatch(value) is None:
            issues.append(
                f"source_attestation.{field} must be a lowercase sha256 digest"
            )
        return value

    def require_canonical_citation(field: str) -> str:
        value = attestation.get(field)
        if not isinstance(value, str) or not value:
            issues.append(f"source_attestation.{field} must be a non-empty string")
            return ""
        try:
            require_canonical_corpus_citation_path(value)
        except CorpusResolutionError as exc:
            issues.append(
                f"source_attestation.{field} must be an exact canonical corpus "
                f"citation path: {exc}"
            )
            return ""
        return value

    require_canonical_citation("requested_corpus_citation_path")
    resolved = require_canonical_citation("resolved_corpus_citation_path")
    source = require_string("corpus_source")
    if source and source != "local":
        issues.append("source_attestation.corpus_source must be local")
    release_name = require_string("corpus_release")
    if release_name:
        try:
            validate_corpus_release_name(release_name)
        except InvalidCorpusReleaseError as exc:
            issues.append(f"source_attestation.corpus_release is invalid: {exc}")
    require_sha256("corpus_release_content_sha256")
    require_sha256("corpus_release_selector_sha256")
    provision_file = require_string("provision_file")
    if provision_file:
        provision_path = Path(provision_file)
        if (
            provision_path.is_absolute()
            or provision_path.as_posix() != provision_file
            or provision_path.parts[:3] != ("data", "corpus", "provisions")
            or any(part in {"", ".", ".."} for part in provision_path.parts)
        ):
            issues.append(
                "source_attestation.provision_file must be a canonical "
                "data/corpus/provisions path"
            )
    provision_file_sha256 = require_sha256("provision_file_sha256")
    source_sha256 = require_sha256("source_sha256")
    require_sha256("resolved_text_sha256")
    require_sha256("generation_input_sha256")

    require_string("source_as_of")
    require_string("expression_date")

    row = attestation.get("row")
    if not isinstance(row, dict):
        issues.append("source_attestation.row must be an object")
    else:
        for field in (
            "provision_file",
            "record_id",
            "citation_path",
            "jurisdiction",
            "document_class",
            "version",
            "source_path",
            "source_as_of",
            "expression_date",
        ):
            value = row.get(field)
            if not isinstance(value, str) or not value.strip():
                issues.append(
                    f"source_attestation.row.{field} must be a non-empty string"
                )
        row_citation = row.get("citation_path")
        if isinstance(row_citation, str) and row_citation:
            try:
                require_canonical_corpus_citation_path(row_citation)
            except CorpusResolutionError as exc:
                issues.append(
                    "source_attestation.row.citation_path must be an exact "
                    f"canonical corpus citation path: {exc}"
                )
        line_number = row.get("line_number")
        if (
            not isinstance(line_number, int)
            or isinstance(line_number, bool)
            or line_number < 1
        ):
            issues.append(
                "source_attestation.row.line_number must be a positive integer"
            )
        row_file_sha256 = row.get("provision_file_sha256")
        if (
            not isinstance(row_file_sha256, str)
            or _SHA256_HEX_PATTERN.fullmatch(row_file_sha256) is None
        ):
            issues.append(
                "source_attestation.row.provision_file_sha256 must be a "
                "lowercase sha256 digest"
            )
        row_body_sha256 = row.get("body_sha256")
        component_rows = attestation.get("component_rows")
        row_is_composed_parent = row_body_sha256 is None and bool(component_rows)
        if not row_is_composed_parent and (
            not isinstance(row_body_sha256, str)
            or _SHA256_HEX_PATTERN.fullmatch(row_body_sha256) is None
        ):
            issues.append(
                "source_attestation.row.body_sha256 must be a lowercase sha256 digest"
            )
        if provision_file and row.get("provision_file") != provision_file:
            issues.append(
                "source_attestation.row.provision_file does not match provision_file"
            )
        if provision_file_sha256 and row_file_sha256 != provision_file_sha256:
            issues.append(
                "source_attestation.row.provision_file_sha256 does not match "
                "provision_file_sha256"
            )
        if row_body_sha256 is not None and source_sha256 != row_body_sha256:
            issues.append(
                "source_attestation.row.body_sha256 does not match source_sha256"
            )
        if resolved and row.get("citation_path") != resolved:
            issues.append(
                "source_attestation.row.citation_path does not match resolved path"
            )
        for field in ("source_as_of", "expression_date"):
            top_value = attestation.get(field)
            if top_value is not None and row.get(field) != top_value:
                issues.append(f"source_attestation.row.{field} does not match {field}")

    component_rows = attestation.get("component_rows")
    if not isinstance(component_rows, list) or not all(
        isinstance(item, dict) for item in component_rows
    ):
        issues.append("source_attestation.component_rows must be a list of objects")
    elif component_rows:
        seen_components: set[tuple[str, int, str]] = set()
        for index, component in enumerate(component_rows):
            for field in (
                "provision_file",
                "record_id",
                "citation_path",
                "jurisdiction",
                "document_class",
                "version",
            ):
                value = component.get(field)
                if not isinstance(value, str) or not value.strip():
                    issues.append(
                        "source_attestation.component_rows"
                        f"[{index}].{field} must be a non-empty string"
                    )
            component_citation = component.get("citation_path")
            if isinstance(component_citation, str) and component_citation:
                try:
                    require_canonical_corpus_citation_path(component_citation)
                except CorpusResolutionError as exc:
                    issues.append(
                        "source_attestation.component_rows"
                        f"[{index}].citation_path must be an exact canonical "
                        f"corpus citation path: {exc}"
                    )
            component_file = component.get("provision_file")
            if isinstance(component_file, str) and component_file.strip():
                component_path = Path(component_file)
                if (
                    component_path.is_absolute()
                    or component_path.as_posix() != component_file
                    or component_path.parts[:3] != ("data", "corpus", "provisions")
                    or any(part in {"", ".", ".."} for part in component_path.parts)
                ):
                    issues.append(
                        "source_attestation.component_rows"
                        f"[{index}].provision_file must be a canonical "
                        "data/corpus/provisions path"
                    )
            component_file_sha256 = component.get("provision_file_sha256")
            if (
                not isinstance(component_file_sha256, str)
                or _SHA256_HEX_PATTERN.fullmatch(component_file_sha256) is None
            ):
                issues.append(
                    "source_attestation.component_rows"
                    f"[{index}].provision_file_sha256 must be a lowercase "
                    "sha256 digest"
                )
            component_line = component.get("line_number")
            if (
                not isinstance(component_line, int)
                or isinstance(component_line, bool)
                or component_line < 1
            ):
                issues.append(
                    "source_attestation.component_rows"
                    f"[{index}].line_number must be a positive integer"
                )
            body_sha256 = component.get("body_sha256")
            if (
                not isinstance(body_sha256, str)
                or _SHA256_HEX_PATTERN.fullmatch(body_sha256) is None
            ):
                issues.append(
                    "source_attestation.component_rows"
                    f"[{index}].body_sha256 must be a lowercase sha256 digest"
                )
            for field in ("source_path", "source_as_of", "expression_date"):
                value = component.get(field)
                if not isinstance(value, str) or not value.strip():
                    issues.append(
                        "source_attestation.component_rows"
                        f"[{index}].{field} must be a non-empty string"
                    )
            component_identity = (
                str(component.get("provision_file") or ""),
                component_line if isinstance(component_line, int) else 0,
                str(component.get("record_id") or ""),
            )
            if component_identity in seen_components:
                issues.append(
                    "source_attestation.component_rows contains duplicate row "
                    f"identity at index {index}"
                )
            seen_components.add(component_identity)

    return issues


def _source_verification_citation_paths(
    source_verification: dict[str, object],
) -> tuple[str, ...]:
    paths: list[str] = []
    singular = source_verification.get("corpus_citation_path")
    if isinstance(singular, str) and singular:
        try:
            require_canonical_corpus_citation_path(singular)
        except CorpusResolutionError:
            return ()
        paths.append(singular)
    return tuple(dict.fromkeys(paths))


def _source_attestation_binding_issues(
    attestation: dict[str, object],
    source_verification: dict[str, object],
    *,
    require_source_sha256: bool = True,
) -> list[str]:
    """Check that the attested source matches the RuleSpec's source pin."""

    issues = _source_attestation_structure_issues(attestation)
    if issues:
        return issues
    if "corpus_citation_paths" in source_verification:
        return [
            "module.source_verification.corpus_citation_paths is not supported; "
            "use exactly one resolver-attested corpus_citation_path"
        ]
    source_sha256 = source_verification.get("source_sha256")
    if source_sha256 is not None and source_sha256 != attestation.get("source_sha256"):
        issues.append(
            "module.source_verification.source_sha256 does not match "
            "source_attestation.source_sha256"
        )
    elif require_source_sha256 and source_sha256 is None:
        issues.append(
            "module.source_verification.source_sha256 does not match "
            "source_attestation.source_sha256"
        )
    declared_paths = set(_source_verification_citation_paths(source_verification))
    attested_paths = {
        str(attestation[field])
        for field in (
            "requested_corpus_citation_path",
            "resolved_corpus_citation_path",
        )
    }
    unattested_paths = declared_paths - attested_paths
    if not declared_paths:
        issues.append("module.source_verification does not declare a corpus path")
    elif unattested_paths:
        issues.append(
            "module.source_verification declares corpus path(s) not bound by "
            "source_attestation: " + ", ".join(sorted(unattested_paths))
        )
    return issues


def _stamp_generated_source_attestation_for_apply(result, output_file: Path) -> None:
    """Mechanically bind model output to the resolver's full stored source body."""

    backend = str(getattr(result, "backend", "") or "").strip().lower()
    if backend not in APPLIED_ENCODING_ENCODER_BACKENDS:
        return
    try:
        payload = yaml.safe_load(output_file.read_text())
    except (OSError, UnicodeError, yaml.YAMLError) as exc:
        raise RuntimeError(
            f"Cannot stamp source attestation in generated RuleSpec: {output_file}"
        ) from exc
    if not isinstance(payload, dict):
        return
    module = payload.get("module")
    source_verification = (
        module.get("source_verification") if isinstance(module, dict) else None
    )
    attestation = _generated_result_source_attestation(result)
    if attestation is None:
        raise RuntimeError(
            "Cannot apply a model-generated RuleSpec without resolver "
            "source_attestation"
        )
    structure_issues = _source_attestation_structure_issues(attestation)
    if structure_issues:
        raise RuntimeError(
            "Cannot apply model result with incomplete source_attestation: "
            + "; ".join(structure_issues)
        )
    if module is None:
        module = {}
        payload["module"] = module
    if not isinstance(module, dict):
        raise RuntimeError("Cannot stamp source attestation: module must be an object")
    if source_verification is None:
        source_verification = {
            "corpus_citation_path": attestation["requested_corpus_citation_path"]
        }
        module["source_verification"] = source_verification
    if not isinstance(source_verification, dict):
        raise RuntimeError(
            "Cannot stamp source attestation: module.source_verification "
            "must be an object"
        )
    if "corpus_citation_paths" in source_verification:
        raise RuntimeError(
            "Cannot apply model result: "
            "module.source_verification.corpus_citation_paths is not supported; "
            "encode other sources separately and import them"
        )
    declared_paths = _source_verification_citation_paths(source_verification)
    attested_paths = {
        str(attestation[field])
        for field in (
            "requested_corpus_citation_path",
            "resolved_corpus_citation_path",
        )
    }
    unattested_paths = set(declared_paths) - attested_paths
    if unattested_paths:
        raise RuntimeError(
            "Cannot apply model result: module.source_verification declares "
            "corpus path(s) not bound by resolver source_attestation: "
            + ", ".join(sorted(unattested_paths))
        )
    # The staleness command uses this singular path to recompute the same hash.
    source_verification["corpus_citation_path"] = attestation[
        "requested_corpus_citation_path"
    ]
    source_verification["source_sha256"] = attestation["source_sha256"]
    output_file.write_text(
        yaml.safe_dump(payload, sort_keys=False, allow_unicode=True),
        encoding="utf-8",
    )


def _supplemental_source_attestation_issues(
    supplemental_files: dict[Path, str],
    *,
    attestation: dict[str, object] | None,
    require_source_verification: bool = False,
) -> list[str]:
    """Reject supplemental RuleSpecs that cannot share the primary source pin.

    An apply manifest currently carries one primary source attestation.  It
    must not cover an automatically repaired dependent whose own corpus path or
    stored-body hash points somewhere else.  Test companions are not RuleSpec
    modules and therefore do not participate in source pinning.
    """

    issues: list[str] = []
    for relative_path, content in sorted(
        supplemental_files.items(), key=lambda item: item[0].as_posix()
    ):
        if relative_path.suffix != RULESPEC_FILE_SUFFIX or relative_path.name.endswith(
            RULESPEC_TEST_FILE_SUFFIX
        ):
            continue
        try:
            payload = yaml.safe_load(content)
        except (UnicodeError, yaml.YAMLError, ValueError) as exc:
            if require_source_verification:
                issues.append(f"{relative_path.as_posix()} is not valid YAML: {exc}")
            continue
        if not isinstance(payload, dict):
            if require_source_verification:
                issues.append(
                    f"{relative_path.as_posix()} must be a RuleSpec YAML mapping"
                )
            continue
        if payload.get("format") != "rulespec/v1":
            if require_source_verification:
                issues.append(
                    f"{relative_path.as_posix()} must declare format: rulespec/v1"
                )
            continue
        module = payload.get("module")
        verification = (
            module.get("source_verification") if isinstance(module, dict) else None
        )
        if not isinstance(verification, dict):
            if require_source_verification:
                issues.append(
                    f"{relative_path.as_posix()} is missing module.source_verification"
                )
            continue
        source_pinned = bool(_source_verification_citation_paths(verification)) or (
            "source_sha256" in verification
        )
        if not source_pinned and not require_source_verification:
            continue
        label = relative_path.as_posix()
        if attestation is None:
            issues.append(
                f"{label} declares source_verification without the primary "
                "resolver source_attestation"
            )
            continue
        issues.extend(
            f"{label}: {issue}"
            for issue in _source_attestation_binding_issues(attestation, verification)
        )
    return issues


_APPLY_VALIDATION_SNAPSHOT_ATTR = "_axiom_apply_validation_snapshot"


def _canonical_apply_relative_path(raw_path: Path) -> Path:
    """Return one content-root-relative apply path without traversal aliases."""

    path = Path(raw_path)
    if (
        path.is_absolute()
        or not path.parts
        or any(part in {"", ".", ".."} for part in path.parts)
        or path.as_posix() != str(raw_path).replace("\\", "/")
    ):
        raise RuntimeError(f"Apply path is not canonical and relative: {raw_path}")
    return path


def _apply_result_metadata(result) -> dict[str, object]:
    """Return the exact result-owned fields admitted by overlay validation."""

    tool = getattr(result, "tool", None)
    if not isinstance(tool, str) or not tool.strip():
        tool = APPLIED_ENCODING_MODEL_TOOL
    backend = str(getattr(result, "backend", "") or "").strip().lower()
    if backend not in APPLIED_ENCODING_ENCODER_BACKENDS:
        raise RuntimeError(f"Cannot sign non-generated backend {backend!r}")
    if tool != APPLIED_ENCODING_MODEL_TOOL:
        raise RuntimeError(
            "Cannot sign a model-generated RuleSpec with a non-allowlisted tool"
        )
    codex_cli_version, codex_cli_sha256 = _result_codex_cli_provenance(result)
    if backend == "codex" and (
        codex_cli_version is None or codex_cli_sha256 is None
    ):
        raise RuntimeError("Codex backend result has no trusted CLI provenance")
    return {
        "tool": tool,
        "citation": str(getattr(result, "citation", "") or ""),
        "runner": str(getattr(result, "runner", "") or ""),
        "backend": backend,
        "model": str(getattr(result, "model", "") or ""),
        "generation_prompt_sha256": getattr(result, "generation_prompt_sha256", None),
        "codex_cli_version": codex_cli_version,
        "codex_cli_sha256": codex_cli_sha256,
        "source_attestation": copy.deepcopy(
            getattr(result, "source_attestation", None)
        ),
    }


def _result_codex_cli_provenance(result) -> tuple[str | None, str | None]:
    version = getattr(result, "codex_cli_version", None)
    digest = getattr(result, "codex_cli_sha256", None)
    # Test doubles and legacy result objects expose arbitrary/missing attributes;
    # both absent means the unchanged API/non-Codex path.
    if not isinstance(version, str) and not isinstance(digest, str):
        return None, None
    if not isinstance(version, str) or not version.strip():
        raise RuntimeError("Codex CLI provenance has no canonical version")
    if not isinstance(digest, str) or re.fullmatch(r"[0-9a-f]{64}", digest) is None:
        raise RuntimeError("Codex CLI provenance has no canonical sha256")
    return version.strip(), digest


def _apply_result_metadata_sha256(result) -> str:
    """Bind writer-controlled manifest metadata used after overlay validation."""

    payload = _apply_result_metadata(result)
    try:
        encoded = json.dumps(
            payload,
            ensure_ascii=True,
            separators=(",", ":"),
            sort_keys=True,
        ).encode("utf-8")
    except (TypeError, ValueError) as exc:
        raise RuntimeError("Apply result metadata is not canonical JSON") from exc
    return hashlib.sha256(encoded).hexdigest()


def _apply_evidence_file_snapshot(result, field: str) -> dict[str, object]:
    raw_path = str(getattr(result, field, "") or "")
    if not raw_path:
        return {"path": "", "sha256": None}
    path = Path(raw_path)
    if path.is_symlink() or not path.is_file():
        raise RuntimeError(f"Apply evidence file is missing or indirect: {path}")
    return {"path": str(path.resolve()), "sha256": _sha256_file(path)}


def _apply_dependency_checkout_identity(root: Path) -> dict[str, object]:
    """Bind one explicit dependency checkout exactly as the overlay stages it."""

    checkout = Path(root).resolve()
    jurisdictions = jurisdiction_subdir_names(
        checkout,
        allow_composition_specs=True,
    )
    return {
        "path": str(checkout),
        "checkout_identity": _git_checkout_execution_identity(checkout),
        "jurisdiction_roots": [
            _rulespec_root_execution_identity(checkout / jurisdiction)
            for jurisdiction in jurisdictions
        ],
    }


def _apply_policy_content_files(content_root: Path) -> dict[str, str]:
    """Hash every regular file under one active RuleSpec content root."""

    root = Path(content_root).resolve()
    files: dict[str, str] = {}
    for directory, directory_names, file_names in os.walk(root, followlinks=False):
        directory_path = Path(directory)
        for name in list(directory_names):
            path = directory_path / name
            if path.is_symlink():
                raise RuntimeError(
                    f"RuleSpec content identity contains symlink: {path}"
                )
        directory_names.sort()
        for name in sorted(file_names):
            path = directory_path / name
            if path.is_symlink() or not path.is_file():
                raise RuntimeError(
                    f"RuleSpec content identity contains indirect file: {path}"
                )
            files[path.relative_to(root).as_posix()] = _sha256_file(path)
    return files


def _apply_validation_execution_identity(
    *,
    axiom_rules_path: Path,
    policy_repo_path: Path,
    relative_output: Path,
    rulespec_dependency_roots: Sequence[Path],
) -> dict[str, object]:
    """Hash the engine and complete RuleSpec closure used by overlay validation."""

    engine = Path(axiom_rules_path).resolve()
    content_root = _rulespec_apply_content_root(policy_repo_path, relative_output)
    dependencies = _normalize_rulespec_dependency_roots(rulespec_dependency_roots)
    encoder = _apply_encoder_execution_identity()
    return {
        "axiom_encode_identity": encoder,
        "axiom_rules_path": str(engine),
        "axiom_rules_identity": _git_checkout_execution_identity(engine),
        "policy_root_identity": _rulespec_root_execution_identity(content_root),
        "policy_content_files": _apply_policy_content_files(content_root),
        "rulespec_dependency_roots": [str(path.resolve()) for path in dependencies],
        "rulespec_dependency_identities": [
            _apply_dependency_checkout_identity(path) for path in dependencies
        ],
    }


def _runtime_attestation_path() -> Path:
    """Return the attestation path inside this interpreter's own prefix."""

    return Path(sys.base_prefix) / _RUNTIME_ATTESTATION_FILENAME


def _load_trusted_runtime_attestation() -> dict[str, str]:
    """Read and validate the root-written runtime attestation, or fail closed.

    Every failure raises so a present marker can never silently degrade to a
    weaker identity. Unknown sibling members (reserved for encode#1158) are
    tolerated for forward compatibility.
    """

    path = _runtime_attestation_path()
    try:
        raw = path.read_text(encoding="utf-8")
    except OSError as exc:
        raise RuntimeError(
            "Cannot apply generated RuleSpec: the trusted-runtime marker is set "
            f"but the runtime attestation is unreadable at {path}: {exc}"
        ) from exc
    try:
        payload = json.loads(raw)
    except (json.JSONDecodeError, ValueError) as exc:
        raise RuntimeError(
            f"Cannot apply generated RuleSpec: the runtime attestation at {path} "
            f"is not valid JSON: {exc}"
        ) from exc
    if not isinstance(payload, dict):
        raise RuntimeError(
            f"Cannot apply generated RuleSpec: the runtime attestation at {path} "
            "is not a JSON object"
        )
    if payload.get("schema") != _RUNTIME_ATTESTATION_SCHEMA:
        raise RuntimeError(
            "Cannot apply generated RuleSpec: the runtime attestation schema "
            f"{payload.get('schema')!r} is not {_RUNTIME_ATTESTATION_SCHEMA!r}"
        )
    provisioned_at = payload.get("provisioned_at")
    if not isinstance(provisioned_at, str) or not provisioned_at:
        raise RuntimeError(
            "Cannot apply generated RuleSpec: the runtime attestation is missing "
            "a provisioned_at timestamp"
        )
    encoder = payload.get("axiom_encode")
    if not isinstance(encoder, dict):
        raise RuntimeError(
            "Cannot apply generated RuleSpec: the runtime attestation lacks an "
            "axiom_encode identity object"
        )
    origin_repository = encoder.get("origin_repository")
    commit = encoder.get("commit")
    version = encoder.get("version")
    package_tree_sha256 = encoder.get("package_tree_sha256")
    if origin_repository != APPLIED_ENCODING_OFFICIAL_REPOSITORY:
        raise RuntimeError(
            "Cannot apply generated RuleSpec: the runtime attestation origin "
            f"{origin_repository!r} is not {APPLIED_ENCODING_OFFICIAL_REPOSITORY!r}"
        )
    if not isinstance(commit, str) or re.fullmatch(r"[0-9a-f]{40}", commit) is None:
        raise RuntimeError(
            "Cannot apply generated RuleSpec: the runtime attestation commit "
            f"{commit!r} is not a full 40-hex Git SHA"
        )
    if not isinstance(version, str) or not version:
        raise RuntimeError(
            "Cannot apply generated RuleSpec: the runtime attestation is missing "
            "the attested encoder version"
        )
    if (
        not isinstance(package_tree_sha256, str)
        or re.fullmatch(r"[0-9a-f]{64}", package_tree_sha256) is None
    ):
        raise RuntimeError(
            "Cannot apply generated RuleSpec: the runtime attestation "
            "package_tree_sha256 is not a 64-hex digest"
        )
    return {
        "origin_repository": origin_repository,
        "commit": commit,
        "provisioned_at": provisioned_at,
        "version": version,
        "package_tree_sha256": package_tree_sha256,
        "path": str(path),
    }


def _live_axiom_encode_apply_commit() -> str | None:
    """Tri-state view of a live Git checkout at the running package root.

    None ONLY when there is genuinely no repository (the expected git-free
    runtime state). A validated clean 40-hex commit when a trustworthy repo is
    present. RAISES when a repo is present but its identity cannot be trusted (a
    git error, a dirty tree, or a malformed HEAD), so ambiguous live evidence
    never silently degrades to "no repo, use the attestation".
    """

    root = _axiom_encode_repo_root()
    environment = dict(os.environ)
    environment.update(
        {
            "GIT_CONFIG_GLOBAL": os.devnull,
            "GIT_CONFIG_SYSTEM": os.devnull,
            "GIT_CONFIG_NOSYSTEM": "1",
            "GIT_TERMINAL_PROMPT": "0",
            "GIT_NO_REPLACE_OBJECTS": "1",
            "GIT_OPTIONAL_LOCKS": "0",
        }
    )

    def run(*args: str) -> subprocess.CompletedProcess[str]:
        return subprocess.run(
            ["git", "-C", str(root), *args],
            capture_output=True,
            text=True,
            env=environment,
            check=False,
        )

    try:
        inside = run("rev-parse", "--is-inside-work-tree")
    except OSError:
        return None
    if inside.returncode != 0:
        stderr = inside.stderr.lower()
        if "not a git repository" in stderr or "not a work tree" in stderr:
            return None
        raise RuntimeError(
            "Cannot apply generated RuleSpec: a live axiom-encode repository is "
            f"present but its worktree state is unverifiable: {inside.stderr.strip()}"
        )
    if inside.stdout.strip() != "true":
        raise RuntimeError(
            "Cannot apply generated RuleSpec: axiom-encode is inside a git dir "
            "without a work tree; refusing to resolve an ambiguous identity"
        )
    head = run("rev-parse", "HEAD")
    status = run("status", "--porcelain", "--untracked-files=no")
    if head.returncode != 0 or status.returncode != 0:
        raise RuntimeError(
            "Cannot apply generated RuleSpec: a live axiom-encode checkout is "
            "present but its commit or status could not be read"
        )
    commit = head.stdout.strip()
    if re.fullmatch(r"[0-9a-f]{40}", commit) is None:
        raise RuntimeError(
            "Cannot apply generated RuleSpec: the live axiom-encode HEAD "
            f"{commit!r} is not a full 40-hex commit"
        )
    if status.stdout.strip():
        raise RuntimeError(
            "Cannot apply generated RuleSpec: the live axiom-encode checkout is "
            "dirty; refusing to reconcile it against the trusted-runtime attestation"
        )
    return commit


def _encoder_identity_binding_core(identity: object) -> object:
    """Drop the informational ``identity_source`` before an identity match.

    A manifest written in one provenance mode is legitimately verified against a
    pinned identity resolved in another (e.g. a trusted-runtime apply verified
    later from a CI Git checkout), so the binding is on repository + commit +
    version; identity_source is validated on its own elsewhere.
    """

    if isinstance(identity, dict):
        return {
            key: value for key, value in identity.items() if key != "identity_source"
        }
    return identity


def _attestation_encoder_execution_identity() -> dict[str, object]:
    """Bind apply provenance to the root-written runtime attestation.

    The cross-repo, git-free case (a pinned encoder dependency in a rulespec
    signed-apply runtime). The executing package bytes are byte-bound to the
    attestation's recorded ``package_tree_sha256`` — mirroring, for the git-free
    runtime, the checkout-vs-runtime tree-hash equality that
    ``_apply_encoder_execution_identity`` enforces for the workflow-checkout case.
    """

    attestation = _load_trusted_runtime_attestation()
    if attestation["version"] != __version__:
        raise RuntimeError(
            "Cannot apply generated RuleSpec: the runtime attestation version "
            f"{attestation['version']!r} does not match the running encoder "
            f"__version__ {__version__!r}; the executing bytes are not the "
            "attested build."
        )
    runtime_package = _deterministic_tree_identity(
        Path(__file__).resolve().parent,
        excluded_directory_names=frozenset({"__pycache__"}),
    )
    if (
        runtime_package.get("state") != "directory"
        or runtime_package.get("tree_sha256") != attestation["package_tree_sha256"]
    ):
        raise RuntimeError(
            "Cannot apply generated RuleSpec: the running encoder package bytes do "
            "not match the trusted-runtime attestation's package_tree_sha256."
        )
    live_commit = _live_axiom_encode_apply_commit()
    if live_commit is not None and live_commit != attestation["commit"]:
        raise RuntimeError(
            "Cannot apply generated RuleSpec: the trusted-runtime attestation "
            f"commit {attestation['commit']} conflicts with the live axiom-encode "
            f"Git checkout commit {live_commit}."
        )
    return {
        "kind": APPLY_IDENTITY_SOURCE_TRUSTED_RUNTIME,
        "path": attestation["path"],
        "commit": attestation["commit"],
        "origin_repository": attestation["origin_repository"],
        "dirty": False,
        "version": __version__,
        "identity_source": APPLY_IDENTITY_SOURCE_TRUSTED_RUNTIME,
    }


def _apply_encoder_execution_identity() -> dict[str, object]:
    """Bind apply provenance to this checkout, the verified CI source checkout,
    or (cross-repo, git-free) the root-provisioned runtime attestation."""

    checkout_override = os.environ.get("AXIOM_ENCODE_APPLY_CHECKOUT")
    trusted_runtime = os.environ.get(_TRUSTED_RUNTIME_ENV) == "1"
    # Contract (d): exactly one apply-identity source may be active.
    if trusted_runtime and checkout_override:
        raise RuntimeError(
            "Cannot apply generated RuleSpec: both AXIOM_ENCODE_APPLY_CHECKOUT and "
            "the trusted-runtime attestation assert an encoder identity; exactly "
            "one apply-identity source may be active."
        )
    if trusted_runtime:
        return _attestation_encoder_execution_identity()
    checkout_root = _axiom_encode_repo_root()
    expected_ci_sha: str | None = None
    if checkout_override:
        if os.environ.get("GITHUB_ACTIONS") != "true":
            raise RuntimeError(
                "AXIOM_ENCODE_APPLY_CHECKOUT is only allowed in GitHub Actions"
            )
        workspace = os.environ.get("GITHUB_WORKSPACE")
        github_sha = os.environ.get("GITHUB_SHA")
        if (
            not workspace
            or not github_sha
            or re.fullmatch(r"[0-9a-f]{40}", github_sha) is None
        ):
            raise RuntimeError("GitHub Actions encoder checkout identity is incomplete")
        expected_checkout = Path(os.path.abspath(workspace)) / "axiom-encode"
        checkout_root = Path(os.path.abspath(checkout_override))
        try:
            canonical_checkout = checkout_root.resolve(strict=True)
        except OSError as exc:
            raise RuntimeError(
                "AXIOM_ENCODE_APPLY_CHECKOUT is not a readable checkout"
            ) from exc
        if (
            checkout_root != expected_checkout
            or canonical_checkout != checkout_root
            or not canonical_checkout.is_dir()
        ):
            raise RuntimeError(
                "AXIOM_ENCODE_APPLY_CHECKOUT must be the canonical, symlink-free "
                "workflow axiom-encode checkout"
            )
        expected_ci_sha = github_sha

    encoder = _git_checkout_execution_identity(
        checkout_root,
        pathspecs=("src/axiom_encode", "pyproject.toml", "uv.lock"),
    )
    if expected_ci_sha is not None:
        if encoder.get("path") != str(checkout_root.resolve(strict=True)):
            raise RuntimeError(
                "Workflow encoder checkout must be the Git repository top level"
            )
        if encoder.get("commit") != expected_ci_sha:
            raise RuntimeError("Workflow encoder checkout does not match GITHUB_SHA")
        versions = _axiom_encode_versions_at_ref(checkout_root, "HEAD")
        if any(
            versions.get(field) != __version__
            for field in ("pyproject", "package", "lock")
        ):
            raise RuntimeError(
                "Provisioned encoder version does not match the workflow checkout"
            )
        checkout_package = _deterministic_tree_identity(
            checkout_root / "src" / "axiom_encode",
            excluded_directory_names=frozenset({"__pycache__"}),
        )
        runtime_package = _deterministic_tree_identity(
            Path(__file__).resolve().parent,
            excluded_directory_names=frozenset({"__pycache__"}),
        )
        if (
            checkout_package.get("state") != "directory"
            or runtime_package.get("state") != "directory"
            or checkout_package.get("file_count") != runtime_package.get("file_count")
            or checkout_package.get("tree_sha256") != runtime_package.get("tree_sha256")
        ):
            raise RuntimeError(
                "Provisioned encoder package bytes do not match the workflow checkout"
            )
    encoder["version"] = __version__
    encoder["identity_source"] = (
        APPLY_IDENTITY_SOURCE_GITHUB_SHA
        if expected_ci_sha is not None
        else APPLY_IDENTITY_SOURCE_GIT
    )
    return encoder


def _portable_clean_apply_git_identity(
    identity: object,
    *,
    label: str,
    expected_repository: str,
    allow_trusted_runtime_attestation: bool = False,
) -> dict[str, str]:
    """Return a path-free commit identity for one required clean checkout.

    When ``allow_trusted_runtime_attestation`` is set (only the encoder, whose
    provenance can vary between a live checkout, a workflow checkout, and the
    root-provisioned runtime) the returned dict also records ``identity_source``
    so consumers can tell the modes apart. A ``trusted-runtime-attestation``
    identity is clean by construction and carries no live checkout path, so only
    the commit and origin are validated.
    """

    if not isinstance(identity, dict):
        raise RuntimeError(
            f"Cannot apply generated RuleSpec: {label} must be a Git checkout"
        )
    if (
        allow_trusted_runtime_attestation
        and identity.get("kind") == APPLY_IDENTITY_SOURCE_TRUSTED_RUNTIME
    ):
        commit = identity.get("commit")
        origin_repository = identity.get("origin_repository")
        if not isinstance(commit, str) or re.fullmatch(r"[0-9a-f]{40}", commit) is None:
            raise RuntimeError(
                f"Cannot apply generated RuleSpec: {label} Git identity is incomplete"
            )
        if origin_repository != expected_repository:
            raise RuntimeError(
                f"Cannot apply generated RuleSpec: {label} origin must be "
                f"{expected_repository}, got {origin_repository!r}"
            )
        return {
            "repository": expected_repository,
            "commit": commit,
            "identity_source": APPLY_IDENTITY_SOURCE_TRUSTED_RUNTIME,
        }
    if identity.get("kind") != "git":
        raise RuntimeError(
            f"Cannot apply generated RuleSpec: {label} must be a Git checkout"
        )
    if identity.get("dirty") is not False:
        raise RuntimeError(
            f"Cannot apply generated RuleSpec: {label} checkout must be clean"
        )
    path = identity.get("path")
    commit = identity.get("commit")
    origin_repository = identity.get("origin_repository")
    if (
        not isinstance(path, str)
        or not path
        or not isinstance(commit, str)
        or re.fullmatch(r"[0-9a-f]{40}", commit) is None
    ):
        raise RuntimeError(
            f"Cannot apply generated RuleSpec: {label} Git identity is incomplete"
        )
    if origin_repository != expected_repository:
        raise RuntimeError(
            f"Cannot apply generated RuleSpec: {label} origin must be "
            f"{expected_repository}, got {origin_repository!r}"
        )
    result: dict[str, str] = {"repository": expected_repository, "commit": commit}
    if allow_trusted_runtime_attestation:
        # The encoder identity carries its source so consumers can distinguish
        # git-dev / workflow-checkout / trusted-runtime provenance.
        source = identity.get("identity_source")
        result["identity_source"] = (
            source if source in _APPLY_IDENTITY_SOURCES else APPLY_IDENTITY_SOURCE_GIT
        )
    return result


def _portable_apply_validation_execution_identity(
    execution: Mapping[str, object],
) -> dict[str, object]:
    """Build the signed, path-portable validator provenance for one apply."""

    encoder = _portable_clean_apply_git_identity(
        execution.get("axiom_encode_identity"),
        label="axiom-encode",
        expected_repository="github.com/TheAxiomFoundation/axiom-encode",
        allow_trusted_runtime_attestation=True,
    )
    encoder_identity = execution.get("axiom_encode_identity")
    if not isinstance(encoder_identity, dict) or not isinstance(
        encoder_identity.get("version"), str
    ):
        raise RuntimeError(
            "Cannot apply generated RuleSpec: encoder version is missing"
        )
    encoder["version"] = str(encoder_identity["version"])
    engine = _portable_clean_apply_git_identity(
        execution.get("axiom_rules_identity"),
        label="Axiom rules engine",
        expected_repository="github.com/TheAxiomFoundation/axiom-rules-engine",
    )

    policy = execution.get("policy_root_identity")
    if not isinstance(policy, dict):
        raise RuntimeError(
            "Cannot apply generated RuleSpec: policy identity is missing"
        )
    policy_path = policy.get("path")
    if not isinstance(policy_path, str):
        raise RuntimeError("Cannot apply generated RuleSpec: policy path is missing")
    logical_policy_root = canonical_rulespec_root_identity(Path(policy_path))
    if logical_policy_root is None:
        raise RuntimeError(
            "Cannot apply generated RuleSpec: policy root is not canonical"
        )
    policy_attestation = {
        "rulespec_root": logical_policy_root,
        "pre_apply_content_sha256": policy.get("content_sha256"),
        "pre_apply_file_count": policy.get("file_count"),
        "toolchain_contract_sha256": policy.get("toolchain_contract_sha256"),
        "validation_waiver_set_sha256": policy.get("validation_waiver_set_sha256"),
    }
    if (
        not isinstance(policy_attestation["pre_apply_content_sha256"], str)
        or _SHA256_HEX_PATTERN.fullmatch(policy_attestation["pre_apply_content_sha256"])
        is None
        or not isinstance(policy_attestation["pre_apply_file_count"], int)
        or policy_attestation["pre_apply_file_count"] < 0
        or not isinstance(policy_attestation["toolchain_contract_sha256"], str)
        or _SHA256_HEX_PATTERN.fullmatch(
            policy_attestation["toolchain_contract_sha256"]
        )
        is None
        or not isinstance(policy_attestation["validation_waiver_set_sha256"], str)
        or _SHA256_HEX_PATTERN.fullmatch(
            policy_attestation["validation_waiver_set_sha256"]
        )
        is None
    ):
        raise RuntimeError(
            "Cannot apply generated RuleSpec: policy execution identity is incomplete"
        )

    dependencies_raw = execution.get("rulespec_dependency_identities")
    if not isinstance(dependencies_raw, list):
        raise RuntimeError(
            "Cannot apply generated RuleSpec: dependency identities are missing"
        )
    dependencies: list[dict[str, object]] = []
    for index, dependency in enumerate(dependencies_raw):
        if not isinstance(dependency, dict):
            raise RuntimeError(
                "Cannot apply generated RuleSpec: dependency identity is malformed"
            )
        dependency_path = dependency.get("path")
        if not isinstance(dependency_path, str):
            raise RuntimeError(
                "Cannot apply generated RuleSpec: dependency path is missing"
            )
        dependency_name = Path(dependency_path).name
        if re.fullmatch(r"rulespec-[a-z]{2}", dependency_name) is None:
            raise RuntimeError(
                "Cannot apply generated RuleSpec: dependency checkout name is not "
                f"canonical: {dependency_name}"
            )
        expected_dependency_repository = (
            f"github.com/TheAxiomFoundation/{dependency_name}"
        )
        checkout = _portable_clean_apply_git_identity(
            dependency.get("checkout_identity"),
            label=f"RuleSpec dependency #{index + 1}",
            expected_repository=expected_dependency_repository,
        )
        jurisdiction_roots_raw = dependency.get("jurisdiction_roots")
        if not isinstance(jurisdiction_roots_raw, list):
            raise RuntimeError(
                "Cannot apply generated RuleSpec: dependency jurisdictions are missing"
            )
        jurisdiction_roots: list[dict[str, object]] = []
        for jurisdiction in jurisdiction_roots_raw:
            if not isinstance(jurisdiction, dict) or not isinstance(
                jurisdiction.get("path"), str
            ):
                raise RuntimeError(
                    "Cannot apply generated RuleSpec: dependency jurisdiction "
                    "identity is malformed"
                )
            logical_root = canonical_rulespec_root_identity(
                Path(str(jurisdiction["path"]))
            )
            if logical_root is None:
                raise RuntimeError(
                    "Cannot apply generated RuleSpec: dependency jurisdiction "
                    "root is not canonical"
                )
            jurisdiction_roots.append(
                {
                    "rulespec_root": logical_root,
                    "content_sha256": jurisdiction.get("content_sha256"),
                    "file_count": jurisdiction.get("file_count"),
                    "toolchain_contract_sha256": jurisdiction.get(
                        "toolchain_contract_sha256"
                    ),
                    "validation_waiver_set_sha256": jurisdiction.get(
                        "validation_waiver_set_sha256"
                    ),
                }
            )
            jurisdiction_attestation = jurisdiction_roots[-1]
            if (
                not isinstance(jurisdiction_attestation["content_sha256"], str)
                or _SHA256_HEX_PATTERN.fullmatch(
                    jurisdiction_attestation["content_sha256"]
                )
                is None
                or not isinstance(jurisdiction_attestation["file_count"], int)
                or jurisdiction_attestation["file_count"] < 0
                or not isinstance(
                    jurisdiction_attestation["toolchain_contract_sha256"], str
                )
                or _SHA256_HEX_PATTERN.fullmatch(
                    jurisdiction_attestation["toolchain_contract_sha256"]
                )
                is None
                or not isinstance(
                    jurisdiction_attestation["validation_waiver_set_sha256"], str
                )
                or _SHA256_HEX_PATTERN.fullmatch(
                    jurisdiction_attestation["validation_waiver_set_sha256"]
                )
                is None
            ):
                raise RuntimeError(
                    "Cannot apply generated RuleSpec: dependency jurisdiction "
                    "content identity is incomplete"
                )
        dependencies.append(
            {
                **checkout,
                "jurisdiction_roots": jurisdiction_roots,
            }
        )

    return {
        "schema": "axiom-encode/apply-validation-execution/v1",
        "axiom_encode": encoder,
        "axiom_rules_engine": engine,
        "policy_pre_apply": policy_attestation,
        "rulespec_dependencies": dependencies,
    }


def _build_apply_validation_snapshot(
    result,
    *,
    output_root: Path,
    policy_repo_path: Path,
    relative_output: Path,
    supplemental_files: Mapping[Path, str],
    local_corpus_release: LocalCorpusRelease,
    validation_execution_identity: Mapping[str, object],
) -> dict[str, object]:
    """Hash the exact artifacts and identities admitted by overlay validation."""

    output_file = Path(str(getattr(result, "output_file", "") or ""))
    if output_file.is_symlink() or not output_file.is_file():
        raise RuntimeError(
            f"Generated output file is missing or indirect: {output_file}"
        )
    canonical_relative_output = _canonical_apply_relative_path(relative_output)
    expected_relative_output = _relative_generated_output_path(
        result,
        output_root=output_root,
    )
    if expected_relative_output != canonical_relative_output:
        raise RuntimeError("Generated output path changed after overlay validation")

    test_file = _rulespec_test_path(output_file)
    if test_file.is_symlink():
        raise RuntimeError(
            f"Generated companion test must not be a symlink: {test_file}"
        )
    test_snapshot: dict[str, object] = {
        "path": str(test_file.resolve()),
        "exists": test_file.is_file(),
        "sha256": _sha256_file(test_file) if test_file.is_file() else None,
    }
    supplemental_snapshot = [
        {
            "path": _canonical_apply_relative_path(path).as_posix(),
            "sha256": hashlib.sha256(content.encode("utf-8")).hexdigest(),
        }
        for path, content in sorted(
            supplemental_files.items(), key=lambda item: Path(item[0]).as_posix()
        )
    ]
    return {
        "schema": "axiom-encode/apply-validation-snapshot/v1",
        "relative_output": canonical_relative_output.as_posix(),
        "policy_content_root": str(
            _rulespec_apply_content_root(
                policy_repo_path,
                canonical_relative_output,
            ).resolve()
        ),
        "corpus_release": local_corpus_release.name,
        "corpus_release_content_sha256": local_corpus_release.content_sha256,
        "corpus_release_selector_sha256": local_corpus_release.selector_sha256,
        "output": {
            "path": str(output_file.resolve()),
            "sha256": _sha256_file(output_file),
        },
        "test": test_snapshot,
        "context_manifest": _apply_evidence_file_snapshot(
            result, "context_manifest_file"
        ),
        "trace": _apply_evidence_file_snapshot(result, "trace_file"),
        "result_metadata": _apply_result_metadata(result),
        "result_metadata_sha256": _apply_result_metadata_sha256(result),
        "supplemental": supplemental_snapshot,
        "validation_execution": copy.deepcopy(dict(validation_execution_identity)),
        "manifest_validation_execution": (
            _portable_apply_validation_execution_identity(validation_execution_identity)
        ),
    }


def _record_successful_apply_validation(
    result,
    *,
    output_root: Path,
    policy_repo_path: Path,
    relative_output: Path,
    supplemental_files: Mapping[Path, str],
    local_corpus_release: LocalCorpusRelease,
    axiom_rules_path: Path,
    rulespec_dependency_roots: Sequence[Path] = (),
) -> None:
    """Persist the exact successful overlay boundary on the in-memory result."""

    setattr(
        result,
        _APPLY_VALIDATION_SNAPSHOT_ATTR,
        _build_apply_validation_snapshot(
            result,
            output_root=output_root,
            policy_repo_path=policy_repo_path,
            relative_output=relative_output,
            supplemental_files=supplemental_files,
            local_corpus_release=local_corpus_release,
            validation_execution_identity=_apply_validation_execution_identity(
                axiom_rules_path=axiom_rules_path,
                policy_repo_path=policy_repo_path,
                relative_output=relative_output,
                rulespec_dependency_roots=rulespec_dependency_roots,
            ),
        ),
    )


def _require_unchanged_successful_apply_validation(
    result,
    *,
    output_root: Path,
    policy_repo_path: Path,
    relative_output: Path,
    supplemental_files: Mapping[Path, str],
    local_corpus_release: LocalCorpusRelease,
) -> None:
    """Reject apply when any artifact changed since the successful overlay run."""

    expected = getattr(result, _APPLY_VALIDATION_SNAPSHOT_ATTR, None)
    if not isinstance(expected, dict):
        raise RuntimeError(
            "Cannot apply generated RuleSpec without a successful bound overlay "
            "validation snapshot"
        )
    validation_execution = expected.get("validation_execution")
    if not isinstance(validation_execution, dict):
        raise RuntimeError("Apply validation snapshot lacks execution identity")
    axiom_rules_path = validation_execution.get("axiom_rules_path")
    dependency_roots = validation_execution.get("rulespec_dependency_roots")
    if (
        not isinstance(axiom_rules_path, str)
        or not isinstance(dependency_roots, list)
        or not all(isinstance(path, str) for path in dependency_roots)
    ):
        raise RuntimeError("Apply validation snapshot has malformed execution inputs")
    actual = _build_apply_validation_snapshot(
        result,
        output_root=output_root,
        policy_repo_path=policy_repo_path,
        relative_output=relative_output,
        supplemental_files=supplemental_files,
        local_corpus_release=local_corpus_release,
        validation_execution_identity=_apply_validation_execution_identity(
            axiom_rules_path=Path(axiom_rules_path),
            policy_repo_path=policy_repo_path,
            relative_output=relative_output,
            rulespec_dependency_roots=tuple(Path(path) for path in dependency_roots),
        ),
    )
    if actual != expected:
        raise RuntimeError(
            "Cannot apply generated RuleSpec: validated artifacts or provenance "
            "changed after overlay validation"
        )


def _planned_apply_file_bytes(
    output_file: Path,
    *,
    relative_output: Path,
    supplemental_files: Mapping[Path, str],
) -> tuple[dict[Path, bytes], bool]:
    """Materialize the exact validated bytes to install under one content root."""

    planned: dict[Path, bytes] = {
        _canonical_apply_relative_path(relative_output): output_file.read_bytes()
    }
    test_source = _rulespec_test_path(output_file)
    relative_test = _rulespec_test_path(relative_output)
    wrote_empty_companion_test = False
    if test_source.is_file():
        planned[_canonical_apply_relative_path(relative_test)] = (
            test_source.read_bytes()
        )
    elif _needs_empty_deferred_companion_test(output_file):
        planned[_canonical_apply_relative_path(relative_test)] = b"[]\n"
        wrote_empty_companion_test = True

    roots = tuple(sorted(RULESPEC_ATOMIC_MODULE_ROOTS))
    for raw_path, content in supplemental_files.items():
        path = _canonical_apply_relative_path(raw_path)
        if not _is_protected_rulespec_yaml_path(path, roots=roots):
            raise RuntimeError(
                f"Supplemental apply path is not protected RuleSpec YAML: {path}"
            )
        if not isinstance(content, str):
            raise RuntimeError(f"Supplemental apply content is not text: {path}")
        planned[path] = content.encode("utf-8")
    return planned, wrote_empty_companion_test


def _require_planned_apply_bytes_match_validation_snapshot(
    result,
    planned: Mapping[Path, bytes],
    *,
    relative_output: Path,
    wrote_empty_companion_test: bool,
) -> None:
    """Reject bytes captured during a swap-and-restore after validation."""

    snapshot = getattr(result, _APPLY_VALIDATION_SNAPSHOT_ATTR, None)
    if not isinstance(snapshot, dict):
        raise RuntimeError("Apply validation snapshot is missing")
    output = snapshot.get("output")
    test = snapshot.get("test")
    supplemental = snapshot.get("supplemental")
    if (
        not isinstance(output, dict)
        or not isinstance(test, dict)
        or not isinstance(supplemental, list)
    ):
        raise RuntimeError("Apply validation snapshot has malformed artifact bindings")

    expected: dict[Path, str] = {}
    canonical_output = _canonical_apply_relative_path(relative_output)
    output_sha256 = output.get("sha256")
    if not isinstance(output_sha256, str):
        raise RuntimeError("Apply validation snapshot lacks generated output digest")
    expected[canonical_output] = output_sha256

    relative_test = _canonical_apply_relative_path(
        _rulespec_test_path(canonical_output)
    )
    if test.get("exists") is True:
        test_sha256 = test.get("sha256")
        if not isinstance(test_sha256, str):
            raise RuntimeError("Apply validation snapshot lacks companion test digest")
        expected[relative_test] = test_sha256
    elif wrote_empty_companion_test:
        expected[relative_test] = hashlib.sha256(b"[]\n").hexdigest()

    for item in supplemental:
        if not isinstance(item, dict):
            raise RuntimeError(
                "Apply validation snapshot has malformed supplemental binding"
            )
        raw_path = item.get("path")
        sha256 = item.get("sha256")
        if not isinstance(raw_path, str) or not isinstance(sha256, str):
            raise RuntimeError(
                "Apply validation snapshot has malformed supplemental binding"
            )
        expected[_canonical_apply_relative_path(Path(raw_path))] = sha256

    actual = {
        _canonical_apply_relative_path(path): hashlib.sha256(raw).hexdigest()
        for path, raw in planned.items()
    }
    if actual != expected:
        raise RuntimeError(
            "Cannot apply generated RuleSpec: planned bytes do not match the "
            "successful overlay validation snapshot"
        )


def _planned_manifest_source_verifications(
    content_root: Path,
    planned: Mapping[Path, bytes],
) -> tuple[list[tuple[str, dict[str, object]]], str]:
    """Load source bindings only from the already snapshot-checked apply bytes."""

    root_identity = canonical_rulespec_root_identity(content_root)
    if root_identity is None:
        raise RuntimeError("Cannot derive canonical RuleSpec root for staged manifest")
    verifications: list[tuple[str, dict[str, object]]] = []
    for raw_relative, raw in planned.items():
        relative = _canonical_apply_relative_path(raw_relative)
        if not _is_protected_rulespec_yaml_path(
            relative,
            roots=tuple(sorted(RULESPEC_ATOMIC_MODULE_ROOTS)),
        ) or relative.name.endswith(RULESPEC_TEST_FILE_SUFFIX):
            continue
        label = (Path(content_root.name) / relative).as_posix()
        try:
            rulespec = yaml.safe_load(raw.decode("utf-8"))
        except (UnicodeError, yaml.YAMLError, RecursionError) as exc:
            raise RuntimeError(
                f"Cannot attest planned apply bytes for {label}: invalid YAML"
            ) from exc
        if not isinstance(rulespec, dict) or rulespec.get("format") != "rulespec/v1":
            raise RuntimeError(
                f"Cannot attest planned apply bytes for {label}: expected rulespec/v1"
            )
        plural_source_issues = find_plural_corpus_citation_path_issues(rulespec)
        if plural_source_issues:
            raise RuntimeError(
                f"Cannot attest planned apply bytes for {label}: "
                + "; ".join(plural_source_issues)
            )
        module = rulespec.get("module")
        verification = (
            module.get("source_verification") if isinstance(module, dict) else None
        )
        if not isinstance(verification, dict):
            raise RuntimeError(
                f"Cannot attest planned apply bytes for {label}: missing "
                "module.source_verification"
            )
        if not _source_verification_citation_paths(verification):
            raise RuntimeError(
                f"Cannot attest planned apply bytes for {label}: missing corpus source"
            )
        verifications.append((label, verification))
    if not verifications:
        raise RuntimeError(
            "Cannot attest a staged manifest without a protected primary RuleSpec"
        )
    return verifications, root_identity


def _expected_planned_manifest_source_attestation(
    *,
    result_metadata: Mapping[str, object],
    content_root: Path,
    planned: Mapping[Path, bytes],
    local_corpus_release: LocalCorpusRelease,
) -> dict[str, object]:
    """Resolve the exact attestation allowed for snapshot-checked apply bytes."""

    backend = str(result_metadata.get("backend") or "").strip().lower()
    if backend not in APPLIED_ENCODING_GENERATED_BACKENDS:
        raise RuntimeError(f"Cannot attest non-generated backend {backend!r}")
    verifications, rulespec_root = _planned_manifest_source_verifications(
        content_root,
        planned,
    )
    provided_raw = result_metadata.get("source_attestation")
    provided = copy.deepcopy(provided_raw) if isinstance(provided_raw, dict) else None
    if backend in APPLIED_ENCODING_ENCODER_BACKENDS:
        if provided is None:
            raise RuntimeError(
                "Cannot attest model-generated planned bytes without source_attestation"
            )
        candidate_paths = [str(provided["requested_corpus_citation_path"])]
    else:
        candidate_paths = sorted(
            {
                citation_path
                for _relative, verification in verifications
                for citation_path in _source_verification_citation_paths(verification)
            }
        )

    failures: list[str] = []
    for citation_path in candidate_paths:
        candidate = _resolver_attestation_for_manifest_source(
            citation_path,
            local_corpus_release=local_corpus_release,
            rulespec_root=rulespec_root,
        )
        if provided is not None:
            mismatched_fields = [
                field
                for field, expected in candidate.items()
                if field != "rulespec_root" and provided.get(field) != expected
            ]
            if mismatched_fields:
                raise RuntimeError(
                    "Validated source_attestation differs from the exact signed "
                    "corpus release: " + ", ".join(sorted(mismatched_fields))
                )
        binding_issues = [
            f"{relative}: {issue}"
            for relative, verification in verifications
            for issue in _source_attestation_binding_issues(
                candidate,
                verification,
                require_source_sha256=(backend in APPLIED_ENCODING_ENCODER_BACKENDS),
            )
        ]
        if not binding_issues:
            return candidate
        failures.extend(binding_issues)
    raise RuntimeError(
        "Cannot bind staged manifest source attestation to planned bytes: "
        + "; ".join(dict.fromkeys(failures))
    )


def _stage_signed_apply_manifest(
    result,
    *,
    output_root: Path,
    content_root: Path,
    corpus_path: Path,
    relative_output: Path,
    planned: Mapping[Path, bytes],
    run_id: str | None,
    signing_broker: SigningBroker,
    axiom_encode_git: dict[str, object],
    allow_shrink: bool = False,
) -> tuple[Path, bytes]:
    """Build and sign the complete manifest in an isolated canonical checkout."""

    checkout_root = _rulespec_checkout_root(content_root)
    toolchain = load_rulespec_toolchain(content_root)
    if toolchain.root != checkout_root:
        raise RuntimeError("RuleSpec toolchain root changed during apply staging")

    with tempfile.TemporaryDirectory(
        dir=checkout_root.parent,
        prefix=f".{checkout_root.name}-apply-stage-",
    ) as temporary:
        staged_checkout = Path(temporary) / checkout_root.name
        staged_content_root = staged_checkout / content_root.name
        staged_content_root.mkdir(parents=True)
        for config_relative in (
            Path(".axiom/toolchain.toml"),
            Path("known-validation-gaps.yaml"),
        ):
            source = checkout_root / config_relative
            raw = read_bounded_regular_file(
                checkout_root,
                source,
                label=f"RuleSpec apply staging file {config_relative}",
                max_bytes=2_000_000,
            )
            target = staged_checkout / config_relative
            target.parent.mkdir(parents=True, exist_ok=True)
            target.write_bytes(raw)

        staged_applied: list[Path] = []
        for relative_path, raw in planned.items():
            target = staged_content_root / relative_path
            target.parent.mkdir(parents=True, exist_ok=True)
            target.write_bytes(raw)
            staged_applied.append(target)

        staged_manifest = _write_applied_encoding_manifest(
            result,
            output_root=output_root,
            policy_repo_path=staged_content_root,
            corpus_path=corpus_path,
            relative_output=relative_output,
            applied_files=staged_applied,
            run_id=run_id,
            signing_broker=signing_broker,
            axiom_encode_git=axiom_encode_git,
            existing_manifest_path=(
                checkout_root
                / _applied_encoding_manifest_path(
                    Path(content_root.name) / relative_output
                )
            ),
            allow_shrink=allow_shrink,
        )
        manifest_relative = staged_manifest.relative_to(staged_checkout)
        return manifest_relative, staged_manifest.read_bytes()


def _require_staged_manifest_matches_validation_snapshot(
    result,
    manifest_bytes: bytes,
    *,
    output_root: Path,
    content_root: Path,
    planned: Mapping[Path, bytes],
    run_id: str | None,
    signing_broker: SigningBroker,
    axiom_encode_git: Mapping[str, object],
    local_corpus_release: LocalCorpusRelease,
) -> None:
    """Reject a manifest built from transient bytes or execution metadata."""

    snapshot = getattr(result, _APPLY_VALIDATION_SNAPSHOT_ATTR, None)
    if not isinstance(snapshot, dict):
        raise RuntimeError("Apply validation snapshot is missing")
    try:
        payload = json.loads(manifest_bytes.decode("utf-8"))
    except (UnicodeError, json.JSONDecodeError) as exc:
        raise RuntimeError("Staged apply manifest is not valid JSON") from exc
    if not isinstance(payload, dict):
        raise RuntimeError("Staged apply manifest must be a JSON object")
    signature_issue = _applied_encoding_manifest_signature_issue(
        payload,
        signing_broker,
    )
    if signature_issue:
        raise RuntimeError(f"Staged apply manifest {signature_issue}")

    result_metadata = snapshot.get("result_metadata")
    validation_execution = snapshot.get("validation_execution")
    manifest_validation_execution = snapshot.get("manifest_validation_execution")
    output = snapshot.get("output")
    trace = snapshot.get("trace")
    context = snapshot.get("context_manifest")
    if (
        not isinstance(result_metadata, dict)
        or not isinstance(validation_execution, dict)
        or not isinstance(manifest_validation_execution, dict)
        or not isinstance(output, dict)
        or not isinstance(trace, dict)
        or not isinstance(context, dict)
    ):
        raise RuntimeError("Apply validation snapshot has malformed manifest bindings")

    release_identity = (
        local_corpus_release.name,
        local_corpus_release.content_sha256,
        local_corpus_release.selector_sha256,
    )
    expected_release_identity = (
        snapshot.get("corpus_release"),
        snapshot.get("corpus_release_content_sha256"),
        snapshot.get("corpus_release_selector_sha256"),
    )
    if release_identity != expected_release_identity:
        raise RuntimeError(
            "Staged apply manifest used a different signed corpus release"
        )

    policy_identity = validation_execution.get("policy_root_identity")
    encoder_identity = validation_execution.get("axiom_encode_identity")
    if not isinstance(policy_identity, dict) or not isinstance(encoder_identity, dict):
        raise RuntimeError("Apply validation snapshot lacks execution provenance")
    encoder_kind = encoder_identity.get("kind")
    if (
        encoder_kind not in ("git", APPLY_IDENTITY_SOURCE_TRUSTED_RUNTIME)
        or encoder_identity.get("dirty") is not False
    ):
        raise RuntimeError(
            "Cannot sign an apply manifest from an uncommitted encoder execution"
        )
    # Path B (axiom_encode_git) and Path A (encoder_identity) are two views of the
    # same encoder identity and must agree on root/commit/version. In
    # trusted-runtime mode the shared "root" is the attestation path Path A also
    # recorded as its "path", so this cross-check holds unchanged for both modes.
    if (
        axiom_encode_git.get("root") != encoder_identity.get("path")
        or axiom_encode_git.get("commit") != encoder_identity.get("commit")
        or axiom_encode_git.get("dirty_tracked") is not False
        or axiom_encode_git.get("version") != encoder_identity.get("version")
    ):
        raise RuntimeError(
            "Staged apply manifest encoder provenance does not match overlay validation"
        )
    if encoder_kind == APPLY_IDENTITY_SOURCE_TRUSTED_RUNTIME and (
        axiom_encode_git.get("identity_source") != APPLY_IDENTITY_SOURCE_TRUSTED_RUNTIME
        or encoder_identity.get("identity_source")
        != APPLY_IDENTITY_SOURCE_TRUSTED_RUNTIME
    ):
        raise RuntimeError(
            "Staged apply manifest encoder provenance does not match overlay validation"
        )

    expected_source_attestation = _expected_planned_manifest_source_attestation(
        result_metadata=result_metadata,
        content_root=content_root,
        planned=planned,
        local_corpus_release=local_corpus_release,
    )
    expected_applied_files = [
        {
            "path": (Path(content_root.name) / relative).as_posix(),
            "sha256": hashlib.sha256(raw).hexdigest(),
        }
        for relative, raw in planned.items()
    ]
    expected_fields = {
        "schema_version": APPLIED_ENCODING_MANIFEST_SCHEMA,
        "tool": result_metadata.get("tool"),
        "axiom_encode_version": __version__,
        "axiom_encode_git": dict(axiom_encode_git),
        "generation_prompt_sha256": result_metadata.get("generation_prompt_sha256"),
        "run_id": run_id,
        "citation": result_metadata.get("citation"),
        "runner": result_metadata.get("runner"),
        "backend": result_metadata.get("backend"),
        "model": result_metadata.get("model"),
        VALIDATION_WAIVER_SET_SHA256_FIELD: policy_identity.get(
            "validation_waiver_set_sha256"
        ),
        "generated_output_root": str(output_root),
        "generated_output_file": output.get("path"),
        "generated_output_sha256": output.get("sha256"),
        "trace_file": trace.get("path") or None,
        "trace_sha256": trace.get("sha256"),
        "context_manifest_file": context.get("path") or None,
        "context_manifest_sha256": context.get("sha256"),
        "applied_files": expected_applied_files,
        "source_attestation": expected_source_attestation,
        "validation_execution": manifest_validation_execution,
    }
    if result_metadata.get("codex_cli_version") is not None:
        expected_fields["codex_cli_version"] = result_metadata["codex_cli_version"]
        expected_fields["codex_cli_sha256"] = result_metadata["codex_cli_sha256"]
    mismatched = [
        field
        for field, expected in expected_fields.items()
        if payload.get(field) != expected
    ]
    if mismatched:
        raise RuntimeError(
            "Staged apply manifest does not match the successful validation "
            "snapshot: " + ", ".join(sorted(mismatched))
        )


def _ensure_safe_apply_target(checkout_root: Path, target: Path) -> None:
    """Reject indirect or escaping live targets before starting installation."""

    checkout_root = checkout_root.resolve()
    try:
        relative = target.relative_to(checkout_root)
    except ValueError as exc:
        raise RuntimeError(f"Apply target escapes RuleSpec checkout: {target}") from exc
    cursor = checkout_root
    for part in relative.parts:
        cursor = cursor / part
        if cursor.is_symlink():
            raise RuntimeError(f"Apply target path contains a symlink: {cursor}")
    if target.exists() and not target.is_file():
        raise RuntimeError(f"Apply target is not a regular file: {target}")


def _atomic_replace_bytes(target: Path, raw: bytes, *, mode: int = 0o644) -> None:
    """Atomically replace one file with already validated bytes."""

    _ensure_durable_directory(target.parent)
    descriptor, temporary = tempfile.mkstemp(
        dir=target.parent,
        prefix=f".{target.name}.apply-",
    )
    temporary_path = Path(temporary)
    try:
        with os.fdopen(descriptor, "wb") as handle:
            handle.write(raw)
            handle.flush()
            os.fchmod(handle.fileno(), mode)
            os.fsync(handle.fileno())
        os.replace(temporary_path, target)
        _fsync_directory(target.parent)
    finally:
        temporary_path.unlink(missing_ok=True)


_APPLY_TRANSACTION_SCHEMA = "axiom-encode/apply-transaction/v2"
_APPLY_TRANSACTION_DIRECTORY = Path(".axiom/.apply-transaction")
_MAX_APPLY_TRANSACTION_ENTRIES = 1_024
_MAX_APPLY_TRANSACTION_DIRECTORIES = 8_192
_MAX_APPLY_TRANSACTION_JOURNAL_BYTES = 4 * 1024 * 1024
_MAX_APPLY_TRANSACTION_FILE_BYTES = 16 * 1024 * 1024
_MAX_APPLY_TRANSACTION_RECOVERY_BYTES = 256 * 1024 * 1024


def _fsync_directory(path: Path) -> None:
    """Persist directory-entry changes before a transaction advances."""

    flags = os.O_RDONLY | getattr(os, "O_DIRECTORY", 0)
    descriptor = os.open(path, flags)
    try:
        os.fsync(descriptor)
    finally:
        os.close(descriptor)


def _ensure_durable_directory(path: Path, *, mode: int = 0o755) -> list[Path]:
    """Create missing ancestors and persist every new directory entry."""

    directory = Path(os.path.abspath(Path(path).expanduser()))
    missing: list[Path] = []
    cursor = directory
    while True:
        if cursor.is_symlink():
            raise RuntimeError(f"Directory path contains a symlink: {cursor}")
        try:
            metadata = cursor.stat()
        except FileNotFoundError:
            missing.append(cursor)
            parent = cursor.parent
            if parent == cursor:
                raise RuntimeError(f"Cannot find an existing ancestor for {directory}")
            cursor = parent
            continue
        if not stat.S_ISDIR(metadata.st_mode):
            raise RuntimeError(f"Directory path contains a non-directory: {cursor}")
        break

    created: list[Path] = []
    for candidate in reversed(missing):
        parent = candidate.parent
        try:
            candidate.mkdir(mode=mode)
        except FileExistsError as exc:
            if candidate.is_symlink() or not candidate.is_dir():
                raise RuntimeError(
                    f"Directory path changed while it was being created: {candidate}"
                ) from exc
        else:
            _fsync_directory(parent)
            created.append(candidate)
    return created


def _require_private_owned_directory(path: Path, *, label: str) -> os.stat_result:
    """Require one non-symlink directory owned privately by this user."""

    try:
        metadata = path.lstat()
    except OSError as exc:
        raise RuntimeError(f"{label} is unavailable: {path}: {exc}") from exc
    if not stat.S_ISDIR(metadata.st_mode):
        raise RuntimeError(f"{label} is not a regular directory: {path}")
    if metadata.st_uid != os.getuid():
        raise RuntimeError(f"{label} is not owned by the current user: {path}")
    if stat.S_IMODE(metadata.st_mode) & 0o077:
        raise RuntimeError(f"{label} must not be accessible by group or other: {path}")
    return metadata


def _read_bounded_nofollow_regular_file(
    path: Path,
    *,
    label: str,
    max_bytes: int,
    require_private: bool,
) -> tuple[bytes, os.stat_result]:
    """Read one bounded regular file through a non-following descriptor."""

    flags = os.O_RDONLY | getattr(os, "O_CLOEXEC", 0) | getattr(os, "O_NONBLOCK", 0)
    if hasattr(os, "O_NOFOLLOW"):
        flags |= os.O_NOFOLLOW
    try:
        descriptor = os.open(path, flags)
    except OSError as exc:
        raise RuntimeError(f"{label} cannot be opened safely: {path}: {exc}") from exc
    try:
        os.set_inheritable(descriptor, False)
        before = os.fstat(descriptor)
        if not stat.S_ISREG(before.st_mode):
            raise RuntimeError(f"{label} is not a regular file: {path}")
        if before.st_nlink != 1:
            raise RuntimeError(f"{label} must have exactly one hard link: {path}")
        if require_private:
            if before.st_uid != os.getuid():
                raise RuntimeError(f"{label} is not owned by the current user: {path}")
            if stat.S_IMODE(before.st_mode) & 0o077:
                raise RuntimeError(
                    f"{label} must not be accessible by group or other: {path}"
                )
        if before.st_size > max_bytes:
            raise RuntimeError(
                f"{label} exceeds the {max_bytes}-byte safety limit: {path}"
            )

        chunks: list[bytes] = []
        total = 0
        while True:
            chunk = os.read(descriptor, min(1024 * 1024, max_bytes + 1 - total))
            if not chunk:
                break
            chunks.append(chunk)
            total += len(chunk)
            if total > max_bytes:
                raise RuntimeError(
                    f"{label} exceeds the {max_bytes}-byte safety limit: {path}"
                )
        after = os.fstat(descriptor)
        identity_fields = (
            "st_dev",
            "st_ino",
            "st_mode",
            "st_nlink",
            "st_uid",
            "st_size",
            "st_mtime_ns",
            "st_ctime_ns",
        )
        if any(
            getattr(before, field) != getattr(after, field) for field in identity_fields
        ):
            raise RuntimeError(f"{label} changed while it was being read: {path}")
        raw = b"".join(chunks)
        if len(raw) != after.st_size:
            raise RuntimeError(f"{label} changed while it was being read: {path}")
        return raw, after
    finally:
        os.close(descriptor)


def _require_private_lock_file(descriptor: int, path: Path) -> None:
    """Validate the inode used for the checkout-wide advisory lock."""

    metadata = os.fstat(descriptor)
    if not stat.S_ISREG(metadata.st_mode) or metadata.st_nlink != 1:
        raise RuntimeError(f"RuleSpec apply lock is not a private regular file: {path}")
    if metadata.st_uid != os.getuid() or stat.S_IMODE(metadata.st_mode) & 0o077:
        raise RuntimeError(f"RuleSpec apply lock is not private to this user: {path}")


@contextlib.contextmanager
def _exclusive_apply_transaction_lock(checkout_root: Path):
    """Serialize all sanctioned mutations of one RuleSpec checkout."""

    checkout_root = Path(checkout_root).resolve(strict=True)
    axiom_dir = checkout_root / ".axiom"
    _ensure_durable_directory(axiom_dir)
    lock_dir = Path(tempfile.gettempdir()) / f"axiom-encode-locks-{os.getuid()}"
    _ensure_durable_directory(lock_dir, mode=0o700)
    _require_private_owned_directory(
        lock_dir,
        label="RuleSpec apply lock directory",
    )
    lock_name = hashlib.sha256(str(checkout_root).encode()).hexdigest() + ".lock"
    lock_path = lock_dir / lock_name
    flags = os.O_RDWR | os.O_CREAT | getattr(os, "O_CLOEXEC", 0)
    if hasattr(os, "O_NOFOLLOW"):
        flags |= os.O_NOFOLLOW
    try:
        descriptor = os.open(lock_path, flags, 0o600)
    except OSError as exc:
        raise RuntimeError(
            f"Cannot open RuleSpec apply transaction lock: {exc}"
        ) from exc
    try:
        os.set_inheritable(descriptor, False)
        _require_private_lock_file(descriptor, lock_path)
        try:
            fcntl.flock(descriptor, fcntl.LOCK_EX | fcntl.LOCK_NB)
        except BlockingIOError as exc:
            raise RuntimeError(
                f"Another RuleSpec apply transaction holds {lock_path}"
            ) from exc
        yield
    finally:
        with contextlib.suppress(OSError):
            fcntl.flock(descriptor, fcntl.LOCK_UN)
        os.close(descriptor)


def _apply_transaction_file_digest(path: Path) -> str | None:
    """Return a regular file digest, ``None`` for absence, and reject indirection."""

    snapshot = _apply_transaction_file_snapshot(path)
    if snapshot is None:
        return None
    _raw, digest, _mode = snapshot
    return digest


def _apply_transaction_file_snapshot(path: Path) -> tuple[bytes, str, int] | None:
    """Read a bounded live target without following its final component."""

    try:
        path.lstat()
    except FileNotFoundError:
        return None
    except OSError as exc:
        raise RuntimeError(
            f"Cannot inspect apply transaction target {path}: {exc}"
        ) from exc
    raw, metadata = _read_bounded_nofollow_regular_file(
        path,
        label="Apply transaction target",
        max_bytes=_MAX_APPLY_TRANSACTION_FILE_BYTES,
        require_private=False,
    )
    mode = stat.S_IMODE(metadata.st_mode)
    if mode > 0o777:
        raise RuntimeError(
            f"Apply transaction target has unsupported special mode bits: {path}"
        )
    return raw, hashlib.sha256(raw).hexdigest(), mode


def _apply_transaction_relative_path(checkout_root: Path, target: Path) -> str:
    try:
        relative = target.relative_to(checkout_root)
    except ValueError as exc:
        raise RuntimeError(
            f"Apply transaction target escapes checkout: {target}"
        ) from exc
    if not relative.parts or any(part in {"", ".", ".."} for part in relative.parts):
        raise RuntimeError(f"Apply transaction target is not canonical: {target}")
    return relative.as_posix()


def _is_canonical_apply_transaction_target(
    checkout_root: Path,
    relative: Path,
) -> bool:
    """Return whether a journal path is one sanctioned live mutation target."""

    def canonical_tail(path: Path, *, suffix: str) -> bool:
        parts = path.parts
        if (
            len(parts) < 3
            or path.suffix != suffix
            or re.fullmatch(r"[a-z]{2}(?:-[a-z0-9_]+)*", parts[0]) is None
            or parts[1] not in RULESPEC_ATOMIC_MODULE_ROOTS
            or monorepo_checkout_name(parts[0]) != checkout_root.name
            or canonical_rulespec_root_identity(checkout_root / parts[0]) is None
        ):
            return False
        return True

    if canonical_tail(relative, suffix=RULESPEC_FILE_SUFFIX):
        return True
    manifest_prefix = APPLIED_ENCODING_MANIFEST_DIR.parts
    if relative.parts[: len(manifest_prefix)] != manifest_prefix:
        return False
    manifest_tail = Path(*relative.parts[len(manifest_prefix) :])
    return canonical_tail(
        manifest_tail, suffix=".json"
    ) and not manifest_tail.name.endswith(".test.json")


def _apply_transaction_target_relative_path(
    checkout_root: Path,
    target: Path,
) -> str:
    relative_value = _apply_transaction_relative_path(checkout_root, target)
    if not _is_canonical_apply_transaction_target(
        checkout_root,
        Path(relative_value),
    ):
        raise RuntimeError(
            "Apply transaction target is outside the canonical RuleSpec/manifest "
            f"mutation surface: {relative_value}"
        )
    return relative_value


def _planned_apply_transaction_directories(
    checkout_root: Path,
    files: Sequence[tuple[Path, bytes | None]],
) -> list[str]:
    """Return the exact absent parent directories that successful writes need."""

    planned: set[Path] = set()
    for target, raw in files:
        if raw is None:
            continue
        cursor = target.parent
        while cursor != checkout_root:
            if cursor.is_symlink():
                raise RuntimeError(f"Apply target path contains a symlink: {cursor}")
            try:
                metadata = cursor.stat()
            except FileNotFoundError:
                planned.add(cursor)
                cursor = cursor.parent
                continue
            if not stat.S_ISDIR(metadata.st_mode):
                raise RuntimeError(
                    f"Apply target path contains a non-directory: {cursor}"
                )
            break
        if cursor == checkout_root and not checkout_root.is_dir():
            raise RuntimeError(f"RuleSpec checkout disappeared: {checkout_root}")
    if len(planned) > _MAX_APPLY_TRANSACTION_DIRECTORIES:
        raise RuntimeError("RuleSpec apply transaction creates too many directories")
    return [
        path.relative_to(checkout_root).as_posix()
        for path in sorted(planned, key=lambda item: (len(item.parts), item.as_posix()))
    ]


def _create_planned_apply_transaction_directories(
    checkout_root: Path,
    directories: Sequence[str],
) -> None:
    """Create journal-bound directories in parent-first durable order."""

    for relative_value in directories:
        directory = checkout_root / relative_value
        if directory.is_symlink() or directory.exists():
            raise RuntimeError(
                f"Apply target directory changed after validation: {directory}"
            )
        parent = directory.parent
        if parent.is_symlink() or not parent.is_dir():
            raise RuntimeError(f"Apply target directory parent is unsafe: {parent}")
        directory.mkdir(mode=0o755)
        _fsync_directory(parent)


def _remove_planned_apply_transaction_directories(
    checkout_root: Path,
    directories: Sequence[str],
) -> None:
    """Remove transaction-created empty directories in child-first order."""

    for relative_value in reversed(directories):
        directory = checkout_root / relative_value
        if directory.is_symlink():
            raise RuntimeError(
                f"Cannot clean indirect apply transaction directory: {directory}"
            )
        if not directory.exists():
            continue
        if not directory.is_dir():
            raise RuntimeError(
                f"Cannot clean non-directory apply transaction path: {directory}"
            )
        try:
            directory.rmdir()
        except OSError as exc:
            raise RuntimeError(
                f"Cannot clean non-empty apply transaction directory: {directory}"
            ) from exc
        _fsync_directory(directory.parent)


def _write_apply_transaction_journal(
    transaction_dir: Path,
    journal: Mapping[str, object],
) -> None:
    raw = (json.dumps(dict(journal), indent=2, sort_keys=True) + "\n").encode()
    _atomic_replace_bytes(transaction_dir / "journal.json", raw, mode=0o600)


def _load_apply_transaction_journal(
    transaction_dir: Path,
    *,
    checkout_root: Path,
) -> dict[str, object]:
    def unique_object(pairs: list[tuple[str, object]]) -> dict[str, object]:
        result: dict[str, object] = {}
        for key, value in pairs:
            if key in result:
                raise ValueError(f"duplicate JSON key {key!r}")
            result[key] = value
        return result

    path = transaction_dir / "journal.json"
    try:
        raw, _metadata = _read_bounded_nofollow_regular_file(
            path,
            label="Apply transaction journal",
            max_bytes=_MAX_APPLY_TRANSACTION_JOURNAL_BYTES,
            require_private=True,
        )
        payload = json.loads(
            raw.decode("utf-8"),
            object_pairs_hook=unique_object,
        )
    except (
        UnicodeDecodeError,
        json.JSONDecodeError,
        RecursionError,
        ValueError,
    ) as exc:
        raise RuntimeError(f"Apply transaction journal is unreadable: {path}") from exc
    if not isinstance(payload, dict):
        raise RuntimeError("Apply transaction journal must be an object")
    if set(payload) != {"schema", "state", "entries", "created_directories"}:
        raise RuntimeError("Apply transaction journal has an unsupported shape")
    if payload.get("schema") != _APPLY_TRANSACTION_SCHEMA:
        raise RuntimeError("Apply transaction journal schema is unsupported")
    if payload.get("state") not in {"prepared", "applying", "committed"}:
        raise RuntimeError("Apply transaction journal state is invalid")
    entries = payload.get("entries")
    if (
        not isinstance(entries, list)
        or not entries
        or len(entries) > _MAX_APPLY_TRANSACTION_ENTRIES
    ):
        raise RuntimeError("Apply transaction journal has no entries")
    expected_fields = {
        "path",
        "existed",
        "mode",
        "old_sha256",
        "backup",
        "delete",
        "new_sha256",
    }
    seen_paths: set[str] = set()
    seen_backups: set[str] = set()
    new_file_parent_paths: set[str] = set()
    old_file_parent_paths: set[str] = set()
    for index, entry in enumerate(entries):
        if not isinstance(entry, dict) or set(entry) != expected_fields:
            raise RuntimeError("Apply transaction journal entry is malformed")
        path_value = entry.get("path")
        if (
            not isinstance(path_value, str)
            or not path_value
            or Path(path_value).is_absolute()
            or Path(path_value).as_posix() != path_value
            or any(part in {"", ".", ".."} for part in Path(path_value).parts)
        ):
            raise RuntimeError("Apply transaction journal path is unsafe")
        relative = Path(path_value)
        if not _is_canonical_apply_transaction_target(checkout_root, relative):
            raise RuntimeError("Apply transaction journal target is not canonical")
        if path_value in seen_paths:
            raise RuntimeError("Apply transaction journal lists a duplicate target")
        seen_paths.add(path_value)
        if type(entry.get("existed")) is not bool:
            raise RuntimeError("Apply transaction journal existence marker is invalid")
        mode = entry.get("mode")
        if type(mode) is not int or not 0 <= mode <= 0o777:
            raise RuntimeError("Apply transaction journal mode is invalid")
        if type(entry.get("delete")) is not bool:
            raise RuntimeError("Apply transaction journal deletion marker is invalid")
        for field in ("old_sha256", "new_sha256"):
            digest = entry.get(field)
            if digest is not None and (
                not isinstance(digest, str)
                or re.fullmatch(r"[0-9a-f]{64}", digest) is None
            ):
                raise RuntimeError(f"Apply transaction journal {field} is invalid")
        backup = entry.get("backup")
        if backup is not None and (
            not isinstance(backup, str)
            or re.fullmatch(r"[0-9]{6}\.old", backup) is None
            or backup != f"{index:06d}.old"
        ):
            raise RuntimeError("Apply transaction journal backup path is invalid")
        if backup is not None:
            if backup in seen_backups:
                raise RuntimeError("Apply transaction journal lists a duplicate backup")
            seen_backups.add(backup)
        if entry["existed"] != (entry["old_sha256"] is not None):
            raise RuntimeError("Apply transaction journal old state is inconsistent")
        if entry["existed"] != (entry["backup"] is not None):
            raise RuntimeError("Apply transaction journal backup is inconsistent")
        if entry["delete"] != (entry["new_sha256"] is None):
            raise RuntimeError("Apply transaction journal new state is inconsistent")
        if entry["delete"] and not entry["existed"]:
            raise RuntimeError("Apply transaction journal deletes an absent target")
        parents = [parent.as_posix() for parent in relative.parents if parent.parts]
        if entry["existed"]:
            old_file_parent_paths.update(parents)
        elif not entry["delete"]:
            new_file_parent_paths.update(parents)

    directories = payload.get("created_directories")
    if (
        not isinstance(directories, list)
        or len(directories) > _MAX_APPLY_TRANSACTION_DIRECTORIES
        or not all(isinstance(item, str) for item in directories)
    ):
        raise RuntimeError("Apply transaction journal directory list is invalid")
    expected_order = sorted(
        set(directories),
        key=lambda item: (len(Path(item).parts), item),
    )
    if directories != expected_order:
        raise RuntimeError("Apply transaction journal directory list is noncanonical")
    for relative_value in directories:
        relative = Path(relative_value)
        if (
            not relative.parts
            or relative.is_absolute()
            or relative.as_posix() != relative_value
            or any(part in {"", ".", ".."} for part in relative.parts)
            or relative_value not in new_file_parent_paths
            or relative_value in old_file_parent_paths
        ):
            raise RuntimeError("Apply transaction journal directory path is unsafe")
    return payload


def _remove_apply_transaction_directory(transaction_dir: Path) -> None:
    parent = transaction_dir.parent
    _require_private_owned_directory(
        transaction_dir,
        label="Apply transaction directory",
    )
    shutil.rmtree(transaction_dir)
    _fsync_directory(parent)


def _apply_transaction_snapshot_matches(
    snapshot: tuple[bytes, str, int] | None,
    *,
    digest: object,
    mode: object,
) -> bool:
    if digest is None:
        return snapshot is None
    return snapshot is not None and snapshot[1] == digest and snapshot[2] == mode


def _read_apply_transaction_backup(
    transaction_dir: Path,
    entry: Mapping[str, object],
) -> bytes:
    backup = transaction_dir / "backups" / str(entry["backup"])
    raw, _metadata = _read_bounded_nofollow_regular_file(
        backup,
        label="Apply transaction backup",
        max_bytes=_MAX_APPLY_TRANSACTION_FILE_BYTES,
        require_private=True,
    )
    if hashlib.sha256(raw).hexdigest() != entry["old_sha256"]:
        raise RuntimeError(f"Apply transaction backup is corrupt: {backup}")
    return raw


def _recover_apply_transaction_locked(checkout_root: Path) -> None:
    """Recover or finalize a journal left by a killed mutation process."""

    transaction_dir = checkout_root / _APPLY_TRANSACTION_DIRECTORY
    if transaction_dir.is_symlink():
        raise RuntimeError("Apply transaction recovery path is unsafe")
    if not transaction_dir.exists():
        return
    _require_private_owned_directory(
        transaction_dir,
        label="Apply transaction directory",
    )
    journal_path = transaction_dir / "journal.json"
    if not journal_path.exists() and not journal_path.is_symlink():
        # No live target is touched before the durable journal exists.
        _remove_apply_transaction_directory(transaction_dir)
        return
    journal = _load_apply_transaction_journal(
        transaction_dir,
        checkout_root=checkout_root,
    )
    entries = journal["entries"]
    assert isinstance(entries, list)
    directories = journal["created_directories"]
    assert isinstance(directories, list)
    state = journal["state"]

    if state == "committed":
        for entry in entries:
            assert isinstance(entry, dict)
            target = checkout_root / str(entry["path"])
            _ensure_safe_apply_target(checkout_root, target)
            current = _apply_transaction_file_snapshot(target)
            if not _apply_transaction_snapshot_matches(
                current,
                digest=entry["new_sha256"],
                mode=entry["mode"],
            ):
                raise RuntimeError(
                    f"Committed apply transaction target changed before cleanup: {target}"
                )
        _remove_apply_transaction_directory(transaction_dir)
        return

    backups_dir = transaction_dir / "backups"
    _require_private_owned_directory(
        backups_dir,
        label="Apply transaction backup directory",
    )

    # Admission is deliberately separate from mutation. A corrupt backup or
    # one externally changed target must not cause recovery to alter another.
    pending_actions: list[
        tuple[
            dict[str, object],
            Path,
            tuple[bytes, str, int] | None,
            bytes | None,
        ]
    ] = []
    recovery_bytes = 0
    for entry in reversed(entries):
        assert isinstance(entry, dict)
        target = checkout_root / str(entry["path"])
        _ensure_safe_apply_target(checkout_root, target)
        current = _apply_transaction_file_snapshot(target)
        if current is not None:
            recovery_bytes += len(current[0])
            if recovery_bytes > _MAX_APPLY_TRANSACTION_RECOVERY_BYTES:
                raise RuntimeError(
                    "Apply transaction recovery exceeds its cumulative byte limit"
                )
        if _apply_transaction_snapshot_matches(
            current,
            digest=entry["old_sha256"],
            mode=entry["mode"],
        ):
            continue
        if state == "prepared" or not _apply_transaction_snapshot_matches(
            current,
            digest=entry["new_sha256"],
            mode=entry["mode"],
        ):
            raise RuntimeError(
                f"Cannot safely recover externally changed apply target: {target}"
            )
        pending_actions.append((entry, target, current, None))

    materialized_actions: list[
        tuple[
            dict[str, object],
            Path,
            tuple[bytes, str, int] | None,
            bytes | None,
        ]
    ] = []
    for entry, target, current, _raw in pending_actions:
        raw = (
            _read_apply_transaction_backup(transaction_dir, entry)
            if entry["existed"]
            else None
        )
        if raw is not None:
            recovery_bytes += len(raw)
            if recovery_bytes > _MAX_APPLY_TRANSACTION_RECOVERY_BYTES:
                raise RuntimeError(
                    "Apply transaction recovery exceeds its cumulative byte limit"
                )
        materialized_actions.append((entry, target, current, raw))

    for entry, target, expected_current, raw in materialized_actions:
        _ensure_safe_apply_target(checkout_root, target)
        if _apply_transaction_file_snapshot(target) != expected_current:
            raise RuntimeError(
                f"Apply target changed during transaction recovery: {target}"
            )
        if entry["existed"]:
            assert raw is not None
            _atomic_replace_bytes(target, raw, mode=int(entry["mode"]))
        else:
            target.unlink()
            _fsync_directory(target.parent)

        restored = _apply_transaction_file_snapshot(target)
        if not _apply_transaction_snapshot_matches(
            restored,
            digest=entry["old_sha256"],
            mode=entry["mode"],
        ):
            raise RuntimeError(f"Apply transaction rollback did not restore {target}")

    _remove_planned_apply_transaction_directories(checkout_root, directories)
    _remove_apply_transaction_directory(transaction_dir)


def _recover_apply_transaction(checkout_root: Path) -> None:
    """Acquire the checkout lock and recover one interrupted transaction."""

    checkout_root = Path(checkout_root).resolve(strict=True)
    with _exclusive_apply_transaction_lock(checkout_root):
        _recover_apply_transaction_locked(checkout_root)


def _install_apply_transaction(
    files: Sequence[tuple[Path, bytes | None]],
    *,
    checkout_root: Path | None = None,
    expected_originals: Mapping[Path, str | None] | None = None,
    pre_install_check: Callable[[], None] | None = None,
    post_install_check: Callable[[], None] | None = None,
) -> None:
    """Durably install a byte-exact set with killed-process recovery."""

    normalized_files = [
        (Path(os.path.abspath(Path(target).expanduser())), raw) for target, raw in files
    ]
    if not normalized_files:
        raise RuntimeError("RuleSpec apply transaction has no files")
    if len(normalized_files) > _MAX_APPLY_TRANSACTION_ENTRIES:
        raise RuntimeError("RuleSpec apply transaction contains too many files")
    if len({target for target, _raw in normalized_files}) != len(normalized_files):
        raise RuntimeError("RuleSpec apply transaction contains duplicate targets")
    if checkout_root is None:
        checkout_root = Path(
            os.path.commonpath(
                [str(target.parent) for target, _raw in normalized_files]
            )
        )
    checkout_root = Path(checkout_root).resolve(strict=True)
    normalized_expected = {
        Path(os.path.abspath(Path(target).expanduser())): digest
        for target, digest in (expected_originals or {}).items()
    }
    relative_targets = {
        target: _apply_transaction_target_relative_path(checkout_root, target)
        for target, _raw in normalized_files
    }

    with _exclusive_apply_transaction_lock(checkout_root):
        _recover_apply_transaction_locked(checkout_root)
        if pre_install_check is not None:
            pre_install_check()

        created_directories = _planned_apply_transaction_directories(
            checkout_root,
            normalized_files,
        )
        transaction_dir = checkout_root / _APPLY_TRANSACTION_DIRECTORY
        transaction_dir.mkdir(mode=0o700)
        _fsync_directory(transaction_dir.parent)
        _require_private_owned_directory(
            transaction_dir,
            label="Apply transaction directory",
        )
        backups_dir = transaction_dir / "backups"
        backups_dir.mkdir(mode=0o700)
        _fsync_directory(transaction_dir)
        _require_private_owned_directory(
            backups_dir,
            label="Apply transaction backup directory",
        )

        entries: list[dict[str, object]] = []
        try:
            for index, (target, raw) in enumerate(normalized_files):
                _ensure_safe_apply_target(checkout_root, target)
                old_snapshot = _apply_transaction_file_snapshot(target)
                old_digest = old_snapshot[1] if old_snapshot is not None else None
                if (
                    target in normalized_expected
                    and old_digest != normalized_expected[target]
                ):
                    raise RuntimeError(
                        f"Apply target changed after validation: {target}"
                    )
                existed = old_digest is not None
                if raw is None and not existed:
                    raise RuntimeError(f"Cannot delete missing apply target: {target}")
                mode = old_snapshot[2] if old_snapshot is not None else 0o644
                backup_name = f"{index:06d}.old" if existed else None
                if existed:
                    assert backup_name is not None
                    assert old_snapshot is not None
                    backup_raw = old_snapshot[0]
                    _atomic_replace_bytes(
                        backups_dir / backup_name,
                        backup_raw,
                        mode=0o600,
                    )
                entries.append(
                    {
                        "path": relative_targets[target],
                        "existed": existed,
                        "mode": mode,
                        "old_sha256": old_digest,
                        "backup": backup_name,
                        "delete": raw is None,
                        "new_sha256": (
                            hashlib.sha256(raw).hexdigest() if raw is not None else None
                        ),
                    }
                )
            journal: dict[str, object] = {
                "schema": _APPLY_TRANSACTION_SCHEMA,
                "state": "prepared",
                "entries": entries,
                "created_directories": created_directories,
            }
            _write_apply_transaction_journal(transaction_dir, journal)
            journal["state"] = "applying"
            _write_apply_transaction_journal(transaction_dir, journal)
            _create_planned_apply_transaction_directories(
                checkout_root,
                created_directories,
            )

            for target, raw in normalized_files:
                entry = next(
                    item for item in entries if item["path"] == relative_targets[target]
                )
                _ensure_safe_apply_target(checkout_root, target)
                current = _apply_transaction_file_snapshot(target)
                if not _apply_transaction_snapshot_matches(
                    current,
                    digest=entry["old_sha256"],
                    mode=entry["mode"],
                ):
                    raise RuntimeError(
                        f"Apply target changed immediately before mutation: {target}"
                    )
                if raw is None:
                    target.unlink()
                    _fsync_directory(target.parent)
                else:
                    _atomic_replace_bytes(target, raw, mode=int(entry["mode"]))
            if post_install_check is not None:
                post_install_check()
            for target, _raw in normalized_files:
                entry = next(
                    item for item in entries if item["path"] == relative_targets[target]
                )
                _ensure_safe_apply_target(checkout_root, target)
                if not _apply_transaction_snapshot_matches(
                    _apply_transaction_file_snapshot(target),
                    digest=entry["new_sha256"],
                    mode=entry["mode"],
                ):
                    raise RuntimeError(
                        f"Apply transaction final state changed before commit: {target}"
                    )
            journal["state"] = "committed"
            _write_apply_transaction_journal(transaction_dir, journal)
            _remove_apply_transaction_directory(transaction_dir)
        except BaseException as exc:
            rollback_error: BaseException | None = None
            try:
                if transaction_dir.exists():
                    _recover_apply_transaction_locked(checkout_root)
            except BaseException as recovery_exc:
                rollback_error = recovery_exc
            detail = (
                f"; durable recovery failed: {rollback_error}"
                if rollback_error is not None
                else ""
            )
            raise RuntimeError(
                f"RuleSpec apply transaction failed: {exc}{detail}"
            ) from exc


def _require_apply_post_install_closure(
    result,
    *,
    output_root: Path,
    policy_repo_path: Path,
    relative_output: Path,
    supplemental_files: Mapping[Path, str],
    corpus_path: Path,
    planned: Mapping[Path, bytes],
    manifest_path: Path,
    manifest_bytes: bytes,
) -> None:
    """Recheck the execution closure while rollback is still possible."""

    expected_snapshot = getattr(result, _APPLY_VALIDATION_SNAPSHOT_ATTR, None)
    if not isinstance(expected_snapshot, dict):
        raise RuntimeError("Apply validation snapshot is missing")
    expected_execution = expected_snapshot.get("validation_execution")
    if not isinstance(expected_execution, dict):
        raise RuntimeError("Apply validation snapshot lacks execution identity")
    axiom_rules_path = expected_execution.get("axiom_rules_path")
    dependency_roots = expected_execution.get("rulespec_dependency_roots")
    expected_policy_files = expected_execution.get("policy_content_files")
    if (
        not isinstance(axiom_rules_path, str)
        or not isinstance(dependency_roots, list)
        or not all(isinstance(path, str) for path in dependency_roots)
        or not isinstance(expected_policy_files, dict)
    ):
        raise RuntimeError("Apply validation snapshot has malformed execution inputs")

    content_root = _rulespec_apply_content_root(policy_repo_path, relative_output)
    final_release = load_rulespec_local_corpus_release(content_root, corpus_path)
    artifact_snapshot = _build_apply_validation_snapshot(
        result,
        output_root=output_root,
        policy_repo_path=content_root,
        relative_output=relative_output,
        supplemental_files=supplemental_files,
        local_corpus_release=final_release,
        validation_execution_identity=expected_execution,
    )
    if artifact_snapshot != expected_snapshot:
        raise RuntimeError(
            "Cannot keep applied RuleSpec: evidence or corpus release changed "
            "during installation"
        )

    current_execution = _apply_validation_execution_identity(
        axiom_rules_path=Path(axiom_rules_path),
        policy_repo_path=content_root,
        relative_output=relative_output,
        rulespec_dependency_roots=tuple(Path(path) for path in dependency_roots),
    )
    for field in (
        "axiom_encode_identity",
        "axiom_rules_path",
        "axiom_rules_identity",
        "rulespec_dependency_roots",
        "rulespec_dependency_identities",
    ):
        if current_execution.get(field) != expected_execution.get(field):
            raise RuntimeError(
                "Cannot keep applied RuleSpec: execution dependency changed "
                f"during installation ({field})"
            )

    expected_policy_identity = expected_execution.get("policy_root_identity")
    current_policy_identity = current_execution.get("policy_root_identity")
    if not isinstance(expected_policy_identity, dict) or not isinstance(
        current_policy_identity, dict
    ):
        raise RuntimeError("Apply execution identity lacks RuleSpec provenance")
    for field in (
        "path",
        "toolchain_root",
        "toolchain_contract_sha256",
        "validation_waiver_set_sha256",
    ):
        if current_policy_identity.get(field) != expected_policy_identity.get(field):
            raise RuntimeError(
                "Cannot keep applied RuleSpec: RuleSpec contract changed during "
                f"installation ({field})"
            )
    expected_checkout = expected_policy_identity.get("checkout_identity")
    current_checkout = current_policy_identity.get("checkout_identity")
    if not isinstance(expected_checkout, dict) or not isinstance(
        current_checkout, dict
    ):
        raise RuntimeError("Apply execution identity lacks checkout provenance")
    for field in ("kind", "path", "commit"):
        if current_checkout.get(field) != expected_checkout.get(field):
            raise RuntimeError(
                "Cannot keep applied RuleSpec: checkout identity changed during "
                f"installation ({field})"
            )

    expected_post_files = dict(expected_policy_files)
    for relative, raw in planned.items():
        expected_post_files[_canonical_apply_relative_path(relative).as_posix()] = (
            hashlib.sha256(raw).hexdigest()
        )
    if current_execution.get("policy_content_files") != expected_post_files:
        raise RuntimeError(
            "Cannot keep applied RuleSpec: live RuleSpec bytes changed during "
            "installation"
        )
    for relative, raw in planned.items():
        target = content_root / _canonical_apply_relative_path(relative)
        if target.read_bytes() != raw:
            raise RuntimeError(
                f"Cannot keep applied RuleSpec: installed bytes changed for {target}"
            )
    if manifest_path.read_bytes() != manifest_bytes:
        raise RuntimeError(
            "Cannot keep applied RuleSpec: installed manifest bytes changed"
        )


def _apply_generated_encoding_result(
    result,
    *,
    output_root: Path,
    policy_repo_path: Path,
    corpus_path: Path,
    run_id: str | None = None,
    supplemental_files: dict[Path, str] | None = None,
    signing_broker: SigningBroker | None = None,
    allow_shrink: bool = False,
) -> list[Path]:
    """Validate, pre-sign, and transactionally install one generated encoding."""
    output_file = Path(str(getattr(result, "output_file", "") or ""))
    relative_output = _relative_generated_output_path(result, output_root=output_root)
    content_root = _rulespec_apply_content_root(policy_repo_path, relative_output)
    checkout_root = _rulespec_checkout_root(content_root)
    # Direct internal callers receive the same killed-process recovery ordering
    # as the public encode --apply entrypoint.
    _recover_apply_transaction(checkout_root)
    signing_broker = signing_broker or _require_applied_encoding_manifest_signer()
    axiom_encode_git = _require_clean_axiom_encode_git_provenance()
    backend = str(getattr(result, "backend", "") or "").strip().lower()
    supplemental_files = dict(supplemental_files or {})

    supplemental_source_issues = _supplemental_source_attestation_issues(
        supplemental_files,
        attestation=_generated_result_source_attestation(result),
        require_source_verification=backend in APPLIED_ENCODING_ENCODER_BACKENDS,
    )
    if supplemental_source_issues:
        raise RuntimeError(
            "Cannot apply supplemental source-verifying RuleSpec(s): "
            + "; ".join(supplemental_source_issues)
        )
    _stamp_generated_source_attestation_for_apply(result, output_file)

    _enforce_canonical_concept_registry(
        candidate_files=[output_file, _rulespec_test_path(output_file)],
        relative_output=relative_output,
        policy_repo_path=policy_repo_path,
    )

    local_corpus_release = load_rulespec_local_corpus_release(
        content_root,
        corpus_path,
    )
    _require_unchanged_successful_apply_validation(
        result,
        output_root=output_root,
        policy_repo_path=content_root,
        relative_output=relative_output,
        supplemental_files=supplemental_files,
        local_corpus_release=local_corpus_release,
    )
    _enforce_no_apply_collision(
        source_file=output_file,
        target_file=content_root / relative_output,
    )
    planned, wrote_empty_companion_test = _planned_apply_file_bytes(
        output_file,
        relative_output=relative_output,
        supplemental_files=supplemental_files,
    )
    _require_planned_apply_bytes_match_validation_snapshot(
        result,
        planned,
        relative_output=relative_output,
        wrote_empty_companion_test=wrote_empty_companion_test,
    )
    manifest_relative, manifest_bytes = _stage_signed_apply_manifest(
        result,
        output_root=output_root,
        content_root=content_root,
        corpus_path=corpus_path,
        relative_output=relative_output,
        planned=planned,
        run_id=run_id,
        signing_broker=signing_broker,
        axiom_encode_git=axiom_encode_git,
        allow_shrink=allow_shrink,
    )
    # Re-open the live toolchain and every evidence artifact after manifest
    # construction so a concurrent mutation cannot be smuggled into install.
    final_corpus_release = load_rulespec_local_corpus_release(
        content_root,
        corpus_path,
    )
    _require_staged_manifest_matches_validation_snapshot(
        result,
        manifest_bytes,
        output_root=output_root,
        content_root=content_root,
        planned=planned,
        run_id=run_id,
        signing_broker=signing_broker,
        axiom_encode_git=axiom_encode_git,
        local_corpus_release=final_corpus_release,
    )
    _require_unchanged_successful_apply_validation(
        result,
        output_root=output_root,
        policy_repo_path=content_root,
        relative_output=relative_output,
        supplemental_files=supplemental_files,
        local_corpus_release=final_corpus_release,
    )

    applied = [content_root / relative_path for relative_path in planned]
    manifest_path = checkout_root / manifest_relative
    transaction_files = [
        *[
            (content_root / relative_path, raw)
            for relative_path, raw in planned.items()
        ],
        (manifest_path, manifest_bytes),
    ]
    for target, _raw in transaction_files:
        _ensure_safe_apply_target(checkout_root, target)

    snapshot = getattr(result, _APPLY_VALIDATION_SNAPSHOT_ATTR, None)
    snapshot_execution = (
        snapshot.get("validation_execution") if isinstance(snapshot, dict) else None
    )
    expected_policy_files = (
        snapshot_execution.get("policy_content_files")
        if isinstance(snapshot_execution, dict)
        else None
    )
    if not isinstance(expected_policy_files, dict):
        raise RuntimeError("Apply validation snapshot lacks original file identities")
    expected_originals: dict[Path, str | None] = {
        content_root / relative_path: expected_policy_files.get(
            _canonical_apply_relative_path(relative_path).as_posix()
        )
        for relative_path in planned
    }
    expected_originals[manifest_path] = _apply_transaction_file_digest(manifest_path)
    new_manifest_applied_files = {
        (Path(content_root.name) / relative_path).as_posix()
        for relative_path in planned
    }

    def pre_install_check() -> None:
        # The transaction lock is now held. Recheck the live destination so a
        # concurrent manifest expansion after staging cannot be overwritten.
        _require_applied_manifest_not_shrunk(
            manifest_path,
            new_applied_files=new_manifest_applied_files,
            allow_shrink=allow_shrink,
        )
        locked_release = load_rulespec_local_corpus_release(
            content_root,
            corpus_path,
        )
        _require_staged_manifest_matches_validation_snapshot(
            result,
            manifest_bytes,
            output_root=output_root,
            content_root=content_root,
            planned=planned,
            run_id=run_id,
            signing_broker=signing_broker,
            axiom_encode_git=axiom_encode_git,
            local_corpus_release=locked_release,
        )
        _require_unchanged_successful_apply_validation(
            result,
            output_root=output_root,
            policy_repo_path=content_root,
            relative_output=relative_output,
            supplemental_files=supplemental_files,
            local_corpus_release=locked_release,
        )

    def post_install_check() -> None:
        _require_apply_post_install_closure(
            result,
            output_root=output_root,
            policy_repo_path=content_root,
            relative_output=relative_output,
            supplemental_files=supplemental_files,
            corpus_path=corpus_path,
            planned=planned,
            manifest_path=manifest_path,
            manifest_bytes=manifest_bytes,
        )

    _install_apply_transaction(
        transaction_files,
        checkout_root=checkout_root,
        expected_originals=expected_originals,
        pre_install_check=pre_install_check,
        post_install_check=post_install_check,
    )
    applied.append(manifest_path)
    if wrote_empty_companion_test:
        print("  apply=generated_empty_deferred_companion_test")
    return applied


def _needs_empty_deferred_companion_test(output_file: Path) -> bool:
    """Return whether a generated deferred module needs an empty test companion."""
    try:
        payload = yaml.safe_load(output_file.read_text())
    except (OSError, yaml.YAMLError, ValueError):
        return False
    if not isinstance(payload, dict):
        return False
    module = payload.get("module")
    if not isinstance(module, dict):
        return False
    if module.get("status") != "deferred":
        return False
    if payload.get("rules") != []:
        return False
    deferred_outputs = module.get("deferred_outputs")
    return isinstance(deferred_outputs, list) and bool(deferred_outputs)


def _resolver_attestation_for_manifest_source(
    citation_path: str,
    *,
    local_corpus_release: LocalCorpusRelease,
    rulespec_root: str,
) -> dict[str, object]:
    """Resolve one source and add only deterministic writer-owned bindings."""

    try:
        canonical_citation = require_canonical_corpus_citation_path(citation_path)
    except CorpusResolutionError as exc:
        raise ValueError(
            "Manifest source citation must be an exact canonical corpus identity: "
            f"{exc}"
        ) from exc
    source_unit = resolve_corpus_source_unit(
        canonical_citation,
        local_corpus_release,
    )
    normalized_source = source_unit.body.replace("\r\n", "\n").replace("\r", "\n")
    return {
        **source_unit.source_attestation,
        "generation_input_sha256": hashlib.sha256(
            normalized_source.encode("utf-8")
        ).hexdigest(),
        "rulespec_root": rulespec_root,
    }


def _manifest_primary_source_verifications(
    *,
    manifest_root: Path,
    applied_files: Sequence[Path],
) -> tuple[list[tuple[str, dict[str, object]]], str]:
    """Load every protected primary RuleSpec and its declared source binding."""

    verifications: list[tuple[str, dict[str, object]]] = []
    root_identities: set[str] = set()
    for path in applied_files:
        relative = path.relative_to(manifest_root).as_posix()
        relative_path = Path(relative)
        if not _is_protected_rulespec_yaml_path(
            relative_path,
            roots=tuple(sorted(RULESPEC_ATOMIC_MODULE_ROOTS)),
        ) or relative_path.name.endswith(RULESPEC_TEST_FILE_SUFFIX):
            continue
        identity = _canonical_rulespec_root_identity_for_path(manifest_root, relative)
        if identity is None:
            raise RuntimeError(
                f"Cannot sign {relative}: its canonical RuleSpec root identity "
                "cannot be derived"
            )
        root_identities.add(identity)
        try:
            rulespec = yaml.safe_load(path.read_text(encoding="utf-8"))
        except (OSError, UnicodeError, yaml.YAMLError, RecursionError) as exc:
            raise RuntimeError(
                f"Cannot sign {relative}: protected RuleSpec is not valid YAML"
            ) from exc
        if not isinstance(rulespec, dict) or rulespec.get("format") != "rulespec/v1":
            raise RuntimeError(
                f"Cannot sign {relative}: protected RuleSpec must declare "
                "format: rulespec/v1"
            )
        plural_source_issues = find_plural_corpus_citation_path_issues(rulespec)
        if plural_source_issues:
            raise RuntimeError(
                f"Cannot sign {relative}: " + "; ".join(plural_source_issues)
            )
        module = rulespec.get("module")
        verification = (
            module.get("source_verification") if isinstance(module, dict) else None
        )
        if not isinstance(verification, dict):
            raise RuntimeError(
                f"Cannot sign {relative}: protected RuleSpec is missing "
                "module.source_verification"
            )
        if "corpus_citation_paths" in verification:
            raise RuntimeError(
                f"Cannot sign {relative}: "
                "module.source_verification.corpus_citation_paths is not supported"
            )
        if not _source_verification_citation_paths(verification):
            raise RuntimeError(
                f"Cannot sign {relative}: module.source_verification is missing "
                "a corpus citation path"
            )
        verifications.append((relative, verification))
    if not verifications:
        raise RuntimeError(
            "Cannot sign an apply manifest without a protected primary RuleSpec"
        )
    if len(root_identities) != 1:
        raise RuntimeError(
            "Cannot sign one apply manifest across multiple canonical RuleSpec roots"
        )
    return verifications, next(iter(root_identities))


def _resolver_owned_manifest_source_attestation(
    result,
    *,
    manifest_root: Path,
    applied_files: Sequence[Path],
    local_corpus_release: LocalCorpusRelease,
) -> dict[str, object]:
    """Return the single resolver attestation binding every covered RuleSpec."""

    backend = str(getattr(result, "backend", "") or "").strip().lower()
    if backend not in APPLIED_ENCODING_GENERATED_BACKENDS:
        raise RuntimeError(f"Cannot sign non-generated backend {backend!r}")
    verifications, rulespec_root = _manifest_primary_source_verifications(
        manifest_root=manifest_root,
        applied_files=applied_files,
    )
    provided = _generated_result_source_attestation(result)
    candidate_paths: list[str]
    if backend in APPLIED_ENCODING_ENCODER_BACKENDS:
        if provided is None:
            raise RuntimeError(
                "Cannot sign a model-generated RuleSpec without resolver "
                "source_attestation"
            )
        structure_issues = _source_attestation_structure_issues(provided)
        if structure_issues:
            raise RuntimeError(
                "Cannot sign a model result with incomplete source_attestation: "
                + "; ".join(structure_issues)
            )
        candidate_paths = [str(provided["requested_corpus_citation_path"])]
    else:
        candidate_paths = sorted(
            {
                citation_path
                for _relative, verification in verifications
                for citation_path in _source_verification_citation_paths(verification)
            }
        )

    candidate_failures: list[str] = []
    for citation_path in candidate_paths:
        try:
            candidate = _resolver_attestation_for_manifest_source(
                citation_path,
                local_corpus_release=local_corpus_release,
                rulespec_root=rulespec_root,
            )
        except ValueError as exc:
            candidate_failures.append(f"{citation_path}: {exc}")
            continue
        if provided is not None:
            mismatched_fields = [
                field
                for field, expected in candidate.items()
                if field != "rulespec_root" and provided.get(field) != expected
            ]
            if mismatched_fields:
                raise RuntimeError(
                    "Cannot sign a model result whose source_attestation differs "
                    "from the explicit signed corpus release: "
                    + ", ".join(sorted(mismatched_fields))
                )
        binding_issues = [
            f"{relative}: {issue}"
            for relative, verification in verifications
            for issue in _source_attestation_binding_issues(
                candidate,
                verification,
                require_source_sha256=(backend in APPLIED_ENCODING_ENCODER_BACKENDS),
            )
        ]
        if not binding_issues:
            return candidate
        candidate_failures.extend(binding_issues)

    detail = "; ".join(dict.fromkeys(candidate_failures))
    raise RuntimeError(
        "Cannot sign one source_attestation that binds every covered protected "
        f"RuleSpec{': ' + detail if detail else ''}"
    )


def _write_applied_encoding_manifest(
    result,
    *,
    output_root: Path,
    policy_repo_path: Path,
    corpus_path: Path,
    relative_output: Path,
    applied_files: list[Path],
    axiom_encode_git: dict[str, object],
    signing_broker: SigningBroker,
    run_id: str | None = None,
    existing_manifest_path: Path | None = None,
    allow_shrink: bool = False,
) -> Path:
    """Record that live RuleSpec files were installed by the encoder."""
    content_root = _rulespec_apply_content_root(policy_repo_path, relative_output)
    manifest_root, manifest_relative_output = _resolve_applied_manifest_placement(
        content_root=content_root,
        relative_output=relative_output,
    )
    manifest_path = manifest_root / _applied_encoding_manifest_path(
        manifest_relative_output
    )
    context_manifest_raw = str(getattr(result, "context_manifest_file", "") or "")
    trace_file_raw = str(getattr(result, "trace_file", "") or "")
    output_file_raw = str(getattr(result, "output_file", "") or "")
    context_manifest = (
        Path(context_manifest_raw).resolve() if context_manifest_raw else None
    )
    trace_file = Path(trace_file_raw).resolve() if trace_file_raw else None
    output_file = Path(output_file_raw).resolve() if output_file_raw else None
    tool = getattr(result, "tool", None)
    if not isinstance(tool, str) or not tool.strip():
        tool = APPLIED_ENCODING_MODEL_TOOL
    backend = str(getattr(result, "backend", "") or "").strip().lower()
    encoder_execution_identity = _current_guard_encoder_execution_identity()
    if backend not in APPLIED_ENCODING_ENCODER_BACKENDS:
        raise RuntimeError(f"Cannot sign non-generated backend {backend!r}")
    if tool != APPLIED_ENCODING_MODEL_TOOL:
        raise RuntimeError(
            "Cannot sign a model-generated RuleSpec with a non-allowlisted tool"
        )
    unique_applied_files: list[Path] = []
    seen_applied_paths: set[str] = set()
    for path in applied_files:
        relative_path = path.relative_to(manifest_root).as_posix()
        if Path(relative_path).suffix != RULESPEC_FILE_SUFFIX:
            raise RuntimeError(
                "Cannot sign an applied RuleSpec manifest containing a file "
                f"without the canonical {RULESPEC_FILE_SUFFIX} extension: "
                f"{relative_path}"
            )
        if relative_path in seen_applied_paths:
            continue
        seen_applied_paths.add(relative_path)
        unique_applied_files.append(path)
    _require_applied_manifest_not_shrunk(
        existing_manifest_path or manifest_path,
        new_applied_files=seen_applied_paths,
        allow_shrink=allow_shrink,
    )
    manifest_path.parent.mkdir(parents=True, exist_ok=True)
    local_corpus_release = load_rulespec_local_corpus_release(
        policy_repo_path,
        corpus_path,
    )
    source_attestation = _resolver_owned_manifest_source_attestation(
        result,
        manifest_root=manifest_root,
        applied_files=unique_applied_files,
        local_corpus_release=local_corpus_release,
    )
    codex_cli_version, codex_cli_sha256 = _result_codex_cli_provenance(result)
    if backend == "codex" and (
        codex_cli_version is None or codex_cli_sha256 is None
    ):
        raise RuntimeError("Codex backend result has no trusted CLI provenance")
    payload = {
        "schema_version": APPLIED_ENCODING_MANIFEST_SCHEMA,
        "generated_at": datetime.now(timezone.utc).isoformat(),
        "tool": tool,
        "axiom_encode_version": __version__,
        "axiom_encode_git": axiom_encode_git,
        "generation_prompt_sha256": getattr(result, "generation_prompt_sha256", None),
        "run_id": run_id,
        "citation": str(getattr(result, "citation", "") or ""),
        "runner": str(getattr(result, "runner", "") or ""),
        "backend": backend,
        "model": str(getattr(result, "model", "") or ""),
        VALIDATION_WAIVER_SET_SHA256_FIELD: verify_rulespec_validation_waiver_set(
            policy_repo_path
        ),
        "generated_output_root": str(output_root),
        "generated_output_file": str(output_file) if output_file is not None else None,
        "generated_output_sha256": _sha256_file(output_file)
        if output_file is not None and output_file.is_file()
        else None,
        "trace_file": str(trace_file) if trace_file is not None else None,
        "trace_sha256": _sha256_file(trace_file)
        if trace_file is not None and trace_file.is_file()
        else None,
        "context_manifest_file": str(context_manifest)
        if context_manifest is not None
        else None,
        "context_manifest_sha256": _sha256_file(context_manifest)
        if context_manifest is not None and context_manifest.is_file()
        else None,
        "applied_files": [
            {
                "path": path.relative_to(manifest_root).as_posix(),
                "sha256": _sha256_file(path),
            }
            for path in unique_applied_files
        ],
    }
    if codex_cli_version is not None:
        payload["codex_cli_version"] = codex_cli_version
        payload["codex_cli_sha256"] = codex_cli_sha256
    payload["source_attestation"] = source_attestation
    validation_snapshot = getattr(
        result,
        _APPLY_VALIDATION_SNAPSHOT_ATTR,
        None,
    )
    validation_execution = (
        validation_snapshot.get("manifest_validation_execution")
        if isinstance(validation_snapshot, dict)
        else None
    )
    if not isinstance(validation_execution, dict):
        raise RuntimeError(
            "Cannot sign a model-generated RuleSpec without bound validation "
            "execution provenance"
        )
    if _encoder_identity_binding_core(
        validation_execution.get("axiom_encode")
    ) != _encoder_identity_binding_core(encoder_execution_identity):
        raise RuntimeError(
            "Cannot sign model validation from a different encoder commit or version"
        )
    payload["validation_execution"] = copy.deepcopy(validation_execution)
    _sign_applied_encoding_manifest(payload, signing_broker)
    manifest_path.write_text(json.dumps(payload, indent=2, sort_keys=True) + "\n")
    return manifest_path


def _require_applied_manifest_not_shrunk(
    manifest_path: Path,
    *,
    new_applied_files: set[str],
    allow_shrink: bool = False,
) -> None:
    """Refuse to silently drop files from an existing manifest's coverage."""

    manifest_path = Path(manifest_path)
    if allow_shrink or not manifest_path.is_file():
        return
    try:
        raw = manifest_path.read_text(encoding="utf-8")
    except (OSError, UnicodeError) as exc:
        problem = f"is unreadable ({exc})"
        raise RuntimeError(
            f"Cannot determine prior apply-manifest coverage because {manifest_path} "
            f"{problem}. Refusing to replace it; pass --allow-shrink to acknowledge "
            "deliberate recovery."
        ) from exc
    try:
        payload = json.loads(raw)
    except json.JSONDecodeError as exc:
        raise RuntimeError(
            f"Cannot determine prior apply-manifest coverage because {manifest_path} "
            f"contains invalid JSON ({exc}). Refusing to replace it; pass "
            "--allow-shrink to acknowledge deliberate recovery."
        ) from exc
    if not isinstance(payload, dict):
        raise RuntimeError(
            f"Cannot determine prior apply-manifest coverage because {manifest_path} "
            "does not contain a JSON object. Refusing to replace it; pass "
            "--allow-shrink to acknowledge deliberate recovery."
        )
    entries = payload.get("applied_files")
    if not isinstance(entries, list):
        raise RuntimeError(
            f"Cannot determine prior apply-manifest coverage because {manifest_path} "
            "has malformed applied_files (expected a list). Refusing to replace it; "
            "pass --allow-shrink to acknowledge deliberate recovery."
        )
    existing_applied_files: set[str] = set()
    for index, entry in enumerate(entries):
        if (
            not isinstance(entry, dict)
            or not isinstance(entry.get("path"), str)
            or not entry["path"].strip()
        ):
            raise RuntimeError(
                f"Cannot determine prior apply-manifest coverage because {manifest_path} "
                f"has malformed applied_files[{index}] (expected an object with a "
                "non-empty string path). Refusing to replace it; pass --allow-shrink "
                "to acknowledge deliberate recovery."
            )
        if entry.get("deleted") is not True:
            existing_applied_files.add(entry["path"])
    dropped = sorted(existing_applied_files - new_applied_files)
    if not dropped:
        return
    raise RuntimeError(
        "Refusing to shrink existing apply manifest coverage; dropped files: "
        + ", ".join(dropped)
        + ". Re-run the signing workflow against the full branch diff using "
        "base ref origin/main, or pass --allow-shrink to confirm this removal."
    )


def _applied_encoding_manifest_path(relative_output: Path) -> Path:
    return (APPLIED_ENCODING_MANIFEST_DIR / relative_output).with_suffix(".json")


def _rulespec_checkout_root(content_root: Path) -> Path:
    """Return the country checkout for one exact canonical content root."""

    resolved = Path(content_root).resolve()
    identity = canonical_rulespec_root_identity(resolved)
    if identity is None:
        raise ValueError(
            "RuleSpec content root must use the canonical "
            f"rulespec-<country>/<jurisdiction> layout: {resolved}"
        )
    return resolved.parent


def _resolve_applied_manifest_placement(
    *, content_root: Path, relative_output: Path
) -> tuple[Path, Path]:
    """Return the one checkout-root manifest placement for an applied module."""
    content_root = Path(content_root).resolve()
    checkout_root = _rulespec_checkout_root(content_root)
    relative_output = Path(relative_output)
    if relative_output.parts and relative_output.parts[0] == content_root.name:
        relative_output = Path(*relative_output.parts[1:])
    return checkout_root, Path(content_root.name) / relative_output


def _sha256_file(path: Path) -> str:
    digest = hashlib.sha256()
    with Path(path).open("rb") as file:
        for chunk in iter(lambda: file.read(1024 * 1024), b""):
            digest.update(chunk)
    return digest.hexdigest()


def _source_relation_preservation_issues(
    existing_content: str,
    generated_content: str,
) -> list[str]:
    """Return issues for source_relation edges dropped by generated content."""
    existing_records = _source_relation_records(existing_content)
    if not existing_records:
        return []
    generated_signatures = {
        record["signature"] for record in _source_relation_records(generated_content)
    }
    issues: list[str] = []
    for record in existing_records:
        if record["signature"] in generated_signatures:
            continue
        issues.append(
            "Generated RuleSpec dropped existing source_relation "
            f"`{record['name']}` (`{record['relation_type']}` -> "
            f"`{record['target']}`). Regenerate with the source_relation "
            "preserved; do not remove provenance edges by manual edit."
        )
    return issues


def _source_relation_records(content: str) -> list[dict[str, object]]:
    try:
        document = yaml.safe_load(content) or {}
    except yaml.YAMLError:
        return []
    rules = document.get("rules") if isinstance(document, dict) else []
    if not isinstance(rules, list):
        return []
    records: list[dict[str, object]] = []
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        if str(rule.get("kind") or "").strip().lower() != "source_relation":
            continue
        source_relation = rule.get("source_relation")
        if not isinstance(source_relation, dict):
            continue
        basis = source_relation.get("basis")
        if not isinstance(basis, dict):
            basis = {}
        relation_type = _normalize_source_relation_field(source_relation.get("type"))
        target = _normalize_source_relation_field(source_relation.get("target"))
        signature = (
            relation_type,
            target,
            _normalize_source_relation_field(source_relation.get("authority")),
            _normalize_source_relation_field(source_relation.get("value")),
            _normalize_source_relation_field(basis.get("delegation")),
        )
        records.append(
            {
                "name": _normalize_source_relation_field(rule.get("name"))
                or "<unnamed>",
                "relation_type": relation_type or "<missing type>",
                "target": target or "<missing target>",
                "signature": signature,
            }
        )
    return records


def _normalize_source_relation_field(value: object) -> str:
    return str(value or "").strip()


def _validate_generated_encoding_in_policy_overlay_with_release(
    result,
    *,
    output_root: Path,
    policy_repo_path: Path,
    axiom_rules_path: Path,
    local_corpus_release: LocalCorpusRelease,
    validate_dependents: bool = True,
    rulespec_dependency_roots: Sequence[Path] = (),
) -> tuple[bool, list[str], dict[Path, str]]:
    """Validate generated artifacts in a temporary policy-repo overlay."""
    setattr(result, _APPLY_VALIDATION_SNAPSHOT_ATTR, None)
    output_file = Path(str(getattr(result, "output_file", "") or ""))
    if not output_file.exists():
        return False, [f"Generated output file not found: {output_file}"], {}
    try:
        relative_output = _relative_generated_output_path(
            result, output_root=output_root
        )
    except RuntimeError as exc:
        return False, [str(exc)], {}
    try:
        _stamp_generated_source_attestation_for_apply(result, output_file)
        source_metadata = _generated_result_source_metadata(result)
    except RuntimeError as exc:
        return False, [f"{relative_output}: {exc}"], {}

    generated_content = output_file.read_text()
    output_test = _rulespec_test_path(output_file)
    generated_test_cases: Any | None = None
    if output_test.exists():
        try:
            loaded_tests = yaml.safe_load(output_test.read_text())
        except (yaml.YAMLError, ValueError):
            loaded_tests = None
        if isinstance(loaded_tests, dict) and isinstance(
            loaded_tests.get("cases"), list
        ):
            generated_test_cases = loaded_tests["cases"]
        elif isinstance(loaded_tests, list):
            generated_test_cases = loaded_tests
    filing_status_issues = find_tax_filing_status_local_input_issues(
        generated_content,
        generated_test_cases,
    )
    if filing_status_issues:
        return (
            False,
            [f"{relative_output}: {issue}" for issue in filing_status_issues],
            {},
        )

    policy_content_root = _rulespec_apply_content_root(
        policy_repo_path,
        relative_output,
    )
    existing_output = policy_content_root / relative_output
    if existing_output.exists():
        existing_content = existing_output.read_text()
        preservation_issues = _source_relation_preservation_issues(
            existing_content,
            generated_content,
        )
        if preservation_issues:
            return (
                False,
                [f"{relative_output}: {issue}" for issue in preservation_issues],
                {},
            )

    with tempfile.TemporaryDirectory() as tmpdir:
        # macOS returns the trusted temporary root through the /var symlink;
        # canonicalize that system-owned alias before strict path admission.
        overlay_parent = Path(tmpdir).resolve(strict=True)
        policy_checkout_path = _rulespec_apply_checkout_root(
            policy_repo_path,
            relative_output,
        )
        overlay_repo_name = policy_checkout_path.name
        staged_dependency_roots = _stage_apply_overlay_dependency_roots(
            overlay_parent=overlay_parent,
            policy_repo_path=policy_checkout_path,
            overlay_repo_name=overlay_repo_name,
            rulespec_dependency_roots=rulespec_dependency_roots,
        )

        overlay_repo = overlay_parent / overlay_repo_name
        _stage_apply_overlay_dependency_root(
            source=policy_checkout_path,
            target=overlay_repo,
        )
        overlay_content_root = overlay_repo / policy_content_root.name
        if canonical_rulespec_root_identity(overlay_content_root) is None:
            raise ValueError(
                "Apply overlay did not preserve the canonical RuleSpec "
                f"jurisdiction root: {overlay_content_root}"
            )
        overlay_target = overlay_content_root / relative_output
        overlay_target.parent.mkdir(parents=True, exist_ok=True)
        shutil.copy2(output_file, overlay_target)
        if output_test.exists():
            shutil.copy2(output_test, _rulespec_test_path(overlay_target))
        if not validate_dependents:
            _suppress_rulespec_ancestor_targets_for_subsection_overlay(
                overlay_content_root,
                relative_output,
            )

        supplemental_files: dict[Path, str] = {}
        repaired_import_symbols = _repair_generated_import_symbol_near_misses(
            rules_file=overlay_target,
            repo_path=overlay_content_root,
        )
        if repaired_import_symbols:
            supplemental_files[relative_output] = overlay_target.read_text()

        pipeline = ValidatorPipeline(
            policy_repo_path=overlay_content_root,
            axiom_rules_path=axiom_rules_path,
            enable_oracles=False,
            require_policy_proofs=True,
            local_corpus_release=local_corpus_release,
            rulespec_dependency_roots=staged_dependency_roots,
            source_metadata=source_metadata,
        )
        dependents = (
            _find_rulespec_dependents(overlay_content_root, relative_output)
            if validate_dependents
            else []
        )
        dependent_pipeline = (
            ValidatorPipeline(
                policy_repo_path=overlay_content_root,
                axiom_rules_path=axiom_rules_path,
                enable_oracles=False,
                enforce_repository_layout=False,
                local_corpus_release=local_corpus_release,
                rulespec_dependency_roots=staged_dependency_roots,
                source_metadata=source_metadata,
            )
            if dependents
            else pipeline
        )
        changed_proof_hash_files = _repair_dependent_proof_import_hashes(
            dependents=dependents,
        )
        for path in changed_proof_hash_files:
            supplemental_files[
                _relative_to_rulespec_apply_content_root(path, overlay_content_root)
            ] = path.read_text()
        validations = _validate_overlay_files(
            pipeline,
            dependent_pipeline=dependent_pipeline,
            overlay_target=overlay_target,
            dependents=dependents,
        )
        for _ in range(_APPLY_OVERLAY_VALIDATION_REPAIR_LIMIT):
            if all(validation.all_passed for _, validation in validations):
                _record_successful_apply_validation(
                    result,
                    output_root=output_root,
                    policy_repo_path=policy_repo_path,
                    relative_output=relative_output,
                    supplemental_files=supplemental_files,
                    local_corpus_release=local_corpus_release,
                    axiom_rules_path=axiom_rules_path,
                    rulespec_dependency_roots=rulespec_dependency_roots,
                )
                return True, [], supplemental_files
            target_validation = next(
                (
                    validation
                    for validated_file, validation in validations
                    if validated_file == overlay_target
                ),
                None,
            )
            changed_proof_hash_files = _repair_dependent_proof_import_hashes(
                dependents=dependents,
            )
            if changed_proof_hash_files:
                for path in changed_proof_hash_files:
                    supplemental_files[
                        _relative_to_rulespec_apply_content_root(
                            path, overlay_content_root
                        )
                    ] = path.read_text()
                validations = _validate_overlay_files(
                    pipeline,
                    dependent_pipeline=dependent_pipeline,
                    overlay_target=overlay_target,
                    dependents=dependents,
                )
                continue
            restatement_repairs = (
                _repair_generated_restatement_source_relation_for_apply(
                    rules_file=overlay_target,
                    test_file=_rulespec_test_path(overlay_target),
                    repo_path=overlay_content_root,
                    relative_output=relative_output,
                    validation=target_validation,
                )
            )
            if restatement_repairs:
                supplemental_files[relative_output] = overlay_target.read_text()
                test_path = _rulespec_test_path(overlay_target)
                if test_path.exists():
                    supplemental_files[
                        _relative_to_rulespec_apply_content_root(
                            test_path, overlay_content_root
                        )
                    ] = test_path.read_text()
                validations = _validate_overlay_files(
                    pipeline,
                    dependent_pipeline=dependent_pipeline,
                    overlay_target=overlay_target,
                    dependents=dependents,
                )
                continue
            upstream_placement_repairs = _repair_upstream_placement_duplicate_imports(
                rules_file=overlay_target,
                test_file=_rulespec_test_path(overlay_target),
                repo_path=overlay_content_root,
                relative_output=relative_output,
            )
            if upstream_placement_repairs:
                supplemental_files[relative_output] = overlay_target.read_text()
                test_path = _rulespec_test_path(overlay_target)
                if test_path.exists():
                    supplemental_files[
                        _relative_to_rulespec_apply_content_root(
                            test_path, overlay_content_root
                        )
                    ] = test_path.read_text()
                validations = _validate_overlay_files(
                    pipeline,
                    dependent_pipeline=dependent_pipeline,
                    overlay_target=overlay_target,
                    dependents=dependents,
                )
                continue
            imported_collision_repairs = _repair_imported_rule_name_collisions(
                rules_file=overlay_target,
                test_file=_rulespec_test_path(overlay_target),
                repo_path=overlay_content_root,
                relative_output=relative_output,
            )
            if imported_collision_repairs:
                supplemental_files[relative_output] = overlay_target.read_text()
                test_path = _rulespec_test_path(overlay_target)
                if test_path.exists():
                    supplemental_files[
                        _relative_to_rulespec_apply_content_root(
                            test_path, overlay_content_root
                        )
                    ] = test_path.read_text()
                validations = _validate_overlay_files(
                    pipeline,
                    dependent_pipeline=dependent_pipeline,
                    overlay_target=overlay_target,
                    dependents=dependents,
                )
                continue
            mixed_scalar_repairs = _repair_mixed_scalar_output_tests(
                rules_file=overlay_target,
                test_file=_rulespec_test_path(overlay_target),
                repo_path=overlay_content_root,
                relative_output=relative_output,
            )
            if mixed_scalar_repairs:
                test_path = _rulespec_test_path(overlay_target)
                supplemental_files[
                    _relative_to_rulespec_apply_content_root(
                        test_path, overlay_content_root
                    )
                ] = test_path.read_text()
                validations = _validate_overlay_files(
                    pipeline,
                    dependent_pipeline=dependent_pipeline,
                    overlay_target=overlay_target,
                    dependents=dependents,
                )
                continue
            future_effective_repairs = _repair_future_effective_output_tests(
                rules_file=overlay_target,
                test_file=_rulespec_test_path(overlay_target),
                repo_path=overlay_content_root,
                relative_output=relative_output,
            )
            if future_effective_repairs:
                test_path = _rulespec_test_path(overlay_target)
                supplemental_files[
                    _relative_to_rulespec_apply_content_root(
                        test_path, overlay_content_root
                    )
                ] = test_path.read_text()
                validations = _validate_overlay_files(
                    pipeline,
                    dependent_pipeline=dependent_pipeline,
                    overlay_target=overlay_target,
                    dependents=dependents,
                )
                continue
            mixed_derived_entity_repairs = _repair_mixed_derived_entity_output_tests(
                rules_file=overlay_target,
                test_file=_rulespec_test_path(overlay_target),
                repo_path=overlay_content_root,
                relative_output=relative_output,
            )
            if mixed_derived_entity_repairs:
                test_path = _rulespec_test_path(overlay_target)
                supplemental_files[
                    _relative_to_rulespec_apply_content_root(
                        test_path, overlay_content_root
                    )
                ] = test_path.read_text()
                validations = _validate_overlay_files(
                    pipeline,
                    dependent_pipeline=dependent_pipeline,
                    overlay_target=overlay_target,
                    dependents=dependents,
                )
                continue
            target_validation = next(
                (
                    validation
                    for validated_file, validation in validations
                    if validated_file == overlay_target
                ),
                None,
            )
            target_test_path = _rulespec_test_path(overlay_target)
            if (
                target_validation is not None
                and _repair_generated_unused_imports_for_apply(
                    rules_file=overlay_target,
                    validation=target_validation,
                )
            ):
                supplemental_files[relative_output] = overlay_target.read_text()
                validations = _validate_overlay_files(
                    pipeline,
                    dependent_pipeline=dependent_pipeline,
                    overlay_target=overlay_target,
                    dependents=dependents,
                )
                continue
            if (
                target_validation is not None
                and _repair_missing_entity_table_rows_for_row_ordered_outputs(
                    test_file=target_test_path,
                    validation=target_validation,
                )
            ):
                supplemental_files[
                    _relative_to_rulespec_apply_content_root(
                        target_test_path, overlay_content_root
                    )
                ] = target_test_path.read_text()
                validations = _validate_overlay_files(
                    pipeline,
                    dependent_pipeline=dependent_pipeline,
                    overlay_target=overlay_target,
                    dependents=dependents,
                )
                continue
            if target_validation is not None and _complete_missing_imported_test_inputs(
                rules_file=overlay_target,
                test_file=target_test_path,
                repo_path=overlay_content_root,
                validation=target_validation,
            ):
                supplemental_files[
                    _relative_to_rulespec_apply_content_root(
                        target_test_path, overlay_content_root
                    )
                ] = target_test_path.read_text()
                validations = _validate_overlay_files(
                    pipeline,
                    dependent_pipeline=dependent_pipeline,
                    overlay_target=overlay_target,
                    dependents=dependents,
                )
                continue
            if target_validation is not None:
                zero_branch_issues = _zero_branch_coverage_issues_for_files(
                    rules_file=overlay_target,
                    test_file=target_test_path,
                )
                if not zero_branch_issues:
                    zero_branch_issues = [
                        result.error
                        for result in target_validation.results.values()
                        if result.error
                        and "Zero branch test coverage missing: " in result.error
                    ]
                zero_branch_repairs = _append_generated_zero_branch_tests_if_missing(
                    rules_file=overlay_target,
                    test_file=target_test_path,
                    repo_path=overlay_content_root,
                    relative_output=relative_output,
                    issues=zero_branch_issues,
                    valid_output_names=_compiled_rulespec_test_output_names(
                        pipeline,
                        overlay_target,
                        relative_output=relative_output,
                    ),
                )
                if zero_branch_repairs:
                    supplemental_files[
                        _relative_to_rulespec_apply_content_root(
                            target_test_path, overlay_content_root
                        )
                    ] = target_test_path.read_text()
                    validations = _validate_overlay_files(
                        pipeline,
                        dependent_pipeline=dependent_pipeline,
                        overlay_target=overlay_target,
                        dependents=dependents,
                    )
                    continue
            removed_invalid_inputs = _remove_invalid_dependent_test_inputs(
                overlay_repo=overlay_content_root,
                relative_output=relative_output,
                validations=validations,
            )
            if removed_invalid_inputs:
                for path in removed_invalid_inputs:
                    supplemental_files[
                        _relative_to_rulespec_apply_content_root(
                            path, overlay_content_root
                        )
                    ] = path.read_text()
                validations = _validate_overlay_files(
                    pipeline,
                    dependent_pipeline=dependent_pipeline,
                    overlay_target=overlay_target,
                    dependents=dependents,
                )
                continue
            removed_unknown_outputs = _remove_unknown_dependent_test_outputs(
                overlay_repo=overlay_content_root,
                relative_output=relative_output,
                validations=validations,
            )
            if removed_unknown_outputs:
                for path in removed_unknown_outputs:
                    supplemental_files[
                        _relative_to_rulespec_apply_content_root(
                            path, overlay_content_root
                        )
                    ] = path.read_text()
                validations = _validate_overlay_files(
                    pipeline,
                    dependent_pipeline=dependent_pipeline,
                    overlay_target=overlay_target,
                    dependents=dependents,
                )
                continue
            removed_cross_module_outputs = _remove_cross_module_dependent_test_outputs(
                overlay_repo=overlay_content_root,
                relative_output=relative_output,
                validations=validations,
            )
            if removed_cross_module_outputs:
                for path in removed_cross_module_outputs:
                    supplemental_files[
                        _relative_to_rulespec_apply_content_root(
                            path, overlay_content_root
                        )
                    ] = path.read_text()
                validations = _validate_overlay_files(
                    pipeline,
                    dependent_pipeline=dependent_pipeline,
                    overlay_target=overlay_target,
                    dependents=dependents,
                )
                continue
            changed_tests = _complete_missing_dependent_test_inputs(
                overlay_repo=overlay_content_root,
                relative_output=relative_output,
                validations=validations,
            )
            if not changed_tests:
                break
            for path in changed_tests:
                supplemental_files[
                    _relative_to_rulespec_apply_content_root(path, overlay_content_root)
                ] = path.read_text()
            validations = _validate_overlay_files(
                pipeline,
                dependent_pipeline=dependent_pipeline,
                overlay_target=overlay_target,
                dependents=dependents,
            )
        issues: list[str] = []
        for validated_file, validation in validations:
            for validator_result in validation.results.values():
                if validator_result.error:
                    relative_file = _relative_to_rulespec_apply_content_root(
                        validated_file,
                        overlay_content_root,
                    )
                    validator_name = getattr(validator_result, "validator_name", "ci")
                    issues.append(
                        f"{relative_file}: {validator_name}: {validator_result.error}"
                    )
        return False, issues, {}


# Keep the apply-overlay validator importable for focused tests and internal
# callers, but require them to pass the already validated release explicitly.
_validate_generated_encoding_in_policy_overlay = (
    _validate_generated_encoding_in_policy_overlay_with_release
)


def _run_generated_encoding_overlay_validation(
    result,
    *,
    output_root: Path,
    policy_repo_path: Path,
    axiom_rules_path: Path,
    local_corpus_release: LocalCorpusRelease,
    validate_dependents: bool = True,
    rulespec_dependency_roots: Sequence[Path] = (),
) -> tuple[bool, list[str], dict[Path, str]]:
    """Dispatch a release-bound overlay run through the patchable test seam."""

    return _validate_generated_encoding_in_policy_overlay(
        result,
        output_root=output_root,
        policy_repo_path=policy_repo_path,
        axiom_rules_path=axiom_rules_path,
        local_corpus_release=local_corpus_release,
        validate_dependents=validate_dependents,
        rulespec_dependency_roots=rulespec_dependency_roots,
    )


def _stage_apply_overlay_dependency_roots(
    *,
    overlay_parent: Path,
    policy_repo_path: Path,
    overlay_repo_name: str,
    rulespec_dependency_roots: Sequence[Path] = (),
) -> tuple[Path, ...]:
    """Copy only caller-authorized dependency checkouts into an overlay."""
    staged_names = {overlay_repo_name}
    staged: list[Path] = []
    for dependency_root in _normalize_rulespec_dependency_roots(
        rulespec_dependency_roots
    ):
        if dependency_root.resolve() == policy_repo_path.resolve():
            continue
        if dependency_root.name in staged_names:
            raise UnsafeRulespecContextPath(
                "Apply overlay dependency collides with an existing canonical "
                f"checkout name: {dependency_root}"
            )
        target = overlay_parent / dependency_root.name
        _stage_apply_overlay_dependency_root(
            source=dependency_root,
            target=target,
        )
        staged_names.add(dependency_root.name)
        staged.append(target)
    return tuple(staged)


_APPLY_OVERLAY_IGNORED_NAMES = frozenset(
    {".git", ".venv", "__pycache__", ".pytest_cache"}
)


def _apply_overlay_copy_ignore(directory: str, names: list[str]) -> set[str]:
    ignored = set(names) & _APPLY_OVERLAY_IGNORED_NAMES
    for name in names:
        if name in ignored:
            continue
        candidate = Path(directory) / name
        if candidate.is_symlink():
            raise UnsafeRulespecContextPath(
                f"Apply overlay source contains a symlink: {candidate}"
            )
    return ignored


def _stage_apply_overlay_dependency_root(*, source: Path, target: Path) -> None:
    if target.exists() or target.is_symlink():
        raise UnsafeRulespecContextPath(
            f"Apply overlay target already exists: {target}"
        )
    if source.is_symlink() or not source.is_dir():
        raise UnsafeRulespecContextPath(
            f"Apply overlay source must be a non-symlink directory: {source}"
        )
    shutil.copytree(
        source,
        target,
        symlinks=True,
        ignore=_apply_overlay_copy_ignore,
    )


def _suppress_rulespec_ancestor_targets_for_subsection_overlay(
    overlay_repo: Path,
    relative_output: Path,
) -> list[Path]:
    """Remove ancestor RuleSpec files from a temporary subsection overlay."""
    suppressed: list[Path] = []
    content_root = _rulespec_apply_content_root(overlay_repo, relative_output)
    preserved_imports = _same_repo_imported_rulespec_paths(
        content_root / relative_output,
        policy_repo_path=overlay_repo,
    )
    for relative_path in _rulespec_ancestor_target_paths(relative_output):
        if relative_path in preserved_imports:
            continue
        for candidate in (
            content_root / relative_path,
            _rulespec_test_path(content_root / relative_path),
        ):
            if not candidate.exists() or not candidate.is_file():
                continue
            candidate.unlink()
            suppressed.append(candidate.relative_to(content_root))
    return suppressed


def _same_repo_imported_rulespec_paths(
    rules_file: Path,
    *,
    policy_repo_path: Path,
) -> set[Path]:
    """Return same-repo RuleSpec import file paths used by a generated target."""
    try:
        payload = yaml.safe_load(rules_file.read_text())
    except (OSError, yaml.YAMLError, ValueError):
        return set()
    if not isinstance(payload, dict):
        return set()
    imports = payload.get("imports")
    if not isinstance(imports, list):
        return set()

    jurisdiction = _repo_jurisdiction_prefix(policy_repo_path)
    imported_paths: set[Path] = set()
    for raw_import in imports:
        if not isinstance(raw_import, str):
            continue
        target = raw_import.strip().strip('"').strip("'").split("#", 1)[0].strip()
        target = target.strip("/")
        if not target:
            continue
        if ":" in target:
            prefix, target = target.split(":", 1)
            if prefix != jurisdiction:
                continue
            target = target.strip().strip("/")
        relative = Path(
            target if target.endswith(RULESPEC_FILE_SUFFIX) else f"{target}.yaml"
        )
        if relative.is_absolute() or any(
            part in {"", ".", ".."} for part in relative.parts
        ):
            continue
        if not relative.parts or relative.parts[0] not in RULESPEC_ATOMIC_MODULE_ROOTS:
            continue
        imported_paths.add(relative)
    return imported_paths


def _repair_generated_import_symbol_near_misses(
    *,
    rules_file: Path,
    repo_path: Path,
) -> list[str]:
    """Repair generated imports whose file exists but exported symbol nearly matches."""
    if not rules_file.exists():
        return []
    try:
        payload = yaml.safe_load(rules_file.read_text()) or {}
    except (OSError, ValueError, yaml.YAMLError):
        return []
    if not isinstance(payload, dict):
        return []
    imports = payload.get("imports")
    if not isinstance(imports, list):
        return []

    replacements: dict[tuple[Path, str], str] = {}
    repaired: list[str] = []
    for index, raw_import in enumerate(imports):
        if not isinstance(raw_import, str):
            continue
        parsed = _parse_same_repo_rulespec_import_ref(
            raw_import,
            repo_path=repo_path,
        )
        if parsed is None or parsed.symbol is None:
            continue
        exported_symbols = _rulespec_exported_rule_names(parsed.path)
        if parsed.symbol in exported_symbols:
            continue
        replacement = _closest_rulespec_exported_symbol(
            parsed.symbol,
            exported_symbols,
        )
        if replacement is None:
            continue
        imports[index] = f"{parsed.canonical_base}#{replacement}"
        replacements[(parsed.relative_path, parsed.symbol)] = replacement
        repaired.append(f"{parsed.symbol}->{replacement}")

    if not replacements:
        return []

    _repair_import_proof_atom_symbols(
        payload,
        repo_path=repo_path,
        replacements=replacements,
    )
    local_rule_names = _rulespec_rule_names_from_payload(payload)
    old_to_new: dict[str, str] = {}
    ambiguous_formula_symbols: set[str] = set()
    for (_, old_symbol), new_symbol in replacements.items():
        if old_symbol in ambiguous_formula_symbols:
            continue
        existing = old_to_new.get(old_symbol)
        if existing is not None and existing != new_symbol:
            old_to_new.pop(old_symbol, None)
            ambiguous_formula_symbols.add(old_symbol)
            continue
        old_to_new[old_symbol] = new_symbol
    for old_symbol, new_symbol in sorted(old_to_new.items()):
        if old_symbol in local_rule_names:
            continue
        _replace_formula_identifier_in_payload(
            payload,
            old=old_symbol,
            new=new_symbol,
        )
    content = yaml.safe_dump(payload, sort_keys=False, allow_unicode=False)
    rules_file.write_text(content)
    return repaired


class _RulespecImportRef(NamedTuple):
    path: Path
    relative_path: Path
    symbol: str | None
    canonical_base: str


def _parse_same_repo_rulespec_import_ref(
    raw_ref: str,
    *,
    repo_path: Path,
) -> _RulespecImportRef | None:
    reference = str(raw_ref).strip().strip('"').strip("'")
    if not reference:
        return None
    base, _, symbol = reference.partition("#")
    base = base.strip().strip("/")
    symbol = symbol.strip() or None
    if not base:
        return None

    jurisdiction = _repo_jurisdiction_prefix(repo_path)
    if ":" in base:
        prefix, base = base.split(":", 1)
        if prefix != jurisdiction:
            return None
        base = base.strip().strip("/")
    if not base:
        return None

    relative_path = Path(
        base if base.endswith(RULESPEC_FILE_SUFFIX) else f"{base}.yaml"
    )
    if relative_path.is_absolute() or any(
        part in {"", ".", ".."} for part in relative_path.parts
    ):
        return None
    if (
        not relative_path.parts
        or relative_path.parts[0] not in RULESPEC_ATOMIC_MODULE_ROOTS
    ):
        return None
    resolved = repo_path / relative_path
    if not resolved.exists() or not resolved.is_file():
        return None
    import_target = relative_path.with_suffix("").as_posix()
    return _RulespecImportRef(
        path=resolved,
        relative_path=relative_path,
        symbol=symbol,
        canonical_base=f"{jurisdiction}:{import_target}",
    )


def _rulespec_exported_rule_names(rules_file: Path) -> set[str]:
    try:
        payload = yaml.safe_load(rules_file.read_text()) or {}
    except (OSError, ValueError, yaml.YAMLError):
        return set()
    if not isinstance(payload, dict):
        return set()
    return _rulespec_rule_names_from_payload(payload)


def _rulespec_rule_names_from_payload(payload: dict[str, object]) -> set[str]:
    rules = payload.get("rules")
    if not isinstance(rules, list):
        return set()
    names: set[str] = set()
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        name = str(rule.get("name") or "").strip()
        if name:
            names.add(name)
    return names


def _replace_formula_identifier_in_payload(
    payload: dict[str, object],
    *,
    old: str,
    new: str,
) -> None:
    rules = payload.get("rules")
    if not isinstance(rules, list):
        return
    token = re.compile(rf"\b{re.escape(old)}\b")
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        versions = rule.get("versions")
        if not isinstance(versions, list):
            continue
        for version in versions:
            if not isinstance(version, dict):
                continue
            formula = version.get("formula")
            if not isinstance(formula, str):
                continue
            version["formula"] = token.sub(new, formula)


def _closest_rulespec_exported_symbol(
    symbol: str,
    exported_symbols: set[str],
) -> str | None:
    scores = sorted(
        (
            (
                difflib.SequenceMatcher(None, symbol, candidate).ratio(),
                candidate,
            )
            for candidate in exported_symbols
        ),
        reverse=True,
    )
    if not scores:
        return None
    best_score, best_candidate = scores[0]
    if best_score < 0.86:
        return None
    if len(scores) > 1 and best_score - scores[1][0] < 0.03:
        return None
    return best_candidate


def _repair_import_proof_atom_symbols(
    payload: dict[str, object],
    *,
    repo_path: Path,
    replacements: dict[tuple[Path, str], str],
) -> None:
    rules = payload.get("rules")
    if not isinstance(rules, list):
        return
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        metadata = rule.get("metadata")
        if not isinstance(metadata, dict):
            continue
        proof = metadata.get("proof")
        if not isinstance(proof, dict):
            continue
        atoms = proof.get("atoms")
        if not isinstance(atoms, list):
            continue
        for atom in atoms:
            if not isinstance(atom, dict) or atom.get("kind") != "import":
                continue
            import_payload = atom.get("import")
            if not isinstance(import_payload, dict):
                continue
            target = import_payload.get("target")
            if not isinstance(target, str):
                continue
            parsed = _parse_same_repo_rulespec_import_ref(target, repo_path=repo_path)
            if parsed is None:
                continue
            if parsed.symbol is None:
                output = str(import_payload.get("output") or "").strip()
                replacement = replacements.get((parsed.relative_path, output))
                if replacement is None:
                    continue
                import_payload["target"] = parsed.canonical_base
                import_payload["output"] = replacement
                continue
            replacement = replacements.get((parsed.relative_path, parsed.symbol))
            if replacement is None:
                continue
            import_payload["target"] = f"{parsed.canonical_base}#{replacement}"
            if import_payload.get("output") == parsed.symbol:
                import_payload["output"] = replacement


def _rulespec_ancestor_target_paths(relative_output: Path) -> list[Path]:
    """Return possible ancestor RuleSpec files for a generated subsection."""
    target = relative_output.with_suffix("")
    source_root = next(
        (
            Path(root)
            for root in sorted(RULESPEC_ATOMIC_MODULE_ROOTS)
            if target == Path(root) or Path(root) in target.parents
        ),
        None,
    )
    if source_root is None:
        return []

    ancestors: list[Path] = []
    current = target.parent
    while (
        current != Path(".")
        and current.as_posix()
        and current.as_posix() != source_root.as_posix()
    ):
        ancestors.append(Path(f"{current.as_posix()}.yaml"))
        current = current.parent
    return ancestors


def _repair_generated_restatement_source_relation_for_apply(
    *,
    rules_file: Path,
    test_file: Path,
    repo_path: Path,
    relative_output: Path,
    validation: object | None,
) -> list[str]:
    """Keep restatement modules non-executable when the model over-encodes them."""
    try:
        rules_document = yaml.safe_load(rules_file.read_text()) or {}
    except (OSError, yaml.YAMLError, ValueError):
        return []
    if not isinstance(rules_document, dict):
        return []

    rules = rules_document.get("rules")
    if not isinstance(rules, list):
        return []

    restatement_symbols, restatement_stems = _generated_restatement_symbols_and_stems(
        rules
    )
    if not restatement_symbols and not restatement_stems:
        return []

    executable_names = {
        str(rule.get("name") or "").strip()
        for rule in rules
        if isinstance(rule, dict) and _is_executable_rulespec_rule(rule)
    }
    changed = False
    repairs: list[str] = []
    if not executable_names and isinstance(rules_document.get("imports"), list):
        rules_document.pop("imports", None)
        changed = True
        repairs.append("imports")

    validation_issues = "\n".join(_validation_issue_strings(validation))
    if "Restated upstream target copied as executable RuleSpec" in validation_issues:
        remove_names = {
            name
            for name in executable_names
            if name in restatement_symbols
            or any(
                _rulespec_name_matches_restatement_stem(name, stem)
                for stem in restatement_stems
            )
        }
        if remove_names:
            rules_document["rules"] = [
                rule
                for rule in rules
                if not (
                    isinstance(rule, dict)
                    and _is_executable_rulespec_rule(rule)
                    and str(rule.get("name") or "").strip() in remove_names
                )
            ]
            changed = True
            repairs.extend(sorted(remove_names))
            _remove_local_test_outputs_and_empty_cases(
                test_file,
                target_base=(
                    f"{_repo_jurisdiction_prefix(repo_path)}:"
                    f"{_relative_rulespec_import_target(relative_output)}"
                ),
                names=remove_names,
            )
            if not any(
                isinstance(rule, dict) and _is_executable_rulespec_rule(rule)
                for rule in rules_document.get("rules") or []
            ):
                rules_document.pop("imports", None)
                if test_file.exists():
                    test_file.write_text("[]\n")

    if not changed:
        return []

    rules_file.write_text(
        yaml.safe_dump(rules_document, sort_keys=False, allow_unicode=False)
    )
    return repairs


def _generated_restatement_symbols_and_stems(
    rules: list[object],
) -> tuple[set[str], set[str]]:
    symbols: set[str] = set()
    stems: set[str] = set()
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        if str(rule.get("kind") or "").strip().lower() != "source_relation":
            continue
        source_relation = rule.get("source_relation")
        if not isinstance(source_relation, dict):
            continue
        if str(source_relation.get("type") or "").strip().lower() != "restates":
            continue
        target = _normalize_source_relation_target_ref(source_relation.get("target"))
        if target and "#" in target:
            symbol = target.rsplit("#", 1)[-1]
            _add_restatement_symbol_and_stems(symbol, symbols=symbols, stems=stems)
        verification = rule.get("verification")
        values = verification.get("values") if isinstance(verification, dict) else None
        if isinstance(values, dict):
            for value_name in values:
                _add_restatement_symbol_and_stems(
                    str(value_name),
                    symbols=symbols,
                    stems=stems,
                )
    return symbols, stems


def _add_restatement_symbol_and_stems(
    symbol: str,
    *,
    symbols: set[str],
    stems: set[str],
) -> None:
    normalized = symbol.strip()
    if not normalized:
        return
    symbols.add(normalized)
    candidates = {normalized}
    if normalized.startswith("snap_"):
        candidates.add(normalized.removeprefix("snap_"))
    suffixes = (
        "_48_states_dc_table",
        "_table",
        "_amount",
        "_amounts",
        "_value",
        "_values",
    )
    for candidate in list(candidates):
        for suffix in suffixes:
            if candidate.endswith(suffix):
                candidates.add(candidate.removesuffix(suffix))
    stems.update(candidate for candidate in candidates if candidate)


def _rulespec_name_matches_restatement_stem(name: str, stem: str) -> bool:
    if not name or not stem:
        return False
    return name == stem or name.startswith(f"{stem}_") or name.endswith(f"_{stem}")


def _remove_local_test_outputs_and_empty_cases(
    test_file: Path,
    *,
    target_base: str,
    names: set[str],
) -> bool:
    if not test_file.exists():
        return False
    try:
        cases = yaml.safe_load(test_file.read_text()) or []
    except (OSError, yaml.YAMLError, ValueError):
        return False
    if not isinstance(cases, list):
        return False

    local_outputs = {f"{target_base}#{name}" for name in names}
    changed = False
    repaired_cases: list[object] = []
    for case in cases:
        if not isinstance(case, dict):
            repaired_cases.append(case)
            continue
        outputs = case.get("output")
        if isinstance(outputs, dict):
            for output_ref in list(outputs):
                if str(output_ref).strip().strip('"').strip("'") in local_outputs:
                    outputs.pop(output_ref, None)
                    changed = True
            if not outputs:
                changed = True
                continue
        repaired_cases.append(case)

    if changed:
        test_file.write_text(
            yaml.safe_dump(repaired_cases, sort_keys=False, allow_unicode=False)
        )
    return changed


def _repair_upstream_placement_duplicate_imports(
    *,
    rules_file: Path,
    test_file: Path,
    repo_path: Path,
    relative_output: Path,
) -> list[str]:
    """Replace copied upstream executable rules with imports to canonical targets."""
    try:
        rules_document = yaml.safe_load(rules_file.read_text()) or {}
    except (OSError, yaml.YAMLError, ValueError):
        return []
    if not isinstance(rules_document, dict):
        return []

    rules = rules_document.get("rules")
    if not isinstance(rules, list):
        return []

    content_repo_path = _generated_validation_repair_policy_repo_path(
        repo_path, relative_output
    )
    relative_parts = relative_output.parts
    if (
        len(relative_parts) >= 2
        and relative_parts[1] in RULESPEC_ATOMIC_MODULE_ROOTS
        and relative_parts[0] == _repo_jurisdiction_prefix(content_repo_path)
    ):
        relative_output = Path(*relative_parts[1:])
    target_rules_file = content_repo_path / relative_output
    duplicate_targets_by_name, duplicate_indexes = (
        _upstream_placement_duplicate_targets(
            rules=rules,
            rules_file=target_rules_file,
            repo_path=content_repo_path,
        )
    )
    if not duplicate_targets_by_name:
        return []

    target_base = (
        f"{_repo_jurisdiction_prefix(content_repo_path)}:"
        f"{_relative_rulespec_import_target(relative_output)}"
    )
    remaining_rules = [
        rule for index, rule in enumerate(rules) if index not in duplicate_indexes
    ]
    if not any(_is_executable_rulespec_rule(rule) for rule in remaining_rules):
        duplicate_sources_by_name = {
            str(rule.get("name") or "").strip(): rule.get("source")
            for index, rule in enumerate(rules)
            if index in duplicate_indexes
            and isinstance(rule, dict)
            and str(rule.get("name") or "").strip()
        }
        existing_rule_names = {
            str(rule.get("name") or "").strip()
            for rule in remaining_rules
            if isinstance(rule, dict) and str(rule.get("name") or "").strip()
        }
        restatement_rules: list[dict[str, Any]] = []
        for name, target in sorted(duplicate_targets_by_name.items()):
            relation_name = f"{name}_restatement"
            suffix = 2
            while relation_name in existing_rule_names:
                relation_name = f"{name}_restatement_{suffix}"
                suffix += 1
            existing_rule_names.add(relation_name)
            restatement_rule: dict[str, Any] = {
                "name": relation_name,
                "kind": "source_relation",
                "source_relation": {
                    "type": "restates",
                    "target": target,
                },
            }
            source = duplicate_sources_by_name.get(name)
            if isinstance(source, str) and source.strip():
                restatement_rule["source"] = source.strip()
            restatement_rules.append(restatement_rule)
        rules_document["rules"] = [*remaining_rules, *restatement_rules]
        rules_document.pop("imports", None)
        rules_file.write_text(
            yaml.safe_dump(rules_document, sort_keys=False, allow_unicode=False)
        )
        if test_file.exists():
            test_file.write_text("[]\n")
        return sorted(duplicate_targets_by_name)

    imports = rules_document.get("imports")
    if not isinstance(imports, list):
        imports = []
        rules_document["imports"] = imports
    existing_imports = {
        str(raw_import).strip().strip('"').strip("'")
        for raw_import in imports
        if isinstance(raw_import, str)
    }
    for target in sorted(duplicate_targets_by_name.values()):
        if target not in existing_imports:
            imports.append(target)
            existing_imports.add(target)

    rules_document["rules"] = remaining_rules

    for rule in rules_document["rules"]:
        if not isinstance(rule, dict):
            continue
        _retarget_local_proof_imports_to_upstream(
            rule,
            target_base=target_base,
            targets_by_name=duplicate_targets_by_name,
        )

    content = yaml.safe_dump(rules_document, sort_keys=False, allow_unicode=False)
    content, _ = _repair_proof_import_hashes(
        content,
        target_base=target_base,
        rules_file=rules_file,
        repo_path=content_repo_path,
    )
    rules_file.write_text(content)

    if test_file.exists():
        _remove_local_test_output_refs_for_names(
            test_file,
            target_base=target_base,
            names=set(duplicate_targets_by_name),
        )

    return sorted(duplicate_targets_by_name)


def _upstream_placement_duplicate_targets(
    *,
    rules: list[object],
    rules_file: Path,
    repo_path: Path,
) -> tuple[dict[str, str], set[int]]:
    repo_root = Path(repo_path).resolve()
    prefix = _rulespec_repo_prefix(repo_root)
    try:
        current_file = Path(rules_file).resolve()
    except OSError:
        current_file = Path(rules_file)
    try:
        candidate_roots = _candidate_upstream_rulespec_roots(repo_root)
        index = _rulespec_executable_index_for_roots(
            tuple(str(root.resolve()) for root in candidate_roots)
        )
    except OSError:
        return {}, set()
    if not index:
        return {}, set()

    duplicate_targets_by_name: dict[str, str] = {}
    duplicate_indexes: set[int] = set()
    for rule_index, rule in enumerate(rules):
        if not isinstance(rule, dict) or not _is_executable_rulespec_rule(rule):
            continue
        signature = _rulespec_executable_signature(rule)
        if signature is None:
            continue
        name = str(rule.get("name") or "").strip()
        if not name:
            continue
        try:
            current_target = _canonical_rulespec_target(
                prefix=prefix,
                repo_root=repo_root,
                rules_file=current_file,
                symbol=name,
            )
        except ValueError:
            continue
        for candidate in index:
            if candidate.symbol != name or candidate.signature != signature:
                continue
            if candidate.target == current_target:
                continue
            if Path(candidate.source_file).resolve() == current_file:
                continue
            if _rulespec_target_is_descendant_of(current_target, candidate.target):
                continue
            duplicate_targets_by_name[name] = candidate.target
            duplicate_indexes.add(rule_index)
            break

    return duplicate_targets_by_name, duplicate_indexes


def _retarget_local_proof_imports_to_upstream(
    rule: dict[str, object],
    *,
    target_base: str,
    targets_by_name: dict[str, str],
) -> None:
    metadata = rule.get("metadata")
    if not isinstance(metadata, dict):
        return
    proof = metadata.get("proof")
    if not isinstance(proof, dict):
        return
    atoms = proof.get("atoms")
    if not isinstance(atoms, list):
        return
    for atom in atoms:
        if not isinstance(atom, dict) or atom.get("kind") != "import":
            continue
        import_payload = atom.get("import")
        if not isinstance(import_payload, dict):
            continue
        output = str(import_payload.get("output") or "").strip()
        if output not in targets_by_name:
            continue
        target = str(import_payload.get("target") or "").strip().strip('"').strip("'")
        if target not in {target_base, f"{target_base}#{output}"}:
            continue
        import_payload["target"] = targets_by_name[output]


def _remove_local_test_output_refs_for_names(
    test_file: Path,
    *,
    target_base: str,
    names: set[str],
) -> bool:
    try:
        cases = yaml.safe_load(test_file.read_text()) or []
    except (OSError, yaml.YAMLError, ValueError):
        return False
    if not isinstance(cases, list):
        return False

    local_outputs = {f"{target_base}#{name}" for name in names}
    changed = False
    for case in cases:
        if not isinstance(case, dict):
            continue
        outputs = case.get("output")
        if not isinstance(outputs, dict):
            continue
        for output_ref in list(outputs):
            if str(output_ref).strip().strip('"').strip("'") in local_outputs:
                outputs.pop(output_ref, None)
                changed = True

    if changed:
        test_file.write_text(
            yaml.safe_dump(cases, sort_keys=False, allow_unicode=False)
        )
    return changed


def _repair_imported_rule_name_collisions(
    *,
    rules_file: Path,
    test_file: Path,
    repo_path: Path,
    relative_output: Path,
) -> list[str]:
    """Rename generated local outputs that collide with imported module exports."""
    try:
        rules_document = yaml.safe_load(rules_file.read_text()) or {}
    except (OSError, yaml.YAMLError, ValueError):
        return []
    if not isinstance(rules_document, dict):
        return []

    rules = rules_document.get("rules")
    if not isinstance(rules, list):
        return []
    imports = rules_document.get("imports")
    if not isinstance(imports, list):
        return []

    imported_names = _imported_module_exported_rule_names(
        imports,
        repo_path=repo_path,
    )
    if not imported_names:
        return []

    local_names = _rulespec_rule_names_from_payload(rules_document)
    collisions = sorted(local_names & imported_names)
    if not collisions:
        return []

    existing_names = set(local_names) | imported_names
    replacements: dict[str, str] = {}
    for name in collisions:
        candidate = f"local_{name}"
        index = 2
        while candidate in existing_names:
            candidate = f"local_{name}_{index}"
            index += 1
        replacements[name] = candidate
        existing_names.add(candidate)

    target_base = (
        f"{_repo_jurisdiction_prefix(repo_path)}:"
        f"{_relative_rulespec_import_target(relative_output)}"
    )
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        name = str(rule.get("name") or "").strip()
        if name in replacements:
            rule["name"] = replacements[name]
        for old, new in replacements.items():
            _replace_formula_identifier_in_rule(rule, old=old, new=new)
        _replace_local_proof_import_targets_in_rule(
            rule,
            target_base=target_base,
            replacements=replacements,
        )

    rules_file.write_text(
        yaml.safe_dump(rules_document, sort_keys=False, allow_unicode=False)
    )

    if test_file.exists():
        _replace_local_test_output_refs(
            test_file,
            target_base=target_base,
            replacements=replacements,
        )

    return collisions


def _imported_module_exported_rule_names(
    imports: list[object],
    *,
    repo_path: Path,
) -> set[str]:
    names: set[str] = set()
    seen_files: set[Path] = set()
    for raw_import in imports:
        if not isinstance(raw_import, str):
            continue
        resolved = _same_repo_import_base_and_file(raw_import, repo_path=repo_path)
        import_file = (
            resolved[1]
            if resolved is not None
            else _rulespec_file_for_absolute_module_ref(
                raw_import,
                policy_repo_path=repo_path,
            )
        )
        if import_file is None:
            continue
        try:
            resolved_file = import_file.resolve()
        except OSError:
            resolved_file = import_file
        if resolved_file in seen_files or not import_file.exists():
            continue
        seen_files.add(resolved_file)
        names.update(_rulespec_exported_rule_names(import_file))
    return names


def _replace_formula_identifier_in_rule(
    rule: dict[str, Any],
    *,
    old: str,
    new: str,
) -> None:
    token = re.compile(rf"\b{re.escape(old)}\b")
    versions = rule.get("versions")
    if not isinstance(versions, list):
        return
    for version in versions:
        if not isinstance(version, dict):
            continue
        formula = version.get("formula")
        if isinstance(formula, str):
            version["formula"] = token.sub(new, formula)


def _replace_local_proof_import_targets_in_rule(
    rule: dict[str, Any],
    *,
    target_base: str,
    replacements: dict[str, str],
) -> None:
    metadata = rule.get("metadata")
    proof = metadata.get("proof") if isinstance(metadata, dict) else None
    atoms = proof.get("atoms") if isinstance(proof, dict) else None
    if not isinstance(atoms, list):
        return
    for atom in atoms:
        if not isinstance(atom, dict) or atom.get("kind") != "import":
            continue
        import_payload = atom.get("import")
        if not isinstance(import_payload, dict):
            continue
        target = str(import_payload.get("target") or "").strip()
        if "#" not in target or not _rulespec_ref_matches_base(target, target_base):
            continue
        output = str(import_payload.get("output") or "").strip()
        if output in replacements:
            import_payload["output"] = replacements[output]
        base, _, fragment = target.partition("#")
        if fragment in replacements:
            import_payload["target"] = f"{base}#{replacements[fragment]}"


def _replace_local_test_output_refs(
    test_file: Path,
    *,
    target_base: str,
    replacements: dict[str, str],
) -> None:
    try:
        test_cases = yaml.safe_load(test_file.read_text()) or []
    except (OSError, yaml.YAMLError, ValueError):
        return
    if not isinstance(test_cases, list):
        return

    changed = False
    for case in test_cases:
        if not isinstance(case, dict):
            continue
        output = case.get("output")
        if not isinstance(output, dict):
            continue
        case_changed = False
        updated: dict[object, object] = {}
        for key, value in output.items():
            key_text = str(key)
            if "#" in key_text and _rulespec_ref_matches_base(key_text, target_base):
                base, _, fragment = key_text.partition("#")
                replacement = replacements.get(fragment)
                if replacement is not None:
                    key = f"{base}#{replacement}"
                    case_changed = True
            updated[key] = value
        if case_changed:
            case["output"] = updated
            changed = True

    if changed:
        test_file.write_text(yaml.safe_dump(test_cases, sort_keys=False))


def _repair_mixed_scalar_output_tests(
    *,
    rules_file: Path,
    test_file: Path,
    repo_path: Path,
    relative_output: Path,
) -> list[str]:
    """Split scalar parameter outputs out of mixed entity companion tests."""
    if not test_file.exists():
        return []
    try:
        rules_document = yaml.safe_load(rules_file.read_text()) or {}
        test_cases = yaml.safe_load(test_file.read_text()) or []
    except (OSError, yaml.YAMLError, ValueError):
        return []
    if not isinstance(rules_document, dict) or not isinstance(test_cases, list):
        return []

    target_base = (
        f"{_repo_jurisdiction_prefix(repo_path)}:"
        f"{_relative_rulespec_import_target(relative_output)}"
    )
    scalar_parameter_rules: dict[str, dict[str, Any]] = {}
    for rule in rules_document.get("rules") or []:
        if not isinstance(rule, dict):
            continue
        if str(rule.get("kind") or "").strip().lower() != "parameter":
            continue
        name = str(rule.get("name") or "").strip()
        if name:
            scalar_parameter_rules[f"{target_base}#{name}"] = rule
    if not scalar_parameter_rules:
        return []
    scalar_outputs = set(scalar_parameter_rules)

    repaired_cases: list[object] = []
    repaired_names: list[str] = []
    existing_names = {
        str(case.get("name") or "") for case in test_cases if isinstance(case, dict)
    }
    for case in test_cases:
        if not isinstance(case, dict):
            repaired_cases.append(case)
            continue
        output = case.get("output")
        if not isinstance(output, dict):
            repaired_cases.append(case)
            continue

        output = dict(output)
        dropped_fractional_parameter_outputs = [
            key
            for key in output
            if _parameter_output_assertion_uses_nonterminating_fraction(
                scalar_parameter_rules.get(str(key))
            )
        ]
        for key in dropped_fractional_parameter_outputs:
            output.pop(key, None)
        if dropped_fractional_parameter_outputs:
            case_name = str(case.get("name") or "case").strip() or "case"
            if case_name not in repaired_names:
                repaired_names.append(case_name)
        if not output:
            continue

        scalar_items = {
            key: _scalar_parameter_test_expected_value(value)
            for key, value in output.items()
            if str(key) in scalar_outputs
        }
        if not scalar_items or len(scalar_items) == len(output):
            repaired_case = case
            if scalar_items:
                repaired_case = _repair_scalar_parameter_case_period(
                    case=case,
                    scalar_output_keys={str(key) for key in scalar_items},
                    scalar_parameter_rules=scalar_parameter_rules,
                )
            if dropped_fractional_parameter_outputs:
                repaired_case = dict(repaired_case)
                repaired_case["output"] = output
                repaired_cases.append(repaired_case)
            elif repaired_case is not case:
                repaired_cases.append(repaired_case)
            else:
                repaired_cases.append(case)
            if repaired_case is not case:
                case_name = str(case.get("name") or "case").strip() or "case"
                if case_name not in repaired_names:
                    repaired_names.append(case_name)
            continue

        entity_items = {
            key: value
            for key, value in output.items()
            if str(key) not in scalar_outputs
        }
        repaired_case = dict(case)
        repaired_case["output"] = entity_items
        repaired_cases.append(repaired_case)

        case_name = str(case.get("name") or "case").strip() or "case"
        scalar_case_name = _unique_test_case_name(
            f"{case_name}_scalar_outputs",
            existing_names,
        )
        existing_names.add(scalar_case_name)
        scalar_case = {
            "name": scalar_case_name,
            "period": copy.deepcopy(case.get("period")),
            "input": copy.deepcopy(case.get("input", {})),
            "output": scalar_items,
        }
        scalar_case = _repair_scalar_parameter_case_period(
            case=scalar_case,
            scalar_output_keys={str(key) for key in scalar_items},
            scalar_parameter_rules=scalar_parameter_rules,
        )
        repaired_cases.append(scalar_case)
        if case_name not in repaired_names:
            repaired_names.append(case_name)

    if not repaired_names:
        return []
    test_file.write_text(yaml.safe_dump(repaired_cases, sort_keys=False))
    return repaired_names


def _repair_scalar_parameter_case_period(
    *,
    case: dict[str, Any],
    scalar_output_keys: set[str],
    scalar_parameter_rules: dict[str, dict[str, Any]],
) -> dict[str, Any]:
    effective_date = _latest_earliest_parameter_effective_date(
        scalar_output_keys=scalar_output_keys,
        scalar_parameter_rules=scalar_parameter_rules,
    )
    if effective_date is None:
        return case
    period = case.get("period")
    period_start = _test_period_start_date(period)
    if period_start is not None and period_start >= effective_date:
        return case
    repaired_case = dict(case)
    repaired_case["period"] = _test_period_on_or_after(period, effective_date)
    return repaired_case


def _repair_future_effective_output_tests(
    *,
    rules_file: Path,
    test_file: Path,
    repo_path: Path,
    relative_output: Path,
) -> list[str]:
    """Move output assertions out of periods before the output is effective."""
    if not test_file.exists():
        return []
    try:
        rules_document = yaml.safe_load(rules_file.read_text()) or {}
        test_cases = yaml.safe_load(test_file.read_text()) or []
    except (OSError, yaml.YAMLError, ValueError):
        return []
    if not isinstance(rules_document, dict) or not isinstance(test_cases, list):
        return []

    target_base = (
        f"{_repo_jurisdiction_prefix(repo_path)}:"
        f"{_relative_rulespec_import_target(relative_output)}"
    )
    output_rules: dict[str, dict[str, Any]] = {}
    for rule in rules_document.get("rules") or []:
        if not isinstance(rule, dict):
            continue
        if str(rule.get("kind") or "").strip().lower() not in {
            "parameter",
            "derived",
        }:
            continue
        for key in _local_rulespec_output_keys(
            rule,
            target_base=target_base,
            repo_path=repo_path,
        ):
            output_rules[key] = rule
    if not output_rules:
        return []

    repaired_cases: list[object] = []
    repaired_names: list[str] = []
    existing_names = {
        str(case.get("name") or "") for case in test_cases if isinstance(case, dict)
    }
    for case in test_cases:
        if not isinstance(case, dict):
            repaired_cases.append(case)
            continue
        output = case.get("output")
        if not isinstance(output, dict) or not output:
            repaired_cases.append(case)
            continue
        period_start = _test_period_start_date(case.get("period"))
        current_items: dict[Any, Any] = {}
        future_items: dict[Any, Any] = {}
        future_dates: list[date] = []
        for key, value in output.items():
            effective_date = _earliest_rule_effective_date(output_rules.get(str(key)))
            if effective_date is not None and (
                period_start is None or period_start < effective_date
            ):
                future_items[key] = value
                future_dates.append(effective_date)
            else:
                current_items[key] = value
        if not future_items or not future_dates:
            repaired_cases.append(case)
            continue

        case_name = str(case.get("name") or "case").strip() or "case"
        effective_period = _test_period_on_or_after(
            case.get("period"),
            max(future_dates),
        )
        if current_items:
            current_case = dict(case)
            current_case["output"] = current_items
            repaired_cases.append(current_case)

            future_case_name = _unique_test_case_name(
                f"{case_name}_effective_outputs",
                existing_names,
            )
            existing_names.add(future_case_name)
            future_case = dict(case)
            future_case["name"] = future_case_name
            future_case["period"] = effective_period
            future_case["input"] = copy.deepcopy(case.get("input", {}))
            future_case["output"] = future_items
            repaired_cases.append(future_case)
        else:
            repaired_case = dict(case)
            repaired_case["period"] = effective_period
            repaired_cases.append(repaired_case)
        if case_name not in repaired_names:
            repaired_names.append(case_name)

    if not repaired_names:
        return []
    test_file.write_text(yaml.safe_dump(repaired_cases, sort_keys=False))
    return repaired_names


def _latest_earliest_parameter_effective_date(
    *,
    scalar_output_keys: set[str],
    scalar_parameter_rules: dict[str, dict[str, Any]],
) -> date | None:
    effective_dates: list[date] = []
    for output_key in scalar_output_keys:
        rule = scalar_parameter_rules.get(output_key)
        if not isinstance(rule, dict):
            continue
        rule_dates: list[date] = []
        versions = rule.get("versions")
        if not isinstance(versions, list):
            continue
        for version in versions:
            if not isinstance(version, dict):
                continue
            parsed = _parse_iso_date(version.get("effective_from"))
            if parsed is not None:
                rule_dates.append(parsed)
        if rule_dates:
            effective_dates.append(min(rule_dates))
    return max(effective_dates) if effective_dates else None


def _earliest_rule_effective_date(rule: dict[str, Any] | None) -> date | None:
    if not isinstance(rule, dict):
        return None
    versions = rule.get("versions")
    if not isinstance(versions, list):
        return None
    dates = [
        parsed
        for version in versions
        if isinstance(version, dict)
        for parsed in [_parse_iso_date(version.get("effective_from"))]
        if parsed is not None
    ]
    return min(dates) if dates else None


def _parse_iso_date(value: Any) -> date | None:
    try:
        return date.fromisoformat(str(value))
    except (TypeError, ValueError):
        return None


def _test_period_start_date(period: Any) -> date | None:
    if isinstance(period, dict):
        return _parse_iso_date(period.get("start"))
    if isinstance(period, int):
        return date(period, 1, 1)
    if isinstance(period, str):
        stripped = period.strip()
        if re.fullmatch(r"\d{4}", stripped):
            return date(int(stripped), 1, 1)
        if re.fullmatch(r"\d{4}-\d{2}", stripped):
            return date(int(stripped[:4]), int(stripped[5:]), 1)
        return _parse_iso_date(stripped)
    if isinstance(period, date):
        return period
    return None


def _test_period_on_or_after(period: Any, effective_date: date) -> Any:
    if isinstance(period, dict):
        repaired = copy.deepcopy(period)
        period_kind = str(repaired.get("period_kind") or "").lower()
        if period_kind == "month":
            start = date(effective_date.year, effective_date.month, 1)
            end = date(
                effective_date.year,
                effective_date.month,
                monthrange(effective_date.year, effective_date.month)[1],
            )
        elif period_kind == "tax_year":
            start = effective_date
            end = date(effective_date.year, 12, 31)
        else:
            start = effective_date
            end = effective_date
        repaired["start"] = start.isoformat()
        repaired["end"] = end.isoformat()
        return repaired
    if isinstance(period, str) and re.fullmatch(r"\d{4}-\d{2}", period.strip()):
        return effective_date.strftime("%Y-%m")
    return effective_date.isoformat()


def _repair_missing_entity_table_rows_for_row_ordered_outputs(
    *,
    test_file: Path,
    validation: object,
) -> list[str]:
    """Move one-row entity test inputs from scalar input into tables.<Entity>."""
    if not test_file.exists():
        return []
    repairs_by_case: dict[str, str] = {}
    for issue in _validation_issue_strings(validation):
        match = _ROW_ORDERED_WITHOUT_TABLE_RE.search(str(issue))
        if match is None:
            continue
        repairs_by_case[match.group("case")] = match.group("entity")
    if not repairs_by_case:
        return []

    try:
        loaded = yaml.safe_load(test_file.read_text()) or []
    except (OSError, yaml.YAMLError, ValueError):
        return []
    cases: list[object]
    if isinstance(loaded, dict) and isinstance(loaded.get("cases"), list):
        cases = loaded["cases"]
        output_payload: object = loaded
    elif isinstance(loaded, list):
        cases = loaded
        output_payload = cases
    else:
        return []

    repaired_names: list[str] = []
    for case in cases:
        if not isinstance(case, dict):
            continue
        case_name = str(case.get("name") or "").strip()
        entity = repairs_by_case.get(case_name)
        if not entity:
            continue
        output = case.get("output")
        if not isinstance(output, dict):
            continue
        row_lengths = {
            len(value) for value in output.values() if isinstance(value, list)
        }
        if row_lengths != {1}:
            continue
        case_input = case.get("input")
        if not isinstance(case_input, dict):
            continue
        row_inputs = {
            key: value
            for key, value in case_input.items()
            if isinstance(key, str) and "#input." in key
        }
        if not row_inputs:
            continue
        remaining_input = {
            key: value for key, value in case_input.items() if key not in row_inputs
        }
        tables = copy.deepcopy(case.get("tables") or {})
        if not isinstance(tables, dict):
            continue
        existing_rows = tables.get(entity)
        if isinstance(existing_rows, list) and existing_rows:
            continue
        tables[entity] = [row_inputs]
        case["input"] = remaining_input
        case["tables"] = tables
        repaired_names.append(case_name)

    if not repaired_names:
        return []
    test_file.write_text(yaml.safe_dump(output_payload, sort_keys=False))
    return repaired_names


def _repair_generated_unused_imports_for_apply(
    *,
    rules_file: Path,
    validation: object,
) -> list[str]:
    """Prune generated imports that validation proves are unused."""
    if not any(
        "Unused import `" in issue for issue in _validation_issue_strings(validation)
    ):
        return []
    try:
        content = rules_file.read_text()
    except OSError:
        return []
    repaired_content, removed_imports = _prune_unused_imports(content)
    if not removed_imports:
        return []
    rules_file.write_text(repaired_content)
    return removed_imports


def _validation_issue_strings(validation: object) -> list[str]:
    """Collect issue strings from a PipelineResult-like object."""
    issues: list[str] = []
    results = getattr(validation, "results", {})
    if not isinstance(results, dict):
        return issues
    for validator_result in results.values():
        for issue in getattr(validator_result, "issues", []) or []:
            issues.append(str(issue))
        error = getattr(validator_result, "error", None)
        if error:
            issues.append(str(error))
    return issues


def _repair_mixed_derived_entity_output_tests(
    *,
    rules_file: Path,
    test_file: Path,
    repo_path: Path,
    relative_output: Path,
) -> list[str]:
    """Split companion tests whose derived outputs span multiple entities."""
    if not test_file.exists():
        return []
    try:
        rules_document = yaml.safe_load(rules_file.read_text()) or {}
        test_cases = yaml.safe_load(test_file.read_text()) or []
    except (OSError, yaml.YAMLError, ValueError):
        return []
    if not isinstance(rules_document, dict) or not isinstance(test_cases, list):
        return []

    target_base = (
        f"{_repo_jurisdiction_prefix(repo_path)}:"
        f"{_relative_rulespec_import_target(relative_output)}"
    )
    derived_entity_by_output: dict[str, str] = {}
    for rule in rules_document.get("rules") or []:
        if not isinstance(rule, dict):
            continue
        if str(rule.get("kind") or "").strip().lower() != "derived":
            continue
        entity = str(rule.get("entity") or "Case").strip() or "Case"
        for key in _local_rulespec_output_keys(
            rule,
            target_base=target_base,
            repo_path=repo_path,
        ):
            derived_entity_by_output[key] = entity
    if not derived_entity_by_output:
        return []

    repaired_cases: list[object] = []
    repaired_names: list[str] = []
    existing_names = {
        str(case.get("name") or "") for case in test_cases if isinstance(case, dict)
    }
    for case in test_cases:
        if not isinstance(case, dict):
            repaired_cases.append(case)
            continue
        output = case.get("output")
        if not isinstance(output, dict):
            repaired_cases.append(case)
            continue

        entity_order: list[str] = []
        for key in output:
            entity = derived_entity_by_output.get(str(key))
            if entity is not None and entity not in entity_order:
                entity_order.append(entity)
        if len(entity_order) <= 1:
            repaired_cases.append(case)
            continue

        case_name = str(case.get("name") or "case").strip() or "case"
        for index, entity in enumerate(entity_order):
            entity_output = {
                key: value
                for key, value in output.items()
                if derived_entity_by_output.get(str(key)) == entity
            }
            if index == 0:
                for key, value in output.items():
                    if str(key) not in derived_entity_by_output:
                        entity_output[key] = value
                repaired_case = dict(case)
                repaired_case["output"] = entity_output
                repaired_cases.append(repaired_case)
                continue

            derived_case_name = _unique_test_case_name(
                f"{case_name}_{_test_case_entity_suffix(entity)}_outputs",
                existing_names,
            )
            existing_names.add(derived_case_name)
            derived_case = dict(case)
            derived_case["name"] = derived_case_name
            derived_case["period"] = copy.deepcopy(case.get("period"))
            derived_case["input"] = copy.deepcopy(case.get("input", {}))
            derived_case["output"] = entity_output
            repaired_cases.append(derived_case)
        repaired_names.append(case_name)

    if not repaired_names:
        return []
    test_file.write_text(yaml.safe_dump(repaired_cases, sort_keys=False))
    return repaired_names


def _local_rulespec_output_keys(
    rule: dict[str, Any],
    *,
    target_base: str,
    repo_path: Path,
) -> set[str]:
    name = str(rule.get("name") or "").strip()
    keys = set(_rulespec_public_item_keys(rule, policy_repo_path=repo_path))
    if name:
        keys.add(name)
        keys.add(f"{target_base}#{name}")
    item_id = str(rule.get("id") or "").strip()
    if item_id:
        keys.add(item_id)
    return {key for key in keys if key}


def _test_case_entity_suffix(entity: str) -> str:
    suffix = re.sub(r"[^a-z0-9]+", "_", entity.strip().lower())
    suffix = suffix.strip("_")
    return suffix or "entity"


def _scalar_parameter_test_expected_value(value: Any) -> Any:
    """Normalize accidental row-shaped expectations for scalar parameters."""
    if not isinstance(value, list) or not value:
        return value
    first = value[0]
    if all(item == first for item in value):
        return first
    return value


def _parameter_output_assertion_uses_nonterminating_fraction(
    rule: dict[str, Any] | None,
) -> bool:
    """Return true when a raw parameter output cannot be stably represented in YAML."""
    if not isinstance(rule, dict):
        return False
    formula = _first_parameter_formula_text(rule)
    if formula is None:
        return False
    match = re.fullmatch(r"\(?\s*(-?\d+)\s*/\s*(-?\d+)\s*\)?", formula)
    if not match:
        return False
    numerator = int(match.group(1))
    denominator = int(match.group(2))
    if denominator == 0:
        return False
    denominator = abs(denominator) // math.gcd(abs(numerator), abs(denominator))
    for factor in (2, 5):
        while denominator % factor == 0 and denominator > 1:
            denominator //= factor
    return denominator != 1


def _first_parameter_formula_text(rule: dict[str, Any]) -> str | None:
    versions = rule.get("versions")
    if not isinstance(versions, list):
        return None
    for version in versions:
        if not isinstance(version, dict):
            continue
        formula = version.get("formula")
        if formula is None:
            continue
        return str(formula).strip()
    return None


def _unique_test_case_name(base: str, existing_names: set[str]) -> str:
    if base not in existing_names:
        return base
    index = 2
    while f"{base}_{index}" in existing_names:
        index += 1
    return f"{base}_{index}"


def _validate_overlay_files(
    pipeline: ValidatorPipeline,
    *,
    dependent_pipeline: ValidatorPipeline,
    overlay_target: Path,
    dependents: list[Path],
) -> list[tuple[Path, object]]:
    validations = [
        (overlay_target, pipeline.validate(overlay_target, skip_reviewers=True))
    ]
    if validations[0][1].all_passed:
        for dependent in dependents:
            validations.append(
                (
                    dependent,
                    dependent_pipeline.validate(dependent, skip_reviewers=True),
                )
            )
    return validations


def _repair_dependent_proof_import_hashes(
    *,
    dependents: list[Path],
) -> list[Path]:
    """Refresh proof import hashes in overlay dependents after target replacement."""
    changed: list[Path] = []
    for dependent in dependents:
        try:
            content_root = find_policy_repo_root(dependent)
            if content_root is None:
                continue
            relative_dependent = dependent.relative_to(content_root)
            content = dependent.read_text()
        except (OSError, ValueError):
            continue
        target_base = (
            f"{content_root.name}:"
            f"{_relative_rulespec_import_target(relative_dependent)}"
        )
        repaired, repair_count = _repair_proof_import_hashes(
            content,
            target_base=target_base,
            rules_file=dependent,
            repo_path=content_root,
        )
        if repair_count <= 0 or repaired == content:
            continue
        dependent.write_text(repaired)
        changed.append(dependent)
    return changed


_MISSING_INPUT_RE = re.compile(
    r"(?:Test case `)?(?P<case>[^`:]+)`?(?: execution failed)?: "
    r"missing input `(?P<input>[^`]+)`"
    r"(?: for entity `(?P<entity>[^`]+)`)?"
)
_APPLY_OVERLAY_VALIDATION_REPAIR_LIMIT = 50

_INVALID_INPUT_REF_RE = re.compile(
    r"input `(?P<input>[^`]+)` does not resolve to an input slot"
)
_ABSOLUTE_RULESPEC_REF_RE = re.compile(r"^[a-z][a-z0-9_-]*:[^\s]+$")
_MIXED_DERIVED_OUTPUT_ENTITIES_RE = re.compile(
    r"Test case `(?P<case>[^`]+)` mixes derived output entities \([^)]+\)"
)
_ROW_ORDERED_WITHOUT_TABLE_RE = re.compile(
    r"Test case `(?P<case>[^`]+)` output .+ uses a row-ordered "
    r"list but has no `tables\.(?P<entity>[^`]+)` rows\."
)


def _remove_invalid_dependent_test_inputs(
    *,
    overlay_repo: Path,
    relative_output: Path,
    validations: list[tuple[Path, object]],
) -> list[Path]:
    """Remove obsolete input refs from dependent tests."""
    target_ref = (
        f"{_repo_jurisdiction_prefix(overlay_repo)}:"
        f"{_relative_rulespec_import_target(relative_output)}"
    )
    target_input_names: set[str] = set()
    target_output_names: set[str] = set()
    target_file = (
        _rulespec_apply_content_root(overlay_repo, relative_output) / relative_output
    )
    if target_file.exists():
        with contextlib.suppress(OSError, ValueError, yaml.YAMLError):
            target_content = target_file.read_text()
            target_input_names = _local_factual_input_names_from_rules_content(
                target_content
            )
            target_payload = yaml.safe_load(target_content) or {}
            target_output_names = set(_rules_by_name_from_payload(target_payload))
    changed: list[Path] = []
    for validated_file, validation in validations:
        if validated_file == target_file:
            continue
        test_path = _rulespec_test_path(validated_file)
        if not test_path.exists():
            continue
        try:
            relative_validated = _relative_to_rulespec_apply_content_root(
                validated_file,
                overlay_repo,
            )
        except ValueError:
            continue
        dependent_ref = (
            f"{_repo_jurisdiction_prefix(overlay_repo)}:"
            f"{_relative_rulespec_import_target(relative_validated)}"
        )
        invalid_refs: set[str] = set()
        for validator_result in validation.results.values():
            error = validator_result.error or ""
            for input_ref in _invalid_input_refs_from_issues([error]):
                if _invalid_dependent_test_input_ref_is_removable(
                    input_ref,
                    target_ref=target_ref,
                    dependent_ref=dependent_ref,
                    repo_path=overlay_repo,
                ):
                    invalid_refs.add(input_ref)
        if not invalid_refs:
            continue
        content = test_path.read_text()
        try:
            test_payload = yaml.safe_load(content) or []
        except (OSError, ValueError, yaml.YAMLError):
            continue
        has_target_invalid_ref = any(
            _rulespec_ref_matches_base(input_ref, target_ref)
            for input_ref in invalid_refs
        )
        if has_target_invalid_ref:
            invalid_refs.update(
                _stale_target_input_refs_in_test_payload(
                    test_payload,
                    target_ref=target_ref,
                    target_input_names=target_input_names,
                )
            )
        removable_refs = _expand_refs_with_matching_test_input_keys(
            test_payload,
            invalid_refs,
        )
        updated = _remove_input_refs_from_test_cases(content, removable_refs)
        if has_target_invalid_ref:
            try:
                updated_payload = yaml.safe_load(updated) or []
            except (OSError, ValueError, yaml.YAMLError):
                updated_payload = None
            if isinstance(updated_payload, list) and _remove_stale_target_outputs(
                updated_payload,
                target_ref=target_ref,
                target_output_names=target_output_names,
                dependent_ref=dependent_ref,
                local_input_names=_dependent_local_formula_input_names(
                    validated_file,
                    repo_path=overlay_repo,
                ),
            ):
                updated = yaml.safe_dump(
                    updated_payload,
                    sort_keys=False,
                    allow_unicode=False,
                )
        if updated == content:
            continue
        test_path.write_text(updated)
        changed.append(test_path)
    return changed


def _stale_target_input_refs_in_test_payload(
    test_payload: object,
    *,
    target_ref: str,
    target_input_names: set[str],
) -> set[str]:
    if not isinstance(test_payload, list):
        return set()
    stale_refs: set[str] = set()
    for test_case in test_payload:
        if not isinstance(test_case, dict):
            continue
        inputs = test_case.get("input")
        for input_ref in _rulespec_input_refs_from_value(inputs):
            if not _rulespec_ref_matches_base(input_ref, target_ref):
                continue
            if "#input." not in input_ref:
                continue
            input_name = input_ref.split("#input.", 1)[1].strip()
            if input_name and input_name not in target_input_names:
                stale_refs.add(input_ref)
    return stale_refs


def _rulespec_input_refs_from_value(value: object) -> set[str]:
    refs: set[str] = set()
    if isinstance(value, dict):
        for key, nested in value.items():
            key_text = str(key)
            if "#input." in key_text:
                refs.add(key_text)
            refs.update(_rulespec_input_refs_from_value(nested))
    elif isinstance(value, list):
        for item in value:
            refs.update(_rulespec_input_refs_from_value(item))
    return refs


def _remove_stale_target_outputs(
    test_payload: list[object],
    *,
    target_ref: str,
    target_output_names: set[str],
    dependent_ref: str,
    local_input_names: set[str],
) -> bool:
    changed = False
    for test_case in test_payload:
        if not isinstance(test_case, dict):
            continue
        outputs = test_case.get("output")
        if not isinstance(outputs, dict):
            continue
        for output_ref in list(outputs):
            output_text = str(output_ref)
            if not _rulespec_ref_matches_base(output_text, target_ref):
                continue
            if "#" not in output_text:
                continue
            output_name = output_text.rsplit("#", 1)[1].strip()
            if not output_name or output_name in target_output_names:
                continue
            output_value = outputs.pop(output_ref)
            if output_name in local_input_names:
                inputs = test_case.setdefault("input", {})
                if isinstance(inputs, dict):
                    inputs.setdefault(
                        f"{dependent_ref}#input.{output_name}",
                        output_value,
                    )
            changed = True
    return changed


def _invalid_dependent_test_input_ref_is_removable(
    input_ref: str,
    *,
    target_ref: str,
    dependent_ref: str,
    repo_path: Path,
) -> bool:
    if "#input." not in input_ref:
        return False
    if _rulespec_ref_matches_base(input_ref, target_ref):
        return True
    if _input_ref_is_import_output_placeholder(input_ref, repo_path=repo_path):
        return True
    return bool(
        _ABSOLUTE_RULESPEC_REF_RE.match(input_ref)
        and not _rulespec_ref_matches_base(input_ref, dependent_ref)
    )


def _remove_unknown_dependent_test_outputs(
    *,
    overlay_repo: Path,
    relative_output: Path,
    validations: list[tuple[Path, object]],
) -> list[Path]:
    """Remove obsolete output assertions from dependent tests."""
    changed: list[Path] = []
    target_path = (
        _rulespec_apply_content_root(overlay_repo, relative_output) / relative_output
    )
    jurisdiction = _repo_jurisdiction_prefix(overlay_repo)
    for validated_file, validation in validations:
        if validated_file == target_path:
            continue
        test_path = _rulespec_test_path(validated_file)
        if not test_path.exists():
            continue
        issues = [
            str(result.error)
            for result in validation.results.values()
            if getattr(result, "error", None)
        ]
        unknown_refs = _unknown_output_refs_from_issues(issues)
        if not unknown_refs:
            continue
        try:
            relative_validated = _relative_to_rulespec_apply_content_root(
                validated_file,
                overlay_repo,
            )
            test_cases = yaml.safe_load(test_path.read_text()) or []
        except (OSError, ValueError, yaml.YAMLError):
            continue
        if not isinstance(test_cases, list):
            continue

        dependent_base = (
            f"{jurisdiction}:{_relative_rulespec_import_target(relative_validated)}"
        )
        local_input_names = _dependent_local_formula_input_names(
            validated_file,
            repo_path=overlay_repo,
        )
        removable_refs = _expand_refs_with_matching_test_output_keys(
            test_cases,
            unknown_refs,
        )
        if not removable_refs:
            continue

        file_changed = False
        for test_case in test_cases:
            if not isinstance(test_case, dict):
                continue
            outputs = test_case.get("output")
            if not isinstance(outputs, dict):
                continue
            for output_ref in list(outputs):
                output_text = str(output_ref)
                if output_text not in removable_refs:
                    continue
                output_name = output_text.rsplit("#", 1)[-1].strip()
                output_value = outputs.pop(output_ref)
                if output_name in local_input_names:
                    inputs = test_case.setdefault("input", {})
                    if isinstance(inputs, dict):
                        input_ref = f"{dependent_base}#input.{output_name}"
                        inputs.setdefault(input_ref, output_value)
                file_changed = True
        if not file_changed:
            continue
        test_path.write_text(
            yaml.safe_dump(test_cases, sort_keys=False, allow_unicode=False)
        )
        changed.append(test_path)
    return changed


def _dependent_local_formula_input_names(
    rules_file: Path,
    *,
    repo_path: Path,
) -> set[str]:
    try:
        rules_content = rules_file.read_text()
        payload = yaml.safe_load(rules_content) or {}
    except (OSError, ValueError, yaml.YAMLError):
        return set()
    input_names = _local_factual_input_names_from_rules_content(rules_content)
    imports = payload.get("imports") if isinstance(payload, dict) else []
    if isinstance(imports, list):
        input_names -= _imported_module_exported_rule_names(
            imports,
            repo_path=repo_path,
        )
    return input_names


def _remove_cross_module_dependent_test_outputs(
    *,
    overlay_repo: Path,
    relative_output: Path,
    validations: list[tuple[Path, object]],
) -> list[Path]:
    """Remove imported output assertions that make dependent tests entity-mixed."""
    changed: list[Path] = []
    jurisdiction = _repo_jurisdiction_prefix(overlay_repo)
    target_path = (
        _rulespec_apply_content_root(overlay_repo, relative_output) / relative_output
    )
    for validated_file, validation in validations:
        if validated_file == target_path:
            continue
        test_path = _rulespec_test_path(validated_file)
        if not test_path.exists():
            continue
        mixed_cases: set[str] = set()
        for validator_result in validation.results.values():
            error = validator_result.error or ""
            mixed_cases.update(
                match.group("case")
                for match in _MIXED_DERIVED_OUTPUT_ENTITIES_RE.finditer(error)
            )
        if not mixed_cases:
            continue

        try:
            test_cases = yaml.safe_load(test_path.read_text()) or []
            relative_validated = _relative_to_rulespec_apply_content_root(
                validated_file,
                overlay_repo,
            )
        except (OSError, ValueError, yaml.YAMLError):
            continue
        if not isinstance(test_cases, list):
            continue

        local_ref = (
            f"{jurisdiction}:{_relative_rulespec_import_target(relative_validated)}#"
        )
        file_changed = False
        for test_case in test_cases:
            if not isinstance(test_case, dict):
                continue
            if str(test_case.get("name") or "") not in mixed_cases:
                continue
            output = test_case.get("output")
            if not isinstance(output, dict) or len(output) <= 1:
                continue
            removable = [
                key
                for key in output
                if _ABSOLUTE_RULESPEC_REF_RE.match(str(key))
                and not str(key).startswith(local_ref)
            ]
            if not removable or len(removable) == len(output):
                continue
            for key in removable:
                output.pop(key, None)
            file_changed = True
        if not file_changed:
            continue
        test_path.write_text(
            yaml.safe_dump(test_cases, sort_keys=False, allow_unicode=False)
        )
        changed.append(test_path)
    return changed


def _remove_input_refs_from_test_cases(content: str, input_refs: set[str]) -> str:
    lines = content.splitlines(keepends=True)
    blocks = _find_yaml_input_blocks(lines)
    if not blocks:
        return content

    remove_indices: set[int] = set()
    for start, end in blocks:
        for index in range(start + 1, end):
            line = lines[index]
            for input_ref in input_refs:
                if re.match(rf"^\s*{re.escape(input_ref)}\s*:", line):
                    remove_indices.add(index)
                    break
                if re.match(rf"^\s*\?\s*{re.escape(input_ref)}\s*$", line):
                    remove_indices.add(index)
                    if index + 1 < end and re.match(r"^\s*:\s*", lines[index + 1]):
                        remove_indices.add(index + 1)
                    break
    if not remove_indices:
        return content
    return "".join(
        line for index, line in enumerate(lines) if index not in remove_indices
    )


def _complete_missing_dependent_test_inputs(
    *,
    overlay_repo: Path,
    relative_output: Path,
    validations: list[tuple[Path, object]],
) -> list[Path]:
    """Fill missing generated target inputs in dependent tests."""
    target_ref = (
        f"{_repo_jurisdiction_prefix(overlay_repo)}:"
        f"{_relative_rulespec_import_target(relative_output)}"
    )
    target_file = (
        _rulespec_apply_content_root(overlay_repo, relative_output) / relative_output
    )
    target_baseline_inputs = _load_test_input_baseline(_rulespec_test_path(target_file))
    target_imported_inputs = _imported_input_refs_by_name(
        target_file,
        repo_path=overlay_repo,
    )
    target_input_names: set[str] = set()
    with contextlib.suppress(OSError, ValueError, yaml.YAMLError):
        target_input_names = _local_factual_input_names_from_rules_content(
            target_file.read_text()
        )
    changed: list[Path] = []
    for validated_file, validation in validations:
        if validated_file == target_file:
            continue
        test_path = _rulespec_test_path(validated_file)
        if not test_path.exists():
            continue
        try:
            relative_validated = _relative_to_rulespec_apply_content_root(
                validated_file,
                overlay_repo,
            )
        except ValueError:
            continue
        dependent_ref = (
            f"{_repo_jurisdiction_prefix(overlay_repo)}:"
            f"{_relative_rulespec_import_target(relative_validated)}"
        )
        missing_inputs: set[str] = set()
        for validator_result in validation.results.values():
            error = validator_result.error or ""
            for match in _MISSING_INPUT_RE.finditer(error):
                missing_inputs.add(match.group("input"))
        if not missing_inputs:
            continue
        baseline_inputs = dict(target_baseline_inputs)
        baseline_inputs.update(_load_test_input_baseline(test_path))
        imported_inputs = _merge_imported_input_refs_by_name(
            _imported_input_refs_by_name(
                validated_file,
                repo_path=overlay_repo,
            ),
            target_imported_inputs,
        )
        local_input_refs: dict[str, list[str]] = {}
        for input_name in sorted(
            _dependent_local_formula_input_names(validated_file, repo_path=overlay_repo)
        ):
            _append_unique_input_ref(
                local_input_refs,
                input_name,
                f"{dependent_ref}#input.{input_name}",
            )
        imported_inputs = _merge_imported_input_refs_by_name(
            local_input_refs,
            imported_inputs,
        )
        content = test_path.read_text()
        updated = content
        for input_name in sorted(missing_inputs):
            for input_ref, value in _default_refs_for_missing_input(
                input_name,
                target_ref=target_ref,
                baseline_inputs=baseline_inputs,
                imported_inputs=imported_inputs,
                target_input_names=target_input_names,
            ):
                updated = _insert_input_default_in_test_cases(
                    updated,
                    input_ref,
                    value,
                )
        if updated != content:
            test_path.write_text(updated)
            changed.append(test_path)
    return changed


def _merge_imported_input_refs_by_name(
    *input_maps: dict[str, list[str]],
) -> dict[str, list[str]]:
    merged: dict[str, list[str]] = {}
    for input_map in input_maps:
        for input_name, input_refs in input_map.items():
            for input_ref in input_refs:
                _append_unique_input_ref(merged, input_name, input_ref)
    return merged


def _complete_missing_imported_test_inputs(
    *,
    rules_file: Path,
    test_file: Path,
    repo_path: Path,
    validation: object,
) -> bool:
    """Fill missing input slots for imported modules in this file's tests."""
    if not test_file.exists():
        return False
    missing_assignments = _missing_input_assignments_from_validation(validation)
    missing_inputs = {assignment["input"] for assignment in missing_assignments}
    if not missing_inputs:
        return False
    current_base = _rulespec_base_for_file(rules_file, repo_path=repo_path)
    local_input_refs: dict[str, list[str]] = {}
    if current_base:
        with contextlib.suppress(OSError, ValueError, yaml.YAMLError):
            for input_name in sorted(
                _local_factual_input_names_from_rules_content(rules_file.read_text())
            ):
                _append_unique_input_ref(
                    local_input_refs,
                    input_name,
                    f"{current_base}#input.{input_name}",
                )
    imported_inputs = _merge_imported_input_refs_by_name(
        local_input_refs,
        _imported_input_refs_by_name(rules_file, repo_path=repo_path),
    )
    if not imported_inputs:
        return False

    content = test_file.read_text()
    updated = content
    relation_row_anchor_bases = [current_base] if current_base else None
    for input_name in sorted(missing_inputs):
        for input_ref in imported_inputs.get(input_name, []):
            updated = _insert_input_default_in_test_cases(
                updated,
                input_ref,
                _infer_missing_input_default(input_name),
                relation_row_anchor_bases=relation_row_anchor_bases,
            )
    for assignment in missing_assignments:
        entity_id = assignment.get("entity")
        if not entity_id:
            continue
        input_names = [assignment["input"]]
        if assignment["input"] in imported_inputs:
            # The validator reports the first missing row input it encounters.
            # Imported aggregate rules can require many defaults, so complete the
            # whole imported input surface for that row in one repair pass.
            input_names = sorted(imported_inputs)
        for input_name in input_names:
            for input_ref in imported_inputs.get(input_name, []):
                updated = _insert_input_default_in_relation_rows_for_test_cases(
                    updated,
                    input_ref=input_ref,
                    value=_infer_missing_input_default(input_name),
                    relation_row_anchor_bases=relation_row_anchor_bases,
                )
                updated = _insert_input_default_in_table_entity_rows(
                    updated,
                    input_ref=input_ref,
                    value=_infer_missing_input_default(input_name),
                    case_name=assignment["case"],
                    entity_id=entity_id,
                )
    if updated == content:
        return False
    test_file.write_text(updated)
    return True


def _missing_input_names_from_validation(validation: object) -> set[str]:
    return {
        assignment["input"]
        for assignment in _missing_input_assignments_from_validation(validation)
    }


def _missing_input_assignments_from_validation(
    validation: object,
) -> list[dict[str, str]]:
    seen_assignments: set[tuple[str, str, str | None]] = set()
    assignments: list[dict[str, str]] = []
    results = getattr(validation, "results", {})
    if not isinstance(results, dict):
        return assignments
    for validator_result in results.values():
        error = getattr(validator_result, "error", "") or ""
        for match in _MISSING_INPUT_RE.finditer(str(error)):
            key = (match.group("case"), match.group("input"), match.group("entity"))
            if key in seen_assignments:
                continue
            seen_assignments.add(key)
            assignment = {
                "case": match.group("case"),
                "input": match.group("input"),
            }
            if match.group("entity"):
                assignment["entity"] = match.group("entity")
            assignments.append(assignment)
    return assignments


def _imported_input_refs_by_name(
    rules_file: Path,
    *,
    repo_path: Path,
) -> dict[str, list[str]]:
    return _collect_imported_input_refs_by_name(
        rules_file,
        repo_path=repo_path,
        seen=set(),
        depth_remaining=4,
    )


def _collect_imported_input_refs_by_name(
    rules_file: Path,
    *,
    repo_path: Path,
    seen: set[Path],
    depth_remaining: int,
) -> dict[str, list[str]]:
    if depth_remaining < 0:
        return {}
    try:
        resolved_rules_file = rules_file.resolve()
    except OSError:
        resolved_rules_file = rules_file
    if resolved_rules_file in seen:
        return {}
    seen.add(resolved_rules_file)

    try:
        payload = yaml.safe_load(rules_file.read_text()) or {}
    except (OSError, ValueError, yaml.YAMLError):
        return {}
    imports = payload.get("imports") if isinstance(payload, dict) else None
    refs_by_name: dict[str, list[str]] = {}
    current_base = _rulespec_base_for_file(rules_file, repo_path=repo_path)
    if isinstance(payload, dict) and current_base:
        for input_name in sorted(
            _direct_imported_deferred_output_names(
                payload,
                repo_path=repo_path,
            )
        ):
            _append_unique_input_ref(
                refs_by_name,
                input_name,
                f"{current_base}#input.{input_name}",
            )
    if not isinstance(imports, list):
        return refs_by_name

    for raw_import in imports:
        if not isinstance(raw_import, str):
            continue
        resolved_import = _same_repo_import_base_and_file(
            raw_import,
            repo_path=repo_path,
        )
        if resolved_import is None:
            continue
        canonical_base, import_file = resolved_import
        if import_file is None or not import_file.exists():
            continue
        input_names = _local_factual_input_names_from_rules_content(
            import_file.read_text()
        )
        for input_name in sorted(input_names):
            _append_unique_input_ref(
                refs_by_name,
                input_name,
                f"{canonical_base}#input.{input_name}",
            )
        transitive_refs = _collect_imported_input_refs_by_name(
            import_file,
            repo_path=repo_path,
            seen=seen,
            depth_remaining=depth_remaining - 1,
        )
        for input_name, refs in transitive_refs.items():
            for input_ref in refs:
                _append_unique_input_ref(
                    refs_by_name,
                    input_name,
                    input_ref,
                )
    return refs_by_name


def _rulespec_base_for_file(rules_file: Path, *, repo_path: Path) -> str:
    try:
        relative = _relative_to_rulespec_apply_content_root(rules_file, repo_path)
    except ValueError:
        return ""
    return (
        f"{_repo_jurisdiction_prefix(repo_path)}:"
        f"{_relative_rulespec_import_target(relative)}"
    )


def _direct_imported_deferred_output_names(
    payload: dict[str, object],
    *,
    repo_path: Path,
) -> set[str]:
    imports = payload.get("imports")
    if not isinstance(imports, list):
        return set()

    names: set[str] = set()
    for raw_import in imports:
        if not isinstance(raw_import, str):
            continue
        resolved_import = _same_repo_import_base_and_file(
            raw_import,
            repo_path=repo_path,
        )
        if resolved_import is None:
            continue
        _, import_file = resolved_import
        if import_file is None or not import_file.exists():
            continue
        deferred_names = _deferred_output_names(import_file)
        if not deferred_names:
            continue
        if "#" not in raw_import:
            names.update(deferred_names)
            continue
        fragment = raw_import.rsplit("#", 1)[1].strip()
        if (
            re.fullmatch(r"[A-Za-z_][A-Za-z0-9_]*", fragment)
            and fragment in deferred_names
        ):
            names.add(fragment)
    return names


def _same_repo_import_base_and_file(
    raw_import: str,
    *,
    repo_path: Path,
) -> tuple[str, Path] | None:
    import_base = raw_import.split("#", 1)[0].strip().strip('"').strip("'").strip("/")
    if not import_base:
        return None
    jurisdiction = _repo_jurisdiction_prefix(repo_path)
    if ":" in import_base:
        prefix, target = import_base.split(":", 1)
        if prefix != jurisdiction:
            return None
        target = target.strip().strip("/")
        canonical_base = f"{prefix}:{target}"
    else:
        target = import_base
        canonical_base = f"{jurisdiction}:{target}"
    if not target:
        return None
    import_file = _import_base_to_repo_file(canonical_base, repo_path=repo_path)
    if import_file is None:
        return None
    return canonical_base, import_file


def _append_unique_input_ref(
    refs_by_name: dict[str, list[str]],
    input_name: str,
    input_ref: str,
) -> None:
    refs = refs_by_name.setdefault(input_name, [])
    if input_ref not in refs:
        refs.append(input_ref)


def _import_base_to_repo_file(import_base: str, *, repo_path: Path) -> Path | None:
    normalized = import_base.strip().strip('"').strip("'").strip("/")
    if not normalized:
        return None
    if ":" in normalized:
        target_ref = _parse_rulespec_target(normalized)
        if target_ref is not None:
            target_file = _resolve_rulespec_target_file(target_ref, repo_path)
            if target_file is not None:
                return target_file
        _, normalized = normalized.split(":", 1)
    if normalized.endswith(RULESPEC_FILE_SUFFIX):
        relative = Path(normalized)
    else:
        relative = Path(f"{normalized}.yaml")
    if (
        relative.is_absolute()
        or any(part in {"", ".", ".."} for part in relative.parts)
        or not relative.parts
        or relative.parts[0] not in RULESPEC_ATOMIC_MODULE_ROOTS
    ):
        return None
    candidates = [repo_path / relative]
    prefix = _repo_jurisdiction_prefix(repo_path)
    if relative.parts and relative.parts[0] in RULESPEC_ATOMIC_MODULE_ROOTS:
        candidates.append(repo_path / prefix / relative)
    for candidate in candidates:
        if candidate.exists():
            return candidate
    return candidates[0]


def _load_test_input_baseline(test_path: Path) -> dict[str, object]:
    """Return the first companion-test input block for generated defaults."""
    try:
        cases = yaml.safe_load(test_path.read_text()) or []
    except (OSError, yaml.YAMLError, ValueError):
        return {}
    if not isinstance(cases, list):
        return {}
    for case in cases:
        if not isinstance(case, dict):
            continue
        inputs = case.get("input")
        if isinstance(inputs, dict):
            return {str(key): value for key, value in inputs.items()}
    return {}


def _default_refs_for_missing_input(
    input_name: str,
    *,
    target_ref: str,
    baseline_inputs: dict[str, object],
    imported_inputs: dict[str, list[str]] | None = None,
    target_input_names: set[str] | None = None,
) -> list[tuple[str, object]]:
    suffix = f"#input.{input_name}"
    matches = [
        (reference, value)
        for reference, value in baseline_inputs.items()
        if reference.endswith(suffix)
    ]
    if matches:
        return matches
    imported_matches = [
        (reference, _infer_missing_input_default(input_name))
        for reference in (imported_inputs or {}).get(input_name, [])
    ]
    if imported_matches:
        return imported_matches
    if target_input_names is not None and input_name not in target_input_names:
        return []
    return [
        (f"{target_ref}#input.{input_name}", _infer_missing_input_default(input_name))
    ]


def _infer_missing_input_default(input_name: str) -> object:
    normalized = input_name.lower()
    if _factual_input_name_looks_boolean(input_name):
        return False
    if "contribution_and_benefit_base" in normalized:
        return 999999999
    tokens = set(re.split(r"[^a-z0-9]+", normalized))
    numeric_markers = (
        "amount",
        "base",
        "compensation",
        "count",
        "cost",
        "costs",
        "credit",
        "credits",
        "deduction",
        "deductions",
        "expense",
        "expenses",
        "gross",
        "hour",
        "hours",
        "income",
        "limit",
        "net",
        "number",
        "num",
        "rate",
        "tax",
        "threshold",
        "value",
        "wage",
        "wages",
        "earning",
        "earnings",
    )
    if tokens.intersection(numeric_markers):
        return 0
    return False


def _insert_input_default_in_test_cases(
    content: str,
    input_ref: str,
    value: object,
    *,
    relation_row_anchor_bases: list[str] | None = None,
) -> str:
    """Insert an input default into every concrete test input block that needs it."""
    lines = content.splitlines(keepends=True)
    lines = _expand_empty_inline_yaml_input_blocks(lines)
    blocks = _find_yaml_input_blocks(lines)
    if not blocks:
        return content

    anchored_blocks = [
        block for block in blocks if re.search(r"\s&\S+", lines[block[0]])
    ]
    target_blocks = [anchored_blocks[0]] if anchored_blocks else list(blocks)
    if anchored_blocks:
        for block in blocks:
            if block in target_blocks:
                continue
            block_text = "".join(lines[block[0] : block[1]])
            if "<<:" in block_text:
                continue
            target_blocks.append(block)

    rendered = _format_yaml_scalar(value)
    for start, end in sorted(target_blocks, reverse=True):
        block_text = "".join(lines[start:end])
        if re.search(rf"^\s*{re.escape(input_ref)}\s*:", block_text, re.MULTILINE):
            continue
        match = re.match(r"^(?P<indent>\s*)input:\s*", lines[start])
        if not match:
            continue
        indent = match.group("indent") + "  "
        newline = "\n" if lines[start].endswith("\n") else ""
        lines.insert(start + 1, f"{indent}{input_ref}: {rendered}{newline}")
    lines = _insert_input_default_in_relation_rows(
        lines,
        input_ref,
        rendered,
        anchor_bases=relation_row_anchor_bases,
    )
    return "".join(lines)


def _insert_input_default_in_relation_rows_for_test_cases(
    content: str,
    *,
    input_ref: str,
    value: object,
    relation_row_anchor_bases: list[str] | None = None,
) -> str:
    lines = content.splitlines(keepends=True)
    lines = _expand_empty_inline_yaml_input_blocks(lines)
    updated = _insert_input_default_in_relation_rows(
        lines,
        input_ref,
        _format_yaml_scalar(value),
        anchor_bases=relation_row_anchor_bases,
    )
    return "".join(updated)


def _expand_empty_inline_yaml_input_blocks(lines: list[str]) -> list[str]:
    expanded = list(lines)
    for index, line in enumerate(expanded):
        match = re.match(
            r"^(?P<indent>\s*)input:(?P<anchor>\s*&\S+)?\s*\{\}\s*(?P<comment>#.*)?(?P<newline>\r?\n?)$",
            line,
        )
        if not match:
            continue
        anchor = match.group("anchor") or ""
        comment = f" {match.group('comment')}" if match.group("comment") else ""
        newline = match.group("newline")
        expanded[index] = f"{match.group('indent')}input:{anchor}{comment}{newline}"
    return expanded


def _insert_input_default_in_table_entity_rows(
    content: str,
    *,
    input_ref: str,
    value: object,
    case_name: str,
    entity_id: str,
) -> str:
    """Insert an input default into table rows matching a validation entity id."""
    try:
        payload = yaml.safe_load(content) or []
    except (ValueError, yaml.YAMLError):
        return content
    if not isinstance(payload, list):
        return content

    changed = False
    for test_case in payload:
        if not isinstance(test_case, dict) or test_case.get("name") != case_name:
            continue
        row_value = value
        inputs = test_case.get("input")
        if isinstance(inputs, dict) and input_ref in inputs:
            row_value = inputs[input_ref]
        tables = test_case.get("tables")
        if not isinstance(tables, dict):
            continue
        for table_entity, rows in tables.items():
            if not isinstance(rows, list):
                continue
            for row_index, row in enumerate(rows, 1):
                if not isinstance(row, dict):
                    continue
                if (
                    _rulespec_table_row_entity_id(str(table_entity), row, row_index)
                    != entity_id
                ):
                    continue
                if input_ref in row:
                    continue
                row[input_ref] = row_value
                changed = True

    if not changed:
        return content
    return yaml.safe_dump(payload, sort_keys=False, allow_unicode=False)


def _insert_input_default_in_relation_rows(
    lines: list[str],
    input_ref: str,
    rendered_value: str,
    *,
    anchor_bases: list[str] | None = None,
) -> list[str]:
    """Insert an input default into relation entity rows sharing module anchors."""
    if "#input." not in input_ref:
        return lines
    input_base = input_ref.split("#input.", 1)[0]
    row_anchor_bases = [input_base]
    for anchor_base in anchor_bases or []:
        if anchor_base and anchor_base not in row_anchor_bases:
            row_anchor_bases.append(anchor_base)

    insertions: dict[int, list[str]] = {}
    remove_indices: set[int] = set()
    for input_start, input_end in _find_yaml_input_blocks(lines):
        index = input_start + 1
        while index < input_end:
            match = re.match(r"^(?P<indent>\s*)-\s+", lines[index])
            if not match:
                index += 1
                continue
            item_indent = len(match.group("indent"))
            item_end = index + 1
            while item_end < input_end:
                candidate = lines[item_end]
                if (
                    candidate.strip()
                    and len(candidate) - len(candidate.lstrip(" ")) <= item_indent
                ):
                    break
                item_end += 1
            item_text = "".join(lines[index:item_end])
            if input_ref not in item_text and any(
                f"{anchor_base}#input." in item_text for anchor_base in row_anchor_bases
            ):
                carried_value, obsolete_line_indices = (
                    _similar_relation_row_input_value(
                        lines=lines,
                        start=index,
                        end=item_end,
                        input_base=input_base,
                        input_ref=input_ref,
                    )
                )
                if carried_value is not None:
                    rendered = carried_value
                    remove_indices.update(obsolete_line_indices)
                else:
                    rendered = rendered_value
                indent = " " * (item_indent + 2)
                newline = "\n" if lines[index].endswith("\n") else ""
                insertions.setdefault(index + 1, []).append(
                    f"{indent}{input_ref}: {rendered}{newline}"
                )
            index = item_end

    if not insertions and not remove_indices:
        return lines

    updated: list[str] = []
    for index, line in enumerate(lines):
        updated.extend(insertions.get(index, []))
        if index not in remove_indices:
            updated.append(line)
    updated.extend(insertions.get(len(lines), []))
    return updated


def _similar_relation_row_input_value(
    *,
    lines: list[str],
    start: int,
    end: int,
    input_base: str,
    input_ref: str,
) -> tuple[str | None, set[int]]:
    missing_name = input_ref.split("#input.", 1)[1]
    best_score = 0.0
    best_value: str | None = None
    best_indices: set[int] = set()
    tied = False
    pattern = re.compile(
        rf"^\s*(?P<ref>{re.escape(input_base)}#input\.(?P<name>[A-Za-z0-9_]+))\s*:\s*(?P<value>[^#\n]+)"
    )
    for index in range(start + 1, end):
        match = pattern.match(lines[index])
        if not match:
            continue
        candidate_name = match.group("name")
        score = _input_name_similarity(missing_name, candidate_name)
        if score < 0.5:
            continue
        if score == best_score:
            tied = True
            continue
        if score > best_score:
            best_score = score
            best_value = match.group("value").strip()
            best_indices = {index}
            tied = False
    if tied or best_value is None:
        return None, set()
    return best_value, best_indices


_INPUT_NAME_STOPWORDS = {
    "a",
    "an",
    "for",
    "individual",
    "is",
    "of",
    "person",
    "section",
    "the",
    "under",
}


def _input_name_similarity(left: str, right: str) -> float:
    left_tokens = _input_name_tokens(left)
    right_tokens = _input_name_tokens(right)
    if not left_tokens or not right_tokens:
        return 0.0
    overlap = left_tokens & right_tokens
    if len(overlap) < 2:
        return 0.0
    return len(overlap) / len(left_tokens | right_tokens)


def _input_name_tokens(name: str) -> set[str]:
    return {
        _singular_input_name_token(token)
        for token in re.split(r"[^a-z0-9]+", name.lower())
        if token and not token.isdigit() and token not in _INPUT_NAME_STOPWORDS
    }


def _singular_input_name_token(token: str) -> str:
    if len(token) > 4 and token.endswith("ies"):
        return f"{token[:-3]}y"
    if len(token) > 4 and token.endswith("s") and not token.endswith("ss"):
        return token[:-1]
    return token


def _find_yaml_input_blocks(lines: list[str]) -> list[tuple[int, int]]:
    blocks: list[tuple[int, int]] = []
    for index, line in enumerate(lines):
        match = re.match(r"^(?P<indent>\s*)input:\s*(?:&\S+\s*)?(?:#.*)?$", line)
        if not match:
            continue
        block_indent = len(match.group("indent"))
        end = index + 1
        while end < len(lines):
            candidate = lines[end]
            if (
                candidate.strip()
                and len(candidate) - len(candidate.lstrip(" ")) <= block_indent
            ):
                break
            end += 1
        blocks.append((index, end))
    return blocks


def _format_yaml_scalar(value: object) -> str:
    if isinstance(value, bool):
        return "true" if value else "false"
    if value is None:
        return "null"
    if isinstance(value, int | float):
        return str(value)
    dumped = yaml.safe_dump(value, default_flow_style=True).strip()
    if dumped.endswith("\n..."):
        dumped = dumped.removesuffix("\n...").strip()
    return dumped


def _insert_false_input_default(content: str, input_ref: str) -> str:
    """Insert a false input default into test input blocks."""
    return _insert_input_default_in_test_cases(content, input_ref, False)


def _rulespec_test_path(path: Path) -> Path:
    """Return the companion RuleSpec test path."""
    return path.with_name(f"{path.stem}.test.yaml")


def _find_rulespec_dependents(
    policy_repo_path: Path, relative_output: Path
) -> list[Path]:
    """Find RuleSpec files that directly import the generated output."""
    target = _relative_rulespec_import_target(relative_output)
    jurisdiction = _repo_jurisdiction_prefix(policy_repo_path)
    content_root = _rulespec_apply_content_root(policy_repo_path, relative_output)
    dependents: list[Path] = []
    for root in sorted(RULESPEC_ATOMIC_MODULE_ROOTS):
        root_path = content_root / root
        if not root_path.exists():
            continue
        for candidate in sorted(root_path.rglob("*.yaml")):
            if candidate.name.endswith(".test.yaml"):
                continue
            try:
                relative_candidate = candidate.relative_to(content_root)
            except ValueError:
                continue
            if relative_candidate == relative_output:
                continue
            if _rulespec_file_imports_target(
                candidate, target=target, jurisdiction=jurisdiction
            ):
                dependents.append(candidate)
    return dependents


def _relative_rulespec_import_target(relative_output: Path) -> str:
    return relative_output.with_suffix("").as_posix()


def _rulespec_anchor_base_for_output(repo_path: Path, relative_output: Path) -> str:
    target_path = relative_output.with_suffix("")
    parts = target_path.parts
    if len(parts) > 1 and parts[0] not in RULESPEC_ATOMIC_MODULE_ROOTS:
        jurisdiction = parts[0]
        target = Path(*parts[1:]).as_posix()
    else:
        jurisdiction = _repo_jurisdiction_prefix(repo_path)
        target = target_path.as_posix()
    return f"{jurisdiction}:{target}"


def _rulespec_file_imports_target(
    path: Path, *, target: str, jurisdiction: str
) -> bool:
    try:
        payload = yaml.safe_load(path.read_text())
    except (OSError, yaml.YAMLError, ValueError):
        return False
    if not isinstance(payload, dict):
        return False
    imports = payload.get("imports")
    if not isinstance(imports, list):
        return False
    canonical = f"{jurisdiction}:{target}"
    for raw_import in imports:
        if not isinstance(raw_import, str):
            continue
        import_target = raw_import.split("#", 1)[0].strip().strip("/")
        if import_target == target or import_target == canonical:
            return True
    return False


def _log_eval_result(
    result,
    *,
    db_path: Path,
    end_session: bool = True,
    log_issue: bool = True,
    prior_attempts: Sequence[_FailedEncodeAttempt] = (),
    final_attempt_success: bool | None = None,
    final_attempt_error: str | None = None,
) -> EncodingRun:
    """Persist an eval-backed encode run in the local run history DB."""
    rulespec_content = _read_optional_text(getattr(result, "output_file", ""))
    source_text = _read_eval_source_text(getattr(result, "context_manifest_file", ""))
    iterations: list[Iteration] = []
    for attempt_number, failed_attempt in enumerate(prior_attempts, 1):
        iterations.append(
            Iteration(
                attempt=attempt_number,
                duration_ms=int(getattr(failed_attempt.result, "duration_ms", 0) or 0),
                errors=[
                    IterationError(
                        error_type="validation",
                        message=failed_attempt.error,
                    )
                ],
                success=False,
            )
        )
    if final_attempt_success is None:
        resolved_final_success = bool(getattr(result, "success", False))
        final_error = getattr(result, "error", None)
    else:
        resolved_final_success = final_attempt_success
        final_error = final_attempt_error
    final_errors = []
    if isinstance(final_error, str) and final_error:
        final_errors.append(
            IterationError(
                error_type="validation",
                message=final_error,
            )
        )
    iterations.append(
        Iteration(
            attempt=len(iterations) + 1,
            duration_ms=int(getattr(result, "duration_ms", 0) or 0),
            errors=final_errors,
            success=resolved_final_success,
        )
    )
    attempt_results = [
        *(failed_attempt.result for failed_attempt in prior_attempts),
        result,
    ]

    run = EncodingRun(
        citation=result.citation,
        file_path=str(result.output_file),
        source_text=source_text,
        iterations=iterations,
        total_duration_ms=sum(iteration.duration_ms for iteration in iterations),
        agent_type=f"{result.backend}:encoder",
        agent_model=str(result.model or ""),
        rulespec_content=rulespec_content,
        review_results=_review_results_from_eval_metrics(result.metrics),
        axiom_encode_version=__version__,
    )
    run.session_id = f"encode-{run.id}"
    db = EncodingDB(db_path)
    db.log_run(run)
    repair_manifest = _write_eval_repair_manifest(result, run) if log_issue else None
    _log_eval_session(
        db,
        result,
        run,
        repair_manifest=repair_manifest,
        log_issue=log_issue,
        end_session=end_session,
        attempt_results=attempt_results,
    )
    return run


def _log_eval_session(
    db: EncodingDB,
    result,
    run: EncodingRun,
    *,
    repair_manifest: Path | None = None,
    log_issue: bool = True,
    end_session: bool = True,
    attempt_results: Sequence[Any] = (),
) -> None:
    """Persist a minimal SDK-style session for eval-backed encode runs."""
    attempts = list(attempt_results) or [result]

    def _sum_attempt_field(field: str) -> int:
        return sum(int(getattr(attempt, field, 0) or 0) for attempt in attempts)

    attempt_costs = [
        float(cost)
        for attempt in attempts
        if isinstance(
            (cost := getattr(attempt, "estimated_cost_usd", None)), (int, float)
        )
        and not isinstance(cost, bool)
    ]

    session = db.start_session(
        model=str(getattr(result, "model", "") or ""),
        cwd=os.getcwd(),
        session_id=run.session_id,
        run_id=run.id,
        axiom_encode_version=__version__,
    )
    db.update_session_tokens(
        session.id,
        input_tokens=_sum_attempt_field("input_tokens"),
        output_tokens=_sum_attempt_field("output_tokens"),
        cache_read_tokens=_sum_attempt_field("cache_read_tokens"),
        cache_creation_tokens=_sum_attempt_field("cache_creation_tokens"),
    )
    db.log_event(
        session.id,
        "encode_request",
        content=f"Encode {getattr(result, 'citation', run.citation)} with {getattr(result, 'runner', '')}",
        tool_name="axiom-encode",
        metadata={
            "run_id": run.id,
            "citation": run.citation,
            "backend": getattr(result, "backend", ""),
            "model": getattr(result, "model", ""),
            "mode": str(getattr(result, "mode", "")),
        },
    )
    result_summary = {
        "run_id": run.id,
        "citation": run.citation,
        "success": bool(getattr(result, "success", False)),
        "standalone_validation_success": bool(getattr(result, "success", False)),
        "duration_ms": _sum_attempt_field("duration_ms"),
        "generation_attempt_count": len(attempts),
        "estimated_cost_usd": sum(attempt_costs) if attempt_costs else None,
        "input_tokens": _sum_attempt_field("input_tokens"),
        "output_tokens": _sum_attempt_field("output_tokens"),
        "cache_read_tokens": _sum_attempt_field("cache_read_tokens"),
        "cache_creation_tokens": _sum_attempt_field("cache_creation_tokens"),
        "reasoning_output_tokens": _sum_attempt_field("reasoning_output_tokens"),
        "retrieved_file_count": len(getattr(result, "retrieved_files", []) or []),
        "unexpected_access_count": len(
            getattr(result, "unexpected_accesses", []) or []
        ),
        "output_file": str(getattr(result, "output_file", "") or ""),
        "trace_file": str(getattr(result, "trace_file", "") or ""),
        "context_manifest_file": str(
            getattr(result, "context_manifest_file", "") or ""
        ),
        "repair_manifest": str(repair_manifest) if repair_manifest else None,
    }
    db.log_event(
        session.id,
        "encode_result",
        content=json.dumps(result_summary, indent=2, sort_keys=True),
        tool_name="axiom-encode",
        metadata={"run_id": run.id, "success": result_summary["success"]},
    )
    error = getattr(result, "error", None)
    if log_issue and isinstance(error, str) and error:
        db.log_event(
            session.id,
            "encode_issue",
            content=error,
            tool_name="validator",
            metadata={
                "run_id": run.id,
                "repair_manifest": str(repair_manifest) if repair_manifest else None,
            },
        )
    if end_session:
        db.end_session(session.id)


def _initial_encode_outcome(result, *, apply_requested: bool) -> dict:
    """Build the workflow-level outcome object for an eval-backed encode run."""
    standalone_success = bool(getattr(result, "success", False))
    outcome = {
        "standalone_validation_success": standalone_success,
        "apply_requested": bool(apply_requested),
        "overlay_validation_success": None,
        "apply_success": False if apply_requested else None,
        "final_success": standalone_success if not apply_requested else False,
        "status": "standalone_validated" if standalone_success else "standalone_failed",
        "primary_error": getattr(result, "error", None),
        "apply_error": None,
        "applied_files": [],
    }
    metrics = getattr(result, "metrics", None)
    if metrics is not None and not standalone_success:
        try:
            labeled_issues = [
                (gate, issues)
                for gate, attribute in (
                    ("compile", "compile_issues"),
                    ("ci", "ci_issues"),
                    ("numeric_occurrence", "numeric_occurrence_issues"),
                    ("generalist_review", "generalist_review_issues"),
                    ("policyengine", "policyengine_issues"),
                    ("taxsim", "taxsim_issues"),
                )
                if (issues := getattr(metrics, attribute, None))
            ]
            outcome.update(summarize_validation_failures(labeled_issues))
        except Exception:
            outcome["validation_failure_counts"] = {"telemetry:error": 1}
    return outcome


def _replace_overlay_validation_failures(outcome: dict, issues: Sequence[str]) -> None:
    """Replace any standalone failure telemetry with the overlay block reason."""
    if not issues:
        # The `standalone_failed:` block route arrives with no overlay issues;
        # the standalone summary is the only telemetry that run has. Keep it.
        return
    for key in (
        "validation_failures",
        "validation_failures_truncated",
        "validation_failure_counts",
    ):
        outcome.pop(key, None)
    try:
        outcome.update(summarize_validation_failures([("overlay", issues)]))
    except Exception:
        outcome["validation_failure_counts"] = {"telemetry:error": 1}


def _record_encode_outcome(
    *,
    db_path: Path,
    result,
    run: EncodingRun,
    outcome: dict,
) -> Path | None:
    """Persist final encode workflow status and close the encode session."""
    db = EncodingDB(db_path)
    run.outcome = dict(outcome)
    db.update_run_outcome(run.id, run.outcome)
    db.log_event(
        run.session_id,
        "encode_outcome",
        content=json.dumps(run.outcome, indent=2, sort_keys=True),
        tool_name="axiom-encode",
        metadata={
            "run_id": run.id,
            "status": run.outcome.get("status"),
            "final_success": run.outcome.get("final_success"),
            "standalone_validation_success": run.outcome.get(
                "standalone_validation_success"
            ),
            "apply_requested": run.outcome.get("apply_requested"),
            "overlay_validation_success": run.outcome.get("overlay_validation_success"),
            "apply_success": run.outcome.get("apply_success"),
        },
    )

    repair_manifest = None
    if run.outcome.get("final_success") is not True:
        if run.outcome.get("standalone_validation_success") is not True:
            repair_manifest = _write_eval_repair_manifest(result, run)
        issue = _encode_outcome_issue(result, run.outcome)
        if issue:
            db.log_event(
                run.session_id,
                "encode_issue",
                content=issue,
                tool_name="validator",
                metadata={
                    "run_id": run.id,
                    "status": run.outcome.get("status"),
                    "repair_manifest": str(repair_manifest)
                    if repair_manifest
                    else None,
                },
            )
    db.end_session(run.session_id)
    return repair_manifest


def _encode_iteration_verdict(
    result,
    outcome: dict[str, Any],
) -> tuple[bool, str | None]:
    """Map the final full-gate outcome to one generation iteration verdict."""
    status = outcome.get("status")
    if status in {"apply_applied", "apply_blocked_manifest"}:
        return True, None
    if status in {"apply_blocked_generation", "apply_blocked_validation"}:
        return False, _encode_outcome_issue(result, outcome)
    success = bool(getattr(result, "success", False))
    return success, None if success else _encode_outcome_issue(result, outcome)


def _encode_outcome_issue(result, outcome: dict) -> str:
    for key in ("apply_error", "primary_error"):
        value = outcome.get(key)
        if isinstance(value, str) and value:
            return value
    error = getattr(result, "error", None)
    if isinstance(error, str) and error:
        return error
    status = outcome.get("status")
    if isinstance(status, str) and status:
        return status
    return ""


def _write_eval_repair_manifest(result, run: EncodingRun) -> Path | None:
    """Write a small action manifest for failed eval-backed encode runs."""
    if bool(getattr(result, "success", False)):
        return None

    manifest_path = _eval_repair_manifest_path(result)
    if manifest_path is None:
        return None
    try:
        manifest_path.parent.mkdir(parents=True, exist_ok=True)
        manifest = {
            "schema_version": "axiom-encode/repair-manifest/v1",
            "created_at": _utc_now_iso(),
            "run_id": run.id,
            "session_id": run.session_id,
            "citation": run.citation,
            "runner": getattr(result, "runner", ""),
            "backend": getattr(result, "backend", ""),
            "model": getattr(result, "model", ""),
            "mode": str(getattr(result, "mode", "")),
            "error": getattr(result, "error", None),
            "files": {
                "output": str(getattr(result, "output_file", "") or ""),
                "trace": str(getattr(result, "trace_file", "") or ""),
                "context_manifest": str(
                    getattr(result, "context_manifest_file", "") or ""
                ),
            },
            "actions": [
                {
                    "id": "inspect_trace",
                    "label": "Inspect the model trace and validation output",
                    "path": str(getattr(result, "trace_file", "") or ""),
                },
                {
                    "id": "rerun_encode",
                    "label": "Rerun axiom-encode encode for the same citation",
                    "citation": run.citation,
                    "backend": getattr(result, "backend", ""),
                    "model": getattr(result, "model", ""),
                },
            ],
        }
        manifest_path.write_text(json.dumps(manifest, indent=2) + "\n")
    except OSError:
        return None
    return manifest_path


def _eval_repair_manifest_path(result) -> Path | None:
    output_file = getattr(result, "output_file", None)
    if not output_file:
        return None
    return Path(str(output_file)).with_suffix(".repair.json")


def _sync_run_to_supabase_if_configured(
    run: EncodingRun, *, db_path: Path = DEFAULT_DB
) -> dict[str, bool]:
    if not (
        os.environ.get("AXIOM_ENCODE_SUPABASE_URL")
        and os.environ.get("AXIOM_ENCODE_SUPABASE_SECRET_KEY")
    ):
        print(
            f"WARNING: run {run.id} ({run.citation}) was NOT synced to Supabase; "
            "it will not appear on the ops dashboard. Set "
            "AXIOM_ENCODE_SUPABASE_URL and AXIOM_ENCODE_SUPABASE_SECRET_KEY, "
            "or reconcile later with `axiom-encode sync-applied-runs`.",
            file=sys.stderr,
        )
        return {"configured": False, "run": False, "session": False}
    from .supabase_sync import sync_agent_sessions_to_supabase, sync_run_to_supabase

    run_synced = sync_run_to_supabase(run, "reviewer_agent")
    session_synced = False
    if run_synced and run.session_id:
        session_stats = sync_agent_sessions_to_supabase(
            session_id=run.session_id,
            db_path=db_path,
        )
        session_synced = (
            session_stats.get("synced", 0) > 0 and session_stats.get("failed", 0) == 0
        )
    return {"configured": True, "run": run_synced, "session": session_synced}


def _read_optional_text(path_value) -> str:
    if not path_value:
        return ""
    path = Path(str(path_value))
    if not path.exists() or not path.is_file():
        return ""
    return path.read_text()


def _read_eval_source_text(context_manifest_file) -> str | None:
    if not context_manifest_file:
        return None
    manifest_path = Path(str(context_manifest_file))
    if not manifest_path.exists() or not manifest_path.is_file():
        return None
    try:
        manifest = json.loads(manifest_path.read_text())
    except json.JSONDecodeError:
        return None
    source_text_file = manifest.get("source_text_file")
    if not isinstance(source_text_file, str) or not source_text_file:
        return None
    source_text_path = manifest_path.parent / source_text_file
    source_text = _read_optional_text(source_text_path)
    return source_text or None


def _review_results_from_eval_metrics(metrics) -> ReviewResults | None:
    if metrics is None:
        return None

    reviews = [
        ReviewResult(
            reviewer="rulespec_reviewer",
            passed=bool(metrics.compile_pass),
            items_checked=10,
            items_passed=10 if metrics.compile_pass else 0,
            critical_issues=list(metrics.compile_issues or []),
        ),
        ReviewResult(
            reviewer="formula_reviewer",
            passed=bool(metrics.ci_pass),
            items_checked=10,
            items_passed=10 if metrics.ci_pass else 0,
            critical_issues=list(metrics.ci_issues or []),
        ),
        ReviewResult(
            reviewer="parameter_reviewer",
            passed=metrics.ungrounded_numeric_count == 0,
            items_checked=10,
            items_passed=10 if metrics.ungrounded_numeric_count == 0 else 0,
            important_issues=[
                item.raw
                for item in (metrics.grounding or [])
                if not getattr(item, "grounded", False)
            ],
        ),
    ]

    if metrics.generalist_review_score is not None:
        score = max(0, min(10, int(round(metrics.generalist_review_score))))
        reviews.append(
            ReviewResult(
                reviewer="integration_reviewer",
                passed=bool(metrics.generalist_review_pass),
                items_checked=10,
                items_passed=score,
                important_issues=list(metrics.generalist_review_issues or []),
            )
        )

    return ReviewResults(
        reviews=reviews,
        policyengine_match=metrics.policyengine_score,
    )


def _print_eval_metrics(result) -> None:
    """Print human-readable eval metrics when present."""
    if not result.metrics:
        return

    print(
        f"  compile={'yes' if result.metrics.compile_pass else 'no'} ci={'yes' if result.metrics.ci_pass else 'no'}"
    )
    print(
        f"  grounded={result.metrics.grounded_numeric_count} ungrounded={result.metrics.ungrounded_numeric_count} embedded_source={'yes' if result.metrics.embedded_source_present else 'no'}"
    )
    if result.metrics.generalist_review_score is not None:
        print(
            f"  generalist_review={'yes' if result.metrics.generalist_review_pass else 'no'} score={result.metrics.generalist_review_score:.1f}/10"
        )
    if result.metrics.policyengine_score is not None:
        print(
            f"  policyengine={'yes' if result.metrics.policyengine_pass else 'no'} score={result.metrics.policyengine_score:.1%}"
        )
    if result.metrics.ungrounded_numeric_count:
        offenders = [item.raw for item in result.metrics.grounding if not item.grounded]
        print(f"  ungrounded_values={', '.join(offenders[:10])}")


def _eval_policy_repo_for_citations(
    citations: Sequence[str],
    authorized_root: Path,
) -> Path:
    """Require one canonical RuleSpec content root for an eval invocation."""

    routed: dict[Path, list[str]] = {}
    for citation in citations:
        normalized = normalize_corpus_identifier(citation)
        policy_repo = _resolve_explicit_policy_repo_for_corpus_source(
            normalized,
            authorized_root,
        )
        routed.setdefault(policy_repo, []).append(citation)
    if len(routed) != 1:
        detail = "; ".join(
            f"{repo}: {', '.join(repo_citations)}"
            for repo, repo_citations in routed.items()
        )
        raise ValueError(
            "One eval invocation cannot span multiple RuleSpec content roots; "
            f"run each jurisdiction separately ({detail})"
        )
    return next(iter(routed))


def cmd_eval(args):
    """Run deterministic model comparisons on one or more citations."""
    runners = _effective_runner_specs(
        args.runner or ["claude:opus", DEFAULT_GPT_RUNNER], args
    )
    rulespec_dependency_roots = _rulespec_dependency_roots_from_args(args)
    corpus_path = _resolve_explicit_existing_directory(
        args.corpus_path,
        label="Axiom Corpus",
    )
    axiom_rules_path = _resolve_explicit_existing_directory(
        args.axiom_rules_path,
        label="Axiom rules engine",
    )
    policy_repo_path = _eval_policy_repo_for_citations(
        args.citations,
        args.policy_repo_path,
    )

    corpus_release = load_rulespec_local_corpus_release(
        policy_repo_path,
        corpus_path,
    )

    results = run_model_eval(
        citations=args.citations,
        runner_specs=runners,
        output_root=args.output,
        policy_path=policy_repo_path,
        runtime_axiom_rules_path=axiom_rules_path,
        corpus_release=corpus_release,
        mode=args.mode,
        extra_context_paths=[Path(path) for path in args.allow_context],
        rulespec_dependency_roots=rulespec_dependency_roots,
    )

    if args.json:
        print(json.dumps([result.to_dict() for result in results], indent=2))
        return

    print(f"Output root: {args.output}")
    print(f"Axiom Corpus: {corpus_path}")
    print(f"Corpus release: {corpus_release.name}")
    print(f"Axiom rules engine: {axiom_rules_path}")
    print(f"Policy repo: {policy_repo_path}")
    print(f"Mode: {args.mode}")
    print()

    for result in results:
        print(f"{result.citation} [{result.runner}]")
        print(
            f"  success={result.success} duration_ms={result.duration_ms} cost_est=${result.estimated_cost_usd or 0:.4f}"
        )
        print(
            f"  tokens in={result.input_tokens} out={result.output_tokens} cache_read={result.cache_read_tokens} reasoning_out={result.reasoning_output_tokens}"
        )
        if getattr(result, "retry_count", 0):
            print(f"  retry_count={result.retry_count}")
        print(f"  retrieved_files={len(result.retrieved_files)}")
        if result.unexpected_accesses:
            print(f"  unexpected_accesses={len(result.unexpected_accesses)}")
        _print_eval_metrics(result)
        if result.error:
            print(f"  error={result.error}")
        print(f"  file={result.output_file}")
        print(f"  trace={result.trace_file}")
        print(f"  manifest={result.context_manifest_file}")
        print()


