def _format_gate_result(gate) -> str:
    """Format one readiness gate for human-readable output."""
    relation = ">=" if gate.comparator == "min" else "<="
    actual = "n/a" if gate.actual is None else f"{gate.actual}"
    return (
        f"  [{'PASS' if gate.passed else 'FAIL'}] {gate.name}: "
        f"{actual} {relation} {gate.threshold}"
    )


def _serialize_eval_result(result) -> dict:
    """Return a JSON-serializable eval result payload."""
    if hasattr(result, "to_dict"):
        payload = result.to_dict()
    elif isinstance(result, dict):
        payload = dict(result)
    else:
        payload = {
            "citation": getattr(result, "citation", None),
            "runner": getattr(result, "runner", None),
            "backend": getattr(result, "backend", None),
            "model": getattr(result, "model", None),
            "mode": getattr(result, "mode", None),
            "output_file": getattr(result, "output_file", None),
            "trace_file": getattr(result, "trace_file", None),
            "context_manifest_file": getattr(result, "context_manifest_file", None),
            "generated_output_sha256": getattr(result, "generated_output_sha256", None),
            "trace_sha256": getattr(result, "trace_sha256", None),
            "context_manifest_sha256": getattr(result, "context_manifest_sha256", None),
            "duration_ms": getattr(result, "duration_ms", None),
            "success": getattr(result, "success", None),
            "error": getattr(result, "error", None),
            "generation_prompt_sha256": getattr(
                result, "generation_prompt_sha256", None
            ),
            "retry_count": getattr(result, "retry_count", 0),
            "admission": getattr(result, "admission", None),
            "metrics": getattr(result, "metrics", None),
            "verdict_file": getattr(result, "verdict_file", ""),
            "verdict_sha256": getattr(result, "verdict_sha256", None),
        }
    return _bind_eval_result_payload(payload)


def _serialize_gate_result(gate) -> dict:
    """Return a JSON-serializable readiness gate payload."""
    if is_dataclass(gate):
        return asdict(gate)
    if isinstance(gate, dict):
        return gate
    return {
        "name": getattr(gate, "name", None),
        "comparator": getattr(gate, "comparator", None),
        "threshold": getattr(gate, "threshold", None),
        "actual": getattr(gate, "actual", None),
        "passed": getattr(gate, "passed", None),
    }


def _serialize_readiness_summary(summary) -> dict:
    """Return a JSON-serializable readiness summary payload."""
    if is_dataclass(summary):
        return asdict(summary)
    if isinstance(summary, dict):
        return summary
    return {
        "total_cases": getattr(summary, "total_cases", None),
        "success_rate": getattr(summary, "success_rate", None),
        "compile_pass_rate": getattr(summary, "compile_pass_rate", None),
        "ci_pass_rate": getattr(summary, "ci_pass_rate", None),
        "zero_ungrounded_rate": getattr(summary, "zero_ungrounded_rate", None),
        "generalist_review_pass_rate": getattr(
            summary, "generalist_review_pass_rate", None
        ),
        "mean_generalist_review_score": getattr(
            summary, "mean_generalist_review_score", None
        ),
        "policyengine_case_count": getattr(summary, "policyengine_case_count", None),
        "policyengine_pass_rate": getattr(summary, "policyengine_pass_rate", None),
        "mean_policyengine_score": getattr(summary, "mean_policyengine_score", None),
        "mean_estimated_cost_usd": getattr(summary, "mean_estimated_cost_usd", None),
        "gate_results": [
            _serialize_gate_result(gate)
            for gate in getattr(summary, "gate_results", []) or []
        ],
        "ready": getattr(summary, "ready", None),
    }


_EVAL_SUITE_EVIDENCE_SCHEMA = "axiom-encode/eval-suite-evidence/v5"
_EVAL_SUITE_RESULTS_SCHEMA = "axiom-encode/eval-suite-results/v5"
_EVAL_SUITE_SUMMARY_SCHEMA = "axiom-encode/eval-suite-summary/v5"
_EVAL_SUITE_REVALIDATION_MARKER = ".eval-suite-revalidation.json"


def _eval_suite_json_sha256(payload: object) -> str:
    encoded = json.dumps(
        payload,
        ensure_ascii=False,
        separators=(",", ":"),
        sort_keys=True,
    ).encode("utf-8")
    return hashlib.sha256(encoded).hexdigest()


def _read_eval_suite_artifact_bytes(
    output_root: Path,
    filename: str,
    *,
    max_bytes: int,
    required: bool = True,
) -> bytes | None:
    path = output_root / filename
    if not path.exists() and not path.is_symlink():
        if required:
            raise ValueError(f"Eval suite output is missing {filename}")
        return None
    try:
        return read_bounded_regular_file(
            output_root,
            path,
            label=f"eval suite {filename}",
            max_bytes=max_bytes,
        )
    except (OSError, ValueError) as exc:
        raise ValueError(f"Could not safely read eval suite {filename}: {exc}") from exc


def _load_eval_suite_ledger_entries_from_bytes(raw: bytes | None) -> list[dict]:
    entries: list[dict] = []
    if raw is None:
        return entries
    try:
        text = raw.decode("utf-8")
    except UnicodeDecodeError as exc:
        raise ValueError("suite-results.jsonl is not valid UTF-8") from exc
    for line_number, line in enumerate(text.splitlines(), start=1):
        if not line.strip():
            continue
        try:
            entry = json.loads(line)
        except json.JSONDecodeError as exc:
            raise ValueError(
                f"suite-results.jsonl contains a malformed row at line {line_number}"
            ) from exc
        if not isinstance(entry, dict):
            raise ValueError(
                f"suite-results.jsonl contains a non-object row at line {line_number}"
            )
        entries.append(entry)
    return entries


def _load_verified_eval_suite_artifacts(
    *,
    output_root: Path,
    manifest,
    effective_runners: list[str],
    axiom_rules_path: Path,
    policy_repo_path: Path,
    corpus_release: LocalCorpusRelease,
    require_complete: bool,
    policyengine_runtime: PolicyEngineRuntime | None = None,
    revalidate_persisted_results: bool = True,
) -> dict[str, object]:
    """Load one suite output only after the harness validates every identity."""

    output_root = Path(output_root)
    transaction_marker = output_root / _EVAL_SUITE_REVALIDATION_MARKER
    if transaction_marker.exists() or transaction_marker.is_symlink():
        raise ValueError(
            "Eval suite output has an incomplete revalidation transaction marker"
        )
    parsed_runners = [parse_runner_spec(spec) for spec in effective_runners]
    if not parsed_runners:
        raise ValueError("Eval suite must have at least one effective runner")

    state_raw_before = _read_eval_suite_artifact_bytes(
        output_root,
        "suite-run.json",
        max_bytes=8 * 1024 * 1024,
    )
    ledger_raw_before = _read_eval_suite_artifact_bytes(
        output_root,
        "suite-results.jsonl",
        max_bytes=256 * 1024 * 1024,
        required=False,
    )
    manifest_identity = _build_eval_suite_manifest_identity(manifest)
    rulespec_roots = _eval_suite_rulespec_roots(manifest, policy_repo_path)
    policyengine_cases = [
        case
        for case in manifest.cases
        if getattr(case, "oracle", "none") == "policyengine"
    ]
    if policyengine_cases:
        if type(policyengine_runtime) is not PolicyEngineRuntime:
            raise PolicyEngineRuntimeError(
                "PolicyEngine eval-suite evidence requires one explicit admitted runtime"
            )
        for case in policyengine_cases:
            policyengine_runtime.assert_matches_rulespec_root(
                _eval_suite_case_policy_repo_root(case, policy_repo_path)
            )
        policyengine_runtime.assert_unchanged()
    execution_identity = _build_eval_suite_execution_identity(
        axiom_rules_path,
        rulespec_roots,
        policyengine_runtime=policyengine_runtime if policyengine_cases else None,
    )
    _run_id, _started_at, results, completed_case_indexes = (
        _load_eval_suite_resume_state(
            output_root=output_root,
            manifest=manifest,
            resolved_runners=effective_runners,
            parsed_runners=parsed_runners,
            corpus_release=corpus_release,
            axiom_rules_path=axiom_rules_path,
            policy_repo_path=policy_repo_path,
            rulespec_roots=rulespec_roots,
            manifest_identity=manifest_identity,
            execution_identity=execution_identity,
            policyengine_runtime=(policyengine_runtime if policyengine_cases else None),
            revalidate_persisted_results=revalidate_persisted_results,
        )
    )
    for result in results:
        _validate_eval_result_artifacts(
            result,
            output_root,
            artifact_name=(
                "Verified eval suite result "
                f"for runner '{getattr(result, 'runner', '')}'"
            ),
        )
    state_raw = _read_eval_suite_artifact_bytes(
        output_root,
        "suite-run.json",
        max_bytes=8 * 1024 * 1024,
    )
    ledger_raw = _read_eval_suite_artifact_bytes(
        output_root,
        "suite-results.jsonl",
        max_bytes=256 * 1024 * 1024,
        required=False,
    )
    if state_raw != state_raw_before or ledger_raw != ledger_raw_before:
        raise ValueError("Eval suite state changed while its identity was verified")
    try:
        run_state = json.loads((state_raw or b"").decode("utf-8"))
    except (UnicodeDecodeError, json.JSONDecodeError) as exc:
        raise ValueError("suite-run.json is malformed") from exc
    if not isinstance(run_state, dict):
        raise ValueError("suite-run.json must contain a JSON object")
    ledger_entries = _load_eval_suite_ledger_entries_from_bytes(ledger_raw)
    if len(ledger_entries) != len(results):
        raise ValueError(
            "suite-results.jsonl row count does not match its validated results"
        )

    expected_case_indexes = set(range(1, len(manifest.cases) + 1))
    complete = completed_case_indexes == expected_case_indexes
    expected_result_count = len(manifest.cases) * len(parsed_runners)
    if run_state.get("status") == "completed":
        if not complete:
            raise ValueError(
                "Completed eval suite state does not have every case-runner result"
            )
        if run_state.get("completed_cases") != len(manifest.cases):
            raise ValueError(
                "Completed eval suite state has an inconsistent completed_cases"
            )
        if run_state.get("result_count") != expected_result_count:
            raise ValueError(
                "Completed eval suite state has an inconsistent result_count"
            )
    if require_complete and (run_state.get("status") != "completed" or not complete):
        raise ValueError(
            "Eval suite must be completed with exactly one result per case and runner"
        )

    return {
        "run_state": run_state,
        "ledger_entries": ledger_entries,
        "results": results,
        "completed_case_indexes": completed_case_indexes,
        "manifest_identity": manifest_identity,
        "execution_identity": execution_identity,
        "parsed_runners": parsed_runners,
        "complete": complete,
    }


def _eval_suite_evidence(run_state: dict) -> dict[str, object]:
    manifest_meta = run_state.get("manifest")
    execution_identity = run_state.get("execution_identity")
    execution_identity_sha256 = run_state.get("execution_identity_sha256")
    if not isinstance(manifest_meta, dict) or not isinstance(execution_identity, dict):
        raise ValueError("Eval suite state is missing immutable execution evidence")
    if not isinstance(execution_identity_sha256, str) or not execution_identity_sha256:
        raise ValueError("Eval suite state is missing execution identity digest")
    run_id = run_state.get("run_id")
    started_at = run_state.get("started_at")
    _validate_eval_suite_run_identity(
        run_id,
        started_at,
        artifact_name="Eval suite state",
    )

    corpus_identity = {
        key: value
        for key, value in run_state.items()
        if key == "corpus_release" or key.startswith("corpus_release_")
    }
    evidence: dict[str, object] = {
        "schema": _EVAL_SUITE_EVIDENCE_SCHEMA,
        "manifest": {
            "name": manifest_meta.get("name"),
            "path": manifest_meta.get("path"),
            "content_sha256": manifest_meta.get("content_sha256"),
            "case_identities": manifest_meta.get("case_identities"),
        },
        "effective_runner_identities": manifest_meta.get("effective_runner_identities"),
        "run": {"id": run_id, "started_at": started_at},
        "corpus": corpus_identity,
        "execution_identity": execution_identity,
        "execution_identity_sha256": execution_identity_sha256,
    }
    evidence["sha256"] = _eval_suite_json_sha256(evidence)
    return evidence


def _build_eval_suite_payload(
    *,
    manifest,
    effective_runners: list[str],
    results: list,
    readiness: dict,
    run_state: dict,
    completed_case_indexes: set[int],
) -> dict[str, object]:
    """Build a content-bound suite payload from harness-verified result groups."""

    parsed_runners = [parse_runner_spec(spec) for spec in effective_runners]
    manifest_meta = run_state.get("manifest")
    if not isinstance(manifest_meta, dict):
        raise ValueError("Eval suite state is missing manifest identity")
    case_identities = manifest_meta.get("case_identities")
    if not isinstance(case_identities, list):
        raise ValueError("Eval suite state is missing canonical case identities")

    expected_loaded_results = len(completed_case_indexes) * len(parsed_runners)
    if len(results) != expected_loaded_results:
        raise ValueError("Eval suite result groups are incomplete")
    serialized_results: list[dict] = []
    result_index = 0
    for case_index in sorted(completed_case_indexes):
        case = manifest.cases[case_index - 1]
        case_identity = case_identities[case_index - 1]
        if not isinstance(case_identity, dict):
            raise ValueError("Eval suite case identity is malformed")
        for runner in parsed_runners:
            result_payload = dict(_serialize_eval_result(results[result_index]))
            result_index += 1
            _validate_eval_result_artifact_binding(
                result_payload,
                artifact_name=(
                    f"Eval suite result for case '{case.name}' runner '{runner.name}'"
                ),
            )
            if (
                result_payload.get("runner") != runner.name
                or result_payload.get("backend") != runner.backend
                or result_payload.get("model") != runner.model
            ):
                raise ValueError(
                    "Eval suite result order or effective runner identity changed"
                )
            result_payload["eval_case"] = {
                "index": case_index,
                "name": case.name,
                "kind": case.kind,
                "corpus_citation_path": _eval_suite_case_corpus_citation_path(case),
                "sha256": case_identity.get("sha256"),
            }
            serialized_results.append(_bind_eval_result_payload(result_payload))

    readiness_payload = {
        runner: _serialize_readiness_summary(summary)
        for runner, summary in readiness.items()
    }
    expected_runner_names = {runner.name for runner in parsed_runners}
    complete = completed_case_indexes == set(range(1, len(manifest.cases) + 1))
    readiness_complete = set(readiness_payload) == expected_runner_names
    all_ready = bool(
        complete
        and expected_runner_names
        and readiness_complete
        and all(summary.get("ready") is True for summary in readiness_payload.values())
    )
    return {
        "schema": _EVAL_SUITE_RESULTS_SCHEMA,
        "manifest": {
            "name": manifest.name,
            "path": str(manifest.path),
            "runners": manifest.runners,
            "effective_runners": effective_runners,
        },
        "evidence": _eval_suite_evidence(run_state),
        "coverage": {
            "expected_case_count": len(manifest.cases),
            "completed_case_count": len(completed_case_indexes),
            "expected_runner_count": len(parsed_runners),
            "expected_result_count": len(manifest.cases) * len(parsed_runners),
            "actual_result_count": len(serialized_results),
            "complete": complete,
            "results_sha256": _eval_suite_json_sha256(serialized_results),
        },
        "results": serialized_results,
        "readiness": readiness_payload,
        "all_ready": all_ready,
    }


def _eval_suite_summary_payload(payload: dict[str, object]) -> dict[str, object]:
    return {
        "schema": _EVAL_SUITE_SUMMARY_SCHEMA,
        "manifest": payload["manifest"],
        "evidence": payload["evidence"],
        "coverage": payload["coverage"],
        "readiness": payload["readiness"],
        "all_ready": payload["all_ready"],
    }


def _atomic_write_eval_suite_artifact(path: Path, raw: bytes) -> None:
    """Replace one suite artifact atomically and durably within its directory."""

    path.parent.mkdir(parents=True, exist_ok=True)
    if path.is_symlink():
        raise ValueError(f"Eval suite artifact must not be a symlink: {path}")
    temporary_path: Path | None = None
    try:
        with tempfile.NamedTemporaryFile(
            mode="wb",
            dir=path.parent,
            prefix=f".{path.name}.",
            suffix=".tmp",
            delete=False,
        ) as handle:
            temporary_path = Path(handle.name)
            handle.write(raw)
            handle.flush()
            os.fsync(handle.fileno())
        os.replace(temporary_path, path)
        temporary_path = None
        directory_fd = os.open(path.parent, os.O_RDONLY)
        try:
            os.fsync(directory_fd)
        finally:
            os.close(directory_fd)
    finally:
        if temporary_path is not None:
            temporary_path.unlink(missing_ok=True)


class _EvalSuiteArtifactSnapshot(NamedTuple):
    existed: bool
    raw: bytes
    mode: int


def _fsync_eval_suite_directories(paths: Sequence[Path]) -> None:
    """Durably persist directory-entry changes for a set of artifacts."""

    for directory in sorted({path.parent for path in paths}, key=str):
        directory_fd = os.open(directory, os.O_RDONLY)
        try:
            os.fsync(directory_fd)
        finally:
            os.close(directory_fd)


def _install_eval_suite_revalidation_transaction(
    output_root: Path,
    artifacts: Sequence[tuple[Path, bytes]],
) -> None:
    """Stage and install one revalidation closure, rolling it all back on failure."""

    root = Path(output_root).resolve()
    marker = root / _EVAL_SUITE_REVALIDATION_MARKER
    normalized: list[tuple[Path, bytes]] = []
    seen: set[Path] = set()
    for raw_path, raw in artifacts:
        path = Path(os.path.abspath(raw_path))
        try:
            path.relative_to(root)
        except ValueError as exc:
            raise ValueError(
                f"Eval-suite revalidation target is outside its output root: {path}"
            ) from exc
        if path in seen:
            raise ValueError(f"Duplicate eval-suite revalidation target: {path}")
        if not isinstance(raw, bytes):
            raise TypeError(f"Eval-suite revalidation bytes are invalid for {path}")
        seen.add(path)
        normalized.append((path, raw))
    if not normalized:
        raise ValueError("Eval-suite revalidation transaction has no artifacts")

    marker_flags = os.O_WRONLY | os.O_CREAT | os.O_EXCL
    if hasattr(os, "O_NOFOLLOW"):
        marker_flags |= os.O_NOFOLLOW
    marker_payload = (
        json.dumps(
            {
                "schema": "axiom-encode/eval-suite-revalidation-transaction/v1",
                "targets": [
                    path.relative_to(root).as_posix() for path, _ in normalized
                ],
            },
            indent=2,
            sort_keys=True,
        )
        + "\n"
    ).encode("utf-8")
    try:
        marker_fd = os.open(marker, marker_flags, 0o600)
    except FileExistsError as exc:
        raise ValueError(
            "Eval suite output already has an active or incomplete revalidation "
            "transaction"
        ) from exc
    with os.fdopen(marker_fd, "wb") as marker_handle:
        marker_handle.write(marker_payload)
        marker_handle.flush()
        os.fsync(marker_handle.fileno())
    _fsync_eval_suite_directories([marker])

    snapshots: dict[Path, _EvalSuiteArtifactSnapshot] = {}
    staged: dict[Path, Path] = {}
    try:
        for path, raw in normalized:
            if path.parent.is_symlink():
                raise ValueError(
                    f"Eval-suite revalidation target parent is a symlink: {path.parent}"
                )
            path.parent.mkdir(parents=True, exist_ok=True)
            if path.is_symlink():
                raise ValueError(
                    f"Eval-suite revalidation target must not be a symlink: {path}"
                )
            if path.exists():
                existing = read_bounded_regular_file(
                    root,
                    path,
                    label="eval-suite revalidation target",
                    max_bytes=256 * 1024 * 1024,
                )
                mode = path.stat(follow_symlinks=False).st_mode & 0o777
                snapshots[path] = _EvalSuiteArtifactSnapshot(True, existing, mode)
            else:
                snapshots[path] = _EvalSuiteArtifactSnapshot(False, b"", 0o600)
            temporary_path: Path | None = None
            try:
                with tempfile.NamedTemporaryFile(
                    mode="wb",
                    dir=path.parent,
                    prefix=f".{path.name}.revalidate.",
                    suffix=".tmp",
                    delete=False,
                ) as handle:
                    temporary_path = Path(handle.name)
                    handle.write(raw)
                    handle.flush()
                    os.fsync(handle.fileno())
                os.chmod(temporary_path, snapshots[path].mode)
                staged[path] = temporary_path
                temporary_path = None
            finally:
                if temporary_path is not None:
                    temporary_path.unlink(missing_ok=True)

        for path, _raw in normalized:
            os.replace(staged[path], path)
            staged.pop(path, None)
        _fsync_eval_suite_directories([path for path, _ in normalized])

        for path, expected in normalized:
            actual = read_bounded_regular_file(
                root,
                path,
                label="installed eval-suite revalidation artifact",
                max_bytes=max(256 * 1024 * 1024, len(expected)),
            )
            if actual != expected:
                raise RuntimeError(
                    f"Installed eval-suite revalidation bytes changed for {path}"
                )
    except BaseException as exc:
        rollback_error: BaseException | None = None
        try:
            for path, _raw in reversed(normalized):
                snapshot = snapshots.get(path)
                if snapshot is None:
                    continue
                if snapshot.existed:
                    restore_path: Path | None = None
                    try:
                        with tempfile.NamedTemporaryFile(
                            mode="wb",
                            dir=path.parent,
                            prefix=f".{path.name}.rollback.",
                            suffix=".tmp",
                            delete=False,
                        ) as handle:
                            restore_path = Path(handle.name)
                            handle.write(snapshot.raw)
                            handle.flush()
                            os.fsync(handle.fileno())
                        os.chmod(restore_path, snapshot.mode)
                        os.replace(restore_path, path)
                        restore_path = None
                    finally:
                        if restore_path is not None:
                            restore_path.unlink(missing_ok=True)
                elif path.exists() or path.is_symlink():
                    path.unlink()
            if snapshots:
                _fsync_eval_suite_directories(list(snapshots))
        except BaseException as rollback_exc:  # pragma: no cover - catastrophic I/O
            rollback_error = rollback_exc
        if rollback_error is not None:
            raise RuntimeError(
                "Eval-suite revalidation failed and its rollback was incomplete; "
                f"the transaction marker remains at {marker}: {rollback_error}"
            ) from exc
        marker.unlink(missing_ok=True)
        _fsync_eval_suite_directories([marker])
        raise
    finally:
        for temporary_path in staged.values():
            temporary_path.unlink(missing_ok=True)

    marker.unlink()
    _fsync_eval_suite_directories([marker])


def _load_eval_suite_run_state(output_root: Path) -> dict | None:
    """Load persisted suite lifecycle state when available."""
    state_path = output_root / "suite-run.json"
    if not state_path.exists():
        return None
    try:
        return json.loads(state_path.read_text())
    except (OSError, json.JSONDecodeError):
        return None


def _suite_auto_resume_reason(state: dict | None, total_cases: int) -> str | None:
    """Return a human-readable reason to auto-resume, if the suite is incomplete."""
    if not state:
        return None
    status = str(state.get("status") or "").strip().lower()
    completed_cases = int(state.get("completed_cases", 0) or 0)
    if completed_cases >= total_cases or status == "completed":
        return None
    error = str(state.get("error") or "").strip()
    if "usage limit" in error.lower():
        return None
    if status not in {"running", "failed", "interrupted"}:
        return None
    active_case = state.get("active_case") or {}
    active_name = active_case.get("name")
    if active_name:
        return f"{status} while running case '{active_name}'"
    if error:
        return f"{status}: {error}"
    return status or "incomplete state"


def _eval_suite_corpus_release(
    manifest,
    *,
    corpus_path: Path,
    policy_repo_path: Path,
) -> LocalCorpusRelease:
    """Load the one configured release shared by all corpus-backed suite cases."""

    releases: dict[tuple[str, str], LocalCorpusRelease] = {}
    for case in manifest.cases:
        if case.kind not in {"citation", "source"}:
            continue
        identifier = case.corpus_citation_path or case.citation or ""
        normalized = (
            require_canonical_corpus_citation_path(identifier)
            if case.kind == "source"
            else normalize_corpus_identifier(identifier)
        )
        policy_repo = _resolve_explicit_policy_repo_for_corpus_source(
            normalized,
            policy_repo_path,
        )
        release = load_rulespec_local_corpus_release(policy_repo, corpus_path)
        releases[(release.name, release.content_sha256)] = release
    if len(releases) > 1:
        names = ", ".join(name for name, _sha256 in sorted(releases))
        raise ValueError(
            "Eval suite corpus cases span different configured release selectors: "
            f"{names}"
        )
    if not releases:
        raise ValueError("Eval suites must contain at least one corpus-backed case")
    return next(iter(releases.values()))


def _eval_suite_policyengine_runtime(
    raw_runtime_root: object,
    manifest,
    policy_repo_path: Path,
) -> PolicyEngineRuntime | None:
    """Load the one runtime required by every PolicyEngine suite case."""

    roots = tuple(
        _eval_suite_case_policy_repo_root(case, policy_repo_path)
        for case in manifest.cases
        if getattr(case, "oracle", "none") == "policyengine"
    )
    if not roots:
        return None
    return _load_policyengine_runtime_for_rulespec_roots(
        raw_runtime_root,
        roots,
    )


def cmd_eval_suite(args):
    """Run a manifest-driven benchmark suite and evaluate readiness gates."""
    manifest = load_eval_suite_manifest(args.manifest)
    effective_runners = list(manifest.runners)
    axiom_rules_path = _resolve_explicit_existing_directory(
        args.axiom_rules_path,
        label="Axiom rules engine",
    )
    policy_repo_path = _resolve_explicit_existing_directory(
        args.policy_repo_path,
        label="RuleSpec checkout",
    )
    corpus_path = _resolve_explicit_existing_directory(
        args.corpus_path,
        label="Axiom Corpus",
    )
    corpus_release = _eval_suite_corpus_release(
        manifest,
        corpus_path=corpus_path,
        policy_repo_path=policy_repo_path,
    )
    policyengine_runtime = _eval_suite_policyengine_runtime(
        getattr(args, "policyengine_runtime_root", None),
        manifest,
        policy_repo_path,
    )

    auto_resume_attempts = max(getattr(args, "auto_resume_attempts", 0), 0)
    auto_resume_delay_seconds = max(getattr(args, "auto_resume_delay_seconds", 0), 0)
    resume_existing = getattr(args, "resume", False)
    recovery_count = 0

    while True:
        try:
            results = run_eval_suite(
                manifest=manifest,
                output_root=args.output,
                axiom_rules_path=axiom_rules_path,
                policy_repo_path=policy_repo_path,
                corpus_release=corpus_release,
                policyengine_runtime=policyengine_runtime,
                resume_existing=resume_existing,
            )
        except KeyboardInterrupt:
            raise
        except BaseException as exc:
            if recovery_count >= auto_resume_attempts:
                raise
            recovery_count += 1
            detail = str(exc).strip() or exc.__class__.__name__
            print(
                "eval-suite exited unexpectedly; "
                f"auto-resuming {recovery_count}/{auto_resume_attempts} "
                f"after {auto_resume_delay_seconds}s ({detail})",
                file=sys.stderr,
            )
            if auto_resume_delay_seconds:
                time.sleep(auto_resume_delay_seconds)
            resume_existing = True
            continue

        auto_resume_reason = _suite_auto_resume_reason(
            _load_eval_suite_run_state(args.output),
            total_cases=len(manifest.cases),
        )
        if auto_resume_reason and recovery_count < auto_resume_attempts:
            recovery_count += 1
            print(
                "eval-suite stopped before completion; "
                f"auto-resuming {recovery_count}/{auto_resume_attempts} "
                f"after {auto_resume_delay_seconds}s ({auto_resume_reason})",
                file=sys.stderr,
            )
            if auto_resume_delay_seconds:
                time.sleep(auto_resume_delay_seconds)
            resume_existing = True
            continue
        break

    try:
        verified_output = _load_verified_eval_suite_artifacts(
            output_root=args.output,
            manifest=manifest,
            effective_runners=effective_runners,
            axiom_rules_path=axiom_rules_path,
            policy_repo_path=policy_repo_path,
            corpus_release=corpus_release,
            policyengine_runtime=policyengine_runtime,
            require_complete=False,
        )
    except ValueError as exc:
        print(str(exc))
        sys.exit(1)
    results = list(verified_output["results"])
    completed_case_indexes = set(verified_output["completed_case_indexes"])
    run_state = dict(verified_output["run_state"])

    grouped: dict[str, list] = {}
    for result in results:
        grouped.setdefault(result.runner, []).append(result)

    readiness = {
        runner: summarize_readiness(runner_results, manifest.gates)
        for runner, runner_results in grouped.items()
    }
    payload = _build_eval_suite_payload(
        manifest=manifest,
        effective_runners=effective_runners,
        results=results,
        readiness=readiness,
        run_state=run_state,
        completed_case_indexes=completed_case_indexes,
    )
    all_ready = bool(payload["all_ready"])
    args.output.mkdir(parents=True, exist_ok=True)
    _atomic_write_eval_suite_artifact(
        args.output / "results.json",
        (json.dumps(payload, indent=2) + "\n").encode("utf-8"),
    )
    _atomic_write_eval_suite_artifact(
        args.output / "summary.json",
        (json.dumps(_eval_suite_summary_payload(payload), indent=2) + "\n").encode(
            "utf-8"
        ),
    )

    if args.json:
        print(json.dumps(payload, indent=2))
        sys.exit(0 if all_ready else 1)

    print(f"Manifest: {manifest.path}")
    print(f"Suite: {manifest.name}")
    print(f"Output root: {args.output}")
    print(f"Runners: {', '.join(effective_runners)}")
    print(f"Axiom rules engine: {axiom_rules_path}")
    print(f"RuleSpec checkout: {policy_repo_path}")
    print(f"Axiom Corpus: {corpus_path}")
    print(f"Corpus release: {corpus_release.name}")
    print()

    for runner, summary in readiness.items():
        print(f"{runner}: {'READY' if summary.ready else 'NOT READY'}")
        print(
            f"  cases={summary.total_cases} success={summary.success_rate:.1%} "
            f"compile={summary.compile_pass_rate:.1%} ci={summary.ci_pass_rate:.1%} "
            f"zero_ungrounded={summary.zero_ungrounded_rate:.1%} "
            f"generalist_review={summary.generalist_review_pass_rate:.1%}"
        )
        if summary.mean_generalist_review_score is not None:
            print(
                f"  mean_generalist_review_score={summary.mean_generalist_review_score:.2f}/10"
            )
        if summary.policyengine_case_count:
            print(
                f"  policyengine_cases={summary.policyengine_case_count} "
                f"pass_rate={(summary.policyengine_pass_rate or 0):.1%} "
                f"mean_score={(summary.mean_policyengine_score or 0):.1%}"
            )
        if summary.mean_estimated_cost_usd is not None:
            print(f"  mean_estimated_cost=${summary.mean_estimated_cost_usd:.4f}")
        for gate in summary.gate_results:
            print(_format_gate_result(gate))

        notable_failures = [
            result
            for result in grouped[runner]
            if (
                not result.success
                or result.error
                or result.metrics is None
                or not result.metrics.compile_pass
                or not result.metrics.ci_pass
                or result.metrics.ungrounded_numeric_count > 0
                or result.metrics.generalist_review_pass is False
            )
        ]
        if notable_failures:
            print("  notable_failures:")
            for result in notable_failures[:5]:
                print(
                    f"    - {result.citation}: success={result.success} "
                    f"compile={getattr(result.metrics, 'compile_pass', None)} "
                    f"ci={getattr(result.metrics, 'ci_pass', None)} "
                    f"ungrounded={getattr(result.metrics, 'ungrounded_numeric_count', None)} "
                    f"generalist={getattr(result.metrics, 'generalist_review_pass', None)}"
                )
        print()

    sys.exit(0 if all_ready else 1)


def cmd_eval_suite_revalidate(args):
    """Revalidate and re-sign a suite without exposing its private key."""

    with isolated_eval_evidence_signer() as evidence_signing_key:
        return _cmd_eval_suite_revalidate_with_signer(args, evidence_signing_key)


def _cmd_eval_suite_revalidate_with_signer(args, evidence_signing_key):
    """Re-run validators for an existing eval-suite output in place."""
    source_output = Path(args.source_output).resolve()
    if not source_output.exists():
        print(f"Suite output not found: {source_output}")
        sys.exit(1)

    run_state = _load_eval_suite_run_state(source_output)
    manifest_path = args.manifest
    if manifest_path is None and run_state:
        manifest_meta = run_state.get("manifest") or {}
        path_str = str(manifest_meta.get("path") or "").strip()
        if path_str:
            manifest_path = Path(path_str)
    if manifest_path is None:
        print(
            "Could not determine manifest path for suite revalidation. "
            "Pass --manifest explicitly."
        )
        sys.exit(1)

    manifest = load_eval_suite_manifest(manifest_path)
    axiom_rules_path = _resolve_explicit_existing_directory(
        args.axiom_rules_path,
        label="Axiom rules engine",
    )
    policy_repo_path = _resolve_explicit_existing_directory(
        args.policy_repo_path,
        label="RuleSpec checkout",
    )
    corpus_path = _resolve_explicit_existing_directory(
        args.corpus_path,
        label="Axiom Corpus",
    )
    corpus_release = _eval_suite_corpus_release(
        manifest,
        corpus_path=corpus_path,
        policy_repo_path=policy_repo_path,
    )
    policyengine_runtime = _eval_suite_policyengine_runtime(
        getattr(args, "policyengine_runtime_root", None),
        manifest,
        policy_repo_path,
    )
    if run_state is None:
        print(
            "suite-run.json with immutable execution identity is required for "
            "revalidation"
        )
        sys.exit(1)
    manifest_meta = run_state.get("manifest")
    if not isinstance(manifest_meta, dict):
        print("suite-run.json is missing immutable manifest identity")
        sys.exit(1)
    effective_runners = manifest_meta.get("effective_runners")
    if not isinstance(effective_runners, list) or any(
        not isinstance(spec, str) or not spec for spec in effective_runners
    ):
        print("suite-run.json is missing effective runner identities")
        sys.exit(1)
    try:
        verified_output = _load_verified_eval_suite_artifacts(
            output_root=source_output,
            manifest=manifest,
            effective_runners=list(effective_runners),
            axiom_rules_path=axiom_rules_path,
            policy_repo_path=policy_repo_path,
            corpus_release=corpus_release,
            policyengine_runtime=policyengine_runtime,
            require_complete=True,
            revalidate_persisted_results=False,
        )
    except ValueError as exc:
        print(str(exc))
        sys.exit(1)
    run_state = copy.deepcopy(verified_output["run_state"])
    ledger_entries = copy.deepcopy(verified_output["ledger_entries"])
    results = copy.deepcopy(verified_output["results"])
    completed_case_indexes = set(verified_output["completed_case_indexes"])
    ledger_path = source_output / "suite-results.jsonl"
    revalidated_verdicts: list[tuple[Path, bytes]] = []

    for entry, result in zip(ledger_entries, results):
        case_index = entry["case_index"]
        case = manifest.cases[case_index - 1]
        expected_policy_repo_root = _eval_suite_case_policy_repo_root(
            case,
            policy_repo_path,
        )
        if not result.output_file:
            continue

        rulespec_file = Path(result.output_file)
        if not rulespec_file.exists():
            raise ValueError(
                f"Result for case '{case.name}' is missing its bound output "
                f"file: {rulespec_file}"
            )

        identifier = case.corpus_citation_path or case.citation
        source_unit = resolve_corpus_source_unit(
            identifier or "",
            corpus_release,
        )
        source_text = source_unit.body
        source_metadata = _source_metadata_with_attestation(
            source_unit,
            rulespec_root=expected_policy_repo_root,
        )
        source_citation_path = _source_metadata_citation_path(source_metadata)

        result.metrics = evaluate_artifact(
            rulespec_file=rulespec_file,
            policy_repo_root=expected_policy_repo_root,
            axiom_rules_path=axiom_rules_path,
            source_text=source_text,
            oracle=case.oracle,
            policyengine_runtime=policyengine_runtime,
            policyengine_rule_hint=case.policyengine_rule_hint,
            local_corpus_release=corpus_release,
            source_metadata=source_metadata,
            source_citation_path=source_citation_path,
            rulespec_dependency_roots=manifest.rulespec_dependency_roots,
        )
        validation_error = _eval_artifact_validation_error(
            result.metrics,
            require_policyengine=case.oracle == "policyengine",
        )
        result.success = validation_error is None
        result.error = validation_error
        if not isinstance(result.admission, dict):  # verified admission invariant
            raise ValueError(
                f"Result for case '{case.name}' is missing its signed admission"
            )
        verdict_path, verdict_raw = _render_eval_result_verdict_evidence(
            source_output,
            case_index,
            case,
            result,
            admission_context=result.admission,
            evidence_signing_key=evidence_signing_key,
        )
        verdict_payload = json.loads(verdict_raw.decode("utf-8"))
        _validate_signed_eval_result_verdict_evidence(
            verdict_payload,
            result,
            artifact_name=(
                f"Staged revalidated result for case '{case.name}' "
                f"runner '{result.runner}'"
            ),
        )
        revalidated_verdicts.append((verdict_path, verdict_raw))
        entry["result"] = result.to_dict()

    grouped: dict[str, list] = {}
    for result in results:
        grouped.setdefault(result.runner, []).append(result)

    readiness = {
        runner: summarize_readiness(runner_results, manifest.gates)
        for runner, runner_results in grouped.items()
    }
    payload = _build_eval_suite_payload(
        manifest=manifest,
        effective_runners=list(effective_runners),
        results=results,
        readiness=readiness,
        run_state=run_state,
        completed_case_indexes=completed_case_indexes,
    )
    all_ready = bool(payload["all_ready"])
    now_iso = _utc_now_iso()
    run_state["updated_at"] = now_iso
    run_state["revalidated_at"] = now_iso
    run_state["revalidation_evidence_sha256"] = payload["evidence"]["sha256"]
    ledger_raw = "".join(
        json.dumps(entry, sort_keys=True) + "\n" for entry in ledger_entries
    ).encode("utf-8")
    results_raw = (json.dumps(payload, indent=2) + "\n").encode("utf-8")
    summary_raw = (
        json.dumps(_eval_suite_summary_payload(payload), indent=2) + "\n"
    ).encode("utf-8")
    run_state_raw = (json.dumps(run_state, indent=2, sort_keys=True) + "\n").encode(
        "utf-8"
    )
    if policyengine_runtime is not None:
        policyengine_runtime.assert_unchanged()
    _install_eval_suite_revalidation_transaction(
        source_output,
        [
            *revalidated_verdicts,
            (ledger_path, ledger_raw),
            (source_output / "results.json", results_raw),
            (source_output / "summary.json", summary_raw),
            (source_output / "suite-run.json", run_state_raw),
        ],
    )

    if args.json:
        print(json.dumps(payload, indent=2))
        sys.exit(0 if all_ready else 1)

    print(f"Manifest: {manifest.path}")
    print(f"Suite: {manifest.name}")
    print(f"Output root: {source_output}")
    print(f"Revalidated cases: {len(results)}")
    print()
    for runner, summary in readiness.items():
        print(f"{runner}: {'READY' if summary.ready else 'NOT READY'}")
        print(
            f"  cases={summary.total_cases} success={summary.success_rate:.1%} "
            f"compile={summary.compile_pass_rate:.1%} ci={summary.ci_pass_rate:.1%} "
            f"zero_ungrounded={summary.zero_ungrounded_rate:.1%} "
            f"generalist_review={summary.generalist_review_pass_rate:.1%}"
        )
        if summary.mean_generalist_review_score is not None:
            print(
                f"  mean_generalist_review_score={summary.mean_generalist_review_score:.2f}/10"
            )
        if summary.policyengine_case_count:
            print(
                f"  policyengine_cases={summary.policyengine_case_count} "
                f"pass_rate={(summary.policyengine_pass_rate or 0):.1%} "
                f"mean_score={(summary.mean_policyengine_score or 0):.1%}"
            )
        if summary.mean_estimated_cost_usd is not None:
            print(f"  mean_estimated_cost=${summary.mean_estimated_cost_usd:.4f}")
        for gate in summary.gate_results:
            print(_format_gate_result(gate))
    sys.exit(0 if all_ready else 1)


def _axiom_encode_repo_root() -> Path:
    """Return the repository root for the current axiom_encode checkout."""
    return Path(__file__).resolve().parents[2]


def _default_eval_suite_archive_root() -> Path:
    """Resolve the durable local archive root for suite outputs."""
    configured = os.getenv("AXIOM_ENCODE_EVAL_ARCHIVE_ROOT")
    if configured:
        return Path(configured).expanduser().resolve()
    return (_axiom_encode_repo_root() / "artifacts" / "eval-suites").resolve()


def _slugify_archive_name(value: str) -> str:
    """Convert an arbitrary archive label into a filesystem-safe directory name."""
    cleaned = re.sub(r"[^A-Za-z0-9._-]+", "-", value.strip().lower())
    cleaned = re.sub(r"-{2,}", "-", cleaned).strip("-")
    return cleaned or "eval-suite"


def _load_verified_eval_suite_archive_payload(
    source_output: Path,
    *,
    axiom_rules_path: Path,
    policy_repo_path: Path,
    corpus_path: Path,
    policyengine_runtime_root: Path | None = None,
) -> dict:
    """Verify a complete suite against current live inputs before archiving."""

    state_raw = _read_eval_suite_artifact_bytes(
        source_output,
        "suite-run.json",
        max_bytes=8 * 1024 * 1024,
    )
    try:
        run_state = json.loads((state_raw or b"").decode("utf-8"))
    except (UnicodeDecodeError, json.JSONDecodeError) as exc:
        raise ValueError("suite-run.json is malformed") from exc
    if not isinstance(run_state, dict):
        raise ValueError("suite-run.json must contain a JSON object")
    manifest_meta = run_state.get("manifest")
    if not isinstance(manifest_meta, dict):
        raise ValueError("suite-run.json is missing immutable manifest identity")
    manifest_path = manifest_meta.get("path")
    effective_runners = manifest_meta.get("effective_runners")
    if not isinstance(manifest_path, str) or not manifest_path:
        raise ValueError("suite-run.json is missing its manifest path")
    if not isinstance(effective_runners, list) or any(
        not isinstance(spec, str) or not spec for spec in effective_runners
    ):
        raise ValueError("suite-run.json is missing effective runner identities")
    manifest = load_eval_suite_manifest(Path(manifest_path))
    policyengine_runtime = _eval_suite_policyengine_runtime(
        policyengine_runtime_root,
        manifest,
        policy_repo_path,
    )
    corpus_release = _eval_suite_corpus_release(
        manifest,
        corpus_path=corpus_path,
        policy_repo_path=policy_repo_path,
    )
    verified_output = _load_verified_eval_suite_artifacts(
        output_root=source_output,
        manifest=manifest,
        effective_runners=list(effective_runners),
        axiom_rules_path=axiom_rules_path,
        policy_repo_path=policy_repo_path,
        corpus_release=corpus_release,
        policyengine_runtime=policyengine_runtime,
        require_complete=True,
    )
    if verified_output["run_state"] != run_state:
        raise ValueError("suite-run.json changed while archive admission was verified")

    results_raw = _read_eval_suite_artifact_bytes(
        source_output,
        "results.json",
        max_bytes=256 * 1024 * 1024,
    )
    try:
        result_payload = _validated_eval_suite_report_payload(
            json.loads((results_raw or b"").decode("utf-8")),
            artifact_root=source_output,
        )
    except (UnicodeDecodeError, json.JSONDecodeError) as exc:
        raise ValueError("results.json is malformed") from exc

    verified_results = [
        _eval_result_from_payload(
            _serialize_eval_result(result),
            artifact_name="Verified archive-admission eval result",
            require_verdict_evidence=True,
        )
        if isinstance(result, dict)
        else result
        for result in verified_output["results"]
    ]
    verified_results_by_runner: dict[str, list] = {}
    for result in verified_results:
        verified_results_by_runner.setdefault(result.runner, []).append(result)
    verified_readiness = {
        runner: summarize_readiness(runner_results, manifest.gates)
        for runner, runner_results in verified_results_by_runner.items()
    }
    expected_payload = _build_eval_suite_payload(
        manifest=manifest,
        effective_runners=list(effective_runners),
        results=verified_results,
        readiness=verified_readiness,
        run_state=run_state,
        completed_case_indexes=set(verified_output["completed_case_indexes"]),
    )
    if result_payload != expected_payload:
        raise ValueError(
            "results.json does not match the verified suite state and results ledger"
        )

    summary_raw = _read_eval_suite_artifact_bytes(
        source_output,
        "summary.json",
        max_bytes=32 * 1024 * 1024,
    )
    try:
        summary_payload = json.loads((summary_raw or b"").decode("utf-8"))
    except (UnicodeDecodeError, json.JSONDecodeError) as exc:
        raise ValueError("summary.json is malformed") from exc
    if summary_payload != _eval_suite_summary_payload(result_payload):
        raise ValueError("summary.json does not match the verified results payload")
    return result_payload


_EVAL_SUITE_ARCHIVE_CONTROL_FILES = {
    "suite-run.json": 8 * 1024 * 1024,
    "suite-results.jsonl": 256 * 1024 * 1024,
    "results.json": 256 * 1024 * 1024,
    "summary.json": 32 * 1024 * 1024,
}
_EVAL_SUITE_ARCHIVE_COMPANION_TEST_MAX_BYTES = 32 * 1024 * 1024
_EVAL_SUITE_ARCHIVE_INDEX_MAX_BYTES = 64 * 1024 * 1024


def _eval_suite_archive_relative_path(
    source_root: Path,
    raw_path: str,
    *,
    label: str,
) -> Path:
    """Return one canonical, lexically contained archive artifact path."""

    if not isinstance(raw_path, str) or not raw_path:
        raise ValueError(f"{label} path is malformed")
    candidate = Path(raw_path)
    canonical = Path(os.path.abspath(raw_path))
    if not candidate.is_absolute() or raw_path != str(canonical):
        raise ValueError(f"{label} path is not canonical: {raw_path}")
    try:
        relative = canonical.relative_to(source_root)
    except ValueError as exc:
        raise ValueError(
            f"{label} is outside the eval-suite output: {raw_path}"
        ) from exc
    if not relative.parts:
        raise ValueError(f"{label} does not name a file: {raw_path}")
    return relative


def _snapshot_verified_eval_suite_archive_files(
    source_output: Path,
    result_payload: dict,
) -> dict[Path, bytes]:
    """Capture the exact bounded file set admitted by the live verifier.

    The caller copies only these in-memory bytes. A full descendant scan rejects
    any extra file or directory, so an archive cannot become an exfiltration
    vehicle for unrelated output-tree contents.
    """

    source_root = Path(os.path.abspath(source_output))
    snapshot: dict[Path, bytes] = {}

    def add_file(
        relative: Path,
        *,
        label: str,
        max_bytes: int,
        expected_sha256: str | None = None,
    ) -> None:
        candidate = source_root / relative
        if relative in snapshot:
            raw = snapshot[relative]
        else:
            try:
                raw = read_bounded_regular_file(
                    source_root,
                    candidate,
                    label=label,
                    max_bytes=max_bytes,
                )
            except (OSError, ValueError) as exc:
                raise ValueError(f"Could not safely snapshot {label}: {exc}") from exc
            snapshot[relative] = raw
        if (
            expected_sha256 is not None
            and hashlib.sha256(raw).hexdigest() != expected_sha256
        ):
            raise ValueError(f"{label} changed after archive verification")

    for filename, max_bytes in _EVAL_SUITE_ARCHIVE_CONTROL_FILES.items():
        add_file(
            Path(filename),
            label=f"eval suite {filename}",
            max_bytes=max_bytes,
        )

    results = result_payload.get("results")
    if not isinstance(results, list):
        raise ValueError("Verified eval-suite archive payload is missing results")
    for result_index, result in enumerate(results, start=1):
        if not isinstance(result, dict):
            raise ValueError("Verified eval-suite archive result is malformed")
        for (
            path_field,
            digest_field,
            artifact_label,
            max_bytes,
        ) in _EVAL_RESULT_ARTIFACT_SPECS:
            raw_path = result.get(path_field)
            expected_sha256 = result.get(digest_field)
            if not raw_path:
                if expected_sha256 is not None:
                    raise ValueError(
                        f"Verified result {result_index} has a {digest_field} "
                        f"without {path_field}"
                    )
                continue
            if not isinstance(expected_sha256, str):
                raise ValueError(
                    f"Verified result {result_index} is missing {digest_field}"
                )
            relative = _eval_suite_archive_relative_path(
                source_root,
                raw_path,
                label=f"Verified result {result_index} {artifact_label}",
            )
            add_file(
                relative,
                label=f"verified result {result_index} {artifact_label}",
                max_bytes=max_bytes,
                expected_sha256=expected_sha256,
            )
            if path_field != "output_file":
                continue
            companion = (source_root / relative).with_name(f"{relative.stem}.test.yaml")
            try:
                os.lstat(companion)
            except FileNotFoundError:
                continue
            companion_relative = companion.relative_to(source_root)
            add_file(
                companion_relative,
                label=f"verified result {result_index} companion RuleSpec test",
                max_bytes=_EVAL_SUITE_ARCHIVE_COMPANION_TEST_MAX_BYTES,
            )

    allowed_files = set(snapshot)
    allowed_directories = {Path(".")}
    for relative in allowed_files:
        allowed_directories.update(relative.parents)
    observed_files: set[Path] = set()
    for directory, directory_names, file_names in os.walk(
        source_root,
        followlinks=False,
    ):
        directory_path = Path(directory)
        relative_directory = directory_path.relative_to(source_root)
        relative_directory = relative_directory or Path(".")
        if relative_directory not in allowed_directories:
            raise ValueError(
                "Eval-suite output contains an unreferenced directory: "
                f"{directory_path}"
            )
        for name in directory_names:
            child = directory_path / name
            child_relative = child.relative_to(source_root)
            child_stat = os.lstat(child)
            if not stat.S_ISDIR(child_stat.st_mode):
                raise ValueError(
                    f"Eval-suite output contains an indirect directory: {child}"
                )
            if child_relative not in allowed_directories:
                raise ValueError(
                    f"Eval-suite output contains an unreferenced directory: {child}"
                )
        for name in file_names:
            child = directory_path / name
            child_relative = child.relative_to(source_root)
            child_stat = os.lstat(child)
            if not stat.S_ISREG(child_stat.st_mode):
                raise ValueError(
                    f"Eval-suite output contains an indirect file: {child}"
                )
            if child_relative not in allowed_files:
                raise ValueError(
                    f"Eval-suite output contains an unreferenced file: {child}"
                )
            observed_files.add(child_relative)
    if observed_files != allowed_files:
        missing = sorted(str(path) for path in allowed_files - observed_files)
        raise ValueError(
            "Eval-suite output changed while its archive snapshot was captured; "
            f"missing: {', '.join(missing)}"
        )
    return snapshot


def _rewrite_archive_paths_in_payload(payload, source_root: Path, archive_root: Path):
    """Rewrite absolute paths that pointed at the source suite root."""
    source_root_str = str(source_root)
    archive_root_str = str(archive_root)
    source_prefix = source_root_str + os.sep

    if isinstance(payload, dict):
        return {
            key: (
                copy.deepcopy(value)
                if key
                in {
                    "evidence",
                    "admission",
                    "execution_identity",
                    "manifest",
                    "retrieved_files",
                    "unexpected_accesses",
                    "source_attestation",
                }
                else _rewrite_archive_paths_in_payload(value, source_root, archive_root)
            )
            for key, value in payload.items()
        }
    if isinstance(payload, list):
        return [
            _rewrite_archive_paths_in_payload(value, source_root, archive_root)
            for value in payload
        ]
    if isinstance(payload, str):
        if payload == source_root_str:
            return archive_root_str
        if payload.startswith(source_prefix):
            return archive_root_str + payload[len(source_root_str) :]
    return payload


def _rewrite_archived_eval_suite_json_files(
    archive_dir: Path,
    source_root: Path,
    *,
    archive_path_root: Path | None = None,
    validate_artifacts: bool = True,
) -> list[str]:
    """Rewrite archived JSON payloads so artifact paths point at the archive."""
    published_root = archive_path_root or archive_dir
    rewritten_files: list[str] = []
    payloads: dict[str, dict] = {}
    originals: dict[str, dict] = {}
    for filename in ("suite-run.json", "results.json", "summary.json"):
        path = archive_dir / filename
        if not path.exists():
            continue
        payload = json.loads(path.read_text())
        if not isinstance(payload, dict):
            raise ValueError(f"Archived {filename} must contain a JSON object")
        originals[filename] = payload
        rewritten = _rewrite_archive_paths_in_payload(
            payload,
            source_root,
            published_root,
        )
        payloads[filename] = rewritten

    results_payload = payloads.get("results.json")
    if results_payload is not None:
        evidence = results_payload.get("evidence")
        coverage = results_payload.get("coverage")
        results = results_payload.get("results")
        if (
            not isinstance(evidence, dict)
            or not isinstance(coverage, dict)
            or not isinstance(results, list)
        ):
            raise ValueError("Archived results.json is missing evidence or coverage")
        results[:] = [
            _bind_eval_result_payload(result) if isinstance(result, dict) else result
            for result in results
        ]
        execution_identity = evidence.get("execution_identity")
        if not isinstance(execution_identity, dict):
            raise ValueError("Archived results.json has malformed execution evidence")
        evidence["execution_identity_sha256"] = _eval_suite_execution_identity_sha256(
            execution_identity
        )
        evidence_without_digest = dict(evidence)
        evidence_without_digest.pop("sha256", None)
        evidence["sha256"] = _eval_suite_json_sha256(evidence_without_digest)
        coverage["results_sha256"] = _eval_suite_json_sha256(results)
        coverage["actual_result_count"] = len(results)
        if validate_artifacts:
            _validated_eval_suite_report_payload(
                results_payload,
                artifact_root=published_root,
            )

        summary_payload = payloads.get("summary.json")
        if summary_payload is None:
            raise ValueError("Archived eval suite is missing summary.json")
        summary_payload["evidence"] = copy.deepcopy(evidence)
        summary_payload["coverage"] = copy.deepcopy(coverage)
        if summary_payload != _eval_suite_summary_payload(results_payload):
            raise ValueError("Archived summary.json does not match archived results")

    for filename, rewritten in payloads.items():
        if rewritten == originals[filename]:
            continue
        _atomic_write_eval_suite_artifact(
            archive_dir / filename,
            (json.dumps(rewritten, indent=2, sort_keys=True) + "\n").encode("utf-8"),
        )
        rewritten_files.append(filename)

    ledger_path = archive_dir / "suite-results.jsonl"
    if ledger_path.exists():
        rows = []
        changed = False
        for line in ledger_path.read_text().splitlines():
            if not line.strip():
                continue
            payload = json.loads(line)
            rewritten = _rewrite_archive_paths_in_payload(
                payload,
                source_root,
                published_root,
            )
            result_payload = rewritten.get("result")
            if not isinstance(result_payload, dict):
                raise ValueError("Archived eval-suite ledger row is malformed")
            rewritten["result"] = _bind_eval_result_payload(result_payload)
            result_payload = rewritten["result"]
            archived_result = _eval_result_from_payload(
                result_payload,
                artifact_name="Archived eval-suite ledger result",
            )
            if validate_artifacts:
                _validate_eval_result_artifacts(
                    archived_result,
                    published_root,
                    artifact_name="Archived eval-suite ledger result",
                )
            rows.append(rewritten)
            changed = changed or rewritten != payload
        if changed:
            _atomic_write_eval_suite_artifact(
                ledger_path,
                "".join(json.dumps(row, sort_keys=True) + "\n" for row in rows).encode(
                    "utf-8"
                ),
            )
            rewritten_files.append("suite-results.jsonl")

    return rewritten_files


def _build_eval_suite_archive_metadata(
    archive_dir: Path,
    source_root: Path,
    rewritten_files: list[str],
    *,
    published_archive_dir: Path | None = None,
) -> dict:
    """Build a compact metadata record for an archived suite snapshot."""
    published_dir = published_archive_dir or archive_dir
    state_path = archive_dir / "suite-run.json"
    summary_path = archive_dir / "summary.json"
    results_path = archive_dir / "results.json"

    state = json.loads(state_path.read_text()) if state_path.exists() else {}
    summary = json.loads(summary_path.read_text()) if summary_path.exists() else {}
    results = json.loads(results_path.read_text()) if results_path.exists() else {}
    manifest = (
        state.get("manifest")
        or summary.get("manifest")
        or results.get("manifest")
        or {}
    )

    return {
        "archived_at": _utc_now_iso(),
        "source_output": str(source_root),
        "archive_dir": str(published_dir),
        "manifest": manifest,
        "status": state.get("status"),
        "run_id": state.get("run_id"),
        "started_at": state.get("started_at"),
        "finished_at": state.get("finished_at"),
        "total_cases": state.get("total_cases"),
        "completed_cases": state.get("completed_cases"),
        "result_count": state.get(
            "result_count", len(results.get("results", []) or [])
        ),
        "all_ready": summary.get("all_ready"),
        "evidence_sha256": (results.get("evidence") or {}).get("sha256"),
        "results_sha256": (results.get("coverage") or {}).get("results_sha256"),
        "rewritten_files": rewritten_files,
    }


@contextlib.contextmanager
def _locked_eval_suite_archive_root(archive_root: Path):
    """Hold the archive registry lock and yield its stable directory descriptor."""

    nofollow = getattr(os, "O_NOFOLLOW", None)
    directory = getattr(os, "O_DIRECTORY", None)
    if nofollow is None or directory is None:
        raise ValueError("Eval-suite archives require no-follow directory opens")
    common_flags = nofollow | getattr(os, "O_CLOEXEC", 0)
    root_fd = os.open(archive_root, os.O_RDONLY | directory | common_flags)
    lock_fd: int | None = None
    try:
        root_stat = os.fstat(root_fd)
        if not stat.S_ISDIR(root_stat.st_mode):
            raise ValueError("Eval-suite archive root is not a directory")
        if root_stat.st_uid != os.geteuid():
            raise ValueError("Eval-suite archive root is not owned by this user")
        try:
            lock_fd = os.open(
                ".archive.lock",
                os.O_RDWR | os.O_CREAT | common_flags,
                0o600,
                dir_fd=root_fd,
            )
        except OSError as exc:
            raise ValueError("Eval-suite archive lock cannot be opened safely") from exc
        lock_stat = os.fstat(lock_fd)
        if (
            not stat.S_ISREG(lock_stat.st_mode)
            or lock_stat.st_nlink != 1
            or lock_stat.st_uid != os.geteuid()
        ):
            raise ValueError(
                "Eval-suite archive lock must be a singly linked owned regular file"
            )
        fcntl.flock(lock_fd, fcntl.LOCK_EX)
        yield root_fd
    finally:
        if lock_fd is not None:
            with contextlib.suppress(OSError):
                fcntl.flock(lock_fd, fcntl.LOCK_UN)
            os.close(lock_fd)
        os.close(root_fd)


def _unique_archive_name(root_fd: int, base_name: str) -> str:
    """Return an unused archive entry name while the registry lock is held."""

    suffix = 1
    while True:
        candidate = base_name if suffix == 1 else f"{base_name}-{suffix}"
        try:
            os.stat(candidate, dir_fd=root_fd, follow_symlinks=False)
        except FileNotFoundError:
            return candidate
        suffix += 1


def _eval_suite_archive_directory_identity(path: Path) -> tuple[int, int]:
    """Return a directory identity suitable for ownership-checked cleanup."""

    path_stat = os.lstat(path)
    if not stat.S_ISDIR(path_stat.st_mode):
        raise ValueError(f"Eval-suite archive path is not a directory: {path}")
    return path_stat.st_dev, path_stat.st_ino


def _remove_owned_eval_suite_archive_directory(
    path: Path,
    expected_identity: tuple[int, int],
) -> bool:
    """Remove only the exact staging/published directory created by this call."""

    try:
        path_stat = os.lstat(path)
    except FileNotFoundError:
        return True
    if (
        not stat.S_ISDIR(path_stat.st_mode)
        or (path_stat.st_dev, path_stat.st_ino) != expected_identity
    ):
        return False
    shutil.rmtree(path)
    return True


def _fsync_eval_suite_archive_tree(root: Path) -> None:
    """Durably persist every directory entry in a newly staged archive."""

    flags = os.O_RDONLY | getattr(os, "O_DIRECTORY", 0)
    if hasattr(os, "O_NOFOLLOW"):
        flags |= os.O_NOFOLLOW
    for directory, _directory_names, _file_names in os.walk(
        root,
        topdown=False,
        followlinks=False,
    ):
        directory_fd = os.open(directory, flags)
        try:
            os.fsync(directory_fd)
        finally:
            os.close(directory_fd)


def _read_eval_suite_archive_index(root_fd: int) -> bytes:
    """Safely read and validate the current archive index, if present."""

    flags = os.O_RDONLY | getattr(os, "O_CLOEXEC", 0)
    flags |= getattr(os, "O_NOFOLLOW", 0) | getattr(os, "O_NONBLOCK", 0)
    try:
        index_fd = os.open("index.jsonl", flags, dir_fd=root_fd)
    except FileNotFoundError:
        return b""
    except OSError as exc:
        raise ValueError("Eval-suite archive index cannot be opened safely") from exc
    try:
        index_stat = os.fstat(index_fd)
        if (
            not stat.S_ISREG(index_stat.st_mode)
            or index_stat.st_nlink != 1
            or index_stat.st_uid != os.geteuid()
        ):
            raise ValueError(
                "Eval-suite archive index must be a singly linked owned regular file"
            )
        if index_stat.st_size > _EVAL_SUITE_ARCHIVE_INDEX_MAX_BYTES:
            raise ValueError("Eval-suite archive index exceeds its safety limit")
        remaining = _EVAL_SUITE_ARCHIVE_INDEX_MAX_BYTES + 1
        chunks: list[bytes] = []
        while remaining:
            chunk = os.read(index_fd, min(1024 * 1024, remaining))
            if not chunk:
                break
            chunks.append(chunk)
            remaining -= len(chunk)
        raw = b"".join(chunks)
        if len(raw) > _EVAL_SUITE_ARCHIVE_INDEX_MAX_BYTES:
            raise ValueError("Eval-suite archive index exceeds its safety limit")
    finally:
        os.close(index_fd)
    try:
        text = raw.decode("utf-8")
    except UnicodeDecodeError as exc:
        raise ValueError("Eval-suite archive index is not valid UTF-8") from exc
    for line_number, line in enumerate(text.splitlines(), start=1):
        if not line.strip():
            continue
        try:
            row = json.loads(line)
        except json.JSONDecodeError as exc:
            raise ValueError(
                f"Eval-suite archive index has malformed JSON at line {line_number}"
            ) from exc
        if not isinstance(row, dict):
            raise ValueError(
                f"Eval-suite archive index has a non-object row at line {line_number}"
            )
    return raw


def _update_eval_suite_archive_index(root_fd: int, metadata: dict) -> None:
    """Atomically replace the safe local index with one appended metadata row."""

    raw = _read_eval_suite_archive_index(root_fd)
    if raw and not raw.endswith(b"\n"):
        raw += b"\n"
    updated = raw + (json.dumps(metadata, sort_keys=True) + "\n").encode("utf-8")
    if len(updated) > _EVAL_SUITE_ARCHIVE_INDEX_MAX_BYTES:
        raise ValueError("Eval-suite archive index exceeds its safety limit")

    temporary_name: str | None = None
    temporary_fd: int | None = None
    flags = os.O_WRONLY | os.O_CREAT | os.O_EXCL | getattr(os, "O_CLOEXEC", 0)
    flags |= getattr(os, "O_NOFOLLOW", 0)
    try:
        for _attempt in range(100):
            candidate = f".index.{os.urandom(16).hex()}.tmp"
            try:
                temporary_fd = os.open(
                    candidate,
                    flags,
                    0o600,
                    dir_fd=root_fd,
                )
            except FileExistsError:
                continue
            temporary_name = candidate
            break
        if temporary_fd is None or temporary_name is None:
            raise ValueError("Could not reserve a temporary eval-suite archive index")
        remaining = memoryview(updated)
        while remaining:
            written = os.write(temporary_fd, remaining)
            if written <= 0:
                raise OSError("short write while updating eval-suite archive index")
            remaining = remaining[written:]
        os.fsync(temporary_fd)
        os.close(temporary_fd)
        temporary_fd = None
        os.replace(
            temporary_name,
            "index.jsonl",
            src_dir_fd=root_fd,
            dst_dir_fd=root_fd,
        )
        temporary_name = None
        os.fsync(root_fd)
    finally:
        if temporary_fd is not None:
            os.close(temporary_fd)
        if temporary_name is not None:
            with contextlib.suppress(FileNotFoundError):
                os.unlink(temporary_name, dir_fd=root_fd)


def _reject_nested_eval_suite_archive_paths(
    source_output: Path,
    archive_root: Path,
) -> None:
    """Reject recursive archive layouts in either direction."""

    if (
        source_output == archive_root
        or source_output.is_relative_to(archive_root)
        or archive_root.is_relative_to(source_output)
    ):
        raise ValueError(
            "Eval-suite source output and archive root must not contain one another"
        )


def _reject_eval_suite_archive_indirection(root: Path) -> None:
    """Reject symlinks and non-regular descendants before archive admission."""

    archive_root = Path(root)
    for directory, directory_names, file_names in os.walk(
        archive_root,
        followlinks=False,
    ):
        directory_path = Path(directory)
        for name in directory_names:
            path = directory_path / name
            if path.is_symlink() or not path.is_dir():
                raise ValueError(
                    f"Eval-suite archive contains an indirect directory: {path}"
                )
        for name in file_names:
            path = directory_path / name
            if path.is_symlink() or not path.is_file():
                raise ValueError(
                    f"Eval-suite archive contains an indirect file: {path}"
                )


def cmd_eval_suite_archive(args):
    """Archive an eval-suite output tree into the durable local registry."""
    source_output = args.source_output.expanduser().resolve()
    if not source_output.exists() or not source_output.is_dir():
        print(f"Eval suite output directory not found: {source_output}")
        sys.exit(1)

    state_path = source_output / "suite-run.json"
    if not state_path.exists():
        print(
            f"Not an eval-suite output directory (missing suite-run.json): {source_output}"
        )
        sys.exit(1)
    try:
        _reject_eval_suite_archive_indirection(source_output)
    except ValueError as exc:
        print(f"Eval suite is not eligible for archive: {exc}")
        sys.exit(1)

    archive_root = (
        args.archive_root.expanduser().resolve()
        if args.archive_root is not None
        else _default_eval_suite_archive_root()
    )
    try:
        _reject_nested_eval_suite_archive_paths(source_output, archive_root)
    except ValueError as exc:
        print(f"Eval suite is not eligible for archive: {exc}")
        sys.exit(1)

    axiom_rules_path = _resolve_explicit_existing_directory(
        args.axiom_rules_path,
        label="Axiom rules engine",
    )
    policy_repo_path = _resolve_explicit_existing_directory(
        args.policy_repo_path,
        label="RuleSpec checkout",
    )
    corpus_path = _resolve_explicit_existing_directory(
        args.corpus_path,
        label="Axiom Corpus",
    )
    try:
        verified_payload = _load_verified_eval_suite_archive_payload(
            source_output,
            axiom_rules_path=axiom_rules_path,
            policy_repo_path=policy_repo_path,
            corpus_path=corpus_path,
            **(
                {"policyengine_runtime_root": args.policyengine_runtime_root}
                if getattr(args, "policyengine_runtime_root", None) is not None
                else {}
            ),
        )
        snapshot = _snapshot_verified_eval_suite_archive_files(
            source_output,
            verified_payload,
        )
    except (OSError, ValueError, yaml.YAMLError) as exc:
        print(f"Eval suite is not eligible for archive: {exc}")
        sys.exit(1)

    base_name = _slugify_archive_name(args.name or source_output.name)
    archive_dir: Path | None = None
    rewritten_files: list[str] = []
    metadata: dict | None = None
    try:
        archive_root.mkdir(parents=True, exist_ok=True)
        with _locked_eval_suite_archive_root(archive_root) as archive_root_fd:
            archive_name = _unique_archive_name(archive_root_fd, base_name)
            archive_dir = archive_root / archive_name
            staging_dir = Path(
                tempfile.mkdtemp(
                    dir=archive_root,
                    prefix=".archive-stage-",
                )
            )
            os.chmod(staging_dir, 0o700)
            staging_identity = _eval_suite_archive_directory_identity(staging_dir)
            published_identity: tuple[int, int] | None = None
            try:
                for relative, raw in sorted(
                    snapshot.items(),
                    key=lambda item: item[0].as_posix(),
                ):
                    _atomic_write_eval_suite_artifact(staging_dir / relative, raw)
                rewritten_files = _rewrite_archived_eval_suite_json_files(
                    staging_dir,
                    source_output,
                    archive_path_root=archive_dir,
                    validate_artifacts=False,
                )
                metadata = _build_eval_suite_archive_metadata(
                    archive_dir=staging_dir,
                    source_root=source_output,
                    rewritten_files=rewritten_files,
                    published_archive_dir=archive_dir,
                )
                _atomic_write_eval_suite_artifact(
                    staging_dir / "archive-metadata.json",
                    (json.dumps(metadata, indent=2, sort_keys=True) + "\n").encode(
                        "utf-8"
                    ),
                )
                _fsync_eval_suite_archive_tree(staging_dir)
                try:
                    os.stat(
                        archive_name,
                        dir_fd=archive_root_fd,
                        follow_symlinks=False,
                    )
                except FileNotFoundError:
                    pass
                else:
                    raise ValueError(
                        f"Eval-suite archive destination appeared concurrently: "
                        f"{archive_dir}"
                    )
                os.rename(
                    staging_dir.name,
                    archive_name,
                    src_dir_fd=archive_root_fd,
                    dst_dir_fd=archive_root_fd,
                )
                published_identity = staging_identity
                os.fsync(archive_root_fd)
                _load_verified_eval_suite_archive_payload(
                    archive_dir,
                    axiom_rules_path=axiom_rules_path,
                    policy_repo_path=policy_repo_path,
                    corpus_path=corpus_path,
                    **(
                        {"policyengine_runtime_root": (args.policyengine_runtime_root)}
                        if getattr(args, "policyengine_runtime_root", None) is not None
                        else {}
                    ),
                )
                _update_eval_suite_archive_index(archive_root_fd, metadata)
            except Exception:
                if published_identity is not None:
                    _remove_owned_eval_suite_archive_directory(
                        archive_dir,
                        published_identity,
                    )
                    os.fsync(archive_root_fd)
                else:
                    _remove_owned_eval_suite_archive_directory(
                        staging_dir,
                        staging_identity,
                    )
                raise
    except (OSError, ValueError, yaml.YAMLError) as exc:
        print(f"Eval suite failed archive admission: {exc}")
        sys.exit(1)
    assert archive_dir is not None
    assert metadata is not None

    if args.json:
        print(json.dumps(metadata, indent=2))
        return

    print(f"Archived eval suite to {archive_dir}")
    print(f"Source: {source_output}")
    print(f"Archive root: {archive_root}")
    if rewritten_files:
        print(f"Rewrote archived paths in: {', '.join(rewritten_files)}")
    if metadata.get("status"):
        print(f"Status: {metadata['status']}")
    if (
        metadata.get("completed_cases") is not None
        and metadata.get("total_cases") is not None
    ):
        print(
            f"Progress: {metadata['completed_cases']}/{metadata['total_cases']} cases"
        )


def _ordered_runner_names(payload: dict) -> list[str]:
    """Preserve runner order from results/readiness payloads."""
    ordered: list[str] = []
    for result in payload.get("results", []) or []:
        runner = result.get("runner")
        if runner and runner not in ordered:
            ordered.append(runner)
    for runner in (payload.get("readiness") or {}).keys():
        if runner not in ordered:
            ordered.append(runner)
    return ordered


def _mean_numeric(values: list[float | int | None]) -> float | None:
    """Return the arithmetic mean for present numeric values."""
    filtered = [float(value) for value in values if value is not None]
    if not filtered:
        return None
    return round(sum(filtered) / len(filtered), 6)


def _format_percent(value: float | None) -> str:
    """Format optional fractions as percentages."""
    if value is None:
        return "n/a"
    return f"{value:.1%}"


def _format_money(value: float | None) -> str:
    """Format optional dollar values for reports."""
    if value is None:
        return "n/a"
    return f"${value:.4f}"


def _format_duration_seconds(value_ms: float | None) -> str:
    """Format optional millisecond durations as seconds."""
    if value_ms is None:
        return "n/a"
    return f"{(value_ms / 1000):.1f}"


def _format_generalist_score(value: float | None) -> str:
    """Format optional 0-10 reviewer scores."""
    if value is None:
        return "n/a"
    return f"{value:.2f}/10"


def _validated_eval_suite_report_payload(
    payload: object,
    *,
    artifact_root: Path | None = None,
) -> dict:
    """Require a complete, internally content-bound eval result payload."""

    if not isinstance(payload, dict):
        raise ValueError("Eval suite result payload must be a JSON object")
    if payload.get("schema") != _EVAL_SUITE_RESULTS_SCHEMA:
        raise ValueError("Eval suite result payload uses an unsupported schema")

    evidence = payload.get("evidence")
    if not isinstance(evidence, dict):
        raise ValueError("Eval suite result payload is missing immutable evidence")
    if evidence.get("schema") != _EVAL_SUITE_EVIDENCE_SCHEMA:
        raise ValueError("Eval suite result payload uses unsupported evidence")
    evidence_sha256 = evidence.get("sha256")
    unsigned_evidence = dict(evidence)
    unsigned_evidence.pop("sha256", None)
    if not isinstance(
        evidence_sha256, str
    ) or evidence_sha256 != _eval_suite_json_sha256(unsigned_evidence):
        raise ValueError("Eval suite evidence digest is missing or inconsistent")

    execution_identity = evidence.get("execution_identity")
    execution_identity_sha256 = evidence.get("execution_identity_sha256")
    if (
        not isinstance(execution_identity, dict)
        or not isinstance(execution_identity_sha256, str)
        or execution_identity_sha256
        != _eval_suite_execution_identity_sha256(execution_identity)
    ):
        raise ValueError("Eval suite execution identity digest is inconsistent")

    run_identity = evidence.get("run")
    if not isinstance(run_identity, dict) or set(run_identity) != {"id", "started_at"}:
        raise ValueError("Eval suite signed run identity is missing")
    _validate_eval_suite_run_identity(
        run_identity.get("id"),
        run_identity.get("started_at"),
        artifact_name="Eval suite evidence",
    )

    corpus_identity = evidence.get("corpus")
    if (
        not isinstance(corpus_identity, dict)
        or set(corpus_identity)
        != {
            "corpus_release",
            "corpus_release_content_sha256",
            "corpus_release_selector_sha256",
        }
        or not isinstance(corpus_identity.get("corpus_release"), str)
        or not corpus_identity.get("corpus_release")
        or not isinstance(corpus_identity.get("corpus_release_content_sha256"), str)
        or not re.fullmatch(
            r"[0-9a-f]{64}", corpus_identity["corpus_release_content_sha256"]
        )
        or not isinstance(corpus_identity.get("corpus_release_selector_sha256"), str)
        or not re.fullmatch(
            r"[0-9a-f]{64}", corpus_identity["corpus_release_selector_sha256"]
        )
    ):
        raise ValueError("Eval suite corpus release identity is incomplete")

    manifest_identity = evidence.get("manifest")
    if not isinstance(manifest_identity, dict):
        raise ValueError("Eval suite manifest identity is missing")
    case_identities = manifest_identity.get("case_identities")
    if not isinstance(case_identities, list) or not case_identities:
        raise ValueError("Eval suite canonical case identities are missing")
    canonical_cases: list[dict] = []
    for expected_index, case_identity in enumerate(case_identities, start=1):
        if (
            not isinstance(case_identity, dict)
            or case_identity.get("index") != expected_index
            or not isinstance(case_identity.get("name"), str)
            or not case_identity.get("name")
            or case_identity.get("kind") not in {"citation", "source"}
            or not isinstance(case_identity.get("corpus_citation_path"), str)
            or not case_identity.get("corpus_citation_path")
            or not isinstance(case_identity.get("sha256"), str)
            or not re.fullmatch(r"[0-9a-f]{64}", case_identity["sha256"])
        ):
            raise ValueError("Eval suite canonical case identity is malformed")
        canonical_cases.append(case_identity)
    if not isinstance(manifest_identity.get("content_sha256"), str) or not re.fullmatch(
        r"[0-9a-f]{64}", manifest_identity["content_sha256"]
    ):
        raise ValueError("Eval suite manifest content digest is malformed")
    manifest_path = manifest_identity.get("path")
    if not isinstance(manifest_path, str) or not manifest_path:
        raise ValueError("Eval suite manifest path is missing")
    try:
        live_manifest = load_eval_suite_manifest(Path(manifest_path))
    except (OSError, ValueError) as exc:
        raise ValueError(
            "Eval suite manifest could not be loaded for readiness verification"
        ) from exc
    live_manifest_identity = _build_eval_suite_manifest_identity(live_manifest)
    if (
        live_manifest.name != manifest_identity.get("name")
        or live_manifest_identity.get("content_sha256")
        != manifest_identity.get("content_sha256")
        or live_manifest_identity.get("case_identities") != canonical_cases
    ):
        raise ValueError("Eval suite manifest changed before readiness verification")

    runner_identities = evidence.get("effective_runner_identities")
    if not isinstance(runner_identities, list) or not runner_identities:
        raise ValueError("Eval suite effective runner identities are missing")
    runners_by_name: dict[str, dict] = {}
    for runner in runner_identities:
        if (
            not isinstance(runner, dict)
            or not isinstance(runner.get("name"), str)
            or not runner.get("name")
            or runner.get("backend") not in {"claude", "codex", "openai"}
            or not isinstance(runner.get("model"), str)
            or not runner.get("model")
            or runner["name"] in runners_by_name
        ):
            raise ValueError("Eval suite effective runner identity is malformed")
        runners_by_name[runner["name"]] = runner
    manifest_runner_identities = [
        {
            "name": runner.name,
            "backend": runner.backend,
            "model": runner.model,
        }
        for runner in [parse_runner_spec(spec) for spec in live_manifest.runners]
    ]
    if runner_identities != manifest_runner_identities:
        raise ValueError(
            "Eval suite runner evidence differs from the signed manifest declaration"
        )

    results = payload.get("results")
    coverage = payload.get("coverage")
    if not isinstance(results, list) or not isinstance(coverage, dict):
        raise ValueError("Eval suite results or coverage metadata is malformed")
    expected_result_count = len(canonical_cases) * len(runner_identities)
    expected_coverage = {
        "expected_case_count": len(canonical_cases),
        "completed_case_count": len(canonical_cases),
        "expected_runner_count": len(runner_identities),
        "expected_result_count": expected_result_count,
        "actual_result_count": len(results),
        "complete": True,
        "results_sha256": _eval_suite_json_sha256(results),
    }
    if {key: coverage.get(key) for key in expected_coverage} != expected_coverage:
        raise ValueError("Eval suite coverage is incomplete or inconsistent")

    expected_pairs = [
        (case["index"], runner["name"])
        for case in canonical_cases
        for runner in runner_identities
    ]
    observed_pairs: list[tuple[int, str]] = []
    verified_results_by_runner: dict[str, list] = {
        runner_name: [] for runner_name in runners_by_name
    }
    for result in results:
        if not isinstance(result, dict):
            raise ValueError("Eval suite contains a malformed result")
        verified_result = _eval_result_from_payload(
            result,
            artifact_name="Eval suite report result",
            require_verdict_evidence=True,
        )
        if artifact_root is not None:
            _validate_eval_result_artifacts(
                verified_result,
                artifact_root,
                artifact_name="Eval suite report result",
            )
        case_marker = result.get("eval_case")
        if not isinstance(case_marker, dict):
            raise ValueError("Eval suite result is missing its canonical case identity")
        case_index = case_marker.get("index")
        if isinstance(case_index, bool) or not isinstance(case_index, int):
            raise ValueError("Eval suite result has an invalid case index")
        if not 1 <= case_index <= len(canonical_cases):
            raise ValueError("Eval suite result has an unknown case index")
        canonical_case = canonical_cases[case_index - 1]
        if verified_result.mode != live_manifest.cases[case_index - 1].mode:
            raise ValueError("Eval suite result uses a different case mode")
        if case_marker != {
            "index": canonical_case["index"],
            "name": canonical_case["name"],
            "kind": canonical_case["kind"],
            "corpus_citation_path": canonical_case["corpus_citation_path"],
            "sha256": canonical_case["sha256"],
        }:
            raise ValueError("Eval suite result uses a different case identity")
        corpus_citation_path = case_marker.get("corpus_citation_path")
        if (
            not isinstance(corpus_citation_path, str)
            or not corpus_citation_path
            or result.get("citation") != corpus_citation_path
        ):
            raise ValueError(
                "Eval suite result citation does not match its canonical case path"
            )
        runner_name = result.get("runner")
        if not isinstance(runner_name, str) or runner_name not in runners_by_name:
            raise ValueError("Eval suite result uses an unknown runner")
        runner_identity = runners_by_name[runner_name]
        if (
            result.get("backend") != runner_identity["backend"]
            or result.get("model") != runner_identity["model"]
        ):
            raise ValueError("Eval suite result uses a different runner identity")
        admission = result.get("admission")
        if not isinstance(admission, dict):
            raise ValueError("Eval suite result is missing its signed admission")
        expected_admission_common = {
            "schema": _EVAL_RESULT_ADMISSION_SCHEMA,
            "run": run_identity,
            "suite": {
                "name": manifest_identity.get("name"),
                "manifest_path": manifest_identity.get("path"),
                "manifest_content_sha256": manifest_identity.get("content_sha256"),
                "manifest_case_identities": canonical_cases,
                "effective_runner_identities": runner_identities,
            },
            "case": canonical_case,
            "corpus": corpus_identity,
            "execution": {
                "identity": execution_identity,
                "sha256": execution_identity_sha256,
            },
        }
        if {
            key: admission.get(key) for key in expected_admission_common
        } != expected_admission_common:
            raise ValueError(
                "Eval suite result admission does not match its run, manifest, case, "
                "corpus, runner, or execution evidence"
            )
        rulespec_admission = admission.get("rulespec")
        if not isinstance(rulespec_admission, dict):
            raise ValueError("Eval suite result has malformed RuleSpec admission")
        admitted_policy_root = rulespec_admission.get("policy_repo_root")
        matching_roots = [
            root
            for root in execution_identity.get("rulespec_roots", [])
            if isinstance(root, dict) and root.get("path") == admitted_policy_root
        ]
        if len(matching_roots) != 1:
            raise ValueError(
                "Eval suite result RuleSpec admission is not in its execution identity"
            )
        root_identity = matching_roots[0]
        expected_rulespec_admission = {
            "policy_repo_root": root_identity.get("path"),
            "root_content_sha256": root_identity.get("content_sha256"),
            "toolchain_contract_sha256": root_identity.get("toolchain_contract_sha256"),
            "validation_waiver_set_sha256": root_identity.get(
                "validation_waiver_set_sha256"
            ),
        }
        if rulespec_admission != expected_rulespec_admission:
            raise ValueError(
                "Eval suite result RuleSpec admission does not match its execution "
                "identity"
            )
        verified_results_by_runner[runner_name].append(verified_result)
        observed_pairs.append((case_index, runner_name))
    if observed_pairs != expected_pairs:
        raise ValueError(
            "Eval suite must contain exactly one ordered result per case and runner"
        )

    readiness = payload.get("readiness")
    if not isinstance(readiness, dict) or set(readiness) != set(runners_by_name):
        raise ValueError(
            "Eval suite readiness does not cover every runner exactly once"
        )
    expected_readiness = {
        runner_name: _serialize_readiness_summary(
            summarize_readiness(
                verified_results_by_runner[runner_name],
                live_manifest.gates,
            )
        )
        for runner_name in runners_by_name
    }
    if readiness != expected_readiness:
        raise ValueError(
            "Eval suite readiness does not match the bound results and manifest gates"
        )
    expected_all_ready = all(
        summary["ready"] for summary in expected_readiness.values()
    )
    if payload.get("all_ready") is not expected_all_ready:
        raise ValueError("Eval suite all_ready flag is inconsistent")

    manifest = payload.get("manifest")
    if manifest != {
        "name": manifest_identity.get("name"),
        "path": manifest_identity.get("path"),
        "runners": list(live_manifest.runners),
        "effective_runners": list(live_manifest.runners),
    }:
        raise ValueError("Eval suite display manifest does not match its evidence")
    return payload


def _build_eval_suite_report(
    payload: dict, left_runner: str, right_runner: str
) -> dict:
    """Build a structured pairwise report from eval-suite JSON output."""
    results = payload.get("results", []) or []
    readiness = payload.get("readiness", {}) or {}

    by_case: dict[int, dict[str, object]] = {}
    for result in results:
        eval_case = result.get("eval_case")
        runner = result.get("runner")
        if not isinstance(eval_case, dict) or not isinstance(runner, str):
            continue
        case_index = eval_case.get("index")
        if isinstance(case_index, bool) or not isinstance(case_index, int):
            continue
        group = by_case.setdefault(
            case_index,
            {"eval_case": eval_case, "results": {}},
        )
        group_results = group["results"]
        if isinstance(group_results, dict):
            group_results[runner] = result

    case_rows: list[dict] = []
    both_present = 0
    left_success_only = 0
    right_success_only = 0
    left_compile_only = 0
    right_compile_only = 0
    left_ci_only = 0
    right_ci_only = 0
    left_zero_ungrounded_only = 0
    right_zero_ungrounded_only = 0
    left_lower_cost = 0
    right_lower_cost = 0
    tied_cost = 0
    left_higher_pe = 0
    right_higher_pe = 0
    tied_pe = 0

    for case_index in sorted(by_case):
        group = by_case[case_index]
        eval_case = group["eval_case"]
        group_results = group["results"]
        if not isinstance(eval_case, dict) or not isinstance(group_results, dict):
            continue
        left = group_results.get(left_runner)
        right = group_results.get(right_runner)
        if left is not None and not isinstance(left, dict):
            left = None
        if right is not None and not isinstance(right, dict):
            right = None
        left_metrics = (left or {}).get("metrics") or {}
        right_metrics = (right or {}).get("metrics") or {}

        row = {
            "case_index": case_index,
            "case": str(eval_case.get("name") or f"case-{case_index}"),
            "corpus_citation_path": eval_case.get("corpus_citation_path"),
            "left_runner": left_runner,
            "right_runner": right_runner,
            "left_success": left.get("success") if left else None,
            "right_success": right.get("success") if right else None,
            "left_compile_pass": left_metrics.get("compile_pass"),
            "right_compile_pass": right_metrics.get("compile_pass"),
            "left_ci_pass": left_metrics.get("ci_pass"),
            "right_ci_pass": right_metrics.get("ci_pass"),
            "left_zero_ungrounded": (
                left_metrics.get("ungrounded_numeric_count") == 0
                if left is not None and left_metrics
                else None
            ),
            "right_zero_ungrounded": (
                right_metrics.get("ungrounded_numeric_count") == 0
                if right is not None and right_metrics
                else None
            ),
            "left_policyengine_score": left_metrics.get("policyengine_score"),
            "right_policyengine_score": right_metrics.get("policyengine_score"),
            "left_estimated_cost_usd": left.get("estimated_cost_usd") if left else None,
            "right_estimated_cost_usd": right.get("estimated_cost_usd")
            if right
            else None,
            "left_duration_ms": left.get("duration_ms") if left else None,
            "right_duration_ms": right.get("duration_ms") if right else None,
            "left_output_file": left.get("output_file") if left else None,
            "right_output_file": right.get("output_file") if right else None,
            "left_generated_output_sha256": (
                left.get("generated_output_sha256") if left else None
            ),
            "right_generated_output_sha256": (
                right.get("generated_output_sha256") if right else None
            ),
            "left_trace_sha256": left.get("trace_sha256") if left else None,
            "right_trace_sha256": right.get("trace_sha256") if right else None,
            "left_context_manifest_sha256": (
                left.get("context_manifest_sha256") if left else None
            ),
            "right_context_manifest_sha256": (
                right.get("context_manifest_sha256") if right else None
            ),
        }
        case_rows.append(row)

        if left is not None and right is not None:
            both_present += 1
            if row["left_success"] and not row["right_success"]:
                left_success_only += 1
            elif row["right_success"] and not row["left_success"]:
                right_success_only += 1

            if row["left_compile_pass"] and not row["right_compile_pass"]:
                left_compile_only += 1
            elif row["right_compile_pass"] and not row["left_compile_pass"]:
                right_compile_only += 1

            if row["left_ci_pass"] and not row["right_ci_pass"]:
                left_ci_only += 1
            elif row["right_ci_pass"] and not row["left_ci_pass"]:
                right_ci_only += 1

            if row["left_zero_ungrounded"] and not row["right_zero_ungrounded"]:
                left_zero_ungrounded_only += 1
            elif row["right_zero_ungrounded"] and not row["left_zero_ungrounded"]:
                right_zero_ungrounded_only += 1

            left_cost = row["left_estimated_cost_usd"]
            right_cost = row["right_estimated_cost_usd"]
            if left_cost is not None and right_cost is not None:
                if left_cost < right_cost:
                    left_lower_cost += 1
                elif right_cost < left_cost:
                    right_lower_cost += 1
                else:
                    tied_cost += 1

            left_pe = row["left_policyengine_score"]
            right_pe = row["right_policyengine_score"]
            if left_pe is not None and right_pe is not None:
                if left_pe > right_pe:
                    left_higher_pe += 1
                elif right_pe > left_pe:
                    right_higher_pe += 1
                else:
                    tied_pe += 1

    runner_summaries: dict[str, dict] = {}
    for runner in [left_runner, right_runner]:
        runner_results = [
            result for result in results if result.get("runner") == runner
        ]
        summary = dict(readiness.get(runner) or {})
        summary["mean_duration_ms"] = _mean_numeric(
            [result.get("duration_ms") for result in runner_results]
        )
        summary["case_count"] = len(runner_results)
        runner_summaries[runner] = summary

    return {
        "manifest": payload.get("manifest") or {},
        "evidence": payload["evidence"],
        "coverage": payload["coverage"],
        "left_runner": left_runner,
        "right_runner": right_runner,
        "runner_summaries": runner_summaries,
        "pairwise": {
            "paired_case_count": both_present,
            "left_success_only_count": left_success_only,
            "right_success_only_count": right_success_only,
            "left_compile_only_count": left_compile_only,
            "right_compile_only_count": right_compile_only,
            "left_ci_only_count": left_ci_only,
            "right_ci_only_count": right_ci_only,
            "left_zero_ungrounded_only_count": left_zero_ungrounded_only,
            "right_zero_ungrounded_only_count": right_zero_ungrounded_only,
            "left_lower_cost_count": left_lower_cost,
            "right_lower_cost_count": right_lower_cost,
            "tied_cost_count": tied_cost,
            "left_higher_policyengine_score_count": left_higher_pe,
            "right_higher_policyengine_score_count": right_higher_pe,
            "tied_policyengine_score_count": tied_pe,
        },
        "case_rows": case_rows,
    }


def _render_eval_suite_report_markdown(report: dict) -> str:
    """Render a human-readable pairwise report suitable for a paper appendix."""
    manifest = report.get("manifest") or {}
    evidence = report.get("evidence") or {}
    evidence_manifest = evidence.get("manifest") or {}
    corpus_identity = evidence.get("corpus") or {}
    execution_identity = evidence.get("execution_identity") or {}
    left_runner = report["left_runner"]
    right_runner = report["right_runner"]
    left_summary = report["runner_summaries"].get(left_runner) or {}
    right_summary = report["runner_summaries"].get(right_runner) or {}
    pairwise = report.get("pairwise") or {}
    case_rows = report.get("case_rows") or []

    lines = [
        f"# {manifest.get('name', 'Eval suite')} model comparison",
        "",
        f"- Manifest: `{manifest.get('path', 'n/a')}`",
        f"- Manifest content SHA-256: `{evidence_manifest.get('content_sha256', 'n/a')}`",
        f"- Evidence SHA-256: `{evidence.get('sha256', 'n/a')}`",
        f"- Execution identity SHA-256: `{evidence.get('execution_identity_sha256', 'n/a')}`",
        f"- Corpus release: `{corpus_identity.get('corpus_release', 'n/a')}`",
        f"- Left runner: `{left_runner}`",
        f"- Right runner: `{right_runner}`",
        "",
        "| Metric | " + left_runner + " | " + right_runner + " |",
        "| --- | ---: | ---: |",
        f"| Cases | {left_summary.get('total_cases', left_summary.get('case_count', 'n/a'))} | {right_summary.get('total_cases', right_summary.get('case_count', 'n/a'))} |",
        f"| Success rate | {_format_percent(left_summary.get('success_rate'))} | {_format_percent(right_summary.get('success_rate'))} |",
        f"| Compile pass rate | {_format_percent(left_summary.get('compile_pass_rate'))} | {_format_percent(right_summary.get('compile_pass_rate'))} |",
        f"| CI pass rate | {_format_percent(left_summary.get('ci_pass_rate'))} | {_format_percent(right_summary.get('ci_pass_rate'))} |",
        f"| Zero-ungrounded rate | {_format_percent(left_summary.get('zero_ungrounded_rate'))} | {_format_percent(right_summary.get('zero_ungrounded_rate'))} |",
        f"| Generalist review pass rate | {_format_percent(left_summary.get('generalist_review_pass_rate'))} | {_format_percent(right_summary.get('generalist_review_pass_rate'))} |",
        f"| Mean generalist review score | {_format_generalist_score(left_summary.get('mean_generalist_review_score'))} | {_format_generalist_score(right_summary.get('mean_generalist_review_score'))} |",
        f"| PolicyEngine pass rate | {_format_percent(left_summary.get('policyengine_pass_rate'))} | {_format_percent(right_summary.get('policyengine_pass_rate'))} |",
        f"| Mean PolicyEngine score | {_format_percent(left_summary.get('mean_policyengine_score'))} | {_format_percent(right_summary.get('mean_policyengine_score'))} |",
        f"| Mean estimated cost | {_format_money(left_summary.get('mean_estimated_cost_usd'))} | {_format_money(right_summary.get('mean_estimated_cost_usd'))} |",
        f"| Mean duration (s) | {_format_duration_seconds(left_summary.get('mean_duration_ms'))} | {_format_duration_seconds(right_summary.get('mean_duration_ms'))} |",
        "",
        "## Pairwise counts",
        "",
        "| Outcome | Count |",
        "| --- | ---: |",
        f"| Paired cases | {pairwise.get('paired_case_count', 0)} |",
        f"| {left_runner} success-only advantages | {pairwise.get('left_success_only_count', 0)} |",
        f"| {right_runner} success-only advantages | {pairwise.get('right_success_only_count', 0)} |",
        f"| {left_runner} compile-only advantages | {pairwise.get('left_compile_only_count', 0)} |",
        f"| {right_runner} compile-only advantages | {pairwise.get('right_compile_only_count', 0)} |",
        f"| {left_runner} CI-only advantages | {pairwise.get('left_ci_only_count', 0)} |",
        f"| {right_runner} CI-only advantages | {pairwise.get('right_ci_only_count', 0)} |",
        f"| {left_runner} lower-cost cases | {pairwise.get('left_lower_cost_count', 0)} |",
        f"| {right_runner} lower-cost cases | {pairwise.get('right_lower_cost_count', 0)} |",
        f"| Tied-cost cases | {pairwise.get('tied_cost_count', 0)} |",
        f"| {left_runner} higher-PE-score cases | {pairwise.get('left_higher_policyengine_score_count', 0)} |",
        f"| {right_runner} higher-PE-score cases | {pairwise.get('right_higher_policyengine_score_count', 0)} |",
        f"| Tied-PE-score cases | {pairwise.get('tied_policyengine_score_count', 0)} |",
        "",
        "## Case-level appendix",
        "",
        "| Case | Corpus citation path | "
        + left_runner
        + " compile | "
        + right_runner
        + " compile | "
        + left_runner
        + " PE | "
        + right_runner
        + " PE | "
        + left_runner
        + " cost | "
        + right_runner
        + " cost |",
        "| --- | --- | ---: | ---: | ---: | ---: | ---: | ---: |",
    ]

    for row in case_rows:
        left_pe = row["left_policyengine_score"]
        right_pe = row["right_policyengine_score"]
        lines.append(
            "| "
            + f"{row['case_index']}. {row['case']}"
            + " | `"
            + str(row["corpus_citation_path"])
            + "`"
            + " | "
            + (
                "pass"
                if row["left_compile_pass"]
                else "fail"
                if row["left_compile_pass"] is not None
                else "n/a"
            )
            + " | "
            + (
                "pass"
                if row["right_compile_pass"]
                else "fail"
                if row["right_compile_pass"] is not None
                else "n/a"
            )
            + " | "
            + (_format_percent(left_pe) if left_pe is not None else "n/a")
            + " | "
            + (_format_percent(right_pe) if right_pe is not None else "n/a")
            + " | "
            + _format_money(row["left_estimated_cost_usd"])
            + " | "
            + _format_money(row["right_estimated_cost_usd"])
            + " |"
        )

    lines.extend(["", "## Immutable execution inputs", ""])
    encoder_identity = execution_identity.get("axiom_encode") or {}
    engine_identity = execution_identity.get("axiom_rules_engine") or {}
    lines.extend(
        [
            f"- axiom-encode version: `{encoder_identity.get('version', 'n/a')}`",
            f"- axiom-encode commit/tree: `{encoder_identity.get('commit', encoder_identity.get('tree_sha256', 'n/a'))}`",
            f"- axiom-rules-engine commit/tree: `{engine_identity.get('commit', engine_identity.get('tree_sha256', 'n/a'))}`",
        ]
    )
    policyengine_runtime = execution_identity.get("policyengine_runtime")
    if isinstance(policyengine_runtime, dict):
        runtime_identity = policyengine_runtime.get("identity")
        if not isinstance(runtime_identity, dict):
            runtime_identity = {}
        lines.append(
            "- PolicyEngine runtime "
            f"`{runtime_identity.get('country', 'n/a')}` at "
            f"`{runtime_identity.get('repository_root', 'n/a')}`: commit "
            f"`{runtime_identity.get('git_head', 'n/a')}`, identity "
            f"`{policyengine_runtime.get('sha256', 'n/a')}`"
        )
    for root in execution_identity.get("rulespec_roots") or []:
        if not isinstance(root, dict):
            continue
        lines.append(
            "- RuleSpec root "
            f"`{root.get('path', 'n/a')}`: content "
            f"`{root.get('content_sha256', 'n/a')}`, toolchain "
            f"`{root.get('toolchain_contract_sha256', 'n/a')}`, waiver set "
            f"`{root.get('validation_waiver_set_sha256', 'n/a')}`"
        )

    return "\n".join(lines) + "\n"


def cmd_eval_suite_report(args):
    """Render a pairwise comparison report from eval-suite JSON output."""
    try:
        result_json = args.result_json.expanduser().resolve()
        if result_json.name != "results.json":
            raise ValueError(
                "eval-suite-report requires the canonical results.json filename"
            )
        preflight_payload = json.loads(result_json.read_text())
        if (
            not isinstance(preflight_payload, dict)
            or preflight_payload.get("schema") != _EVAL_SUITE_RESULTS_SCHEMA
        ):
            raise ValueError("Eval suite result payload uses an unsupported schema")
        payload = _load_verified_eval_suite_archive_payload(
            result_json.parent,
            axiom_rules_path=_resolve_explicit_existing_directory(
                args.axiom_rules_path,
                label="Axiom rules engine",
            ),
            policy_repo_path=_resolve_explicit_existing_directory(
                args.policy_repo_path,
                label="RuleSpec checkout",
            ),
            corpus_path=_resolve_explicit_existing_directory(
                args.corpus_path,
                label="Axiom Corpus",
            ),
            **(
                {"policyengine_runtime_root": args.policyengine_runtime_root}
                if getattr(args, "policyengine_runtime_root", None) is not None
                else {}
            ),
        )
    except (OSError, json.JSONDecodeError, ValueError) as exc:
        print(f"Invalid eval-suite result payload: {exc}")
        sys.exit(1)
    available_runners = _ordered_runner_names(payload)
    if not available_runners:
        print(f"No runner results found in {args.result_json}")
        sys.exit(1)

    left_runner = args.left_runner or (
        available_runners[0] if available_runners else None
    )
    right_runner = args.right_runner or (
        available_runners[1] if len(available_runners) > 1 else None
    )
    if not left_runner or not right_runner:
        print(
            "Need two runners to compare. Pass --left-runner and --right-runner or provide a two-runner suite JSON."
        )
        sys.exit(1)
    if left_runner not in available_runners or right_runner not in available_runners:
        print(
            f"Requested runners must exist in the suite JSON. Available: {', '.join(available_runners)}"
        )
        sys.exit(1)

    report = _build_eval_suite_report(payload, left_runner, right_runner)

    if args.csv_out:
        args.csv_out.parent.mkdir(parents=True, exist_ok=True)
        with args.csv_out.open("w", newline="") as fh:
            fieldnames = (
                list(report["case_rows"][0].keys()) if report["case_rows"] else []
            )
            writer = csv.DictWriter(fh, fieldnames=fieldnames)
            if fieldnames:
                writer.writeheader()
                writer.writerows(report["case_rows"])

    if args.json:
        rendered = json.dumps(report, indent=2)
    else:
        rendered = _render_eval_suite_report_markdown(report)

    if args.markdown_out and not args.json:
        args.markdown_out.parent.mkdir(parents=True, exist_ok=True)
        args.markdown_out.write_text(rendered)

    print(rendered)


# =========================================================================
# Session Commands
# =========================================================================


def cmd_session_start(args):
    """Start a new session."""
    db = EncodingDB(args.db)
    from . import __version__

    session = db.start_session(
        model=args.model,
        cwd=args.cwd or str(Path.cwd()),
        axiom_encode_version=__version__,
    )

    # Output just the session ID for hooks to capture
    print(session.id)


def cmd_session_end(args):
    """End a session."""
    db = EncodingDB(args.db)
    db.end_session(args.session)
    print(f"Session {args.session} ended")


def cmd_log_event(args):
    """Log an event to a session."""
    db = EncodingDB(args.db)

    metadata = {}
    if args.metadata:
        try:
            metadata = json.loads(args.metadata)
        except json.JSONDecodeError:
            pass

    event = db.log_event(
        session_id=args.session,
        event_type=args.type,
        tool_name=args.tool,
        content=args.content,
        metadata=metadata,
    )

    print(f"Event {event.sequence}: {event.event_type}")


def cmd_sessions(args):
    """List recent sessions."""
    db = EncodingDB(args.db)
    sessions = db.get_recent_sessions(limit=args.limit)

    if not sessions:
        print("No sessions found.")
        return

    print(
        f"{'ID':<10} {'Started':<20} {'Events':<8} {'Model':<15} {'Version':<10} {'Status'}"
    )
    print("-" * 82)

    for s in sessions:
        started = s.started_at.strftime("%Y-%m-%d %H:%M") if s.started_at else "?"
        status = "ended" if s.ended_at else "active"
        model = s.model[:15] if s.model else "-"
        version = s.axiom_encode_version[:10] if s.axiom_encode_version else "-"
        print(
            f"{s.id:<10} {started:<20} {s.event_count:<8} {model:<15} {version:<10} {status}"
        )


def cmd_session_show(args):
    """Show a session transcript."""
    db = EncodingDB(args.db)

    session = db.get_session(args.session_id)
    if not session:
        print(f"Session not found: {args.session_id}")
        sys.exit(1)

    events = db.get_session_events(args.session_id)

    if args.json:
        output = {
            "session": {
                "id": session.id,
                "started_at": session.started_at.isoformat()
                if session.started_at
                else None,
                "ended_at": session.ended_at.isoformat() if session.ended_at else None,
                "model": session.model,
                "cwd": session.cwd,
                "axiom_encode_version": session.axiom_encode_version,
                "event_count": session.event_count,
            },
            "events": [
                {
                    "sequence": e.sequence,
                    "timestamp": e.timestamp.isoformat() if e.timestamp else None,
                    "type": e.event_type,
                    "tool": e.tool_name,
                    "content": e.content[:500]
                    if e.content
                    else "",  # Truncate long content
                    "metadata": e.metadata,
                }
                for e in events
            ],
        }
        print(json.dumps(output, indent=2))
    else:
        print(f"Session: {session.id}")
        print(f"Model: {session.model}")
        print(f"Axiom Encode: {session.axiom_encode_version or '-'}")
        print(f"Started: {session.started_at}")
        print(f"Ended: {session.ended_at or 'active'}")
        print(f"Events: {session.event_count}")
        print("-" * 60)

        for e in events:
            time_str = e.timestamp.strftime("%H:%M:%S") if e.timestamp else "?"
            tool_str = f" [{e.tool_name}]" if e.tool_name else ""
            content_preview = (
                (e.content[:80] + "...")
                if e.content and len(e.content) > 80
                else (e.content or "")
            )

            print(f"{e.sequence:3}. [{time_str}] {e.event_type}{tool_str}")
            if content_preview:
                print(f"     {content_preview}")


def cmd_session_stats(args):
    """Show session statistics."""
    db = EncodingDB(args.db)
    stats = db.get_session_stats()

    print("=== Session Statistics ===")
    print(f"Total sessions: {stats['total_sessions']}")
    print(f"Avg events/session: {stats['avg_events_per_session']}")
    print()

    if stats["event_type_counts"]:
        print("Event types:")
        for event_type, count in sorted(
            stats["event_type_counts"].items(), key=lambda x: -x[1]
        ):
            print(f"  {event_type}: {count}")
        print()

    if stats["tool_usage"]:
        print("Top tools:")
        for tool, count in list(stats["tool_usage"].items())[:10]:
            print(f"  {tool}: {count}")


# =========================================================================
# Transcript Sync Commands
# =========================================================================


def cmd_sync_transcripts(args):
    """Sync local transcripts to Supabase."""
    from .supabase_sync import sync_transcripts_to_supabase

    print(
        f"Syncing transcripts{f' for session {args.session}' if args.session else ''}..."
    )

    try:
        stats = sync_transcripts_to_supabase(session_id=args.session)
        print(
            f"Done! {stats['synced']} synced, {stats['failed']} failed of {stats['total']} total"
        )
    except ValueError as e:
        print(f"Error: {e}")
        print(
            "Set AXIOM_ENCODE_SUPABASE_URL and "
            "AXIOM_ENCODE_SUPABASE_SECRET_KEY environment variables"
        )
        sys.exit(1)


def cmd_transcript_stats(args):
    """Show local transcript database stats."""
    from .supabase_sync import get_local_transcript_stats

    stats = get_local_transcript_stats()

    if not stats.get("exists"):
        print("No local transcript database found")
        print("Transcripts are created automatically when subagents complete")
        return

    print("=== Local Transcript Stats ===")
    print(f"Total transcripts: {stats['total']}")
    print(f"Unsynced: {stats['unsynced']}")
    print(f"Synced: {stats['synced']}")
    print()

    if stats.get("by_type"):
        print("By agent type:")
        for agent_type, count in sorted(stats["by_type"].items(), key=lambda x: -x[1]):
            print(f"  {agent_type}: {count}")


def cmd_sync_agent_sessions(args):
    """Sync agent sessions to Supabase."""
    from .supabase_sync import sync_agent_sessions_to_supabase

    print(f"Syncing agent sessions{f' for {args.session}' if args.session else ''}...")

    try:
        stats = sync_agent_sessions_to_supabase(
            session_id=args.session,
            include_all=getattr(args, "all", False) is True,
        )
        print(
            f"Done! {stats['synced']} synced, {stats['failed']} failed of {stats['total']} total"
        )
    except ValueError as e:
        print(f"Error: {e}")
        print(
            "Set AXIOM_ENCODE_SUPABASE_URL and "
            "AXIOM_ENCODE_SUPABASE_SECRET_KEY environment variables"
        )
        sys.exit(1)


def cmd_sync_applied_runs(args):
    """Backfill Supabase encoding_runs from applied-rulespec manifests."""
    from .supabase_sync import sync_applied_manifest_runs

    missing = [repo for repo in args.repos if not Path(repo).is_dir()]
    if missing:
        for repo in missing:
            print(f"Repo checkout not found: {repo}")
        sys.exit(1)

    try:
        stats = sync_applied_manifest_runs(
            [Path(repo) for repo in args.repos],
            dry_run=getattr(args, "dry_run", False) is True,
        )
    except ValueError as e:
        print(f"Error: {e}")
        print(
            "Set AXIOM_ENCODE_SUPABASE_URL and "
            "AXIOM_ENCODE_SUPABASE_SECRET_KEY environment variables"
        )
        sys.exit(1)

    print(
        f"manifests={stats['total']} synced={stats['synced']} "
        f"failed={stats['failed']} skipped={stats['skipped']} "
        f"preserved={stats.get('preserved', 0)}"
    )
    if stats["failed"]:
        sys.exit(1)


if __name__ == "__main__":  # pragma: no cover
    main()
